# ── BUG-005 P0-Fix Teil 2: Supabase-Timeout-Helper ────────────────────────────
# Verhindert dass eine hängende Supabase-Query den ganzen Request-Handler blockiert.
# Default 5s timeout. Module-level ThreadPool — timed-out futures laufen im Hintergrund
# weiter und werden vom Pool recycled, kein Thread-Leak. cancel_futures=False ist OK,
# weil die Pool-Größe begrenzt ist und Cloud Run die Container ohnehin recycled.
#
# Symptom vor Fix: `sb.table('jobs').select(...).execute()` hat 30+ Sekunden gehangen
# wenn der supabase-py-Client in einem schlechten Verbindungszustand war. Da der Call
# innerhalb von `with _jobs_lock:` lief, hingen ALLE anderen Lock-User auch.
import concurrent.futures as _sb_cf
_SB_TIMEOUT_EXECUTOR = _sb_cf.ThreadPoolExecutor(
    max_workers=16,
    thread_name_prefix='sb-timeout',
)

def _supabase_execute_with_timeout(label, fn, timeout_s=5):
    """Run fn (typically a wrapped supabase .execute()) with a hard timeout.

    Returns (result, timed_out_or_failed_flag).
    On timeout or exception: returns (None, True) and logs reason.

    Verwendung:
        def _do(): return sb.table('jobs').select('data').eq('job_id', x).execute()
        res, timed_out = _supabase_execute_with_timeout('load_job', _do, timeout_s=5)
    """
    try:
        fut = _SB_TIMEOUT_EXECUTOR.submit(fn)
        try:
            return fut.result(timeout=timeout_s), False
        except _sb_cf.TimeoutError:
            print(f'[supabase-timeout] {label} exceeded {timeout_s}s — returning None')
            return None, True
    except Exception as e:
        print(f'[supabase-timeout] {label} error: {type(e).__name__}: {e}')
        return None, True


# Transiente httpx-Fehler beim Wiederverwenden einer stale Supabase-Connection
# ("RemoteProtocolError: Server disconnected"). Cloud Run + supabase-py/httpx
# halten Keep-Alive-Connections, die Supabase nach Idle schließt — der nächste
# Call auf der gleichen Connection scheitert, ein RETRY auf frischer Connection
# klappt. Symptom in den Logs: [delay-obs] sb_load/sb_write_FAIL.
_SB_TRANSIENT_ERRORS = (
    'RemoteProtocolError', 'RemoteDisconnected', 'ConnectError', 'ConnectTimeout',
    'ReadError', 'ReadTimeout', 'WriteError', 'PoolTimeout', 'ConnectionError',
)

def _sb_retry(label, fn, retries=2, backoff=0.35):
    """Führt fn() (typisch ein supabase `.execute()`) aus und wiederholt bei
    TRANSIENTEN Verbindungsfehlern (stale Keep-Alive). Gibt das Ergebnis zurück
    oder wirft den letzten Fehler nach `retries` Versuchen (Caller behält sein
    bestehendes try/except + Disk-Fallback)."""
    last = None
    for attempt in range(retries + 1):
        try:
            return fn()
        except Exception as e:
            if type(e).__name__ not in _SB_TRANSIENT_ERRORS or attempt >= retries:
                raise
            last = e
            print(f'[sb-retry] {label}: {type(e).__name__} — retry {attempt + 1}/{retries}')
            try: time.sleep(backoff * (attempt + 1))
            except Exception: pass
    if last:
        raise last


# ── Zentrale SB-Retry-Schicht (2026-07-03) ────────────────────────────────────
# Root-Cause der [friends]/[fgroups]/[ical-briefings] sb_load_fail-Flakes:
# das globale `sb` (Zeile ~42) ist EIN geteilter supabase-py-Client mit EINEM
# httpx-Connection-Pool. Supabase/PostgREST schließt Keep-Alive-Connections
# nach Idle; der nächste Request auf der stale Connection stirbt mit
# "RemoteProtocolError: Server disconnected". `_sb_retry` (oben) fing das nur
# an 2 Call-Sites. Statt jede der ~60 sb.table(...)-Stellen zu wrappen, hängen
# wir den Retry direkt vor den httpx-Transport des PostgREST-Session-Clients:
# JEDER Read und jeder IDEMPOTENTE Write bekommt bei transienten Fehlern
# automatisch 1–2 frische Versuche.
#
# Idempotenz-Regel (Retry nur wenn ein Doppel-Ausführen konvergiert):
#   · GET/HEAD/OPTIONS           → immer (Reads)
#   · DELETE/PUT/PATCH           → ja (PostgREST filter-basierte Writes)
#   · POST mit Prefer: resolution=merge-duplicates|ignore-duplicates → ja (Upsert)
#   · POST ohne Upsert-Prefer (plain INSERT, RPC) → NEIN (könnte doppeln)
import httpx as _sb_httpx


class _SBRetryTransport(_sb_httpx.BaseTransport):
    def __init__(self, inner, retries=2, backoff=0.35):
        self._inner = inner
        self._retries = retries
        self._backoff = backoff

    @staticmethod
    def _idempotent(request):
        m = (request.method or '').upper()
        if m in ('GET', 'HEAD', 'OPTIONS', 'DELETE', 'PUT', 'PATCH'):
            return True
        if m == 'POST':
            prefer = request.headers.get('prefer', '') or ''
            return ('resolution=merge-duplicates' in prefer
                    or 'resolution=ignore-duplicates' in prefer)
        return False

    def handle_request(self, request):
        attempt = 0
        while True:
            try:
                return self._inner.handle_request(request)
            except Exception as e:
                name = type(e).__name__
                if (name not in _SB_TRANSIENT_ERRORS
                        or attempt >= self._retries
                        or not self._idempotent(request)):
                    raise
                attempt += 1
                safe_upstream_path = _redact_observability_url(request.url.path)
                print(f'[sb-retry] transport {request.method} '
                      f'{safe_upstream_path}: {name} — retry {attempt}/{self._retries}')
                try:
                    time.sleep(self._backoff * attempt)
                except Exception:
                    pass

    def close(self):
        self._inner.close()


def _install_sb_retry_transport(client=None):
    """Best-effort: wickelt den httpx-Transport des PostgREST-Clients in
    _SBRetryTransport. `sb.postgrest.session` (httpx.Client) und dessen
    `_transport` sind über postgrest-py 0.16…1.x stabil; falls sich das je
    ändert, loggen wir und alles verhält sich wie bisher (per-Call-Site
    try/except + Disk-Fallbacks bleiben unangetastet)."""
    target = client if client is not None else sb
    if not SB_AVAILABLE or target is None:
        return
    try:
        session = getattr(getattr(target, 'postgrest', None), 'session', None)
        transport = getattr(session, '_transport', None)
        if transport is None:
            print('[sb-retry] transport install skipped: session/_transport nicht gefunden')
            return
        if isinstance(transport, _SBRetryTransport):
            return
        session._transport = _SBRetryTransport(transport)
        print('[sb-retry] transport installed (alle Reads + idempotente Writes)')
    except Exception as e:
        print(f'[sb-retry] transport install failed: {type(e).__name__}: {e}')


if SB_AVAILABLE and isinstance(sb, globals().get('_ThreadLocalSB', ())):
    # Jeder neue Thread-Client bekommt seinen EIGENEN Retry-Wrapper.  Hier
    # absichtlich keinen Client materialisieren: gunicorn darf vor dem Fork
    # keine offenen DB-Sockets erzeugen.
    sb.set_on_create(_install_sb_retry_transport)
    import atexit as _sb_atexit
    _sb_atexit.register(sb.close_all)
else:
    # Backward-compatible für Tests/Fallbacks, die einen direkten Fake-Client
    # injizieren.
    _install_sb_retry_transport()


def _close_current_thread_supabase_client():
    """Release a client owned by a short-lived executor thread.

    Gunicorn and the module-level timeout/push executors keep stable threads and
    intentionally retain one pool each. Per-request executors (friends-today,
    route-history) destroy their threads after every response; without this
    hook their clients remained strongly referenced by the proxy registry.
    """
    proxy_cls = globals().get('_ThreadLocalSB')
    client_proxy = globals().get('sb')
    if proxy_cls is not None and isinstance(client_proxy, proxy_cls):
        client_proxy.close_current()

