def _bug004_get_route_needs_auth(path):
    """True wenn ein GET-Path token-spezifische PII liefert (siehe
    _BUG004_GET_PII_PREFIXES). Bewusst Prefix-basiert damit Sub-Pfade
    (/dm/<friend>, /channel/<id>, /<datum>) automatisch erfasst sind.
    """
    for prefix in _BUG004_GET_PII_PREFIXES:
        if path.startswith(prefix):
            return True
    return False


# ── AUTH-BINDING (BUG-AUDIT 2026-06-07, gehärtet 2026-06-08) ─────────────
# Cross-User-/Public-Pfade: hier ist das AT-Token im Pfad ABSICHTLICH das
# eines ANDEREN Users (Friend-Discovery) ODER der Pfad läuft bevor überhaupt
# ein Token existiert (Auth/Signup). Für diese Pfade darf der Bearer NICHT
# gleich dem Pfad-Token sein müssen — sonst bräche der Friend-Lookup bzw.
# der Login. Alle ÜBRIGEN owner-scoped Pfade binden den Bearer constant-time
# an das Pfad-Token (Verhalten siehe _bug004_token_auth_gate, abhängig vom
# Enforcement-Flag AEROX_REQUIRE_TOKEN_BINDING).
#
# WICHTIG zur Regex-Semantik: _BUG004_TOKEN_PATH_RE matcht das ERSTE AT-…-
# Segment im Pfad ("first match wins"). Für Routen wie
#   /api/user/friend-roster/<token>/<friend_token>
#   /api/user/friend-compare/<token>/<friend_token>
#   /api/crew-chat/<token>/dm/<friend_token>
# ist das erste Segment IMMER das EIGENE Token des Callers → owner-scoped →
# Binding ist korrekt (der Caller-Bearer muss dem eigenen Token gleichen).
# Es gibt aktuell KEINE Route, bei der ein FREMDES Token als erstes AT-…-
# Segment auftaucht ausser den beiden expliziten Discovery-GETs unten.
#
# Hinweis Wall/Forum: dort ist das Pfad-Token das EIGENE Token des Callers
# (Author-Identität), also owner-scoped. Aktuelle iOS-Builds schicken überall
# den Bearer; fehlend oder abweichend wird deshalb standardmäßig abgewiesen.
#
# ⚠️ FOLLOW-UP / RESTLAST (echte Security erst danach vollständig):
#   1. Das Token muss langfristig AUS DER URL RAUS — nur noch im Header. Solange
#      es im Pfad steht (Access-Logs, Proxy-Logs, Referer, Browser-History,
#      Sentry-Breadcrumbs) bleibt der URL-Leak-Vektor offen; Bearer-Binding
#      schützt nur gegen das WIEDERVERWENDEN eines geleakten Tokens durch einen
#      ANDEREN authentifizierten Aufrufer, NICHT gegen das Leak selbst.
#      => Header-only-Token ist der eigentliche Fix, Bearer-Binding ist Stufe 1.
#
# Deny-by-default: aktuelle iOS-Builds senden Authorization auf allen Requests.
# Nur der explizite Notfallwert `AEROX_REQUIRE_TOKEN_BINDING=0` deaktiviert die
# Pflicht temporär; fehlend/1/sonstige Werte bleiben enforced.
def _token_binding_enforced_from_env(value=None):
    if value is None:
        value = os.environ.get('AEROX_REQUIRE_TOKEN_BINDING')
    return str(value or '').strip() != '0'


_BUG004_REQUIRE_TOKEN_BINDING = _token_binding_enforced_from_env()

# Cross-user Ausnahmen sind methoden- UND route-genau.  Prefix-Ausnahmen waren
# gefährlich: der öffentliche GET `/profile/<other>` exemptete dadurch auch den
# owner-scoped PUT; `/friends/<other>` exemptete `/add`, `/remove` und
# `/overlap`.  Neue Routen sind jetzt deny-by-default owner-scoped und müssen
# hier ausdrücklich als exakter Public-Discovery-Read eingetragen werden.
_BUG004_CROSS_USER_ROUTE_RULES = (
    (frozenset(('GET', 'HEAD')),
     _bug004_re.compile(r'^/api/user/profile/AT-[A-Za-z0-9_-]+/?$')),
    (frozenset(('GET', 'HEAD')),
     _bug004_re.compile(r'^/api/user/friends/AT-[A-Za-z0-9_-]+/?$')),
)

# Unauthenticated-Routen: laufen BEVOR ein Token existiert (Signup/Login/
# Apple/Forgot/Reset). Diese sind bereits über _BUG004_WHITELIST_PREFIXES
# ('/api/auth/') gedeckt und erreichen das Binding gar nicht erst. Family-
# Pair-Code-/Redeem-Routen existieren in diesem Backend nicht (liegen in den
# AeroX-Blueprints); falls sie hier eingeführt werden, MÜSSEN sie in
# _BUG004_WHITELIST_PREFIXES (nicht hier) als pre-token public eingetragen
# werden, da sie noch kein AT-…-Token tragen.


def _bug004_is_cross_user_route(method, path):
    """True only for an explicitly public cross-user method+route pair."""
    method = (method or '').upper()
    path = path or ''
    for methods, pattern in _BUG004_CROSS_USER_ROUTE_RULES:
        if method in methods and pattern.fullmatch(path):
            return True
    return False


def _request_bearer_token():
    """Extrahiert das Bearer-Token aus dem Authorization-Header. None wenn
    kein/kein-Bearer-Header anliegt."""
    try:
        auth = request.headers.get('Authorization') or ''
    except Exception:
        return None
    if not auth:
        return None
    parts = auth.split(None, 1)
    if len(parts) == 2 and parts[0].lower() == 'bearer':
        tok = parts[1].strip()
        return tok or None
    return None


def _request_bearer_matches(path_token):
    """True wenn ein Authorization-Bearer anliegt UND constant-time gleich
    `path_token` ist. False wenn kein Bearer anliegt oder er nicht passt."""
    bearer = _request_bearer_token()
    if not bearer or not path_token:
        return False
    try:
        return hmac.compare_digest(bearer, path_token)
    except Exception:
        return False


@app.before_request
def _bug004_token_auth_gate():
    """Reject Requests mit gefakeden AT-...-Tokens die nicht in auth_users
    existieren.

    Coverage:
    - POST/PUT/DELETE/PATCH: ALLE Routes mit AT-...-Pattern werden geprüft
      (ausser Whitelist-Prefixes für Auth/Payment/Tax-Job).
    - GET/HEAD: nur Routes die PII zurückgeben (siehe _BUG004_GET_PII_PREFIXES).
      Friend-Discovery-Routes (/profile/, /wall/, /forum/) bleiben offen.
    """
    try:
        method = (request.method or '').upper()
        path = request.path or ''
        # Frühe Whitelist auch für GET-Pfad — public-Endpoints bypassen.
        for prefix in _BUG004_WHITELIST_PREFIXES:
            if path.startswith(prefix):
                return None
        # Welche Methoden kommen ins Gate?
        if method in ('POST', 'PUT', 'DELETE', 'PATCH'):
            requires_check = True
        elif method in ('GET', 'HEAD'):
            requires_check = _bug004_get_route_needs_auth(path)
        else:
            requires_check = False
        if not requires_check:
            return None
        m = _BUG004_TOKEN_PATH_RE.search(path)
        if not m:
            return None  # kein AT-...-Token im Pfad → kein Auth-Gate
        token = m.group(1)
        # Guest-Tokens: explicit pass-through (Route entscheidet selbst)
        if token.startswith('AT-GUEST-'):
            return None
        # Scoped Family-Tokens (AT-FAM-): liegen NICHT in auth_users, sondern in
        # family_scoped_tokens (per Pair-Code gemünzt). Ohne Pass-through gibt das
        # Gate 401 → das gesamte Family→Crew-Feature (feed-status family/…,
        # family-roster) war tot. Pass-through nur wenn der scoped Token gültig auf
        # einen Crew zeigt; die Route validiert/auflöst selbst.
        if token.startswith('AT-FAM-'):
            try:
                from blueprints.family_watch import _scoped_token_crew
                if _scoped_token_crew(token):
                    return None
            except Exception:
                pass
            return jsonify({'ok': False, 'error': 'unauthorized'}), 401
        # Bekanntes Token? — _validate_token_exists nutzt 60s-Cache
        validation = _validate_token(token)
        if validation.state is _TokenValidationState.UNAVAILABLE:
            return _auth_store_unavailable_response()
        if validation.state is _TokenValidationState.INVALID:
            return jsonify({'ok': False, 'error': 'unauthorized'}), 401
        # AUTH-BINDING (BUG-AUDIT 2026-06-07, gehärtet 2026-06-08): Das alte Gate
        # prüfte NUR ob das Pfad-Token in auth_users existiert — es band es NICHT
        # an den authentifizierten Aufrufer. Jeder mit irgendeinem gültigen Bearer
        # (oder, ohne Bearer, mit Kenntnis eines fremden Pfad-Tokens) konnte fremde
        # owner-scoped Pfade ansprechen, solange das Pfad-Token existierte.
        #
        # Zwei Modi, gesteuert über AEROX_REQUIRE_TOKEN_BINDING (default enforce):
        #
        #   ENFORCE  (Default; jeder Wert ausser '0'): Für jede owner-scoped Route (nicht als
        #     exakte Cross-User-Methode/-Route deklariert) MUSS ein
        #     Authorization: Bearer <t>
        #     anliegen und constant-time gleich dem Pfad-Token sein.
        #       - Bearer fehlt        → 401 token_binding_required
        #       - Bearer ≠ Pfad-Token → 401 token_binding_mismatch
        #     Voraussetzung: der iOS-Client sendet den Bearer bereits (parallel
        #     ausgerollt). Solange das nicht flächendeckend ist → Flag AUS lassen.
        #
        #   EMERGENCY LEGACY (nur explizit Flag == '0'): altes Verhalten.
        #       - Bearer anliegend & Mismatch → 401 token_binding_mismatch
        #       - Bearer fehlt                → nur warnen, NICHT blocken
        #         (aktueller iOS-Default für owner-Routen, App bricht sonst).
        if not _bug004_is_cross_user_route(method, path):
            bearer = _request_bearer_token()
            if _BUG004_REQUIRE_TOKEN_BINDING:
                # ENFORCE: Bearer ist Pflicht und muss passen.
                if bearer is None:
                    return jsonify({'ok': False, 'error': 'token_binding_required'}), 401
                if not hmac.compare_digest(bearer, token):
                    return jsonify({'ok': False, 'error': 'token_binding_mismatch'}), 401
            else:
                # LEGACY: nur Mismatch-bei-anliegendem-Bearer blockt.
                if bearer is not None:
                    if not hmac.compare_digest(bearer, token):
                        return jsonify({'ok': False, 'error': 'token_binding_mismatch'}), 401
                else:
                    try:
                        app.logger.warning(
                            f'[bug004-gate] EMERGENCY opt-out owner-route ohne Bearer '
                            f'method={method} user_ref={_push_token_ref(token)}')
                    except Exception:
                        pass
    except Exception as e:
        # UNERWARTETER Gate-Fehler (Bug im Gate selbst, NICHT der bewusst
        # fail-open gehaltene auth_users-Cache-Reload — der lebt in
        # _validate_token_exists und wirft nicht, siehe Fix 2026-07-01
        # „App loggt mich immer wieder aus").
        try:
            app.logger.error(
                f'[bug004-gate] UNEXPECTED gate error {type(e).__name__}: '
                f'{str(e)[:300]} path={_redact_observability_url(request.path)!r} '
                f'method={request.method}',
                exc_info=True)
        except Exception:
            pass
        if _BUG004_REQUIRE_TOKEN_BINDING:
            # ENFORCE-Modus: fail-CLOSED, aber als 503 (nicht 401 — die iOS-App
            # wertet explizite Session-Invalid-Codes als Logout; 503 ist ein
            # transienter Serverfehler und triggert keinen Logout).
            return jsonify({'error': 'auth_gate_error'}), 503
        # LEGACY-Modus (Enforcement aus): pass-through wie bisher — wir dürfen
        # keinen Ausfall verursachen bevor Enforcement überhaupt an ist.
        return None


@app.before_request
def _bug005_before_request():
    try:
        path = request.path or ''
        if any(path.startswith(p) for p in _REQ_LOG_SKIP):
            return
        # In Flask `g` thread-lokal kontext-speichern
        from flask import g as _g
        _g._req_start = _req_time.time()
        _g._req_id = _req_uuid.uuid4().hex[:8]
        tid = _req_threading.get_ident()
        # PID muss bei jedem call frisch geholt werden (gthread teilt PID, threads variieren)
        safe_path = _redact_observability_url(path)
        print(f"{_REQ_LOG_PREFIX} start id={_g._req_id} path={safe_path} method={request.method} pid={os.getpid()} tid={tid}")
    except Exception as _e:
        # Instrumentation darf NIE die App stoppen
        pass


@app.after_request
def _bug005_after_request(response):
    try:
        path = request.path or ''
        if any(path.startswith(p) for p in _REQ_LOG_SKIP):
            return response
        from flask import g as _g
        start = getattr(_g, '_req_start', None)
        rid = getattr(_g, '_req_id', '?')
        if start is None:
            return response
        dur_ms = int((_req_time.time() - start) * 1000)
        tid = _req_threading.get_ident()
        safe_path = _redact_observability_url(path)
        print(f"{_REQ_LOG_PREFIX} done  id={rid} path={safe_path} status={response.status_code} duration_ms={dur_ms} pid={os.getpid()} tid={tid}")
    except Exception:
        pass
    return response


@app.after_request
def _public_cache_headers(response):
    """Kosten-Hebel: Cache-Control auf öffentliche, cachebare GET-Endpunkte der
    APP (kostenlose Nutzer). Clients/CDN liefern Wiederholungen selbst aus →
    weniger Cloud-Run-Requests + Supabase-Reads + Egress. NUR GET 200, nur wenn
    nicht schon gesetzt, nur diese unkritischen Pfade. KEINE Auth-/POST-Routen.
    Avatare: URL ist pro Upload eindeutig (uuid im Dateinamen) → `immutable`."""
    try:
        if request.method != 'GET' or response.status_code != 200:
            return response
        if response.headers.get('Cache-Control'):
            return response
        path = request.path or ''
        cc = None
        if path.startswith('/api/user/avatar/') and path.count('/') >= 4:
            cc = 'public, max-age=31536000, immutable'          # Bild fix pro URL
        elif path.startswith('/api/ax/suggest'):
            cc = 'public, max-age=86400'                        # quasi statisch
        elif (path.startswith('/api/ax/callsign/') or path.startswith('/api/ax/aircraft/')
              or path.startswith('/api/ax/photo/') or path.startswith('/api/ax/route/')):
            cc = 'public, max-age=21600'                        # Route/Foto stabil (6h)
            # Sweep-P3 2026-07-10: own=1/watch=1-Callsign-Antworten (eigener
            # Flieger, darf paid-anreichern) NICHT in den Edge-Cache — der
            # aerox-cdn-Worker cached jede public,max-age-Antwort per URL und
            # würde die (Bearer-gegateten) Paid-Daten anonym ausliefern bzw.
            # den free-Pfad mit abweichenden own-Antworten vergiften. `private`
            # ist der dokumentierte Worker-Opt-out (Regex no-store|private);
            # der Client selbst darf weiter 6h cachen.
            if path.startswith('/api/ax/callsign/') and any(
                    (request.args.get(k) or '').strip().lower()
                    in ('1', 'true', 'yes', 'y')
                    for k in ('own', 'watch', 'mine')):
                cc = 'private, max-age=21600'
        elif path.startswith('/api/ax/schedule/'):
            cc = 'public, max-age=1800'                         # Fahrplan (30 min)
        elif path.startswith('/api/adsb/area'):
            cc = 'public, max-age=20'                           # live, aber CDN-coalesce
        if cc:
            response.headers['Cache-Control'] = cc
    except Exception:
        pass
    return response


@app.after_request
def _security_headers(response):
    """Security-Header (Audit 2026-07-01). setdefault-Semantik: setzt NUR wenn
    nicht schon von der Route/flask-cors gesetzt — clobbert weder CORS-Header
    (Access-Control-* wird hier nicht angefasst) noch Cache-Control
    (_public_cache_headers). Flask führt ALLE after_request-Hooks aus."""
    try:
        h = response.headers
        # Auf allen Responses: MIME-Sniffing aus.
        h.setdefault('X-Content-Type-Options', 'nosniff')
        # Cloud Run ist HTTPS-only → HSTS ist risikofrei.
        h.setdefault('Strict-Transport-Security', 'max-age=31536000; includeSubDomains')
        # Nur auf HTML (Admin-Panel): Clickjacking + minimale CSP. JSON-API-
        # Responses bekommen bewusst KEINE CSP (nutzlos + Header-Bloat).
        ct = (h.get('Content-Type') or '').lower()
        if ct.startswith('text/html'):
            h.setdefault('X-Frame-Options', 'DENY')
            h.setdefault('Content-Security-Policy',
                         "default-src 'self'; img-src 'self' data: https:; "
                         "style-src 'self' 'unsafe-inline'; "
                         "script-src 'self' 'unsafe-inline'; "
                         "frame-ancestors 'none'")
    except Exception:
        pass
    return response


@app.teardown_request
def _bug005_teardown(exc):
    try:
        from flask import g as _g
        rid = getattr(_g, '_req_id', None)
        if not rid:
            return  # nicht instrumentiert
        if exc is None:
            return  # normaler request — schon im after_request geloggt
        start = getattr(_g, '_req_start', None)
        dur_ms = int((_req_time.time() - start) * 1000) if start else -1
        path = (request.path if request else '?') or '?'
        tid = _req_threading.get_ident()
        safe_path = _redact_observability_url(path)
        print(f"{_REQ_LOG_PREFIX} error id={rid} path={safe_path} exc={type(exc).__name__} duration_ms={dur_ms} pid={os.getpid()} tid={tid}")
    except Exception:
        pass


