UPLOAD_TTL_HOURS = 4   # Pre-Upload nur kurz aufbewahren — nach Auswertung gelöscht


class UploadPersistError(Exception):
    """Raised wenn Supabase-Persist der uploaded_files nicht garantiert werden konnte.
    P0 #90 Fix: zwingt Caller zu reagieren statt silent return False zu schlucken."""
    pass


def _save_uploaded_files_supabase(ref, files_dict, hours=UPLOAD_TTL_HOURS):
    """Persist uploaded files to Supabase 'uploaded_files' table.
    files_dict: { key: [(bytes, filename), ...] } oder { key: [bytes, ...] }

    P0 #90 Fix:
    - returnt True bei Erfolg
    - raised UploadPersistError bei jedem Fehler (kein silent return False mehr)
    - safe logging: nur ref[:8], doc_keys, error_type — keine Bytes, kein Base64,
      keine Dateinamen, keine PII

    Idempotent: delete-then-insert für gleichen ref.
    """
    if not SB_AVAILABLE:
        raise UploadPersistError('supabase_unavailable')
    if not ref:
        raise UploadPersistError('missing_ref')
    if not files_dict:
        raise UploadPersistError('empty_files_dict')

    doc_keys = sorted([k for k, v in files_dict.items() if v])
    expires = (datetime.utcnow() + timedelta(hours=hours)).isoformat()
    rows = []
    encode_failures = 0
    for key, items in files_dict.items():
        for idx, item in enumerate(items):
            try:
                data = item[0] if isinstance(item, tuple) else item
                fname = item[1] if isinstance(item, tuple) and len(item) > 1 else f'{key}_{idx}'
                rows.append({
                    'ref':       ref,
                    'key':       key,
                    'idx':       idx,
                    'filename':  fname or f'{key}_{idx}',
                    'data_b64':  base64.b64encode(data).decode(),
                    'expires_at': expires,
                })
            except Exception as e:
                encode_failures += 1
                app.logger.warning(
                    f"[upload-persist] encode_fail ref={ref[:8]} key={key} idx={idx} "
                    f"err={type(e).__name__}"
                )
    if not rows:
        raise UploadPersistError(
            f'all_encode_failed (keys={doc_keys}, failures={encode_failures})'
        )
    try:
        # Erst alte Einträge für ref löschen, dann neu inserten — idempotent.
        sb.table('uploaded_files').delete().eq('ref', ref).execute()
        # In Batches von 5 inserten — JSONB-Rows können groß sein
        for i in range(0, len(rows), 5):
            sb.table('uploaded_files').insert(rows[i:i+5]).execute()
        app.logger.info(
            f"[upload-persist] ok ref={ref[:8]} rows={len(rows)} keys={doc_keys}"
        )
        return True
    except Exception as e:
        app.logger.error(
            f"[upload-persist] supabase_fail ref={ref[:8]} keys={doc_keys} "
            f"err={type(e).__name__}"
        )
        raise UploadPersistError(f'supabase_insert_failed:{type(e).__name__}')


def _load_uploaded_files_supabase(ref):
    """Return {key: [(bytes, filename), ...]} or {} if nothing/expired."""
    if not SB_AVAILABLE or not ref:
        return {}
    try:
        r = sb.table('uploaded_files').select('*').eq('ref', ref).execute()
        if not r.data:
            return {}
        out = {}
        now = datetime.utcnow()
        for row in r.data:
            try:
                exp_str = (row.get('expires_at') or '').replace('Z', '').split('+')[0]
                if datetime.fromisoformat(exp_str) < now:
                    continue
            except: pass
            key = row['key']
            data = base64.b64decode(row['data_b64'])
            fname = row.get('filename') or f"{key}_{row.get('idx',0)}"
            out.setdefault(key, []).append((row.get('idx', 0), data, fname))
        # Sortieren nach idx, dann strip
        return {k: [(d, f) for (_, d, f) in sorted(v)] for k, v in out.items()}
    except Exception as e:
        app.logger.error(
            f"[upload-load] supabase_fail ref={ref[:8]} err={type(e).__name__}"
        )
        return {}


def _delete_uploaded_files_supabase(ref):
    """Cleanup nach erfolgreicher Auswertung — Datenschutz first."""
    if not SB_AVAILABLE or not ref:
        return
    try:
        sb.table('uploaded_files').delete().eq('ref', ref).execute()
    except Exception as e:
        app.logger.warning(
            f"[upload-delete] supabase_fail ref={ref[:8]} err={type(e).__name__}"
        )


@app.route('/api/init-upload-session', methods=['POST'])
def init_upload_session():
    """Erzeugt einen ref-Slot OHNE Stripe — Frontend kann sofort beim Upload Files persistieren.
    Beim späteren /api/create-payment-intent kann derselbe ref reused werden."""
    ref = str(uuid.uuid4())
    _store[ref] = {
        'form':     {},
        'files':    {},
        'paid':     False,
        'expires':  datetime.utcnow() + timedelta(hours=26),  # 24h + Puffer
        'kind':     'preupload',
    }
    return jsonify({'ref': ref})


@app.route('/api/upload-files', methods=['POST'])
def upload_files():
    """Pre-Upload: Frontend lädt Dateien VOR der Bezahlung hoch, damit sie bei
    3DS-Redirect oder Reload nicht verloren gehen. Files in _store[ref]['files'].
    """
    ref = request.form.get('ref', '').strip()
    if not ref or ref not in _store:
        return jsonify({'error': 'ref not found'}), 404

    saved_count = 0
    for key in _ALL_FILE_KEYS:
        files = request.files.getlist(key)
        if files:
            normalized = []
            for f in files:
                try:
                    # _normalize_upload liefert bereits (bytes, filename) als Tupel
                    normalized.append(_normalize_upload(f.read(), f.filename))
                    saved_count += 1
                except Exception as e:
                    app.logger.warning(
                        f"[upload-files] normalize_fail ref={ref[:8]} key={key} "
                        f"err={type(e).__name__}"
                    )
            if normalized:
                _store[ref]['files'][key] = normalized

    # P0 #90 Fix: Persistenz-Fehler MUSS sichtbar sein. Frontend darf erst zum
    # Bezahl-Schritt wechseln wenn Supabase-Persist bestätigt ist — sonst riskiert
    # User Geldverlust (zahlt + Files weg).
    if _store[ref].get('files'):
        try:
            _save_uploaded_files_supabase(ref, _store[ref]['files'])
        except UploadPersistError as e:
            ec = AEROTAX_ERROR_CODES['UPLOAD_PERSIST_FAILED']
            app.logger.error(
                f"[upload-files] persist_failed ref={ref[:8]} err={type(e).__name__}"
            )
            return jsonify({
                'ok':           False,
                'reason_code':  'UPLOAD_PERSIST_FAILED',
                'user_title':   ec['user_title'],
                'user_message': ec['user_message'],
                'retryable':    ec['retryable'],
                'support':      ec['support'],
                'next_actions': ec.get('next_actions', []),
            }), 503

    app.logger.info(f"[upload-files] ok ref={ref[:8]} count={saved_count}")
    return jsonify({'status': 'ok', 'count': saved_count})


_processed_stripe_events = {}  # event_id → timestamp; Idempotenz für Webhooks
# P0 #96: in-memory cache ist nur noch L1 — Source-of-Truth ist Supabase-Tabelle
# `payment_intent_consumptions`. Cache short-circuits Lookups; bei cache-miss wird
# atomar gegen Supabase geclaimt.
_consumed_payment_intents = {}  # pi_id → consumed_at  (L1-Cache, NICHT Source-of-Truth)
_ip_rate_buckets = {}  # ip → list[ts]; rolling window 1h für /api/process Anti-Abuse


# ─── P0 #96: PaymentIntent atomic claim via Supabase ─────────────────────────

def _try_consume_payment_intent_supabase(pi_id, ref=None, job_id=None):
    """Atomic claim eines PaymentIntent via Supabase-Tabelle
    `payment_intent_consumptions`. Multi-Container-safe: Primary-Key auf
    payment_intent_id garantiert dass nur 1 Container je PI claimen kann.

    Returns (outcome, existing_record):
      ('claimed',          None):           erster Erfolg — Caller darf processen
      ('already_used',     record_dict):    PI war schon verbraucht (existing-row)
      ('lock_unavailable', None):           Supabase down / Tabelle fehlt /
                                            Network-Fehler — Caller MUSS für
                                            paid PIs fail-closed reagieren
    """
    if not pi_id:
        return ('lock_unavailable', None)
    if not SB_AVAILABLE:
        app.logger.error(f"[pi-lock] supabase_unavailable pi={pi_id[:12]}")
        return ('lock_unavailable', None)
    try:
        sb.table('payment_intent_consumptions').insert({
            'payment_intent_id': pi_id,
            'ref':               ref or None,
            'job_id':            job_id,
            'status':            'claimed',
        }).execute()
        app.logger.info(
            f"[pi-lock] claimed pi={pi_id[:12]} ref={(ref or '')[:8]} "
            f"job={(job_id or '')[:8]}"
        )
        return ('claimed', None)
    except Exception as e:
        msg = str(e)
        msg_lower = msg.lower()
        is_conflict = (
            '23505' in msg
            or 'duplicate key' in msg_lower
            or 'unique constraint' in msg_lower
            or 'unique violation' in msg_lower
        )
        if is_conflict:
            try:
                r = sb.table('payment_intent_consumptions') \
                      .select('*').eq('payment_intent_id', pi_id).limit(1).execute()
                existing = (r.data or [None])[0]
                app.logger.warning(
                    f"[pi-lock] already_used pi={pi_id[:12]} "
                    f"existing_job={(existing or {}).get('job_id', '')[:8] if existing else ''}"
                )
                return ('already_used', existing)
            except Exception as _se:
                app.logger.error(
                    f"[pi-lock] existing_lookup_fail pi={pi_id[:12]} "
                    f"err={type(_se).__name__}"
                )
                return ('already_used', None)
        # Kein Conflict → echtes Lock-Problem (Supabase down, schema missing, etc.)
        app.logger.error(
            f"[pi-lock] insert_fail pi={pi_id[:12]} err={type(e).__name__}"
        )
        return ('lock_unavailable', None)


def _update_payment_intent_lock_status(pi_id, status, job_id=None):
    """Aktualisiert den Lock-Row-Status nach Job-Lifecycle-Events.
    Wird aus `_set_job_failed` + Done-Path aufgerufen. Best-Effort — kein Raise.

    status: 'claimed', 'failed_retryable', 'failed_support', 'done'
    """
    if not pi_id or not SB_AVAILABLE:
        return
    try:
        payload = {'status': status}
        if job_id:
            payload['job_id'] = job_id
        sb.table('payment_intent_consumptions') \
          .update(payload).eq('payment_intent_id', pi_id).execute()
    except Exception as e:
        app.logger.warning(
            f"[pi-lock] status_update_fail pi={pi_id[:12]} status={status} "
            f"err={type(e).__name__}"
        )


def _atomic_write_json(path, data, max_items=None, **json_kwargs):
    """Atomares Schreiben: temp-file → fsync → os.replace.
    Verhindert halb-geschriebene Dateien bei Container-Crash + race-conditions
    bei parallelen Writes (POSIX-Garantie: rename ist atomic).
    Optional: cap der Liste auf max_items (älteste raus). Zusätzliche kwargs
    werden an json.dump weitergereicht (z.B. indent=2, default=str).
    Default-ensure_ascii=False außer override.
    """
    if max_items is not None and isinstance(data, list):
        data = data[-max_items:]
    json_kwargs.setdefault('ensure_ascii', False)
    target_dir = os.path.dirname(path) or '.'
    os.makedirs(target_dir, exist_ok=True)
    fd, tmp_path = tempfile.mkstemp(prefix='.tmp_', dir=target_dir)
    try:
        with os.fdopen(fd, 'w') as f:
            json.dump(data, f, **json_kwargs)
            f.flush()
            os.fsync(f.fileno())
        os.replace(tmp_path, path)
    except Exception:
        try: os.remove(tmp_path)
        except Exception: pass
        raise


def _is_private_or_local_ip(host):
    """Returns True wenn host eine private/loopback/link-local-IP ist.
    Schützt gegen SSRF gegen interne Services (169.254 metadata, 10.x, etc.).
    """
    import ipaddress, socket
    try:
        # Hostname auflösen (IDN-safe)
        candidates = []
        try:
            infos = socket.getaddrinfo(host, None, family=socket.AF_UNSPEC)
            for info in infos:
                ip_str = info[4][0]
                candidates.append(ipaddress.ip_address(ip_str))
        except Exception:
            # Hostname kann auch direkt eine IP sein
            candidates.append(ipaddress.ip_address(host))
        for ip in candidates:
            if (ip.is_private or ip.is_loopback or ip.is_link_local or
                ip.is_multicast or ip.is_reserved or ip.is_unspecified):
                return True
        return False
    except Exception:
        # Wenn DNS fehlschlägt, lieber blockieren als zulassen
        return True


def _token_rate_limited(token, endpoint, limit, window_sec):
    """Rate-Limit pro User-Token (statt IP, da hinter NAT mehrere User).
    Returns True wenn Limit erreicht. Shared Bucket-Dict mit _ip_rate_limited."""
    if not token: return False
    now = datetime.utcnow().timestamp()
    cutoff = now - window_sec
    key = f'tok:{token}:{endpoint}'
    bucket = _ip_rate_buckets.setdefault(key, [])
    bucket[:] = [t for t in bucket if t > cutoff]
    if len(bucket) >= limit:
        return True
    bucket.append(now)
    return False


def _ip_rate_limited(ip, endpoint='process', limit=20, window_sec=3600):
    """Sliding-Window Rate-Limit pro IP. Liefert True wenn limit überschritten.
    Default: 20 Versuche pro Stunde pro IP für /api/process. Stripe-Payment ist
    der primäre Anti-Abuse-Layer (kostet Geld); IP-Limit fängt nur Brute-Force
    auf das Endpoint selbst (z.B. Promo-Code-Raten) ab."""
    if not ip: return False
    now = datetime.utcnow().timestamp()
    cutoff = now - window_sec
    key = f'{ip}:{endpoint}'
    bucket = _ip_rate_buckets.setdefault(key, [])
    # Alte Entries räumen + Cleanup wenn dict zu groß (>10000 keys)
    bucket[:] = [t for t in bucket if t > cutoff]
    if len(_ip_rate_buckets) > 10000:
        for k in list(_ip_rate_buckets.keys())[:5000]:
            _ip_rate_buckets.pop(k, None)
    if len(bucket) >= limit:
        return True
    bucket.append(now)
    return False


def _client_ip():
    """Extrahiert Client-IP hinter Cloudflare. CF-Connecting-IP ist der vom Proxy
    gesetzte, vertrauenswürdige Header. In X-Forwarded-For hängt der Proxy die
    echte IP hinten AN — das ERSTE Element ist Client-kontrolliert (Spoof-Prefix
    würde das Rate-Limit umgehen) → LETZTES Element nehmen.

    Hetzner-Tunnel-Kette (Sweep-P3 2026-07-10, per Worker-Code verifiziert):
    Client → CF-Edge (aerox-cdn-Worker) → fetch hetzner-api-Tunnel → cloudflared
    → gunicorn. Der Worker baut Subrequests mit `headers: request.headers`,
    reicht CF-Connecting-IP also 1:1 weiter — der Normalfall trifft Zweig 1.
    Dokumentierte Fallback-Kette, falls ein Hop den Header doch verschluckt
    (z.B. künftige Worker-Änderung / Direkt-Zugriff am Tunnel):
      1. CF-Connecting-IP  (CF-gesetzt bzw. vom Worker durchgereicht)
      2. X-Real-IP         (Reverse-Proxy-Konvention, z.B. nginx/cloudflared)
      3. X-Forwarded-For   LETZTES Element (nur das hat der letzte vertrauens-
                           würdige Hop angehängt; erstes Element = spoofbar)
      4. remote_addr       (Direktverbindung)"""
    cf = (request.headers.get('CF-Connecting-IP', '') or '').strip()
    if cf:
        return cf
    xri = (request.headers.get('X-Real-IP', '') or '').strip()
    if xri:
        return xri
    xff = request.headers.get('X-Forwarded-For', '')
    if xff:
        return xff.split(',')[-1].strip()
    return request.remote_addr or ''


# ── Durable Auth-Rate-Limits (Audit 2026-07-01) ─────────────────────────────
# _ip_rate_limited/_token_rate_limited sind PER-INSTANZ (Cloud Run skaliert →
# jeder Container zählt für sich; Restart = Reset). Für die Auth-Routen
# (Brute-Force/Enumeration/Mail-Bombing) wird ZUSÄTZLICH das Supabase-durable
# Sliding-Window aus rate_limits/ benutzt. Eigenschaften:
#   - FAIL-OPEN: Supabase down/Tabelle fehlt → _sb_get_bucket liefert (now, 0)
#     → nie ein Login wegen des Limiter-Stores blockiert.
#   - EIN blockierender Supabase-Roundtrip pro Auth-Versuch (der GET); das
#     Increment läuft fire-and-forget über _SB_TIMEOUT_EXECUTOR.
#   - Identifier werden gehasht (kein E-Mail-/IP-Klartext in der Tabelle).
# rate_limits/config.py liest SUPABASE_KEY/SUPABASE_SERVICE_ROLE_KEY — dieses
# Backend setzt aber SUPABASE_SERVICE_KEY. Alias mappen (nur wenn unbelegt),
# sonst fällt das Package still auf seinen In-Memory-Fallback zurück.
if os.environ.get('SUPABASE_SERVICE_KEY') and not (
        os.environ.get('SUPABASE_KEY') or os.environ.get('SUPABASE_SERVICE_ROLE_KEY')):
    os.environ['SUPABASE_KEY'] = os.environ['SUPABASE_SERVICE_KEY']
try:
    from rate_limits import config as _rl_durable
except Exception as _rl_imp_err:  # Package kaputt → Feature aus, Auth läuft weiter
    print(f'[auth-rl] rate_limits import failed — durable limits OFF: {_rl_imp_err}')
    _rl_durable = None

# Limits gespiegelt an den bestehenden In-Memory-Checks (gleiche Größenordnung,
# leicht großzügiger, damit der durable Layer nie STRENGER ist als das heutige
# Verhalten auf einer Single-Instanz).
_DURABLE_AUTH_SCOPES = {
    'auth_login_ip':    {'limit': 30, 'window_sec': 600},
    'auth_signup_ip':   {'limit': 15, 'window_sec': 3600},
    'auth_forgot_email': {'limit': 5, 'window_sec': 600},
}


def _durable_auth_rate_limited(identifier, scope):
    """True wenn das Supabase-durable Fenster für (identifier, scope) voll ist.
    Fail-open bei JEDEM Fehler (Import fehlt, SB down, Tabelle fehlt)."""
    if _rl_durable is None or not identifier:
        return False
    cfg = _DURABLE_AUTH_SCOPES.get(scope)
    if not cfg:
        return False
    try:
        import hashlib as _hl
        key = 'rl-' + _hl.sha256(f'{scope}:{identifier}'.encode('utf-8')).hexdigest()[:32]
        now = int(time.time())
        window_sec = cfg['window_sec']
        # 1 blockierender Roundtrip: GET (1.5s Timeout, fail-open in rate_limits)
        ws, count = _rl_durable._sb_get_bucket(key, scope, window_sec, now)
        if now - ws >= window_sec:
            ws, count = now, 0
        # Increment asynchron — kein zweiter blockierender Roundtrip im Request.
        try:
            _SB_TIMEOUT_EXECUTOR.submit(
                _rl_durable._sb_upsert_bucket, key, scope, window_sec, ws, count + 1)
        except Exception:
            pass
        if count >= cfg['limit']:
            print(f'[auth-rl] durable limit hit scope={scope} count={count}')
            return True
    except Exception as e:
        # NIE Logins blockieren weil der Limiter-Store zickt.
        print(f'[auth-rl] durable check error (fail-open): {type(e).__name__}: {e}')
    return False

@app.route('/api/stripe-webhook', methods=['POST'])
def stripe_webhook():
    """Markiert _store[ref].paid=True. Auswertung selbst läuft NICHT hier — der
    Frontend-Flow ruft /api/process direkt auf nach Payment-Element Erfolg.
    Webhook bleibt als Backup / Confirmation bestehen."""
    payload = request.get_data()
    sig     = request.headers.get('Stripe-Signature', '')

    if not WEBHOOK_SECRET:
        return jsonify({'error': 'Stripe Webhook Secret fehlt.'}), 500

    try:
        event = stripe.Webhook.construct_event(payload, sig, WEBHOOK_SECRET)
    except Exception as e:
        print(f'[stripe_webhook] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'error': 'webhook_signature_verification_failed'}), 400

    # Idempotenz: gleicher Webhook-Event nur 1x verarbeiten
    eid = event.get('id', '')
    if eid and eid in _processed_stripe_events:
        return jsonify({'status': 'ok', 'idempotent': True})
    if eid:
        # Alte Einträge >1h aufräumen
        cutoff = datetime.utcnow() - timedelta(hours=1)
        for k, ts in list(_processed_stripe_events.items()):
            if ts < cutoff:
                _processed_stripe_events.pop(k, None)
        _processed_stripe_events[eid] = datetime.utcnow()

    if event['type'] in ('checkout.session.completed', 'payment_intent.succeeded'):
        obj = event['data']['object']
        ref = (obj.get('metadata') or {}).get('ref', '')
        if ref and ref in _store:
            _store[ref]['paid'] = True
            print(f"[stripe-webhook] ref {ref[:8]} marked paid via {event['type']}")

    return jsonify({'status': 'ok'})


@app.route('/api/status/<ref>', methods=['GET'])
def check_status(ref):
    entry = _store.get(ref)
    if not entry:
        return jsonify({'status': 'not_found'}), 404
    if entry.get('dl_token'):
        return jsonify({'status': 'ready',
                        'download_url': f'/api/download/{entry["dl_token"]}'})
    elif entry.get('paid'):
        return jsonify({'status': 'processing'})
    else:
        return jsonify({'status': 'pending'})


PDF_TTL_HOURS = 24

def _save_pdf(token, pdf_bytes, filename, hours=PDF_TTL_HOURS):
    """Persist PDF in Supabase + In-Memory _store. Beide Wege werden versucht."""
    expires = datetime.utcnow() + timedelta(hours=hours)
    _store[token] = {
        'pdf_bytes': pdf_bytes,
        'filename':  filename,
        'expires':   expires,
    }
    if SB_AVAILABLE:
        try:
            sb.table('pdfs').upsert({
                'token':      token,
                'filename':   filename,
                'pdf_b64':    base64.b64encode(pdf_bytes).decode(),
                'expires_at': expires.isoformat(),
            }).execute()
        except Exception as e:
            print(f"[supabase] pdf save fail: {e}")


def _load_pdf(token):
    """In-Memory zuerst, dann Supabase. Returns (bytes, filename, expires) or None.

    B-5 P1 Fix: 5s Timeout auf Supabase-Query — vorher konnte hängender PDF-Load
    den /api/download-Endpoint 30s+ blockieren."""
    entry = _store.get(token)
    if entry and entry.get('pdf_bytes'):
        return entry['pdf_bytes'], entry.get('filename') or 'AeroTax_Auswertung.pdf', entry.get('expires')
    if SB_AVAILABLE:
        def _do_pdf_load(): return sb.table('pdfs').select('*').eq('token', token).limit(1).execute()
        r, timed_out = _supabase_execute_with_timeout(
            f'_load_pdf({token[:12]})', _do_pdf_load, timeout_s=5)
        if timed_out:
            return None
        try:
            if r is not None and r.data:
                row = r.data[0]
                exp = None
                try:
                    exp_str = (row.get('expires_at') or '').replace('Z', '').split('+')[0]
                    exp = datetime.fromisoformat(exp_str)
                    if exp < datetime.utcnow():
                        return None
                except: pass
                # downloaded_at aus Supabase mit übernehmen — sonst Replay-Schutz nach Worker-Restart wirkungslos
                downloaded_at = None
                try:
                    da_str = (row.get('downloaded_at') or '').replace('Z', '').split('+')[0]
                    if da_str:
                        downloaded_at = datetime.fromisoformat(da_str)
                except: pass
                pdf_bytes = base64.b64decode(row['pdf_b64'])
                # In-Memory cachen inklusive downloaded_at
                _store[token] = {
                    'pdf_bytes':     pdf_bytes,
                    'filename':      row.get('filename'),
                    'expires':       exp,
                    'downloaded_at': downloaded_at,
                }
                return pdf_bytes, row.get('filename') or 'AeroTax_Auswertung.pdf', exp
        except Exception as e:
            print(f"[supabase] pdf load fail: {e}")
    return None


@app.route('/api/download/<token>', methods=['GET'])
def download_pdf(token):
    res = _load_pdf(token)
    if not res:
        abort(404)
    pdf_bytes, filename, expires = res
    if expires and datetime.utcnow() > expires:
        abort(410)
    # Replay-Schutz: nach 1. erfolgreichem Download Token markieren
    # Cache-Header: kein Caching durch Browser/CDN damit zweiter Klick wirklich Backend trifft
    entry = _store.get(token) or {}
    if entry.get('downloaded_at'):
        # Innerhalb von 60s den Re-Click erlauben (User klickt manchmal 2x), danach blocken
        try:
            dl_at = entry['downloaded_at']
            if isinstance(dl_at, str):
                dl_at = datetime.fromisoformat(dl_at.replace('Z',''))
            if (datetime.utcnow() - dl_at).total_seconds() > 60:
                print(f"[download] token {token[:8]}: blocked re-download (>60s nach 1. Download)")
                abort(410)
        except: pass
    # PDF-Download = finaler Bescheid → Edit-Token verbrauchen + Download-Marker setzen
    try:
        sess_tok = entry.get('session_token')
        if sess_tok:
            _mark_session_consumed(sess_tok)
        _store.setdefault(token, {})['downloaded_at'] = datetime.utcnow()
        # Auch in Supabase persistieren falls möglich
        if SB_AVAILABLE:
            try:
                sb.table('pdfs').update({'downloaded_at': datetime.utcnow().isoformat()}).eq('token', token).execute()
            except Exception as _se:
                pass  # downloaded_at-Spalte könnte fehlen, in-memory reicht für 60s-Fenster
    except Exception as e:
        print(f"[download] consume-mark fail: {e}")
    response = send_file(
        io.BytesIO(pdf_bytes),
        mimetype='application/pdf',
        as_attachment=True,
        download_name=filename,
    )
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response


def _mark_session_consumed(token):
    """Markiert Session als final (nach PDF-Download). Restore wird damit blockiert."""
    s = _load_session(token)
    if not s: return
    rd = s.get('result_data') or {}
    if rd.get('_consumed_at'): return  # bereits consumed
    rd['_consumed_at'] = datetime.utcnow().isoformat() + 'Z'
    s['result_data'] = rd
    _save_session(token, s)
    print(f"[session] {token[:8]}... consumed (PDF downloaded)")


@app.route('/api/restore-session/<token>', methods=['POST'])
def restore_session(token):
    """User gibt AT-Code ein → bekommt Form-Werte zurück + Free-Retry-Token, kann
    Files erneut hochladen ohne erneut zu zahlen. PDF-Download invalidiert das.
    """
    token = (token or '').strip().upper()
    if not token.startswith('AT-'):
        return jsonify({'error': 'Ungültiges Code-Format'}), 400
    s = _load_session(token)
    if not s:
        return jsonify({'error': 'Code abgelaufen oder ungültig (24h-Frist)'}), 404
    rd = s.get('result_data') or {}
    if rd.get('_consumed_at'):
        return jsonify({
            'error': 'Code bereits verbraucht — du hast die Auswertung als PDF heruntergeladen. '
                     'Eine neue Berechnung erfordert Neukauf.',
            'consumed': True,
        }), 410
    form_inputs = rd.get('_form_inputs') or {}
    if not form_inputs:
        return jsonify({'error': 'Keine speicherbaren Form-Werte gefunden — Session zu alt.'}), 422

    # Free-Retry-Token vergeben (60 Min Fenster für Neuberechnung)
    info = _recovery_tokens.get(token, {}) or _load_recovery_token_from_supabase(token) or {}
    _rt_payload = {
        'token': token,
        'retries_used': int(info.get('retries_used', 0)),  # nicht hochzählen — Edit ≠ Recovery
        'expires': (datetime.utcnow() + timedelta(minutes=60)).isoformat() + 'Z',
        'kind': 'edit',
    }
    _recovery_tokens[token] = _rt_payload
    # P1 #111: Multi-Container-Safe via Supabase
    _save_recovery_token_to_supabase(token, _rt_payload)
    return jsonify({
        'ok': True,
        'form_inputs':      form_inputs,
        'free_retry_token': token,
        'message': 'Du kannst jetzt deine Dateien erneut hochladen und neu berechnen — kostenlos.',
    })


# Demo ohne Zahlung (gibt Fallback-Werte zurück)
@app.route('/api/demo', methods=['POST'])
def demo():
    """Demo — uses provided data or generates random Max Mustermann values."""
    import random
    # Check if client sent fixed data
    req = request.get_json(silent=True) or {}
    
    if req.get('name') == 'Max Mustermann' and req.get('km'):
        # Use the exact data sent by frontend
        r_data = req
        km = float(r_data.get('km', 22))
        fahr_tage = int(r_data.get('fahr_tage', 62))
        arbeitstage = int(r_data.get('arbeitstage', 140))
        hotel_naechte = int(r_data.get('hotel_naechte', 72))
        vma_72 = float(r_data.get('vma_72', 84))
        vma_73 = float(r_data.get('vma_73', 196))
        vma_74 = float(r_data.get('vma_74', 56))
        vma_in = float(r_data.get('vma_in', 336))
        vma_aus = float(r_data.get('vma_aus', 5180))
        fahr = float(r_data.get('fahr', 598.40))
        reinig = float(r_data.get('reinig', 224.00))
        trink = float(r_data.get('trink', 259.20))
        gesamt = float(r_data.get('gesamt', 6597.60))
        ag_z17 = float(r_data.get('ag_z17', 280))
        spesen_g = float(r_data.get('spesen_gesamt', 5920))
        spesen_s = float(r_data.get('spesen_steuer', 1340))
        z77 = float(r_data.get('z77', 4580))
        netto = float(r_data.get('netto', 1737.60))
        name = 'Max Mustermann'
    else:
        # Generate random values
        r = lambda a, b: round(random.uniform(a, b), 2)
        ri = lambda a, b: random.randint(a, b)
        km = ri(15, 60); fahr_tage = ri(45, 70); arbeitstage = ri(110, 150)
        hotel_naechte = ri(50, 80)
        vma_72 = ri(3, 8) * 14; vma_73 = ri(8, 15) * 14; vma_74 = ri(0, 2) * 28
        vma_in = vma_72 + vma_73 + vma_74; vma_aus = r(3500, 6000)
        fahr = round(min(km,20)*fahr_tage*0.30 + max(0,km-20)*fahr_tage*0.38, 2)
        reinig = round(arbeitstage * 1.60, 2); trink = round(hotel_naechte * 3.60, 2)
        gesamt = round(fahr + reinig + trink + vma_in + vma_aus, 2)
        ag_z17 = r(200, 450); spesen_g = r(4000, 7000); spesen_s = r(800, 2000)
        z77 = round(spesen_g - spesen_s, 2); netto = round(gesamt - ag_z17 - z77, 2)
        name = 'Max Mustermann'
    r = lambda a,b: round((a+b)/2, 2)  # safe fallback
    result = {
        'name': name,
        'year': 2025,
        'datum': datetime.now().strftime('%d.%m.%Y'),
        'km': km, 'fahr_tage': fahr_tage,
        'arbeitstage': arbeitstage, 'hotel_naechte': hotel_naechte,
        'vma_72_tage': vma_72//14, 'vma_73_tage': vma_73//14,
        'vma_74_tage': vma_74//28 if vma_74 else 0,
        'vma_72': vma_72, 'vma_73': vma_73, 'vma_74': vma_74,
        'vma_in': vma_in, 'vma_aus': vma_aus,
        'fahr': fahr, 'reinig': reinig, 'trink': trink,
        'gesamt': gesamt, 'ag_z17': ag_z17,
        'spesen_gesamt': spesen_g, 'spesen_steuer': spesen_s,
        'z77': z77, 'netto': netto,
        'brutto': 54200.00, 'lohnsteuer': 7980.00,
        'arbeitgeber': 'Deutsche Lufthansa AG',
        'uploaded_summary': 'Demo-Modus — keine echten Dokumente',
        '_isDemo': True,
        'not_uploaded': '',
        'abrechnungen': [
            {'erstellt': f'{mon:02d}.2025', 'bezeichnung': f'Monat {mon}',
             'gesamt': round(spesen_g/12, 2),
             'steuerpflichtig': round(spesen_s/12, 2),
             'steuerfrei': round((spesen_g-spesen_s)/12, 2)}
            for mon in range(1, 13)
        ],
    }

    pdf   = erstelle_pdf(result)
    token = str(uuid.uuid4())
    _save_pdf(token, pdf, 'AeroTax_Auswertung_Demo_2025.pdf', hours=1)
    safe = {k: v for k, v in result.items()
            if isinstance(v, (int, float, str))}
    return jsonify({'status':'ready',
                    'download_url': f'/api/download/{token}',
                    'data': safe})


# ── BILD-NORMALISIERUNG (HEIC/WEBP/etc → JPEG) + DOWNSCALE ─────
# Task B (v10.4.2): iPhone-Fotos sind oft 4032×3024 (~30 MB decoded RAM).
# Wir scalen auf max 1500px max-Dim runter — Sonnet braucht die Auflösung
# nicht und der RAM-Druck auf Render Free-Tier sinkt deutlich. PDFs bleiben
# unangetastet. EXIF-Rotation wird angewandt (iPhone speichert oft sideways).
_IMAGE_MAX_DIM = 1500
_IMAGE_JPEG_QUALITY = 88


def _normalize_upload(file_bytes, filename=''):
    """Konvertiert exotische Bildformate zu JPEG + downscaled große Bilder.

    Regeln:
      - PDF: immer unverändert
      - HEIC/HEIF/WEBP/TIFF: → JPEG (mit Downscale wenn nötig)
      - JPEG/PNG:
         · wenn max(width,height) > 1500 → Downscale + JPEG-Re-Save
         · wenn EXIF-Orientation ≠ 1 → orientation-fix + JPEG-Re-Save
         · sonst unverändert (kein Quality-Loss)
      - Returns (bytes, filename)
    """
    if not file_bytes:
        return file_bytes, filename
    ext = filename.lower().rsplit('.', 1)[-1] if '.' in filename else ''

    # PDF: NIEMALS anfassen
    if file_bytes[:4] == b'%PDF' or ext == 'pdf':
        return file_bytes, filename

    if not PIL_AVAILABLE:
        return file_bytes, filename

    try:
        from PIL import ImageOps as _IOps
        img = Image.open(io.BytesIO(file_bytes))
        original_size = img.size

        # EXIF-Orientation anwenden (iPhone-Photos sind oft EXIF-rotated)
        try:
            exif = img.getexif() if hasattr(img, 'getexif') else None
            had_exif_rotation = bool(exif and exif.get(0x0112, 1) != 1)
        except Exception:
            had_exif_rotation = False
        img = _IOps.exif_transpose(img)

        # Downscale wenn zu groß
        needs_resize = max(img.size) > _IMAGE_MAX_DIM
        if needs_resize:
            img.thumbnail((_IMAGE_MAX_DIM, _IMAGE_MAX_DIM), Image.Resampling.LANCZOS)

        # Format-Konvertierung nötig?
        is_jpeg = file_bytes[:3] == b'\xff\xd8\xff'
        is_png = file_bytes[:8] == b'\x89PNG\r\n\x1a\n'
        needs_convert = not (is_jpeg or is_png)  # HEIC/WEBP/TIFF etc.

        # Wenn weder Resize noch Convert noch EXIF-Rotation: original lassen
        # (vermeidet unnötige JPEG-Re-Compression)
        if not (needs_resize or needs_convert or had_exif_rotation):
            return file_bytes, filename

        buf = io.BytesIO()
        img.convert('RGB').save(buf, format='JPEG',
                                  quality=_IMAGE_JPEG_QUALITY, optimize=True)
        new_bytes = buf.getvalue()

        # Neuer Filename
        if needs_convert:
            new_name = (filename.rsplit('.', 1)[0] + '.jpg') if '.' in filename else (filename or 'image') + '.jpg'
        else:
            new_name = filename or 'image.jpg'

        action = []
        if needs_resize: action.append(f'resize {original_size}→{img.size}')
        if needs_convert: action.append(f'convert {ext or "?"}→jpg')
        if had_exif_rotation: action.append('exif-rotate')
        print(f"[image-normalize] {filename}: {', '.join(action)} | "
              f"{len(file_bytes)//1024}KB → {len(new_bytes)//1024}KB")
        return new_bytes, new_name

    except Exception as e:
        print(f"[image-normalize] fehlgeschlagen für {filename}: {e}")
        return file_bytes, filename


# ── PROCESS MIT ECHTEN PDFs ────────────────────────────────────
# Wird vom Frontend aufgerufen wenn echte Dokumente hochgeladen werden
# Unterstützt: Free Promo Code + Paid Flow (nach Webhook)
# ── ASYNC JOB STORE + PERSISTENZ ───────────────────────────────
# In-Memory Job-Store für schnellen Zugriff, plus Disk-Persistierung für Restart-Resilience.
_jobs = {}
_jobs_lock = __import__('threading').RLock()
# BUG-012 #17: RLock statt Lock — re-entrant für selben Thread.
# Vorher konnte ein Handler `with _jobs_lock:` haben und intern `_save_job_to_disk`
# rufen, das selbst `with _jobs_lock:` macht → Deadlock mit threading.Lock.
# RLock ist re-entrant: gleicher Thread kann den Lock mehrfach acquiren ohne
# zu blocken (acquire-counter wird inkrementiert). Multi-Thread-Safety bleibt
# gewährleistet — andere Threads warten wie vorher.
_JOBS_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'jobs_state')
os.makedirs(_JOBS_DIR, exist_ok=True)

# ── WARTESCHLANGE ──────────────────────────────────────────────
# Verhindert dass mehrere Auswertungen parallel laufen → schützt vor OOM auf Free-Tier.
# 1 Worker-Thread zieht Jobs sequenziell aus der Queue. Andere User warten in Position 2,3,...
import queue as _stdqueue
_calc_queue = _stdqueue.Queue()
_calc_running_id = None
_calc_worker_started = False
# Geschätzte Zeit pro Job in Sekunden (für ETA-Berechnung im Frontend)
_AVG_JOB_SECONDS = 150


def _get_queue_position(job_id):
    """Gibt die 1-basierte Queue-Position zurück. 1 = wird gerade gerechnet bzw als Nächstes.
    None wenn nicht in Queue (vermutlich schon fertig oder läuft gerade).
    Atomar gegen race conditions: wir snapshoten beide Werte unter Lock.
    """
    with _jobs_lock:
        running = _calc_running_id
        snap = list(_calc_queue.queue)
    if running == job_id:
        return 1
    pos = 1 if running else 0
    for entry in snap:
        if entry[0] == job_id:
            return pos + 1
        pos += 1
    return None


def _release_memory_to_os():
    """Forciert Python-Allocator Speicher tatsächlich an OS zurückzugeben (Linux/glibc).
    Standardmäßig hält Python freigegebenen RAM intern für Reuse — auf Render Free
    wirkt das dann nach OUTSIDE wie Memory-Leak. malloc_trim(0) räumt das auf."""
    try:
        import ctypes
        ctypes.CDLL("libc.so.6").malloc_trim(0)
    except Exception:
        pass  # Mac/Windows oder kein libc — egal


# ════════════════════════════════════════════════════════════════════════════
# v13 Cloud Tasks Worker — saubere Architektur für Cloud Run
# ════════════════════════════════════════════════════════════════════════════
# Problem: Cloud Run zählt nur aktive HTTP-Requests. Background-Threads gehen
# in SIGTERM nach dem Request-Return.
#
# Lösung: Worker läuft SYNCHRON im /api/internal/process-job HTTP-Request.
# /api/process erstellt nur den Job + dispatcht einen Cloud Task. Der Cloud
# Task ruft /api/internal/process-job auf, das hält die Connection offen
# bis die Berechnung fertig ist.
#
# Mode-Switch via ENV AEROTAX_EXECUTION_MODE:
#   - 'thread'      → Background-Thread (Default, lokal/dev/Render-Legacy)
#   - 'cloud_tasks' → Cloud Tasks Enqueue → Worker-Endpoint (Cloud Run)
# ════════════════════════════════════════════════════════════════════════════

AEROTAX_EXECUTION_MODE = os.environ.get('AEROTAX_EXECUTION_MODE', 'thread').lower()
AEROTAX_TASKS_QUEUE = os.environ.get('AEROTAX_TASKS_QUEUE', 'aerotax-jobs')
AEROTAX_TASKS_LOCATION = os.environ.get('AEROTAX_TASKS_LOCATION', 'europe-west3')
AEROTAX_GCP_PROJECT = os.environ.get('AEROTAX_GCP_PROJECT', 'aerotax-prod')
AEROTAX_CLOUD_RUN_WORKER_URL = os.environ.get('AEROTAX_CLOUD_RUN_WORKER_URL', '').rstrip('/')
AEROTAX_TASK_INVOKER_SA = os.environ.get(
    'AEROTAX_TASK_INVOKER_SA',
    'aerotax-task-invoker@aerotax-prod.iam.gserviceaccount.com'
)


def _enqueue_cloud_task(job_id, attempt=1, delay_seconds=0):
    """Dispatcht einen Cloud Task auf die aerotax-jobs Queue.
    Worker wird unter dem AEROTAX_CLOUD_RUN_WORKER_URL/api/internal/process-job aufgerufen.
    Auth via OIDC ID-Token (service-account aerotax-task-invoker).

    Returns task name (str) oder raised RuntimeError bei Konfig-Fehler.
    """
    if not AEROTAX_CLOUD_RUN_WORKER_URL:
        raise RuntimeError('AEROTAX_CLOUD_RUN_WORKER_URL not configured (cloud_tasks mode)')

    try:
        from google.cloud import tasks_v2
    except ImportError as e:
        raise RuntimeError(f'google-cloud-tasks not installed: {e}')

    full_url = f'{AEROTAX_CLOUD_RUN_WORKER_URL}/api/internal/process-job'

    client = tasks_v2.CloudTasksClient()
    parent = client.queue_path(AEROTAX_GCP_PROJECT, AEROTAX_TASKS_LOCATION, AEROTAX_TASKS_QUEUE)

    payload = {'job_id': job_id, 'attempt': int(attempt)}
    body_bytes = json.dumps(payload).encode('utf-8')

    task = {
        'http_request': {
            'http_method': tasks_v2.HttpMethod.POST,
            'url': full_url,
            'headers': {'Content-Type': 'application/json'},
            'body': body_bytes,
            'oidc_token': {
                'service_account_email': AEROTAX_TASK_INVOKER_SA,
                'audience': full_url,
            },
        },
    }

    if delay_seconds and delay_seconds > 0:
        from google.protobuf import timestamp_pb2
        d = datetime.utcnow() + timedelta(seconds=int(delay_seconds))
        ts = timestamp_pb2.Timestamp()
        ts.FromDatetime(d)
        task['schedule_time'] = ts

    resp = client.create_task(parent=parent, task=task)
    print(f"[cloud-tasks] enqueued job={job_id[:8]} attempt={attempt} task={resp.name.rsplit('/', 1)[-1][:16]}")
    return resp.name


def _verify_internal_task_auth(request):
    """Verifiziert dass ein eingehender Request auf /api/internal/process-job
    wirklich von Cloud Tasks kommt (via OIDC ID-Token vom service account).

    Returns True wenn auth ok, sonst False.
    """
    # Local-Dev-Bypass: wenn nicht im cloud_tasks-Mode, akzeptiere ohne Auth
    # (Tests rufen den Endpoint direkt; Worker läuft in Thread-Mode gar nicht)
    if AEROTAX_EXECUTION_MODE != 'cloud_tasks':
        if request.headers.get('X-Internal-Task-Mode') == 'test':
            return True
        # Cloud Tasks Mode aus → kein realer Worker erwartet
        return False

    auth = request.headers.get('Authorization', '')
    if not auth.startswith('Bearer '):
        return False
    token = auth[7:]

    try:
        from google.oauth2 import id_token
        from google.auth.transport import requests as _g_req
        info = id_token.verify_oauth2_token(token, _g_req.Request())
        # Email muss unserem service-account entsprechen
        if info.get('email') != AEROTAX_TASK_INVOKER_SA:
            print(f"[task-auth] email mismatch: got={info.get('email')}")
            return False
        # Audience muss der Worker-URL entsprechen (verhindert token-reuse für andere services)
        expected_aud = f'{AEROTAX_CLOUD_RUN_WORKER_URL}/api/internal/process-job'
        if info.get('aud') != expected_aud:
            print(f"[task-auth] audience mismatch: got={info.get('aud')[:80]}")
            return False
        return True
    except Exception as e:
        print(f"[task-auth] verify fail: {type(e).__name__}: {str(e)[:200]}")
        return False


def _calc_worker():
    """Background-Worker: pickt Jobs aus _calc_queue, führt sequenziell aus.

    NUR aktiv in thread-mode (default lokal/dev). In cloud_tasks-mode startet
    diese Funktion zwar (kein harter Bypass), aber /api/process puttet
    nicht mehr in die Queue — der Worker bleibt idle.
    """
    global _calc_running_id
    while True:
        try:
            job_id, form, files = _calc_queue.get()
        except Exception as e:
            print(f"[queue-worker] queue.get fail: {e}")
            continue
        try:
            with _jobs_lock:
                _calc_running_id = job_id
                if job_id in _jobs and _jobs[job_id].get('status') == 'queued':
                    _jobs[job_id]['status'] = 'pending'
            _run_process_async(job_id, form, files)
        except Exception as e:
            print(f"[queue-worker] job {job_id[:8]} crash: {e}")
        finally:
            with _jobs_lock:
                _calc_running_id = None
            try: _calc_queue.task_done()
            except: pass
            # Aggressive Memory-Freigabe nach jedem Job
            gc.collect()
            _release_memory_to_os()


def _restart_recovery_async():
    """Läuft im Background-Thread, blockiert nicht den App-Start (sonst Render Port-Timeout).

    v11 P0-Fix: scannt SOWOHL Disk-Files (ephemeral) ALS AUCH Supabase nach
    Jobs die beim Restart in nicht-terminalen Status hängen. Markiert sie als
    'failed' damit Stale-Detector nicht weiter wartet und User klar erfährt
    dass sein Job nicht weiterläuft.

    Bisher: nur Disk-Scan → bei ephemeral-Disk (Render Free) wurden orphan
    Supabase-Jobs nicht erkannt → blieben endlos 'running'/'processing' →
    Frontend pollte ewig.
    """
    recovered_total = 0
    # 1. Disk-Scan (wie bisher)
    try:
        if os.path.exists(_JOBS_DIR):
            for fn in os.listdir(_JOBS_DIR):
                if not fn.endswith('.json'): continue
                try:
                    path = os.path.join(_JOBS_DIR, fn)
                    with open(path) as _f:
                        j = json.load(_f)
                    if j.get('status') in ('queued', 'pending', 'running', 'processing'):
                        j['status'] = 'failed'
                        j['error']  = 'Server wurde neugestartet während die Auswertung lief. Bitte mit deinem Code (AT-...) erneut starten — keine erneute Zahlung nötig.'
                        j['restart_recovered'] = True
                        job_id = fn[:-5]
                        with _jobs_lock:
                            _jobs[job_id] = j
                        with open(path, 'w') as _wf:
                            json.dump(j, _wf, default=str)
                        recovered_total += 1
                except Exception as _re:
                    print(f"[queue] Restart-Recovery fail für {fn}: {_re}")
    except Exception as _e:
        print(f"[queue] Restart-Recovery konnte JOBS_DIR nicht lesen: {_e}")

    # 2. Supabase-Scan: jeder Job mit non-terminal status seit dem Boot wird failed.
    #    Wichtig: NICHT die jobs aus Disk-Scan überschreiben (die haben schon
    #    den korrekten Recovery-State).
    if SB_AVAILABLE:
        try:
            res = sb.table('jobs').select('job_id,data').execute()
            rows = (res and res.data) or []
            for row in rows:
                jid = row.get('job_id')
                if not jid: continue
                d = row.get('data') or {}
                status = (d.get('status') or '').lower()
                if status not in ('queued', 'pending', 'running', 'processing'):
                    continue
                # Bereits durch Disk-Scan recovered? Skip.
                with _jobs_lock:
                    if jid in _jobs and _jobs[jid].get('status') == 'failed':
                        continue
                # Mark als failed
                d['status'] = 'failed'
                d['error'] = 'Server wurde neugestartet während die Auswertung lief. Bitte mit deinem Code (AT-...) erneut starten — keine erneute Zahlung nötig.'
                d['restart_recovered'] = True
                d['restart_recovered_at'] = datetime.utcnow().isoformat() + 'Z'
                try:
                    sb.table('jobs').update({
                        'data': d,
                        'updated_at': datetime.utcnow().isoformat() + 'Z',
                    }).eq('job_id', jid).execute()
                    with _jobs_lock:
                        _jobs[jid] = d
                    recovered_total += 1
                except Exception as _se:
                    print(f"[queue] Restart-Recovery Supabase-update fail {jid[:8]}: {_se}")
        except Exception as _ssee:
            print(f"[queue] Restart-Recovery Supabase-scan fail: {_ssee}")

    if recovered_total > 0:
        print(f"[queue] Restart-Recovery: {recovered_total} Job(s) auf 'failed' gesetzt (Disk+Supabase)")


def _start_calc_worker():
    global _calc_worker_started
    if _calc_worker_started:
        return
    # BUG-002 fix: In cloud_tasks-mode startet KEIN Legacy-Background-Thread.
    # Cloud Tasks invokes /api/internal/process-job synchron pro Request — kein lokaler
    # Queue-Worker, kein boot-time Supabase-Scan. Beides hatte den Gunicorn-Mainloop
    # blockiert und Cloud Run zu Container-Kills geführt (Restart-Loop).
    if AEROTAX_EXECUTION_MODE == 'cloud_tasks':
        print("[boot] cloud_tasks mode: legacy background worker disabled")
        print("[boot] cloud_tasks mode: restart-recovery background thread disabled")
        _calc_worker_started = True  # idempotent
        return
    _calc_worker_started = True
    _T = __import__('threading').Thread
    # Worker-Thread (verarbeitet Queue) sofort starten
    _T(target=_calc_worker, daemon=True, name='calc-worker').start()
    # Restart-Recovery in eigenem Thread (kann lange dauern bei vielen alten Jobs)
    # → blockiert nicht den App-Start, Port wird sofort geöffnet
    _T(target=_restart_recovery_async, daemon=True, name='restart-recovery').start()
    print("[queue] Worker-Thread + Restart-Recovery gestartet (async)")


# Worker beim App-Init starten (bei Render-Worker-Start).
# Tests/Imports können die Threads deaktivieren, damit Unit-Tests wirklich isoliert bleiben.
if os.environ.get('AEROTAX_DISABLE_BG_THREADS') != '1':
    _start_calc_worker()


_PII_KEYS = {
    # Direkte Identifier (DSGVO Art. 4)
    'identnr', 'geburtsdatum', 'personalnummer',
    'name', 'vorname', 'nachname',
    'finanzamt', 'steuernummer_ag',
    'adresse', 'plz', 'ort', 'strasse',
    'iban', 'bic',
    'email', 'telefon', 'phone',
}


def _redact_pii(obj):
    """Rekursiv: ersetzt PII-Felder durch '[redacted]'. Nicht in-place — neue Struktur.
    Wird vor Disk-Persist genutzt damit job-state files keine personenbezogenen
    Daten enthalten (DSGVO-Compliance)."""
    if isinstance(obj, dict):
        out = {}
        for k, v in obj.items():
            if isinstance(k, str) and k.lower().lstrip('_') in _PII_KEYS:
                out[k] = '[redacted]' if v else v
            else:
                out[k] = _redact_pii(v)
        return out
    if isinstance(obj, list):
        return [_redact_pii(x) for x in obj]
    return obj


def _save_job_to_disk(job_id):
    """v15 P0 #95 Fix: Speichert Job-State in Supabase (persistent über Restarts)
    + Disk-Fallback.

    PII (Name etc.) bleibt PERSISTIERT — sonst heißt das PDF nach
    Container-Restart `[redacted].pdf` und der Chat zeigt „Hallo [redacted]".
    Persistierung ist sicher weil:
      - Supabase: Service-Role-Key only (kein public access), RLS enabled,
        encryption at rest
      - Disk: Cloud Run ephemeral storage, container-gebunden, restart-gelöscht
      - Job-Cleanup-Loop löscht expired Jobs nach 24h (DSGVO „Recht auf Vergessen")

    PII wird WEITER redacted bei:
      - Stdout/Logs (siehe `_audit` / `print`-Calls die _redact_pii nutzen)
      - Audit-Trail / Diagnostics-Outputs
    """
    with _jobs_lock:
        j = _jobs.get(job_id, {}).copy()
    if not j: return
    j_safe = {k: v for k, v in j.items() if k != 'files'}
    # NOTE: KEIN _redact_pii(j_safe) hier — PII muss persistent bleiben
    # für PDF-Filename + Chat-Anrede nach Restart. Logs/Audit redacten weiter.
    # Supabase-Persistenz (überlebt Render-Container-Wipes)
    if SB_AVAILABLE:
        try:
            sb.table('jobs').upsert({
                'job_id':     job_id,
                'data':       j_safe,
                'updated_at': datetime.utcnow().isoformat() + 'Z',
            }).execute()
        except Exception as e:
            app.logger.warning(
                f"[persist] supabase_save_fail job={job_id[:8]} "
                f"err={type(e).__name__} — falling back to disk"
            )
    # Disk-Fallback (auch zusätzlich für lokale Dev)
    try:
        with open(os.path.join(_JOBS_DIR, f'{job_id}.json'), 'w') as f:
            json.dump(j_safe, f, default=str)
    except Exception as e:
        app.logger.warning(
            f"[persist] disk_save_fail job={job_id[:8]} err={type(e).__name__}"
        )


# ════════════════════════════════════════════════════════════════════════════
# v11 B-002: Session-Token-Decorator für alle /api/job/<id>/* Routes
#
# Ziel: Job-Routes nur für den User zugänglich, der den Job gestartet hat.
# Vorher: jeder mit der job_id-UUID hatte Vollzugriff.
# Jetzt:  X-Session-Token-Header muss zum gespeicherten session_token des Jobs
#         passen, sonst 403 mit freundlicher Meldung.
#
# Backwards-compat: Token kann auch als `?session_token=...` Query-Param oder im
# JSON-Body `session_token` mitkommen (für Upload-Endpoints die multipart sind).
# ════════════════════════════════════════════════════════════════════════════
def _extract_session_token_from_request():
    """Liest Session-Token aus Header / Query / Form / JSON Body — in dieser
    Priorität. Whitespace getrimmt. Leer-String → None."""
    tok = (request.headers.get('X-Session-Token') or '').strip()
    if tok:
        return tok
    tok = (request.args.get('session_token') or '').strip()
    if tok:
        return tok
    tok = (request.form.get('session_token') or '').strip()
    if tok:
        return tok
    try:
        body = request.get_json(silent=True) or {}
        tok = (body.get('session_token') or '').strip()
        if tok:
            return tok
    except Exception:
        pass
    return None


def requires_session_token(fn):
    """Decorator: lädt Job, prüft Session-Token. 403 bei Fehlen/Falsch.
    Funktion bekommt den Job geladen UND validiert übergeben.
    Verwendung: View-Funktion erste Position `job_id`, Decorator liest selbst.

    BUG-005 P0-Fix: nutzt `_get_or_load_job` — hält `_jobs_lock` NICHT während
    Supabase-Load. Bei Supabase-Timeout: 503 fetch_error statt 30s-Hang.
    """
    import functools as _ft
    @_ft.wraps(fn)
    def _wrapped(*args, **kwargs):
        job_id = kwargs.get('job_id') or (args[0] if args else None)
        if not job_id:
            return jsonify({'error': 'job_id fehlt'}), 400
        j, load_status = _get_or_load_job(job_id)
        if load_status == 'timeout':
            return jsonify(_fetch_error_response()), 503
        if not j:
            return jsonify({'error': 'Diese Auswertung ist nicht mehr verfügbar — bitte starte eine neue Auswertung.'}), 404
        expected = (j.get('session_token') or '').strip()
        provided = _extract_session_token_from_request()
        if not expected:
            # Legacy-Job ohne gespeicherten Token (vor v11 erstellt) — wir lassen
            # diesen Sonderfall durch, damit aktive Auswertungen beim Deploy nicht
            # plötzlich 403 bekommen. Neu erstellte Jobs haben immer einen Token.
            return fn(*args, **kwargs)
        if not provided or not hmac.compare_digest(expected, provided):
            return jsonify({
                'error': 'Diese Auswertung konnte nicht geöffnet werden. '
                         'Bitte nutze deinen Zugangscode erneut.'
            }), 403
        return fn(*args, **kwargs)
    return _wrapped


def _load_job_from_disk(job_id):
    """v9.7 + BUG-005 P0-Fix: Lädt Job-State aus Supabase (überlebt Restart) mit
    5s Timeout, dann Disk-Fallback.

    Verwendet `_supabase_execute_with_timeout` → bei Hang return None statt
    endlos hängen.

    **Hält KEIN `_jobs_lock`** (auch nicht zum Memory-Mirror) — siehe
    `_get_or_load_job()` für die Lock-Sequenz, die Caller verwenden sollen.

    Returns: job_dict_or_None — gleiche Signatur wie vorher (backwards-compat).

    Achtung: `None` heißt "nicht gefunden ODER timeout". Wer den Unterschied
    braucht → `_get_or_load_job(job_id)` benutzen (gibt status-tuple zurück).
    """
    # 1. Supabase mit Timeout
    if SB_AVAILABLE:
        def _do_sb_query():
            return sb.table('jobs').select('data').eq('job_id', job_id).limit(1).execute()
        res, timed_out = _supabase_execute_with_timeout(
            f'_load_job({job_id[:8]})', _do_sb_query, timeout_s=5
        )
        if timed_out:
            # Nicht Disk fallback bei Timeout — vermutlich ist Supabase die
            # vertrauenswürdigere Quelle, Disk könnte stale sein.
            return None
        if res is not None:
            rows = (res.data) or []
            if rows and rows[0].get('data'):
                return rows[0]['data']
    # 2. Disk-Fallback (nur wenn Supabase nicht-existierender oder beide leer)
    path = os.path.join(_JOBS_DIR, f'{job_id}.json')
    if not os.path.exists(path):
        return None
    try:
        with open(path) as f:
            return json.load(f)
    except Exception as e:
        print(f"[persist] Job {job_id[:8]} disk load fail: {e}")
        return None


def _load_job_from_persistence(job_id):
    """Wie `_load_job_from_disk`, aber unterscheidet timeout vs not-found.

    Returns (job_dict_or_None, timed_out_flag).
      - (dict, False)  → erfolgreich geladen
      - (None, False)  → nicht gefunden (weder Supabase noch Disk)
      - (None, True)   → Supabase-Query timed out (caller: fetch_error-response)
    """
    if SB_AVAILABLE:
        def _do_sb_query():
            return sb.table('jobs').select('data').eq('job_id', job_id).limit(1).execute()
        res, timed_out = _supabase_execute_with_timeout(
            f'_load_job({job_id[:8]})', _do_sb_query, timeout_s=5
        )
        if timed_out:
            return None, True
        if res is not None:
            rows = (res.data) or []
            if rows and rows[0].get('data'):
                return rows[0]['data'], False
    path = os.path.join(_JOBS_DIR, f'{job_id}.json')
    if not os.path.exists(path):
        return None, False
    try:
        with open(path) as f:
            return json.load(f), False
    except Exception as e:
        print(f"[persist] Job {job_id[:8]} disk load fail: {e}")
        return None, False


def _get_or_load_job(job_id):
    """Memory-first Job-Lookup mit Lock-Disziplin.

    KRITISCH: hält `_jobs_lock` NIEMALS während Supabase/Disk-I/O. Vorher hing
    der Lock für 30s+ wenn `sb.table('jobs').execute()` blockierte → ALLE
    anderen Lock-User waren blockiert → /api/session und /api/job hingen 30s.

    Returns (job_dict_or_None, load_status).
      load_status: 'memory'    → war schon in _jobs
                   'persisted' → frisch aus Supabase/Disk geladen + ins _jobs gespiegelt
                   'timeout'   → Supabase-Query hing → caller sollte fetch_error returnen
                   'not_found' → nirgendwo zu finden → caller sollte expired returnen

    Caller MUST handle 'timeout' separately from 'not_found' — sonst rendert User
    eine „abgelaufen"-Meldung obwohl es nur ein transient DB-Hang ist.
    """
    if not job_id:
        return None, 'not_found'
    with _jobs_lock:
        j = _jobs.get(job_id)
    if j is not None:
        return j, 'memory'
    # KEIN Lock während Persistenz-I/O
    j, timed_out = _load_job_from_persistence(job_id)
    if timed_out:
        return None, 'timeout'
    if j is None:
        return None, 'not_found'
    with _jobs_lock:
        _jobs[job_id] = j
    return j, 'persisted'


# ══════════════════════════════════════════════════════════════════════════════
# v10.4 — job_chunks: persistente Chunk-Zwischenergebnisse für DP-Reader.
# Reduziert Memory-Pressure auf Render Free-Tier (chunks werden sofort gespeichert,
# große Sonnet-Responses sofort freigegeben).
# Disk-Fallback wenn Supabase nicht verfügbar.
# ══════════════════════════════════════════════════════════════════════════════

_job_chunks_memory = {}  # job_id → list of chunk dicts (in-memory fallback)
_JOB_CHUNKS_DIR = os.path.join(os.path.dirname(__file__), '_job_chunks_state')
try:
    os.makedirs(_JOB_CHUNKS_DIR, exist_ok=True)
except Exception:
    pass


def _sanitize_chunk_result(result):
    """v10.4: Stellt sicher dass NIEMALS PDF-Bytes oder base64 in result_json landen.
    Entfernt verdächtig große String-Felder und bekannte Binary-Keys."""
    if not isinstance(result, dict):
        return result
    BLOCKED_KEYS = {'file_bytes', 'file_bytes_list', 'pdf_bytes', 'data_b64',
                    'base64', 'b64', 'raw_pdf', 'pdf_content', 'image_bytes'}
    out = {}
    for k, v in result.items():
        if k in BLOCKED_KEYS:
            continue
        # String-Feld > 50 KB ist verdächtig (PDFs sind groß, normaler Text klein)
        if isinstance(v, str) and len(v) > 50_000:
            out[k] = f'<truncated:{len(v)} chars>'
        elif isinstance(v, dict):
            out[k] = _sanitize_chunk_result(v)
        elif isinstance(v, list):
            out[k] = [_sanitize_chunk_result(x) if isinstance(x, dict) else x for x in v]
        else:
            out[k] = v
    return out


def create_job_chunk(job_id, document_type, chunk_index,
                     page_from=None, page_to=None,
                     file_hash=None, parser_version=None):
    """Erstellt einen pending-Chunk-Eintrag. Idempotent via (job_id, document_type, chunk_index).
    v10.4.1: file_hash + parser_version unterstützen Cache-Lookups bei Wiederholung
    derselben Datei.
    v11 B-015: NO-OP wenn AEROTAX_USE_CHUNK_PERSISTENCE=0 (default).
    Returns chunk_id (UUID) oder None bei Fehler oder bei Flag=0."""
    if not AEROTAX_USE_CHUNK_PERSISTENCE:
        return None
    import uuid as _uuid
    chunk_id = str(_uuid.uuid4())
    row = {
        'id': chunk_id,
        'job_id': str(job_id),
        'document_type': document_type,
        'chunk_index': int(chunk_index),
        'page_from': page_from,
        'page_to': page_to,
        'file_hash': file_hash,
        'parser_version': parser_version,
        'status': 'pending',
        'result_json': None,
        'error_code': None,
        'error_message': None,
        'created_at': datetime.utcnow().isoformat() + 'Z',
        'updated_at': datetime.utcnow().isoformat() + 'Z',
    }
    if SB_AVAILABLE:
        try:
            sb.table('job_chunks').upsert(
                row, on_conflict='job_id,document_type,chunk_index'
            ).execute()
            return chunk_id
        except Exception as e:
            print(f"[chunks] create supabase fail {job_id[:8]}/{document_type}/{chunk_index}: {str(e)[:120]}")
    # Disk-Fallback
    _job_chunks_memory.setdefault(job_id, []).append(row)
    try:
        path = os.path.join(_JOB_CHUNKS_DIR, f'{job_id}.json')
        with open(path, 'w') as f:
            json.dump(_job_chunks_memory[job_id], f)
    except Exception:
        pass
    return chunk_id


def mark_job_chunk_running(chunk_id):
    """Markiert chunk als 'running'.
    v11 B-015: NO-OP wenn chunk_id None (Flag=0)."""
    if not AEROTAX_USE_CHUNK_PERSISTENCE or not chunk_id:
        return
    _update_chunk_fields(chunk_id, status='running')


def save_job_chunk_result(chunk_id, result_json):
    """Speichert Chunk-Result + setzt status='completed'.
    result_json wird sanitized (kein base64/PDF-bytes).
    v11 B-015: NO-OP wenn chunk_id None (Flag=0) oder Persistence ausgeschaltet."""
    if not AEROTAX_USE_CHUNK_PERSISTENCE or not chunk_id:
        return
    sanitized = _sanitize_chunk_result(result_json)
    _update_chunk_fields(chunk_id, status='completed', result_json=sanitized,
                         error_code=None, error_message=None)


def mark_job_chunk_failed(chunk_id, error_code, error_message):
    """Markiert chunk als failed mit Code + Message.
    v11 B-015: NO-OP wenn chunk_id None (Flag=0)."""
    if not AEROTAX_USE_CHUNK_PERSISTENCE or not chunk_id:
        return
    _update_chunk_fields(chunk_id, status='failed',
                         error_code=str(error_code)[:50],
                         error_message=str(error_message)[:500])


def _update_chunk_fields(chunk_id, **fields):
    """Internes Update — auf Supabase + Disk-Fallback."""
    fields['updated_at'] = datetime.utcnow().isoformat() + 'Z'
    if SB_AVAILABLE:
        try:
            sb.table('job_chunks').update(fields).eq('id', chunk_id).execute()
            return
        except Exception as e:
            print(f"[chunks] update supabase fail {chunk_id[:8]}: {str(e)[:120]}")
    # Disk-Fallback
    for job_id, chunks in _job_chunks_memory.items():
        for c in chunks:
            if c.get('id') == chunk_id:
                c.update(fields)
                try:
                    path = os.path.join(_JOB_CHUNKS_DIR, f'{job_id}.json')
                    with open(path, 'w') as f:
                        json.dump(chunks, f)
                except Exception:
                    pass
                return


def load_job_chunks(job_id, document_type=None, status=None):
    """Lädt alle Chunks für einen Job. Optional gefiltert nach document_type/status.
    Returns list of chunk dicts, sortiert nach chunk_index."""
    chunks = []
    if SB_AVAILABLE:
        try:
            q = sb.table('job_chunks').select('*').eq('job_id', str(job_id))
            if document_type:
                q = q.eq('document_type', document_type)
            if status:
                q = q.eq('status', status)
            res = q.execute()
            chunks = (res and res.data) or []
        except Exception as e:
            print(f"[chunks] load supabase fail {str(job_id)[:8]}: {str(e)[:120]}")
    if not chunks:
        # Disk-Fallback
        path = os.path.join(_JOB_CHUNKS_DIR, f'{job_id}.json')
        if os.path.exists(path):
            try:
                chunks = json.load(open(path))
            except Exception:
                chunks = []
        if not chunks and job_id in _job_chunks_memory:
            chunks = _job_chunks_memory[job_id]
        if document_type:
            chunks = [c for c in chunks if c.get('document_type') == document_type]
        if status:
            chunks = [c for c in chunks if c.get('status') == status]
    chunks.sort(key=lambda c: c.get('chunk_index', 0))
    return chunks


def find_cached_chunk(file_hash, document_type, chunk_index, parser_version):
    """v10.4.1: Cache-Lookup für completed chunks.
    Wenn dieselbe Datei (SHA-256) + selbe parser_version bereits ausgewertet:
    Result direkt aus Supabase ohne Sonnet-Call.

    v11 B-015: returns None wenn AEROTAX_USE_CHUNK_PERSISTENCE=0 (default).
    Cache-Hit ist Optimierung, kein Korrektheits-Feature.

    Returns result_json (dict) oder None.
    """
    if not AEROTAX_USE_CHUNK_PERSISTENCE:
        return None
    if not file_hash or not parser_version:
        return None
    if SB_AVAILABLE:
        try:
            res = sb.table('job_chunks').select('result_json').eq(
                'file_hash', file_hash).eq(
                'document_type', document_type).eq(
                'chunk_index', int(chunk_index)).eq(
                'parser_version', parser_version).eq(
                'status', 'completed').limit(1).execute()
            rows = (res and res.data) or []
            if rows:
                return rows[0].get('result_json')
        except Exception as e:
            print(f"[chunks] cache lookup fail: {str(e)[:120]}")
    # Disk-Fallback: scan all known chunks (rare path, slower)
    try:
        for fn in os.listdir(_JOB_CHUNKS_DIR):
            if not fn.endswith('.json'): continue
            try:
                chunks = json.load(open(os.path.join(_JOB_CHUNKS_DIR, fn)))
                for c in chunks:
                    if (c.get('file_hash') == file_hash and
                        c.get('document_type') == document_type and
                        c.get('chunk_index') == int(chunk_index) and
                        c.get('parser_version') == parser_version and
                        c.get('status') == 'completed'):
                        return c.get('result_json')
            except Exception:
                continue
    except Exception:
        pass
    return None


def cleanup_old_wall_images(max_age_days: int = 180):
    """Löscht hochgeladene Wall-Bilder älter als N Tage (Default 180).
    posts.json ist auf 5000 Einträge gecapped — Bilder zu noch älteren Posts sind
    unauffindbar, würden aber sonst auf der Disk verbleiben (Storage-Leak).
    Wird im _cleanup_loop aufgerufen.
    """
    try:
        img_root = os.path.join(_USER_HISTORY_DIR, 'wall_images')
        if not os.path.isdir(img_root):
            return
        cutoff = datetime.utcnow() - timedelta(days=max_age_days)
        deleted = 0
        for token_dir in os.listdir(img_root):
            full_dir = os.path.join(img_root, token_dir)
            if not os.path.isdir(full_dir):
                continue
            try:
                for fn in os.listdir(full_dir):
                    fp = os.path.join(full_dir, fn)
                    try:
                        if datetime.utcfromtimestamp(os.path.getmtime(fp)) < cutoff:
                            os.remove(fp)
                            deleted += 1
                    except Exception:
                        pass
                if not os.listdir(full_dir):
                    try: os.rmdir(full_dir)
                    except Exception: pass
            except Exception:
                continue
        if deleted:
            print(f"[cleanup] wall_images: {deleted} files (>{max_age_days}d) deleted")
    except Exception as e:
        print(f"[cleanup] wall_images fail: {str(e)[:120]}")


def cleanup_old_job_chunks():
    """Löscht job_chunks älter als 7 Tage. Wird im _cleanup_loop aufgerufen."""
    if not SB_AVAILABLE:
        # Disk-Fallback Cleanup
        try:
            cutoff = datetime.utcnow() - timedelta(days=7)
            for fn in os.listdir(_JOB_CHUNKS_DIR):
                if not fn.endswith('.json'): continue
                path = os.path.join(_JOB_CHUNKS_DIR, fn)
                try:
                    if datetime.utcfromtimestamp(os.path.getmtime(path)) < cutoff:
                        os.remove(path)
                except Exception:
                    pass
        except Exception:
            pass
        return
    try:
        cutoff = (datetime.utcnow() - timedelta(days=7)).isoformat()
        res = sb.table('job_chunks').delete().lt('updated_at', cutoff).execute()
        deleted = len((res and getattr(res, 'data', None)) or [])
        if deleted:
            print(f"[cleanup] supabase: {deleted} job_chunks (>7d) deleted")
    except Exception as e:
        print(f"[cleanup] job_chunks delete fail: {str(e)[:120]}")


def _audit(job_id, event, data=None):
    """Schreibt Audit-Event in Job-Log + Render-Stdout. Audit-konform für Tax-Compliance.

    B-7 Audit-Fix: PII wird VOR stdout-print über _redact_pii gefiltert. Job-Audit-Log
    wird beim Persist-Step (_save_job_to_disk → _redact_pii) ohnehin redacted, aber
    stdout-Lines gingen vorher ungeredactet raus.
    """
    entry = {
        'ts': datetime.utcnow().isoformat() + 'Z',
        'event': event,
        'data': data,
    }
    with _jobs_lock:
        if job_id in _jobs:
            _jobs[job_id].setdefault('audit', []).append(entry)
    # B-7: Redaction für stdout (nicht für in-memory audit log — der wird beim Save redacted)
    try:
        _safe_data = _redact_pii(data) if data else ''
    except Exception:
        _safe_data = '<redact-fail>'
    print(f"[AUDIT {job_id[:8]}] {event}: {json.dumps(_safe_data, default=str)[:200] if _safe_data else ''}")


def _validate_file_categories(files):
    """Quick sanity check: peek in PDF-text und prüfe ob Files typisch zur Kategorie passen.
    Liefert Liste warnings (leer = alles ok). Verhindert teure KI-Calls bei
    offensichtlich falschen Uploads (z.B. User lädt Reisepass statt LSB hoch)."""
    warnings = []
    # Marker-Strings die typisch in der Kategorie vorkommen (case-insensitive)
    markers = {
        'lsb':     ['lohnsteuerbescheinigung', 'bruttoarbeitslohn', 'arbeitslohn',
                    'bescheinigungsnummer', 'einbehaltene lohnsteuer'],
        'se':      ['streckeneinsatz', 'spesen', 'stfrei', 'steuerfrei',
                    'abrechnung', 'verpflegung'],
        'dp':      ['dienstplan', 'duty', 'roster', 'flug', 'frei'],
        'einsatz': ['einsatzplan', 'briefing', 'cas-pub', 'rotation', 'duty'],
    }
    label_de = {'lsb': 'Lohnsteuerbescheinigung', 'se': 'Streckeneinsatz',
                'dp': 'Dienstplan', 'einsatz': 'Einsatzplan'}
    for cat, kw_list in markers.items():
        items = files.get(cat) or []
        for idx, item in enumerate(items):
            pdf_bytes = item[0] if isinstance(item, tuple) else item
            if not pdf_bytes or not isinstance(pdf_bytes, (bytes, bytearray)):
                continue
            try:
                with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
                    # Erste Seite reicht für Sanity — sparsam mit Memory
                    page1_text = (pdf.pages[0].extract_text() or '') if pdf.pages else ''
            except Exception:
                continue  # nicht lesbar — Plausi überspringen, KI versucht's
            ptext = page1_text.lower()
            if not any(kw in ptext for kw in kw_list):
                warnings.append(
                    f'⚠ Datei {idx+1} in Kategorie "{label_de[cat]}" enthält keine '
                    f'typischen Begriffe (z.B. "{kw_list[0]}"). Bitte prüfen ob du das '
                    f'richtige Dokument hochgeladen hast.'
                )
    return warnings


@app.route('/api/process', methods=['POST'])
def process_real():
    """Startet asynchrone Auswertung. Liefert sofort job_id, Frontend pollt /api/job/<id>."""
    try:
        # Rate-Limit pro IP: max 20 Process-Calls/h. Stripe ist primärer Anti-Abuse-Layer,
        # IP-Limit fängt nur Versuche das Endpoint zu spammen (z.B. Promo-Code-Brute-Force).
        ip = _client_ip()
        if _ip_rate_limited(ip, 'process', limit=20, window_sec=3600):
            return jsonify({
                'error': 'Zu viele Versuche von dieser Verbindung. Bitte warte ca. 1 Stunde und versuche es dann erneut.'
            }), 429
        anreise = request.form.get('anreise', 'auto')
        # Robuste Number-Casts mit Fallback bei fehlerhaftem Input
        def _safe_int(v, default):
            try: return int(float(v))
            except: return default
        def _safe_float(v, default=0.0):
            try: return float(v)
            except: return default
        year_input = _safe_int(request.form.get('year', 2025), 2025)
        # Year auf supportete Range klemmen (2023-2026)
        year_input = max(2023, min(2026, year_input))

        # Sanity-Caps für User-Eingaben (verhindert absurde Werte)
        km_raw = _safe_float(request.form.get('km', 0))
        km_capped = max(0.0, min(500.0, km_raw))  # 0-500 km plausible
        anfahrt_raw = _safe_int(request.form.get('anfahrt_min', 0), 0)
        anfahrt_capped = max(0, min(180, anfahrt_raw))  # 0-180 min plausible
        oepnv_raw = _safe_float(request.form.get('oepnv_kosten', 0))
        oepnv_capped = max(0.0, min(10000.0, oepnv_raw))
        shuttle_raw = _safe_float(request.form.get('shuttle_kosten', 0))
        shuttle_capped = max(0.0, min(10000.0, shuttle_raw))
        # Ausfallzeit (Mutterschutz/Krankheit/Teilzeit) — Monate die nicht gearbeitet wurde
        ausfall_raw = _safe_int(request.form.get('ausfallzeit_monate', 0), 0)
        ausfall_capped = max(0, min(12, ausfall_raw))

        # Anreise: kann Multi-Mode sein (CSV: "auto,shuttle"), bleibt für Single-Mode kompatibel
        # km nur relevant wenn auto/fahrrad in den Modes
        anreise_modes_raw = set(m.strip() for m in str(anreise).split(',') if m.strip())
        has_km = bool(anreise_modes_raw & {'auto', 'fahrrad'})

        # P1 #5 Fix: Server-Validation für base. CLAUDE.md verbietet hardcoded FRA;
        # bei fehlender base würde MUC/BER/DUS-Crew silent als FRA-Crew klassifiziert.
        _base_raw = (request.form.get('base') or '').strip()
        if not _base_raw:
            return jsonify({
                'error': 'Pflichtfeld „Homebase" fehlt. Bitte wähle deine Homebase im Formular.',
                'reason_code': 'UPLOAD_MISSING_REQUIRED',
            }), 400

        form = {
            'name':    request.form.get('name', 'Flugbegleiter'),
            'vorname': request.form.get('vorname', ''),
            'nachname':request.form.get('nachname', ''),
            'year':    year_input,
            'base':    _base_raw,
            'anreise': anreise,
            'km':      km_capped if has_km else 0,
            'fahrzeug':   request.form.get('fahrzeug', 'verbrenner'),
            'oepnv_kosten': oepnv_capped,
            'shuttle_kosten': shuttle_capped,
            'jobticket':  request.form.get('jobticket', 'nein'),
            'anfahrt_min': anfahrt_capped,
            'ausfallzeit_monate': ausfall_capped,
        }

        files = {}
        for key in _ALL_FILE_KEYS:
            uploaded = request.files.getlist(key)
            if uploaded:
                files[key] = [_normalize_upload(f.read(), f.filename) for f in uploaded]

        # Audit: Wieviele Files kamen direkt im Request an?
        # v11 Clean-Release: dp = legacy_ignored_flight_hours_summary (nicht mehr aktive Quelle).
        # Aktiv-Pflicht-Kategorien sind lsb + se + cas.
        direct_parts = []
        for k, v in files.items():
            if not v:
                continue
            label = {
                'dp': 'legacy_ignored_flight_hours_summary',
                'se': 'streckeneinsatz',
                'lsb': 'lsb',
                'cas': 'dienstplan_cas',
            }.get(k, k)
            direct_parts.append(f"{label}={len(v)}")
        print(f"[process] Direct-Upload: {', '.join(direct_parts) or 'KEINE'}")

        # Fallback: Files aus _store (in-memory) — überlebt Stripe-Retry
        # v11: Pflicht-Set = LSB + SE + CAS (kein DP mehr)
        ref_for_fallback = (request.form.get('ref') or '').strip()
        if (not files.get('lsb') or not files.get('se') or not files.get('cas')) \
                and ref_for_fallback and _store.get(ref_for_fallback, {}).get('files'):
            stored = _store[ref_for_fallback]['files']
            for k, items in stored.items():
                if k in files:
                    continue
                files[k] = [it[0] if isinstance(it, tuple) else it for it in items]
            print(f"[process] ref={ref_for_fallback[:8]} Files aus _store geladen ({sum(len(v) for v in files.values())} insgesamt)")

        # Letzter Fallback: Supabase — überlebt Render-Restart
        if (not files.get('lsb') or not files.get('se') or not files.get('cas')) \
                and ref_for_fallback:
            sb_files = _load_uploaded_files_supabase(ref_for_fallback)
            if sb_files:
                for k, items in sb_files.items():
                    if k in files:
                        continue
                    files[k] = [d for (d, _) in items]
                print(f"[process] ref={ref_for_fallback[:8]} Files aus Supabase geladen ({sum(len(v) for v in files.values())} insgesamt)")

        # v11: CAS ist neues 3. Pflicht-Dokument. Wenn nur DP (Flugstundenübersicht) hochgeladen
        # wurde, friendly weisen — User soll CAS hochladen.
        if files.get('dp') and not files.get('cas'):
            return jsonify({
                'error': 'Die Flugstundenübersicht wird im neuen Ablauf nicht mehr benötigt. '
                         'Bitte lade stattdessen deinen Dienstplan/CAS/Roster hoch — '
                         'du findest ihn in MyTime → Document Store.'
            }), 400

        if not files.get('lsb') or not files.get('se') or not files.get('cas'):
            return jsonify({
                'error': 'Für die Auswertung brauchst du Lohnsteuerbescheinigung, '
                         'Streckeneinsatzabrechnung und Dienstplan/CAS/Roster.'
            }), 400

        # ── PAYMENT-GATE: ref (Stripe), free_retry_token, oder valider Promo-Code ──
        free_retry_token = (request.form.get('free_retry_token') or '').strip()
        ref = (request.form.get('ref') or '').strip()
        pi_id = (request.form.get('payment_intent_id') or '').strip()
        promo_code = (request.form.get('promo_code') or '').strip().upper()
        is_free_retry = _is_valid_recovery_token(free_retry_token)
        is_paid = bool(ref and _store.get(ref, {}).get('paid'))
        # P0 #96: Replay-Schutz wurde verlagert nach unten (NACH payment-gate-
        # Verifikation + nach pre-persist) und nutzt jetzt persistente Supabase-
        # Lock-Tabelle — Multi-Container-safe.
        # Wenn Webhook noch nicht durch ist: PaymentIntent direkt bei Stripe verifizieren
        if not is_paid and pi_id:
            try:
                pi = stripe.PaymentIntent.retrieve(pi_id)
                pi_ref = ((pi.metadata or {}).get('ref') or '').strip() if pi else ''
                # SECURITY (Bug-Hunt CRITICAL): Betrag + Währung gegen den
                # Serverpreis prüfen — ein „succeeded" PI über 1 Cent darf NICHT
                # freischalten. Defense-in-depth zusätzlich zum fixen Create-Betrag.
                _pi_amt = int(getattr(pi, 'amount_received', 0) or getattr(pi, 'amount', 0) or 0) if pi else 0
                _pi_cur = (getattr(pi, 'currency', '') or '').lower() if pi else ''
                if pi and pi.status == 'succeeded' and (_pi_amt < EXPECTED_PRICE_CENTS or (_pi_cur and _pi_cur != 'eur')):
                    return jsonify({'error': 'Zahlungsbetrag ungültig.'}), 402
                if pi and pi.status == 'succeeded' and pi_ref:
                    # WICHTIG: PaymentIntent darf nur die eigene Upload-ref freischalten.
                    # Sonst könnte ein bezahlter PI versehentlich/absichtlich für fremde refs genutzt werden.
                    if ref and ref != pi_ref:
                        return jsonify({'error': 'Zahlung passt nicht zu dieser Upload-Session.'}), 402
                    ref = ref or pi_ref
                    is_paid = True
                    if ref and ref in _store:
                        _store[ref]['paid'] = True
            except Exception as _e:
                print(f"[stripe] PI verify fail {pi_id[:12]}: {_e}")
        # v11 B-004: Default leer — Promo-Codes nur via ENV setzen, keine
        # gehärteten Codes im Source. Vorher: 'AEROTAXFREEPASS26' war via Repo-Lesen
        # öffentlich raterbar und hätte Free-Auswertungen erlaubt.
        valid_promos = set(c.strip().upper() for c in os.environ.get('PROMO_CODES', '').split(',') if c.strip())
        is_promo = bool(promo_code and promo_code in valid_promos)
        allow_unpaid = os.environ.get('ALLOW_UNPAID') == '1'
        if not (is_paid or is_free_retry or is_promo or allow_unpaid):
            return jsonify({
                'error': 'Zahlung nicht verifiziert. Bitte schließe den Bezahlvorgang ab und versuche es dann erneut.'
            }), 402

        # ── P0 #90: PRE-PERSIST vor PI-Consume ──
        # Im Cloud-Tasks-Mode lädt der Worker Files aus Supabase. Wenn Persistenz
        # nach PI-Consume fehlschlägt, hat User gezahlt + keine verwertbare
        # Auswertung. Daher JETZT (vor Consume) persistieren — schlägt das fehl,
        # 503 mit reason_code UPLOAD_PERSIST_FAILED und KEIN Job, KEIN PI-Consume.
        # is_free_retry: keine neuen Files; Files müssen vom vorherigen Job in
        # Supabase noch da sein (TTL=4h). Pre-persist wird übersprungen — Worker
        # liefert UPLOAD_FILES_MISSING wenn nicht mehr da.
        sb_ref_pre = ref or (request.form.get('ref') or '').strip()
        if not sb_ref_pre:
            sb_ref_pre = f'auto-{uuid.uuid4().hex[:12]}'
        if AEROTAX_EXECUTION_MODE == 'cloud_tasks' and not is_free_retry:
            files_pre_format = {}
            for k, items in files.items():
                if not items:
                    continue
                files_pre_format[k] = []
                for it in items:
                    if isinstance(it, tuple) and len(it) >= 2:
                        files_pre_format[k].append((it[0], it[1] or f'{k}.pdf'))
                    elif isinstance(it, (bytes, bytearray)):
                        files_pre_format[k].append((bytes(it), f'{k}.pdf'))
            if files_pre_format:
                try:
                    _save_uploaded_files_supabase(sb_ref_pre, files_pre_format)
                except UploadPersistError as _pe:
                    ec = AEROTAX_ERROR_CODES['UPLOAD_PERSIST_FAILED']
                    app.logger.error(
                        f"[process] pre_persist_failed ref={sb_ref_pre[:8]} "
                        f"err={type(_pe).__name__}"
                    )
                    return jsonify({
                        'ok':           False,
                        'reason_code':  'UPLOAD_PERSIST_FAILED',
                        'user_title':   ec['user_title'],
                        'user_message': ec['user_message'],
                        'retryable':    ec['retryable'],
                        'support':      ec['support'],
                        'next_actions': ec.get('next_actions', []),
                    }), 503

        # ── P0 #96: PaymentIntent atomic-claim VOR Job-Creation ──
        # Multi-Container-Safe: persistente Lock-Tabelle in Supabase. Nur ein
        # Container kann je PI claimen. Promo + free_retry brauchen keinen Lock,
        # weil dort kein pi_id involviert ist.
        ref = ref or sb_ref_pre
        job_id = str(uuid.uuid4())
        if pi_id and not is_free_retry and not is_promo:
            # L1-Cache short-circuit (gleicher Container, gleicher PI)
            if pi_id in _consumed_payment_intents:
                ec = AEROTAX_ERROR_CODES['PAYMENT_ALREADY_USED']
                return jsonify({
                    'ok':              False,
                    'reason_code':     'PAYMENT_ALREADY_USED',
                    'user_title':      ec['user_title'],
                    'user_message':    ec['user_message'],
                    'retryable':       ec['retryable'],
                    'support':         ec['support'],
                    'next_actions':    ec.get('next_actions', []),
                }), 409
            # L2: atomarer Supabase-Insert (multi-container safe)
            outcome, existing = _try_consume_payment_intent_supabase(pi_id, ref, job_id)
            if outcome == 'already_used':
                ec = AEROTAX_ERROR_CODES['PAYMENT_ALREADY_USED']
                resp = {
                    'ok':              False,
                    'reason_code':     'PAYMENT_ALREADY_USED',
                    'user_title':      ec['user_title'],
                    'user_message':    ec['user_message'],
                    'retryable':       ec['retryable'],
                    'support':         ec['support'],
                    'next_actions':    ec.get('next_actions', []),
                }
                if existing and existing.get('job_id'):
                    resp['existing_job_id'] = existing['job_id']
                if existing and existing.get('status'):
                    resp['existing_status'] = existing['status']
                # L1 fülle damit nächster Call sofort short-circuited
                _consumed_payment_intents[pi_id] = datetime.utcnow()
                return jsonify(resp), 409
            if outcome == 'lock_unavailable':
                # Fail-closed bei echter Zahlung — lieber temporär nicht bedienen
                # als Double-Spending zulassen
                ec = AEROTAX_ERROR_CODES['PAYMENT_LOCK_FAILED']
                return jsonify({
                    'ok':              False,
                    'reason_code':     'PAYMENT_LOCK_FAILED',
                    'user_title':      ec['user_title'],
                    'user_message':    ec['user_message'],
                    'retryable':       ec['retryable'],
                    'support':         ec['support'],
                    'next_actions':    ec.get('next_actions', []),
                }), 503

        # ── ASYNC: Job anlegen, Token sofort generieren, im Hintergrund starten ──
        # Ab hier: PI darf consumed werden, weil Files persistiert sind.
        if is_free_retry:
            session_token = free_retry_token
            # Recovery-Token verbrauchen — nur 1x pro Token zulässig
            _recovery_tokens.pop(free_retry_token, None)
            # P1 #111: auch in Supabase löschen damit anderer Container es nicht
            # nochmal akzeptiert
            _delete_recovery_token_from_supabase(free_retry_token)
            _save_session(session_token, {
                'job_id': job_id,
                'result_data': {},
                'notes': [],
                'download_url': None,
                'chat_history': [],
            })
        else:
            # Normaler Pfad: Token sofort erstellen, 24h gültig auch bei Fehler.
            session_token = _make_session_token(job_id)
            _save_session(session_token, {
                'job_id': job_id,
                'result_data': {},
                'notes': [],
                'download_url': None,
                'chat_history': [],
            })
            # Bezahlung verbrauchen — Ref + PI können nur 1x für /api/process genutzt werden
            if ref and ref in _store:
                _store[ref]['paid'] = False
                _store[ref]['used_at'] = datetime.utcnow().isoformat() + 'Z'
            if pi_id:
                _consumed_payment_intents[pi_id] = datetime.utcnow()
                # Alte Einträge >25h aufräumen
                cutoff_pi = datetime.utcnow() - timedelta(hours=25)
                for k, ts in list(_consumed_payment_intents.items()):
                    if ts < cutoff_pi:
                        _consumed_payment_intents.pop(k, None)
        # Tentative Status — wird nach Put auf Basis echter Position korrigiert
        with _jobs_lock:
            _jobs[job_id] = {
                'status':   'pending',  # vorläufig, wird gleich aktualisiert
                'progress': 0,
                'created':  datetime.utcnow().isoformat() + 'Z',
                'session_token': session_token,
            }
        # ref/pi_id ans form-dict heften
        form['ref'] = ref or ''
        form['pi_id'] = pi_id or ''
        # Audit: nur die 3 Pflicht-Kategorien zählen + optionale Belege
        _v7_files = {
            'lsb': len(files.get('lsb') or []),
            'streckeneinsatz': len(files.get('se') or []),
            'cas': len(files.get('cas') or []),
            'dp_legacy': len(files.get('dp') or []),  # v11: dp ist nicht mehr Pflicht — Legacy-Tracking
        }
        _audit(job_id, 'job_created', {'year': form['year'], 'base': form['base'], 'files': _v7_files})

        # WICHTIG: ZUERST auf Disk persistieren, DANN in Queue einreihen.
        # Sonst: Crash zwischen put und save → Job in Queue (geht bei Restart verloren)
        # aber NICHT in JOBS_DIR → Frontend pollt 404. Mit save-first: Job überlebt
        # Restart, Restart-Recovery markiert ihn als 'failed' mit klarem Hinweis.
        _save_job_to_disk(job_id)

        # Queue-Tiefe-Limit: bei zu vielen Jobs in der Queue sofort 503 zurück
        # (verhindert OOM bei Spike + lange Wartezeiten)
        MAX_QUEUE_DEPTH = 8  # ~20 Min Wartezeit max
        current_queue_size = _calc_queue.qsize() + (1 if _calc_running_id else 0)
        if current_queue_size >= MAX_QUEUE_DEPTH:
            with _jobs_lock:
                _jobs[job_id]['status'] = 'rejected'
                _jobs[job_id]['error']  = f'Server gerade überlastet ({current_queue_size} Auswertungen in Wartezeit). Bitte in 5-10 Min mit deinem Code (AT-...) erneut versuchen — keine erneute Zahlung nötig.'
            _save_job_to_disk(job_id)
            return jsonify({
                'job_id': job_id,
                'status': 'rejected',
                'error':  _jobs[job_id]['error'],
                'session_token': session_token,
            }), 503

        # v13 Cloud Tasks: Verzweigung nach AEROTAX_EXECUTION_MODE.
        # Thread-Mode (Default): wie bisher in _calc_queue putten — Background-Thread
        # picks up. Funktioniert lokal/dev und auf Plattformen mit langen
        # Background-Tasks (Render Starter, eigener VPS).
        # Cloud-Tasks-Mode: Job + Form persistieren, Cloud Task dispatchen, der ruft
        # /api/internal/process-job — Worker läuft SYNCHRON im HTTP-Request, Cloud Run
        # killt nichts mehr wegen idle-Time.
        if AEROTAX_EXECUTION_MODE == 'cloud_tasks':
            # P0 #90: defensive idempotenter Re-Persist.
            # Die Pflicht-Persistenz lief bereits VOR PI-Consume (oben). Dieser
            # Block ist nur ein Sicherheitsnetz für seltene Sub-Sekunden-Races
            # (z.B. Supabase-TTL gerade umgeschwungen). Bei Fail jetzt: Job war
            # bereits angelegt + PI consumed → wir markieren ihn explizit als
            # UPLOAD_PERSIST_FAILED (retryable, support=true) statt WORKER_RESTARTED.
            sb_ref = (form.get('ref') or '').strip()
            if not sb_ref:
                sb_ref = f'auto-{job_id[:12]}'
                form['ref'] = sb_ref
            files_sb_format = {}
            for k, items in files.items():
                if not items:
                    continue
                files_sb_format[k] = []
                for it in items:
                    if isinstance(it, tuple) and len(it) >= 2:
                        files_sb_format[k].append((it[0], it[1] or f'{k}.pdf'))
                    elif isinstance(it, (bytes, bytearray)):
                        files_sb_format[k].append((bytes(it), f'{k}.pdf'))
                    else:
                        continue
            if files_sb_format:
                try:
                    _save_uploaded_files_supabase(sb_ref, files_sb_format)
                except UploadPersistError as _pe:
                    # Pre-persist hatte Erfolg, Re-persist scheitert — sehr selten.
                    # Job wurde schon angelegt, PI ist consumed. Failed_retryable mit
                    # eigenem reason_code damit Support eingreifen kann.
                    _set_job_failed(job_id, 'UPLOAD_PERSIST_FAILED',
                                     f'defensive_repersist_failed:{type(_pe).__name__}')
                    app.logger.error(
                        f"[process] defensive_repersist_failed job={job_id[:8]} "
                        f"ref={sb_ref[:8]} err={type(_pe).__name__}"
                    )
                    ec = AEROTAX_ERROR_CODES['UPLOAD_PERSIST_FAILED']
                    return jsonify({
                        'job_id':       job_id,
                        'ok':           False,
                        'reason_code':  'UPLOAD_PERSIST_FAILED',
                        'user_title':   ec['user_title'],
                        'user_message': ec['user_message'],
                        'retryable':    ec['retryable'],
                        'support':      ec['support'],
                        'next_actions': ec.get('next_actions', []),
                        'session_token': session_token,
                    }), 503

            # Form ans Job hängen — Worker im nächsten Request liest es aus Persistenz
            with _jobs_lock:
                _jobs[job_id]['form'] = form
                _jobs[job_id]['attempt_id'] = 1
                _jobs[job_id]['status'] = 'queued'
            _save_job_to_disk(job_id)

            try:
                _enqueue_cloud_task(job_id, attempt=1)
            except Exception as _e:
                # Enqueue fail → Job als failed_retryable markieren
                _set_job_failed(job_id, 'WORKER_RESTARTED',
                                 f'Cloud Tasks enqueue failed: {str(_e)[:200]}')
                print(f"[process] cloud_tasks enqueue fail: {_e}")
                return jsonify({
                    'job_id': job_id,
                    'status': 'failed',
                    'error': 'Auswertung konnte nicht gestartet werden. Bitte erneut versuchen.',
                    'session_token': session_token,
                }), 500

            return jsonify({
                'job_id': job_id,
                'status': 'queued',
                'canonical_state': 'queued',
                'execution_mode': 'cloud_tasks',
                'session_token': session_token,
                'poll_url': f'/api/job/{job_id}',
            })

        # ── Thread-Mode (Default / Legacy) ──────────────────────────────
        _calc_queue.put((job_id, form, files))
        queue_pos = _get_queue_position(job_id) or 1
        # Echten Status anhand Position setzen
        initial_status = 'queued' if queue_pos > 1 else 'pending'
        with _jobs_lock:
            _jobs[job_id]['status'] = initial_status
        _save_job_to_disk(job_id)

        return jsonify({
            'job_id': job_id,
            'status': initial_status,
            'queue_position': queue_pos,
            'eta_seconds':    max(0, (queue_pos - 1) * _AVG_JOB_SECONDS),
            'session_token': session_token,
            'poll_url': f'/api/job/{job_id}',
        })

    except Exception as e:
        print(f'Process error: {e}')
        import traceback; traceback.print_exc()
        return jsonify({'error': 'internal_error'}), 500


@app.route('/api/internal/process-job', methods=['POST'])
def internal_process_job():
    """v13 Cloud Tasks Worker — wird von Cloud Tasks aufgerufen, hält die HTTP-
    Connection offen bis Berechnung fertig. Cloud Run sieht aktive Verbindung,
    SIGTERM kommt erst nach Return.

    Auth: OIDC ID-Token vom aerotax-task-invoker Service-Account.
    Body: {"job_id": "...", "attempt": N}

    Idempotenz:
      - status=done → 200 idempotent, kein Re-Compute
      - canonical_state=failed_support → 200 no-retry
      - status=processing mit gleicher/höherer attempt → 200 duplicate
      - sonst: lock auf attempt_id, run.
    """
    if not _verify_internal_task_auth(request):
        return jsonify({'error': 'unauthorized'}), 401

    body = request.get_json(silent=True) or {}
    job_id = body.get('job_id', '').strip()
    attempt = int(body.get('attempt', 1) or 1)
    if not job_id:
        return jsonify({'error': 'job_id required'}), 400

    # Job laden — Memory zuerst, dann Disk
    with _jobs_lock:
        j = _jobs.get(job_id) or _load_job_from_disk(job_id)
        if j:
            _jobs[job_id] = j  # in Memory ziehen
    if not j:
        # Auch nicht auf Disk — vermutlich ephemeral verloren oder älterer Cleanup
        print(f"[worker] job {job_id[:8]} not found — task is no-op")
        return jsonify({'idempotent': True, 'no_op': True, 'reason': 'job not found'}), 200

    # P1 #9 Fix: nur DEFAULT bei missing key, NICHT bei falsy values
    # (vorher: '' / 0 / None wurde fälschlich auf 'pending' gemappt → re-process)
    status = j.get('status', 'pending') or 'pending'
    current_attempt = int(j.get('attempt_id', 0) or 0)

    # ── Idempotenz-Branches ────────────────────────────────────────────
    # done → return 200, kein Re-Compute
    if status in ('done',):
        return jsonify({'idempotent': True, 'status': 'done'}), 200

    # failed_support oder cancelled → kein Retry
    _state = _classify_job_state(j)
    if _state['canonical_state'] == 'failed_support':
        return jsonify({
            'idempotent': True, 'no_retry': True,
            'canonical_state': 'failed_support',
            'reason_code': _state.get('reason_code'),
        }), 200
    if status == 'cancelled':
        return jsonify({'idempotent': True, 'no_retry': True, 'status': 'cancelled'}), 200

    # processing mit gleicher oder höherer attempt → ggf. ignore duplicate,
    # ABER: CR-1 Audit-Fix — wenn `processing_started_at` älter als STALE_THRESHOLD,
    # nehmen wir an dass der Container mid-process gekillt wurde und der Job stuck ist.
    # Re-Process erlauben statt für immer im 'processing'-State stehen zu lassen.
    if status == 'processing' and current_attempt >= attempt:
        _is_stale = False
        try:
            _started_str = (j.get('processing_started_at') or '').replace('Z', '').split('+')[0]
            if _started_str:
                _started = datetime.fromisoformat(_started_str)
                _age_sec = (datetime.utcnow() - _started).total_seconds()
                # 15min ist großzügig für unsere Pipeline (CAS+Sonnet+ReportLab=max 8min)
                if _age_sec > 900:
                    _is_stale = True
                    print(f"[worker] CR-1 stale-detection: job {job_id[:8]} processing for "
                          f"{int(_age_sec)}s — re-attempt allowed (vorheriger Container gekillt?)")
        except Exception as _se:
            print(f"[worker] CR-1 stale-check failed: {_se} — annahme: not stale")
        if not _is_stale:
            return jsonify({
                'idempotent': True, 'duplicate': True,
                'current_attempt': current_attempt, 'task_attempt': attempt,
            }), 200
        # else: fall through to re-process

    # ── Files + Form rekonstruieren ────────────────────────────────────
    form = j.get('form') or {}
    if not form:
        _set_job_failed(job_id, 'WORKER_RESTARTED', 'Job form data missing — cannot run')
        return jsonify({'error': 'job form missing', 'reason_code': 'WORKER_RESTARTED'}), 200

    ref = form.get('ref') or ''
    if not ref:
        _set_job_failed(job_id, 'UPLOAD_EXPIRED', 'No upload ref in job — uploads expired')
        return jsonify({'error': 'no upload ref', 'reason_code': 'UPLOAD_EXPIRED'}), 200

    files_raw = _load_uploaded_files_supabase(ref)
    if not files_raw:
        # P0 #90: ref existiert (Job hat pre-persistet bekommen) aber Files sind weg.
        # Das ist NICHT „Dokumente abgelaufen" (Datenschutz-Cleanup), sondern echtes
        # Persistenz-Problem. User hat ggf. bezahlt — Support muss eingreifen.
        _set_job_failed(job_id, 'UPLOAD_FILES_MISSING',
                         'Uploaded files not retrievable from storage')
        app.logger.error(
            f"[worker] upload_files_missing job={job_id[:8]} ref={ref[:8]}"
        )
        return jsonify({
            'error': 'uploaded files not found',
            'reason_code': 'UPLOAD_FILES_MISSING',
        }), 200

    # Format-Anpassung: _load_uploaded_files_supabase returnt {key: [(bytes, fname), ...]}.
    # Bestehender Code in process()/run_process_async erwartet die selbe Shape — passt.
    files = files_raw

    # ── Lock: attempt_id setzen, status=processing ─────────────────────
    with _jobs_lock:
        j['status'] = 'processing'
        j['attempt_id'] = attempt
        j['processing_started_at'] = datetime.utcnow().isoformat() + 'Z'
        _jobs[job_id] = j
    _save_job_to_disk(job_id)

    # ── Synchron berechnen ────────────────────────────────────────────
    print(f"[worker] job={job_id[:8]} attempt={attempt} start")
    try:
        _run_process_async(job_id, form, files)
    except Exception as e:
        import traceback as _tb
        _tb.print_exc()
        # _run_process_async fängt schon die meisten Errors selbst und setzt status=failed.
        # Falls hier doch was durchkommt: hart als failed markieren.
        _set_job_failed(job_id, 'WORKER_RESTARTED', f'Worker exception: {str(e)[:200]}')

    # Final state lesen
    with _jobs_lock:
        final_j = _jobs.get(job_id) or {}
    final_status = final_j.get('status', 'unknown')
    final_state = _classify_job_state(final_j)
    print(f"[worker] job={job_id[:8]} done status={final_status} canonical={final_state['canonical_state']}")

    # ── Response ───────────────────────────────────────────────────────
    if final_status == 'done':
        return jsonify({'ok': True, 'status': 'done'}), 200
    # failed_retryable → 500 damit Cloud Tasks retried (bis max_attempts=2)
    if final_state['canonical_state'] == 'failed_retryable' and attempt < AEROTAX_MAX_RETRY:
        return jsonify({
            'retryable': True,
            'reason_code': final_state.get('reason_code'),
            'attempt': attempt, 'max_attempts': AEROTAX_MAX_RETRY,
        }), 500
    # failed_support → 200 (kein Retry)
    return jsonify({
        'ok': False,
        'status': final_status,
        'canonical_state': final_state['canonical_state'],
        'reason_code': final_state.get('reason_code'),
    }), 200


def _run_process_async(job_id, form, files):
    """Background-Worker — führt die echte Auswertung durch, schreibt Ergebnis in _jobs."""
    try:
        with _jobs_lock:
            _jobs[job_id]['status'] = 'running'
            _jobs[job_id]['progress'] = 5
        _audit(job_id, 'calculation_started')

        # Plausi-Check: sind die Files typisch zur Kategorie?
        try:
            file_warnings = _validate_file_categories(files)
            if file_warnings:
                _audit(job_id, 'file_validation_warnings', {'warnings': file_warnings})
                print(f"[file-validation] {len(file_warnings)} Warnung(en): {file_warnings[0][:120]}")
        except Exception as e:
            file_warnings = []
            print(f"[file-validation] Skip wegen Fehler: {e}")

        # v10.4: job_id durchreichen für chunked DP-Pipeline (Supabase-Persistenz + Heartbeat)
        result = berechne(form, files, job_id=job_id)
        if isinstance(result, tuple):
            result = result[0]
        # File-Validation-Warnings vorne in Notes einfügen — User soll sie sehen
        if file_warnings:
            existing_notes = result.get('hinweise') or result.get('notes') or []
            if isinstance(existing_notes, list):
                # vorne anhängen damit prominent
                key = 'hinweise' if 'hinweise' in result else 'notes'
                result[key] = list(file_warnings) + existing_notes
        _audit(job_id, 'calculation_done', {
            'gesamt': result.get('gesamt'), 'netto': result.get('netto'),
            'verification': result.get('_verification'),
        })
        # Tag-für-Tag-Klassifikation getrennt loggen (für Debug/Validation,
        # nicht im /api/job-Status weil zu groß). Über /api/job/<id>/audit abrufbar.
        _tage_detail = result.get('_tage_detail') or []
        if _tage_detail or result.get('_klass_summary'):
            _audit(job_id, 'classification_detail', {
                'summary':  result.get('_klass_summary'),
                'nachweis': (result.get('_nachweis') or '')[:2000],
                'unklare_tage':     result.get('_unklare_tage'),
                'audit_notes':      result.get('_audit_notes') or [],
                'unresolved_days':  result.get('_unresolved_days') or [],
                'vma_unmapped_se':  result.get('_vma_unmapped_se') or [],
                'document_health':  result.get('_document_health') or {},
                'z77_audit':        result.get('_z77_audit') or {},
                # v8.6: Diagnose-Listen für Live-Audit
                'extra_fahrtage':         result.get('_extra_fahrtage') or [],
                'extra_arbeitstage':      result.get('_extra_arbeitstage') or [],
                'extra_hotelnaechte':     result.get('_extra_hotelnaechte') or [],
                'wrong_z72_candidates':   result.get('_wrong_z72_candidates') or [],
                'missing_z73_candidates': result.get('_missing_z73_candidates') or [],
                'missing_z76_candidates': result.get('_missing_z76_candidates') or [],
                'missing_deutschland_14_candidates': result.get('_missing_deutschland_14_candidates') or [],
                'aerotax_z76_dates_amounts':   result.get('_aerotax_z76_dates_amounts') or [],
                'rescues':                     result.get('_rescues') or [],
                'training_sequences':          result.get('_training_sequences') or [],
                'training_commute_candidates': result.get('_training_commute_candidates') or [],
                'office_z72_candidates':       result.get('_office_z72_candidates') or [],
                'missing_reader_days':         result.get('_missing_reader_days') or [],
                'hotel_candidate_issues':      result.get('_hotel_candidate_issues') or [],
                'bmf_missing':            result.get('_bmf_missing') or [],
                'iata_unknown':           result.get('_iata_unknown') or [],
                'versions': {
                    'app': APP_VERSION,
                    'engine': ENGINE_VERSION,
                    'readers': READER_VERSIONS,
                    'prompt': PROMPT_VERSION,
                    'bmf_data_year': int(form.get('year', 2025)),
                },
                'tage_detail': _tage_detail,
                # 2026-05-21 — Source-Labeling per Bucket (Highest-Defensible-
                # Produktregel). Frontend/PDF rendern „* Nutzerangabe"-Sternchen
                # und Audit-Hinweise basierend auf source_type pro Bucket.
                # Schema: {bucket: {type, label, user_inputs, star_required}}
                'source_breakdown': {
                    'block_a': {
                        'fahr': {
                            'type': 'mixed',
                            'label': 'CAS-Fahrtage + Nutzerangabe (km) + BMF-Pauschale',
                            'user_inputs': ['km'],
                            'star_required': True,
                            'audit': (
                                f'{form.get("km", "?")} km × Fahrtage × '
                                f'0,30 €/km (bis 20 km) bzw. 0,38 €/km (ab 21. km). '
                                f'Quelle: km vom Nutzer angegeben.'
                            ),
                        },
                        'reinig': {
                            'type': 'calculated',
                            'label': 'Pauschal-Ansatz pro Arbeitstag (Crew-Erfahrungswert)',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': 'Reinigungstage × Pauschal-Satz. Pauschal-Erfahrungswert für Crew-Uniform.',
                        },
                        'trink': {
                            'type': 'calculated',
                            'label': 'Pauschal-Ansatz pro Hotelnacht (Crew-Erfahrungswert)',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': 'Hotelnächte × Pauschal-Satz. Pauschal-Erfahrungswert für Reisenebenkosten.',
                        },
                        'opt_zu': {
                            'type': 'user',
                            'label': 'Belege vom Nutzer hochgeladen',
                            'user_inputs': ['optionale_belege'],
                            'star_required': True,
                            'audit': 'Telefon, Gewerkschaft, Arbeitsmittel etc. Belege vom Nutzer.',
                        },
                    },
                    'block_b': {
                        'vma_72': {
                            'type': 'mixed',
                            'label': 'CAS-Zeiten + commute_min + BMF-Pauschale',
                            'user_inputs': ['anfahrt_min'],
                            'star_required': False,
                            'audit': 'Inland-Tag >8h. Quellen: CAS-Zeiten, BMF §9 Abs. 4a 2025.',
                        },
                        'vma_73': {
                            'type': 'mixed',
                            'label': 'CAS-Tour-Cluster + BMF',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': 'Inland An-/Abreisetag. Quellen: CAS-Tour-Kontext, BMF.',
                        },
                        'vma_74': {
                            'type': 'document',
                            'label': 'CAS overnight Inland + BMF',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': 'Inland 24h-Tag. Quellen: CAS-Übernachtung, BMF.',
                        },
                        'vma_aus': {
                            'type': 'mixed',
                            'label': 'CAS-Layover + SE-foreign-stfrei + BMF-Land',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': (
                                'Auslands-Tage (Z76). Highest-defensible: voll_24h für Mid-Tour-Tage '
                                'wenn SE-Evidence prev+today+next foreign vorhanden. '
                                'Quellen: CAS-Layover, SE-stfrei_ort, BMF 2025.'
                            ),
                        },
                    },
                    'erstattung': {
                        'ag_z17': {
                            'type': 'document',
                            'label': 'Lohnsteuerbescheinigung Zeile 17',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': 'AG-Fahrkostenzuschuss. Quelle: LSB Z17 direkt gelesen.',
                        },
                        'z77': {
                            'type': 'document',
                            'label': 'Streckeneinsatz-Abrechnungen Summenzeilen',
                            'user_inputs': [],
                            'star_required': False,
                            'audit': 'Steuerfreie Spesen pro Monat aus SE-Summenzeilen. Quelle: AG-Beleg.',
                        },
                    },
                    'review_user_inputs': [],  # gefüllt nach review-bulk-answer
                    'legend': {
                        '*': 'Nutzerangabe — bitte Plausibilität selbst prüfen.',
                        'CAS': 'Dienstplan / Crew-Allocation-System',
                        'SE': 'Streckeneinsatz-Abrechnung (AG-Beleg)',
                        'LSB': 'Lohnsteuerbescheinigung',
                        'BMF': 'BMF-Pauschalen § 9 Abs. 4a EStG 2025',
                        'Pauschal-Ansatz': 'Crew-typischer Erfahrungswert (keine BMF-Pauschale)',
                    },
                },
            })

        with _jobs_lock:
            _jobs[job_id]['progress'] = 90

        pdf_bytes = erstelle_pdf(result)
        token = str(uuid.uuid4())
        name = result['name'].replace(' ', '_')
        year = form.get('year', 2025)
        _save_pdf(token, pdf_bytes, f'AeroTax_Auswertung_{year}_{name}.pdf')
        _audit(job_id, 'pdf_created', {'token': token, 'size_kb': len(pdf_bytes)//1024})

        # ── DATENSCHUTZ: ALLE Originaldateien sofort aus dem Speicher + Supabase entfernen ──
        try:
            for k in list(files.keys()):
                files[k] = None
            files.clear()
        except: pass
        # In-Memory _store[ref].files auch leeren
        try:
            ref_used = (form.get('ref') if isinstance(form, dict) else '') or ''
            if ref_used and ref_used in _store and _store[ref_used].get('files'):
                _store[ref_used]['files'] = {}
            # Supabase uploaded_files für ref löschen
            if ref_used:
                _delete_uploaded_files_supabase(ref_used)
        except Exception as _de:
            print(f"[cleanup] partial fail: {_de}")
        # File-bytes aus Result auch entfernen (Belege-Bilder waren da für PDF-Embedding)
        for b in result.get('optionale_belege', []):
            b.pop('file_bytes_list', None)
        _audit(job_id, 'files_purged', {'note': 'Originaldokumente sofort nach PDF-Generierung gelöscht (RAM + Supabase)'})

        # Filter: Felder die zum Frontend gehen — Dicts/Listen behalten
        # (außer file_bytes_list die explizit ausgeschlossen wird, da Bytes nicht JSON-serializable)
        def _is_jsonable(v):
            if isinstance(v, (int, float, str, bool)) or v is None:
                return True
            if isinstance(v, (list, tuple)):
                return all(_is_jsonable(x) for x in v)
            if isinstance(v, dict):
                return all(isinstance(k, str) and _is_jsonable(x) for k, x in v.items())
            return False
        safe = {k: v for k, v in result.items()
                if k != 'optionale_belege' and _is_jsonable(v)}
        opt_belege_safe = []
        for b in result.get('optionale_belege', []):
            b_safe = {k: v for k, v in b.items() if k != 'file_bytes_list'}
            opt_belege_safe.append(b_safe)

        # Form-Inputs für Edit-Restore mit-speichern (alle User-Eingaben)
        safe['_form_inputs'] = {
            'name':           form.get('name', ''),
            'vorname':        form.get('vorname', ''),
            'nachname':       form.get('nachname', ''),
            'year':           form.get('year', 2025),
            'base':           form.get('base', 'Frankfurt (FRA)'),
            'anreise':        form.get('anreise', 'auto'),
            'km':             form.get('km', 0),
            'fahrzeug':       form.get('fahrzeug', 'verbrenner'),
            'oepnv_kosten':   form.get('oepnv_kosten', 0),
            'shuttle_kosten': form.get('shuttle_kosten', 0),
            'jobticket':      form.get('jobticket', 'nein'),
            'anfahrt_min':    form.get('anfahrt_min', 0),
        }
        safe['_consumed_at'] = None  # wird beim PDF-Download gesetzt

        # Session-Token wurde bereits beim job_created erstellt — jetzt nur Result reinpacken
        with _jobs_lock:
            session_token = _jobs[job_id].get('session_token')
        # v8.22 Rest-1: kurzer ATX-Code zusätzlich zum Token
        short_code = _make_short_code(session_token) if session_token else ''
        safe['short_code'] = short_code
        if session_token:
            _save_session(session_token, {
                'job_id': job_id,
                'result_data': safe,
                'notes': result.get('notes', []),
                'download_url': f'/api/download/{token}',
                'short_code': short_code,
                'chat_history': [],
            })
            # Verknüpfung dl_token → session_token, damit Download den Token consumen kann
            _store.setdefault(token, {})['session_token'] = session_token
            # B9-Fix: Wenn User share_roster aktiv hat, persistieren wir das
            # tage_detail in roster_snapshot_<token>.json, damit Friends
            # darauf auch nach Container-Restart Zugriff haben (vorher: nur
            # in-memory _store → bei Render-Sleep verlor man alle Friend-Rosters).
            try:
                # BUG-017-Fix: share_roster SB-primary lesen (default-on), nicht
                # disk-only mit truthy-Check. Auf einer frischen Cloud-Run-Instanz
                # ist das Disk-File leer → der alte truthy-Check unterdrückte das
                # Auto-Save obwohl der User share_roster (default an) hat.
                prof = (_profile_load(session_token) or {}).get('profile') or {}
                if prof.get('share_roster') is not False:
                    _tage = safe.get('_tage_detail') or []
                    # Supabase-first + Disk (multi-instance-sicher).
                    _roster_snapshot_save(session_token, {
                        'taken_at': datetime.now().isoformat(),
                        'auto_saved': True,
                        'tage': _tage,
                    })
                    # Crews-on-Flight: Flugnummer-Assignments ingesten
                    # (best-effort). Speist /api/crew/flight-Lookup.
                    _crew_flight_ingest(session_token, _tage)
                    # Crew-Graph: Same-Flight-Overlap-Kanten neu ableiten
                    # (best-effort, idempotent). Nach _crew_flight_ingest.
                    try:
                        from blueprints.crew_graph_blueprint import rebuild_overlap_edges
                        rebuild_overlap_edges(session_token, _tage)
                    except Exception as _cg_e:
                        app.logger.warning(f'[crew-graph] autosave_rebuild_fail {type(_cg_e).__name__}: {str(_cg_e)[:120]}')
            except Exception as _e:
                app.logger.warning(f'[share-roster-auto-save] {_e}')

        with _jobs_lock:
            _jobs[job_id] = {
                **_jobs[job_id],
                'status':       'done',
                'progress':     100,
                'completed':    datetime.utcnow().isoformat() + 'Z',
                'download_url': f'/api/download/{token}',
                'data':         safe,
                'abrechnungen': result.get('abrechnungen', []),
                'optionale_belege': opt_belege_safe,
                'notes':        result.get('notes', []),
            }
            _pi_for_lock = ((_jobs[job_id].get('form') or {}).get('pi_id') or '').strip()
        # R44 (2026-05-28) Monats-Tracking: Eintrag in User-History für Dashboard
        try:
            _hist_token = token
            _hist_entry = {
                'job_id':       job_id,
                'completed_at': datetime.utcnow().isoformat() + 'Z',
                'year':         int(safe.get('year', 2025) or 2025),
                'gesamt':       float(safe.get('gesamt', 0) or 0),
                'vma_aus':      float(safe.get('vma_aus', 0) or 0),
                'vma_in':       float(safe.get('vma_in', 0) or 0),
                'hotel_naechte': int(safe.get('hotel_naechte', 0) or 0),
                'fahr_tage':    int(safe.get('fahr_tage', 0) or 0),
                'arbeitstage':  int(safe.get('arbeitstage', 0) or 0),
                'reinigungstage': int(safe.get('reinigungstage', 0) or 0),
                'name':         safe.get('name', '') or 'Auswertung',
                'summary_label': f"Steuerjahr {safe.get('year', 2025)}",
            }
            _user_history_append(_hist_token, _hist_entry)
        except Exception as _hist_e:
            print(f'[r44-history] save failed: {_hist_e}')
        # P0 #96: Lock-Status auf 'done' setzen — Cleanup-Cron darf nach 30 Tagen
        if _pi_for_lock:
            _update_payment_intent_lock_status(_pi_for_lock, 'done', job_id=job_id)

    except Exception as e:
        import traceback
        traceback.print_exc()
        _audit(job_id, 'calculation_failed', {'error': str(e)})
        # Session-Token bleibt gültig — User kann mit demselben Token einfach erneut auswerten
        with _jobs_lock:
            session_token = _jobs[job_id].get('session_token', '')
            _jobs[job_id] = {
                **_jobs[job_id],
                'status':   'failed',
                'error':    str(e),
                'completed': datetime.utcnow().isoformat() + 'Z',
            }
        _save_job_to_disk(job_id)
        # P1 #114 Fix: kein Session-Token-Leak in Cloud-Logs. Token war 24h gültig,
        # Cloud-Log-Reader konnte impersonate. Nur Token-Prefix für Audit-Korrelation.
        _tok_safe = (session_token[:8] + '…') if session_token else 'no-token'
        app.logger.warning(f"[FAIL {job_id[:8]}] Job failed. session_token_prefix={_tok_safe}")
    finally:
        # Erfolg oder Fehler: persistiere Status nach Disk
        _save_job_to_disk(job_id)


# ════════════════════════════════════════════════════════════════════════════
# v12 Phase A — Failure-Safe State-Machine
# ════════════════════════════════════════════════════════════════════════════
# Zentrale Wahrheit für „in welchem Zustand befindet sich diese Auswertung?".
# Alle status-relevanten Endpoints lesen NUR über _classify_job_state() —
# keine Ad-hoc-Heuristik mit '_followme_align_failed' / status / pending_reread
# verstreut über den Code-Base.
#
# Vertrag mit Frontend: jede status-Response enthält canonical_state +
# reason_code + user_title + user_message + next_actions[]. Frontend rendert
# nach canonical_state — keine ad-hoc Frontend-Heuristik mehr.
# ════════════════════════════════════════════════════════════════════════════

AEROTAX_CANONICAL_STATES = (
    'created',           # Job-Skelett, kein Upload
    'uploaded',          # Dateien da, noch nicht im Queue
    'queued',            # In Queue, wartet auf Worker
    'processing',        # Worker rechnet (LSB → SE → CAS → Klassifikation → PDF)
    'needs_review',      # Berechnet, aber offene Punkte (kritisch oder optional)
    'done',              # PDF freigegeben
    'failed_retryable',  # Transient — Retry sicher (Worker-Restart, Timeout, Rate-Limit)
    'failed_support',    # Rechen-Integrität verletzt — Support empfehlen
    'expired',           # Session-Token > 24h
    'deleted',           # User hat explizit gelöscht
)

# Max-Retries pro Session. Bei Überschreitung → failed_support (kein weiterer Retry).
AEROTAX_MAX_RETRY = 2

# Error-Codes — strukturierter Vertrag mit Frontend.
# Pro Code: user_title + user_message + retryable + support.
# user_message ist immer freundlich, immer deutsch, nie technisch.
