@app.route('/api/admin/qa-seed', methods=['POST'])
def admin_qa_seed():
    """Synthetic session seeder für Browser-QA. Dormant bis env gesetzt.

    Body: {"scenario": "needs_review" | "done"}
    Header: X-QA-Seed-Token: <muss zu env AEROTAX_QA_SEED_TOKEN matchen>

    Returns: {token, short_code, canonical_state, pdf_allowed, download_url, expires_at}
    """
    expected = os.environ.get('AEROTAX_QA_SEED_TOKEN', '').strip()
    if not expected:
        return jsonify({
            'error': 'qa-seed endpoint dormant',
            'hint':  'set env AEROTAX_QA_SEED_TOKEN to enable',
        }), 403
    provided = (request.headers.get('X-QA-Seed-Token') or '').strip()
    if not provided or not hmac.compare_digest(expected, provided):
        return jsonify({'error': 'Unauthorized'}), 401

    body = request.get_json(silent=True) or {}
    scenario = (body.get('scenario') or '').strip().lower()
    if scenario not in ('needs_review', 'done'):
        return jsonify({'error': "scenario must be 'needs_review' or 'done'"}), 400

    job_id = str(uuid.uuid4())
    result_data = dict(_QA_SEED_RESULT_TEMPLATE)
    result_data['datum'] = datetime.now().strftime('%d.%m.%Y')

    if scenario == 'needs_review':
        result_data['_review_items'] = _build_qa_seed_review_items()
        download_url = None
    else:  # done
        result_data['_review_items'] = []
        try:
            pdf_bytes = erstelle_pdf(result_data)
            pdf_token = str(uuid.uuid4())
            _save_pdf(pdf_token, pdf_bytes, 'AeroTax_QA_Seed_2025.pdf', hours=24)
            download_url = f'/api/download/{pdf_token}'
        except Exception as e:
            # Fehlerdetail NUR server-side loggen — keine Exception-Interna
            # (Pfade/Klassennamen/Stack-Hinweise) im Response-Body (Audit 2026-07-01).
            print(f"[qa-seed] PDF generation failed: {type(e).__name__}: {e}")
            return jsonify({'error': 'pdf_generation_failed'}), 500

    token = _make_session_token(job_id)

    job_entry = {
        'job_id':         job_id,
        'status':         'done',
        'data':           result_data,
        'session_token':  token,
        'created_at':     datetime.utcnow().isoformat() + 'Z',
        'updated_at':     datetime.utcnow().isoformat() + 'Z',
        '_qa_seed':       True,
    }
    with _jobs_lock:
        _jobs[job_id] = job_entry
    _save_job_to_disk(job_id)

    _save_session(token, {
        'job_id':       job_id,
        'result_data':  result_data,
        'notes':        [],
        'download_url': download_url,
        'chat_history': [],
    })

    state = _classify_job_state(job_entry, None)
    expires_at = (datetime.utcnow() + timedelta(hours=SESSION_HOURS)).isoformat() + 'Z'

    # Token-Prefix wird gehasht statt raw geloggt, damit Cloud-Run-Logs kein
    # tatsächliches Session-Token-Material enthalten (Security FAIL BE-8).
    token_hash = _hashlib.sha256(token.encode('utf-8')).hexdigest()[:12]
    print(f"[qa-seed] scenario={scenario} token_h={token_hash} job_id={job_id[:8]} "
          f"canonical={state['canonical_state']} pdf_allowed={state['pdf_allowed']}")

    return jsonify({
        'token':            token,
        'short_code':       _make_short_code(token),
        'job_id':           job_id,
        'scenario':         scenario,
        'canonical_state':  state['canonical_state'],
        'pdf_allowed':      state['pdf_allowed'],
        'download_url':     download_url,
        'expires_at':       expires_at,
        'note':             'QA test session — synthetic data, no Sonnet, no real customer PDF',
    }), 201


@app.route('/api/qa/<qid>/upvote', methods=['POST'])
def qa_upvote(qid):
    """Upvote für Frage oder Antwort. Body: {answer_id?}."""
    ip = request.headers.get('X-Forwarded-For', request.remote_addr or 'unknown').split(',')[0].strip()
    if not _qa_rate_check(ip, 'upvote', max_per_hour=60):
        return jsonify({'error': 'Zu viele Upvotes — bitte warte'}), 429
    body = request.get_json(silent=True) or {}
    answer_id = body.get('answer_id')
    ip_hash = _hashlib.sha256((ip + _recovery_pepper()).encode()).hexdigest()[:8]
    target_type = 'answer' if answer_id else 'question'
    target_id = answer_id if answer_id else qid

    if SB_AVAILABLE:
        try:
            # Minimaler Spam-Schutz: 1-Sekunden-Window — User kann frei mehrfach liken
            cutoff = (datetime.utcnow() - timedelta(seconds=1)).isoformat()
            check = sb.table('upvotes').select('id').eq('target_type', target_type).eq('target_id', target_id).eq('ip_hash', ip_hash).gte('created_at', cutoff).limit(1).execute()
            if check.data:
                return jsonify({'error': 'Bitte langsamer klicken'}), 429
            # Alte Votes derselben IP fürs selbe Target löschen (>1s alt) — UNIQUE-Constraint Workaround
            try:
                sb.table('upvotes').delete().eq('target_type', target_type).eq('target_id', target_id).eq('ip_hash', ip_hash).lt('created_at', cutoff).execute()
            except Exception as _de:
                print(f"[supabase] cleanup old votes fail: {_de}")
            sb.table('upvotes').insert({
                'target_type': target_type,
                'target_id': target_id,
                'ip_hash': ip_hash,
            }).execute()
            # Counts zurückgeben
            cutoff_30d = (datetime.utcnow() - timedelta(days=30)).isoformat()
            r30 = sb.table('upvotes').select('id', count='exact').eq('target_type', target_type).eq('target_id', target_id).gte('created_at', cutoff_30d).execute()
            rtotal = sb.table('upvotes').select('id', count='exact').eq('target_type', target_type).eq('target_id', target_id).execute()
            return jsonify({
                'ok': True,
                'upvotes_30d': r30.count or 0,
                'upvotes_total': rtotal.count or 0,
            })
        except Exception as e:
            err_str = str(e).lower()
            if 'unique' in err_str or 'duplicate' in err_str:
                return jsonify({'error': 'Schon gevotet — bitte 1 Stunde warten'}), 429
            print(f"[supabase] upvote fail: {e}")
            return jsonify({'error': 'Speichern fehlgeschlagen'}), 500

    # Disk-Fallback
    vote = {'ts': datetime.utcnow().isoformat() + 'Z', 'h': ip_hash}
    with _qa_lock:
        questions = _qa_load()
        for q in questions:
            if q['id'] == qid:
                target = None
                if answer_id:
                    for a in q.get('answers', []):
                        if a['id'] == answer_id:
                            target = a; break
                else:
                    target = q
                if not target:
                    return jsonify({'error': 'Antwort nicht gefunden'}), 404
                target.setdefault('upvotes_log', [])
                cutoff = datetime.utcnow() - timedelta(seconds=1)
                already_voted = any(
                    v.get('h') == ip_hash and datetime.fromisoformat(v.get('ts','').replace('Z','')) >= cutoff
                    for v in target['upvotes_log']
                )
                if already_voted:
                    return jsonify({'error': 'Bitte langsamer klicken'}), 429
                target['upvotes_log'].append(vote)
                _qa_save(questions)
                return jsonify({
                    'ok': True,
                    'upvotes_30d': _qa_effective_upvotes(target['upvotes_log']),
                    'upvotes_total': _qa_total_upvotes(target['upvotes_log']),
                })
    return jsonify({'error': 'Nicht gefunden'}), 404


# ════════════════════════════════════════════════════════════════════════
# R44 (2026-05-28) — Monats-Tracking-Endpoints für AeroTax-App
# Speichert vergangene Auswertungen pro User-Token in einem JSON-Index
# damit das Frontend eine "Verlauf"-View bauen kann. Storage: einfache
# JSON-Datei pro Token unter _user_history_state/. Privat-tauglich,
# kein DB-Aufwand.
# ════════════════════════════════════════════════════════════════════════
_USER_HISTORY_DIR = '_user_history_state'

def _user_history_path(token):
    """Token → JSON-Pfad. Token wird sanitized (nur a-z0-9-)."""
    import os
    import re
    if not token or not isinstance(token, str):
        return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe:
        return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'{safe}.json')


# ── User-History SB persistence (PERSISTENCE-FIX 2026-06-07) ──────────────
# Vorher disk-only (_user_history_state/<token>.json) → auf Cloud Run bei jedem
# Redeploy/Restart weg. Pattern wie user_licenses/layover_recs:
#   SB primary, Disk mirror, Lazy-Migrate beim ersten SB-leeren Read.
# Schema: 1 Row pro Auswertung, PK (token, key). key = job_id wenn vorhanden,
# sonst datum (= bestehende Dedup-Identität). Felder liegen in entry-jsonb.
def _user_history_entry_key(entry):
    """Dedup-/PK-key einer History-Entry: job_id wenn vorhanden, sonst datum."""
    if not isinstance(entry, dict):
        return None
    jid = entry.get('job_id')
    if jid:
        return str(jid)
    dt = entry.get('datum')
    if dt:
        return str(dt)
    return None


def _user_history_load_from_supabase(token):
    """Alle History-Entries eines Tokens aus SB, neueste zuerst.
    None bei SB-down/error. Dict {token, entries:[...]} bei Hit (auch leer)."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('user_history').select('entry,created_at')
             .eq('token', token).order('created_at', desc=True)
             .limit(60).execute())
        entries = []
        for row in (r.data or []):
            e = row.get('entry')
            if isinstance(e, dict):
                entries.append(e)
        return {'token': token, 'entries': entries}
    except Exception as e:
        app.logger.warning(
            f'[user-history] sb_load_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:120]}')
        return None


def _user_history_upsert_to_supabase(token, entry):
    """Upsert einer einzelnen History-Entry (PK token,key). True bei Erfolg."""
    if not SB_AVAILABLE or not token:
        return False
    key = _user_history_entry_key(entry)
    if not key:
        return False
    now = datetime.now(timezone.utc).isoformat()
    row = {'token': token, 'key': key, 'entry': entry, 'updated_at': now}
    try:
        sb.table('user_history').upsert(row, on_conflict='token,key').execute()
        return True
    except Exception as e:
        app.logger.error(
            f'[user-history] sb_upsert_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}')
        return False


def _user_history_load_from_disk(token):
    p = _user_history_path(token)
    if not p:
        return {'token': token, 'entries': []}
    try:
        with open(p) as f:
            return json.load(f)
    except FileNotFoundError:
        return {'token': token, 'entries': []}
    except Exception:
        return {'token': token, 'entries': []}


def _user_history_load(token):
    """SB primary, Disk fallback. Lazy-migriert disk→SB beim ersten Read wenn
    SB leer aber Disk-Entries existieren. Gleiche Shape wie früher:
    {token, entries:[...], _last_updated?}."""
    if not token:
        return {'token': token, 'entries': []}
    sb_data = _user_history_load_from_supabase(token)
    if sb_data is not None and sb_data.get('entries'):
        return sb_data
    # SB leer/down → Disk-Fallback (+ Lazy-Migrate wenn SB up aber leer)
    disk = _user_history_load_from_disk(token)
    disk_entries = (disk or {}).get('entries') or []
    if sb_data is not None and not sb_data.get('entries') and disk_entries:
        app.logger.info(f'[user-history] lazy-migrate tok={token[:8]} disk→supabase ({len(disk_entries)})')
        for e in disk_entries:
            _user_history_upsert_to_supabase(token, e)
    return disk


def _user_history_save_to_disk(token, data):
    p = _user_history_path(token)
    if not p:
        return False
    try:
        _atomic_write_json(p, data, ensure_ascii=False, indent=2)
        return True
    except Exception:
        return False


def _user_history_append(token, entry):
    """Hängt eine fertige Auswertung an die Token-History.
    entry: {datum, year, month?, gesamt, vma_aus, hotel_naechte, fahr_tage,
            arbeitstage, job_id, summary_label}
    SB-primary (single-Entry-Upsert) + Disk-Mirror (best-effort)."""
    if not token:
        return False
    # SB: einzelne Entry upsert (PK token,key dedupt nach job_id/datum)
    sb_ok = _user_history_upsert_to_supabase(token, entry)
    # Disk-Mirror: bestehende Liste lesen, dedup + insert + cap, zurückschreiben
    data = _user_history_load_from_disk(token)
    if 'entries' not in data or not isinstance(data['entries'], list):
        data['entries'] = []
    key = _user_history_entry_key(entry)
    if key:
        data['entries'] = [e for e in data['entries']
                           if _user_history_entry_key(e) != key]
    data['entries'].insert(0, entry)
    data['entries'] = data['entries'][:60]  # max 60 = 5 Jahre Monate
    data['_last_updated'] = datetime.now().isoformat()
    disk_ok = _user_history_save_to_disk(token, data)
    if not (sb_ok or disk_ok):
        app.logger.error(f'[user-history] CRITICAL tok={token[:8]}: weder SB noch Disk gesichert!')
        return False
    return True


@app.route('/api/user/history/<token>', methods=['GET'])
def get_user_history(token):
    """Listet alle vergangenen Auswertungen eines Tokens.

    Response: {token, entries: [...], count}
    entries sind sortiert (neueste zuerst).
    """
    data = _user_history_load(token)
    return jsonify({
        'token': token,
        'entries': data.get('entries', []) or [],
        'count': len(data.get('entries', []) or []),
        'last_updated': data.get('_last_updated'),
    })


# ════════════════════════════════════════════════════════════════════════
# R45 (2026-05-28) Profile + Friends Stub-Endpoints für AeroCrew-App-Roadmap
# Aktuell File-Storage. Bei Vollausbau: PostgreSQL-Migration.
# ════════════════════════════════════════════════════════════════════════
def _user_profile_path(token):
    import os, re
    if not token: return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe: return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'profile_{safe}.json')


# ── P0-Fix Phase 2 (2026-05-31): user_profiles + user_friends + user_push_tokens
# in Supabase persistieren. Vorher lebten alle 3 nur auf ephemeral Container-disk
# → bei jedem Cloud-Run-Redeploy = wiped. Pattern wie _auth_load/_save:
#   load_from_sb → primary; load_from_disk → fallback; lazy-migration einmalig
#   beim ersten Read wenn SB leer aber Disk-Daten vorhanden.
# Scope-Hinweis: NUR die profile{...}-Whitelist-Felder werden in SB gespiegelt
# (name/homebase/position/airline/hometown/share_*/current_city/employers +
# metadata-jsonb für unknown keys). Side-Keys: subscription (W18) sowie
# sponsored_slots, marker_mapping, lufthansa_credentials, lufthansa_last_sync
# (W18-Followup 2026-06-10, via _profile_sidekey_get/_set) werden in
# metadata-jsonb mitgespiegelt; lufthansa_events + crew_aircraft bleiben
# disk-only (Bloat bzw. separater Patch).

_PROFILE_KNOWN_COLS = {
    'name', 'homebase', 'position', 'airline', 'hometown',
    'share_roster', 'employers',
    # Home-Address (2026-06-06): Commute-Distance / Smart-Pickup. Vorher
    # on-device-only → bei Re-Install verloren. Echte Top-Level-Spalten
    # (siehe Migration 20260606_home_address.sql), nicht metadata-jsonb.
    'home_address', 'home_latitude', 'home_longitude',
    'home_transport_mode', 'home_geocoded',
}


def _profile_load_from_supabase(token):
    """Liest eine Profile-Row aus Supabase. None bei SB-down/error oder wenn
    Token keine Row hat. Dict bei Hit (auch wenn alle Felder leer)."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = sb.table('user_profiles').select('*').eq('token', token).limit(1).execute()
        rows = r.data or []
        if not rows:
            return None
        row = rows[0]
        prof = {}
        for k in _PROFILE_KNOWN_COLS:
            v = row.get(k)
            if v is not None:
                prof[k] = v
        if prof.get('employers') is None:
            prof['employers'] = []
        md = row.get('metadata') or {}
        if isinstance(md, dict):
            # share_location, current_city und andere unknown-keys als
            # Top-Level zurückfalten — damit Caller die alte Profil-Shape sehen
            for k, v in md.items():
                if k not in prof:
                    prof[k] = v
        # FIX (Bug-Hunt #10): updated_at durchreichen, damit die Family-Card
        # „zuletzt aktiv" (last_seen_iso) auf SB-primary-Hosting funktioniert.
        if row.get('updated_at') is not None:
            prof['_updated_at'] = row.get('updated_at')
        return prof
    except Exception as e:
        app.logger.warning(
            f'[profile] sb_load_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:120]}'
        )
        return None


# ── SQL-RPC-Wrapper (Data-Layer-Refactor 2026-07-01) ────────────────────────
# Atomare server-seitige Mutationen (Counter-Bumps, metadata-Merge) via RPC
# statt read-modify-write in Python (Lost-Updates über mehrere Cloud-Run-
# Instanzen). Die RPCs kommen aus supabase_migrations/20260701_data_layer.sql
# und werden vom User MANUELL im SQL-Editor applied — der Code MUSS ohne sie
# funktionieren: fehlt eine RPC (PGRST202), wird sie für diesen Prozess
# deaktiviert (einmal geloggt) und der Caller nutzt seinen degradierten
# best-effort-Fallback (per-Row read-modify-write).
_SOCIAL_RPC_DISABLED = set()


def _social_rpc_call(fn_name, params):
    """Ruft eine Postgres-RPC. Returns (ok, data). ok=False ⇒ Caller-Fallback."""
    if not SB_AVAILABLE or fn_name in _SOCIAL_RPC_DISABLED:
        return False, None
    try:
        r = sb.rpc(fn_name, params).execute()
        return True, r.data
    except Exception as e:
        msg = str(e)
        if 'PGRST202' in msg or 'Could not find the function' in msg \
                or 'does not exist' in msg:
            if fn_name not in _SOCIAL_RPC_DISABLED:
                _SOCIAL_RPC_DISABLED.add(fn_name)
                app.logger.warning(
                    f'[rpc] {fn_name} fehlt in Supabase — Migration '
                    f'supabase_migrations/20260701_data_layer.sql anwenden. '
                    f'Degradierter read-modify-write-Fallback aktiv.')
        else:
            app.logger.warning(
                f'[rpc] {fn_name} failed: {type(e).__name__}: {msg[:120]}')
        return False, None


# ── Fehlende-Tabelle-Degradierung (Migrations werden manuell applied) ───────
# Neue Durability-Tabellen (user_flight_ops, user_voice_notes aus
# supabase_migrations/20260702_durability.sql) legt der User MANUELL im
# SQL-Editor an. Bis dahin wirft PostgREST PGRST205 ("Could not find the table
# ... in the schema cache"). Der Code MUSS ohne die Tabelle laufen und auf Disk
# degradieren — exakt wie die RPC-Fallbacks oben. Pro Tabelle einmal loggen.
_SB_TABLE_MISSING = set()


def _sb_table_is_missing(tbl, err):
    """True wenn `err` ein 'Tabelle fehlt'-Fehler ist. Loggt einmal pro Tabelle."""
    msg = str(err)
    if 'PGRST205' in msg or 'Could not find the table' in msg \
            or ('schema cache' in msg and 'table' in msg.lower()):
        if tbl not in _SB_TABLE_MISSING:
            _SB_TABLE_MISSING.add(tbl)
            app.logger.warning(
                f'[sb] Tabelle {tbl} fehlt in Supabase — Migration '
                f'supabase_migrations/20260702_durability.sql anwenden. '
                f'Disk-Fallback aktiv.')
        return True
    return False


def _profile_metadata_merge_sb(token, patch):
    """Atomarer metadata-Merge (coalesce(metadata,'{}') || patch) via RPC.
    Returns True wenn der Merge server-seitig eine EXISTIERENDE Row traf
    (oder nichts zu mergen war); False ⇒ Caller nutzt den alten
    read-merge-upsert-Pfad (legt auch die Row neu an, best-effort)."""
    if not patch:
        return True
    ok, data = _social_rpc_call('profile_metadata_merge',
                                {'p_token': token, 'p_patch': patch})
    if not ok:
        return False
    # RPC returnt die Zahl der upgedateten Rows (int, ggf. als 1-Element-Liste
    # gewrappt). Alles andere (0, None, unerwartete Shape) ⇒ Fallback.
    if isinstance(data, list) and data:
        data = (next(iter(data[0].values()), None)
                if isinstance(data[0], dict) else data[0])
    if not isinstance(data, (int, float, str)) or isinstance(data, bool):
        return False
    try:
        return int(data) >= 1
    except (TypeError, ValueError):
        return False


def _profile_save_to_supabase(token, profile):
    """Upsert einer Profile-Row. True/False für Erfolg."""
    if not SB_AVAILABLE or not token:
        return False
    profile = profile or {}
    row = {'token': token, 'updated_at': datetime.now(timezone.utc).isoformat()}
    meta = {}
    for k, v in profile.items():
        if k in _PROFILE_KNOWN_COLS:
            row[k] = v
        else:
            meta[k] = v
    # DURABILITY (2026-06-29 → atomar seit 2026-07-01): metadata-jsonb NICHT
    # clobbern. Ein voller Overwrite der metadata-Spalte loeschte avatar_url/
    # location_source/current_city/share_location fuer JEDEN aktiven User (DER
    # Avatar-Verschwinde-Bug: Foto in R2 vorhanden, Pointer in metadata weg).
    # Primärpfad jetzt ATOMAR: RPC profile_metadata_merge (server-seitiges
    # `||`, trifft nur existierende Rows) + Known-Cols-Upsert OHNE
    # metadata-Key (Spalte bleibt unberührt) — kein read-modify-write-Fenster
    # mehr zwischen zwei Instanzen.
    if _profile_metadata_merge_sb(token, meta):
        try:
            sb.table('user_profiles').upsert(row, on_conflict='token').execute()
            return True
        except Exception as e:
            app.logger.error(
                f'[profile] sb_save_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}'
            )
            return False
    # Fallback (RPC fehlt/failt ODER Row existiert noch nicht): bisheriger
    # best-effort read-merge-upsert — legt die Row inkl. metadata an.
    try:
        prev = sb.table('user_profiles').select('metadata') \
                 .eq('token', token).limit(1).execute().data or []
        if prev:
            base = prev[0].get('metadata') or {}
            if isinstance(base, dict):
                base.update(meta)
                meta = base
    except Exception:
        pass  # Merge best-effort — im Zweifel schreiben statt 500
    row['metadata'] = meta
    try:
        sb.table('user_profiles').upsert(row, on_conflict='token').execute()
        return True
    except Exception as e:
        app.logger.error(
            f'[profile] sb_save_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


def _profile_load_from_disk(token):
    """Liest komplette profile-Disk-Datei. Returns dict (mind. {token,profile:{}})."""
    p = _user_profile_path(token)
    if not p:
        return {'token': token, 'profile': {}}
    try:
        with open(p) as f:
            return json.load(f) or {'token': token, 'profile': {}}
    except FileNotFoundError:
        return {'token': token, 'profile': {}}
    except Exception:
        return {'token': token, 'profile': {}}


def _profile_load(token):
    """SB primary, Disk fallback. Lazy-migriert disk→SB beim ersten Read wenn
    SB-Row fehlt aber Disk-Daten existieren.
    Returns gleiche Shape wie früher: {token, profile, [_updated_at, ...]} — d.h.
    SB-Daten werden in den 'profile'-Subkey gewrappt damit alle bestehenden
    Caller (`(json.load() or {}).get('profile', {})`) ohne Änderung weiterlaufen.
    Bei Disk-Fallback bleibt der komplette Disk-Inhalt erhalten (subscription,
    crew_aircraft, etc.) — die SB-only-Path liefert nur 'profile'.
    """
    if not token:
        return {'token': token, 'profile': {}}
    sb_prof = _profile_load_from_supabase(token)
    if sb_prof is not None:
        disk_full = _profile_load_from_disk(token)
        out = {k: v for k, v in (disk_full or {}).items() if k not in ('token', 'profile')}
        out['token'] = token
        out['profile'] = sb_prof
        return out
    # SB-Miss: disk-Fallback + lazy-Migration wenn SB up
    disk_full = _profile_load_from_disk(token)
    disk_prof = (disk_full or {}).get('profile') or {}
    if SB_AVAILABLE and disk_prof:
        app.logger.info(f'[profile] lazy-migrate tok={token[:8]} disk→supabase')
        _profile_save_to_supabase(token, disk_prof)
    return disk_full


# Schlanke metadata-Keys die Friend-/Social-Listen brauchen. Bewusst OHNE
# avatar_b64 & Co. — metadata kann ~270KB Bild-Bytes pro User tragen, ein
# `select metadata` über 50 Friends wäre >13MB Response für eine Namensliste.
_PROFILE_BULK_META_KEYS = (
    'avatar_url', 'share_location', 'current_city', 'location_source',
    'role', 'account_type',
    # PRE-FLIGHT-TIMELINE (2026-07-12): selbst angegebene Fahrzeit
    # Wohnung→Flughafen (Minuten) — friends-today reicht sie in die
    # „Fahrt zum Flughafen"-Phase des crew_state-Resolvers.
    'commute_minutes',
)


def _profiles_load_bulk(tokens, include_metadata=False):
    """Batch-Load von Profil-Dicts für viele Tokens in EINEM SB-Query statt
    N× _profile_load (N+1-Killer für Friend-Listen). Returns {token: profile}
    — profile hat dieselbe Shape wie _profile_load(token)['profile'] (Known-
    Cols + zurückgefaltete metadata-Keys), aber default NUR die schlanken
    _PROFILE_BULK_META_KEYS (via PostgREST `alias:metadata->>key`).
    include_metadata=True lädt die volle metadata-jsonb; avatar_b64/
    avatar_bytes werden trotzdem sofort gestrippt (Bloat-Schutz).
    Tokens ohne SB-Row fallen auf die Disk-Kopie zurück (best-effort, kein
    Lazy-Migrate hier — das macht weiterhin _profile_load auf Einzelpfaden).
    Bei SB-down: kompletter Disk-Fallback pro Token."""
    out = {}
    toks = [t for t in dict.fromkeys(tokens or []) if t]
    if not toks:
        return out
    sb_ok = False
    if SB_AVAILABLE:
        if include_metadata:
            cols = 'token,updated_at,metadata,' + ','.join(sorted(_PROFILE_KNOWN_COLS))
        else:
            cols = ('token,updated_at,' + ','.join(sorted(_PROFILE_KNOWN_COLS)) + ','
                    + ','.join(f'{k}:metadata->>{k}' for k in _PROFILE_BULK_META_KEYS))
        try:
            for i in range(0, len(toks), 200):
                r = (sb.table('user_profiles').select(cols)
                     .in_('token', toks[i:i + 200]).execute())
                for row in (r.data or []):
                    tok = row.get('token')
                    if not tok:
                        continue
                    prof = {}
                    for k in _PROFILE_KNOWN_COLS:
                        v = row.get(k)
                        if v is not None:
                            prof[k] = v
                    if prof.get('employers') is None:
                        prof['employers'] = []
                    if include_metadata:
                        md = row.get('metadata') or {}
                        if isinstance(md, dict):
                            for k, v in md.items():
                                if k in ('avatar_b64', 'avatar_bytes'):
                                    continue
                                if k not in prof:
                                    prof[k] = v
                    else:
                        for k in _PROFILE_BULK_META_KEYS:
                            v = row.get(k)
                            if v is not None and k not in prof:
                                # ->> liefert IMMER text — bool/int-Keys
                                # (share_location) zurück-typisieren, damit
                                # `is False`-Gates weiter funktionieren.
                                if v == 'true':
                                    v = True
                                elif v == 'false':
                                    v = False
                                elif isinstance(v, str) and v.isdigit() \
                                        and k in ('share_location',
                                                  'commute_minutes'):
                                    v = int(v)  # legacy int-0/1 + Minuten
                                prof[k] = v
                    if row.get('updated_at') is not None:
                        prof['_updated_at'] = row.get('updated_at')
                    out[tok] = prof
            sb_ok = True
        except Exception as e:
            app.logger.warning(
                f'[profile] bulk_load_fail n={len(toks)} err={type(e).__name__}: {str(e)[:120]}')
    # Disk-Fallback für fehlende Tokens (SB-down oder Row fehlt) — hält das
    # alte Verhalten der per-Token-_profile_load-Schleifen (Disk als Backup).
    for t in toks:
        if t in out:
            continue
        try:
            dp = (_profile_load_from_disk(t) or {}).get('profile') or {}
        except Exception:
            dp = {}
        if dp or not sb_ok:
            out[t] = dp
    return out


def _profile_save(token, profile, full_disk_payload=None):
    """Schreibt profile in SB (primary) + Disk (best-effort Cache).
    full_disk_payload: optional komplettes Disk-Dict (für Endpoints die
    Side-Keys wie crew_aircraft mit-schreiben). Wenn None: minimaler Wrap.
    Returns True wenn mind. ein Pfad gehalten hat.
    """
    if not token:
        return False
    sb_ok = _profile_save_to_supabase(token, profile)
    disk_ok = False
    p = _user_profile_path(token)
    if p:
        payload = full_disk_payload if full_disk_payload is not None else {
            'token': token, 'profile': profile,
            # UTC-Z sekundengenau (Audit 2026-07-05): _updated_at wird als
            # last_seen_iso an die Family-Watch ausgeliefert — vorher naiv-
            # lokales isoformat() mit Mikrosekunden, das iOS-seitig ein
            # nicht-toleranter ISO-Parser nicht verstand.
            '_updated_at': datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ'),
        }
        try:
            _atomic_write_json(p, payload)
            disk_ok = True
        except Exception as e:
            app.logger.warning(f'[profile] disk_save_fail tok={token[:8]}: {e}')
    if not (sb_ok or disk_ok):
        app.logger.error(
            f'[profile] CRITICAL tok={token[:8]}: weder SB noch Disk gesichert!'
        )
        return False
    return True


# ── W18-Followup (2026-06-10): Side-Key-Persistenz für Top-Level-Disk-Keys ──
# subscription wurde mit W18 bereits durch _profile_save nach SB gespiegelt,
# die übrigen Side-Keys (sponsored_slots, marker_mapping, lufthansa_*) blieben
# disk-only (siehe Scope-Hinweis oben) → auf Cloud Run nach jedem Redeploy weg.
# Diese zwei Helper wenden das W18-Pattern generisch an: Key landet BEIDES im
# profile-Subkey (→ SB metadata-jsonb, da nicht in _PROFILE_KNOWN_COLS) und
# als Top-Level-Disk-Key (Backwards-compat für alte Reader).

def _profile_sidekey_get(token, key, default=None):
    """Liest einen Side-Key SB-first (profile-Subkey via metadata-jsonb),
    Legacy-Top-Level-Disk-Key als Fallback."""
    try:
        full = _profile_load(token) or {}
        prof = full.get('profile') or {}
        if prof.get(key) is not None:
            return prof.get(key)
        if full.get(key) is not None:
            return full.get(key)
    except Exception:
        pass
    return default


def _profile_sidekey_set(token, key, value, remove=False):
    """Schreibt (oder entfernt, remove=True) einen Side-Key in SB + Disk.
    Basis-Profil kommt aus _profile_load (SB-first) — NICHT disk-only, sonst
    würde der metadata-Upsert auf einer frischen Instanz bestehende
    metadata-Keys (z.B. subscription) wegwischen."""
    full = _profile_load(token) or {}
    profile = dict(full.get('profile') or {})
    if remove:
        profile.pop(key, None)
    else:
        profile[key] = value
    disk_full = dict(_profile_load_from_disk(token) or {})
    disk_full['token'] = token
    disk_full['profile'] = profile
    if remove:
        disk_full.pop(key, None)
    else:
        disk_full[key] = value
    disk_full['_updated_at'] = datetime.now().isoformat()
    return _profile_save(token, profile, full_disk_payload=disk_full)


# PUBLIC-Profile-Whitelist (BUG-AUDIT 2026-06-07, PII-LEAK-FIX):
# Der Profile-GET ist Friend-Discovery → PUBLIC. Er darf NUR opt-in-/Anzeige-
# Felder liefern. Insbesondere DÜRFEN home_address/home_latitude/
# home_longitude/home_transport_mode (Commute-Distance, 2026-06-06) NIEMALS
# hier raus — das ist die Wohnadresse + GPS-Koordinaten des Users. Vorher gab
# der Endpoint das KOMPLETTE profile-Dict 1:1 zurück → Wohnadresse für jeden
# mit dem (nicht-geheimen) AT-Token abrufbar.
_PUBLIC_PROFILE_FIELDS = (
    'name', 'homebase', 'position', 'airline', 'hometown',
    'avatar_url', 'account_type', 'share_roster', 'share_location',
)


def _is_family_account(profile_or_token):
    """Robuster, geteilter Marker: ist dieser Account ein FAMILY-Konto?

    Family-Konten (Family-Watch-Feature, für immer gratis, dünner Client, kein
    Dienstplan) bleiben in der Crew-Suche/Discovery SICHTBAR (Owner-Entscheidung
    2026-07-16 „lass sie doch da aber deutlich als familie"), werden aber als
    role='family' markiert und sind NICHT per Crew-Follow verbindbar (das
    Family-Pairing läuft über einen ANDEREN Pfad: family_scoped_tokens/Pair-Code
    in blueprints/family_watch.py, nicht über friend-requests).

    Wahrheitsquelle = `account_type == 'family'` — der einzige, konsistent an
    ALLEN Stellen (entitlement, promo-offer, search, contacts-match) genutzte
    Marker. FAIL-OPEN by design: nur der EINDEUTIGE Marker gilt als Family;
    bei fehlendem/unbekanntem Wert wird der Account als CREW behandelt, damit
    keine echte Crew fälschlich aus Suche/Follow verschwindet.

    Akzeptiert entweder ein bereits geladenes Profil-Dict ODER einen Token
    (dann wird das Profil nachgeladen)."""
    prof = profile_or_token
    if isinstance(prof, str):
        prof = ((_profile_load(prof) or {}).get('profile') or {})
    if not isinstance(prof, dict):
        return False
    return (prof.get('account_type') or '').strip().lower() == 'family'


def _public_profile_projection(token):
    """Lädt das volle Profil und projiziert es auf die PUBLIC-Whitelist.
    Liefert {token, profile:{nur-whitelist-felder}} — gleiche Shape wie früher,
    aber ohne private Felder (home_address/lat/lon/transport_mode, email,
    billing, subscription, marker_mapping, …)."""
    full = _profile_load(token) or {}
    prof = (full.get('profile') or {}) if isinstance(full, dict) else {}
    public = {}
    for k in _PUBLIC_PROFILE_FIELDS:
        v = prof.get(k)
        if v is not None:
            public[k] = v
    # role='family' ADDITIV mitgeben (byte-kompatibel für alle anderen): der
    # nächste iOS-Build leitet daraus „Familie" statt „Crew-Mitglied" ab.
    if _is_family_account(prof):
        public['role'] = 'family'
    return {'token': token, 'profile': public}


# ── Paywall-Rollout (User 2026-06-25) ────────────────────────────────────────
# HARD WALL ab dem Wall-Datum (26.12.2026): bis dahin ALLES gratis (Beta). Ab dann
# beim NÄCHSTEN App-Öffnen entweder zahlen ODER die Gratis-Phase nutzen:
#   - Gründungs-Crew (vor dem Wall-Datum dabei): löst einen 6-Monate-Offer-Code ein
#     (auto-renew) → 6 Monate gratis, dann 11,99 €/Jahr.
#   - Neue ab dem Wall-Datum: 1-Woche-Apple-Trial → dann 11,99 €/Jahr.
#   - Family: für immer gratis.
# KEINE passive Gnadenfrist mehr — die +6 Monate kommen aus dem eingelösten Code,
# nicht aus einem free_until. So landet die Gründungs-Crew wirklich im Auto-Renew.
_PAYWALL_WALL_DATE = '2026-12-26'          # Hard Wall ab hier (6 Monate Beta ab 2026-06-25)


def _auth_created_at_for_token(token):
    """Echtes Signup-Datum (E-Mail-Auth) für einen Token, falls vorhanden."""
    try:
        # SCALE-FIX: Single-Row-Lookup by token statt Full-Table-Scan
        # (Entitlement-Endpoint kann häufig gepollt werden).
        _em, rec = _auth_find_user_by('token', token)
        if rec:
            return rec.get('created_at')
    except Exception:
        pass
    return None


@app.route('/api/user/entitlement/<token>', methods=['GET'])
def user_entitlement(token):
    """Sagt der App, ob die Bezahlschranke für diesen User gilt — siehe Paywall-
    Rollout-Kommentar oben. Antwort: {ok, pro_required, free_until, family}."""
    if not token:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    loaded = _profile_load(token) or {}
    prof = dict(loaded.get('profile') or {})
    is_family = (prof.get('account_type') == 'family')
    # Kohorten-Stempel: persistiertes pro_first_seen → echtes Auth-Signup-Datum →
    # sonst JETZT (und einmalig persistieren). So gilt jeder, der die App vor dem
    # Wall-Datum öffnet, als Gründungs-Crew, auch ohne E-Mail-Signup (Apple/Family).
    # KEIN Profil-Re-Save hier — ein partielles Save würde andere Felder (z.B.
    # account_type → Family!) clobbern. Wer die App vor dem Wall-Datum öffnet,
    # rechnet ohnehin seen=jetzt < Wall = Gründungs-Crew; das reicht.
    seen = prof.get('pro_first_seen') or _auth_created_at_for_token(token) \
        or datetime.now().isoformat()
    today = datetime.now().date().isoformat()
    seen_date = str(seen)[:10]
    if is_family:
        return jsonify({'ok': True, 'pro_required': False,
                        'free_until': None, 'family': True})
    # HARD WALL: bis zum Wall-Datum gratis, danach erforderlich (Code/Trial/Kauf).
    # Gründungs-Crew = vor dem Wall-Datum dabei → free bis zum Wall-Datum, danach
    # über den 6-Monate-Code (KEINE passive Gnadenfrist mehr, sonst kein Auto-Renew-
    # „Catch"). Neue ab dem Wall-Datum → sofort erforderlich (1-Woche-Trial deckt die
    # Probe). pro_required steuert die Wall; founding wählt Code-Screen vs 1-Woche.
    founding = seen_date < _PAYWALL_WALL_DATE
    free_until = _PAYWALL_WALL_DATE if founding else seen_date
    pro_required = today >= free_until
    return jsonify({'ok': True, 'pro_required': pro_required,
                    'free_until': free_until, 'family': False, 'founding': founding})


@app.route('/api/storekit/promo-offer', methods=['GET'])
def storekit_promo_offer():
    """Signiert das 6-Monate-Gründungs-Crew-Promo-Offer (Apple „Promotional Offer").
    NUR für die Gründungs-Crew (vor dem Wall-Datum dabei, nicht Family) → 6+6.

    Owner-Setup (App Store Connect, einmalig — NUR der Owner):
      1) Beim Abo aerox.pro.yearly ein „Promotional Offer" anlegen:
         Offer-ID z.B. `founding6m`, Typ Free, Dauer 6 Monate, Auto-Renew.
      2) Einen „Subscription Key" (.p8) in ASC erzeugen (Users & Access → Keys →
         In-App-Purchase). Key-ID notieren.
      3) Diese Env-Vars auf Cloud Run setzen:
           ASC_SUB_KEY_P8   = kompletter .p8-PEM-Inhalt (-----BEGIN PRIVATE KEY----- …)
           ASC_SUB_KEY_ID   = die Key-ID
           ASC_FOUNDING_OFFER_ID = founding6m   (oder die gewählte Offer-ID)
           ASC_BUNDLE_ID    = aerotax.AeroTax   (Default, falls abweichend)
    Ohne diese Config → 503 (App fällt sauber auf das normale Intro-Offer zurück).
    """
    token = (request.headers.get('Authorization', '') or '').replace('Bearer ', '').strip()
    if not token or len(token) < 8:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    key_pem = os.environ.get('ASC_SUB_KEY_P8')
    key_id = os.environ.get('ASC_SUB_KEY_ID')
    bundle_id = os.environ.get('ASC_BUNDLE_ID', 'aerotax.AeroTax')
    offer_id = os.environ.get('ASC_FOUNDING_OFFER_ID', 'founding6m')
    product_id = (request.args.get('product') or 'aerox.pro.yearly').strip()
    if not key_pem or not key_id:
        return jsonify({'ok': False, 'error': 'not_configured',
                        'message': 'ASC promo key not set'}), 503
    # Founding-Check (gleiche Logik wie /entitlement).
    prof = (_profile_load(token) or {}).get('profile') or {}
    if prof.get('account_type') == 'family':
        return jsonify({'ok': False, 'error': 'family_exempt'}), 403
    seen = prof.get('pro_first_seen') or _auth_created_at_for_token(token) \
        or datetime.now().isoformat()
    if str(seen)[:10] >= _PAYWALL_WALL_DATE:
        return jsonify({'ok': False, 'error': 'not_founding'}), 403
    # Apple-Signatur-Algorithmus: Felder mit U+2063 verbunden, ES256 (P-256/SHA-256),
    # DER-Signatur base64-kodiert. applicationUsername = leer (StoreKit-2-Flow).
    import uuid as _uuid
    nonce = str(_uuid.uuid4()).lower()
    ts = int(datetime.now().timestamp() * 1000)
    payload = '\u2063'.join([bundle_id, key_id, product_id, offer_id, '', nonce, str(ts)])
    # Optionaler appAccountToken (StoreKit-2 K\u00e4ufer-Zuordnung). Nur additiv in die
    # JWS-Payload aufgenommen \u2014 die Legacy-Signatur bleibt hiervon unber\u00fchrt.
    app_account_token = (request.args.get('appAccountToken')
                         or request.args.get('app_account_token') or '').strip()
    try:
        from cryptography.hazmat.primitives import hashes, serialization
        from cryptography.hazmat.primitives.asymmetric import ec, utils as _asym_utils
        pkey = serialization.load_pem_private_key(key_pem.encode('utf-8'), password=None)
        sig = pkey.sign(payload.encode('utf-8'), ec.ECDSA(hashes.SHA256()))
        sig_b64 = base64.b64encode(sig).decode('ascii')
        # --- Additive JWS (ES256) Signatur nach Apple-StoreKit-2-Spec ---
        # Compact serialization: base64url(header).base64url(payload).base64url(sig),
        # base64url OHNE Padding; Signatur als raw R||S (64 Bytes), NICHT DER.
        def _b64url(raw: bytes) -> str:
            return base64.urlsafe_b64encode(raw).rstrip(b'=').decode('ascii')
        jws_header = {'alg': 'ES256', 'kid': key_id, 'typ': 'JWT'}
        jws_payload = {
            'appBundleId': bundle_id,
            'productId': product_id,
            'offerIdentifier': offer_id,
            'nonce': nonce,
            'timestamp': ts,
        }
        if app_account_token:
            jws_payload['appAccountToken'] = app_account_token
        # Kompakte, deterministische JSON-Serialisierung (kein Whitespace).
        header_seg = _b64url(json.dumps(
            jws_header, separators=(',', ':'), ensure_ascii=False).encode('utf-8'))
        payload_seg = _b64url(json.dumps(
            jws_payload, separators=(',', ':'), ensure_ascii=False).encode('utf-8'))
        signing_input = f'{header_seg}.{payload_seg}'.encode('ascii')
        der_sig = pkey.sign(signing_input, ec.ECDSA(hashes.SHA256()))
        r, s = _asym_utils.decode_dss_signature(der_sig)
        raw_sig = r.to_bytes(32, 'big') + s.to_bytes(32, 'big')
        signature_jws = f'{signing_input.decode("ascii")}.{_b64url(raw_sig)}'
    except Exception as e:
        print(f'[storekit_promo_offer] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'sign_failed', 'message': 'internal_error'}), 500
    return jsonify({'ok': True, 'offer_id': offer_id, 'key_id': key_id,
                    'nonce': nonce, 'timestamp': ts, 'signature_b64': sig_b64,
                    'signature_jws': signature_jws})


@app.route('/api/user/profile/<token>', methods=['GET'])
def get_user_profile(token):
    # PUBLIC-BY-DESIGN (BUG-004 audit, 2026-06-02): Profile-Lookup ist im
    # Friend-Discovery-Flow notwendig BEVOR eine Friendship besteht — d.h. ein
    # User scannt z.B. einen QR-Code, möchte Profil sehen vor Accept. Daher
    # bewusst NICHT durch _bug004_token_auth_gate gedeckt.
    #
    # PII-LEAK-FIX (2026-06-07): Antwort ist auf _PUBLIC_PROFILE_FIELDS
    # WHITELISTED. Vorher floss das komplette Profil (inkl. home_address +
    # GPS-Koordinaten + transport_mode) verbatim raus. Private Felder
    # (home_*, email, billing, subscription) werden NIE zurückgeliefert.
    if not token:
        return jsonify({'error': 'invalid token'}), 400
    try:
        # Owner-Pfad: wenn der Caller einen Authorization-Bearer schickt, der
        # mit dem Pfad-Token übereinstimmt (constant-time), ist es der Owner
        # selbst → volles Profil (inkl. home_*) für Cross-Device-Sync
        # (BackgroundSyncService/Stores.swift liest home_address zurück).
        # Sonst (Friend-Discovery, kein/falscher Bearer): PUBLIC-Whitelist.
        if _request_bearer_matches(token):
            full = _profile_load(token) or {}
            # Interne Avatar-Storage-Keys (base64-Bytes) NICHT an den Client
            # zurückgeben — sie dienen nur dem serverseitigen Serve-Fallback und
            # würden den Profile-Sync unnötig um ~270 KB aufblähen. Der Client
            # braucht nur `avatar_url`.
            prof = dict(full.get('profile') or {})
            for _k in ('avatar_b64', 'avatar_mime', 'avatar_dir_key'):
                prof.pop(_k, None)
            full = dict(full)
            full['profile'] = prof
            for _k in ('avatar_b64', 'avatar_mime', 'avatar_dir_key'):
                full.pop(_k, None)
            # RESTFIX B: Crew-Pünktlichkeits-Cache (metadata.punctuality) explizit
            # an die Top-Level-Antwort spiegeln, damit iOS gespeicherten Rang/
            # Score/History ohne separaten /api/ax/punctuality-Call lesen kann.
            # Additiv — profile.punctuality (via metadata-fold) bleibt erhalten.
            if isinstance(prof.get('punctuality'), dict):
                full['punctuality'] = prof['punctuality']
            return jsonify(full)
        return jsonify(_public_profile_projection(token))
    except Exception as e:
        print(f'[get_user_profile] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'error': 'internal_error'}), 500


@app.route('/api/user/profile/<token>', methods=['PUT'])
def put_user_profile(token):
    if not token:
        return jsonify({'error': 'invalid token'}), 400
    # SECURITY (IDOR-Fix): PUT ist owner-scoped, wird aber über das Cross-User-Prefix
    # (für den GET-Friend-Lookup) vom Binding-Gate AUSGENOMMEN. Schreiben MUSS an den
    # Caller gebunden sein — sonst kann jeder ein fremdes Profil (Name/Homebase/
    # Adresse/account_type) überschreiben. iOS sendet auf jedem Request den eigenen
    # Bearer → legit passt; ein fremder Bearer matcht nicht.
    if not _request_bearer_matches(token):
        return jsonify({'ok': False, 'error': 'token_binding_required'}), 401
    body = request.get_json(silent=True) or {}
    # Whitelist erweitert: hometown + employers waren vorher silent-gedroppt
    # (G3-Finding) → User editiert "Hometown" → kein round-trip-Sync.
    # Wave-1 BUG-003 (2026-06-02): account_type + family_share_defaults
    # waren silent-gedroppt → iOS UserProfile.isFamily-Flag konnte nicht
    # persistiert werden, Family-Watcher-Root-Stack wurde nie geladen.
    #
    # MERGE statt CLOBBER (2026-06-05): Vorher baute der PUT ein FRISCHES
    # profile-Dict NUR aus den im Body gesendeten Feldern und schrieb es als
    # komplette Row zurück → jeder partielle PUT (z.B. EmployersView pusht nur
    # employers, OnboardingView pusht nur name/homebase) LÖSCHTE alle anderen
    # bereits gespeicherten Felder (hometown, position, airline, share_*…).
    # Das war der "warum bleibt nichts gespeichert"-Bug. Jetzt: existierendes
    # Profil als Basis laden, nur die im Body vorhandenen Felder überschreiben.
    existing = (_profile_load(token) or {}).get('profile') or {}
    profile = dict(existing) if isinstance(existing, dict) else {}
    safe_keys = ('name', 'homebase', 'position', 'airline', 'hometown')
    for k in safe_keys:
        if k in body and body.get(k):
            profile[k] = body.get(k)
    # account_type: 'crew' | 'family' — validate strikt, sonst 400.
    if 'account_type' in body:
        at = body.get('account_type')
        if at not in ('crew', 'family'):
            return jsonify({'ok': False, 'error': 'invalid_account_type'}), 400
        profile['account_type'] = at
    # family_share_defaults: optional Liste mit Feld-Strings
    fsd = body.get('family_share_defaults')
    if isinstance(fsd, list):
        # Whitelist gegen FamilyShareField-Enum (iOS-Side)
        allowed = {'layover_place', 'current_city', 'landed_status',
                   'next_flight', 'photos', 'voice_notes', 'aircraft_reg'}
        profile['family_share_defaults'] = [f for f in fsd
                                            if isinstance(f, str) and f in allowed][:20]
    # employers ist eine Liste — separat validieren (max 10, jeweils dict)
    emps = body.get('employers')
    if isinstance(emps, list):
        profile['employers'] = [e for e in emps if isinstance(e, dict)][:10]
    # share_roster: Reziprozität — User teilt seinen Plan + sieht im Gegenzug
    # die Pläne der Buddies. Default TRUE (User-Anweisung, reziproker Social-
    # Mechanismus). User kann in Settings jederzeit ausschalten.
    if 'share_roster' in body:
        profile['share_roster'] = bool(body.get('share_roster'))
    # share_location: aktuelle Stadt teilen (NUR Stadt, keine GPS-Koordinaten).
    # Default TRUE. iOS-LocationStore sendet ~1×/Stunde im Foreground.
    if 'share_location' in body:
        profile['share_location'] = bool(body.get('share_location'))
    # current_city: vom iOS-Client gepushte aktuelle Stadt (reverse-geocoded).
    # Backend speichert as-is, prüft beim Friend-Lookup ob share_location=true.
    if 'current_city' in body:
        cc = body.get('current_city')
        if isinstance(cc, str) and 0 < len(cc) <= 64:
            profile['current_city'] = cc
    # Privacy: current_city NUR löschen wenn share_location in DIESEM Request
    # explizit auf False gesetzt wird — nicht bei jedem PUT bei dem der gespeicherte
    # Wert zufällig False ist (das würde city bei jedem name-/employer-PUT löschen).
    # Privacy: current_city löschen wenn:
    # (a) share_location in DIESEM Request explizit auf False gesetzt, ODER
    # (b) das gespeicherte Profil hat share_location=False UND der Request enthält current_city
    #     (sonst würde ein partial-PUT die Stadt speichern trotz gespeichertem Opt-out).
    stored_share_loc = profile.get('share_location', True)
    if ('share_location' in body and body.get('share_location') is False) or \
       (stored_share_loc is False and 'current_city' in body):
        profile.pop('current_city', None)
    # location_source: 'roster' (Dienstplan-Modus, Default) | 'gps'. Steuert
    # SERVERSEITIG, ob die gespeicherte current_city überhaupt an Freunde/Family
    # geleakt werden darf. Im roster-Modus NIE — sonst könnten Freunde erfahren,
    # dass die Crew während eines Layovers tatsächlich woanders hingeflogen ist
    # (Privacy-Anweisung User 2026-06-29). Nur 'gps'/'roster' zulässig.
    if 'location_source' in body:
        ls = body.get('location_source')
        if ls in ('roster', 'gps'):
            profile['location_source'] = ls
    # Home-Address (2026-06-06): Commute-Distance / Smart-Pickup. Felder kommen
    # partiell — nur die im Body vorhandenen überschreiben (MERGE-Semantik wie
    # oben). Floats + bool defensiv casten, damit ein iOS-Tippfehler/None kein
    # 500 auslöst (ungültige Zahl → Feld wird übersprungen, nicht gespeichert).
    if 'home_address' in body:
        ha = body.get('home_address')
        if isinstance(ha, str) and 0 < len(ha) <= 256:
            profile['home_address'] = ha
        elif ha in (None, ''):
            profile.pop('home_address', None)
    for _coord_key in ('home_latitude', 'home_longitude'):
        if _coord_key in body:
            cv = body.get(_coord_key)
            if cv is None or cv == '':
                profile.pop(_coord_key, None)
            else:
                try:
                    profile[_coord_key] = float(cv)
                except (TypeError, ValueError):
                    pass  # ungültige Koordinate → still überspringen
    if 'home_transport_mode' in body:
        tm = body.get('home_transport_mode')
        if isinstance(tm, str) and 0 < len(tm) <= 32:
            profile['home_transport_mode'] = tm
        elif tm in (None, ''):
            profile.pop('home_transport_mode', None)
    if 'home_geocoded' in body:
        profile['home_geocoded'] = bool(body.get('home_geocoded'))
    # PRE-FLIGHT-TIMELINE (ADDITIV 2026-07-12): selbst angegebene Fahrzeit
    # Wohnung→Flughafen in Minuten (ÖPNV/Auto) — speist serverseitig die
    # „Fahrt zum Flughafen"-Phase der Crew-Bordkarten (crew_state.pre_phase).
    # Landet in metadata-jsonb (kein Schema-Change). Der Wert existiert
    # clientseitig bereits als SmartPickup-Fahrzeit — TODO iOS: beim
    # Profil-Sync mitsenden (Client-Seite bewusst noch nicht gebaut).
    # None/0/'' löscht; Unplausibles (>6 h) wird still verworfen.
    if 'commute_minutes' in body:
        _cmv = body.get('commute_minutes')
        if _cmv in (None, '', 0, '0'):
            profile.pop('commute_minutes', None)
        else:
            try:
                _cmi = int(_cmv)
                if 0 < _cmi <= 360:
                    profile['commute_minutes'] = _cmi
            except (TypeError, ValueError):
                pass  # ungültiger Wert → still überspringen (kein 500)
    # Disk-Payload erhält Side-Keys (subscription, crew_aircraft, …) die NICHT
    # in SB sind — lesen, profile-Subkey ersetzen, zurückschreiben. Sonst würde
    # ein PUT alles andere im disk-File zerstören.
    disk_full = dict(_profile_load_from_disk(token) or {})
    disk_full['token'] = token
    disk_full['profile'] = profile
    disk_full['_updated_at'] = datetime.now().isoformat()
    if _profile_save(token, profile, full_disk_payload=disk_full):
        # BUG-018-Fix: Wenn share_roster in DIESEM Request getoggelt wurde, die
        # bereits existierenden crew_flight_assignments-Rows mit-aktualisieren —
        # sonst bleibt opt_in auf dem alten Wert (z.B. User schaltet Sharing aus,
        # ist aber weiter auf der Crew-on-Flight-Tafel sichtbar).
        if 'share_roster' in body and SB_AVAILABLE and sb is not None:
            try:
                sb.table('crew_flight_assignments').update(
                    {'opt_in': bool(body['share_roster'])}
                ).eq('self_token', token).execute()
            except Exception:
                pass
        # Avatar-Storage-Bytes nicht in die Save-Antwort spiegeln (Bandbreite).
        resp_profile = {k: v for k, v in profile.items()
                        if k not in ('avatar_b64', 'avatar_mime', 'avatar_dir_key')}
        return jsonify({'ok': True, 'profile': resp_profile})
    return jsonify({'ok': False, 'error': 'persist_failed'}), 500


@app.route('/api/user/location', methods=['POST'])
def post_user_location():
    """LocationStore (iOS) pusht ~1×/Stunde die aktuelle Stadt — NUR
    Stadt-String, KEINE GPS-Koordinaten (Privacy-by-Design).

    Body: {token, city} — city max 64 chars, non-empty, kein HTML.
    Token-Auth: Body-Feld `token` (analog put_user_profile-Pattern).

    Persistence: gleicher Pfad wie put_user_profile → setzt `current_city`
    im profile-JSON. Wenn `share_location=False` im Profil → silent 200
    (kein Speichern, aber keine Fehlermeldung für den Client).

    Rate-Limit: 24 calls/Tag pro Token (Spam-Schutz, falls iOS-Client
    durch Bug öfter als 1×/h pushed).
    """
    body = request.get_json(silent=True) or {}
    token = (body.get('token') or '').strip()
    if not token:
        return jsonify({'ok': False, 'error': 'missing token'}), 400
    # SECURITY (IDOR-Fix): Body-Token-Endpoint umgeht das Pfad-Token-Binding-Gate
    # → expliziter Bearer-Match. Sonst könnte jeder die Stadt eines fremden Users
    # setzen. iOS sendet auf JEDEM Request den eigenen Bearer → legit passt.
    if not _request_bearer_matches(token):
        return jsonify({'ok': False, 'error': 'token_binding_required'}), 401

    # Rate-Limit: 24 calls/Tag pro Token (24h window).
    if _token_rate_limited(token, 'user_location', limit=24, window_sec=86400):
        return jsonify({'ok': False, 'error': 'rate_limited'}), 429

    raw_city = body.get('city')
    if not isinstance(raw_city, str):
        return jsonify({'ok': False, 'error': 'missing city'}), 400
    # Sanitize: strip whitespace, strip HTML-Tags (defensiv — iOS sendet
    # CLPlacemark.locality, aber Server-Side validieren ist Pflicht).
    city = raw_city.strip()
    # HTML/Control-Char Filter: alles ausser printable Unicode raus.
    city = ''.join(c for c in city if c.isprintable() and c not in '<>')
    city = city[:64]
    if not city:
        return jsonify({'ok': False, 'error': 'empty city'}), 400

    p = _user_profile_path(token)
    if not p:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400

    # Existing profile SB-PRIMARY laden (nicht disk-only!). Die Cloud-Run-Disk ist
    # ephemer — nach einem Restart ist sie leer, und ein disk-only-Load + Save
    # haette die komplette metadata-Spalte (avatar_url etc.) ueberschrieben. Mit
    # SB-primary sieht der Save den echten aktuellen Profil-Stand.
    profile = dict((_profile_load(token) or {}).get('profile') or {})

    # share_location default TRUE (User-Anweisung: "aus prinzip immer aktuelle
    # location teilen"). Nur wenn explizit auf False gesetzt → silent skip.
    if profile.get('share_location', True) is False:
        return jsonify({'ok': True, 'skipped': 'sharing_off'})

    profile['current_city'] = city
    # BUG-005-Fix: SB-primary persistieren (wie put_user_profile) statt disk-only —
    # sonst landet current_city nie in Supabase (metadata-jsonb) und ist nach jedem
    # Cloud-Run-Redeploy weg. Disk-Side-Keys erhalten, profile-Subkey ersetzen.
    disk_full = dict(_profile_load_from_disk(token) or {})
    disk_full['token'] = token
    disk_full['profile'] = profile
    disk_full['_updated_at'] = datetime.now().isoformat()
    if _profile_save(token, profile, full_disk_payload=disk_full):
        return jsonify({'ok': True})
    return jsonify({'ok': False, 'error': 'persist_failed'}), 500


@app.route('/api/user/search', methods=['GET'])
def user_search():
    """Crew-Discovery (J11). Query: ?q=&airline=&homebase=&limit=20&token=<own>.
    token-Param wird genutzt um (a) eigene Blocks rauszufiltern und (b) den
    Searcher selbst nicht zurückzugeben. Privacy: liefert nur public profile-
    Felder, NIEMALS email/apple_sub/internal.
    Rate-Limit: max 20 Ergebnisse pro Call, Query muss ≥2 Zeichen haben.
    """
    q = (request.args.get('q') or '').strip().lower()
    airline = (request.args.get('airline') or '').strip().lower()
    homebase = (request.args.get('homebase') or '').strip().upper()
    limit = min(int(request.args.get('limit') or 20), 50)
    searcher_token = (request.args.get('token') or '').strip()
    # exclude_family=1 → Family-Accounts ausblenden (eine Family sucht ihre CREW,
    # nicht andere Familien). „Crew" = account_type None/'crew', nie 'family'.
    # Owner-Entscheidung 2026-07-16: Family-Konten bleiben in der Crew-Suche
    # SICHTBAR („lass sie doch da aber deutlich als familie"). Sie werden aber
    # als role='family' markiert (der nächste iOS-Build zeigt „Familie" statt
    # „Crew-Mitglied" und blendet den Folgen-Button aus). Das Follow-Gate im
    # Friend-Request-Core lehnt zusätzlich serverseitig ab (auch für alte Builds).
    # Der `exclude_family`-Opt-in bleibt unverändert erhalten.
    exclude_family = str(request.args.get('exclude_family') or '').strip() in ('1', 'true', 'yes')
    # Mindestens ein Filter muss gesetzt sein damit das nicht zu User-Listing wird
    if len(q) < 2 and not airline and not homebase:
        return jsonify({'count': 0, 'users': [],
                        'error': 'min_query_or_filter_required'}), 400
    blocked = _blocked_by(searcher_token) if searcher_token else set()
    results = []
    used_source = 'disk'

    # W18-Fix (2026-06-01): Primär gegen Supabase suchen — Disk-Iteration
    # über profile_*.json verliert nach jedem Cloud-Run-Redeploy alle Hits.
    # SB-Query nutzt ilike auf name + eq auf homebase/airline (indiziert via
    # idx_user_profiles_homebase/idx_user_profiles_airline). Fallback auf
    # Disk wenn SB nicht erreichbar.
    sb_done = False
    if SB_AVAILABLE:
        try:
            # avatar_url + account_type sind KEINE Spalten — sie liegen im
            # metadata-jsonb (siehe _profile_save_to_supabase). Daher metadata
            # selektieren und daraus auslesen, NICHT als Spalten (sonst 42703 →
            # SB-Fail → Disk-Fallback → leere Suche).
            qbuilder = sb.table('user_profiles').select(
                'token,name,homebase,airline,"position",metadata'
            )
            if q:
                # ilike ist case-insensitive — name enthält Substring q
                qbuilder = qbuilder.ilike('name', f'%{q}%')
            if airline:
                qbuilder = qbuilder.ilike('airline', airline)
            if homebase:
                qbuilder = qbuilder.eq('homebase', homebase)
            # Höheres SB-Limit als Endpoint-Limit, da blocks/self-filter
            # nachträglich Rows entfernen können.
            qbuilder = qbuilder.limit(max(limit * 3, 60))
            r = qbuilder.execute()
            for row in (r.data or []):
                target_token = row.get('token')
                if not target_token or target_token == searcher_token:
                    continue
                if target_token in blocked:
                    continue
                name = (row.get('name') or '').strip()
                # Filter "kein-Name" raus — sonst wirkt's wie ein User-Listing
                if not name:
                    continue
                md = row.get('metadata') or {}
                if not isinstance(md, dict):
                    md = {}
                acct = (md.get('account_type') or '').strip().lower()
                if exclude_family and acct == 'family':
                    continue
                entry = {
                    'token': target_token,
                    'name': name,
                    'airline': row.get('airline'),
                    'homebase': row.get('homebase'),
                    'position': row.get('position'),
                    'avatar_url': md.get('avatar_url'),
                    'account_type': acct or 'crew',
                }
                # role='family' ADDITIV (byte-kompatibel für Crew: Feld fehlt):
                # der nächste iOS-Build zeigt daraus „Familie" statt „Crew-Mitglied"
                # und blendet den Folgen-Button aus.
                if acct == 'family':
                    entry['role'] = 'family'
                results.append(entry)
                if len(results) >= limit:
                    break
            sb_done = True
            used_source = 'supabase'
        except Exception as e:
            app.logger.warning(
                f'[user_search] sb_fail err={type(e).__name__}: {str(e)[:120]} → disk fallback'
            )
            sb_done = False
            results = []

    if not sb_done:
        # Disk-Fallback (alte Logik) — bei SB-down oder vor erster Migration
        try:
            for fn in os.listdir(_USER_HISTORY_DIR):
                if not fn.startswith('profile_') or not fn.endswith('.json'):
                    continue
                try:
                    with open(os.path.join(_USER_HISTORY_DIR, fn)) as f:
                        data = json.load(f) or {}
                except Exception:
                    continue
                target_token = data.get('token')
                if not target_token or target_token == searcher_token:
                    continue
                if target_token in blocked:
                    continue
                pr = data.get('profile') or {}
                name = (pr.get('name') or '').strip()
                a = (pr.get('airline') or '').strip().lower()
                h = (pr.get('homebase') or '').strip().upper()
                acct = (pr.get('account_type') or '').strip().lower()
                # Match-Logik
                if q and q not in name.lower():
                    continue
                if airline and airline != a:
                    continue
                if homebase and homebase != h:
                    continue
                if exclude_family and acct == 'family':
                    continue
                entry = {
                    'token': target_token,
                    'name': name,
                    'airline': pr.get('airline'),
                    'homebase': pr.get('homebase'),
                    'position': pr.get('position'),
                    'avatar_url': pr.get('avatar_url'),
                    'account_type': acct or 'crew',
                }
                # role='family' ADDITIV (byte-kompatibel für Crew: Feld fehlt).
                if acct == 'family':
                    entry['role'] = 'family'
                results.append(entry)
                if len(results) >= limit:
                    break
        except FileNotFoundError:
            pass
    # Sortiere alphabetisch nach Name
    results.sort(key=lambda u: (u.get('name') or '').lower())
    return jsonify({'count': len(results), 'users': results, 'source': used_source})


# ── Kontakte-Matching (B1 Tibor 2026-07-12) ─────────────────────────────────
# Warum: der iOS-Kontakte-Tab matchte bisher clientseitig 60 ZUFÄLLIGE von N
# Kontakt-Namen (Set-Order!) einzeln gegen /api/user/search — bei 265 Kontakten
# wurden ~77% nie geprüft („Von 265 Kontakten ist niemand bei AeroX", obwohl
# Miguel+Jennifer drin waren). Dieser Endpoint macht das Matching SERVERSEITIG
# in EINEM Request über ALLE Kontakte, mit zwei Basen:
#   1. E-Mail-HASHES (SHA-256 der lowercased/trimmed Adresse) gegen die
#      Registrierungs-E-Mails (auth_users) — E-Mails existieren für JEDEN
#      Account. Privacy: der Client lädt NIE Roh-Adressen hoch, nur Hashes;
#      die Response enthält NUR public-Profil-Felder (wie /api/user/search).
#   2. Namen (Klartext, wie bisher bei der Namens-Suche) gegen user_profiles.
#      Match-Regel bewusst KONSERVATIVER als die Substring-Suche: Token-Set-
#      Gleichheit ODER Profilname (≥2 Wörter) vollständig im Kontakt-Namen
#      enthalten („Dr. Miguel Schumann ✈️" findet „Miguel Schumann").

_CONTACTS_HASH_RE = re.compile(r'^[0-9a-f]{64}$')


def _contacts_name_tokens(s):
    """Anzeigename → normalisierte Vergleichs-Tokens (casefold, NFKC,
    Satzzeichen/Emojis → Space). 'Dr. Miguel Schumann ✈️' → ['dr','miguel',
    'schumann']. Leere Liste wenn nichts Alphanumerisches übrig bleibt."""
    import unicodedata
    s = unicodedata.normalize('NFKC', str(s or ''))
    cleaned = ''.join(ch if (ch.isalnum() or ch.isspace() or ch in "-'")
                      else ' ' for ch in s)
    # Bindestrich/Apostroph zusätzlich splitten ("Anna-Lena" ≙ "Anna Lena")
    cleaned = cleaned.replace('-', ' ').replace("'", ' ')
    return [t for t in cleaned.casefold().split() if t]


def _contacts_name_match(profile_name, contact_token_sets):
    """True wenn der AeroX-Profilname zu EINEM Kontakt passt.
    Regeln (konservativ, kein Substring-Raten):
      • Token-Set-Gleichheit (auch „Schumann, Miguel" umgedreht), ODER
      • Profilname hat ≥2 Tokens und ALLE stecken im Kontakt-Namen
        (Titel/Emojis/Zusätze im Kontakt stören nicht).
    Ein-Wort-Profilnamen matchen NUR exakt (sonst matcht „Miguel" jeden
    Kontakt, der das Wort irgendwo trägt)."""
    ps = set(_contacts_name_tokens(profile_name))
    if not ps:
        return False
    for cs in contact_token_sets:
        if ps == cs:
            return True
        if len(ps) >= 2 and ps <= cs:
            return True
    return False


def _contacts_email_hash(email):
    """Kanonischer E-Mail-Hash: SHA-256 über strip().lower() — MUSS mit der
    iOS-Seite (CrewConnectSearchView.emailHash) identisch bleiben."""
    return hashlib.sha256(
        str(email or '').strip().lower().encode('utf-8')).hexdigest()


def _contacts_match_auth_rows():
    """[(email, token)] aller Accounts — SB primary (paginiert), Disk-Fallback.
    NUR intern fürs Hash-Matching; E-Mails verlassen den Server nie."""
    rows = []
    if SB_AVAILABLE and sb is not None:
        try:
            offset, page = 0, 1000
            while offset < 20000:
                r = (sb.table('auth_users').select('email,token')
                     .range(offset, offset + page - 1).execute())
                chunk = r.data or []
                rows.extend((row.get('email'), row.get('token'))
                            for row in chunk)
                if len(chunk) < page:
                    break
                offset += page
            return rows
        except Exception as e:
            app.logger.warning(
                f'[contacts-match] sb_auth_fail {type(e).__name__}: '
                f'{str(e)[:120]} → disk')
    for em, rec in (_auth_load_from_disk() or {}).items():
        rows.append((em, (rec or {}).get('token')))
    return rows


def _contacts_match_profile_rows():
    """[(token, name)] aller Profile — SB primary (paginiert), Disk-Fallback."""
    rows = []
    if SB_AVAILABLE and sb is not None:
        try:
            offset, page = 0, 1000
            while offset < 20000:
                r = (sb.table('user_profiles').select('token,name')
                     .range(offset, offset + page - 1).execute())
                chunk = r.data or []
                rows.extend((row.get('token'), row.get('name'))
                            for row in chunk)
                if len(chunk) < page:
                    break
                offset += page
            return rows
        except Exception as e:
            app.logger.warning(
                f'[contacts-match] sb_prof_fail {type(e).__name__}: '
                f'{str(e)[:120]} → disk')
    try:
        for fn in os.listdir(_USER_HISTORY_DIR):
            if not fn.startswith('profile_') or not fn.endswith('.json'):
                continue
            try:
                with open(os.path.join(_USER_HISTORY_DIR, fn)) as f:
                    data = json.load(f) or {}
            except Exception:
                continue
            pr = data.get('profile') or {}
            rows.append((data.get('token'), pr.get('name')))
    except FileNotFoundError:
        pass
    return rows


@app.route('/api/user/contacts-match', methods=['POST'])
def user_contacts_match():
    """Adressbuch-Abgleich in EINEM Request (siehe Block-Kommentar oben).

    Body: {token: <own>, email_hashes: [sha256-hex…], names: [Anzeigename…],
           exclude_family: bool}
    Antwort: {ok, count, users: [wie /api/user/search + matched_by
              ('email'|'name')], checked: {names, email_hashes}}
    Privacy-Audit: Response NUR public-Profil-Felder — NIEMALS email/apple_sub.
    Rate-Limit: 12/h pro Token (der Scan ist eine bewusste User-Aktion).
    """
    data = request.get_json(silent=True) or {}
    own = str(data.get('token') or '').strip()
    if not own or not _validate_token_exists(own):
        return jsonify({'ok': False, 'error': 'invalid_token'}), 401
    if _token_rate_limited(own, 'contacts_match', limit=12, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited'}), 429
    exclude_family = bool(data.get('exclude_family'))

    hashes = set()
    for h in (data.get('email_hashes') or [])[:1000]:
        h = str(h or '').strip().lower()
        if _CONTACTS_HASH_RE.match(h):
            hashes.add(h)
    contact_sets = []
    for n in (data.get('names') or [])[:500]:
        toks = _contacts_name_tokens(n)
        if toks:
            contact_sets.append(set(toks))
    if not hashes and not contact_sets:
        return jsonify({'ok': True, 'count': 0, 'users': [],
                        'checked': {'names': 0, 'email_hashes': 0}})

    matched = {}   # token -> 'email' | 'name' (email gewinnt als stärkere Basis)
    if hashes:
        for em, tok in _contacts_match_auth_rows():
            if tok and em and _contacts_email_hash(em) in hashes:
                matched[tok] = 'email'
    if contact_sets:
        for tok, name in _contacts_match_profile_rows():
            if tok and tok not in matched and \
                    _contacts_name_match(name, contact_sets):
                matched[tok] = 'name'

    blocked = _blocked_by(own)
    toks = [t for t in matched if t != own and t not in blocked][:100]

    # Public-Profil-Felder der Treffer (eine IN-Query statt N Lookups)
    profs = {}
    if SB_AVAILABLE and sb is not None and toks:
        try:
            r = (sb.table('user_profiles')
                 .select('token,name,homebase,airline,"position",metadata')
                 .in_('token', toks).execute())
            for row in (r.data or []):
                profs[row.get('token')] = row
        except Exception as e:
            app.logger.warning(
                f'[contacts-match] sb_pub_fail {type(e).__name__}: '
                f'{str(e)[:120]} → per-token disk')
    users = []
    for t in toks:
        row = profs.get(t)
        if row is None:
            pr = (_profile_load(t) or {}).get('profile') or {}
            row = {'token': t, 'name': pr.get('name'),
                   'homebase': pr.get('homebase'),
                   'airline': pr.get('airline'),
                   'position': pr.get('position'),
                   'metadata': {'avatar_url': pr.get('avatar_url'),
                                'account_type': pr.get('account_type')}}
        name = (row.get('name') or '').strip()
        if not name:
            continue   # ohne Namen nicht anzeigbar (wie /api/user/search)
        md = row.get('metadata') or {}
        if not isinstance(md, dict):
            md = {}
        acct = (md.get('account_type') or '').strip().lower()
        if exclude_family and acct == 'family':
            continue
        users.append({
            'token': t,
            'name': name,
            'airline': row.get('airline'),
            'homebase': row.get('homebase'),
            'position': row.get('position'),
            'avatar_url': md.get('avatar_url'),
            'account_type': acct or 'crew',
            'matched_by': matched.get(t),
        })
    users.sort(key=lambda u: (u.get('name') or '').lower())
    return jsonify({'ok': True, 'count': len(users), 'users': users,
                    'checked': {'names': len(contact_sets),
                                'email_hashes': len(hashes)}})


@app.route('/api/user/lookup-by-short/<short>', methods=['GET'])
def user_lookup_by_short(short):
    """Resolve 8-char Token-Prefix → full Token + public profile fields.

    Wall-Post/Forum-Posts carry `author_short = token[:8]` only (privacy).
    Wenn der User auf den Avatar/Namen tappt, braucht der iOS-Client den
    vollen Token um Buddy-Requests/DMs zu starten. Dieser Endpoint löst
    das Prefix auf — strict whitelisted auf die exakt gleichen public-Profil-
    Felder wie /api/user/search (token, name, airline, homebase, position).

    Privacy-Audit:
    - NIEMALS: email, apple_sub, friends-list, blocks/mutes, internal IDs
    - Min-Prefix-Länge: 8 (entspricht `token[:8]` aus Wall/Forum)
    - 404 wenn kein Match
    - 409 wenn >1 Match (Ambiguität — kein Auto-Resolve, Client entscheidet)

    Skaliert linear über alle profile_*.json — bei <10k Usern OK, danach
    Index nötig (Postgres-Migration siehe ROADMAP.md).
    """
    short = (short or '').strip()
    if len(short) < 8:
        return jsonify({'error': 'short_too_short_min_8'}), 400
    if len(short) > 64:
        return jsonify({'error': 'short_too_long'}), 400
    # Whitelist allowed chars (matches token alphabet from _user_profile_path)
    import re as _re_lookup
    if not _re_lookup.match(r'^[A-Za-z0-9_-]+$', short):
        return jsonify({'error': 'short_invalid_chars'}), 400

    # W19-Hardening (2026-06-01): Per-IP Rate-Limit gegen Token-Enumeration.
    # Endpoint ist unauthenticated (kein User-Token im Header) → Worst-Case
    # könnte ein Angreifer 8-char-Prefixes brute-forcen um aktive User-Tokens
    # zu erraten. 30 calls / 10min reichen für legitime UX (User-Tap auf Avatar),
    # blockieren aber Massen-Enumeration (~6.8e12 möglich Prefix-Werte sind
    # bei 30 calls/10min auch ohne Limit unpraktisch, aber das Limit stoppt
    # gezielte Scanning-Versuche und reduziert Log-Lärm).
    client_ip = _client_ip()
    if client_ip and _ip_rate_limited(client_ip, endpoint='lookup_by_short',
                                       limit=30, window_sec=600):
        return jsonify({
            'error': 'rate_limited',
            'detail': 'Zu viele Lookup-Anfragen — bitte 10 Minuten warten.',
        }), 429

    matches = []

    # SB-primary: Token-Prefix-Match via LIKE 'short%' — nutzt PK-Index (token).
    sb_done = False
    if SB_AVAILABLE:
        try:
            r = sb.table('user_profiles').select(
                'token,name,homebase,airline,"position"'
            ).like('token', f'{short}%').limit(2).execute()
            for row in (r.data or []):
                target_token = row.get('token') or ''
                if not target_token or not target_token.startswith(short):
                    continue
                matches.append({
                    'token': target_token,
                    'name': (row.get('name') or '').strip() or None,
                    'homebase': row.get('homebase'),
                    'airline': row.get('airline'),
                    'position': row.get('position'),
                })
                if len(matches) > 1:
                    break
            sb_done = True
        except Exception as e:
            app.logger.warning(
                f'[lookup_by_short] sb_fail err={type(e).__name__}: {str(e)[:120]} → disk fallback'
            )
            sb_done = False
            matches = []

    if not sb_done:
        try:
            for fn in os.listdir(_USER_HISTORY_DIR):
                if not fn.startswith('profile_') or not fn.endswith('.json'):
                    continue
                try:
                    with open(os.path.join(_USER_HISTORY_DIR, fn)) as f:
                        data = json.load(f) or {}
                except Exception:
                    continue
                target_token = data.get('token') or ''
                if not target_token or not target_token.startswith(short):
                    continue
                pr = data.get('profile') or {}
                matches.append({
                    'token': target_token,
                    'name': (pr.get('name') or '').strip() or None,
                    'homebase': pr.get('homebase'),
                    'airline': pr.get('airline'),
                    'position': pr.get('position'),
                })
                if len(matches) > 1:
                    # Mehr als 1 Match — ambiguous, früh abbrechen
                    break
        except FileNotFoundError:
            pass

    if not matches:
        return jsonify({'error': 'not_found'}), 404
    if len(matches) > 1:
        # 409 Conflict — Client soll User-Hint anzeigen ("Profil unvollständig")
        return jsonify({'error': 'ambiguous', 'count': len(matches)}), 409
    return jsonify(matches[0])


