# R46 (2026-05-28) Friends-System, Layover-Match, Stats, iCal-Export,
# Push-Token-Registry — alle file-based für privaten Use. Postgres-Migration
# bei Skalierung (siehe ROADMAP.md).
# ════════════════════════════════════════════════════════════════════════
def _user_friends_path(token):
    import os, re
    if not token: return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe: return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'friends_{safe}.json')


def _user_push_path(token):
    import os, re
    if not token: return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe: return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'push_{safe}.json')


# ── Push-Token SB-Layer ─────────────────────────────────────────────
# Tabelle: user_push_tokens (user_token PK, expo_token, apns_token, device_id,
# platform, metadata jsonb). Eine Row pro User-Token; Re-Install = Update.

_PUSH_KNOWN_COLS = {'expo_token', 'apns_token', 'device_id', 'platform'}

# ── Push-Preference-Filter (2026-07-03) ─────────────────────────────
# User-steuerbare Push-Kategorien (POST /api/push/prefs). Persistiert als
# registry['prefs'] → landet in der metadata-jsonb-Column (kein DDL nötig).
# _send_push_notification unterdrückt nur bei EXPLIZITEM False (fail-open).
_PUSH_PREF_KEYS = ('dm', 'group_message', 'friend_request',
                   'friend_accepted', 'roster_change', 'family_message',
                   'community')

# data['type'] (Call-Sites) → Pref-Key. Nicht gemappte Typen → immer senden.
_PUSH_TYPE_TO_PREF = {
    'dm': 'dm',
    'group_message': 'group_message',
    'friend_request': 'friend_request',
    'buddy_request': 'friend_request',
    'friend_accept': 'friend_accepted',
    'friend_accepted': 'friend_accepted',
    'buddy_accepted': 'friend_accepted',
    'roster_change': 'roster_change',
    'duty_change': 'roster_change',
    'wall_comment': 'community',
    'wall_comment_reply': 'community',
    'forum_reply': 'community',
    'forum_mention': 'community',
    # Audit 2026-07-12: bisher ungemappte Typen → jetzt filterbar (fail-open
    # bleibt: kein gesetzter Pref = senden).
    'friend_remind': 'community',
    'family_message': 'family_message',
    'family_reply': 'family_message',
    'family_reaction': 'family_message',
    'trade_interest': 'community',
    'trade_closed': 'community',
}


def _push_load_from_supabase(token):
    """Returns dict in legacy-shape ({token, push_token, apns_token, …}) oder
    None bei SB-down / Row fehlt."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = sb.table('user_push_tokens').select('*').eq('user_token', token).limit(1).execute()
        rows = r.data or []
        if not rows:
            return None
        row = rows[0]
        out = {'token': token}
        # Mapping: expo_token → push_token (legacy file-field-name)
        if row.get('expo_token') is not None:
            out['push_token'] = row.get('expo_token') or ''
        if row.get('apns_token') is not None:
            out['apns_token'] = row.get('apns_token') or ''
        if row.get('platform') is not None:
            out['platform'] = row.get('platform') or ''
        if row.get('device_id') is not None:
            out['device_id'] = row.get('device_id') or ''
        md = row.get('metadata') or {}
        if isinstance(md, dict):
            for k, v in md.items():
                if k not in out:
                    out[k] = v
        return out
    except Exception as e:
        app.logger.warning(
            f'[push] sb_load_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:120]}'
        )
        return None


def _push_save_to_supabase(token, registry):
    """Upsert. Erwartet legacy-shape ({token, push_token, apns_token, …}).
    push_token wird in expo_token-Column gemappt."""
    if not SB_AVAILABLE or not token:
        return False
    reg = registry or {}
    row = {
        'user_token': token,
        'updated_at': datetime.now(timezone.utc).isoformat(),
    }
    # legacy 'push_token' → expo_token
    if 'push_token' in reg:
        row['expo_token'] = reg.get('push_token') or None
    if 'apns_token' in reg:
        row['apns_token'] = reg.get('apns_token') or None
    if 'platform' in reg:
        row['platform'] = reg.get('platform') or None
    if 'device_id' in reg:
        row['device_id'] = reg.get('device_id') or None
    meta = {}
    legacy_meta_keys = ('bundle_id', 'registered_at')
    for k in legacy_meta_keys:
        if k in reg:
            meta[k] = reg.get(k)
    # Auch echte unknown-Felder durchreichen
    for k, v in reg.items():
        if k in ('token', 'push_token') or k in _PUSH_KNOWN_COLS:
            continue
        if k not in meta:
            meta[k] = v
    row['metadata'] = meta
    try:
        sb.table('user_push_tokens').upsert(row, on_conflict='user_token').execute()
        return True
    except Exception as e:
        app.logger.error(
            f'[push] sb_save_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


def _push_load_from_disk(token):
    """Returns legacy-shape ({token, push_token, apns_token, …}) oder {}."""
    p = _user_push_path(token)
    if not p:
        return {}
    try:
        with open(p) as f:
            return json.load(f) or {}
    except Exception:
        return {}


def _push_load(token):
    """SB primary, Disk fallback, lazy-migration. Returns dict (evt. leer)."""
    if not token:
        return {}
    sb_reg = _push_load_from_supabase(token)
    if sb_reg is not None:
        return sb_reg
    disk_reg = _push_load_from_disk(token)
    if SB_AVAILABLE and disk_reg and (disk_reg.get('push_token') or disk_reg.get('apns_token')):
        app.logger.info(f'[push] lazy-migrate tok={token[:8]} disk→supabase')
        _push_save_to_supabase(token, disk_reg)
    return disk_reg


def _push_save(token, registry):
    """SB (primary) + Disk (cache)."""
    if not token:
        return False
    sb_ok = _push_save_to_supabase(token, registry)
    disk_ok = False
    p = _user_push_path(token)
    if p:
        try:
            _atomic_write_json(p, registry)
            disk_ok = True
        except Exception as e:
            app.logger.warning(f'[push] disk_save_fail tok={token[:8]}: {e}')
    if not (sb_ok or disk_ok):
        app.logger.error(
            f'[push] CRITICAL tok={token[:8]}: weder SB noch Disk gesichert!'
        )
        return False
    return True


# ── Multi-device Push-Installations (additiv zum Legacy-Store) ──────────

def _push_token_ref(token):
    """PII-freie, nicht umkehrbare Korrelation für Push-Logs."""
    return _hashlib.sha256(str(token or '').encode('utf-8')).hexdigest()[:10]


def _push_normalized_environment(value):
    value = (value or '').strip().lower()
    return value if value in ('prod', 'sandbox') else 'unknown'


def _push_installation_register(user_token, registry, unregister_token=None):
    """Atomically bind one APNs installation to an account.

    The database uniqueness boundary is `(apns_token,bundle_id,environment)`.
    Re-registering the same device under another account therefore performs an
    account switch instead of leaving the previous association active.
    Returns installation UUID string, or None when the durable store/RPC is not
    available. The caller decides whether a legacy route may degrade.
    """
    reg = registry or {}
    apns_token = (reg.get('apns_token') or '').strip()
    if not (SB_AVAILABLE and sb is not None and user_token and apns_token):
        return None
    params = {
        'p_user_token': user_token,
        'p_apns_token': apns_token,
        'p_bundle_id': (reg.get('bundle_id') or 'aerotax.AeroTax').strip(),
        'p_environment': _push_normalized_environment(reg.get('apns_env')),
        'p_device_id': (reg.get('device_id') or '').strip() or None,
        'p_platform': (reg.get('platform') or 'ios').strip(),
        'p_metadata': {
            'environment_source': reg.get('apns_env_source') or 'server',
            'registered_via': reg.get('registered_via') or 'legacy',
        },
        'p_unregister_secret_hash': (
            _hashlib.sha256(str(unregister_token).encode('utf-8')).hexdigest()
            if unregister_token else None),
    }
    try:
        result = sb.rpc('register_push_installation', params).execute()
        data = result.data
        if isinstance(data, list):
            data = data[0] if data else None
        if isinstance(data, dict):
            data = data.get('register_push_installation') or data.get('id')
        return str(data) if data else None
    except Exception as e:
        app.logger.error(
            f'[push-install] register_fail user_ref={_push_token_ref(user_token)} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return None


def _push_installations_for_user(user_token):
    """Return active APNs installations; None means durable store unavailable."""
    if not (SB_AVAILABLE and sb is not None and user_token):
        return None
    try:
        result = (sb.table('push_installations').select(
            'id,user_token,apns_token,bundle_id,environment,device_id,platform,'
            'active,metadata')
            .eq('user_token', user_token).eq('active', True).execute())
        rows = []
        for row in (result.data or []):
            if not isinstance(row, dict) or not (row.get('apns_token') or '').strip():
                continue
            rows.append({
                'installation_id': str(row.get('id') or ''),
                'token': user_token,
                'apns_token': row.get('apns_token') or '',
                'bundle_id': row.get('bundle_id') or 'aerotax.AeroTax',
                'apns_env': _push_normalized_environment(row.get('environment')),
                'device_id': row.get('device_id') or '',
                'platform': row.get('platform') or 'ios',
            })
        return rows
    except Exception as e:
        app.logger.warning(
            f'[push-install] list_fail user_ref={_push_token_ref(user_token)} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return None


def _push_installation_tombstone(user_token, installation_id=None,
                                 apns_token=None, bundle_id=None,
                                 apns_env=None, reason='logout'):
    """Durably disable one installation, or all for legacy logout callers."""
    if not (SB_AVAILABLE and sb is not None and user_token):
        return None
    params = {
        'p_user_token': user_token,
        'p_installation_id': installation_id or None,
        'p_apns_token': (apns_token or '').strip() or None,
        'p_bundle_id': (bundle_id or '').strip() or None,
        'p_environment': (_push_normalized_environment(apns_env)
                          if apns_env else None),
        'p_reason': reason,
    }
    try:
        result = sb.rpc('tombstone_push_installations', params).execute()
        data = result.data
        if isinstance(data, list):
            data = data[0] if data else 0
        if isinstance(data, dict):
            data = data.get('tombstone_push_installations', 0)
        return int(data or 0)
    except Exception as e:
        app.logger.error(
            f'[push-install] tombstone_fail user_ref={_push_token_ref(user_token)} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return None


def _push_installation_tombstone_by_capability(installation_id,
                                               unregister_token):
    """Tombstone after logout without retaining the account Bearer on-device."""
    if not (SB_AVAILABLE and sb is not None and installation_id
            and unregister_token):
        return None
    secret_hash = _hashlib.sha256(
        str(unregister_token).encode('utf-8')).hexdigest()
    try:
        result = sb.rpc('tombstone_push_installation_by_secret', {
            'p_installation_id': installation_id,
            'p_unregister_secret_hash': secret_hash,
            'p_reason': 'offline_logout_retry',
        }).execute()
        data = result.data
        if isinstance(data, list):
            data = data[0] if data else False
        if isinstance(data, dict):
            data = data.get('tombstone_push_installation_by_secret', False)
        return bool(data)
    except Exception as e:
        app.logger.error(
            f'[push-install] capability_tombstone_fail '
            f'installation={str(installation_id)[:8]} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return None


def _push_installation_delivery_update(registry, success, reason=None):
    """Update delivery health for one installation; never affects the request."""
    installation_id = (registry or {}).get('installation_id')
    if not (SB_AVAILABLE and sb is not None and installation_id):
        return False
    now_iso = datetime.now(timezone.utc).isoformat()
    patch = {'updated_at': now_iso}
    if success:
        patch.update({'last_success_at': now_iso, 'failure_count': 0})
    else:
        patch.update({'last_failure_at': now_iso})
    try:
        q = sb.table('push_installations').update(patch).eq('id', installation_id)
        q.execute()
        if not success:
            # PostgREST has no portable atomic increment here; the durable
            # outbox attempt counter remains authoritative for retry/dead-letter.
            pass
        return True
    except Exception:
        return False


def _push_delivery_registrations(user_token):
    """Multi-device candidates without resurrecting stale legacy bindings."""
    legacy = _push_load(user_token) or {}
    installations = _push_installations_for_user(user_token)
    if installations is None:
        # With Supabase configured, a failed durable registry read is not
        # permission to use a possibly stale disk/legacy token: after a shared-
        # device account switch that could disclose the previous account's push.
        # Let the durable outbox retry instead. File-only local/dev keeps its
        # historical compatibility behavior.
        if SB_AVAILABLE and sb is not None:
            safe_legacy = dict(legacy)
            safe_legacy['_durable_registry_unavailable'] = True
            safe_legacy['push_token'] = ''
            safe_legacy['apns_token'] = ''
            return [], safe_legacy
        return ([legacy] if legacy else []), legacy
    if installations:
        return installations, legacy
    # The release migration backfills legacy rows before this code deploys.
    # Therefore an authoritative empty result means "no active installation"
    # (including tombstoned/account-rebound devices), never "lazy rebind me".
    # Lazy re-registration here would allow a stale legacy row to resurrect a
    # logged-out or newly account-bound device.
    if (legacy.get('apns_token') or '').strip():
        # This row belongs to the APNs migration path, so an empty durable set
        # means tombstoned/rebound. Suppress its Expo fallback too; it commonly
        # points at the same physical app installation.
        safe_legacy = dict(legacy)
        safe_legacy['apns_token'] = ''
        safe_legacy['push_token'] = ''
        return [], safe_legacy
    # Expo-only legacy clients have no native installation to migrate and keep
    # their existing compatibility delivery path.
    return [], legacy


def _friends_load_from_supabase(token):
    """Liest alle Friend-Edges (out-bound) für owner_token aus Supabase.
    Returns dict in der Shape {token, friends:[...], requests_out:[...],
    requests_in:[...]} — None bei SB-down. Empty-Dict ist OK (kein Eintrag).
    Reziproke Pending-in werden ebenfalls geholt (friend_token=token UND
    status=pending → fließt in requests_in).
    Groups bleiben disk-only und werden hier NICHT touched.
    """
    if not SB_AVAILABLE or not token:
        return None
    try:
        # Outgoing edges (owner=token)
        r1 = sb.table('user_friends').select('friend_token,status').eq(
            'owner_token', token).execute()
        out_rows = r1.data or []
        # Incoming pending (someone else's request to me)
        r2 = sb.table('user_friends').select('owner_token,status').eq(
            'friend_token', token).eq('status', 'pending').execute()
        in_rows = r2.data or []
        friends = []
        requests_out = []
        for row in out_rows:
            ft = row.get('friend_token')
            st = (row.get('status') or 'accepted').lower()
            if not ft:
                continue
            if st == 'accepted':
                friends.append(ft)
            elif st == 'pending':
                requests_out.append(ft)
        requests_in = [row.get('owner_token') for row in in_rows if row.get('owner_token')]
        return {
            'token': token,
            'friends': friends,
            'requests_out': requests_out,
            'requests_in': requests_in,
        }
    except Exception as e:
        app.logger.warning(
            f'[friends] sb_load_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:120]}'
        )
        return None


def _friends_save_to_supabase(token, data):
    """Replaces alle out-bound Edges für owner_token in Supabase mit dem,
    was in `data` steht (friends → status=accepted, requests_out → pending).
    Strategie: delete-all-by-owner + insert. Atomic via PostgREST RPC wäre
    schöner, aber 2 Queries reichen — bei Race kommen Daten leicht out-of-sync,
    aber lazy-reload heilt das beim nächsten Read.
    requests_in werden NICHT geschrieben — die gehören dem anderen Owner."""
    if not SB_AVAILABLE or not token:
        return False
    data = data or {}
    friends = [t for t in (data.get('friends') or []) if isinstance(t, str)]
    reqs_out = [t for t in (data.get('requests_out') or []) if isinstance(t, str)]
    rows = []
    seen = set()
    for ft in friends:
        if ft in seen or ft == token:
            continue
        seen.add(ft)
        rows.append({'owner_token': token, 'friend_token': ft, 'status': 'accepted'})
    for ft in reqs_out:
        if ft in seen or ft == token:
            continue
        seen.add(ft)
        rows.append({'owner_token': token, 'friend_token': ft, 'status': 'pending'})
    try:
        sb.table('user_friends').delete().eq('owner_token', token).execute()
        if rows:
            for i in range(0, len(rows), 500):
                sb.table('user_friends').upsert(
                    rows[i:i+500], on_conflict='owner_token,friend_token'
                ).execute()
        return True
    except Exception as e:
        app.logger.error(
            f'[friends] sb_save_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


def _friends_edge_upsert(owner_token, friend_token, status):
    """Atomarer Single-Edge-Upsert auf user_friends (PK owner_token,friend_token).
    Idempotent: gleicher Edge konvergiert statt zu clobbern. True bei Erfolg."""
    if not SB_AVAILABLE or sb is None or not owner_token or not friend_token:
        return False
    if owner_token == friend_token:
        return False
    try:
        sb.table('user_friends').upsert(
            {'owner_token': owner_token, 'friend_token': friend_token, 'status': status},
            on_conflict='owner_token,friend_token').execute()
        return True
    except Exception as e:
        app.logger.warning(
            f'[friends] edge_upsert_fail {owner_token[:6]}->{friend_token[:6]} '
            f'err={type(e).__name__}: {str(e)[:120]}')
        return False


def _friends_edge_delete(owner_token, friend_token):
    """Atomarer Single-Edge-Delete auf user_friends. True bei Erfolg."""
    if not SB_AVAILABLE or sb is None or not owner_token or not friend_token:
        return False
    try:
        (sb.table('user_friends').delete()
         .eq('owner_token', owner_token).eq('friend_token', friend_token).execute())
        return True
    except Exception as e:
        app.logger.warning(
            f'[friends] edge_delete_fail {owner_token[:6]}->{friend_token[:6]} '
            f'err={type(e).__name__}: {str(e)[:120]}')
        return False


def _friend_groups_load_from_supabase(token):
    """Lädt Friend-Groups aus user_friend_groups in SB. Returns list[dict] oder
    None bei SB-down. Empty-list = keine Groups (kein Fehler).
    Migration 20260601_friend_groups.sql muss applied sein.
    """
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = sb.table('user_friend_groups').select(
            'id,name,members,created_at,updated_at'
        ).eq('owner_token', token).execute()
        out = []
        for row in (r.data or []):
            mem = row.get('members')
            if not isinstance(mem, list):
                mem = []
            out.append({
                'id': row.get('id'),
                'name': row.get('name') or '',
                'members': [m for m in mem if isinstance(m, str)],
                'created_at': row.get('created_at'),
                'updated_at': row.get('updated_at'),
            })
        return out
    except Exception as e:
        app.logger.warning(
            f'[fgroups] sb_load_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:120]}'
        )
        return None


def _friend_groups_save_to_supabase(token, groups):
    """Replaces alle Gruppen für owner_token. Strategie: delete-by-owner + upsert.
    Wie _friends_save_to_supabase — atomic-genug für die UX (User-CRUD läuft
    serialisiert, kein concurrent edit).
    Returns True/False für Erfolg.
    """
    if not SB_AVAILABLE or not token:
        return False
    groups = groups or []
    rows = []
    seen_ids = set()
    for g in groups:
        if not isinstance(g, dict):
            continue
        gid = (g.get('id') or '').strip()
        if not gid or gid in seen_ids:
            continue
        seen_ids.add(gid)
        name = (g.get('name') or '').strip()[:60]
        members = [m for m in (g.get('members') or []) if isinstance(m, str)]
        rows.append({
            'id': gid,
            'owner_token': token,
            'name': name or 'Gruppe',
            'members': members,
            'updated_at': datetime.now(timezone.utc).isoformat(),
        })
    try:
        sb.table('user_friend_groups').delete().eq('owner_token', token).execute()
        if rows:
            for i in range(0, len(rows), 200):
                sb.table('user_friend_groups').upsert(
                    rows[i:i+200], on_conflict='id'
                ).execute()
        return True
    except Exception as e:
        app.logger.error(
            f'[fgroups] sb_save_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


def _friends_load_from_disk(token):
    """Liest komplette friends-Disk-Datei. Returns mind. {token, friends:[]}."""
    p = _user_friends_path(token)
    if not p:
        return {'token': token, 'friends': []}
    try:
        with open(p) as f:
            return json.load(f) or {'token': token, 'friends': []}
    except Exception:
        return {'token': token, 'friends': []}


def _friends_load(token):
    """SB primary, Disk fallback. Lazy-Migration disk→SB beim ersten Read.
    Friend-`groups` werden seit 2026-06-01 ebenfalls aus user_friend_groups
    geladen (vorher disk-only). Bei SB-down fällt groups auf disk zurück.
    """
    if not token:
        return {'token': token, 'friends': []}
    sb_data = _friends_load_from_supabase(token)
    # Groups separat aus SB nachladen (eigene Tabelle).
    sb_groups = _friend_groups_load_from_supabase(token) if sb_data is not None else None
    if sb_data is not None:
        disk = _friends_load_from_disk(token)
        out = dict(sb_data)
        if sb_groups is not None and sb_groups:
            out['groups'] = sb_groups
        elif sb_groups is not None and not sb_groups and disk.get('groups'):
            # Disk hat groups, SB nicht → lazy-migrate
            app.logger.info(f'[fgroups] lazy-migrate tok={token[:8]} disk→supabase')
            _friend_groups_save_to_supabase(token, disk['groups'])
            out['groups'] = disk['groups']
        elif sb_groups is None and 'groups' in (disk or {}):
            # SB-Groups-Load fehlte (table missing/SB-down) → disk-Fallback
            out['groups'] = disk.get('groups')
        elif sb_groups is not None:
            # SB-Groups leer + Disk leer → leeres groups[] zurückgeben damit
            # Caller (Endpoints) keinen None-Branch braucht
            out['groups'] = []
        return out
    # SB-Miss (down or error) → Disk-Fallback + lazy-Migration wenn SB up
    disk = _friends_load_from_disk(token)
    if SB_AVAILABLE and (disk.get('friends') or disk.get('requests_out') or
                          disk.get('requests_in')):
        # Lazy-Migration: nur ausführen wenn nicht-leer (sonst leere File
        # provoziert ständig leeren SB-write).
        app.logger.info(f'[friends] lazy-migrate tok={token[:8]} disk→supabase')
        _friends_save_to_supabase(token, disk)
    if SB_AVAILABLE and disk.get('groups'):
        _friend_groups_save_to_supabase(token, disk['groups'])
    return disk


def _friends_save_disk_only(token, data):
    """Schreibt NUR den Disk-Read-Cache, ohne den ganzen Blob nach SB zu pushen.
    Genutzt nachdem SB bereits atomar per-Edge aktualisiert wurde (Friend-Accept/
    -Decline) — ein zusätzlicher Blob-Upsert würde genau den lost-update-Clobber
    wieder einführen, den die per-Edge-Writes vermeiden."""
    if not token:
        return False
    p = _user_friends_path(token)
    if not p:
        return False
    try:
        _atomic_write_json(p, data)
        return True
    except Exception as e:
        app.logger.warning(f'[friends] disk_only_save_fail tok={token[:8]}: {e}')
        return False


def _friends_save(token, data):
    """Schreibt sowohl Disk (cache) als auch SB (primary). True wenn mind.
    eines erfolgreich war (analog _auth_save).
    Groups werden separat in user_friend_groups persistiert."""
    if not token:
        return False
    disk_ok = False
    p = _user_friends_path(token)
    if p:
        try:
            _atomic_write_json(p, data)
            disk_ok = True
        except Exception as e:
            app.logger.warning(f'[friends] disk_save_fail tok={token[:8]}: {e}')
    sb_ok = _friends_save_to_supabase(token, data)
    # Groups separat persistieren — eigene Tabelle, eigener Save-Path.
    # Fehler hier NICHT als Save-Fail werten (Friends sind primär; Groups
    # können bei SB-down weiterhin disk-only existieren).
    if SB_AVAILABLE and 'groups' in (data or {}):
        try:
            _friend_groups_save_to_supabase(token, data.get('groups') or [])
        except Exception as e:
            app.logger.warning(f'[fgroups] save during friends_save fail tok={token[:8]}: {e}')
    if not (sb_ok or disk_ok):
        app.logger.error(
            f'[friends] CRITICAL tok={token[:8]}: weder SB noch Disk gesichert!'
        )
        return False
    return True


def _friend_facing_city(prof, roster_city=None):
    """Privacy-Gate für die an FREUNDE/Family ausgelieferte Standort-Stadt.

    Im Dienstplan-Modus (`location_source` == 'roster' ODER fehlend → Default)
    wird die gespeicherte GPS-`current_city` IGNORIERT und stattdessen NUR die
    aus dem geteilten Roster abgeleitete Stadt (heutiger Layover/Dienst-Ort)
    serviert. Sonst könnten Freunde erfahren, dass die Crew während eines
    Layovers tatsächlich woanders hingeflogen ist (User-Anweisung 2026-06-29).
    Nur bei `location_source` == 'gps' darf die echte reverse-geocodete GPS-Stadt
    raus. Die Entscheidung fällt SERVERSEITIG — robust gegen einen stale Wert,
    den der Client evtl. noch mitschickt.

    Returns die anzuzeigende Stadt (str) oder None. Der share_location-Hard-Gate
    bleibt dem Aufrufer vorgelagert (None/False = gar keine Location).
    """
    if not isinstance(prof, dict):
        return None
    src = prof.get('location_source')
    src = src.strip().lower() if isinstance(src, str) else ''
    if src == 'gps':
        return prof.get('current_city')
    # roster-Modus (Default): GPS-Stadt verwerfen, nur den Roster-Ort servieren.
    return roster_city or None


@app.route('/api/user/friends/<token>', methods=['GET'])
def get_user_friends(token):
    """Listet alle Friends eines Users mit deren Profile-Daten."""
    data = _friends_load(token)
    enriched = []
    # N+1-Fix (2026-07-01): EIN Bulk-Query über alle Friend-Profile statt
    # _profile_load pro Friend (SB-first-Verhalten von #29B bleibt erhalten;
    # metadata wird NICHT wholesale geladen — nur schlanke Keys, kein
    # avatar_b64-Bloat).
    _bulk_profs = _profiles_load_bulk(data.get('friends', []))
    for friend_token in data.get('friends', []):
        prof = _bulk_profs.get(friend_token) or {}
        # Interne Avatar-Storage-Keys NICHT mit ausliefern: die base64-Bytes
        # (~270 KB/Friend) würden die Friends-Antwort enorm aufblähen und die
        # rohen Bild-Bytes leaken. Der Client braucht nur `avatar_url` (CrewAvatar
        # lädt das Bild über den serve-Endpoint). (DURABILITY-FIX 2026-06-15)
        # PII-LEAK-FIX (Bug-Hunt): NUR Public-Whitelist ausliefern — vorher ging
        # das VOLLE Profil raus inkl. home_address + GPS-Koordinaten der Freunde.
        if isinstance(prof, dict):
            pub = {k: v for k, v in prof.items() if k in _PUBLIC_PROFILE_FIELDS}
            # current_city nur wenn Location-Sharing nicht aus ist. PRIVACY:
            # im Dienstplan-Modus (location_source != 'gps') wird die gespeicherte
            # GPS-Stadt verworfen und NUR der heutige Roster-Ort serviert — sonst
            # leaken wir, dass die Crew während eines Layovers woanders hingeflogen
            # ist. _user_current_iata = heutiger Layover/Dienst-Ort aus dem Roster.
            if prof.get('share_location') is not False:
                _fc = _friend_facing_city(prof, _user_current_iata(friend_token))
                if _fc:
                    pub['current_city'] = _fc
            prof = pub
        enriched.append({
            'token': friend_token,
            'match_id': _hashlib.sha256(friend_token.encode()).hexdigest()[:16],
            'profile': prof,
            'short': friend_token[:8] + '…',
        })
    return jsonify({
        'token': token,
        'friends': enriched,
        'count': len(enriched),
    })


@app.route('/api/user/friends/<token>/add', methods=['POST'])
def add_user_friend(token):
    """Friend per Token-Code hinzufügen. Body: {friend_token}."""
    body = request.get_json(silent=True) or {}
    friend_token = (body.get('friend_token') or '').strip()
    if not friend_token or friend_token == token:
        return jsonify({'ok': False, 'error': 'invalid friend_token'}), 400
    data = _friends_load(token)
    if 'friends' not in data: data['friends'] = []
    if friend_token in data['friends']:
        return jsonify({'ok': True, 'already_added': True})
    data['friends'].append(friend_token)
    data['_updated_at'] = datetime.now().isoformat()
    _friends_save(token, data)
    # Symmetrisch: Friend bekommt mich auch
    reverse = _friends_load(friend_token)
    if 'friends' not in reverse: reverse['friends'] = []
    if token not in reverse['friends']:
        reverse['friends'].append(token)
        reverse['_updated_at'] = datetime.now().isoformat()
        _friends_save(friend_token, reverse)
    return jsonify({'ok': True, 'friends_count': len(data['friends'])})


@app.route('/api/user/friends/<token>/remove', methods=['POST'])
def remove_user_friend(token):
    body = request.get_json(silent=True) or {}
    friend_token = (body.get('friend_token') or '').strip()
    if not friend_token:
        return jsonify({'ok': False, 'error': 'missing friend_token'}), 400
    data = _friends_load(token)
    data['friends'] = [f for f in (data.get('friends') or []) if f != friend_token]
    _friends_save(token, data)
    # Symmetrisch
    reverse = _friends_load(friend_token)
    reverse['friends'] = [f for f in (reverse.get('friends') or []) if f != token]
    _friends_save(friend_token, reverse)
    return jsonify({'ok': True})


@app.route('/api/user/friends/<token>/overlap', methods=['GET'])
def get_friends_overlap(token):
    """Findet Layover-Überlappungen mit Friends.
    Vergleicht _tage_detail aus jüngster Auswertung mit Friend-Auswertungen.
    Returns: pro Friend eine Liste {datum, place} überlappender Tage.
    """
    # Eigene Tage holen
    my_session = _store.get(token) or {}
    my_data = my_session.get('result_data') or {}
    my_tage = my_data.get('_tage_detail') or []
    # Build my layover-set: {datum: place}
    def _extract_layover_set(tage):
        out = {}
        for t in tage:
            if not isinstance(t, dict): continue
            klass = (t.get('klass') or '').upper()
            # Nightstop = letzte Tages-Ankunft (nicht blind reader_facts.layover_ort,
            # das bei Multi-Leg-Turnaround-Tagen einen Vortags-/Kontext-Wert trug).
            place = (_feed_nightstop_ort(t) or '').upper().strip()
            if klass in _CREW_DEST_LAYOVER_KLASSEN and place and len(place) == 3:
                out[t.get('datum')] = place
        return out

    # _store ist in-memory/per-Instanz — Fallback auf den persistenten
    # roster_snapshot (Muster wie get_friend_roster), sonst war der Overlap
    # nach Container-Restart/anderer Instanz immer leer (2026-07-01).
    if not my_tage:
        my_tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    my_layovers = _extract_layover_set(my_tage)
    if not my_layovers:
        return jsonify({'token': token, 'overlaps': [], 'reason': 'no_layovers_in_my_data'})

    def _hhmm_to_min(s):
        if not s or not isinstance(s, str): return None
        try:
            parts = s.strip().split(':')
            if len(parts) < 2: return None
            return int(parts[0]) * 60 + int(parts[1])
        except Exception:
            return None

    my_tage_by_date = {t.get('datum'): t for t in my_tage if isinstance(t, dict)}
    friends = (_friends_load(token).get('friends') or [])
    # N+1-Fix (2026-07-01): Friend-Namen in EINEM Bulk-Query statt
    # _profile_load pro gematchtem Friend.
    _bulk_profs = _profiles_load_bulk(friends)
    overlaps = []
    for friend_token in friends:
        friend_session = _store.get(friend_token) or {}
        friend_tage = (friend_session.get('result_data') or {}).get('_tage_detail') or []
        if not friend_tage:
            # Persistenter Snapshot-Fallback (Muster wie get_friend_roster).
            friend_tage = (_roster_snapshot_read(friend_token) or {}).get('tage') or []
        friend_layovers = _extract_layover_set(friend_tage)
        friend_tage_by_date = {t.get('datum'): t for t in friend_tage if isinstance(t, dict)}
        shared = []
        for datum, place in my_layovers.items():
            if friend_layovers.get(datum) == place:
                my_t = my_tage_by_date.get(datum) or {}
                fr_t = friend_tage_by_date.get(datum) or {}
                my_start = _hhmm_to_min((my_t.get('reader_facts') or {}).get('start_time'))
                fr_start = _hhmm_to_min((fr_t.get('reader_facts') or {}).get('start_time'))
                briefing_diff = (fr_start - my_start) if (my_start is not None and fr_start is not None) else None
                shared.append({
                    'datum': datum,
                    'place': place,
                    'briefing_diff_min': briefing_diff,
                })
        if shared:
            # BUG-035-Fix: Friend-Name SB-primary (bulk-geladen, s.o.).
            prof = _bulk_profs.get(friend_token) or {}
            overlaps.append({
                'friend_token': friend_token,
                'friend_name': prof.get('name', friend_token[:8] + '…'),
                'shared_layovers': shared,
                'count': len(shared),
            })
    overlaps.sort(key=lambda x: -x['count'])
    return jsonify({'token': token, 'overlaps': overlaps, 'friends_checked': len(friends)})


# ═══════════════════════════════════════════════════════════════════════════
# Crew at my Destination (Feature 2026-06-08)
# ───────────────────────────────────────────────────────────────────────────
# Modus A (Layover-basiert): wer von meinen Friends hat ±24h einen Layover an
#   DERSELBEN Station wie ich → Avatare auf der Crew Map. Opt-in (default an)
#   über layover_visibility; respektiert zusätzlich share_roster=False.
# Modus B (manueller Pin): „ich will hier am <Datum> was machen" → nur für
#   gegenseitige Friends sichtbar (manual_pins, gefiltert über user_friends).
# Tabellen: supabase_migrations/20260608_crew_at_destination.sql
# Mutationen (POST) sind automatisch durch _bug004_token_auth_gate gebunden
#   (Bearer == path-token).
# ═══════════════════════════════════════════════════════════════════════════

# Audit-Fix 2026-07-06: Z73 (Inland-Übernachtung) und Z74 (Ausland-
# Übernachtung) sind genauso echte Hotel-Nächte wie Z76 (vgl. CLAUDE.md
# „Hotel-Nächte: nur Z73/Z74/Z76 mit overnight=True") — der Z76-only-Filter
# machte Friends-Overlap/Hangouts für Inlands-Übernachtungen blind.
_CREW_DEST_LAYOVER_KLASSEN = ('Z73', 'Z74', 'Z76')

def _layover_visibility_get(token):
    """True = meine Layover dürfen als Match erscheinen. Opt-in DEFAULT-ON:
    fehlender Row → True. SB-primary; bei SB-down konservativ True (sichtbar)."""
    if not token:
        return False
    if SB_AVAILABLE:
        try:
            r = (sb.table('layover_visibility').select('enabled')
                 .eq('user_token', token).limit(1).execute())
            if r.data:
                return bool(r.data[0].get('enabled'))
        except Exception as e:
            app.logger.warning(f'[crew-dest] vis_load_fail err={type(e).__name__}: {str(e)[:120]}')
    return True  # default-on (Opt-in: Row entsteht erst beim aktiven Umlegen)

def _layover_visibility_set(token, enabled):
    if not token or not SB_AVAILABLE:
        return False
    try:
        sb.table('layover_visibility').upsert(
            {'user_token': token, 'enabled': bool(enabled),
             'updated_at': datetime.now().isoformat()},
            on_conflict='user_token').execute()
        return True
    except Exception as e:
        app.logger.warning(f'[crew-dest] vis_save_fail err={type(e).__name__}: {str(e)[:120]}')
        return False

def _pin_not_expired(row):
    """Meetup-Pins verfallen nach ihrem Event-Tag (Owner 2026-07-04: 'Devil
    wears prada ist doch schon vorbei und noch zu sehen?'). pin_date < heute
    → raus. Ohne pin_date: 48h ab created_at als Frist. Wirft nie."""
    try:
        today = datetime.now(timezone.utc).date().isoformat()
        pd = (row.get('pin_date') or '')[:10]
        if pd:
            return pd >= today
        ca = row.get('created_at') or ''
        if ca:
            created = datetime.fromisoformat(str(ca).replace('Z', '+00:00'))
            return (datetime.now(timezone.utc) - created).total_seconds() < 48 * 3600
    except Exception:
        pass
    return True


def _manual_pins_load(token):
    """Eigene Pins (zur Verwaltung). Liste von Row-Dicts."""
    if not token or not SB_AVAILABLE:
        return []
    try:
        r = (sb.table('manual_pins').select('*')
             .eq('user_token', token).order('pin_date').limit(500).execute())
        return [x for x in (r.data or []) if _pin_not_expired(x)]
    except Exception as e:
        app.logger.warning(f'[crew-dest] pins_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return []

def _manual_pins_for_friends(token, friend_tokens):
    """Pins der GEGENSEITIGEN Friends (Privacy: nur mutual). friend_tokens ist
    bereits die mutual-Liste (user_friends ist bidirektional beim Add)."""
    if not friend_tokens or not SB_AVAILABLE:
        return []
    try:
        r = (sb.table('manual_pins').select('*')
             .in_('user_token', list(friend_tokens)[:500]).limit(2000).execute())
        return [x for x in (r.data or []) if _pin_not_expired(x)]
    except Exception as e:
        app.logger.warning(f'[crew-dest] friend_pins_fail err={type(e).__name__}: {str(e)[:120]}')
        return []


def _public_pins_at_iatas(iatas):
    """ÖFFENTLICHE Treffpunkt-Pins an den DESTINATIONS-Flughäfen des Users — von
    ALLER Crew, nicht nur Buddies (User: „alle Flieger Zugang zum Pin"). Ein Pin
    ist ein öffentlicher Meetup-Spot an einem Ort; die LIVE-Crew-Position bleibt
    davon unberührt friends-only. Nur Pins an Orten, wo der User selbst hin fliegt,
    damit es relevant + nicht global-überflutet ist."""
    iatas = [i for i in (iatas or []) if i]
    if not iatas or not SB_AVAILABLE:
        return []
    try:
        r = (sb.table('manual_pins').select('*')
             .in_('iata_code', list(set(iatas))[:60]).limit(2000).execute())
        return [x for x in (r.data or []) if _pin_not_expired(x)]
    except Exception as e:
        app.logger.warning(f'[crew-dest] public_pins_fail err={type(e).__name__}: {str(e)[:120]}')
        return []

def _user_future_layovers(token, days_ahead=60):
    """Layover-Tage eines Users im Fenster [heute, heute+days_ahead] als Liste
    {datum, date_obj, iata, start_time, end_time}. Quelle: _store (frisch) ODER
    persistenter roster_snapshot (überlebt Container-Restart)."""
    from datetime import date as _d, timedelta as _td
    sess = _store.get(token) or {}
    tage = (sess.get('result_data') or {}).get('_tage_detail') or []
    if not tage:
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    today = _d.today()
    cutoff = today + _td(days=days_ahead)
    out = []
    for t in tage:
        if not isinstance(t, dict):
            continue
        klass = (t.get('klass') or '').upper()
        rf = t.get('reader_facts') or {}
        # Nightstop = letzte Tages-Ankunft aus ical_sectors (Fallback layover_ort).
        place = (_feed_nightstop_ort(t) or '').upper().strip()
        if klass not in _CREW_DEST_LAYOVER_KLASSEN or len(place) != 3:
            continue
        d = t.get('datum')
        try:
            dd = _d.fromisoformat((d or '')[:10])
        except Exception:
            continue
        if dd < today or dd > cutoff:
            continue
        out.append({'datum': (d or '')[:10], 'date_obj': dd, 'iata': place,
                    'start_time': rf.get('start_time'), 'end_time': rf.get('end_time')})
    return out


def _user_current_iata(token):
    """IATA des Flughafens, an dem der User HEUTE physisch ist — gleiche Quelle
    wie friends_today/Live-City (heutiger Roster-Tag, reader_facts.layover_ort).
    Anders als _user_future_layovers NICHT auf Z76 gefiltert: wer heute an einem
    Airport sitzt (Turnaround/positioniert/wohnt dort), soll lokale öffentliche
    Hangout-Pins sehen, auch wenn der Tag nicht als Layover klassifiziert ist.
    Returns 3-letter IATA (uppercase) oder None."""
    from datetime import date as _d
    sess = _store.get(token) or {}
    tage = (sess.get('result_data') or {}).get('_tage_detail') or []
    if not tage:
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    today = _d.today().isoformat()
    for t in tage:
        if not isinstance(t, dict) or (t.get('datum') or '')[:10] != today:
            continue
        place = (_feed_nightstop_ort(t) or '').upper().strip()
        if len(place) == 3 and place.isalpha():
            return place
        return None
    return None


@app.route('/api/user/crew-at-destination/<token>', methods=['GET'])
def get_crew_at_destination(token):
    """Crew an MEINEN Zielen. Returns:
      { ok, layover_matches: [{iata, lat, lng, my_dates, friends:[...]}],
        manual_pins: [{id, iata, lat, lng, date, note, owner_token, owner_name,
                       owner_match_id, mine}] }
    Modus A: Friends mit Layover an meiner Station ±24h (Opt-in + share_roster).
    Modus B: Pins meiner gegenseitigen Friends + meine eigenen.
    """
    from collections import defaultdict
    ap = _airports_compact_lookup()
    my_layovers = _user_future_layovers(token)
    friends = _friends_load(token).get('friends') or []
    friend_set = set(friends)

    # ── Modus A: Layover-Matches gruppiert nach IATA ──
    by_iata = defaultdict(lambda: {'friends': {}, 'my_dates': set()})
    for myl in my_layovers:
        by_iata[myl['iata']]['my_dates'].add(myl['datum'])

    # N+1-Fix (2026-07-01): Friend-Profile in EINEM Bulk-Query.
    _bulk_profs = _profiles_load_bulk(friends)
    for fr in friends:
        if not _layover_visibility_get(fr):
            continue
        prof = _bulk_profs.get(fr) or {}
        if prof.get('share_roster') is False:
            continue
        for fl in _user_future_layovers(fr):
            if fl['iata'] not in by_iata:
                continue  # nur an MEINEN Zielen
            # ±24h gegen irgendeinen meiner Layover an dieser Station
            if not any(myl['iata'] == fl['iata'] and abs((fl['date_obj'] - myl['date_obj']).days) <= 1
                       for myl in my_layovers):
                continue
            slot = by_iata[fl['iata']]['friends']
            if fr not in slot:  # ein Eintrag pro Friend (frühestes Match)
                slot[fr] = {
                    'token': fr,
                    'name': prof.get('name') or (fr[:8] + '…'),
                    'match_id': _hashlib.sha256(fr.encode()).hexdigest()[:16],
                    'datum': fl['datum'],
                    'start_time': fl['start_time'],
                    'end_time': fl['end_time'],
                }

    layover_matches = []
    for iata, info in by_iata.items():
        if not info['friends']:
            continue
        coord = ap.get(iata)
        # Kanonische Gruppen-Channel-ID (Multi-Agent-Review 2026-06-10, Welle A):
        # Der iOS-Client errechnete die ID vorher aus my_dates.first — also dem
        # EIGENEN Datum. Bei einem ±24h-Match (A am 10., B am 11.) kamen beide
        # auf verschiedene IDs und landeten in getrennten Räumen. Wir liefern die
        # ID jetzt serverseitig aus dem FRÜHESTEN Datum im Match-Cluster
        # (eigene Layover ∪ gematchte Friend-Tage an dieser Station). Für den
        # häufigen Paar-Fall (gleiche Nacht) deterministisch identisch für alle;
        # die seltene 3er-Kette (A-10/B-11/C-12, A≁C) degradiert sauber.
        _cluster_dates = set(info['my_dates']) | {
            f.get('datum') for f in info['friends'].values() if f.get('datum')
        }
        _canon = min((d for d in _cluster_dates if d), default='')
        channel_id = f"group__lo_{iata.upper()}_{''.join(ch for ch in _canon if ch.isdigit())}"
        layover_matches.append({
            'iata': iata,
            'lat': coord[0] if coord else None,
            'lng': coord[1] if coord else None,
            'my_dates': sorted(info['my_dates']),
            'channel_id': channel_id,
            'friends': sorted(info['friends'].values(), key=lambda x: x['datum']),
        })
    layover_matches.sort(key=lambda m: -len(m['friends']))

    # ── Modus B: manuelle Treffpunkt-Pins ──
    # Sichtbar: eigene + gegenseitige Buddies + ÖFFENTLICHE Pins an MEINEN
    # Destinations-Flughäfen (alle Crew — der Pin ist ein öffentlicher Meetup-Spot,
    # zu dem jeder beitreten kann). Die LIVE-Crew-POSITION bleibt friends-only.
    dest_iatas = set(by_iata.keys())
    # Hangouts auch für Crew VOR ORT sichtbar: der aktuelle Standort-Flughafen
    # des Users (heutiger Roster-Tag / Live-City) zählt als öffentlicher Meetup-
    # Ort, auch wenn er kein eigenes Layover-Ziel ist. Sonst sieht Crew, die
    # gerade an einem Airport ist, lokale Hangouts nie. Nur DIESE eine IATA dazu —
    # keine Ausweitung auf „alle Pins überall".
    public_iatas = set(dest_iatas)
    cur_iata = _user_current_iata(token)
    if cur_iata:
        public_iatas.add(cur_iata)
    pins_out = []
    seen = set()
    _all_pins = (_manual_pins_load(token)
                 + _manual_pins_for_friends(token, friend_set)
                 + _public_pins_at_iatas(public_iatas))
    # N+1-Fix (2026-07-01): Owner-Namen in EINEM Bulk-Query statt pro Pin.
    _owner_profs = _profiles_load_bulk(
        [p.get('user_token') for p in _all_pins
         if p.get('user_token') and p.get('user_token') != token])
    for p in _all_pins:
        pid = p.get('id')
        if not pid or pid in seen:
            continue
        seen.add(pid)
        owner = p.get('user_token') or ''
        mine = owner == token
        is_public_meetup = (p.get('iata_code') or '').upper() in public_iatas
        if not mine and owner not in friend_set and not is_public_meetup:
            continue  # Privacy: nur mutual ODER öffentlicher Pin an meinem Ziel
        oprof = {} if mine else (_owner_profs.get(owner) or {})
        pins_out.append({
            'id': pid,
            'iata': p.get('iata_code'),
            'lat': p.get('lat'),
            'lng': p.get('lng'),
            'date': str(p.get('pin_date')) if p.get('pin_date') else None,
            'note': p.get('note'),
            # Token-Leak-Fix: owner_token ist das Bearer-Credential — NUR für
            # eigene Pins + mutual Friends (DM-Flow). Öffentliche Meetup-Pins
            # von Fremden liefern nur owner_match_id (opak) + owner_name.
            'owner_token': owner if (mine or owner in friend_set) else None,
            'owner_name': 'Du' if mine else (oprof.get('name') or (owner[:8] + '…')),
            'owner_match_id': _hashlib.sha256(owner.encode()).hexdigest()[:16],
            'mine': mine,
        })

    return jsonify({'ok': True, 'layover_matches': layover_matches,
                    'manual_pins': pins_out})


def _hangouts_load_all_active():
    """ALLE noch aktiven (nicht abgelaufenen) Treffpunkt-Pins — global, von ALLER
    Crew. Ein Hangout ist ein öffentlicher, beitretbarer Meetup-Spot; jeder soll
    ihn sehen + per Pin-Channel beitreten können (Capability-Modell).

    „Aktiv" = pin_date >= heute ODER pin_date NULL (datumslose Pins altern nicht,
    konsistent mit der iOS-isPinActive-Logik). Server-seitiger Zeitfilter, damit
    abgelaufene Pins gar nicht erst übertragen werden; der Client filtert via
    isPinActive zusätzlich (yyyy-MM-dd lexikografisch korrekt). Liste von Rows."""
    if not SB_AVAILABLE:
        return []
    from datetime import date as _d
    today = _d.today().isoformat()
    try:
        # pin_date >= today  ODER  pin_date IS NULL. or_() mit gte+is.null.
        r = (sb.table('manual_pins').select('*')
             .or_(f'pin_date.gte.{today},pin_date.is.null')
             .limit(5000).execute())
        return r.data or []
    except Exception as e:
        app.logger.warning(f'[hangouts] load_all_fail err={type(e).__name__}: {str(e)[:120]}')
        return []


@app.route('/api/user/hangouts/<token>', methods=['GET'])
def list_hangouts(token):
    """GLOBALER öffentlicher Hangout-Feed: ALLE aktiven manual_pins, sichtbar für
    jeden authentifizierten Viewer — unabhängig von Standort oder Freundschaft.
    Ein Hangout ist ein öffentlicher Meetup; jeder kann ihn sehen + (über den
    Pin-Channel `group__pin_<id>`) beitreten.

    Returns: { ok, hangouts: [{id, iata, lat, lng, date, note, owner_name,
                               owner_match_id, owner_token?, mine}] }

    Privacy: das rohe owner_token (= Bearer-Credential) wird NUR für eigene Pins
    und gegenseitige Friends ausgeliefert (DM-Flow). Fremde Hangouts liefern nur
    die opake owner_match_id + owner_name. Die LIVE-Crew-Position bleibt unberührt
    friends-only (separater Endpoint crew-at-destination). Dieser Feed ist ADDITIV.
    """
    friend_set = set(_friends_load(token).get('friends') or [])
    out = []
    _pins = _hangouts_load_all_active()
    # N+1-Fix (2026-07-01): Owner-Namen in EINEM Bulk-Query statt pro Hangout.
    _owner_profs = _profiles_load_bulk(
        [p.get('user_token') for p in _pins
         if p.get('user_token') and p.get('user_token') != token])
    for p in _pins:
        pid = p.get('id')
        if not pid:
            continue
        owner = p.get('user_token') or ''
        mine = owner == token
        is_friend = owner in friend_set
        oprof = {} if mine else (_owner_profs.get(owner) or {})
        out.append({
            'id': pid,
            'iata': p.get('iata_code'),
            'lat': p.get('lat'),
            'lng': p.get('lng'),
            'date': str(p.get('pin_date')) if p.get('pin_date') else None,
            'note': p.get('note'),
            # Token-Leak-Schutz: rohes owner_token NUR für self + mutual Friends.
            'owner_token': owner if (mine or is_friend) else None,
            'owner_name': 'Du' if mine else (oprof.get('name') or (owner[:8] + '…')),
            'owner_match_id': _hashlib.sha256(owner.encode()).hexdigest()[:16],
            'mine': mine,
        })
    return jsonify({'ok': True, 'hangouts': out})


