@app.route('/api/leaderboard/<iata>/<token>', methods=['GET'])
def get_destination_leaderboard(iata, token):
    """Crew-Competition: Wer fliegt am häufigsten nach <iata>? Rankt alle Crew,
    die ihren Plan teilen (share_roster != False), nach Anzahl Dienst-Tage mit
    diesem Ziel im Routing/Location. Liefert Top-20 + den eigenen Rang.

    { ok, iata, total_crew, ranking:[{rank, name, count, mine}], my_rank, my_count }
    Privacy: nur opt-in-Crew (share_roster); Namen aus user_profiles, kein Token.
    """
    iata = (iata or '').upper().strip()[:3]
    if not SB_AVAILABLE or len(iata) != 3:
        return jsonify({'ok': False, 'iata': iata, 'ranking': [],
                        'my_rank': None, 'my_count': 0, 'total_crew': 0})
    from collections import defaultdict
    counts = defaultdict(int)

    def _is_outbound_arrival(summary, location, iata):
        txt = f"{summary or ''} {location or ''}".upper()
        for grp in re.findall(r'[A-Z]{3}(?:\s*-\s*[A-Z]{3})+', txt):
            legs = [p.strip() for p in grp.split('-')]
            if legs and legs[-1] == iata:
                return True
        return False

    try:
        # EIN Query über alle Briefings, die das IATA in Location/Summary tragen.
        # Ein Mehrtages-Layover liegt als 1 Row pro Kalendertag vor — wir zählen
        # NUR die Hinflug-Ankunft (letztes Leg eines Routings == iata), nie
        # Return-Legs oder Layover-Fortsetzungstage (ical_klass == 'hotel_layover').
        pat = f'%{iata}%'
        r = (sb.table('user_ical_briefings')
             .select('token,datum,ical_summary,ical_location,ical_klass')
             .or_(f'ical_location.ilike.{pat},ical_summary.ilike.{pat}')
             .limit(20000).execute())
        seen = set()
        for row in (r.data or []):
            tk = row.get('token'); dt = row.get('datum')
            if not tk or not dt:
                continue
            if (row.get('ical_klass') or '') == 'hotel_layover':
                continue
            if not _is_outbound_arrival(row.get('ical_summary'),
                                        row.get('ical_location'), iata):
                continue
            key = (tk, dt)
            if key in seen:
                continue
            seen.add(key)
            counts[tk] += 1
    except Exception as e:
        app.logger.warning(f'[leaderboard] query-fail: {str(e)[:150]}')
        return jsonify({'ok': False, 'iata': iata, 'ranking': [],
                        'my_rank': None, 'my_count': 0, 'total_crew': 0})

    # Pro Token EINMAL gezählt (datum-dedupe oben). Namen + opt-in joinen.
    # N+1-Fix (2026-07-01): alle Ranking-Profile in EINEM Bulk-Query.
    _bulk_profs = _profiles_load_bulk(list(counts.keys()))
    ranked = []
    for tk, cnt in counts.items():
        prof = _bulk_profs.get(tk) or {}
        if prof.get('share_roster') is False:
            continue
        # Eigene Homebase ist kein "Besuch" — raus aus dem Ranking.
        if (prof.get('homebase') or '').upper().strip() == iata:
            continue
        ranked.append({
            'token': tk,
            'name': (prof.get('name') or 'Crew').strip() or 'Crew',
            'count': cnt,
            'mine': tk == token,
        })
    ranked.sort(key=lambda x: (-x['count'], x['name'].lower()))

    my_rank = None
    my_count = 0
    out = []
    for i, e in enumerate(ranked):
        rank = i + 1
        if e['mine']:
            my_rank = rank
            my_count = e['count']
        if rank <= 20 or e['mine']:
            out.append({'rank': rank, 'name': e['name'],
                        'count': e['count'], 'mine': e['mine']})
    # eigenen Eintrag anhängen wenn außerhalb Top-20 (damit man seinen Rang sieht).
    return jsonify({'ok': True, 'iata': iata, 'total_crew': len(ranked),
                    'ranking': out[:21], 'my_rank': my_rank, 'my_count': my_count})


# ── Hangout-Geo-Push (Owner-Wunsch 2026-07-16) ──────────────────────────────
# Wenn ein User einen öffentlichen Treffpunkt-Pin (Hangout) erstellt, sollen
# ALLE AeroX-User im ~100-km-Umkreis EINEN Push bekommen, damit der global
# sichtbare Hangout auffindbar wird.
#
# STANDORT-QUELLE (ehrlichste vorhandene): Es gibt KEINE gespeicherte Live-GPS-
# Koordinate pro User im Backend — das Profil trägt nur `current_city` (String)
# und `location_source`. Die einzige verlässliche, serverseitige Positions-
# Wahrheit ist der HEUTIGE Roster-Ort (Layover/Dienst-Airport) via
# `_user_current_iata(token)` → Airport-Koordinate aus airports_compact.json.
# Das ist dieselbe Quelle, die friends-today / Live-City nutzen. NÄHERUNG:
# Airport-Zentrum statt exakter Aufenthaltsort; wer heute keinen 3-Letter-Roster-
# Ort hat, hat für uns keine bekannte Position und wird ausgeschlossen.
#
# SICHERHEIT: Der eigentliche Sende-Fanout ist hinter dem Flag HANGOUT_GEO_PUSH
# (Default '0' = AUS). Solange AUS: Auswahl läuft + wird geloggt, aber NICHTS
# gesendet ("would notify N users"). 550 echte Produktions-User, APNs live.
HANGOUT_GEO_PUSH_RADIUS_KM = 100.0
HANGOUT_GEO_PUSH_MAX_RECIPIENTS = 300     # Vernunft-Deckel pro Hangout
HANGOUT_GEO_PUSH_COOLDOWN_SEC = 30 * 60   # pro Ersteller max 1 Geo-Push / 30 min

# In-Memory Cooldown-Map {creator_token: last_geo_push_epoch}. Reicht (best-effort
# Anti-Spam); übersteht keinen Restart, was für einen 30-min-Deckel unkritisch ist.
_hangout_geo_push_last = {}


def _hangout_geo_push_enabled():
    """Flag-Gate. Default AUS. Nur wenn HANGOUT_GEO_PUSH in {'1','true','on','yes'}
    wird tatsächlich gesendet — sonst nur count-Logging."""
    return os.environ.get('HANGOUT_GEO_PUSH', '0').strip().lower() in (
        '1', 'true', 'on', 'yes')


def _hangout_geo_push_cooldown_active(creator_token, now_epoch=None):
    """True wenn der Ersteller innerhalb der Cooldown-Fensters schon einen
    Geo-Push ausgelöst hat (Anti-Spam)."""
    if not creator_token:
        return False
    import time as _t
    now_epoch = now_epoch if now_epoch is not None else _t.time()
    last = _hangout_geo_push_last.get(creator_token)
    return last is not None and (now_epoch - last) < HANGOUT_GEO_PUSH_COOLDOWN_SEC


def _users_near(lat, lon, radius_km=HANGOUT_GEO_PUSH_RADIUS_KM,
                exclude_token=None):
    """Reine Geo-Selektion: liefert die User-Tokens, deren zuletzt bekannte
    Position (heutiger Roster-Ort → Airport-Koordinate) innerhalb radius_km um
    (lat, lon) liegt. Haversine-Distanz.

    Kandidaten = alle Tokens in user_push_tokens (nur wer ein Gerät hat, kann
    überhaupt gepusht werden). Für jeden:
      • Position via _user_current_iata → Airport-Koordinate; kein Ort ⇒ raus.
      • Ausschluss: Ersteller selbst.
      • Ausschluss: share_location == False (explizit; Default True).
      • Ausschluss: Family-Konten (account_type == 'family').
    Returns sortierte Liste (nach Distanz) von {token, iata, distance_km}.
    Der Empfänger-Deckel wird NICHT hier, sondern im Fanout angewandt (damit
    die reine Selektion testbar bleibt).
    """
    if lat is None or lon is None or not SB_AVAILABLE or sb is None:
        return []
    try:
        lat = float(lat); lon = float(lon)
    except (TypeError, ValueError):
        return []

    # Kandidaten-Tokens: alle registrierten Push-Empfänger (paginiert).
    tokens = []
    try:
        for i in range(0, 20000, 1000):
            r = (sb.table('user_push_tokens').select('user_token')
                 .range(i, i + 999).execute())
            batch = [x.get('user_token') for x in (r.data or []) if x.get('user_token')]
            tokens.extend(batch)
            if len(batch) < 1000:
                break
    except Exception as e:
        app.logger.warning(
            f'[hangout-geo] token_scan_fail err={type(e).__name__}: {str(e)[:120]}')
        return []
    tokens = [t for t in dict.fromkeys(tokens) if t and t != exclude_token]
    if not tokens:
        return []

    profs = _profiles_load_bulk(tokens)
    ap = _airports_compact_lookup()
    out = []
    for t in tokens:
        prof = profs.get(t) or {}
        # share_location AUS respektieren (explizites False; Default an).
        if prof.get('share_location') is False:
            continue
        # Family-Konten ausschließen.
        if _is_family_account(prof):
            continue
        iata = _user_current_iata(t)
        if not iata:
            continue
        coord = ap.get(iata)
        if not coord:
            continue
        d = _haversine_km(lat, lon, coord[0], coord[1])
        if d <= radius_km:
            out.append({'token': t, 'iata': iata, 'distance_km': round(d, 1)})
    out.sort(key=lambda x: x['distance_km'])
    return out


def _hangout_notify_nearby(creator_token, lat, lon, iata, title, pin_id,
                           now_epoch=None):
    """Best-effort Geo-Fanout NACH erfolgreichem Pin-Insert. Wählt Empfänger im
    Umkreis, wendet Deckel + Ersteller-Cooldown an. Sendet NUR wenn
    HANGOUT_GEO_PUSH aktiv — sonst reines count-Logging ("would notify").
    Returns dict {selected, sent, capped, cooldown, enabled} (für Tests/Logs).
    Wirft nie (der Erstell-Response darf nie brechen)."""
    import time as _t
    now_epoch = now_epoch if now_epoch is not None else _t.time()
    result = {'selected': 0, 'sent': 0, 'capped': False,
              'cooldown': False, 'enabled': _hangout_geo_push_enabled()}
    try:
        if _hangout_geo_push_cooldown_active(creator_token, now_epoch):
            result['cooldown'] = True
            app.logger.info(
                f'[hangout-geo] cooldown active creator={_push_token_ref(creator_token)} '
                f'— skip iata={iata}')
            return result

        near = _users_near(lat, lon, exclude_token=creator_token)
        result['selected'] = len(near)
        if len(near) > HANGOUT_GEO_PUSH_MAX_RECIPIENTS:
            result['capped'] = True
            near = near[:HANGOUT_GEO_PUSH_MAX_RECIPIENTS]

        place = (iata or '').upper() or 'deiner Nähe'
        short_title = (title or 'Treffpunkt').strip()[:60]
        body = f'Neuer Treffpunkt in {place}: {short_title}'
        data = {'type': 'hangout_nearby', 'pin_id': pin_id,
                'iata': iata, 'deep_link': f'aerox://hangout/{pin_id}'}

        if not result['enabled']:
            app.logger.info(
                f'[hangout-geo] FLAG OFF — would notify {len(near)} users '
                f'iata={iata} pin={pin_id}')
            return result

        # Cooldown erst NACH bestätigter Send-Absicht setzen.
        _hangout_geo_push_last[creator_token] = now_epoch
        sent = 0
        for u in near:
            try:
                _push_outbox_enqueue(
                    u['token'], 'AeroX Treffpunkt', body, data=data,
                    thread_id=f'hangout__{pin_id}', category='community',
                    idempotency_key=f'hangout-geo:{pin_id}:{_push_token_ref(u["token"])}')
                sent += 1
            except Exception:
                continue
        result['sent'] = sent
        app.logger.info(
            f'[hangout-geo] notified sent={sent} selected={result["selected"]} '
            f'capped={result["capped"]} iata={iata} pin={pin_id}')
        return result
    except Exception as e:
        app.logger.warning(
            f'[hangout-geo] notify_fail err={type(e).__name__}: {str(e)[:160]}')
        return result


@app.route('/api/user/manual-pins/<token>', methods=['GET'])
def list_manual_pins(token):
    """Eigene Pins (zur Verwaltung/Löschen)."""
    rows = _manual_pins_load(token)
    out = [{
        'id': p.get('id'), 'iata': p.get('iata_code'),
        'lat': p.get('lat'), 'lng': p.get('lng'),
        'date': str(p.get('pin_date')) if p.get('pin_date') else None,
        'note': p.get('note'),
    } for p in rows]
    return jsonify({'ok': True, 'pins': out})


@app.route('/api/user/manual-pins/<token>', methods=['POST'])
def create_manual_pin(token):
    """Body: {iata, date (YYYY-MM-DD), note, lat?, lng?}. lat/lng werden aus iata
    aufgelöst wenn nicht mitgegeben. Token-binding durch _bug004-Gate."""
    import uuid as _uuid
    if not SB_AVAILABLE:
        return jsonify({'ok': False, 'error': 'storage_unavailable'}), 503
    body = request.get_json(silent=True) or {}
    iata = (body.get('iata') or '').upper().strip()
    if len(iata) != 3:
        return jsonify({'ok': False, 'error': 'invalid_iata'}), 400
    ap = _airports_compact_lookup()
    coord = ap.get(iata)
    lat = body.get('lat')
    lng = body.get('lng')
    if lat is None or lng is None:
        if not coord:
            return jsonify({'ok': False, 'error': 'iata_not_found'}), 400
        lat, lng = coord[0], coord[1]
    pin_date = (body.get('date') or '').strip() or None
    note = (body.get('note') or '').strip()[:280] or None
    pin_id = _uuid.uuid4().hex[:16]
    row = {
        'id': pin_id, 'user_token': token, 'iata_code': iata,
        'lat': float(lat), 'lng': float(lng), 'pin_date': pin_date, 'note': note,
        'created_at': datetime.now().isoformat(),
    }
    try:
        sb.table('manual_pins').insert(row).execute()
    except Exception as e:
        app.logger.warning(f'[crew-dest] pin_insert_fail err={type(e).__name__}: {str(e)[:120]}')
        return jsonify({'ok': False, 'error': 'insert_failed'}), 500
    # Best-effort Geo-Push an AeroX-User im ~100-km-Umkreis (nach dem Commit,
    # try/except intern — bricht NIE den Erstell-Response). Sendet nur wenn
    # HANGOUT_GEO_PUSH aktiv; sonst nur count-Logging. Deep-Link auf den Hangout.
    try:
        _hangout_notify_nearby(token, lat, lng, iata,
                               title=(note or iata), pin_id=pin_id)
    except Exception:
        pass
    return jsonify({'ok': True, 'pin': {
        'id': pin_id, 'iata': iata, 'lat': lat, 'lng': lng,
        'date': pin_date, 'note': note}})


@app.route('/api/user/manual-pins/<token>/<pin_id>/delete', methods=['POST'])
def delete_manual_pin(token, pin_id):
    """Löscht NUR den eigenen Pin (gezielter Delete, owner-scoped). Token-binding
    durch _bug004-Gate."""
    if not SB_AVAILABLE:
        return jsonify({'ok': False, 'error': 'storage_unavailable'}), 503
    try:
        sb.table('manual_pins').delete().eq('id', pin_id).eq('user_token', token).execute()
    except Exception as e:
        app.logger.warning(f'[crew-dest] pin_delete_fail err={type(e).__name__}: {str(e)[:120]}')
        return jsonify({'ok': False, 'error': 'delete_failed'}), 500
    return jsonify({'ok': True})


@app.route('/api/user/friend-groups/<token>', methods=['GET'])
def list_friend_groups(token):
    """Listet alle Friend-Groups des Users."""
    data = _friends_load(token)
    groups = data.get('groups') or []
    return jsonify({'token': token, 'groups': groups, 'count': len(groups)})


@app.route('/api/user/friend-groups/<token>/create', methods=['POST'])
def create_friend_group(token):
    """Erstellt eine neue Friend-Group. Body: {name, member_tokens: [...]}"""
    import uuid as _uuid
    body = request.get_json(silent=True) or {}
    name = (body.get('name') or '').strip()
    members = body.get('member_tokens') or []
    if not name:
        return jsonify({'ok': False, 'error': 'name_required'}), 400
    if not isinstance(members, list):
        return jsonify({'ok': False, 'error': 'member_tokens_must_be_list'}), 400
    # Nur tatsächliche Friends dürfen Members sein
    data = _friends_load(token)
    friends_set = set(data.get('friends') or [])
    members = [m for m in members if isinstance(m, str) and m in friends_set]
    new_group = {
        'id': str(_uuid.uuid4())[:8],
        'name': name[:60],
        'members': members,
        'created_at': datetime.now().isoformat(),
    }
    if 'groups' not in data: data['groups'] = []
    data['groups'].append(new_group)
    _friends_save(token, data)
    return jsonify({'ok': True, 'group': new_group})


@app.route('/api/user/friend-groups/<token>/<group_id>/update', methods=['POST'])
def update_friend_group(token, group_id):
    body = request.get_json(silent=True) or {}
    data = _friends_load(token)
    groups = data.get('groups') or []
    friends_set = set(data.get('friends') or [])
    found = False
    for g in groups:
        if g.get('id') == group_id:
            if 'name' in body and isinstance(body['name'], str):
                g['name'] = body['name'].strip()[:60]
            if 'member_tokens' in body and isinstance(body['member_tokens'], list):
                g['members'] = [m for m in body['member_tokens'] if isinstance(m, str) and m in friends_set]
            g['updated_at'] = datetime.now().isoformat()
            found = True
            break
    if not found:
        return jsonify({'ok': False, 'error': 'group_not_found'}), 404
    _friends_save(token, data)
    return jsonify({'ok': True})


@app.route('/api/user/friend-groups/<token>/<group_id>/delete', methods=['POST'])
def delete_friend_group(token, group_id):
    data = _friends_load(token)
    groups = data.get('groups') or []
    new_groups = [g for g in groups if g.get('id') != group_id]
    if len(new_groups) == len(groups):
        return jsonify({'ok': False, 'error': 'group_not_found'}), 404
    data['groups'] = new_groups
    _friends_save(token, data)
    return jsonify({'ok': True})


def _friend_group_row_by_id(group_id):
    """Lädt die Gruppen-Zeile GLOBAL per `id` aus user_friend_groups (owner_token,
    name, members). Die Gruppe liegt in der Friend-Group-Zeile ihres OWNERs — ein
    per-Code beigetretenes Mitglied findet sie NICHT über den eigenen Token, daher
    der id-basierte Lookup (identisch zum Push-Fanout, app.py ~24885)."""
    if not (SB_AVAILABLE and sb is not None and group_id):
        return None
    try:
        r = (sb.table('user_friend_groups')
             .select('id,owner_token,name,members')
             .eq('id', group_id).limit(1).execute())
        rows = r.data or []
        return rows[0] if rows else None
    except Exception as e:
        app.logger.warning(
            f'[fgroups] row_by_id_fail gid={group_id} err={type(e).__name__}: {str(e)[:120]}')
        return None


@app.route('/api/user/friend-groups/<token>/<group_id>/add-member', methods=['POST'])
def add_member_to_group(token, group_id):
    """Fügt EINE Person direkt zu einer Layover-Gruppe hinzu (Zweck-Gruppe auf Zeit
    — KEINE Freundschaft als Voraussetzung, KEINE Freundschafts-Anfrage).

    Body: {"target_token": "AT-…"}.

    Regeln:
    - Der Aufrufer (`token`, per BUG-004-Gate an den Bearer gebunden) MUSS selbst
      Mitglied der Gruppe sein — Owner ODER in `members` (Capability-Modell: wer
      via Code/QR beigetreten ist, steht spätestens nach dem ersten Post in
      `members`, siehe Push-Fanout). Sonst 403.
    - Das Ziel darf KEIN Family-Konto sein (Family-Pairing läuft über einen
      anderen Pfad) → 400 `family_account_not_addable`.
    - Idempotent: schon Mitglied ⇒ ok.
    - Die Gruppe erscheint beim Hinzugefügten über denselben Mechanismus wie beim
      Code-Beitritt (Push mit `type=group_added` + Invite-Code → das Gerät joint
      lokal via JoinedGroupsStore). Er kann sie jederzeit verlassen.
    """
    body = request.get_json(silent=True) or {}
    target = (body.get('target_token') or '').strip()
    if not target:
        return jsonify({'ok': False, 'error': 'target_token_required'}), 400
    if target == token:
        # Sich selbst hinzufügen ist ein No-Op-Erfolg (man ist bereits drin).
        return jsonify({'ok': True, 'already_member': True})

    row = _friend_group_row_by_id(group_id)
    if not row:
        return jsonify({'ok': False, 'error': 'group_not_found'}), 404

    owner_token = row.get('owner_token') or ''
    members = [m for m in (row.get('members') or []) if isinstance(m, str)]

    # Aufrufer muss Mitglied sein (Owner oder in members).
    if token != owner_token and token not in members:
        return jsonify({'ok': False, 'error': 'not_a_member'}), 403

    # Ziel darf kein Family-Konto sein.
    if _is_family_account(target):
        return jsonify({'ok': False, 'error': 'family_account_not_addable',
                        'message': 'Familien-Konten können nicht hinzugefügt werden.'}), 400

    already = (target == owner_token) or (target in members)
    if not already:
        new_members = members + [target]
        try:
            if SB_AVAILABLE and sb is not None:
                sb.table('user_friend_groups').update(
                    {'members': new_members}).eq('id', group_id).execute()
        except Exception as e:
            app.logger.error(
                f'[fgroups] add_member_fail gid={group_id} err={type(e).__name__}: {str(e)[:200]}')
            return jsonify({'ok': False, 'error': 'add_failed'}), 503

    group_name = (row.get('name') or '').strip() or 'Layover-Chat'
    # Best-effort Push: „X hat dich hinzugefügt" + Invite-Code, damit das Gerät des
    # Hinzugefügten die Gruppe lokal joint (kein server-seitiges Group-Listing).
    if not already:
        try:
            adder_name = ((_profile_load(token) or {}).get('profile') or {}).get('name') or 'Crew'
            _push_outbox_enqueue(
                target,
                'Layover-Chat',
                f'{adder_name} hat dich zu „{group_name}" hinzugefügt.',
                data={'type': 'group_added', 'group_id': group_id,
                      'group_name': group_name},
                thread_id=f'group__{group_id}',
                idempotency_key=f'group-added:{group_id}:{_push_token_ref(target)}')
        except Exception:
            pass

    return jsonify({'ok': True, 'group_id': group_id, 'group_name': group_name,
                    'already_member': bool(already)})


@app.route('/api/user/friends-homebases/<token>', methods=['GET'])
def get_friends_homebases(token):
    """OffBlock-Pattern: Liste Friends gruppiert nach Homebase.
    Returns: {homebases: [{iata, count, friends:[{token, name}]}]}
    """
    from collections import defaultdict
    data = _friends_load(token)
    friends = data.get('friends') or []
    grouped = defaultdict(list)
    # N+1-/Durability-Fix (2026-07-01): Bulk-SB-Query statt Disk-Datei pro
    # Friend — die Disk ist auf Cloud Run ephemer/per-Instanz, die Gruppierung
    # war dort fast immer '???' weil die Profil-Dateien fehlten.
    _bulk_profs = _profiles_load_bulk(friends)
    for fr in friends:
        pr = _bulk_profs.get(fr) or {}
        hb = (pr.get('homebase') or '').upper().strip()
        if not hb or len(hb) != 3: hb = '???'
        grouped[hb].append({
            'token': fr[:16] + '…',  # truncate for privacy
            # NAME-FIX (Owner 2026-07-13): kein erfundener 'Friend'-Platzhalter —
            # leerer Name bleibt ehrlich '' (iOS lässt ihn dann weg).
            'name': pr.get('name') or '',
            'avatar_url': pr.get('avatar_url'),
            'airline': pr.get('airline') or '',
            'position': pr.get('position') or '',
        })
    homebases = [{'iata': hb, 'count': len(fl), 'friends': fl}
                 for hb, fl in sorted(grouped.items(), key=lambda x: -len(x[1]))]
    return jsonify({'token': token, 'homebases': homebases})


def _station_local_date(iso_utc, iata):
    """UTC-ISO → station-lokales Datum 'YYYY-MM-DD' (via airport_tz, Fallback
    Europe/Berlin — dieselbe Operations-TZ wie die iCal-Tages-Buckets). None bei
    Parse-Fehler. Wirft nie."""
    s = (iso_utc or '').strip()
    if not s:
        return None
    try:
        dt = datetime.fromisoformat(s.replace('Z', '+00:00'))
    except Exception:
        return None
    try:
        from zoneinfo import ZoneInfo as _ZI
    except Exception:
        _ZI = None  # type: ignore
    tzname = None
    try:
        tzname = airport_tz(iata) if iata else None
    except Exception:
        tzname = None
    if _ZI is not None:
        try:
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=_ZI('UTC'))
            return dt.astimezone(_ZI(tzname or 'Europe/Berlin')).strftime('%Y-%m-%d')
        except Exception:
            pass
    try:
        return dt.strftime('%Y-%m-%d')
    except Exception:
        return None


def _feed_nightstop_ort(day, homebase=None):
    """Der Übernachtungs-/Nightstop-Ort EINES Roster-Tages für die FEED-Flächen
    (friends-today `lay_eff`, Crew-Vergleich/Overlap-Edges, Family, Layover-Rec-
    Discover). Vereinheitlichte Ableitung — vorher las jede Fläche `reader_facts.
    layover_ort` blind, was bei Multi-Leg-Turnaround-Tagen (Florian 2026-07-16:
    MUC→FCO→MUC→FCO, letzte Ankunft 15:05 FCO) fälschlich einen Vortags-/Kontext-
    Wert (BER) trug.

    REGEL: Nightstop eines Tages = Ankunfts-IATA des LETZTEN Flug-Sektors, der am
    SELBEN (stations-lokalen) Kalendertag ankommt. Ein Red-Eye (Ankunft am
    Folgetag) zählt NICHT als Nightstop dieses Tages.

    Ableitung nur wenn belastbare `ical_sectors` da sind:
      • sortiere nach dep_iso, nimm die Sektoren, deren arr_iso stations-lokal auf
        `day['datum']` fällt (Red-Eye/Folgetag fällt raus),
      • Nightstop = `to` des letzten solchen Sektors.
    Fehlen Sektoren/arr_iso/Ziel-IATAs (leg-loser Layover-Ruhetag wie eine reine
    LAYOVER-Zeile, SWISS-Feeds ohne arr_iso), bleibt der bisherige `reader_facts.
    layover_ort` die Wahrheit (byte-kompatibel).

    homebase (optional): landet der Tag mit seiner letzten same-day-Ankunft an der
    HOMEBASE, ist es ein Same-Day-Turnaround ZURÜCK nach Hause → KEIN Layover.
    Dann fällt die Funktion auf den Reader-Fallback (typisch None/leer) zurück,
    statt die Homebase als „Übernachtungsort" zu behaupten. Die statischen Feed-
    Flächen rufen OHNE homebase auf (sie wollen den Ziel-Ort auch bei Heimkehr);
    die friends-today-Live-Basis ruft MIT homebase auf (dort darf ein Turnaround
    keinen Basis-Pin erzeugen, die Live-Kaskade zeigt „unterwegs"/Position).
    Wirft nie."""
    rf = (day.get('reader_facts') or {}) if isinstance(day, dict) else {}
    fallback = rf.get('layover_ort')
    if not isinstance(day, dict):
        return fallback
    datum = (day.get('datum') or '')[:10]
    if not re.match(r'^\d{4}-\d{2}-\d{2}$', datum):
        return fallback
    secs = day.get('ical_sectors')
    if not isinstance(secs, list) or not secs:
        return fallback
    hb = (homebase or '').strip().upper() or None
    try:
        # nach Abflug sortieren (die Sektor-Reihenfolge ist die Flug-Reihenfolge)
        ordered = sorted(
            [s for s in secs if isinstance(s, dict) and s.get('arr_iso')],
            key=lambda s: str(s.get('dep_iso') or s.get('arr_iso') or ''))
        last_same_day = None
        for s in ordered:
            to = str(s.get('to') or '').strip().upper()
            if not (len(to) == 3 and to.isalpha()):
                continue
            arr_date = _station_local_date(s.get('arr_iso'), to)
            if arr_date is None:
                # Ohne station-lokales Ankunftsdatum keine belastbare Aussage —
                # dieser Sektor darf den Fallback nicht überschreiben.
                continue
            if arr_date == datum:
                last_same_day = to
            # arr_date > datum (Red-Eye) ⇒ überspringen; arr_date < datum kommt
            # bei sauber sortierten Tages-Sektoren praktisch nicht vor.
        if last_same_day:
            # Same-Day-Turnaround zurück zur Homebase = keine Übernachtung
            # außerhalb → Reader-Fallback (typisch None), kein Basis-Pin.
            if hb and last_same_day == hb:
                return fallback
            return last_same_day
    except Exception:
        return fallback
    # Keine same-day-Ankunft ableitbar (nur Red-Eye / unbekannte Ziele) →
    # bisherige Reader-Wahrheit behalten, kein erfundener Ort.
    return fallback


@app.route('/api/user/friend-roster/<token>/<friend_token>', methods=['GET'])
def get_friend_roster(token, friend_token):
    """Liefert das Roster eines Friends (Tag-Detail-Liste) für Tour-Compare.
    Privacy: nur wenn beide friends sind UND Friend hat share_roster=true im
    Profile (Default off). Honest empty array wenn nicht geteilt.
    Query: ?days=30 (default 30, max 90)
    """
    from datetime import date as _date, timedelta as _td
    from blueprints.aerox_data_blueprint import _route_label_cities, _iata_city_name
    days_limit = min(int(request.args.get('days') or 30), 90)
    # Friend-Check
    me = _friends_load(token)
    if friend_token not in (me.get('friends') or []):
        return jsonify({'ok': False, 'shared': False,
                        'error': 'not_friends', 'days': []}), 403
    # KEIN share_roster-Opt-Out mehr (Produkt-Entscheidung 2026-06-25): eine
    # ANGENOMMENE Freundschaft IST die Zustimmung, den Plan zu teilen. Es gibt
    # keinen Aus-Schalter mehr (im Client entfernt) — wer dich als Freund:in
    # bestätigt, sieht deinen Plan, reziprok.
    # Auch der FREUND-Roster soll frisch sein (Pickup-Events kommen erst ~1 Tag
    # vorher in den Feed) — gedrosselter Re-Sync seines calendar_feed.
    _maybe_refresh_calendar_feed(friend_token)
    # Friend roster: 1) aus _store (in-memory, frisch wenn Friend gerade aktiv),
    # 2) Fallback auf persistenten roster_snapshot — überlebt Container-Restart.
    # Vorher: nur _store → bei Render-Sleep waren alle Friend-Rosters leer.
    sess = _store.get(friend_token) or {}
    tage = (sess.get('result_data') or {}).get('_tage_detail') or []
    if not tage:
        tage = (_roster_snapshot_read(friend_token) or {}).get('tage') or []
    today = _date.today()
    cutoff = today + _td(days=days_limit)
    out = []
    for day in tage:
        if not isinstance(day, dict): continue
        d = day.get('datum')
        if not d: continue
        try:
            day_date = _date.fromisoformat(d[:10])
            if day_date > cutoff or day_date < today - _td(days=30): continue
        except Exception:
            continue
        rf = day.get('reader_facts') or {}
        # Nightstop = letzte Tages-Ankunft aus ical_sectors (Fallback: das rohe
        # reader_facts.layover_ort, das bei Turnaround-Tagen einen Vortags-Wert trug).
        _lay = _feed_nightstop_ort(day)
        out.append({
            'datum': d,
            'klass': day.get('klass'),
            'marker': day.get('marker'),
            'routing': day.get('routing'),
            'eur': day.get('eur'),
            'layover_ort': _lay,
            # Hübsches Tour-Label mit Städtenamen (2026-07-03: Family/Friends
            # sollen NIE rohe Token-Ketten wie "FRA-SFO-FRA" sehen). IATA-Codes
            # bleiben in routing/layover_ort verfügbar.
            'route_label': _route_label_cities(day.get('routing'), _lay),
            'layover_city': (_iata_city_name(_lay) if _lay else None),
            'start_time': rf.get('start_time'),
            'end_time': rf.get('end_time'),
            # Pro-Leg-Sektoren durchreichen (User 2026-07-01: „wer Zugriff auf den
            # Kalender hat, soll GENAU dasselbe sehen wie der Besitzer"). Ohne das zeigte
            # das Freunde-Sheet nur eine Route-Zeile/Tag statt der echten Legs. Familie
            # nutzt dieselbe Quelle (simplified/volle Namen im Client).
            'ical_sectors': day.get('ical_sectors'),
        })
    # FALLBACK (User 2026-06-30: „der Plan ist gespeichert, muss nur verlinkt
    # werden"): hat der Friend KEINEN gepushten Roster-Snapshot (z.B. er hat den
    # Plan nur als Kalender-Feed importiert, aber die App nie zum Snapshot-Push
    # geöffnet), bauen wir seinen Plan DIREKT aus dem gespeicherten `calendar_feed`
    # seines Profils. So sieht man den Plan eines Freundes, sobald die Freundschaft
    # steht — ohne dass er extra etwas pushen muss. (Roster-Snapshot bleibt die
    # bevorzugte, exaktere Quelle; das hier greift nur, wenn sie leer ist.)
    # FALLBACK = EXAKT die REICHE Quelle des Family-Pfads (_load_crew_roster_days):
    # hat der Friend keinen gepushten Snapshot, bauen wir den Plan aus seinen
    # `user_ical_briefings` (Routing aus den ical_location-IATAs, Zeiten aus
    # ical_start/end_iso). Der alte calendar_feed-Fallback lieferte routing=None →
    # nur Punkte/Per-Tag-Pillen statt verbundener Tour-Balken (Bild #55). Die FAMILIE
    # sieht den Plan über genau diese Quelle KORREKT — Friends jetzt genauso
    # (User 2026-06-30: „mach es einfach wie bei Family, die sehen es komplett richtig").
    if not out:
        try:
            briefs = _ical_briefings_load(friend_token) or {}
            def _hhmm(x):
                m = re.search(r'T(\d{2}:\d{2})', str(x or ''))
                return m.group(1) if m else None
            for datum, row in briefs.items():
                if not isinstance(row, dict) or len(str(datum)) != 10:
                    continue
                try:
                    dd = _date.fromisoformat(datum)
                    if dd > cutoff or dd < today - _td(days=30):
                        continue
                except Exception:
                    continue
                summ = (row.get('ical_summary') or '')
                up = summ.upper()
                klass = 'OFF' if 'OFF DAY' in up else ('Z76' if 'LAYOVER' in up else None)
                # F6: Routing PRIMÄR aus den Pro-Leg-Sektoren bauen (volle Kette
                # ZRH-LIS-ZRH). Der LOCATION-Fallback sah bei SWISS nur die
                # ABFLUG-Airports (LOCATION=Dep-Station je Leg) → verstümmelte
                # Ketten wie „ZRH-BCN" ohne Rückflug-Ziel.
                routing = None
                _secs = row.get('ical_sectors') or []
                if isinstance(_secs, list) and _secs:
                    chain = []
                    for s0 in _secs:
                        if not isinstance(s0, dict):
                            continue
                        s_frm = str(s0.get('from') or '').strip().upper()
                        s_to = str(s0.get('to') or '').strip().upper()
                        if len(s_frm) != 3 or len(s_to) != 3:
                            continue
                        if not chain:
                            chain.append(s_frm)
                        elif chain[-1] != s_frm:
                            chain.append(s_frm)
                        chain.append(s_to)
                    if len(chain) >= 2:
                        routing = '-'.join(chain)
                if not routing:
                    codes = re.findall(r'\b[A-Z]{3}\b', (row.get('ical_location') or '').upper())
                    dedup = []
                    for c in codes:
                        if not dedup or dedup[-1] != c:
                            dedup.append(c)
                    routing = '-'.join(dedup) if len(dedup) >= 2 else None
                out.append({
                    'datum': datum,
                    'klass': klass,
                    'marker': summ or None,
                    'routing': routing,
                    'eur': None,
                    'layover_ort': row.get('ical_layover_ort'),
                    'route_label': _route_label_cities(routing,
                                                       row.get('ical_layover_ort')),
                    'layover_city': (_iata_city_name(row.get('ical_layover_ort'))
                                     if row.get('ical_layover_ort') else None),
                    'start_time': _hhmm(row.get('ical_start_iso') or row.get('ical_start')),
                    'end_time': _hhmm(row.get('ical_end_iso') or row.get('ical_end')),
                    # Pro-Leg-Sektoren aus den Briefings durchreichen (s.o.) → Freunde-/
                    # Familie-Sheet zeigt die echten Legs wie beim Besitzer.
                    'ical_sectors': row.get('ical_sectors'),
                })
            out.sort(key=lambda d: d.get('datum') or '')
        except Exception:
            pass
    # LIVE-/ACTUAL-TIME-ANREICHERUNG (Owner 2026-07-14, Basti-Kalender): Friend-
    # Sektoren brauchen dieselben gemessenen Felder wie der eigene Kalender
    # (status, est_dep/arr, delay, tail), nicht nur das Kennzeichen. Der bestehende
    # Enricher bringt Zeitfenster-Guard, Codeshare-Faltung, Dual-Side-Memo und
    # Tail-Guard bereits mit. `free_only=True` ist hier hart: dieser N-Crew-Fanout
    # darf nie den bezahlten Board-Fallback öffnen. Genau EIN Enricher-Aufruf pro
    # Tages-Sektorliste; kein anschließender `_enrich_leg_tails`-Doppel-Fetch.
    _hb = None   # echte Homebase des FREUNDES (lazy, 10-min-Memo) — Audit 2026-07-05
    for _e in out:
        try:
            _secs = _e.get('ical_sectors')
            if isinstance(_secs, list) and _secs:
                if _hb is None:
                    _hb = _profile_homebase_cached(friend_token) or ''
                # VERGANGENHEITS-HORIZONT (Owner/Fable 2026-07-15): das Freunde-
                # Roster-Sheet zeigt die 30-Tage-Tour-Retention. Der Enrich-
                # Fenster-Guard bleibt für alle anderen Aufrufer bei 30 h, hier
                # aber weit geöffnet, damit die für VORTAGE persistierten Ist-
                # Zeiten (airport_delay_obs) je Leg gelesen werden — statt nackter
                # „Gelandet/Abgeflogen". free_only=True bleibt hart; der Live-
                # Board-Scan bleibt via _flight_obs_merged auf HEUTE begrenzt,
                # nur der datums-gezielte Warehouse-Read erreicht die alten Tage.
                _enrich_leg_delays(_secs, _e.get('datum'), free_only=True,
                                   homebase=(_hb or None),
                                   past_horizon_h=24 * 35)
        except Exception:
            pass
    return jsonify({'ok': True, 'shared': True, 'count': len(out),
                    'days': out,
                    'source': 'snapshot' if tage else 'ical_briefings'})


def _active_sector_flight_numbers(day):
    """Flugnummer des GERADE laufenden Sektors aus day['ical_sectors'] (UTC-
    Zeiten), Fenster dep−15 min … arr+10 min. Leere Liste wenn kein Leg aktiv
    — iOS zeigt „fliegt" dann NICHT (ehrlich: am Boden/Layover). Wirft nie."""
    try:
        secs = (day or {}).get('ical_sectors') or []
        now_utc = datetime.now(timezone.utc)
        out = []
        for s in secs:
            if not isinstance(s, dict):
                continue
            fno = str(s.get('flight') or '').replace(' ', '').upper()
            dep_raw, arr_raw = s.get('dep_iso'), s.get('arr_iso')
            if not (fno and dep_raw and arr_raw):
                continue
            dep = datetime.fromisoformat(str(dep_raw).replace('Z', '+00:00'))
            arr = datetime.fromisoformat(str(arr_raw).replace('Z', '+00:00'))
            if (dep - timedelta(minutes=15)) <= now_utc <= (arr + timedelta(minutes=10)):
                out.append(fno)
        return out
    except Exception:
        return []


def _friends_live_leg_check(fno, frm, to):
    """GRATIS-Gegencheck gegen den aircraft_live-Store (NAS-Harvester/FR24-gRPC)
    für die lay_eff-Kaskade: fliegt die Maschine dieser Flugnummer GERADE
    (route-konsistent, dest == to)?
      'airborne' — nachweislich in der Luft,
      'at_dep'   — am Boden nahe (≤8 km) dem ABFLUG-Flughafen (wartet noch),
      'at_arr'   — am Boden nahe dem ZIEL (echt angekommen),
      None       — kein frischer Snapshot / Position keinem Ende zuordenbar.
    Reiner Supabase/NAS-Read (kein Paid-Spend), wirft nie. Existiert, weil die
    reine Plan-Uhr (ARR-DECKEL arr+30min) einen real verspäteten, obs-losen Leg
    sonst ans Ziel teleportiert, während die Maschine noch fliegt oder gar noch
    am Abflug-Gate steht (Nachfix 2026-07-10)."""
    try:
        from blueprints.aerox_data_blueprint import _aircraft_live_pos, _iata_latlon
        pos, _rt, _rg, _ty = _aircraft_live_pos(flight=fno, dep=to)
        if not pos or pos.get('lat') is None or pos.get('lon') is None:
            return None
        if not pos.get('on_ground'):
            return 'airborne'
        for ap, label in ((frm, 'at_dep'), (to, 'at_arr')):
            try:
                ll = _iata_latlon(ap)
                if ll and _haversine_km(float(pos['lat']), float(pos['lon']),
                                        ll[0], ll[1]) <= 8.0:
                    return label
            except Exception:
                continue
        return None
    except Exception:
        return None


def _friends_obs_provably_stale(merged, frm, to, dep):
    """Beweist eine Board-Obs als VERALTET (Row eines FRÜHEREN Betriebstags)
    über ihre EIGENEN Zeitstempel — statt „kein Delay = stale" als Proxy
    (Boards flippen häufig nur den Status auf delayed/Boarding OHNE est-Zeiten;
    ein echt wartender Flug trägt also NICHT zwingend einen Delay).
    Live verifizierter Root-Cause (Tibor LH1139): die BCN-dep-Row trug ein
    est_dep vom VORTAG. Regel: mindestens ein datierbarer Stempel liegt ≥6 h
    VOR dem Roster-Plan-Abflug (heutige Rows liegen nie so früh — Delays
    schieben nach HINTEN) und KEIN Stempel sieht aktuell aus. Zeit-lose Rows
    (nur „HH:MM"/kein Stempel) sind NICHT beweisbar stale → Pin bleibt (die
    sichere Fehlerrichtung: Crew am Abflughafen). Wirft nie."""
    if not merged or dep is None:
        return False
    saw_old = saw_current = False
    for val, ap in ((merged.get('esti_dep'), frm), (merged.get('sched_dep'), frm),
                    (merged.get('esti_arr'), to), (merged.get('sched_arr'), to)):
        if not val:
            continue
        try:
            iso = _board_local_to_utc_iso(val, ap)
            if not iso:
                continue
            ts = datetime.fromisoformat(iso.replace('Z', '+00:00'))
        except Exception:
            continue
        if ts <= dep - timedelta(hours=6):
            saw_old = True
        else:
            saw_current = True
    return saw_old and not saw_current


_FRIENDS_TODAY_MEMO = {}          # "token|datum" → (expires_monotonic, resp)
_FRIENDS_TODAY_TTL = 90.0         # 90 s: Feed lädt sonst pro Aufruf N×M sequ. Board-Lookups
_FRIENDS_TODAY_WORKER_HEALTH = _req_threading.local()


def _friends_today_worker_health_begin():
    _FRIENDS_TODAY_WORKER_HEALTH.failed = False


def _friends_today_worker_health_fail():
    """Mark the current friend resolver as degraded without leaking identity."""
    _FRIENDS_TODAY_WORKER_HEALTH.failed = True


def _friends_today_worker_health_failed():
    return bool(getattr(_FRIENDS_TODAY_WORKER_HEALTH, 'failed', False))


def _friends_today_response(payload):
    """JSON-Antwort ohne HTTP-/URLCache.

    Der 90-s-Memo oben ist die EINE kontrollierte Frischegrenze. Personalisierte
    Crew-States dürfen nicht zusätzlich in CF-/URLSession-Caches hängen bleiben:
    sonst liefert der 60-s-iOS-Refresh weiter `pre_flight`, obwohl der Server
    schon `flying` kennt (Basti/LH890, 2026-07-14).
    """
    resp = jsonify(payload)
    resp.headers['Cache-Control'] = 'private, no-store, max-age=0'
    return resp


def _friend_briefing_day_sectors(fr, datum):
    """(ical_sectors, imported_at, ical_summary, ical_start_iso) des Tages
    DIREKT aus user_ical_briefings (1 gefilterter SB-Read). Der serverseitige
    Kalender-Refresh (_maybe_refresh_calendar_feed) hält diese Tabelle frisch —
    der push-basierte roster_snapshot kann dahinter STALE sein (Diagnose
    2026-07-10: iCal-Freunde froren auf dem letzten App-Push ein).
    summary/start (ADDITIV 2026-07-12) speisen die PRE-FLIGHT-TIMELINE:
    Summary trägt den Pickup-Token, ical_start den (beim Import via
    _corrected_briefing_start_iso schon LT→UTC-gelösten) Report-Start.
    (None, None, None, None) wenn nichts da / SB down."""
    try:
        if not (SB_AVAILABLE and sb is not None and fr and datum):
            return None, None, None, None
        r = (sb.table('user_ical_briefings')
             .select('datum,updated_at,raw_event,ical_summary,ical_start')
             .eq('token', fr).eq('datum', datum).limit(1).execute())
        rows = getattr(r, 'data', None) or []
        if not rows:
            return None, None, None, None
        row = rows[0]
        ts = str(row.get('updated_at') or '') or None
        summary = str(row.get('ical_summary') or '') or None
        start_iso = str(row.get('ical_start') or '') or None
        raw = row.get('raw_event') or {}
        secs = raw.get('ical_sectors') if isinstance(raw, dict) else None
        if not (isinstance(secs, list) and secs):
            return None, ts, summary, start_iso
        return secs, ts, summary, start_iso
    except Exception:
        _friends_today_worker_health_fail()
        return None, None, None, None


def _crew_pre_flight_ctx(day, secs, brief_summary, brief_start_iso,
                         commute_minutes):
    """PRE-FLIGHT-TIMELINE-Bausteine (Owner 2026-07-12) für den Resolver —
    NUR echte Quellen, fehlt ein Baustein bleibt sein Feld None und der
    Resolver überspringt die Phase (nie geratene Zeiten):
      pickup:  aus dem Roh-iCal-Summary geparst (crew_live_state.
               parse_pickup_hhmm = Server-Nachbau der iOS-Referenz-Regexe
               RosterLabels.pickupTimeFromSummary); die HH:MM ist Ortszeit an
               der Station des ERSTEN Abflugs (dort steht das Hotel) → UTC via
               airport_tz (FRA/EDDF-Fallback Europe/Berlin wie überall).
      report:  Briefing-/Report-Start des Tages — user_ical_briefings.
               ical_start (beim Import via _corrected_briefing_start_iso
               schon LT→UTC + Default-genullt) bzw. Snapshot ical_start_iso.
      commute_minutes: vom Crew-Mitglied SELBST angegebene Fahrzeit
               Wohnung→Flughafen (Profil-Feld, s. put_user_profile).
    Wirft nie; None wenn gar kein Baustein da ist."""
    try:
        from blueprints.crew_live_state import (parse_pickup_hhmm,
                                                pickup_utc_for_leg)
        day = day or {}
        first = None
        for s in (secs or []):
            if isinstance(s, dict) and s.get('dep_iso'):
                if first is None or str(s.get('dep_iso')) < str(first.get('dep_iso')):
                    first = s
        pickup = None
        if first is not None:
            for src in (brief_summary, day.get('marker'),
                        day.get('ical_summary')):
                hm = parse_pickup_hhmm(src)
                if not hm:
                    continue
                st = str(first.get('from') or '').strip().upper()
                tzname = airport_tz(st) or (
                    'Europe/Berlin' if st in ('FRA', 'EDDF') else None)
                pickup = pickup_utc_for_leg(hm, first.get('dep_iso'), tzname)
                break
        report = brief_start_iso or day.get('ical_start_iso') or None
        cm = None
        try:
            cm = int(commute_minutes)
            if not (0 < cm <= 360):
                cm = None
        except (TypeError, ValueError):
            cm = None
        if pickup is None and not report and cm is None:
            return None
        return {'pickup': pickup, 'report': report, 'commute_minutes': cm}
    except Exception:
        return None


def _crew_state_for_day(fr, day, datum, homebase=None, snap_ts=None,
                        commute_minutes=None, obs_lookup=None,
                        live_lookup=None, carry_sectors=None,
                        carry_datum=None):
    """Additives `crew_state`-Feld für friends-today — EINE Wahrheit über den
    Neubau-Resolver blueprints/crew_live_state (Owner 2026-07-10: „baue es
    komplett neu auf damit es funktioniert, auch Text"). iOS zeigt text.title/
    subtitle 1:1, kein lokales Raten mehr. Frisches Briefing SCHLÄGT stalen
    Snapshot (pick_fresher_sectors). free-first: Board-Obs free_only=True,
    Live-Gegencheck = reiner aircraft_live-Read. None bei jedem Fehler —
    Altfelder bleiben unverändert stehen.
    commute_minutes (ADDITIV 2026-07-12): selbst angegebene Fahrzeit des
    Freundes (Profil) → PRE-FLIGHT-TIMELINE-Phase „Fahrt zum Flughafen".
    obs_lookup/live_lookup (ADDITIV 2026-07-13, Latenz-Hebel): die geteilten
    Lookup-Closures pro Request EINMAL bauen und hier reinreichen, statt sie
    bei jedem der bis zu 3 crew_state-Läufe pro Freund neu zu bauen. Beide
    schließen NUR über gecachte/memoisierte Leaf-Reads (_flight_obs_merged /
    _aircraft_live_pos) und sind zustandslos → thread-safe teilbar. None =
    Rückfall auf frisch gebaute Lookups (Alt-Callsites/Tests).
    carry_sectors (ADDITIV 2026-07-16, Julien/Tibor-Overnight-Carry): schon
    ausgewählte, noch aktive Legs des VORTAGS (crew_live_state.carry_over_legs)
    — sie werden VOR die heutigen Sektoren in DENSELBEN Resolver gereicht, damit
    ein Über-Nacht-Leg (dep gestern 22:15Z, arr heute 06:00Z, keyt auf dem
    Abflugtag) nach Berliner Mitternacht nicht als `home`/„Basis" verschwindet,
    sondern ganz normal durch Leg-Auswahl + Engine + Wrong-Day-Guards läuft
    (enroute/landed je nach Obs/Zeit-Physik). None/leer = altes Verhalten."""
    try:
        from blueprints.crew_live_state import (resolve_crew_live_state,
                                                pick_fresher_sectors,
                                                duty_from_roster_day,
                                                build_obs_lookup,
                                                build_live_lookup,
                                                build_local_hhmm)
        from blueprints.aerox_data_blueprint import _iata_city_name
        day = day or {}
        snap_secs = [s for s in (day.get('ical_sectors') or [])
                     if isinstance(s, dict)]
        b_secs, b_ts, b_summary, b_start_iso = \
            _friend_briefing_day_sectors(fr, datum)
        secs, _src = pick_fresher_sectors(snap_secs, snap_ts, b_secs, b_ts)
        # OVERNIGHT-CARRY (Julien/Tibor 2026-07-16): die noch aktiven Vortags-
        # Legs VOR die heutigen Sektoren mergen. Der Resolver sortiert intern
        # nach dep (_norm_legs) → der Über-Nacht-Leg wird als aktuelles Leg
        # gepickt und ganz normal bewertet (enroute/landed). Doppelte Flug-
        # nummern (derselbe Leg auch heute gekeyt) werden entfernt — der heutige
        # Eintrag ist frischer/maßgeblich. Wirft nie (Liste ist schon gefiltert).
        _carry_fns = set()
        if carry_sectors:
            try:
                _today = secs or []
                _today_fns = {str(s.get('flight') or '').replace(' ', '').upper()
                              for s in _today
                              if isinstance(s, dict) and s.get('flight')}
                _carry = [s for s in carry_sectors
                          if isinstance(s, dict)
                          and str(s.get('flight') or '').replace(' ', '').upper()
                          not in _today_fns]
                if _carry:
                    secs = _carry + list(_today)
                    _carry_fns = {str(s.get('flight') or '').replace(' ', '').upper()
                                  for s in _carry if s.get('flight')}
            except Exception:
                _carry_fns = set()
        rf = day.get('reader_facts') or {}
        # duty für Leg-lose Tage: Standby > Urlaub > Frei (B2 2026-07-12 —
        # der Resolver soll den SERVER-Text „Heute frei"/„Im Urlaub" liefern,
        # exakt die klass-Tokens, die iOS bisher LOKAL erkannte; sonst zeigte
        # jede Fläche einen anderen Text für dieselbe Person). Ableitung als
        # GETEILTE Funktion neben dem Resolver (Regressions-Sweep 2026-07-12
        # #7): family_watch nutzt dieselbe — vorher divergierte Family
        # („Basis X") vom Crew-Feed („Heute frei") für dieselbe Person.
        duty = duty_from_roster_day(day.get('klass'), day.get('marker'))
        # Geteilte Lookups (Latenz-Hebel 2026-07-13): obs_lookup ist an `datum`
        # gebunden (Spillover/Next-Läufe reichen KEINE fremde weiter → dort
        # None), live_lookup ist datums-unabhängig und wird pro Request EINMAL
        # gebaut. None ⇒ frisch bauen (Alt-Callsites/Tests).
        _obs_lk = obs_lookup or build_obs_lookup(_flight_obs_merged, datum)
        _live_lk = live_lookup or build_live_lookup()
        # DATUMS-DISPATCH für CARRY-Legs (Julien/Tibor 2026-07-16): der geteilte
        # obs_lookup ist an HEUTE gebunden. Ein carried Vortags-Leg (LH423 auf
        # dem 15.) darf NICHT die HEUTIGE Instanz derselben täglichen Flugnummer
        # (16., Abflug erst am Abend, „Scheduled") sehen — die würde ihn erneut
        # auf pre_flight pinnen (der Wrong-Day-Guard greift NICHT, weil deren arr
        # nach dem carried dep liegt). Für carried Flugnummern deshalb einen
        # eigenen, an das VORTAGS-Datum gebundenen Lookup nutzen; alles andere
        # bleibt am heutigen Lookup. Ohne carry_datum/carry-Legs exakt _obs_lk.
        if _carry_fns and carry_datum:
            _carry_obs_lk = build_obs_lookup(_flight_obs_merged, carry_datum)

            def _obs_dispatch(flight_no, dep_iata, arr_iata,
                              _today_lk=_obs_lk, _y_lk=_carry_obs_lk,
                              _cfns=_carry_fns):
                _fn = str(flight_no or '').replace(' ', '').upper()
                lk = _y_lk if _fn in _cfns else _today_lk
                return lk(flight_no, dep_iata, arr_iata)
            _obs_lk = _obs_dispatch
        cs = resolve_crew_live_state(
            secs or [],
            _obs_lk,
            _live_lk,
            datetime.now(timezone.utc),
            homebase=homebase,
            # Geplanter Nightstop = letzte Tages-Ankunft außerhalb der Homebase
            # (nicht blind reader_facts.layover_ort → Turnaround-Tage trugen
            # einen Vortags-Wert; Same-Day-Heimkehr = kein Layover).
            layover_iata=_feed_nightstop_ort(day, homebase=homebase),
            duty=duty,
            city_lookup=_iata_city_name,
            local_hhmm=build_local_hhmm(airport_tz),
            status_bucket=_flight_status_bucket,
            pre_ctx=_crew_pre_flight_ctx(day, secs, b_summary, b_start_iso,
                                         commute_minutes))
        # Museums-Wächter (2026-07-12, Jennifer/LH781): Board-obs liefern
        # ausgemusterte Regs (Fraport, D-ABTL) — der Resolver hängt o['reg']
        # ungeprüft an current_leg. Eine tote Reg vergiftet iOS-Reg-Lookups
        # (Crew-Tap-Radar-Fokus, Live-Karten-Upgrade) → Karte stirbt still.
        # Gleiche Regel wie überall: lieber reg=None als eine Museums-Reg.
        try:
            _leg = (cs or {}).get('current_leg') or {}
            if _leg.get('reg') and not _tail_recently_active(_leg['reg']):
                _leg['reg'] = None
        except Exception:
            pass
        return cs
    except Exception as e:
        _friends_today_worker_health_fail()
        app.logger.info(f'[friends-today] crew_state_skip {type(e).__name__}')
        return None


@app.route('/api/user/friends-today/<token>', methods=['GET'])
def get_friends_today(token):
    """OffBlock-Pattern: Was machen meine Friends HEUTE (oder an gegebenem Datum).
    Query: ?datum=YYYY-MM-DD (default today)
    """
    from datetime import date as _date
    import time as _time
    from blueprints.aerox_data_blueprint import (_route_label_cities, _iata_city_name,
                                                 _aircraft_live_pos)
    # TZ-Fix (Sweep J7 2026-07-10): Default-„heute" = Berliner Betriebstag
    # (die Roster-`datum`-Keys sind Homebase-Tage), NICHT Server-UTC — zwischen
    # 00:00–02:00 CEST zeigte der UTC-Default sonst den Vortag und der 90s-Memo
    # zementierte ihn. Kein iOS-Callsite schickt datum mit.
    # Der Berliner „heute"-Anker wird auch für die Live-Gates unten gebraucht
    # (Audit B3 2026-07-12): die verglichen bisher gegen _date.today() (Server-
    # UTC) — zwischen 00:00–02:00 CEST war datum (Berlin) schon der neue Tag,
    # die Gates aber noch auf dem UTC-Vortag → keine Live-Beobachtungen/kein
    # crew_state. EINE Quelle für Default UND Vergleich.
    try:
        _heute_berlin = _airport_local_now('FRA').strftime('%Y-%m-%d')
    except Exception:
        _heute_berlin = _date.today().isoformat()
    datum = request.args.get('datum') or _heute_berlin
    # TTL-Cache (Owner 2026-07-09 „warum dauert Wo-ist-Crew immer so lange"): die
    # Sektor-Kaskade unten macht pro Freund × Sektor sequenzielle _flight_obs_merged-
    # Board-Lookups + Kalender-Refresh — jedes Feed-Laden neu = langsam. 90 s cachen.
    _ck = f"{token}|{datum}"
    _now_m = _time.monotonic()
    _hit = _FRIENDS_TODAY_MEMO.get(_ck)
    if _hit and _hit[0] > _now_m:
        return _friends_today_response(_hit[1])
    data = _friends_load(token)
    friends = data.get('friends') or []
    out = []
    # N+1-Fix (2026-07-01): Friend-Profile in EINEM Bulk-Query (SB-primary
    # wie get_user_friends; Disk-Datei ist auf Cloud Run ephemer).
    _bulk_profs = _profiles_load_bulk(friends)

    # LATENZ-HEBEL 1 PARALLELISIEREN (Owner 2026-07-13, „warum dauert
    # friends-today kalt 5–9 s"): die Pro-Freund-Arbeit (crew_state ×3 +
    # flights_live + Positions-Kaskade, alles serielle Supabase-Roundtrips)
    # ist zwischen Freunden UNABHÄNGIG → über einen ThreadPoolExecutor
    # gleichzeitig laufen lassen (Muster wie das flight-detail-Aggregat
    # ax_flight_detail). Wall-Clock ≈ der langsamste Freund statt der SUMME.
    #   • current_app existiert in Worker-Threads NICHT → das konkrete
    #     App-Objekt reinreichen; jeder Worker pusht via test_request_context
    #     seinen eigenen App-+Request-Kontext (Flask-Kontexte sind thread-local).
    #   • Reihenfolge MUSS die ursprüngliche Friend-Reihenfolge bleiben (iOS
    #     matcht über match_id, aber der Golden pinnt die Liste) → Ergebnisse
    #     mit ihrem Index gesammelt und danach exakt so sortiert.
    # HEBEL 2 GETEILTE LOOKUPS: live_lookup ist datums-unabhängig und wird
    # hier EINMAL gebaut (statt bei jedem der bis zu 3 crew_state-Läufe pro
    # Freund neu); der obs_lookup für HEUTE ebenso. Beide schließen nur über
    # die 90-s-memoisierten Leaf-Reads (_flight_obs_merged / _aircraft_live_pos)
    # → gleiche Flüge über mehrere Freunde = EIN Read, thread-safe geteilt.
    from concurrent.futures import ThreadPoolExecutor, as_completed
    from flask import current_app as _cur_app
    _app_obj = _cur_app._get_current_object()
    try:
        from blueprints.crew_live_state import (build_obs_lookup as _bol,
                                                build_live_lookup as _bll)
        _shared_live_lk = _bll()
        _shared_obs_lk_today = _bol(_flight_obs_merged, datum)
    except Exception:
        _shared_live_lk = None
        _shared_obs_lk_today = None

    # Kalender-Refresh bleibt im MAIN-Thread (liest request.host/-headers zum
    # Bauen der Self-Call-URL — im synthetischen Worker-Request-Kontext wären
    # die leer; die Funktion ist ohnehin ≥3h gedrosselt und spawnt den Fetch
    # selbst als Daemon-Thread, kehrt also sofort zurück).
    for fr in friends:
        _maybe_refresh_calendar_feed(fr)

    def _process_friend(_idx, fr):
        """Die komplette Pro-Freund-Arbeit — läuft im Worker-Thread mit
        gepushtem App-+Request-Kontext des ECHTEN App-Objekts. Gibt
        (idx, entry|None) zurück; None = Freund fällt raus (kein Roster-Tag
        / share_roster aus), exakt wie das frühere `continue`."""
        sess = _store.get(fr) or {}
        rd = sess.get('result_data') or {}
        tage = rd.get('_tage_detail') or []
        _snap_ts = None   # taken_at des Snapshots (Frische-Vergleich crew_state)
        if not tage:
            # _store ist in-memory/per-Instanz — persistenter Snapshot-Fallback
            # (Muster wie get_friend_roster ~11430), sonst war „Friends heute"
            # nach Container-Restart/anderer Instanz immer leer (2026-07-01).
            _snap = _roster_snapshot_read(fr) or {}
            tage = _snap.get('tage') or []
            _snap_ts = _snap.get('taken_at')
        else:
            # Nachfix 2026-07-10: auch der In-Memory-Pfad braucht einen Frische-
            # Timestamp. Mit snap_ts=None ließ pick_fresher_sectors JEDES
            # Briefing gewinnen (updated_at ist NOT NULL → b_ts nie None) —
            # auch ein wochenaltes (kaputte Feed-URL im Backoff) gegen frisch
            # gepushte In-Memory-Daten. taken_at des persistenten Snapshots ist
            # der beste verfügbare Proxy: er wird von derselben Auswertung
            # (app.py ~3837) bzw. jedem Roster-Push (take_roster_snapshot)
            # mitgeschrieben. Fehlt der Snapshot ganz, bleibt None →
            # Briefing-Vorrang wie dokumentiert.
            _snap_ts = (_roster_snapshot_read(fr) or {}).get('taken_at')
        day = next((t for t in tage if isinstance(t, dict) and t.get('datum') == datum), None)
        if not day: return (_idx, None)
        pr = _bulk_profs.get(fr) or {}
        # PRIVACY-FIX (Bug-Hunt): Friend mit share_roster=False NICHT zeigen —
        # vorher wurde sein voller Tagesplan (Marker/Routing/Layover/Zeiten/Flug-
        # nummern) trotz Opt-out durchgereicht. Spiegelt get_friend_roster.
        if pr.get('share_roster') is False:
            return (_idx, None)
        rf = day.get('reader_facts') or {}
        # WO IST DIE CREW JETZT (2026-07-04): rf['layover_ort'] ist der Über-
        # nachtungsort NACH dem heutigen Dienst. Morgens VOR dem ersten Abflug
        # steht die Crew aber noch am GESTRIGEN Übernachtungsort — das ist der
        # Abflughafen des ersten heutigen Sektors (ical_sectors[0].from, UTC-
        # Zeiten aus dem Snapshot). Sonst zeigte der Feed z.B. „Tirana", während
        # der Freund noch in Billund frühstückt. Nur fürs heutige Datum, nur mit
        # klarer dep_iso, und nur wenn der erste Abflug NICHT die Homebase ist
        # (an der Basis bleibt die bisherige Basis-Anzeige korrekt).
        # BASIS: der GEPLANTE Übernachtungsort. Bevorzugt die letzte Tages-
        # Ankunft, die als echte Übernachtung außerhalb der Homebase gilt
        # (_feed_nightstop_ort mit Homebase-Gate) — reines reader_facts.
        # layover_ort trug bei Multi-Leg-Turnaround-Tagen einen Vortags-/
        # Kontext-Wert (Florian 2026-07-16: BER statt FCO). Ein Same-Day-
        # Turnaround ZURÜCK zur Homebase bleibt korrekt ohne Layover (None) →
        # die Live-Kaskade unten pinnt „unterwegs"/Position, kein Basis-Ort.
        _friend_hb = (pr.get('homebase') or '').strip().upper() or None
        lay_eff = _feed_nightstop_ort(day, homebase=_friend_hb)
        try:
            if datum == _heute_berlin:
                secs = [s for s in (day.get('ical_sectors') or [])
                        if isinstance(s, dict) and s.get('dep_iso')]
                # HOMEBASE-FALL (Owner 2026-07-07, Sebastian „Dienstplan
                # sagt FRA, Wo-ist sagt Oslo, WARUM kein Live-Flieger?"):
                # dieselbe Signal-Kaskade gilt auch für Homebase-Abflüge.
                # ECHTER-STATUS-KASKADE (Owner 2026-07-04, Tibor: Flug
                # spät → er steht real noch am Abflughafen [BLL], die App
                # zeigte ihn schon weiter, nur weil die PLAN-Abflugzeit
                # vorbei war). Signal-getrieben statt Uhr-getrieben:
                #   • noch NICHT abgeflogen (grounded/cancelled/Delay-Pin
                #     ODER kein Signal & innerhalb 4h nach Plan) → Crew ist
                #     am Abflughafen dieses Legs,
                #   • AIRBORNE → unterwegs, geplanten Layover BEHALTEN,
                #   • LANDED → weiter zum Ziel DIESES Legs — und dann den
                #     NÄCHSTEN Sektor prüfen.
                # MULTI-SEKTOR-FIX (Owner 2026-07-07, Sebastian OSL-FRA-RIX:
                # Feed zeigte ihn den ganzen Nachmittag in FRA statt im
                # RIX-Layover): vorher stoppte die Kaskade nach dem ERSTEN
                # Sektor — „Leg 1 gelandet ⇒ lay_eff = FRA" und die
                # Folge-Legs (FRA→RIX, längst gelandet) wurden nie
                # angesehen. Jetzt läuft die Kaskade die heutigen Sektoren
                # der Reihe nach ab, bis ein Leg NICHT als geflogen gilt.
                pos = None
                observed_end = False   # letztes „geflogen" war ECHTE Board-Obs?
                for sec in secs:
                    dep = datetime.fromisoformat(
                        str(sec['dep_iso']).replace('Z', '+00:00'))
                    # PLAN-ANKUNFT dieses Sektors (TIBOR-LIVEFALL 2026-07-10,
                    # LH1139 BCN→FRA 06:40–08:55): die Kaskade kannte bisher
                    # NUR dep_iso — der zeitlich AKTUELLE Leg braucht aber
                    # beide Enden (dep_iso ≤ now < arr_iso+Puffer). arr_iso
                    # fehlt bei manchen Roster-Quellen → None = altes
                    # Verhalten, kein erfundenes Ende.
                    arr_dt = None
                    try:
                        if sec.get('arr_iso'):
                            arr_dt = datetime.fromisoformat(
                                str(sec['arr_iso']).replace('Z', '+00:00'))
                    except Exception:
                        arr_dt = None
                    # PLAUSI-GUARD (Nachfix 2026-07-10): korruptes/Red-Eye-
                    # arr_iso ≤ dep_iso (Roster-Reader-Macke: Red-Eye-Ankunft
                    # ohne end_iso fällt auf den Abflugtag) machte _grace_end
                    # < dep — der Leg galt als GEFLOGEN, bevor er überhaupt
                    # abgeflogen war, und entschärfte zusätzlich den Branch-4-
                    # Pin. Ein Flug landet IMMER nach seinem Abflug →
                    # unplausibles Ende verwerfen (= altes dep+4h-Verhalten).
                    if arr_dt is not None and arr_dt <= dep:
                        arr_dt = None
                    frm = str(sec.get('from') or '').strip().upper()
                    to = str(sec.get('to') or '').strip().upper()
                    if not (len(frm) == 3 and frm.isalpha()):
                        break
                    merged = None
                    try:
                        fno = _fn_norm(sec.get('flight'))
                        if fno and len(fno) >= 3:
                            merged = _flight_obs_merged(
                                fno, date=datum, dep_iata=frm,
                                arr_iata=(to if (len(to) == 3 and to.isalpha())
                                          else None),
                                free_only=True, live=False)
                    except Exception:
                        merged = None
                    bucket = (_flight_status_bucket(merged.get('status'))
                              if merged else None)
                    # Bekannter Abflug-Delay OHNE bucketbaren Status
                    # (status=None, sehr HÄUFIG) — Tibor BLL→FRA: verspätet,
                    # aber noch nicht abgeflogen. Ohne diese Kopplung fiel der
                    # Fall in den 4h-Uhr-Zweig → Crew fälschlich am Layover.
                    delay_pin = bool(
                        merged and merged.get('delay_known')
                        and int(merged.get('dep_delay_min') or 0) > 0)
                    # STALE-KAPPE (Sebastian LH890, 2026-07-07): eine reine
                    # Delay-Beobachtung OHNE Board-Status („minor", dep_delay 30)
                    # bekommt oft NIE einen Terminal-Status — der Pin gälte sonst
                    # EWIG und die Crew klebte nach dem längst erfolgten Abflug
                    # am Boden. Nach der delay-korrigierten Ist-Abflugzeit
                    # (Plan + bekannter Delay) + 45 min Puffer ist das Signal
                    # stale → Pin fällt, der Uhr-Zweig (5) entscheidet. Ein ECHT
                    # noch wartender Flug bekommt laufend neue Obs (Delay wächst
                    # → eff_dep wandert mit). Ein ECHTES `grounded`-Board-Signal
                    # bleibt dagegen Ewig-Pin (Owner 2026-07-04: „unabhängig von
                    # der Uhr, auch bei starker Verspätung").
                    if delay_pin:
                        eff_dep = dep + timedelta(
                            minutes=max(0, int(merged.get('dep_delay_min') or 0)))
                        if datetime.now(timezone.utc) >= eff_dep + timedelta(minutes=45):
                            delay_pin = False
                    if merged and merged.get('cancelled'):
                        # (1) Annulliert schlägt ALLES: Crew ist nie
                        # losgeflogen → bleibt am Abflughafen.
                        pos = frm
                        break
                    elif merged and bucket == 'landed':
                        # (2) Leg gelandet → Crew ist (mindestens) am Ziel
                        # dieses Legs. Nächsten Sektor prüfen.
                        if len(to) == 3 and to.isalpha():
                            pos = to
                        observed_end = True
                        continue
                    elif merged and bucket == 'airborne':
                        # (3) Unterwegs → geplanten Layover behalten (der
                        # Feed zeigt „unterwegs nach X" via flight_numbers).
                        pos = None
                        break
                    elif (merged and bucket == 'grounded') or delay_pin:
                        # (4) Echtes Signal „noch nicht abgeflogen" → Crew
                        # ist am Abflughafen dieses Legs, egal wie spät.
                        # STALE-GROUNDED-KAPPE v2 (Tibor LH1139 BCN→FRA,
                        # 2026-07-10 ~09:30: Feed klebte auf „unterwegs nach
                        # Barcelona", obwohl der Leg 08:55 gelandet war —
                        # gestrige AENA-„Boarding"-Row derselben Flugnummer,
                        # live verifiziert: die BCN-dep-Row trug est_dep vom
                        # VORTAG). v1 nahm „kein quantifizierter Delay" als
                        # Stale-Beweis — Boards flippen aber häufig NUR den
                        # Status (delayed/Boarding) OHNE est-Zeiten: ein ECHT
                        # noch wartender Flug wäre ab arr+30min ans Ziel
                        # teleportiert worden. Jetzt entscheidet (a) der
                        # GRATIS aircraft_live-Gegencheck und (b) die
                        # Staleness der Obs SELBST (est/sched-Stempel eines
                        # FRÜHEREN Betriebstags). Unbeweisbar stale ⇒ der
                        # Ewig-Pin (Owner 2026-07-04 „unabhängig von der
                        # Uhr") bleibt — die sichere Fehlerrichtung.
                        if (arr_dt is not None and not delay_pin
                                and datetime.now(timezone.utc)
                                >= arr_dt + timedelta(minutes=30)):
                            _lv = _friends_live_leg_check(fno, frm, to)
                            if _lv == 'airborne':
                                # Maschine fliegt NACHWEISLICH → Board-Row
                                # stale; wie Zweig (3): unterwegs, geplanten
                                # Layover behalten.
                                pos = None
                                break
                            if _lv == 'at_arr':
                                # Echt am Ziel gelandet (Live-Beobachtung).
                                if len(to) == 3 and to.isalpha():
                                    pos = to
                                observed_end = True
                                continue
                            if (_lv != 'at_dep'
                                    and _friends_obs_provably_stale(
                                        merged, frm, to, dep)):
                                if len(to) == 3 and to.isalpha():
                                    pos = to
                                observed_end = False
                                continue
                        pos = frm
                        break
                    else:
                        # (5) Kein Signal → 4h-Grace: bis 4h nach Plan-
                        # Abflug gilt die Crew als (noch) am Abflughafen;
                        # danach Plan-Annahme „geflogen" → weiter zum Ziel
                        # und den nächsten Sektor prüfen (sonst bliebe ein
                        # obs-loser Zwischenstopp für immer kleben).
                        # ARR-DECKEL (Tibor LH1139 BCN→FRA 2026-07-10): die
                        # reine dep+4h-Grace pinnte die Crew bei Kurzstrecken
                        # noch STUNDEN nach der Plan-Landung an den Abflug-
                        # hafen (BCN dep 06:40 → Grace bis 10:40, obwohl arr
                        # 08:55 — um 09:30 stand „unterwegs nach Barcelona"
                        # statt „in Frankfurt"). Der zeitlich aktuelle Leg
                        # endet an SEINER Plan-Ankunft: ohne Gegenteils-
                        # Signal gilt er ab arr+30min als geflogen.
                        _grace_end = dep + timedelta(hours=4)
                        if arr_dt is not None:
                            _grace_end = min(_grace_end,
                                             arr_dt + timedelta(minutes=30))
                        if datetime.now(timezone.utc) < _grace_end:
                            pos = frm
                            break
                        # GEISTER-SCHUTZ (Nachfix 2026-07-10): der ARR-DECKEL
                        # kippte einen obs-losen Leg (typisch Outstation-
                        # Abflug: nur DE/EU-Hubs geharvestet → kein Board)
                        # ab arr+30min BLIND auf „geflogen" — bei realem,
                        # unbeobachtetem Delay >30min zeigte der Feed die
                        # Crew am Ziel, während die Maschine noch flog oder
                        # noch am Abflug-Gate stand. Vor dem Plan-Flip den
                        # GRATIS aircraft_live-Store fragen (existiert genau
                        # dafür): airborne → ehrlich „unterwegs" (geplanten
                        # Layover behalten, wie Zweig 3); am Boden nahe dem
                        # ABFLUG-Flughafen → Pin bleibt. Nur ohne Gegenbeweis
                        # gilt die Plan-Annahme (kein erfundener Ort).
                        if arr_dt is not None:
                            _lv = _friends_live_leg_check(fno, frm, to)
                            if _lv == 'airborne':
                                pos = None
                                break
                            if _lv == 'at_dep':
                                pos = frm
                                break
                        if len(to) == 3 and to.isalpha():
                            pos = to
                        observed_end = False
                        continue
                else:
                    # Kein break: alle heutigen Legs gelten als geflogen.
                    # Endete der Tag mit einer ECHTEN Landungs-Beobachtung,
                    # zählt deren Ziel (Board schlägt Plan). Ohne Obs (reine
                    # Plan-Annahme nach Grace) zählt der GEPLANTE Über-
                    # nachtungsort (letzte Tages-Ankunft) — kein erfundener Ort.
                    if not observed_end and lay_eff:
                        pos = None
                if pos:
                    lay_eff = pos
        except Exception:
            lay_eff = _feed_nightstop_ort(day, homebase=_friend_hb)
        # Privacy-Gate: share_location=False (bool) oder =0 (legacy int) → kein city.
        share_loc_val = pr.get('share_location', True)
        share_loc = share_loc_val is not False and share_loc_val != 0
        # LIVE-ANREICHERUNG (Owner 2026-07-03 „alle Live-Sachen anbinden"): pro
        # Tages-Leg Delay/Status/Cancelled aus dem zentralen Dual-Side-Resolver
        # (Board+Warehouse BEIDER Seiten). free_only=True — Fan-out über viele
        # Friends darf keinen AeroDataBox-Spend auslösen; Resolver ist memoisiert
        # (gleiche Flüge über mehrere Reader = ein Lookup). Nur wenn sich die
        # Flugnummern sauber den Routing-Legs zuordnen lassen (ehrlich, kein
        # Raten). Leere Liste = keine Live-Daten, iOS zeigt wie bisher.
        # NUR für den HEUTIGEN Betriebstag (Guard 2026-07-03): für ein
        # Vergangenheits-datum ist „live" sinnlos und jeder Resolver-Miss
        # löste ungecachte airport_delay_obs-SB-Reads aus — bei bis zu
        # 4 Legs × 2 Seiten × N Friends pro Request.
        flights_live = []
        try:
            fns = [str(f).replace(' ', '').upper()
                   for f in (rf.get('flight_numbers') or []) if str(f or '').strip()]
            chain = [c for c in (day.get('routing') or '').upper().split('-')
                     if len(c) == 3 and c.isalpha()]
            # Leg-Liste (fno, from, to): primaer reader_facts+chain (Tax-Pfad),
            # sonst DIREKT aus ical_sectors — reine iCal-Freunde (Tibor!) hatten
            # fns=None -> flights_live blieb strukturell IMMER leer und iOS fiel
            # trotz airborne Leg auf "Basis" zurueck (Diagnose 2026-07-10).
            # 4-Tupel (fno, from, to, dep_iso): dep_iso = Soll-Abflug DIESES Legs
            # (echt-UTC, aus ical_sectors) → Wrong-Day-Physik-Gate unten. Aus dem
            # Tax-Pfad (fns+chain, keine ical-Zeiten) bleibt dep_iso None (Gate
            # fail-open, wie bisher).
            _legs_fl = []
            if fns and len(chain) >= 2 and len(fns) == len(chain) - 1:
                # dep_iso je Leg best-effort aus den ical_sectors nach (fno,from,to)
                # nachschlagen — der Tax-Pfad kennt die Zeiten sonst nicht.
                _sec_dep_iso = {}
                for _sec in (day.get('ical_sectors') or []):
                    _sfn = (_sec.get('flight') or _sec.get('flight_no') or '') \
                        .replace(' ', '').upper().strip()
                    _sfr = (_sec.get('from') or _sec.get('dep') or '').strip().upper()
                    _sto = (_sec.get('to') or _sec.get('arr') or '').strip().upper()
                    _sdi = (_sec.get('dep_iso') or '').strip()
                    if _sfn and _sfr and _sto and _sdi:
                        _sec_dep_iso.setdefault((_sfn, _sfr, _sto), _sdi)
                _legs_fl = [(fno, chain[i], chain[i + 1],
                             _sec_dep_iso.get((fno.replace(' ', '').upper(),
                                               chain[i], chain[i + 1])))
                            for i, fno in enumerate(fns[:4])]
            else:
                for _sec in (day.get('ical_sectors') or [])[:4]:
                    _fn = (_sec.get('flight') or _sec.get('flight_no') or '').strip()
                    _fr = (_sec.get('from') or _sec.get('dep') or '').strip().upper()
                    _to = (_sec.get('to') or _sec.get('arr') or '').strip().upper()
                    if _fn and len(_fr) == 3 and len(_to) == 3:
                        _legs_fl.append((_fn, _fr, _to, (_sec.get('dep_iso') or '').strip() or None))
            if datum == _heute_berlin and _legs_fl:
                for idx, (fno, _dep_ia, _arr_ia, _leg_dep_iso) in enumerate(_legs_fl):
                    m = _flight_obs_merged(fno, date=datum,
                                           dep_iata=_dep_ia,
                                           arr_iata=_arr_ia,
                                           free_only=True, live=False)
                    # WRONG-DAY-PHYSIK-GATE (Owner/Fable 2026-07-15, Rest-Leck der
                    # crew_state-Klasse): _flight_obs_merged matcht täglich fliegende
                    # Flugnummern (LH423 BOS→FRA) datums-agnostisch und liefert bei
                    # einem Über-Nacht-Rückleg (dep HEUTE abends, arr MORGEN) die
                    # GESTRIGE Tages-Instanz, die längst in FRA gelandet ist. Die trug
                    # `status=LANDED` in flights_live[0] — für ALLE Freunde, obwohl der
                    # crew_state korrekt pre_flight sagte (der Resolver gatet via
                    # crew_live_state._obs_is_wrong_day, dieses parallele Array bislang
                    # NICHT). Dieselbe physikalische Schranke: liegt die beobachtete
                    # Ankunft VOR dem Soll-Abflug DIESES Legs (minus Marge), ist es ein
                    # Fremd-Tag-Match → verwerfen (kein Eintrag, iOS fällt auf den
                    # crew_state-Zustand zurück). Fail-open ohne dep_iso/ohne Ankunft.
                    if m and _flights_live_obs_wrong_day(m, _leg_dep_iso, _arr_ia):
                        m = None
                    if m:
                        # ECHTE Live-Position dieses Legs aus dem NAS-Harvester-Store
                        # (aircraft_live/FR24-gRPC) — reale Süd-Route (LH meidet
                        # Russland!). Owner 2026-07-09: Crew wurde sonst per Großkreis
                        # ÜBER RUSSLAND simuliert (Basti/Miguel falsch). None ⇒ iOS
                        # simuliert wie bisher. Endpoint ist gecacht → 1 Read/90s/Leg.
                        _clp = None
                        _cp = _cr = _crg = _cty = None
                        try:
                            _cp, _cr, _crg, _cty = _aircraft_live_pos(
                                flight=fno, dep=_arr_ia)
                            if _cp and not _cp.get('on_ground'):
                                _clp = {'lat': _cp.get('lat'), 'lon': _cp.get('lon'),
                                        'track': _cp.get('track'), 'gs': _cp.get('gs'),
                                        'alt': _cp.get('alt'), 'on_ground': False}
                        except Exception:
                            _clp = None
                        # est_*/sched_*: Board-Zeiten stehen in STATIONS-Ortszeit
                        # (dep mit airport_tz(from), arr mit airport_tz(to)) → hier
                        # genau EINMAL nach echt-UTC (…Z) wandeln, damit iOS sie wie
                        # dep_iso durch den station-lokalen Formatter schickt OHNE
                        # Doppelverschiebung. None wenn keine Zeit / TZ unbekannt —
                        # nie ein naiver String. Aus diesen effDep/effArr baut iOS
                        # die Großkreis-Progress-Interpolation der fliegenden Crew.
                        flights_live.append({
                            'flight': fno,
                            'dep_iata': _dep_ia, 'arr_iata': _arr_ia,
                            'dep_delay_min': m.get('dep_delay_min'),
                            'arr_delay_min': m.get('arr_delay_min'),
                            'delay_min': m.get('delay_min'),
                            'delay_side': m.get('delay_side'),
                            'delay_known': bool(m.get('delay_known')),
                            'status': m.get('status'),
                            'cancelled': m.get('cancelled'),
                            'sched_dep_iso': _board_local_to_utc_iso(
                                m.get('sched_dep'), _dep_ia),
                            'est_dep_iso': _board_local_to_utc_iso(
                                m.get('esti_dep'), _dep_ia),
                            'sched_arr_iso': _board_local_to_utc_iso(
                                m.get('sched_arr'), _arr_ia),
                            'est_arr_iso': _board_local_to_utc_iso(
                                m.get('esti_arr'), _arr_ia),
                            'sides': m.get('sides'),
                            'live': _clp,   # echte FR24-Position (Süd-Route) | None
                        })
                        # FLIGHTSTATE-Engine: Shadow (loggen) und/oder Flip (die
                        # Engine entscheidet `live` + liefert die Phase). Reuse von
                        # m + _cp (kein Extra-Read). Best-effort, nie werfend.
                        #   FLIGHTSTATE_SHADOW=1       → nur Diffs loggen
                        #   FLIGHTSTATE_LIVE_FRIENDS=1 → Engine steuert live/phase
                        #                                (Kill-Switch: Var entfernen)
                        try:
                            from blueprints.flight_state_shadow import shadow_enabled
                            _fs_flip = os.environ.get(
                                'FLIGHTSTATE_LIVE_FRIENDS', '') in ('1', 'true', 'yes')
                            if shadow_enabled() or _fs_flip:
                                from blueprints.flight_state_collectors import (
                                    build_keys as _fs_bk,
                                    obs_from_board_merged as _fs_obm,
                                    obs_from_aircraft_live as _fs_oal)
                                from blueprints.flight_state import (
                                    resolve_flight_state as _fs_resolve,
                                    project_friend_leg as _fs_proj,
                                    prior_state as _fs_prior,
                                    remember_state as _fs_remember,
                                    LEGACY_STATUS as _fs_legacy_status)
                                from blueprints.flight_state_shadow import shadow_record as _fs_shadow
                                from blueprints.aerox_data_blueprint import (
                                    _iata_latlon, _iata_elev_ft)
                                _fs_keys = _fs_bk(
                                    fno, datum, _dep_ia, _arr_ia,
                                    roster_tail=m.get('reg'),
                                    sched_dep_iso=_board_local_to_utc_iso(
                                        m.get('sched_dep'), _dep_ia),
                                    sched_arr_iso=_board_local_to_utc_iso(
                                        m.get('sched_arr'), _arr_ia),
                                    dep_ll=_iata_latlon(_dep_ia),
                                    arr_ll=_iata_latlon(_arr_ia),
                                    dep_elev_ft=_iata_elev_ft(_dep_ia))
                                _fs_obs = _fs_obm(m, _fs_keys,
                                                  board_to_iso=_board_local_to_utc_iso)
                                _fs_obs += _fs_oal(_cp, _cr, _crg, _cty)
                                _fs = None
                                if _fs_flip:
                                    # prior → Monotonie/Sticky-Airborne wirken
                                    _fs = _fs_resolve(_fs_keys, _fs_obs,
                                                      prior=_fs_prior(fno, datum))
                                    _fs_remember(_fs)
                                if shadow_enabled():
                                    # fs= reicht das Flip-Resultat weiter — kein
                                    # Doppel-Resolve pro Leg (Shadow+Flip = 1x)
                                    _fs_shadow('friends_flights_live', _fs_keys,
                                               _fs_obs, flights_live[-1], fs=_fs)
                                if _fs_flip:
                                    _leg = _fs_proj(_fs)
                                    # Engine-gegatete Position (Taxi ⇒ None ⇒ kein Geist)
                                    flights_live[-1]['live'] = _leg['live']
                                    # additiv: 'lost' ⇒ iOS kann die Vorwärts-
                                    # Simulation ehrlich stoppen (P1-4c)
                                    flights_live[-1]['live_status'] = _leg['live_status']
                                    flights_live[-1]['phase'] = _fs['phase']
                                    flights_live[-1]['phase_conf'] = _fs['phase_conf']
                                    flights_live[-1]['eta_iso'] = _fs['times']['eta_iso']
                                    flights_live[-1]['eta_conf'] = _fs['times']['eta_conf']
                                    # ROHSTATUS-LECK (Owner/Fable 2026-07-13): das
                                    # Legacy-Feld 'status' blieb bislang der rohe
                                    # Board-String (m.get('status')) — z. B. dep-side
                                    # „Abgeflogen"/„airborne" für einen NUR rollenden
                                    # Flieger (TAXI_OUT). Alte/andere iOS-Pfade, die
                                    # flights_live[].status ungegatet durch
                                    # DelayLogic.phase(...) schicken (CrewBoardingCards),
                                    # sahen so „.airborne" für ein Taxi. Jetzt trägt
                                    # das Feld die LEGACY_STATUS-Projektion der
                                    # kanonischen Engine-Phase (TAXI_OUT→"GROUNDED",
                                    # AIRBORNE→"AIRBORNE", LANDED/ARRIVED→"LANDED"…) —
                                    # DIESELBE Wahrheit wie crew_state/phase, keine
                                    # erfundenen Daten (rein Umbenennung der Phase).
                                    flights_live[-1]['status'] = _fs_legacy_status.get(
                                        _fs['phase'], flights_live[-1].get('status'))
                        except Exception:
                            pass
        except Exception:
            flights_live = []
        # ── EINE Wahrheit (Neubau 2026-07-10): crew_state aus dem zentralen
        # Resolver blueprints/crew_live_state — Zustand + SERVERSEITIGER Text
        # („Fliegt gerade" / „Gelandet in …" / „Wartet auf LH… · HH:MM" /
        # „Layover …" / „Basis …"). ADDITIV: alle Altfelder unten bleiben für
        # alte Builds unverändert. Nur für den heutigen Betriebstag (für
        # Vergangenheit/Zukunft ist ein LIVE-Zustand sinnlos). Fixt die
        # iCal-Freunde-Lücke: der Resolver arbeitet auf ical_sectors und
        # braucht KEINE reader_facts.flight_numbers (Tibor-Diagnose).
        crew_state = None
        crew_state_next = None
        if datum == _heute_berlin:
            _hb_arg = (pr.get('homebase') or '').strip().upper() or None
            _cm_arg = pr.get('commute_minutes')
            crew_state = _crew_state_for_day(
                fr, day, datum, homebase=_hb_arg, snap_ts=_snap_ts,
                commute_minutes=_cm_arg, obs_lookup=_shared_obs_lk_today,
                live_lookup=_shared_live_lk)
            # OVERNIGHT-CARRY (Julien/Tibor 2026-07-16): meldet der HEUTIGE
            # Roster-Tag NICHTS AKTIVES (kein pre_flight/flying/landed —
            # today_blocks_spillover), aber ein Über-Nacht-Leg des VORTAGS ist
            # nachweislich noch unterwegs/frisch gelandet (LH423 BOS→FRA dep
            # 15.07 22:15Z / arr 16.07 06:00Z keyt auf dem Abflugtag → nach
            # Berliner Mitternacht fand der Resolver am 16. kein Leg und fiel auf
            # „home"/„Basis Frankfurt"), dann die noch aktiven Vortags-Legs VOR
            # die heutigen Sektoren in DENSELBEN Resolver reichen. Robuster als
            # der externe Sieger-Vergleich (spillover_wins unten): das Leg läuft
            # GANZ NORMAL durch Leg-Auswahl + Engine + Wrong-Day-Guards
            # (enroute/landed je nach Obs/Zeit-Physik) und trägt die Reg aus dem
            # Sektor-tail (→ aircraft_live-Positions-Tier greift). NUR wenn heute
            # inaktiv → ein echter Heute-Zustand wird nie überschrieben. Der
            # carried Leg bekommt einen an das VORTAGS-Datum gebundenen obs_lookup
            # (carry_datum), damit nicht die HEUTIGE Instanz derselben täglichen
            # Flugnummer ihn erneut auf pre_flight pinnt.
            try:
                from blueprints.crew_live_state import (
                    carry_over_legs as _col, pick_fresher_sectors as _pfs,
                    today_blocks_spillover as _tbs)
                import datetime as _cy_dt
                _cy_now = _cy_dt.datetime.now(_cy_dt.timezone.utc)
                if not _tbs(crew_state, _cy_now):
                    _gestern0 = (_cy_dt.date.fromisoformat(datum)
                                 - _cy_dt.timedelta(days=1)).isoformat()
                    _dy0 = next((t for t in tage if isinstance(t, dict)
                                 and t.get('datum') == _gestern0), None)
                    _ysnap0 = [s for s in ((_dy0 or {}).get('ical_sectors') or [])
                               if isinstance(s, dict)]
                    _yb0, _yb0_ts, _, _ = _friend_briefing_day_sectors(
                        fr, _gestern0)
                    _ysecs0, _ = _pfs(_ysnap0, _snap_ts, _yb0, _yb0_ts)
                    _carry_secs = _col(_ysecs0 or [], _cy_now) or None
                    if _carry_secs:
                        _cs_carry = _crew_state_for_day(
                            fr, day, datum, homebase=_hb_arg, snap_ts=_snap_ts,
                            commute_minutes=_cm_arg,
                            obs_lookup=_shared_obs_lk_today,
                            live_lookup=_shared_live_lk,
                            carry_sectors=_carry_secs, carry_datum=_gestern0)
                        # Nur übernehmen, wenn der Carry-Lauf tatsächlich einen
                        # aktiven Zustand ergibt (der Über-Nacht-Leg wurde
                        # gepickt) — sonst bleibt der ehrliche Heute-Zustand.
                        if _cs_carry and _cs_carry.get('state') in (
                                'pre_flight', 'flying', 'landed'):
                            crew_state = _cs_carry
            except Exception:
                pass
            # ÜBER-MITTERNACHT-SPILLOVER RÜCKWÄRTS (Owner 2026-07-12,
            # Jennifer-Fall): ein Über-Nacht-Leg (dep GESTERN 12.07 15:40Z
            # SIN→FRA, arr am Folgetag) verschwand nach Berliner Mitternacht
            # aus dem Resolver — der sieht nur den HEUTIGEN Roster-Tag, und
            # der ist auf dem Ankunftstag leglos → „Basis Frankfurt"/falscher
            # Ort mit falscher Richtung, während die Crew nachweislich noch
            # flog. Symmetrisch zum crew_state_next-Fenster (vorwärts) schaut
            # der Feed jetzt EINEN Tag zurück: meldet HEUTE nichts Aktives
            # und reicht ein gestriger Leg (Plan-Fenster + Verspätungs-Puffer
            # + „frisch gelandet") bis in den heutigen Tag, entscheidet der
            # Resolver-Lauf über die GESTRIGEN Sektoren (spillover_wins, rein
            # + getestet in blueprints/crew_live_state /
            # tests/test_overnight_spillover.py).
            # Regressions-Sweep 2026-07-12 #6+#8: (a) das Vorab-Gate blockte
            # bei JEDEM heutigen pre_flight — ein reiner Plan-pre_flight mit
            # Abflug in der Zukunft (Nacht-Turnaround-Rückleg) ist aber kein
            # Beweis-Zustand → today_blocks_spillover/spillover_wins kennen
            # jetzt genau diese Ausnahme (geteilte Prüfung, kein Drift).
            # (b) das Gate las die gestrigen Sektoren NUR aus dem Roster-
            # Snapshot, der Resolver-Lauf aber via pick_fresher_sectors aus
            # der frischeren Briefing-Quelle — iCal-Freunde mit stalem
            # Snapshot (exakt die Population, für die pick_fresher_sectors
            # gebaut wurde) verloren den Spillover. Jetzt wählt das Gate
            # DIESELBE Quelle wie der Resolver; day_y=None (Snapshot beginnt
            # erst heute) bricht nicht mehr ab.
            try:
                from blueprints.crew_live_state import (
                    yesterday_leg_reaches_into_today, spillover_wins,
                    today_blocks_spillover, pick_fresher_sectors)
                import datetime as _cs_dt
                _cs_now = _cs_dt.datetime.now(_cs_dt.timezone.utc)
                if not today_blocks_spillover(crew_state, _cs_now):
                    _gestern = (_cs_dt.date.fromisoformat(datum)
                                - _cs_dt.timedelta(days=1)).isoformat()
                    day_y = next((t for t in tage if isinstance(t, dict)
                                  and t.get('datum') == _gestern), None)
                    _y_snap = [s for s in ((day_y or {}).get('ical_sectors') or [])
                               if isinstance(s, dict)]
                    _yb_secs, _yb_ts, _yb_sum, _yb_start = \
                        _friend_briefing_day_sectors(fr, _gestern)
                    y_secs, _y_src = pick_fresher_sectors(
                        _y_snap, _snap_ts, _yb_secs, _yb_ts)
                    # HEBEL 3 (×3 NUR WO NÖTIG): der teure gestern-Compute läuft
                    # erst, wenn das gestrige Leg per CHEAP Sektor-Check plausibel
                    # über Mitternacht in HEUTE reicht (kein Extra-DB-Read — die
                    # Sektoren sind schon geladen). obs_lookup NICHT geteilt
                    # (anderes Datum), live_lookup schon (datums-unabhängig).
                    if yesterday_leg_reaches_into_today(y_secs or [], _cs_now):
                        cs_y = _crew_state_for_day(
                            fr, day_y, _gestern, homebase=_hb_arg,
                            snap_ts=_snap_ts, commute_minutes=_cm_arg,
                            live_lookup=_shared_live_lk)
                        if spillover_wins(crew_state, cs_y, now=_cs_now):
                            crew_state = cs_y
            except Exception:
                pass
            # 24-H-FENSTER ÜBER MITTERNACHT (Owner 2026-07-12, Tibor-Fall,
            # Crew-Feed-Härtung #1): friends-today liefert nur den heutigen
            # Berliner Tag → das „Check-in ab 24 h vorher"-Fenster der
            # Bordkarten konnte NIE über Mitternacht schauen (Frühflug am
            # Vorabend unsichtbar). Zusätzlich (ADDITIV, altes Feld bleibt):
            # ist HEUTE kein aktiver Zustand (kein pre_flight/flying) und der
            # ERSTE Abflug von MORGEN liegt binnen 24 h → dessen crew_state
            # als `crew_state_next` mitgeben. iOS (≥ Build 95) rendert daraus
            # die Vorabend-Bordkarte; „Wo ist deine Crew"/Live bleiben auf
            # dem HEUTE-Zustand (Layover-Text geht nicht verloren).
            try:
                if (crew_state or {}).get('state') not in ('pre_flight', 'flying'):
                    import datetime as _cs_dt
                    _morgen = (_cs_dt.date.fromisoformat(datum)
                               + _cs_dt.timedelta(days=1)).isoformat()
                    day2 = next((t for t in tage if isinstance(t, dict)
                                 and t.get('datum') == _morgen), None)
                    # HEBEL 3 (×3 NUR WO NÖTIG): den teuren morgen-Vorabend-
                    # Compute nur laufen lassen, wenn MORGEN plausibel ein Flug
                    # binnen ~24 h ansteht — billiger Vorab-Check aus den schon
                    # geladenen Sektoren (KEIN Extra-DB-Read). KONSERVATIV: hat
                    # ein Sektor keinen parsebaren dep_iso, wird trotzdem
                    # gerechnet (im Zweifel rechnen → keine echte Vorabend-
                    # Bordkarte, z.B. Ole morgen früh, geht verloren). Die
                    # endgültige 24-h-/pre_flight-Entscheidung trifft weiter der
                    # Resolver + das Fenster unten; dies ist nur ein Superset-Gate.
                    def _day2_flight_within_24h(_d2):
                        _secs2 = [s for s in ((_d2 or {}).get('ical_sectors')
                                              or []) if isinstance(s, dict)]
                        if not _secs2:
                            return False
                        _lim = (_cs_dt.datetime.now(_cs_dt.timezone.utc)
                                + _cs_dt.timedelta(hours=24))
                        for s in _secs2:
                            _di = s.get('dep_iso') or s.get('dep_iso_z')
                            if not _di:
                                return True   # unbekannt → konservativ rechnen
                            try:
                                _dt = _cs_dt.datetime.fromisoformat(
                                    str(_di).replace('Z', '+00:00'))
                                if _dt <= _lim:
                                    return True
                            except Exception:
                                return True   # unparsebar → konservativ rechnen
                        return False
                    if day2 and _day2_flight_within_24h(day2):
                        cs2 = _crew_state_for_day(
                            fr, day2, _morgen, homebase=_hb_arg,
                            snap_ts=_snap_ts, commute_minutes=_cm_arg,
                            live_lookup=_shared_live_lk)
                        _leg2 = (cs2 or {}).get('current_leg') or {}
                        _dep_iso2 = _leg2.get('dep_iso')
                        if (cs2 or {}).get('state') == 'pre_flight' and _dep_iso2:
                            _dep_dt2 = _cs_dt.datetime.strptime(
                                _dep_iso2, '%Y-%m-%dT%H:%M:%SZ').replace(
                                tzinfo=_cs_dt.timezone.utc)
                            _rest_s = (_dep_dt2
                                       - _cs_dt.datetime.now(_cs_dt.timezone.utc)
                                       ).total_seconds()
                            if 0 < _rest_s <= 24 * 3600:
                                crew_state_next = cs2
            except Exception:
                crew_state_next = None
        return (_idx, {
            'token': fr[:16] + '…',
            # Stabile match_id (Hash) statt vollem Token — iOS matcht Friend↔
            # FriendToday hierüber (vorher: truncated token != voller Token aus
            # /friends → CrewMap-Pins fanden ihr Profil nie). Kein Token-Leak.
            'match_id': hashlib.sha256(fr.encode()).hexdigest()[:16],
            # NAME-FIX (Owner 2026-07-13 „Bordkarte sagt friend statt name"):
            # KEIN erfundener englischer Platzhalter. Fehlt der Profilname,
            # ehrlich '' (leer) → die iOS-Karte lässt den Namen weg statt
            # 'Friend' anzuzeigen. (Golden-Fixture bleibt byte-gleich: dort
            # tragen ALLE Profile einen Namen, der Fallback greift nie.)
            'name': pr.get('name') or '',
            'avatar_url': pr.get('avatar_url'),
            'homebase': pr.get('homebase') or '',
            # Standort-Stadt — nur wenn share_location an ist UND (Dienstplan-Modus)
            # serverseitig freigegeben: im roster-Modus (location_source != 'gps')
            # wird die GPS-current_city verworfen und stattdessen der heutige
            # Roster-Layover-Ort serviert, damit Freunde NICHT sehen, dass die Crew
            # während eines Layovers woanders hingeflogen ist (User 2026-06-29).
            'current_city': (_friend_facing_city(pr, lay_eff)
                             if share_loc else None),
            'klass': day.get('klass'),
            'marker': day.get('marker'),
            'routing': day.get('routing'),
            'layover': lay_eff,
            # Städtenamen-Label (2026-07-03): nie rohe IATA-Ketten anzeigen.
            # route_label bewusst mit dem TOUR-Layover (rf), nicht lay_eff —
            # es beschreibt die heutige Route, nicht den aktuellen Aufenthalt.
            'route_label': _route_label_cities(day.get('routing'),
                                               rf.get('layover_ort')),
            'layover_city': (_iata_city_name(lay_eff) if lay_eff else None),
            'start': rf.get('start_time'),
            'end': rf.get('end_time'),
            # Flugnummer(n) des Tages (z.B. "LH400") — iOS leitet daraus den
            # ADS-B-Callsign ab und zeigt das echte Live-Flugzeug, wenn der
            # Friend gerade fliegt (klass=Z72). Nur durchgereicht, keine neue
            # Privacy-Stufe: gleiche Sichtbarkeit wie routing (Mutual-Friend-Gate
            # gilt bereits über _friends_load). Leere Liste wenn nichts gelesen.
            # iCAL-FALLBACK (2026-07-04): Reine-iCal-Freunde (Kalender-Feed, kein
            # Tax-Job) haben KEINE reader_facts.flight_numbers → die „fliegt
            # gerade"-Live-Karte erschien für sie nie. Fallback: die Nummer des
            # Sektors, der JETZT läuft (dep−15 min … arr+10 min, UTC aus
            # ical_sectors) — dadurch gilt „fliegt" exakt während des Legs statt
            # den ganzen Tag (iOS wertet nicht-leere Liste als „fliegt jetzt").
            'flight_numbers': (list(rf.get('flight_numbers') or [])
                               or _active_sector_flight_numbers(day)),
            # ADDITIV (2026-07-03): Live-Delay/Status pro Leg aus dem Dual-Side-
            # Resolver — iOS kann „fliegt gerade, +25 min" direkt anzeigen statt
            # nur den ADS-B-Callsign abzuleiten. Leer = keine Beobachtung.
            'flights_live': flights_live,
            # ADDITIV (Neubau 2026-07-10): EIN expliziter Live-Zustand inkl.
            # serverseitigem Text — iOS zeigt crew_state.text 1:1 (kein
            # lastRouteIATA-Raten mehr). None = Resolver übersprungen/Fehler.
            'crew_state': crew_state,
            'crew_state_next': crew_state_next,
        })

    def _worker(_idx, fr):
        # current_app fehlt im Worker → EIGENEN App-+Request-Kontext des
        # ECHTEN App-Objekts pushen (Muster _detail_subcall). Der Pfad ist
        # kosmetisch (kein Query-Read im Body — datum kommt aus der Closure);
        # er dient nur dazu, dass request-context-gebundene Helfer (z.B.
        # app.logger im crew_state-Skip) nicht werfen. Ein echter Worker-Fehler
        # wird separat markiert: er darf nicht wie ein legitimes `continue`
        # (kein Roster-Tag / Privacy-Opt-out) aussehen und vor allem nicht als
        # scheinbar vollständiger 200-Stand 90 s memoisiert werden.
        try:
            _friends_today_worker_health_begin()
            with _app_obj.test_request_context(
                    f'/api/user/friends-today/{token}?datum={datum}'):
                _i, _entry = _process_friend(_idx, fr)
                return (_i, _entry, _friends_today_worker_health_failed())
        except Exception as _e:
            app.logger.warning(
                f'[friends-today] worker_fail friend_ref='
                f'{hashlib.sha256(fr.encode()).hexdigest()[:10]} '
                f'err={type(_e).__name__}: {str(_e)[:120]}')
            return (_idx, None, True)
        finally:
            # This ThreadPoolExecutor is created/destroyed per request. Close
            # its per-thread HTTP/2 pool or the proxy registry would retain a
            # dead-thread client after every friends-today refresh.
            _close_current_thread_supabase_client()

    # Fan-out: max_workers gedeckelt (kleine Crews sind die Norm; ein sehr
    # großer Freundeskreis soll keine Verbindungs-/Thread-Flut auslösen —
    # dieselbe Größenordnung wie die anderen Aggregat-Pools). Ergebnisse mit
    # Index sammeln und in ORIGINALER Friend-Reihenfolge sortieren (Golden +
    # iOS-match_id-Kontrakt verlangen stabile Reihenfolge).
    _results = {}
    _worker_failed = False
    if friends:
        _mw = max(1, min(8, len(friends)))
        _ex = ThreadPoolExecutor(max_workers=_mw)
        try:
            _futs = [_ex.submit(_worker, i, fr) for i, fr in enumerate(friends)]
            for _f in as_completed(_futs):
                try:
                    _i, _entry, _failed = _f.result()
                except Exception as _e:
                    _worker_failed = True
                    app.logger.warning(
                        f'[friends-today] future_fail err={type(_e).__name__}: '
                        f'{str(_e)[:120]}')
                    continue
                _worker_failed = _worker_failed or _failed
                if _entry is not None:
                    _results[_i] = _entry
        finally:
            _ex.shutdown(wait=True)
    out = [_results[i] for i in sorted(_results)]

    _resp = {'datum': datum, 'count': len(out), 'friends_today': out}
    if _worker_failed:
        # Additiv/backward-compatible: bestehende Decoder ignorieren unbekannte
        # Top-Level-Keys. Erfolgreiche Vollantworten bleiben byte-/golden-gleich.
        # Der iOS-LKG-Pfad kann an diesen Markern erkennen, dass fehlende Rows
        # KEIN bestätigter neuer Crew-Stand sind.
        _resp['partial'] = True
        _resp['complete'] = False
    else:
        if len(_FRIENDS_TODAY_MEMO) > 5000:
            _FRIENDS_TODAY_MEMO.clear()
        _FRIENDS_TODAY_MEMO[_ck] = (_now_m + _FRIENDS_TODAY_TTL, _resp)
    return _friends_today_response(_resp)


def _flight_ops_path(token):
    import os, re
    if not token: return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe: return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'flightops_{safe}.json')


# ── Flight-Ops SB persistence (P1 durability, 2026-07-02) ──
# Per-Flight-Operational-Details (Catering/Pax/Fuel/SSR/Endorsement) — vom User
# GETIPPT, speisen Logbuch + Trip-Stats. Lagen NUR auf ephemeral Disk
# (flightops_<token>.json) → jeder Cloud-Run-Redeploy wipte sie. Pattern exakt
# wie user_manual_briefings: SB-primary, Disk-Fallback, Lazy-Migrate beim ersten
# SB-leeren Read. Tabelle user_flight_ops(token, datum, ops jsonb) PK(token,datum).

def _flight_ops_load_from_supabase(token):
    """dict[datum_str → ops_dict] | None bei SB-down/Tabelle-fehlt."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('user_flight_ops').select('datum,ops')
             .eq('token', token).execute())
        out = {}
        for row in (r.data or []):
            datum = row.get('datum')
            ops = row.get('ops')
            if datum and isinstance(ops, dict):
                out[str(datum)] = ops
        return out
    except Exception as e:
        if _sb_table_is_missing('user_flight_ops', e):
            return None
        app.logger.warning(
            f'[flight-ops] sb_load_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:120]}')
        return None


def _flight_ops_save_to_supabase(token, ops_by_date):
    """Bulk-upsert aller Flight-Ops. True bei Erfolg/leer, False bei Fehler."""
    if not SB_AVAILABLE or not token or ops_by_date is None:
        return False
    rows = []
    for datum, ops in (ops_by_date or {}).items():
        if not isinstance(ops, dict):
            continue
        if not isinstance(datum, str) or len(datum) < 10:
            continue
        rows.append({'token': token, 'datum': datum[:10], 'ops': ops})
    if not rows:
        return True
    try:
        for i in range(0, len(rows), 500):
            sb.table('user_flight_ops').upsert(
                rows[i:i+500], on_conflict='token,datum').execute()
        return True
    except Exception as e:
        if _sb_table_is_missing('user_flight_ops', e):
            return False
        app.logger.error(
            f'[flight-ops] sb_save_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}')
        return False


def _flight_ops_upsert_datum_to_supabase(token, datum, ops):
    """Single-Datum-Upsert (für put_flight_ops). True bei Erfolg."""
    if not SB_AVAILABLE or not token or not datum or not isinstance(ops, dict):
        return False
    try:
        sb.table('user_flight_ops').upsert(
            {'token': token, 'datum': datum[:10], 'ops': ops},
            on_conflict='token,datum').execute()
        return True
    except Exception as e:
        if _sb_table_is_missing('user_flight_ops', e):
            return False
        app.logger.error(
            f'[flight-ops] sb_upsert_fail tok={token[:8]} err={type(e).__name__}: {str(e)[:200]}')
        return False


def _flight_ops_delete_datum_from_supabase(token, datum):
    if not SB_AVAILABLE or not token or not datum:
        return False
    try:
        sb.table('user_flight_ops').delete().eq('token', token).eq('datum', datum[:10]).execute()
        return True
    except Exception as e:
        if not _sb_table_is_missing('user_flight_ops', e):
            app.logger.warning(f'[flight-ops] sb_delete_fail tok={token[:8]}: {str(e)[:120]}')
        return False


def _flight_ops_load_from_disk(token):
    p = _flight_ops_path(token)
    if not p:
        return {}
    try:
        with open(p) as f:
            return json.load(f) or {}
    except FileNotFoundError:
        return {}
    except Exception:
        return {}


@app.route('/api/user/flight-ops/<token>', methods=['GET'])
def get_flight_ops(token):
    """Liefert alle Per-Flight-Operational-Details (Catering/Pax/Fuel/SSR/Endorsement) zurück.
    Optional: ?datum=YYYY-MM-DD für einzelnen Tag.
    """
    if not _flight_ops_path(token):
        return jsonify({'error': 'invalid token'}), 400
    try:
        # SB-primary (Disk-Fallback + Lazy-Migrate steckt in _flight_ops_load).
        data = _flight_ops_load(token)
    except Exception as e:
        print(f'[get_flight_ops] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'error': 'internal_error'}), 500
    datum = request.args.get('datum')
    if datum:
        return jsonify({'datum': datum, 'ops': data.get(datum, {})})
    return jsonify({'count': len(data), 'ops_by_date': data})


@app.route('/api/user/flight-ops/<token>/<datum>', methods=['PUT'])
def put_flight_ops(token, datum):
    """Speichert/aktualisiert Per-Flight-Operational-Details für einen Tag.
    Body: full FlightOps-Object (kein Patch, replace).
    """
    import re
    if not re.match(r'^\d{4}-\d{2}-\d{2}$', datum or ''):
        return jsonify({'ok': False, 'error': 'invalid_datum'}), 400
    p = _flight_ops_path(token)
    if not p:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    body = request.get_json(silent=True) or {}
    if not isinstance(body, dict):
        return jsonify({'ok': False, 'error': 'body_must_be_object'}), 400
    # Strip oversize payloads (DOS protection)
    if len(json.dumps(body)) > 16_000:
        return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
    # SB-primary: einzelnes Datum upserten. Disk-Mirror best-effort.
    sb_ok = _flight_ops_upsert_datum_to_supabase(token, datum, body)
    disk_ok = False
    try:
        data = _flight_ops_load_from_disk(token)
        data[datum] = body
        with open(p, 'w') as f:
            json.dump(data, f, ensure_ascii=False)
        disk_ok = True
    except Exception as e:
        print(f'[put_flight_ops] disk_save_fail (ok wenn SB lief): {type(e).__name__}: {str(e)[:300]}')
    if not (sb_ok or disk_ok):
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True, 'datum': datum})


@app.route('/api/user/flight-ops/<token>/<datum>', methods=['DELETE'])
def delete_flight_ops(token, datum):
    """Löscht Operational-Details für einen Tag."""
    p = _flight_ops_path(token)
    if not p:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    # SB-primary löschen, dann Disk-Mirror.
    _flight_ops_delete_datum_from_supabase(token, datum)
    try:
        with open(p) as f:
            data = json.load(f)
        if datum in data:
            del data[datum]
            with open(p, 'w') as f:
                json.dump(data, f, ensure_ascii=False)
    except FileNotFoundError:
        pass
    except Exception as e:
        print(f'[delete_flight_ops] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True})


# ─── Aviation Master-Data Endpoints ──────────────────────────────────────────
# METAR, Currency, Aircraft-Registry, NOTAMs — alle aus public APIs (CC0/PD)

_AVIATION_CACHE = {}  # in-mem TTL cache: key -> (expires_at, value)
def _aviation_cache_get(key, ttl_sec):
    import time
    rec = _AVIATION_CACHE.get(key)
    if rec and rec[0] > time.time():
        return rec[1]
    return None

def _aviation_cache_set(key, value, ttl_sec):
    import time
    _AVIATION_CACHE[key] = (time.time() + ttl_sec, value)
    if len(_AVIATION_CACHE) > 500:
        oldest = sorted(_AVIATION_CACHE.items(), key=lambda x: x[1][0])[:200]
        for k, _ in oldest:
            _AVIATION_CACHE.pop(k, None)


def _cache_soft_cap(cache, max_items=500, drop=200):
    """Generischer Soft-Cap für unbounded In-Memory-Caches (gleiches Muster
    wie _aviation_cache_set): über max_items → älteste ~drop Einträge raus.
    Erwartet Values als (ts, ...)-Tupel; sonst Insertion-Order als Näherung."""
    try:
        if len(cache) <= max_items:
            return
        def _age(item):
            v = item[1]
            if isinstance(v, tuple) and v and isinstance(v[0], (int, float)):
                return v[0]
            return 0
        for k, _ in sorted(cache.items(), key=_age)[:drop]:
            cache.pop(k, None)
    except Exception:
        pass


@app.route('/api/aviation/metar/<icao>', methods=['GET'])
def get_metar(icao):
    """METAR Wetter-Report von aviationweather.gov (US Public Domain).
    Beispiel: /api/aviation/metar/EDDF → Frankfurt METAR
    """
    import re
    icao = (icao or '').strip().upper()
    if not re.match(r'^[A-Z]{4}$', icao):
        return jsonify({'error': 'invalid icao'}), 400
    cached = _aviation_cache_get(f'metar:{icao}', 600)
    if cached is not None:
        return jsonify(cached)
    try:
        import urllib.request as ur
        url = f'https://aviationweather.gov/api/data/metar?ids={icao}&format=json&hours=1'
        req = ur.Request(url, headers={'User-Agent': 'Aeris/1.0'})
        with ur.urlopen(req, timeout=10) as r:
            raw = json.loads(r.read().decode('utf-8'))
        if not raw:
            result = {'icao': icao, 'reports': []}
        else:
            result = {'icao': icao, 'reports': [
                {
                    'raw': r.get('rawOb'),
                    'time': r.get('reportTime'),
                    'temp_c': r.get('temp'),
                    'dewpoint_c': r.get('dewp'),
                    'wind_dir': r.get('wdir'),
                    'wind_speed_kt': r.get('wspd'),
                    'wind_gust_kt': r.get('wgst'),
                    'visibility_sm': r.get('visib'),
                    'altimeter_hpa': r.get('altim'),
                    'flight_category': r.get('fltCat'),
                } for r in raw[:5]
            ]}
        _aviation_cache_set(f'metar:{icao}', result, 600)
        return jsonify(result)
    except Exception as e:
        print(f'[get_metar] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'icao': icao, 'reports': [], 'error': 'upstream_error'}), 502


@app.route('/api/aviation/taf/<icao>', methods=['GET'])
def get_taf(icao):
    """TAF Wetter-Forecast von aviationweather.gov."""
    import re
    icao = (icao or '').strip().upper()
    if not re.match(r'^[A-Z]{4}$', icao):
        return jsonify({'error': 'invalid icao'}), 400
    cached = _aviation_cache_get(f'taf:{icao}', 1800)
    if cached is not None:
        return jsonify(cached)
    try:
        import urllib.request as ur
        url = f'https://aviationweather.gov/api/data/taf?ids={icao}&format=json'
        req = ur.Request(url, headers={'User-Agent': 'Aeris/1.0'})
        with ur.urlopen(req, timeout=10) as r:
            raw = json.loads(r.read().decode('utf-8'))
        result = {'icao': icao, 'forecasts': raw[:3] if raw else []}
        _aviation_cache_set(f'taf:{icao}', result, 1800)
        return jsonify(result)
    except Exception as e:
        print(f'[get_taf] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'icao': icao, 'forecasts': [], 'error': 'upstream_error'}), 502


@app.route('/api/aviation/currency', methods=['GET'])
def get_currency_rates():
    """Wechselkurse via exchangerate.host (frei).
    Query: ?base=EUR&symbols=USD,GBP,CHF
    """
    base = (request.args.get('base') or 'EUR').upper()[:3]
    symbols = (request.args.get('symbols') or 'USD,GBP,CHF,JPY,CNY,CAD,AUD,SGD,AED').upper()
    cache_key = f'cur:{base}:{symbols}'
    cached = _aviation_cache_get(cache_key, 3600 * 12)
    if cached is not None:
        return jsonify(cached)
    try:
        import urllib.request as ur
        url = f'https://api.exchangerate.host/latest?base={base}&symbols={symbols}'
        with ur.urlopen(url, timeout=10) as r:
            data = json.loads(r.read().decode('utf-8'))
        result = {'base': base, 'date': data.get('date'), 'rates': data.get('rates', {})}
        _aviation_cache_set(cache_key, result, 3600 * 12)
        return jsonify(result)
    except Exception as e:
        print(f'[get_currency_rates] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'base': base, 'rates': {}, 'error': 'upstream_error'}), 502


@app.route('/api/aviation/aircraft/<icao24>', methods=['GET'])
def get_aircraft_by_icao24(icao24):
    """Live-Aircraft-State von OpenSky-Network (frei, anonym).
    Beispiel: /api/aviation/aircraft/3c6589
    Returns current lat/lon/altitude/velocity wenn airborne.
    """
    import re
    icao24 = (icao24 or '').strip().lower()
    if not re.match(r'^[0-9a-f]{6}$', icao24):
        return jsonify({'error': 'invalid icao24'}), 400
    cached = _aviation_cache_get(f'os:{icao24}', 60)
    if cached is not None:
        return jsonify(cached)
    try:
        import urllib.request as ur
        url = f'https://opensky-network.org/api/states/all?icao24={icao24}'
        with ur.urlopen(url, timeout=10) as r:
            data = json.loads(r.read().decode('utf-8'))
        states = data.get('states') or []
        if not states:
            result = {'icao24': icao24, 'state': None}
        else:
            s = states[0]
            result = {
                'icao24': icao24,
                'callsign': (s[1] or '').strip() if s[1] else None,
                'origin_country': s[2],
                'time_position': s[3],
                'last_contact': s[4],
                'lon': s[5], 'lat': s[6],
                'baro_altitude_m': s[7],
                'on_ground': s[8],
                'velocity_ms': s[9],
                'heading': s[10],
                'vertical_rate_ms': s[11],
                'geo_altitude_m': s[13],
            }
        _aviation_cache_set(f'os:{icao24}', result, 60)
        return jsonify(result)
    except Exception as e:
        print(f'[get_aircraft_by_icao24] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'icao24': icao24, 'state': None, 'error': 'upstream_error'}), 502


@app.route('/api/aviation/notams/<icao>', methods=['GET'])
def get_notams(icao):
    """NOTAM-Liste für Flughafen via FAA NOTAM Search (frei).
    Beispiel: /api/aviation/notams/KJFK
    Hinweis: nur US-Airports werden von FAA gehostet — EU via Eurocontrol API würde Account brauchen.
    """
    import re
    icao = (icao or '').strip().upper()
    if not re.match(r'^[A-Z]{4}$', icao):
        return jsonify({'error': 'invalid icao'}), 400
    cached = _aviation_cache_get(f'notam:{icao}', 1800)
    if cached is not None:
        # Sweep-P3 2026-07-10: gecachte Negativ-Treffer als 200 + leeres Array
        # ausliefern (Alt-Build-Kompat — ältere iOS-Builds werten 502 als
        # harten Fehler und retryen sofort, der Negativ-Cache lief damit ins
        # Leere). Nur der FRISCHE Upstream-Fehler unten bleibt 502; das
        # 'error'-Feld bleibt im Body, damit neue Clients es erkennen.
        return jsonify(cached), 200
    try:
        import urllib.request as ur
        url = f'https://external-api.faa.gov/notamapi/v1/notams?icaoLocation={icao}&pageSize=20'
        req = ur.Request(url, headers={'User-Agent': 'Aeris/1.0'})
        with ur.urlopen(req, timeout=10) as r:
            data = json.loads(r.read().decode('utf-8'))
        items = data.get('items', [])
        result = {'icao': icao, 'count': len(items), 'notams': [
            {
                'id': it.get('properties', {}).get('notamNumber'),
                'effective': it.get('properties', {}).get('effectiveStart'),
                'expires': it.get('properties', {}).get('effectiveEnd'),
                'text': it.get('properties', {}).get('coreNOTAMData', {}).get('notam', {}).get('text', '')[:500],
            } for it in items[:20]
        ]}
        _aviation_cache_set(f'notam:{icao}', result, 1800)
        return jsonify(result)
    except Exception as e:
        # Negativ-Cache 30 min (Sweep J2 2026-07-10): die FAA-API verlangt
        # inzwischen einen API-Key (anonym 401) — ohne Cache lief JEDER Request
        # erneut in den 10s-Upstream-Call.
        result = {'icao': icao, 'notams': [], 'error': 'notam_unavailable'}
        _aviation_cache_set(f'notam:{icao}', result, 1800)
        return jsonify(result), 502


