def _iata_to_icao(iata):
    """IATA → ICAO. Returns None wenn unbekannt."""
    if not iata:
        return None
    return _IATA_TO_ICAO.get(iata.strip().upper())


def _decode_metar_human(raw, temp_c, wind_kt, wind_dir, visibility_sm, conditions):
    """Wandelt METAR-Rohdaten in einen kurzen deutschen Klartext um.
    Beispiel: "12 °C, leichter Wind aus Süd (12 kt), Sicht 10 km, klar"
    Bewusst defensiv: jeder fehlende Wert wird stillschweigend weggelassen.
    """
    parts = []
    if temp_c is not None:
        try:
            parts.append(f"{int(round(float(temp_c)))} °C")
        except (TypeError, ValueError):
            pass
    if wind_kt is not None:
        try:
            kt = float(wind_kt)
            if kt < 7:
                wind_label = "leichter Wind"
            elif kt < 17:
                wind_label = "mäßiger Wind"
            elif kt < 28:
                wind_label = "frischer Wind"
            else:
                wind_label = "starker Wind"
            dir_label = ""
            if wind_dir is not None:
                try:
                    deg = int(float(wind_dir))
                    dirs = ['Nord', 'Nordost', 'Ost', 'Südost',
                            'Süd', 'Südwest', 'West', 'Nordwest']
                    idx = int(((deg + 22.5) % 360) // 45)
                    dir_label = f" aus {dirs[idx]}"
                except (TypeError, ValueError):
                    pass
            parts.append(f"{wind_label}{dir_label} ({int(round(kt))} kt)")
        except (TypeError, ValueError):
            pass
    # Sicht: aviationweather liefert in statute miles (SM) → in km umrechnen
    if visibility_sm is not None:
        try:
            sm = float(visibility_sm)
            km = sm * 1.609
            if km >= 10:
                parts.append("Sicht > 10 km")
            else:
                parts.append(f"Sicht {km:.1f} km")
        except (TypeError, ValueError):
            pass
    if conditions:
        parts.append(str(conditions))
    elif raw:
        # Cloud-Layer aus rawOb extrahieren (CLR/SKC/FEW/SCT/BKN/OVC)
        import re as _re
        if _re.search(r'\b(CLR|SKC|NSC|CAVOK)\b', raw):
            parts.append("klar")
        elif _re.search(r'\bOVC\d{3}\b', raw):
            parts.append("bedeckt")
        elif _re.search(r'\bBKN\d{3}\b', raw):
            parts.append("stark bewölkt")
        elif _re.search(r'\bSCT\d{3}\b', raw):
            parts.append("locker bewölkt")
        elif _re.search(r'\bFEW\d{3}\b', raw):
            parts.append("leicht bewölkt")
        if _re.search(r'\b(RA|SHRA|DZ)\b', raw):
            parts.append("Regen")
        if _re.search(r'\b(SN|SHSN)\b', raw):
            parts.append("Schnee")
        if _re.search(r'\b(TS|TSRA)\b', raw):
            parts.append("Gewitter")
        if _re.search(r'\bFG\b', raw):
            parts.append("Nebel")
    return ", ".join(parts) if parts else "—"


@app.route('/api/weather/metar/<iata>', methods=['GET'])
def get_metar_by_iata(iata):
    """METAR-Live-Report für IATA-Code (mit IATA→ICAO Mapping + decoded text).
    Beispiel: /api/weather/metar/FRA → Frankfurt EDDF METAR.
    Return-Shape kompatibel zu iOS `MetarReportLive`.
    Cache: 15 min in-mem.
    """
    import re
    iata_clean = (iata or '').strip().upper()
    if not re.match(r'^[A-Z]{3}$', iata_clean):
        return jsonify({'error': 'invalid_iata', 'iata': iata_clean,
                        'status': 'invalid'}), 400
    icao = _iata_to_icao(iata_clean)
    if not icao:
        return jsonify({'error': 'icao_mapping_missing', 'iata': iata_clean,
                        'status': 'unknown_airport'}), 404

    cache_key = f'metar_v2:{icao}'
    cached = _aviation_cache_get(cache_key, 900)
    if cached is not None:
        return jsonify(cached)

    try:
        import urllib.request as ur
        url = f'https://aviationweather.gov/api/data/metar?ids={icao}&format=json&hours=1'
        req = ur.Request(url, headers={
            'User-Agent': 'AeroX/1.0 (aviation-app; +https://aerosteuer.de)',
            'Accept': 'application/json',
        })
        with ur.urlopen(req, timeout=8) as r:
            raw = json.loads(r.read().decode('utf-8'))
    except Exception as e:
        # Silent return None mit Status — iOS zeigt dann kein Wetter, ohne crash.
        print(f'[airport-weather] fetch fail {icao}: {type(e).__name__}: {str(e)[:200]}')
        return jsonify({'iata': iata_clean, 'icao': icao,
                        'status': 'fetch_failed',
                        'error': 'upstream_error'}), 502

    if not raw:
        result = {'iata': iata_clean, 'icao': icao, 'status': 'no_data',
                  'raw': None, 'temp_c': None, 'wind_kt': None,
                  'visibility_km': None, 'conditions': None,
                  'time_iso': None, 'decoded': None}
        _aviation_cache_set(cache_key, result, 900)
        return jsonify(result)

    first = raw[0] if isinstance(raw, list) else raw
    raw_ob = first.get('rawOb')
    temp_c = first.get('temp')
    wind_kt = first.get('wspd')
    wind_dir = first.get('wdir')
    vis_sm = first.get('visib')
    # `wxString` ist das human-readable Wetter-Phänomen (Rain, Snow, etc.).
    # #9: NICHT auf `clouds` zurückfallen — das ist eine Liste von Dicts
    # ({'cover': 'FEW', 'base': 3500}), die als roher Python-Repr in den
    # `decoded`-Text leakte ("…, {'cover': 'FEW', 'base': 3500}"). Die Wolken
    # decodiert `_decode_metar_human` ohnehin sauber aus dem rohen METAR
    # (FEW/SCT/BKN/OVC → "leicht/locker/stark bewölkt/bedeckt").
    conditions = first.get('wxString')
    if isinstance(conditions, list):
        conditions = ', '.join(str(c) for c in conditions if c)
    time_iso = first.get('reportTime')
    visibility_km = None
    if vis_sm is not None:
        try:
            visibility_km = round(float(vis_sm) * 1.609, 1)
        except (TypeError, ValueError):
            pass
    decoded = _decode_metar_human(raw_ob, temp_c, wind_kt, wind_dir,
                                  vis_sm, conditions)
    result = {
        'iata': iata_clean,
        'icao': icao,
        'status': 'ok',
        'raw': raw_ob,
        'temp_c': temp_c,
        'wind_kt': wind_kt,
        'wind_dir': wind_dir,
        'visibility_km': visibility_km,
        'conditions': conditions,
        'time_iso': time_iso,
        'decoded': decoded,
    }
    _aviation_cache_set(cache_key, result, 900)
    return jsonify(result)


# ═══════════════════════════════════════════════════════════════════════════
#  Airport-Enrichment: /api/airport/<icao>/detail
#  ---------------------------------------------------------------------------
#  Kombiniert (alle FREE-Quellen, keine paid API):
#    · METAR + TAF  → aviationweather.gov (US Public Domain), via demselben
#      Fetch-Pfad + `_decode_metar_human` wie /api/weather/metar.
#    · Runways + Frequencies + Elevation → OurAirports CSVs (Public Domain,
#      davidmegginson.github.io/ourairports-data).
#
#  OurAirports-Load-Strategie: LAZY + Prozess-weiter Cache. Beim ERSTEN Call
#  laden wir runways.csv / airport-frequencies.csv / airports.csv einmal herunter,
#  parsen sie in ICAO-gekeyte Dicts und halten sie im Speicher (_OURAIRPORTS_*).
#  KEIN Download beim Startup (würde Cold-Start blocken). Ein Lock serialisiert
#  den Erst-Load (Thundering-Herd-Schutz); schlägt der Download fehl, liefern wir
#  ehrlich runways/frequencies=[] statt zu crashen — METAR/TAF kommen trotzdem.
# ═══════════════════════════════════════════════════════════════════════════

_OURAIRPORTS_BASE = "https://davidmegginson.github.io/ourairports-data"
_OURAIRPORTS_LOCK = __import__('threading').Lock()
_OURAIRPORTS_LOADED = False
_OURAIRPORTS_RUNWAYS = {}       # ICAO(upper) -> [runway dicts]
_OURAIRPORTS_FREQS = {}         # ICAO(upper) -> [freq dicts]
_OURAIRPORTS_AIRPORTS = {}      # ICAO(upper) -> {elevation_ft, name, ...}
_OURAIRPORTS_LOAD_ERROR = None


def _ourairports_fetch_csv(name):
    """Lädt eine OurAirports-CSV und gibt sie als Liste von Dicts zurück.
    Wirft bei Netz-/Parse-Fehler (Caller fängt + degradiert)."""
    import csv as _csv
    import urllib.request as ur
    url = f'{_OURAIRPORTS_BASE}/{name}'
    req = ur.Request(url, headers={'User-Agent': 'AeroX/1.0 (aviation-app)'})
    with ur.urlopen(req, timeout=20) as r:
        text = r.read().decode('utf-8', errors='replace')
    return list(_csv.DictReader(io.StringIO(text)))


def _ourairports_ensure_loaded():
    """Lazy one-shot Load der OurAirports-Daten in Prozess-Caches. Idempotent.
    Returns True wenn Daten verfügbar sind (auch teilweise), False bei total-Fail.
    Blockt NIE den Startup — wird erst beim ersten /detail-Call aufgerufen."""
    global _OURAIRPORTS_LOADED, _OURAIRPORTS_LOAD_ERROR
    if _OURAIRPORTS_LOADED:
        return True
    with _OURAIRPORTS_LOCK:
        if _OURAIRPORTS_LOADED:
            return True
        try:
            # airports.csv: ident (ICAO) -> elevation/name. Index für die anderen
            # CSVs nutzt airport_ref (numeric id) → wir brauchen die id→ICAO-Map.
            airports = _ourairports_fetch_csv('airports.csv')
            id_to_icao = {}
            for a in airports:
                icao = (a.get('ident') or '').strip().upper()
                if not icao:
                    continue
                aid = (a.get('id') or '').strip()
                if aid:
                    id_to_icao[aid] = icao
                _OURAIRPORTS_AIRPORTS[icao] = {
                    'elevation_ft': _to_int_or_none(a.get('elevation_ft')),
                    'name': a.get('name') or None,
                    'iata': (a.get('iata_code') or '').strip().upper() or None,
                    'lat': _to_float_or_none(a.get('latitude_deg')),
                    'lon': _to_float_or_none(a.get('longitude_deg')),
                }

            runways = _ourairports_fetch_csv('runways.csv')
            for rw in runways:
                aref = (rw.get('airport_ref') or '').strip()
                icao = id_to_icao.get(aref)
                if not icao:
                    icao = (rw.get('airport_ident') or '').strip().upper()
                if not icao:
                    continue
                lit = (rw.get('lighted') or '').strip()
                _OURAIRPORTS_RUNWAYS.setdefault(icao, []).append({
                    'le_ident': (rw.get('le_ident') or '').strip() or None,
                    'he_ident': (rw.get('he_ident') or '').strip() or None,
                    'length_ft': _to_int_or_none(rw.get('length_ft')),
                    'width_ft': _to_int_or_none(rw.get('width_ft')),
                    'surface': (rw.get('surface') or '').strip() or None,
                    'lit': (lit == '1') if lit in ('0', '1') else None,
                })

            freqs = _ourairports_fetch_csv('airport-frequencies.csv')
            for fr in freqs:
                aref = (fr.get('airport_ref') or '').strip()
                icao = id_to_icao.get(aref)
                if not icao:
                    icao = (fr.get('airport_ident') or '').strip().upper()
                if not icao:
                    continue
                _OURAIRPORTS_FREQS.setdefault(icao, []).append({
                    'type': (fr.get('type') or '').strip() or None,
                    'description': (fr.get('description') or '').strip() or None,
                    'mhz': _to_float_or_none(fr.get('frequency_mhz')),
                })
            _OURAIRPORTS_LOADED = True
            _OURAIRPORTS_LOAD_ERROR = None
            return True
        except Exception as e:
            _OURAIRPORTS_LOAD_ERROR = f'{type(e).__name__}: {str(e)[:120]}'
            try:
                app.logger.warning(f'[airport-detail] ourairports load FAIL: {_OURAIRPORTS_LOAD_ERROR}')
            except Exception:
                pass
            return False


def _to_int_or_none(v):
    try:
        s = str(v).strip()
        if not s:
            return None
        return int(float(s))
    except (TypeError, ValueError):
        return None


def _to_float_or_none(v):
    try:
        s = str(v).strip()
        if not s:
            return None
        return float(s)
    except (TypeError, ValueError):
        return None


def _fetch_aviationweather(kind, icao):
    """Holt rohe METAR- oder TAF-JSON-Liste von aviationweather.gov. kind ∈
    {'metar','taf'}. Liefert die JSON-Liste oder None bei Fehler. Wirft NIE."""
    import urllib.request as ur
    hours = '&hours=1' if kind == 'metar' else ''
    url = f'https://aviationweather.gov/api/data/{kind}?ids={icao}&format=json{hours}'
    try:
        req = ur.Request(url, headers={
            'User-Agent': 'AeroX/1.0 (aviation-app; +https://aerosteuer.de)',
            'Accept': 'application/json',
        })
        with ur.urlopen(req, timeout=8) as r:
            return json.loads(r.read().decode('utf-8'))
    except Exception:
        return None


@app.route('/api/airport/<icao>/detail', methods=['GET'])
def get_airport_detail(icao):
    """Kombinierte Airport-Info: METAR + TAF (aviationweather.gov) +
    Runways/Frequencies/Elevation (OurAirports). Alle Quellen frei.

    200: {ok, icao, name, metar:{raw,decoded,...}|null, taf:{raw}|null,
          runways:[{le_ident,he_ident,length_ft,surface,lit}],
          frequencies:[{type,description,mhz}], elevation_ft}
    400: ungültiger ICAO.

    Ehrlich: einzelne Quellen können fehlen — dann ist das jeweilige Feld
    null/[] mit `*_status` statt eines Fehlers für den ganzen Call.
    """
    import re
    icao = (icao or '').strip().upper()
    if not re.match(r'^[A-Z0-9]{4}$', icao):
        return jsonify({'ok': False, 'error': 'invalid_icao'}), 400

    cache_key = f'airport_detail:{icao}'
    cached = _aviation_cache_get(cache_key, 600)
    if cached is not None:
        return jsonify(cached)

    # ─── METAR (raw + decoded via shared helper) ───
    metar = None
    metar_status = 'no_data'
    raw_metar = _fetch_aviationweather('metar', icao)
    if raw_metar is None:
        metar_status = 'fetch_failed'
    elif raw_metar:
        m = raw_metar[0] if isinstance(raw_metar, list) else raw_metar
        vis_sm = m.get('visib')
        visibility_km = None
        if vis_sm is not None:
            try:
                visibility_km = round(float(vis_sm) * 1.609, 1)
            except (TypeError, ValueError):
                pass
        conditions = m.get('wxString')
        if isinstance(conditions, list):
            conditions = ', '.join(str(c) for c in conditions if c)
        metar = {
            'raw': m.get('rawOb'),
            'temp_c': m.get('temp'),
            'dewpoint_c': m.get('dewp'),
            'wind_dir': m.get('wdir'),
            'wind_kt': m.get('wspd'),
            'wind_gust_kt': m.get('wgst'),
            'visibility_km': visibility_km,
            'altimeter_hpa': m.get('altim'),
            'flight_category': m.get('fltCat'),
            'time_iso': m.get('reportTime'),
            'decoded': _decode_metar_human(m.get('rawOb'), m.get('temp'),
                                           m.get('wspd'), m.get('wdir'),
                                           vis_sm, conditions),
        }
        metar_status = 'ok'

    # ─── TAF (raw forecast) ───
    taf = None
    taf_status = 'no_data'
    raw_taf = _fetch_aviationweather('taf', icao)
    if raw_taf is None:
        taf_status = 'fetch_failed'
    elif raw_taf:
        t = raw_taf[0] if isinstance(raw_taf, list) else raw_taf
        taf = {
            'raw': t.get('rawTAF'),
            'time_iso': t.get('issueTime'),
            'valid_from': t.get('validTimeFrom'),
            'valid_to': t.get('validTimeTo'),
        }
        taf_status = 'ok'

    # ─── Runways / Frequencies / Elevation (OurAirports, lazy-loaded) ───
    oa_ok = _ourairports_ensure_loaded()
    runways = _OURAIRPORTS_RUNWAYS.get(icao, []) if oa_ok else []
    frequencies = _OURAIRPORTS_FREQS.get(icao, []) if oa_ok else []
    ap = _OURAIRPORTS_AIRPORTS.get(icao, {}) if oa_ok else {}
    elevation_ft = ap.get('elevation_ft')
    static_status = 'ok' if oa_ok else 'unavailable'

    result = {
        'ok': True,
        'icao': icao,
        'name': ap.get('name'),
        'iata': ap.get('iata'),
        'lat': ap.get('lat'),
        'lon': ap.get('lon'),
        'elevation_ft': elevation_ft,
        'metar': metar,
        'metar_status': metar_status,
        'taf': taf,
        'taf_status': taf_status,
        'runways': runways,
        'frequencies': frequencies,
        'static_status': static_status,
    }
    # Nur cachen wenn mindestens eine dynamische Quelle echte Daten lieferte —
    # so retryt ein transienter aviationweather-Fail nicht erst nach 10 min.
    if metar_status == 'ok' or taf_status == 'ok' or static_status == 'ok':
        _aviation_cache_set(cache_key, result, 600)
    return jsonify(result)


# ─── Aviation-News Vollartikel-Proxy (Multi-Source) ─────────────────────────
# W-Article (2026-06-01): erweitert von aero.de-only auf 6 Aviation-Quellen.
# Pipeline:
#   1. SSRF-Whitelist: Host MUSS in NEWS_ARTICLE_ALLOWED_HOSTS sein.
#   2. 24h-Cache (in-mem dict + threading.Lock, key=sha256(url)).
#   3. Fetch via requests (10s timeout, identifizierender User-Agent).
#   4. Fulltext-Extraction Priorität:
#         (a) readability-lxml (Mozilla-Algorithmus, robust pro Source)
#         (b) BeautifulSoup-Heuristik (article/main/.entry-content/.article-content)
#         (c) Legacy-Regex (`_extract_article_text`, aero.de-tuned)
#      Es gewinnt das längste Resultat ≥80 Zeichen.
#   5. Optional: Title + image_url + published_at aus <meta og:*>-Tags.
# Whitelist ist HARDCODED — kein User-Input, kein DB-Lookup, kein Bypass.

NEWS_ARTICLE_ALLOWED_HOSTS = frozenset({
    # aero.de · deutsche Hauptquelle
    'aero.de', 'www.aero.de',
    # aeroTELEGRAPH · DE-Branchenmedium (WordPress)
    'aerotelegraph.com', 'www.aerotelegraph.com',
    # AEROBUZZ · DE-Branchenmedium (WordPress)
    'aerobuzz.de', 'www.aerobuzz.de',
    # Aviation.Direct · DE-Branchenmedium (WordPress)
    'aviation.direct', 'www.aviation.direct',
    # Austrian Wings · AT-Branchenmedium (WordPress)
    'austrianwings.info', 'www.austrianwings.info',
    # Reuters Aerospace & Defense
    'reuters.com', 'www.reuters.com',
    # AvHerald · Incident-Reports
    'avherald.com', 'www.avherald.com',
    # Simple Flying
    'simpleflying.com', 'www.simpleflying.com',
    # The Air Current
    'theaircurrent.com', 'www.theaircurrent.com',
    # Flightradar24 Blog (Squawk)
    'flightradar24.com', 'www.flightradar24.com',
})

NEWS_ARTICLE_CACHE_TTL_SECONDS = 24 * 3600   # 24h — Artikel ändern sich nach Publish quasi nie.
_NEWS_ARTICLE_CACHE = {}                     # key = sha256(url)[:24] → (expires_at, payload)
try:
    import threading as _news_threading
    _NEWS_ARTICLE_CACHE_LOCK = _news_threading.Lock()
except Exception:
    _NEWS_ARTICLE_CACHE_LOCK = None


def _news_article_cache_get(url):
    """Cache-Lookup; gibt None bei Miss/Stale zurück."""
    import time as _t
    import hashlib as _hl
    key = _hl.sha256(url.encode('utf-8', errors='replace')).hexdigest()[:24]
    if _NEWS_ARTICLE_CACHE_LOCK:
        _NEWS_ARTICLE_CACHE_LOCK.acquire()
    try:
        rec = _NEWS_ARTICLE_CACHE.get(key)
        if not rec:
            return None
        exp, payload = rec
        if exp <= _t.time():
            _NEWS_ARTICLE_CACHE.pop(key, None)
            return None
        return payload
    finally:
        if _NEWS_ARTICLE_CACHE_LOCK:
            _NEWS_ARTICLE_CACHE_LOCK.release()


def _news_article_cache_set(url, payload):
    """Cache-Insert; soft-GC bei >800 Einträgen (älteste 200 raus)."""
    import time as _t
    import hashlib as _hl
    key = _hl.sha256(url.encode('utf-8', errors='replace')).hexdigest()[:24]
    if _NEWS_ARTICLE_CACHE_LOCK:
        _NEWS_ARTICLE_CACHE_LOCK.acquire()
    try:
        _NEWS_ARTICLE_CACHE[key] = (_t.time() + NEWS_ARTICLE_CACHE_TTL_SECONDS, payload)
        if len(_NEWS_ARTICLE_CACHE) > 800:
            oldest = sorted(_NEWS_ARTICLE_CACHE.items(), key=lambda kv: kv[1][0])[:200]
            for k, _v in oldest:
                _NEWS_ARTICLE_CACHE.pop(k, None)
    finally:
        if _NEWS_ARTICLE_CACHE_LOCK:
            _NEWS_ARTICLE_CACHE_LOCK.release()


# ── Persistenter Server-Side-Cache (Supabase) ──────────────────────────────
# Der In-Memory-Cache oben (_NEWS_ARTICLE_CACHE) lebt nur pro Worker-Prozess und
# ist nach jedem Cloud-Run-Restart weg → jeder Artikel würde dann wieder pro User
# frisch gescraped, was die Server-IP bei den Quellseiten flaggt. Diese zweite
# Cache-Ebene liegt in Supabase (`news_article_cache`), wird über alle Worker und
# Restarts hinweg geteilt und sorgt dafür, dass eine Quelle pro Artikel höchstens
# ~1× pro TTL angefasst wird statt 1× pro Leser.
NEWS_ARTICLE_SB_CACHE_TTL_SECONDS = 14 * 24 * 3600   # 14 Tage — Artikel ändern sich nach Publish quasi nie.


def _news_article_url_key(url):
    """Stabiler Cache-Key: sha256(url) hex, erste 32 Zeichen."""
    import hashlib as _hl
    return _hl.sha256((url or '').encode('utf-8', errors='replace')).hexdigest()[:32]


def _news_sb_cache_get(url):
    """Persistenter Supabase-Cache-Lookup. Returns payload-dict bei frischem Hit,
    sonst None (Miss / stale / Tabelle fehlt / Fehler / Timeout). Wirft nie."""
    if not SB_AVAILABLE:
        return None
    try:
        key = _news_article_url_key(url)

        def _do():
            return (sb.table('news_article_cache')
                      .select('url, fulltext, title, source, image_url, published_at, fetched_at')
                      .eq('url_key', key).limit(1).execute())
        res, timed_out = _supabase_execute_with_timeout('news_cache_get', _do, timeout_s=5)
        if timed_out or res is None or not getattr(res, 'data', None):
            return None
        row = res.data[0]
        fulltext = row.get('fulltext')
        if not fulltext or len(fulltext) < 80:
            return None
        # Auch gecachten Text (evtl. vor dem Cruft-/Boilerplate-Fix gespeichert) am
        # Ausgang putzen — Boilerplate (Abo-Promo/Autoren-Bio) + Header-/Footer-Cruft
        # raus, sonst liefert der alte Cache den Müll zurück (Owner 2026-07-11).
        try:
            _cl = _news_strip_boilerplate(fulltext, source_host=row.get('source') or '')
            _tidied = _tidy_article_text(_cl or fulltext)
            # 30%-Notanker wie im Scrape-Pfad (Kandidaten-Putz in
            # _news_extract_fulltext): frisst der Putz fast alles weg
            # (überaggressiv/unerwartetes Layout), lieber das gecachte
            # Original liefern als einen Artikel-Torso (Audit B4).
            if _tidied and len(_tidied) >= max(80, int(len(fulltext) * 0.30)):
                fulltext = _tidied
        except Exception:
            pass
        # TTL-Prüfung gegen fetched_at.
        import time as _t
        from datetime import datetime as _dt
        fetched_raw = (row.get('fetched_at') or '').replace('Z', '+00:00')
        try:
            fetched = _dt.fromisoformat(fetched_raw)
            age = _t.time() - fetched.timestamp()
            if age > NEWS_ARTICLE_SB_CACHE_TTL_SECONDS:
                return None
        except Exception:
            # Unparsebares fetched_at → vorsichtshalber als stale behandeln.
            return None
        return {
            'ok': True,
            'url': row.get('url') or url,
            'source': row.get('source'),
            'fulltext': fulltext,
            'title': row.get('title'),
            # Self-Heal am Ausgang (Owner 2026-07-12): Alt-Einträge können noch
            # relative/http-/Pixel-URLs tragen → normalisieren statt roh liefern.
            'image_url': _news_normalize_image_url(row.get('image_url'),
                                                   base_url=row.get('url') or url),
            'published_at': row.get('published_at'),
            'cache_ttl_seconds': NEWS_ARTICLE_SB_CACHE_TTL_SECONDS,
        }
    except Exception as e:
        print(f'[news-cache] get error: {type(e).__name__}: {str(e)[:120]}')
        return None


def _news_sb_cache_set(url, payload):
    """Upsert eines extrahierten Artikels in den persistenten Supabase-Cache.
    Best-effort: jeder Fehler (Tabelle fehlt, Timeout, …) wird geschluckt, der
    Artikel wurde dem User ja trotzdem geliefert."""
    if not SB_AVAILABLE:
        return
    try:
        from datetime import datetime as _dt, timezone as _tz
        record = {
            'url_key': _news_article_url_key(url),
            'url': url,
            'fulltext': payload.get('fulltext'),
            'title': payload.get('title'),
            'source': payload.get('source'),
            'image_url': payload.get('image_url'),
            'published_at': payload.get('published_at'),
            'fetched_at': _dt.now(_tz.utc).isoformat(),
        }

        def _do():
            return sb.table('news_article_cache').upsert(record, on_conflict='url_key').execute()
        _supabase_execute_with_timeout('news_cache_set', _do, timeout_s=5)
    except Exception as e:
        print(f'[news-cache] set error: {type(e).__name__}: {str(e)[:120]}')


def _tidy_article_text(text):
    """Leichte Lesbarkeits-Politur direkt vor Caching/Ausgabe.

    Konservativ — nur eindeutiger Müll fällt raus, Redaktionstext bleibt:
      * Whitespace pro Zeile normalisieren (NBSP, Mehrfach-Spaces, Tabs).
      * Absätze durch genau eine Leerzeile trennen (max. 1 Leerzeile am Stück).
      * Offensichtliche Rest-Boilerplate-Zeilen droppen (Cookie/Consent-Hinweise,
        "Lesen Sie auch", "Mehr zum Thema", Share-Prompts, Bild-Credits "Foto: …").
    Reine String-Operation, wirft nie nach außen.
    """
    import re as _re
    if not text:
        return text

    # Kurze, eindeutig nicht-redaktionelle Zeilen (komplette Zeile = Boilerplate).
    _DROP_LINE_SUBSTR = (
        'lesen sie auch', 'mehr zum thema', 'das könnte sie auch interessieren',
        'auch interessant', 'weiterlesen', 'related articles', 'read also',
        'jetzt teilen', 'artikel teilen', 'beitrag teilen', 'share this article',
        'auf facebook teilen', 'auf twitter teilen', 'auf whatsapp teilen',
        'diesen artikel teilen', 'cookie', 'consent', 'wir verwenden cookies',
        'akzeptieren sie', 'datenschutzerklärung', 'zur startseite',
    )
    # Bild-Credit-/Caption-Präfixe (ganze Zeile beginnt damit).
    _CREDIT_PREFIX = (
        'foto:', 'fotos:', 'bild:', 'bilder:', 'photo:', 'image:', 'quelle:',
        'grafik:', 'symbolbild:', 'archivfoto:', '© ', '(c) ',
    )

    def _is_drop(line):
        low = line.strip().lower()
        if not low:
            return False
        # Reine Credit-/Caption-Zeile (kurz) → raus.
        if any(low.startswith(p) for p in _CREDIT_PREFIX) and len(low) <= 160:
            return True
        # Kurze Zeile, die voll aus einem Boilerplate-Marker besteht.
        if len(low) <= 90 and any(m in low for m in _DROP_LINE_SUBSTR):
            return True
        return False

    out_lines = []
    for raw_line in text.split('\n'):
        line = raw_line.replace('\xa0', ' ').replace('\t', ' ')
        line = _re.sub(r'[ ]{2,}', ' ', line).strip()
        if _is_drop(line):
            continue
        out_lines.append(line)

    joined = '\n'.join(out_lines)
    # Mehr als eine Leerzeile am Stück → genau eine (= ein Absatz-Abstand).
    joined = _re.sub(r'\n{3,}', '\n\n', joined)
    joined = joined.strip()

    # HEADER-/FOOTER-CRUFT (Owner 2026-07-10: „Backend scrapt+putzt, App zeigt nur"):
    # vorne ALLE kurzen Header-Zeilen VOR dem ersten echten Absatz (Quell-Label wie
    # „aeroTELEGRAPH", Ticker-Slug „ticker-condor-grun", fremde Schlagzeilen) — „kurz"
    # = < 60 Zeichen UND kein Satzzeichen-Ende; nur wenn ein echter Absatz (≥100) folgt
    # (köpft nie einen kurzen echten Artikel). Hinten Datum-/Flug-Fußzeile. Greift für
    # Reader-Proxy UND Harvest, da beide durch _tidy_article_text laufen.
    _trail_date = _re.compile(
        r'^(?:[A-Za-zÄÖÜäöü]+\s+\d{1,2},?\s+\d{4}|\d{1,2}\.\s*[A-Za-zÄÖÜäöü]+\.?\s+\d{4})$')
    _trail_flight = _re.compile(r'^(?:flug|flight)\s+[A-Z0-9]{2,8},?$', _re.IGNORECASE)
    clines = joined.split('\n')
    ci, cdrop = 0, 0
    while ci < len(clines) and cdrop < 6:
        s = clines[ci].strip()
        if not s:
            ci += 1
            continue
        if len(s) >= 60 or s.endswith(('.', '!', '?')):
            break
        if not any(len(l.strip()) >= 100 for l in clines[ci + 1:ci + 11]):
            break
        ci += 1
        cdrop += 1
    clines = clines[ci:]
    while clines:
        s = clines[-1].strip()
        if not s:
            clines.pop()
            continue
        if _trail_date.match(s) or _trail_flight.match(s):
            clines.pop()
            continue
        break

    # TRAILING „Verwandte Artikel"-Liste kappen (Owner 2026-07-11): austrian_wings/
    # simpleflying hängen NACH dem Artikel eine Liste aus Headlines + Datums-Zeilen
    # bzw. Teaser („5 Questions", Feedback-Footer) an. Ansatz: letzten ECHTEN Absatz
    # finden; enthält der Schwanz danach ein Related-Signal (reine DD.MM.YYYY-Zeile,
    # „5 Questions", „Found an error"), alles NACH dem letzten echten Absatz kappen.
    _relb_date = _re.compile(r'^\d{1,2}\.\d{1,2}\.\d{4}$')
    last_real = -1
    for _k, _l in enumerate(clines):
        _s = _l.strip()
        if len(_s) >= 150 and _s[-1:] in '.!?"”':
            last_real = _k
    if last_real >= 0:
        _tail = clines[last_real + 1:]
        _sig = any(_relb_date.match(t.strip())
                   or t.strip().lower() in ('5 questions',)
                   or 'found an error' in t.lower()
                   for t in _tail)
        if _sig:
            clines = clines[:last_real + 1]
    return '\n'.join(clines).strip()


@app.route('/api/news/article', methods=['GET'])
def get_news_article():
    """Vollartikel-Text einer Aviation-News-URL.

    Query: ?url=<encoded article URL>
    Whitelist: aero.de, aerotelegraph.com, aerobuzz.de, aviation.direct,
               austrianwings.info, reuters.com, avherald.com, simpleflying.com,
               theaircurrent.com, flightradar24.com (jeweils +www.).
    Return:
        ok=True  → {ok, url, source, fulltext, title, image_url,
                    published_at, cache_hit, cache_ttl_seconds}
        ok=False → {ok:false, error, [detail]} mit passendem HTTP-Status.
    Cache: 24h pro URL, in-memory.
    """
    from urllib.parse import urlparse, unquote
    raw_url = request.args.get('url') or ''
    raw_url = unquote(raw_url).strip()
    if not raw_url:
        return jsonify({'ok': False, 'error': 'missing_url'}), 400
    try:
        parsed = urlparse(raw_url)
    except Exception:
        return jsonify({'ok': False, 'error': 'invalid_url'}), 400
    if parsed.scheme not in ('http', 'https'):
        return jsonify({'ok': False, 'error': 'invalid_scheme'}), 400
    host = (parsed.netloc or '').lower().split(':')[0]
    # SSRF-Schutz: nur Whitelist-Hosts (keine Subdomain-Spoofs wie aero.de.evil.com,
    # weil exact-Match auf den ganzen netloc geprüft wird).
    if host not in NEWS_ARTICLE_ALLOWED_HOSTS:
        return jsonify({
            'ok': False,
            'error': 'host_not_allowed',
            'allowed_hosts': sorted(NEWS_ARTICLE_ALLOWED_HOSTS),
        }), 403

    # Ein Cache-Treffer gilt nur als „gut", wenn er SUBSTANZIELL ist. Kurze
    # Einträge (< 500 Zeichen) sind meist ein alter RSS-Teaser (vom Harvest), der
    # den vollen gescrapten Artikel verdrängt hat → NICHT ausliefern, stattdessen
    # frisch scrapen (self-heal, Owner 2026-07-10: „sieht nach RSS-Feed aus").
    def _cache_is_full(c):
        return c is not None and len((c.get('fulltext') or '')) >= 500

    # Cache hit? (L1: In-Memory pro Worker)
    cached = _news_article_cache_get(raw_url)
    if _cache_is_full(cached):
        return jsonify({**cached, 'cache_hit': True})

    # L2: Persistenter Supabase-Cache (geteilt über Worker/Restarts hinweg).
    # Bei frischem Hit liefern wir OHNE die Quellseite anzufassen → kein Re-Scrape
    # pro User, Server-IP wird nicht geflaggt. Defensiv: jeder Cache-Fehler fällt
    # still auf den Live-Scrape unten zurück.
    sb_cached = _news_sb_cache_get(raw_url)
    if _cache_is_full(sb_cached):
        result = {**sb_cached, 'cache_hit': True}
        # In den schnellen In-Memory-Cache hochziehen für Folge-Requests.
        try:
            _news_article_cache_set(raw_url, {**sb_cached, 'cache_hit': False})
        except Exception:
            pass
        return jsonify(result)

    # Fetch HTML
    try:
        import requests as _requests
        resp = _requests.get(
            raw_url,
            timeout=10,
            headers={
                'User-Agent': 'AeroX/1.0 (research-fetch; +https://aerosteuer.de)',
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                'Accept-Language': 'de-DE,de;q=0.9,en-US;q=0.7,en;q=0.5',
            },
            allow_redirects=True,
        )
        if resp.status_code != 200:
            return jsonify({
                'ok': False,
                'error': 'upstream_status',
                'status': resp.status_code,
            }), 502
        # requests entscheidet selbst via apparent_encoding wenn der Header lügt.
        if not resp.encoding or resp.encoding.lower() == 'iso-8859-1':
            resp.encoding = resp.apparent_encoding or 'utf-8'
        html = resp.text
    except Exception as e:
        print(f'[get_news_article] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'fetch_failed', 'detail': 'upstream_error'}), 502

    # Extract via mehrere Strategien, längstes valides Ergebnis gewinnt.
    # (_news_extract_best_fulltext entfernt bereits Boilerplate + Spenden-Appelle.)
    fulltext = _news_extract_best_fulltext(html, source_host=host)
    if not fulltext or len(fulltext) < 80:
        return jsonify({'ok': False, 'error': 'extraction_failed', 'url': raw_url}), 200

    # Lesbarkeits-Politur direkt vor Cache/Ausgabe (Whitespace/Absätze/Rest-Müll).
    try:
        tidied = _tidy_article_text(fulltext)
        if tidied and len(tidied) >= 80:
            fulltext = tidied
    except Exception:
        pass

    # Metadata aus <meta og:*>/<title>/<time> — base_url für relative Bilder.
    meta = _news_extract_metadata(html, base_url=raw_url)

    result = {
        'ok': True,
        'url': raw_url,
        'source': host,
        'fulltext': fulltext,
        'title': meta.get('title'),
        'image_url': meta.get('image_url'),
        'published_at': meta.get('published_at'),
        'cache_hit': False,
        'cache_ttl_seconds': NEWS_ARTICLE_CACHE_TTL_SECONDS,
    }
    _news_article_cache_set(raw_url, result)
    # Persistent in Supabase ablegen, damit die Quelle nicht pro User neu
    # gescraped wird. Best-effort — Fehler beeinflussen die Antwort nicht.
    _news_sb_cache_set(raw_url, result)
    return jsonify(result)


def _news_extract_best_fulltext(html, source_host=''):
    """Multi-Strategy-Extraktion: readability → bs4-Heuristik → Legacy-Regex.

    Jeder Kandidat wird durch `_news_strip_boilerplate` von Rest-Müll befreit
    (Nav/Share/Related/Newsletter/Cookie/Footer/Author-Bio/Promo-Cards). Es
    gewinnt der Kandidat mit der **größten bereinigten** Textlänge — NICHT der
    roh-längste, weil "viel Text" oft "viel Boilerplate" bedeutet.
    """
    candidates = []

    # PRE-CLEAN: Autoren-Bio / Artikel-Header-Meta / Excerpt-Boxen aus dem HTML
    # entfernen, BEVOR readability/bs4/legacy laufen (Owner 2026-07-11: simpleflying-
    # Bios wie „Experienced ICAO … Instructor …" landeten oben im Text, weil
    # readability sie mitzieht). Best-effort; bei Fehler bleibt das Roh-HTML.
    try:
        from bs4 import BeautifulSoup as _BS
        _s = _BS(html, 'html.parser')
        for _j in _s.select(
            '.article-header-data, .w-article-header-comp, '
            '[class*="author-bio"], [class*="author_bio"], [class*="authorBio"], '
            '.byline, [class*="contributor-bio"], '
            '.article-excerpt, .entry-excerpt, .post-excerpt'):
            _j.decompose()
        html = str(_s)
    except Exception:
        pass

    # Strategie 1: readability-lxml (Mozilla-Algorithmus)
    try:
        from readability import Document as _ReadabilityDoc  # type: ignore
        doc = _ReadabilityDoc(html)
        summary_html = doc.summary(html_partial=True)
        plain = _news_html_to_plain(summary_html)
        if plain and len(plain) >= 80:
            candidates.append(('readability', plain))
    except ImportError:
        # readability-lxml fehlt — graceful fallback auf bs4/legacy.
        pass
    except Exception:
        # readability kann auf Cloudflare-Challenges/leeren Pages crashen — skip.
        pass

    # Strategie 2: BeautifulSoup-Heuristik (article, main, .entry-content, …)
    try:
        bs_plain = _news_bs4_extract(html)
        if bs_plain and len(bs_plain) >= 80:
            candidates.append(('bs4', bs_plain))
    except Exception:
        pass

    # Strategie 3: Legacy-Regex (aero.de-tuned, funktioniert dort am besten)
    try:
        legacy = _extract_article_text(html)
        if legacy and len(legacy) >= 80:
            candidates.append(('legacy', legacy))
    except Exception:
        pass

    if not candidates:
        return ''

    # Boilerplate-Filter auf jeden Kandidaten (robust: bei Fehler Roh-Text).
    cleaned = []
    for strat, raw in candidates:
        try:
            cl = _news_strip_boilerplate(raw, source_host=source_host)
        except Exception:
            cl = raw
        # Wenn der Filter fast alles wegfrisst (überaggressiv / unerwartetes
        # Layout), lieber den Roh-Text behalten als einen leeren Artikel.
        if not cl or len(cl) < max(80, int(len(raw) * 0.30)):
            cl = raw
        cleaned.append((strat, cl))

    # Größte BEREINIGTE Länge gewinnt. Hard-Cap 20k.
    cleaned.sort(key=lambda kv: len(kv[1]), reverse=True)
    best = cleaned[0][1]
    # Spenden-/Förder-Appelle aus dem finalen Volltext entfernen.
    try:
        best = _strip_donation_appeals(best)
    except Exception:
        pass
    if len(best) > 20000:
        best = best[:20000].rsplit('\n\n', 1)[0]
    return best


# Marker für Spenden-/Solicitation-Appelle (case-insensitive substring).
# Zweistufig: "strong" = an sich schon ein Aufruf (Satz wird gedroppt sobald
# ein solcher Marker vorkommt). "weak" = Marker braucht ZUSÄTZLICH ein
# Call-to-Action-Verb im selben Satz, damit nicht jeder Artikel der z.B. "IBAN"
# oder "Newsletter" beiläufig erwähnt zerschossen wird. Bewusst konservativ.
_DONATION_MARKERS_STRONG = (
    'spendenaufruf', 'unterstützen sie uns', 'unterstütze uns',
    'jetzt unterstützen', 'jetzt unterstützen sie', 'spendenkonto',
    'werde mitglied', 'werden sie mitglied', 'werde fördermitglied',
    'support us', 'donate', 'buy us a coffee', 'buy me a coffee',
    'abonnieren sie',
)
_DONATION_MARKERS_WEAK = (
    'spende', 'paypal', 'patreon', 'steady', 'iban', 'fördermitglied',
    'newsletter', 'membership',
)
_DONATION_CTA_VERBS = (
    'unterstützen sie', 'unterstütze uns', 'unterstütz uns',
    'spenden sie', 'jetzt spenden', 'spende jetzt', 'bitte spende',
    'abonnier', 'registrier', 'klicken sie', 'helfen sie',
    'werde mitglied', 'werden sie mitglied', 'jetzt unterstützen',
    'pledge', 'please support', 'support our', 'please donate',
    'subscribe', 'join us', 'become a', 'sign up',
)


def _strip_donation_appeals(text):
    """Entfernt Spenden-/Förder-/Solicitation-Sätze aus Artikel-Volltext.

    Wirkt absatz- und satzweise: nur der konkrete anstößige Satz/Absatz fällt
    raus, der Rest bleibt erhalten. Ein Satz fliegt nur dann, wenn er einen
    eindeutigen Spenden-Marker (strong) ODER einen schwachen Marker PLUS ein
    Call-to-Action-Verb enthält. Reine String-Operation, wirft nie nach außen.
    """
    import re as _re
    if not text:
        return text

    def _is_appeal(sentence):
        low = sentence.lower()
        if any(m in low for m in _DONATION_MARKERS_STRONG):
            return True
        if any(m in low for m in _DONATION_MARKERS_WEAK):
            if any(v in low for v in _DONATION_CTA_VERBS):
                return True
        return False

    out_lines = []
    for line in text.split('\n'):
        if not line.strip():
            out_lines.append(line)
            continue
        # Satzweise splitten (Satzende-Zeichen + Whitespace), Trenner behalten.
        parts = _re.split(r'(?<=[.!?])\s+', line)
        kept = [p for p in parts if not _is_appeal(p)]
        if not kept:
            # Ganze Zeile war Appell → als Leerzeile droppen.
            continue
        out_lines.append(' '.join(kept).strip())

    joined = '\n'.join(out_lines)
    joined = _re.sub(r'\n{3,}', '\n\n', joined)
    return joined.strip()


# Zeilen-Marker für Boilerplate (Nav/Share/Related/Newsletter/Cookie/Footer).
