    'jetzt anmelden', 'kostenlos registrieren',
    # Social / Share
    'teilen auf', 'jetzt teilen', 'share this', 'share on', 'auf facebook',
    'auf twitter', 'auf whatsapp', 'auf linkedin', 'follow us', 'folge uns',
