def _roster_snapshot_path(token):
    import os, re
    if not token: return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe: return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'roster_snapshot_{safe}.json')


def _roster_changes_path(token):
    import os, re
    if not token: return None
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    if not safe: return None
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, f'roster_changes_{safe}.json')


# ── Roster-Snapshot: Supabase-first mit Disk-Fallback ────────────────────
# Multi-Agent-Review 2026-06-10 (Welle A): Snapshots lagen NUR auf der Disk der
# schreibenden Cloud-Run-Instanz. Bei >1 Instanz (Skalierung auf viele User)
# oder Container-Wipe sah die lesende Instanz nichts → Friends-Roster leer.
# Tabelle: supabase_migrations/20260610_roster_snapshots.sql. Fehlt sie noch,
# degradiert alles sauber auf Disk-only (kein Hard-Fail).

def _sb_roster_snapshot_upsert(token, payload):
    """Best-effort Write-Through nach Supabase. True bei Erfolg."""
    if not (SB_AVAILABLE and token and isinstance(payload, dict)):
        return False
    try:
        def _do():
            return sb.table('roster_snapshots').upsert({
                'token': token,
                'payload': payload,
                'updated_at': datetime.now(timezone.utc).isoformat(),
            }, on_conflict='token').execute()
        _supabase_execute_with_timeout('roster_snapshot_upsert', _do)
        return True
    except Exception:
        return False  # Tabelle fehlt / SB down → Disk bleibt die Quelle


def _sb_roster_snapshot_load(token):
    """Liest den Snapshot-Payload aus Supabase. None wenn nicht vorhanden."""
    if not (SB_AVAILABLE and token):
        return None
    try:
        def _do():
            return sb.table('roster_snapshots').select('payload').eq(
                'token', token).limit(1).execute()
        # _supabase_execute_with_timeout liefert (result, timed_out) — das Tupel
        # MUSS entpackt werden. Vorher: getattr(tuple,'data') == None → der SB-
        # Snapshot-Read lieferte IMMER None → friends-today/friend-roster sahen
        # nie einen Roster-Tag (Symptom: Friend im Layover als „Basis <Homebase>").
        r, _timed_out = _supabase_execute_with_timeout('roster_snapshot_load', _do)
        if _timed_out:
            # friends-today must not interpret a transport failure as an
            # authoritative "friend has no roster today" and cache the omission.
            _friends_today_worker_health_fail()
        rows = getattr(r, 'data', None) or []
        if rows:
            return rows[0].get('payload')
    except Exception:
        _friends_today_worker_health_fail()
        return None
    return None


def _roster_snapshot_save(token, payload):
    """Schreibt Snapshot nach Supabase UND Disk. True wenn mind. eines klappt."""
    sb_ok = _sb_roster_snapshot_upsert(token, payload)
    disk_ok = False
    sp = _roster_snapshot_path(token)
    if sp:
        try:
            with open(sp, 'w') as f:
                json.dump(payload, f, ensure_ascii=False)
            disk_ok = True
        except Exception:
            pass
    return sb_ok or disk_ok


def _roster_snapshot_read(token):
    """Liest Snapshot: Supabase-first (multi-instance-sicher), dann Disk."""
    payload = _sb_roster_snapshot_load(token)
    if not payload:
        sp = _roster_snapshot_path(token)
        if sp and os.path.exists(sp):
            try:
                with open(sp) as f:
                    payload = json.load(f)
            except Exception:
                payload = None
    return payload or {}


def _compute_roster_diff(old_tage, new_tage, today=None, near_added_days=10):
    """Returns list of {datum, kind, old, new} where kind ∈ added/removed/modified.

    RAUSCHREDUKTION (Jennifer Schenke 2026-07-16 „ein Haufen Dienstplanänderungen
    im Feed, teilweise für die Zukunft, verstehe nicht was geändert wurde"). Zwei
    Fluten waren die Ursache:

    1) FERNE ZUKUNFTS-'added': Veröffentlicht LH einen neuen Monat, war JEDER neue
       Tag ein 'added'-Eintrag → Flut. Das ist normales Roster-Wachstum, keine
       Änderung, die der User prüfen muss. 'added' wird darum nur für NAHE Tage
       gemeldet (heute … heute+near_added_days). Fernere neue Tage = still.

    2) ANREICHERUNGS-'modified': Der Digest verglich routing/layover_ort/Zeiten
       exakt. Das Backend reichert diese Felder aber NACH dem ersten Import an
       (leer→gefüllt) → beim nächsten Sync sah der Diff „vorher leer, jetzt
       gefüllt" und meldete JEDEN angereicherten Tag als 'modified', obwohl der
       User nichts geändert hat. Jetzt zählt ein Feld nur als geändert, wenn
       BEIDE Seiten einen nicht-leeren Wert tragen der sich UNTERSCHEIDET — ein
       leer↔gefüllt-Übergang (Anreicherung/transientes Re-Parse) ist KEINE
       Änderung. `klass` bleibt exakt verglichen (Tour↔Frei ist echte Änderung).
    """
    old_by = {t.get('datum'): t for t in (old_tage or []) if isinstance(t, dict)}
    new_by = {t.get('datum'): t for t in (new_tage or []) if isinstance(t, dict)}
    changes = []
    keys = set(old_by.keys()) | set(new_by.keys())

    def _norm(v):
        return (str(v).strip() if v is not None else '')

    def _field_changed(av, bv):
        # leer↔gefüllt zählt NICHT (Anreicherung/Re-Parse); nur ein echter
        # Wert-Wechsel zwischen zwei nicht-leeren Werten.
        a, b = _norm(av), _norm(bv)
        return bool(a) and bool(b) and a != b

    def _meaningfully_modified(a, b):
        arf, brf = (a.get('reader_facts') or {}), (b.get('reader_facts') or {})
        # klass exakt (auch leer↔gefüllt): ein Tag wird Tour / verliert Tour.
        if _norm(a.get('klass')) != _norm(b.get('klass')):
            return True
        for af, bf in ((a.get('routing'), b.get('routing')),
                       (arf.get('start_time'), brf.get('start_time')),
                       (arf.get('end_time'), brf.get('end_time')),
                       (arf.get('layover_ort'), brf.get('layover_ort'))):
            if _field_changed(af, bf):
                return True
        return False

    def _added_is_near(k):
        if not today:
            return True
        try:
            from datetime import date as _date
            d = _date.fromisoformat(k[:10]); t = _date.fromisoformat(today[:10])
            # NUR heute … heute+near_added_days melden. Fernere Zukunfts-Tage
            # (veröffentlichter neuer Monat) und nachgetragene Vergangenheit
            # (< heute) bleiben still — kein 'added'-Flut.
            return 0 <= (d - t).days <= near_added_days
        except Exception:
            return True

    for k in sorted(keys):
        a, b = old_by.get(k), new_by.get(k)
        if a is None and b is not None:
            if _added_is_near(k):
                changes.append({'datum': k, 'kind': 'added', 'new': b})
        elif b is None and a is not None:
            changes.append({'datum': k, 'kind': 'removed', 'old': a})
        elif a and b and _meaningfully_modified(a, b):
            changes.append({'datum': k, 'kind': 'modified', 'old': a, 'new': b})
    return changes


@app.route('/api/admin/wipe-calendar', methods=['POST'])
def admin_wipe_calendar():
    """Einmaliger, secret-gegateter Kalender-Wipe für GENAU EINEN User (per E-Mail).
    Löscht ALLE kalenderbezogenen Daten STRIKT token-scoped: user_ical_briefings,
    user_manual_briefings, roster_snapshots (Key 'token'), briefings + ical_events
    (Key 'user_token') sowie den gespeicherten calendar_feed im Profil. Alles andere
    (Freunde/Avatare/Chats/Steuer/Licenses) bleibt unberührt — gleiche Token-Scoping-
    Logik wie der DSGVO-Account-Delete-Cascade.
    Auth: Header `X-Wipe-Secret` == env `WIPE_ADMIN_SECRET`. Ist die Env-Var nicht
    gesetzt, antwortet der Endpoint IMMER 403 (inert by default). Nach Gebrauch die
    Env-Var wieder entfernen → Endpoint dauerhaft inert.
    """
    import hmac as _hmac
    secret_env = (os.environ.get('WIPE_ADMIN_SECRET') or '').strip()
    got = (request.headers.get('X-Wipe-Secret') or '').strip()
    if not secret_env or not _hmac.compare_digest(got, secret_env):
        return jsonify({'ok': False, 'error': 'forbidden'}), 403
    body = request.get_json(silent=True) or {}
    email = (body.get('email') or '').strip().lower()
    if not email:
        return jsonify({'ok': False, 'error': 'email_required'}), 400
    if not (SB_AVAILABLE and sb is not None):
        return jsonify({'ok': False, 'error': 'supabase_unavailable'}), 503
    # 1) Token per E-Mail auflösen (auth_users) — limit(1), striktes Match.
    try:
        r = sb.table('auth_users').select('*').eq('email', email).limit(1).execute()
        rows = getattr(r, 'data', None) or []
        if not rows:
            return jsonify({'ok': False, 'error': 'user_not_found'}), 404
        token = (rows[0].get('token') or '').strip()
        if not token:
            return jsonify({'ok': False, 'error': 'no_token_for_user'}), 404
    except Exception as e:
        # Detail nur server-side (Audit 2026-07-01) — auch secret-gated Endpoints
        # geben keine Exception-Interna an den Client zurück.
        try:
            app.logger.error(f'[admin-wipe] auth lookup failed: '
                             f'{type(e).__name__}: {str(e)[:300]}')
        except Exception:
            pass
        return jsonify({'ok': False, 'error': 'auth_lookup_failed'}), 500
    # 2) Kalender-Tabellen token-scoped leeren (best-effort je Tabelle).
    deleted = {}
    cal_tables = [
        ('user_ical_briefings', 'token'),
        ('user_manual_briefings', 'token'),
        ('roster_snapshots', 'token'),
        ('briefings', 'user_token'),
        ('ical_events', 'user_token'),
    ]
    for tbl, col in cal_tables:
        try:
            _r = sb.table(tbl).delete().eq(col, token).execute()
            deleted[tbl] = len((_r and getattr(_r, 'data', None)) or [])
        except Exception as e:
            deleted[tbl] = f'error:{type(e).__name__}'
            app.logger.warning(f'[wipe-cal] {tbl}_fail: {str(e)[:120]}')
    # 3) Gespeicherten calendar_feed im Profil entfernen (sonst re-importiert der
    #    Client evtl. den alten Feed). profile-jsonb + top-level backwards-compat.
    try:
        disk_full = dict(_profile_load_from_disk(token) or {})
        disk_full['token'] = token
        profile = dict(disk_full.get('profile') or {})
        profile.pop('calendar_feed', None)
        disk_full.pop('calendar_feed', None)
        disk_full['profile'] = profile
        disk_full['_updated_at'] = datetime.now().isoformat()
        _profile_save(token, profile, full_disk_payload=disk_full)
        deleted['profile.calendar_feed'] = 'cleared'
    except Exception as e:
        deleted['profile.calendar_feed'] = f'error:{type(e).__name__}'
        app.logger.warning(f'[wipe-cal] profile_feed_fail: {str(e)[:120]}')
    # 4) Ephemere Disk-Fallback-Dateien sicherheitshalber löschen.
    try:
        for _p in (_ical_briefings_path(token), _briefing_path(token),
                   _roster_snapshot_path(token)):
            if _p and os.path.exists(_p):
                os.remove(_p)
    except Exception:
        pass
    app.logger.info(f'[wipe-cal] done email={email} token={token[:6]}… deleted={deleted}')
    return jsonify({'ok': True, 'email': email, 'token_prefix': token[:6],
                    'deleted': deleted})


@app.route('/api/user/roster-snapshot/<token>', methods=['POST'])
def take_roster_snapshot(token):
    """Speichert aktuellen tage_detail-Stand als Snapshot. Vergleicht mit vorigem Snapshot
    und persistiert Diff als pending changes.
    """
    body = request.get_json(silent=True) or {}
    sess = _store.get(token) or {}
    rd = sess.get('result_data') or {}
    new_tage = rd.get('_tage_detail') or []
    # AeroX (Crew-App) liefert sein iCal-geparstes Roster DIREKT im Body mit — es
    # durchlaeuft nicht die Tax-Pipeline, also ist _store leer. Ohne das war der
    # gespeicherte Snapshot leer → Friends sahen NIE den Plan. Body hat Vorrang.
    # Shape je Tag: {datum, klass, marker, routing, eur?, reader_facts:{layover_ort,
    # start_time, end_time}}. Defensiv: nur dicts mit datum, Cap 400.
    body_tage = body.get('tage') or body.get('tage_detail')
    if isinstance(body_tage, list):
        clean = [t for t in body_tage if isinstance(t, dict) and t.get('datum')][:400]
        if clean:
            new_tage = clean
    if not _roster_snapshot_path(token):
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    old_tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    # ERSTE Baseline (noch kein Snapshot vorhanden): NICHT alle Tage als „added"
    # melden — das flutete den User mit Hunderten Pseudo-Änderungen (User
    # 2026-06-29: „dachte mein Plan wird per Push verbunden"). Beim allerersten
    # Push nur still die Baseline setzen, Diff bleibt leer. Änderungen erst ab
    # dem ZWEITEN Push (echter Vorher/Nachher-Vergleich).
    _today_ymd = None
    try:
        _today_ymd = _airport_local_now('FRA').strftime('%Y-%m-%d')
    except Exception:
        _today_ymd = datetime.now().strftime('%Y-%m-%d')
    diff = _compute_roster_diff(old_tage, new_tage, today=_today_ymd) if old_tage else []
    # Persist new snapshot (Supabase-first + Disk, multi-instance-sicher)
    if not _roster_snapshot_save(token, {
        'taken_at': datetime.now().isoformat(), 'tage': new_tage,
    }):
        return jsonify({'ok': False, 'error': 'snapshot_persist_failed'}), 500
    # Crews-on-Flight: Flugnummer-Assignments aus dem neuen Snapshot ingesten
    # (best-effort, wirft nie). Speist /api/crew/flight-Lookup.
    _crew_flight_ingest(token, new_tage)
    # Crew-Graph: aus dem frisch geschriebenen crew_flight_assignments-Index die
    # Same-Flight-Overlap-Kanten neu berechnen (best-effort, wirft nie,
    # idempotenter SET-Upsert). Erst NACH _crew_flight_ingest, damit die eigenen
    # Assignments schon sichtbar sind.
    try:
        from blueprints.crew_graph_blueprint import rebuild_overlap_edges
        rebuild_overlap_edges(token, new_tage)
    except Exception as _cg_e:
        app.logger.warning(f'[crew-graph] snapshot_rebuild_fail {type(_cg_e).__name__}: {str(_cg_e)[:120]}')
    # Append diff to changes log
    cp = _roster_changes_path(token)
    try:
        try:
            with open(cp) as f: existing = json.load(f)
        except FileNotFoundError:
            existing = {'pending': [], 'history': []}
        pending = existing.get('pending') or []
        for ch in diff:
            ch['detected_at'] = datetime.now().isoformat()
            ch['status'] = 'pending'
            pending.append(ch)
        existing['pending'] = pending
        with open(cp, 'w') as f: json.dump(existing, f, ensure_ascii=False)
    except Exception as e:
        print(f'[take_roster_snapshot] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    if diff:
        try:
            n = len(diff)
            kinds = {c.get('kind') for c in diff}
            if n == 1:
                body = 'Eine Änderung im Dienstplan erkannt — bitte prüfen.'
            else:
                body = f'{n} Änderungen im Dienstplan erkannt — bitte prüfen.'
            # Lockscreen-Buttons (Annehmen/Ablehnen): category='DUTY_CHANGE'
            # matcht EXAKT die in iOS registrierte UNNotificationCategory
            # (PushService.registerActionCategories). roster_change_id = stabile
            # Änderungs-ID im iOS-Handler-Contract (respondRosterChange:
            # changeId == datum des Changes; '*' = alle pending — beides findet
            # /api/user/roster-changes/<token>/decide wieder). Die Buttons
            # bestätigen NUR Kenntnisnahme (pending → history + Baseline),
            # sie mutieren NIE den Dienstplan selbst.
            change_id = (diff[0].get('datum') or '*') if n == 1 else '*'
            _push_notify_async(token, 'Dienstplan-Änderung', body,
                               data={'type': 'roster_change',
                                     'roster_change_id': str(change_id)},
                               category='DUTY_CHANGE',
                               idempotency_key=(
                                   f'roster-change:{token}:{change_id}:'
                                   f'{_hashlib.sha256(body.encode()).hexdigest()[:12]}'))
        except Exception:
            pass
    return jsonify({'ok': True, 'changes_count': len(diff), 'changes': diff})


@app.route('/api/user/roster-changes/<token>', methods=['GET'])
def get_roster_changes(token):
    """Liste aller pending + history Roster-Änderungen."""
    cp = _roster_changes_path(token)
    if not cp: return jsonify({'error': 'invalid token'}), 400
    try:
        with open(cp) as f: data = json.load(f)
    except FileNotFoundError:
        data = {'pending': [], 'history': []}
    return jsonify({
        'pending': data.get('pending') or [],
        'history': (data.get('history') or [])[-50:],
    })


@app.route('/api/user/roster-changes/<token>/decide', methods=['POST'])
def decide_roster_change(token):
    """Body: {datum, decision: 'accept'|'reject'} — verschiebt Change von pending → history."""
    body = request.get_json(silent=True) or {}
    datum = body.get('datum')
    decision = (body.get('decision') or '').lower()
    if decision not in ('accept', 'reject'):
        return jsonify({'ok': False, 'error': 'invalid_decision'}), 400
    cp = _roster_changes_path(token)
    if not cp: return jsonify({'ok': False, 'error': 'invalid token'}), 400
    try:
        with open(cp) as f: data = json.load(f)
    except FileNotFoundError:
        return jsonify({'ok': False, 'error': 'no_changes'}), 404
    pending = data.get('pending') or []
    # BULK (User 2026-06-29: „alle auf einmal akzeptieren oder ablehnen, sonst
    # sammeln sich tausend an"): datum='*' ODER all=true → ALLE pending auf einmal
    # entscheiden und nach history verschieben.
    if body.get('all') or datum in ('*', None, ''):
        now_iso = datetime.now().isoformat()
        for c in pending:
            c['decision'] = decision; c['decided_at'] = now_iso
            c['status'] = decision + 'ed'
        history = (data.get('history') or []) + pending
        data['pending'] = []
        data['history'] = history[-500:]   # history deckeln, sonst wächst sie ewig
        try:
            with open(cp, 'w') as f: json.dump(data, f, ensure_ascii=False)
        except Exception as e:
            print(f'[decide_roster_change] error: {type(e).__name__}: {str(e)[:300]}')
            return jsonify({'ok': False, 'error': 'internal_error'}), 500
        return jsonify({'ok': True, 'decided': len(pending), 'pending_remaining': 0})
    matched = next((c for c in pending if c.get('datum') == datum), None)
    if not matched:
        return jsonify({'ok': False, 'error': 'change_not_found'}), 404
    matched['decision'] = decision
    matched['decided_at'] = datetime.now().isoformat()
    matched['status'] = decision + 'ed'
    data['pending'] = [c for c in pending if c.get('datum') != datum]
    history = data.get('history') or []
    history.append(matched)
    data['history'] = history
    try:
        with open(cp, 'w') as f: json.dump(data, f, ensure_ascii=False)
    except Exception as e:
        print(f'[decide_roster_change] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    # Snapshot-Baseline aktualisieren — sonst würde der nächste Snapshot den
    # gleichen Diff erneut als "pending" detektieren. Bei 'accept' nehmen wir
    # den neuen Wert in den Baseline-Snapshot auf; bei 'reject' wird der alte
    # Wert beibehalten (User sagt "die Änderung ist falsch / wird zurückgenommen").
    try:
        sp = _roster_snapshot_path(token)
        if sp and os.path.exists(sp):
            with open(sp) as f: snap = json.load(f)
            snap_tage = snap.get('tage') or []
            kind = matched.get('kind')
            new_payload = matched.get('new') or {}
            old_payload = matched.get('old') or {}
            keep_value = new_payload if decision == 'accept' else old_payload
            idx = next((i for i, t in enumerate(snap_tage) if t.get('datum') == datum), None)
            if kind == 'removed' and decision == 'accept':
                # Tag wurde tatsächlich entfernt → aus Baseline raus
                if idx is not None:
                    snap_tage.pop(idx)
            elif kind == 'added':
                # 'accept' = neuer Tag bleibt (ist schon im neuen tage_detail);
                # 'reject' = User behauptet er sei nicht hinzugekommen → trotzdem
                # in Baseline aufnehmen damit es nicht erneut als "added" gemeldet wird.
                if idx is None and keep_value:
                    snap_tage.append(keep_value)
            elif kind == 'modified':
                if idx is not None and keep_value:
                    snap_tage[idx] = keep_value
                elif keep_value:
                    snap_tage.append(keep_value)
            snap['tage'] = snap_tage
            snap['baseline_updated_at'] = datetime.now().isoformat()
            with open(sp, 'w') as f: json.dump(snap, f, ensure_ascii=False)
    except Exception as e:
        app.logger.warning(f'[roster-decide] baseline merge failed: {e}')
    return jsonify({'ok': True})


# ─── Crash-Reporting Endpoint ───────────────────────────────────────────────

@app.route('/api/crash-report', methods=['POST'])
def post_crash_report():
    """Empfängt Crash-Reports vom iOS-Client. Speichert in JSON-Log.
    Body: {token?, error_type, message, stack, device, ios, app_version, build, ts}
    """
    body = request.get_json(silent=True) or {}
    if not isinstance(body, dict):
        return jsonify({'ok': False, 'error': 'body_must_be_object'}), 400
    if len(json.dumps(body)) > 32_000:
        return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
    import os
    crash_dir = os.path.join(_USER_HISTORY_DIR, 'crashes')
    os.makedirs(crash_dir, exist_ok=True)
    fname = f'crash_{datetime.now().strftime("%Y%m%d_%H%M%S_%f")}.json'
    try:
        body['received_at'] = datetime.now().isoformat()
        with open(os.path.join(crash_dir, fname), 'w') as f:
            json.dump(body, f, ensure_ascii=False)
    except Exception as e:
        print(f'[post_crash_report] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True})


# ─── MetricKit-Diagnostik-Intake (Crash/Hang-Telemetrie, iOS) ────────────────
#
# Empfängt MXCrashDiagnostic/MXHangDiagnostic-Reports vom iOS-Client
# (Storage/CrashTelemetry.swift). Motivation: ein Tester-Freeze wurde nur per
# Mundpropaganda bekannt — MetricKit sieht Watchdog-Kills + Hangs, die der
# In-Process-CrashHandler (/api/crash-report oben) nicht abfangen kann.
#
# Auth: KEIN Token-Binding — Crashes können vor/ohne Login passieren. Das
# BUG-004-Gate greift hier nicht (kein AT-…-Segment im PFAD; das optionale
# Bearer-Token im Header inspiziert das Gate nicht) → kein Whitelist-Eintrag
# nötig. Größen-Cap 512 KB ist der Anti-Abuse-Layer.
#
# Persistenz: Supabase `ax_crash_reports` (Migration
# supabase_migrations/20260702_crash_reports.sql — manuell im SQL-Editor
# ausführen). Fehlt die Tabelle / ist SB down → degradiert zu Logging-only
# (kompakte Zeile in stdout), Request gilt trotzdem als ok (Pattern wie
# _sb_roster_snapshot_upsert).

_MK_MAX_BODY_BYTES = 512 * 1024

# Alert-Throttle: max. 1 Mail pro Stunde pro (kind, app build) — in-process
# TTL-Dict (Pattern wie _ip_rate_buckets; per-Instanz reicht: Cloud Run läuft
# hier praktisch single-instance, und im Worst Case kommen ein paar Mails mehr,
# nie ein Sturm pro Instanz).
_MK_ALERT_LAST_SENT = {}     # (kind, build) -> unix ts
_MK_ALERT_TTL_SEC = 3600


def _mk_top_frames(call_stack, limit=5):
    """Zieht die obersten Frames aus einem MetricKit-callStackTree-JSON.

    Struktur: {"callStacks": [{"callStackRootFrames": [{"binaryName": …,
    "offsetIntoBinaryTextSegment": …, "subFrames": […]}]}]} — wir laufen die
    erste Root-Kette entlang. Bei truncated Stacks (String statt Objekt) → [].
    """
    frames = []
    try:
        if not isinstance(call_stack, dict):
            return frames
        stacks = call_stack.get('callStacks') or []
        if not stacks:
            return frames
        node_list = stacks[0].get('callStackRootFrames') or []
        while node_list and len(frames) < limit:
            node = node_list[0]
            binary = node.get('binaryName') or '?'
            offset = node.get('offsetIntoBinaryTextSegment')
            frames.append(f'{binary} +{offset}' if offset is not None else binary)
            node_list = node.get('subFrames') or []
    except Exception:
        pass
    return frames


def _mk_send_alert_email(row, top_frames):
    """Alert-Mail an SUPPORT_NOTIFY_EMAIL via Resend (Pattern wie
    _send_support_email_notification). Failures nur loggen."""
    api_key = os.environ.get('RESEND_API_KEY', '').strip()
    to_email = os.environ.get('SUPPORT_NOTIFY_EMAIL', 'miguel.schumann@icloud.com').strip()
    if not api_key:
        print('[mk-alert] RESEND_API_KEY nicht gesetzt — überspringe Alert-Mail')
        return
    try:
        import urllib.request
        import html as _html
        kind = row.get('kind', '?')
        ver = f"{row.get('app_version', '?')} ({row.get('build', '?')})"
        payload_obj = row.get('payload') or {}
        detail_bits = []
        if kind == 'crash':
            for k in ('exception_type', 'exception_code', 'signal'):
                v = payload_obj.get(k)
                if v is not None:
                    detail_bits.append(f'{k}={v}')
            if payload_obj.get('termination_reason'):
                detail_bits.append(str(payload_obj['termination_reason'])[:200])
        else:
            dur = payload_obj.get('hang_duration_s')
            if dur is not None:
                detail_bits.append(f'hang {round(float(dur), 1)}s')
        e = _html.escape
        frames_html = ''.join(f'<li><code>{e(f)}</code></li>' for f in top_frames) or '<li>—</li>'
        subject = f"[AeroX {kind.upper()}] {ver} · {row.get('os', '?')}"
        # Subject header-safe halten (kein CRLF aus payload-Strings).
        subject = subject.replace('\r', ' ').replace('\n', ' ')[:200]
        html_body = (
            f"<h2 style='font-family:sans-serif'>AeroX {e(kind)} report</h2>"
            f"<p style='font-family:sans-serif;color:#444'>"
            f"<b>App:</b> {e(ver)}<br>"
            f"<b>OS:</b> {e(str(row.get('os', '?')))} · <b>Device:</b> {e(str(row.get('device', '?')))}<br>"
            f"<b>User:</b> {e(str(row.get('user_token') or 'anonym'))}<br>"
            f"<b>Detail:</b> {e(' · '.join(detail_bits) or '—')}"
            f"</p>"
            f"<p style='font-family:sans-serif'><b>Top-Frames:</b></p>"
            f"<ol style='font-family:monospace;font-size:13px'>{frames_html}</ol>"
            f"<p style='font-family:sans-serif;font-size:12px;color:#888'>"
            f"Voller Report in Supabase <code>ax_crash_reports</code> "
            f"(throttled: max. 1 Mail/h pro Kind+Build).</p>"
        )
        payload = json.dumps({
            'from': 'AeroX Crash <support@aerosteuer.de>',
            'to': [to_email],
            'subject': subject,
            'html': html_body,
        }).encode()
        req = urllib.request.Request(
            'https://api.resend.com/emails',
            data=payload,
            headers={'Authorization': f'Bearer {api_key}', 'Content-Type': 'application/json',
                     'User-Agent': 'AeroX-Backend/1.0'},
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            if 200 <= resp.status < 300:
                print(f'[mk-alert] {kind} alert sent to {to_email}')
            else:
                print(f'[mk-alert] unexpected status {resp.status}')
    except Exception as e:
        print(f'[mk-alert] send fail: {e}')


@app.route('/api/telemetry/diagnostics', methods=['POST'])
def post_telemetry_diagnostics():
    """MetricKit-Diagnostik vom iOS-Client (1 Report pro POST).

    Body (JSON, vom Client auf ~256 KB gecappt):
      kind ('crash'|'hang'), app_version, build, os, device, platform_arch,
      ts_begin/ts_end, call_stack (callStackTree-JSON, ggf. als truncated
      String + call_stack_truncated), crash: exception_type/-code, signal,
      termination_reason, vm_region_info · hang: hang_duration_s.
    Optionales Bearer-Token im Authorization-Header (kein Binding/Validierung
    — nur zur Zuordnung gespeichert).
    """
    # Größen-Cap ZUERST (Content-Length wenn gesetzt, sonst gelesene Bytes) —
    # vor jedem JSON-Parse, damit ein 50-MB-Body nicht erst geparsed wird.
    if (request.content_length or 0) > _MK_MAX_BODY_BYTES:
        return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
    raw = request.get_data(cache=True) or b''
    if len(raw) > _MK_MAX_BODY_BYTES:
        return jsonify({'ok': False, 'error': 'payload_too_large'}), 413
    body = request.get_json(silent=True)
    if not isinstance(body, dict):
        return jsonify({'ok': False, 'error': 'body_must_be_object'}), 400
    kind = str(body.get('kind') or '').strip().lower()
    if kind not in ('crash', 'hang'):
        return jsonify({'ok': False, 'error': 'kind_must_be_crash_or_hang'}), 400

    # Optionales Bearer-Token — NICHT validiert (Crash kann vor Login passieren),
    # nur format-geprüft gespeichert, damit kein Müll in die Spalte läuft.
    user_token = None
    auth = request.headers.get('Authorization', '')
    if auth.startswith('Bearer '):
        cand = auth[7:].strip()
        if cand.startswith('AT-') and len(cand) <= 256:
            user_token = cand

    row = {
        'created_at': datetime.now(timezone.utc).isoformat(),
        'user_token': user_token,
        'app_version': str(body.get('app_version') or '')[:64],
        'build': str(body.get('build') or '')[:64],
        'os': str(body.get('os') or '')[:64],
        'device': str(body.get('device') or '')[:64],
        'kind': kind,
        'payload': body,
    }

    # Persistenz best-effort: Supabase-Insert; Tabelle fehlt / SB down →
    # Logging-only-Fallback (Report ist dann wenigstens in Cloud-Run-Logs).
    stored = False
    if SB_AVAILABLE:
        try:
            def _do():
                return sb.table('ax_crash_reports').insert(row).execute()
            res, failed = _supabase_execute_with_timeout('mk_diag_insert', _do)
            stored = not failed
        except Exception as e:
            print(f'[mk-diag] sb insert fail ({type(e).__name__}: {str(e)[:200]}) — logging only')
    if not stored:
        try:
            print(f'[mk-diag] FALLBACK-LOG {json.dumps(row, ensure_ascii=False)[:4000]}')
        except Exception:
            print(f'[mk-diag] FALLBACK-LOG kind={kind} version={row["app_version"]} build={row["build"]}')

    # Alert-Mail — throttled auf 1/h pro (kind, build).
    top_frames = _mk_top_frames(body.get('call_stack'))
    throttle_key = (kind, row['build'])
    now_ts = datetime.utcnow().timestamp()
    last = _MK_ALERT_LAST_SENT.get(throttle_key, 0)
    if now_ts - last >= _MK_ALERT_TTL_SEC:
        _MK_ALERT_LAST_SENT[throttle_key] = now_ts
        if len(_MK_ALERT_LAST_SENT) > 500:   # Dict klein halten
            _MK_ALERT_LAST_SENT.clear()
            _MK_ALERT_LAST_SENT[throttle_key] = now_ts
        _mk_send_alert_email(row, top_frames)
    else:
        print(f'[mk-diag] alert throttled (kind={kind} build={row["build"]}, '
              f'next in {int(_MK_ALERT_TTL_SEC - (now_ts - last))}s)')

    return jsonify({'ok': True, 'stored': stored})


# ─── Voice-Notes Storage (Per-Day Audio) ────────────────────────────────────

def _voice_note_path(token, datum):
    import os, re
    if not token: return None
    safe_t = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
    safe_d = re.sub(r'[^0-9-]', '', datum or '')[:10]
    if not safe_t or not safe_d: return None
    voice_dir = os.path.join(_USER_HISTORY_DIR, 'voice_notes', safe_t)
    os.makedirs(voice_dir, exist_ok=True)
    return os.path.join(voice_dir, f'{safe_d}.m4a')


# ── Voice-Notes durable storage (P1, 2026-07-02) ──
# Die .m4a-Aufnahmen lagen NUR auf ephemeral Disk (voice_notes/<token>/<datum>.m4a)
# → jeder Cloud-Run-Redeploy wipte sie. Wie Avatare: Bytes nach R2 (Zero-Egress,
# durabel), Metadata (r2_key/mime/size) in Supabase-Tabelle user_voice_notes.
# Read: SB-Metadata → R2-Bytes, sonst deterministischer Key → R2, sonst Disk.
# Der R2-Key ist deterministisch (voice/<token>/<datum>.m4a), damit die Bytes
# auch ohne SB-Metadata (Tabelle noch nicht angelegt) auffindbar bleiben.

def _voice_note_r2_key(token, datum):
    import re
    safe_t = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    safe_d = re.sub(r'[^0-9-]', '', datum or '')[:10]
    if not safe_t or not safe_d:
        return None
    return f'voice/{safe_t}/{safe_d}.m4a'


def _voice_note_meta_upsert(token, datum, r2_key, mime, size_bytes):
    if not SB_AVAILABLE or not token or not datum:
        return False
    try:
        sb.table('user_voice_notes').upsert({
            'token': token, 'day_key': datum[:10], 'r2_key': r2_key,
            'mime': mime or 'audio/mp4', 'size_bytes': int(size_bytes or 0),
        }, on_conflict='token,day_key').execute()
        return True
    except Exception as e:
        if _sb_table_is_missing('user_voice_notes', e):
            return False
        app.logger.error(f'[voice-note] sb_meta_fail tok={token[:8]}: {str(e)[:160]}')
        return False


def _voice_note_meta_get(token, datum):
    if not SB_AVAILABLE or not token or not datum:
        return None
    try:
        r = (sb.table('user_voice_notes').select('*')
             .eq('token', token).eq('day_key', datum[:10]).limit(1).execute())
        rows = r.data or []
        return rows[0] if rows else None
    except Exception as e:
        if not _sb_table_is_missing('user_voice_notes', e):
            app.logger.warning(f'[voice-note] sb_meta_get_fail: {str(e)[:120]}')
        return None


def _voice_note_meta_list(token):
    """Liste der Tage mit Voice-Note (SB). None bei SB-down/Tabelle-fehlt."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('user_voice_notes').select('day_key')
             .eq('token', token).execute())
        return sorted({str(row.get('day_key')) for row in (r.data or [])
                       if row.get('day_key')})
    except Exception as e:
        if not _sb_table_is_missing('user_voice_notes', e):
            app.logger.warning(f'[voice-note] sb_meta_list_fail: {str(e)[:120]}')
        return None


def _voice_note_meta_delete(token, datum):
    if not SB_AVAILABLE or not token or not datum:
        return False
    try:
        sb.table('user_voice_notes').delete().eq('token', token).eq('day_key', datum[:10]).execute()
        return True
    except Exception as e:
        if not _sb_table_is_missing('user_voice_notes', e):
            app.logger.warning(f'[voice-note] sb_meta_del_fail: {str(e)[:120]}')
        return False


@app.route('/api/user/voice-note/<token>/<datum>', methods=['POST'])
def upload_voice_note(token, datum):
    """Upload M4A Voice-Note für einen Flugtag. Max 60s / 2 MB.
    Durabel: Bytes → R2, Metadata → SB (user_voice_notes). Disk-Mirror best-effort."""
    p = _voice_note_path(token, datum)
    if not p: return jsonify({'ok': False, 'error': 'invalid_path'}), 400
    audio = request.files.get('audio')
    if not audio:
        return jsonify({'ok': False, 'error': 'no_audio_file'}), 400
    data = audio.read()
    if len(data) > 2 * 1024 * 1024:
        return jsonify({'ok': False, 'error': 'audio_too_large'}), 413
    mime = getattr(audio, 'mimetype', None) or 'audio/mp4'
    # 1) Bytes durabel nach R2 (wie Avatare).
    r2_key = _voice_note_r2_key(token, datum)
    r2_ok = False
    if R2_AVATARS_ENABLED and r2_key:
        try:
            _r2_put_bytes(r2_key, data, mime)
            r2_ok = True
        except Exception as e:
            app.logger.warning(f'[voice-note] r2_put_fail: {str(e)[:120]}')
    # 2) Metadata nach SB (nur wenn Bytes sicher in R2 liegen).
    if r2_ok:
        _voice_note_meta_upsert(token, datum, r2_key, mime, len(data))
    # 3) Disk-Mirror/Fallback (best-effort; einzige Sicherung wenn R2 aus).
    disk_ok = False
    try:
        with open(p, 'wb') as f: f.write(data)
        disk_ok = True
    except Exception as e:
        print(f'[upload_voice_note] disk_save_fail (ok wenn R2 lief): {type(e).__name__}: {str(e)[:300]}')
    if not (r2_ok or disk_ok):
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True, 'datum': datum, 'size_kb': len(data) // 1024})


@app.route('/api/user/voice-note/<token>/<datum>', methods=['GET'])
def get_voice_note(token, datum):
    import os
    # 1) SB-Metadata → R2-Key (bevorzugt), sonst deterministischer Key → R2-Bytes.
    meta = _voice_note_meta_get(token, datum)
    r2_key = (meta or {}).get('r2_key') or _voice_note_r2_key(token, datum)
    mime = (meta or {}).get('mime') or 'audio/mp4'
    if R2_AVATARS_ENABLED and r2_key:
        raw, ct = _r2_get_bytes(r2_key)
        if raw:
            from flask import Response
            return Response(raw, mimetype=ct or mime)
    # 2) Disk-Fallback (M4A-Container mit AAC → audio/mp4 ist semantisch korrekt).
    p = _voice_note_path(token, datum)
    if p and os.path.exists(p):
        from flask import send_file
        return send_file(p, mimetype='audio/mp4', conditional=True)
    return jsonify({'error': 'not_found'}), 404


@app.route('/api/user/voice-note/<token>/<datum>', methods=['DELETE'])
def delete_voice_note(token, datum):
    import os
    # R2-Bytes + SB-Metadata + Disk-Mirror löschen (alle best-effort).
    r2_key = _voice_note_r2_key(token, datum)
    if R2_AVATARS_ENABLED and r2_key:
        _r2_delete_key(r2_key)
    _voice_note_meta_delete(token, datum)
    p = _voice_note_path(token, datum)
    try:
        if p and os.path.exists(p): os.remove(p)
    except Exception as e:
        print(f'[delete_voice_note] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True})


@app.route('/api/user/voice-note/<token>', methods=['GET'])
def list_voice_notes(token):
    """Liste aller voice-note-Tage für User. SB-primary + Disk-Merge."""
    import os, re
    safe_t = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    if not safe_t: return jsonify({'error':'invalid token'}), 400
    sb_dates = _voice_note_meta_list(token)  # None wenn SB-down/Tabelle-fehlt
    disk_dates = []
    voice_dir = os.path.join(_USER_HISTORY_DIR, 'voice_notes', safe_t)
    if os.path.isdir(voice_dir):
        disk_dates = [f.replace('.m4a', '') for f in os.listdir(voice_dir)
                      if f.endswith('.m4a')]
    dates = sorted(set((sb_dates or []) + disk_dates))
    return jsonify({'dates': dates, 'count': len(dates)})


# ─── Flight-Notes (Per-Day Text-Notes, plain-text, max 500 chars) ───────────
# Ergänzung zu Voice-Notes — User kann pro Flugtag eine kurze Text-Notiz
# tippen ("Catering vergessen", "FO neu eingeschult", …). Storage:
# profile.metadata.flight_notes[datum] = "<text>".
# Persistenz läuft über die bestehende _profile_load/_profile_save-Pipeline —
# d.h. SB metadata-jsonb (primary) + Disk (Cache). Damit überlebt der Inhalt
# Cloud-Run-Redeploys automatisch.

_FLIGHT_NOTE_MAX_CHARS = 500
_FLIGHT_NOTE_DATUM_RE = re.compile(r'^\d{4}-\d{2}-\d{2}$')


def _sanitize_flight_note(raw):
    """Plain text only — strippt HTML-Tags + Control-Chars, cap auf 500."""
    if not isinstance(raw, str):
        return ''
    # HTML/Tags raus (defensiv — Backend speichert; Frontend rendert plain).
    s = re.sub(r'<[^>]*>', '', raw)
    # Control-Chars raus außer \n und \t (Multi-line erlaubt).
    s = ''.join(c for c in s if c == '\n' or c == '\t' or c.isprintable())
    s = s.strip()
    return s[:_FLIGHT_NOTE_MAX_CHARS]


@app.route('/api/user/flight-notes/<token>', methods=['GET'])
def list_flight_notes(token):
    """Liefert dict {datum: note} für alle Flugtag-Text-Notizen des Users."""
    if not token:
        return jsonify({'error': 'invalid token'}), 400
    try:
        full = _profile_load(token) or {}
        prof = full.get('profile') or {}
        # profile.metadata.flight_notes — _profile_save_to_supabase legt
        # unknown keys in metadata-jsonb ab, _profile_load_from_supabase
        # faltet die wieder ins prof-Dict hoch. Daher direkt aus prof.
        notes = prof.get('flight_notes') or {}
        if not isinstance(notes, dict):
            notes = {}
        return jsonify({'notes': notes, 'count': len(notes)})
    except Exception as e:
        print(f'[list_flight_notes] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'error': 'internal_error'}), 500


@app.route('/api/user/flight-notes/<token>/<datum>', methods=['PUT'])
def put_flight_note(token, datum):
    """Speichert/Updated eine Per-Day Text-Notiz. Body: {note: "..."}.
    Empty-String → Eintrag wird entfernt (User hat Notiz gelöscht).
    """
    if not token:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    if not _FLIGHT_NOTE_DATUM_RE.match(datum or ''):
        return jsonify({'ok': False, 'error': 'invalid datum'}), 400
    body = request.get_json(silent=True) or {}
    raw = body.get('note') if isinstance(body.get('note'), str) else ''
    # Frühe Abwehr gegen riesige Payloads — sanitize kappt auch, aber
    # 4×500 = 2000 char Roh-Limit verhindert Memory-Waste bei Abuse.
    if len(raw) > _FLIGHT_NOTE_MAX_CHARS * 4:
        return jsonify({'ok': False, 'error': 'note_too_long'}), 413
    note = _sanitize_flight_note(raw)
    try:
        # Vollständigen Disk-Profile-Inhalt laden (inkl. Side-Keys wie
        # subscription, crew_aircraft) — _profile_save würde diese sonst
        # killen wenn full_disk_payload None ist.
        disk_full = dict(_profile_load_from_disk(token) or {})
        # Profile aus SB (oder Disk) als Quelle für das flight_notes-Dict —
        # damit zwei gleichzeitige PUTs aus verschiedenen Geräten nicht
        # gegenseitig überschreiben (best-effort, kein echter Lock).
        full = _profile_load(token) or {}
        prof = dict(full.get('profile') or {})
        notes_raw = prof.get('flight_notes') or {}
        notes = dict(notes_raw) if isinstance(notes_raw, dict) else {}
        if note:
            notes[datum] = note
        else:
            notes.pop(datum, None)
        prof['flight_notes'] = notes
        disk_full['token'] = token
        disk_full['profile'] = prof
        disk_full['_updated_at'] = datetime.now().isoformat()
        if not _profile_save(token, prof, full_disk_payload=disk_full):
            return jsonify({'ok': False, 'error': 'persist_failed'}), 500
        return jsonify({'ok': True, 'datum': datum,
                        'note': note, 'len': len(note)})
    except Exception as e:
        app.logger.exception('[flight-notes] put_failed')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500


@app.route('/api/user/flight-notes/<token>/<datum>', methods=['GET'])
def get_flight_note(token, datum):
    """Liefert eine einzelne Per-Day Text-Notiz."""
    if not token:
        return jsonify({'error': 'invalid token'}), 400
    if not _FLIGHT_NOTE_DATUM_RE.match(datum or ''):
        return jsonify({'error': 'invalid datum'}), 400
    try:
        full = _profile_load(token) or {}
        prof = full.get('profile') or {}
        notes = prof.get('flight_notes') or {}
        if not isinstance(notes, dict):
            notes = {}
        return jsonify({'datum': datum, 'note': notes.get(datum, '')})
    except Exception as e:
        print(f'[get_flight_note] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'error': 'internal_error'}), 500


# ─── Crew Chat Messages (HTTP-Polling-Fallback; WebSocket optional) ─────────
# Keep API simple: messages stored per-channel. Channel = sorted(token1, token2) für DMs
# oder explicit group_id für Group-Chats.

def _chat_path(channel_id):
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_-]', '', channel_id or '')[:128]
    if not safe: return None
    chat_dir = os.path.join(_USER_HISTORY_DIR, 'chat')
    os.makedirs(chat_dir, exist_ok=True)
    return os.path.join(chat_dir, f'{safe}.json')


# ── Social-Persistenz: kanonisches Row-Schema (P0 Fix, 2026-06-07) ──
# WURZEL-BUG (live reproduziert): PostgREST-Bulk-Upsert verlangt, dass ALLE
# Objekte im Array DIESELBEN Keys haben ("PGRST102: All object keys must
# match"). Zusätzlich füllt PostgREST fehlende Keys NICHT mit der Spalten-
# DEFAULT, sondern schickt explizit NULL → NOT-NULL-Verletzung (23502) bei
# Spalten wie `deleted`, `hashtags`, `like_count`, `is_anonymous`.
#
# Symptom: Frisch erstellte Forum-Threads/Wall-Posts/DMs/Replies hatten nach
# dem metadata-Split nicht exakt dieselben Keys wie die aus SB geladenen
# Altzeilen → der GESAMTE Batch wurde verworfen → der Post „blieb nicht".
# Disk-Fallback maskierte das lokal, Cloud-Run-Redeploy wipte ihn → weg.
#
# FIX: Jede Row wird gegen ein festes Spalten→Default-Schema normalisiert.
# Garantiert (a) identische Key-Sets über alle Rows und (b) keine NULL in
# NOT-NULL-Spalten. `metadata` und `body` sind immer present.
def _sb_normalize_rows(rows, schema_defaults):
    """Erzwingt für jede Row exakt die Keys aus schema_defaults (+ vorhandene
    Werte). Fehlende Keys → Default. None in NOT-NULL-Defaults → Default.
    schema_defaults: dict col→default (default None ⇒ Spalte ist nullable)."""
    out = []
    for r in rows:
        norm = {}
        for col, default in schema_defaults.items():
            v = r.get(col, None)
            if v is None and default is not None:
                v = default
            norm[col] = v
        out.append(norm)
    return out


# Default-Schemata pro Tabelle. None ⇒ nullable (Wert darf NULL bleiben).
# Nicht-None ⇒ NOT-NULL-Spalte, fehlend/NULL wird durch Default ersetzt.
_SB_SCHEMA_DM_MESSAGES = {
    'id': '', 'channel_id': '', 'author_token': '', 'ts': 0,
    'body': None, 'image_url': None, 'metadata': {},
}
_SB_SCHEMA_WALL_POSTS = {
    'id': '', 'author_token': '', 'ts': 0, 'body': None,
    'layover_iata': None, 'image_url': None, 'hashtags': [],
    'like_count': 0, 'comment_count': 0, 'deleted': False,
    'is_anonymous': False, 'anon_handle': None, 'metadata': {},
}
_SB_SCHEMA_WALL_COMMENTS = {
    'id': '', 'post_id': '', 'author_token': '', 'body': None,
    'ts': 0, 'parent_id': None, 'image_url': None,
    'is_anonymous': False, 'anon_handle': None, 'metadata': {},
}
_SB_SCHEMA_FORUM_THREADS = {
    'id': '', 'category_id': '', 'author_token': '', 'title': None,
    'body': None, 'ts': 0, 'hashtags': [], 'like_count': 0,
    'reply_count': 0, 'deleted': False, 'metadata': {},
}
_SB_SCHEMA_FORUM_REPLIES = {
    'id': '', 'thread_id': '', 'author_token': '', 'body': None,
    'ts': 0, 'parent_reply_id': None, 'mentioned_token': None,
    'image_url': None, 'like_count': 0, 'metadata': {},
}


# ── DM-Messages SB persistence (P0 Worker-P1, 2026-06-01) ──
# Disk-only wipte alle DMs bei jedem Cloud-Run-Redeploy. SB als Primary.
# Schema: 1 Row pro Message. SB-Spalte body ↔ disk-Feld text.
_DM_MSG_KNOWN_COLS = {
    'id', 'channel_id', 'author_token', 'ts', 'image_url',
}


def _dm_messages_load_from_supabase(channel_id):
    """Liest Messages für channel_id aus SB. None bei SB-down/error.
    Re-hydrated: SB-body → disk-text, iso aus metadata."""
    if not SB_AVAILABLE or not channel_id:
        return None
    try:
        r = (sb.table('dm_messages').select('*')
             .eq('channel_id', channel_id)
             .order('ts', desc=False)
             .limit(2000).execute())
        rows = r.data or []
        out = []
        for row in rows:
            m = {}
            for k in _DM_MSG_KNOWN_COLS:
                v = row.get(k)
                if v is not None:
                    m[k] = v
            if row.get('body') is not None:
                m['text'] = row.get('body')
            md = row.get('metadata') or {}
            if isinstance(md, dict):
                for k, v in md.items():
                    if k not in m:
                        m[k] = v
            out.append(m)
        return out
    except Exception as e:
        app.logger.warning(
            f'[dm] sb_load_fail ch={(channel_id or "")[:16]} '
            f'err={type(e).__name__}: {str(e)[:120]}'
        )
        return None


def _dm_messages_save_to_supabase(channel_id, messages):
    """Bulk-upsert Messages eines Channels nach SB. True bei vollem Erfolg."""
    if not SB_AVAILABLE or not channel_id or messages is None:
        return False
    rows = []
    for m in (messages or []):
        if not isinstance(m, dict):
            continue
        mid = m.get('id')
        if not mid:
            continue
        row = {'id': mid, 'channel_id': channel_id}
        meta = {}
        for k, v in m.items():
            if k == 'text':
                row['body'] = v
            elif k == 'body':
                row['body'] = v
            elif k == 'channel_id':
                continue
            elif k in _DM_MSG_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        if row.get('author_token') is None:
            row['author_token'] = ''
        if row.get('ts') is None:
            row['ts'] = 0
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_DM_MESSAGES)
    try:
        for i in range(0, len(rows), 500):
            _sb_retry('dm_save',
                      lambda batch=rows[i:i+500]:
                          sb.table('dm_messages').upsert(batch, on_conflict='id').execute())
        return True
    except Exception as e:
        app.logger.error(
            f'[dm] sb_save_fail ch={(channel_id or "")[:16]} '
            f'err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


def _dm_load_messages_from_disk(channel_id):
    """Disk-Fallback. Tolerant ggü. älterer flat-list-Shape."""
    p = _chat_path(channel_id)
    if not p:
        return []
    try:
        with open(p) as f:
            raw = json.load(f)
    except FileNotFoundError:
        return []
    except Exception:
        return []
    if isinstance(raw, dict):
        return raw.get('messages') or []
    if isinstance(raw, list):
        return raw
    return []


def _dm_load_messages(channel_id):
    """SB primary, Disk fallback, lazy-migrate."""
    if not channel_id:
        return []
    sb_data = _dm_messages_load_from_supabase(channel_id)
    if sb_data is None:
        return _dm_load_messages_from_disk(channel_id)
    if sb_data:
        return sb_data
    disk_data = _dm_load_messages_from_disk(channel_id)
    if disk_data and SB_AVAILABLE:
        app.logger.info(
            f'[dm] lazy-migrate ch={(channel_id or "")[:16]} '
            f'{len(disk_data)} msgs → supabase'
        )
        _dm_messages_save_to_supabase(channel_id, disk_data)
        return disk_data
    return []


def _dm_save_messages(channel_id, messages):
    """SB primary + Disk Read-Cache. Cap auf letzte 500 Messages je Channel."""
    if not channel_id:
        return
    capped = (messages or [])[-500:] if isinstance(messages, list) else messages
    sb_ok = _dm_messages_save_to_supabase(channel_id, capped)
    p = _chat_path(channel_id)
    if not p:
        return
    try:
        _atomic_write_json(p, {'messages': capped})
    except Exception as e:
        app.logger.warning(f'[dm] disk_save_fail ch={(channel_id or "")[:16]}: {e}')
        if not sb_ok:
            app.logger.error('[dm] CRITICAL: weder SB noch Disk gesichert!')


def _dm_save_messages_disk(channel_id, messages):
    """NUR den Disk-Read-Cache schreiben (Data-Layer-Refactor 2026-07-01):
    für Mutationen, die ihre SB-Änderung bereits per-Row upserted haben —
    _dm_save_messages würde sonst alle ≤500 Messages erneut bulk-upserten."""
    p = _chat_path(channel_id)
    if not p:
        return
    try:
        _atomic_write_json(p, {'messages': (messages or [])[-500:]})
    except Exception as e:
        app.logger.warning(f'[dm] disk_save_fail (ok wenn SB lief) ch={(channel_id or "")[:16]}: {e}')


def _dm_channel(token_a, token_b):
    import re
    a = re.sub(r'[^A-Za-z0-9_-]', '', token_a or '')[:64]
    b = re.sub(r'[^A-Za-z0-9_-]', '', token_b or '')[:64]
    if not a or not b: return None
    return 'dm__' + '__'.join(sorted([a, b]))


def _resolve_friend_token(my_token, friend_token):
    """Eine über /friends-today gereichte friend_token-Variante kann PII-gekürzt
    sein (`fr[:16] + '…'`). Die DM-Endpoints brauchen aber den VOLLEN Token: sonst
    schlägt der Friendship-Check fehl (Chat-Sheet bleibt leer) UND der DM-Channel
    wäre asymmetrisch (jede Seite kombiniert ihren vollen mit dem gekürzten Gegen-
    Token → unterschiedliche `dm__`-IDs → Nachricht „kommt nicht an"). Wir lösen die
    gekürzte Variante über die eigene Freundschafts-Kante auf: der volle Friend-Token,
    der mit dem gesäuberten Prefix beginnt. Volle Tokens (exakt in der Friend-Liste)
    laufen UNVERÄNDERT durch — der Resolver kann also nur FIXEN, nie einen
    funktionierenden Voll-Token-Flow brechen."""
    if not friend_token:
        return friend_token
    import re
    cleaned = re.sub(r'[^A-Za-z0-9_-]', '', friend_token)
    if not cleaned:
        return friend_token
    try:
        friends = (_friends_load(my_token) or {}).get('friends') or []
    except Exception:
        return friend_token
    full = [f for f in friends if isinstance(f, str)]
    if cleaned in full:
        return cleaned                      # schon voll → unverändert
    matches = [f for f in full if f.startswith(cleaned)]
    if len(matches) == 1:
        return matches[0]                   # eindeutige Prefix-Auflösung → voller Token
    return friend_token                     # nicht eindeutig → unverändert lassen


def _group_id_from_channel(channel_id):
    """Extrahiert die friend-group-id aus einer Group-Channel-id.
    Akzeptiert die Präfixe `group__<gid>` und `grp__<gid>`. Gibt None zurück
    wenn channel_id kein Group-Channel ist (z.B. ein DM-Channel)."""
    cid = channel_id or ''
    for prefix in ('group__', 'grp__'):
        if cid.startswith(prefix):
            gid = cid[len(prefix):]
            return gid or None
    return None


def _channel_access_error(token, channel_id):
    """Membership-Gate für generische Channel-Endpoints. Returns None wenn Zugriff
    erlaubt, sonst ein (jsonify, status)-Tuple für 403/400.

    - DM-Channel (`dm__a__b`): Caller-Token muss einer der beiden Teilnehmer sein.
      (Die /dm-Wrapper haben zusätzlich einen Friend-Gate; dieser hier verhindert
      direkten Zugriff auf die generische /channel-Route ohne Friend-Check.)
    - Group-Channel (`group__<gid>`): Caller muss Mitglied der Group sein.
    - Unbekanntes Format → 400 invalid_channel (kein still-erlaubter Catch-all)."""
    cid = channel_id or ''
    if cid.startswith('dm__'):
        import re
        safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
        parts = cid[len('dm__'):].split('__')
        if safe and safe in parts:
            return None
        return jsonify({'error': 'not_a_member'}), 403
    gid = _group_id_from_channel(cid)
    if gid is not None:
        # CAPABILITY-Modell: die Gruppen-ID ist das Geheimnis (nur per Invite-Code/
        # QR bekannt). Wer sie hat, ist eingeladen — Crew ODER Nicht-Crew. KEIN
        # Owner-Mitgliederlisten-Check: der sperrte per-Code-Beigetretene mit 403 aus
        # → der Layover-Chat war für genau die Eingeladenen kaputt (sie sahen die
        # Gruppe lokal, bekamen aber beim Lesen/Senden 403). Bearer==path-token ist
        # über den _bug004-Gate bereits geprüft (Caller ist als er selbst auth'd).
        # Identisch zum /api/layover-group-Meta-Endpoint (gleiche Gruppe, gleiches Modell).
        return None
    return jsonify({'error': 'invalid_channel'}), 400


@app.route('/api/crew-chat/<token>/channel/<channel_id>', methods=['GET'])
def get_chat_messages(token, channel_id):
    """Liefert Messages für Channel. Query: ?since_ts=epoch (nur neuere)."""
    if not _chat_path(channel_id):
        return jsonify({'error': 'invalid_channel'}), 400
    # Membership-Gate: ohne diesen konnte JEDER auth'd User einen beliebigen
    # Group-Channel (oder fremden DM-Channel) lesen, nur indem er die channel_id
    # kannte (Isolation-Leak). DMs sind zusätzlich friend-gated via /dm-Wrapper.
    _gate = _channel_access_error(token, channel_id)
    if _gate is not None:
        return _gate
    msgs = _dm_load_messages(channel_id) or []
    # Soft-Delete-Gate: vom Autor geloeschte Messages (deleted==True, gesetzt vom
    # DELETE-Endpoint) werden NIE ausgeliefert. Ohne dieses Filter taucht eine
    # geloeschte Nachricht beim naechsten Poll/Reload (oder auf einem neuen Geraet)
    # wieder auf, weil der Server das Original sonst weiterhin zurueckgibt.
    msgs = [m for m in msgs if not m.get('deleted')]
    since = float(request.args.get('since_ts') or 0)
    if since:
        msgs = [m for m in msgs if (m.get('ts') or 0) > since]
    # `is_mine` explizit mitgeben → iOS muss nicht mehr den GEKÜRZTEN author_token
    # (token[:16]+'…') prefix-vergleichen (fragil bei Token-Prefix-Kollision).
    # Vergleich gegen DIESELBE Kürzung, mit der gesendet wurde.
    my_trunc = (token or '')[:16] + '…'
    out = []
    for m in msgs[-100:]:
        mm = dict(m)
        mm['is_mine'] = (m.get('author_token') == my_trunc)
        # iOS-CONTRACT-FIX (DM „Nachricht nicht im Verlauf sichtbar", 2026-06-29):
        # author_token MUSS im Payload bleiben — das iOS-`ChatMessage`-Struct
        # deklariert `author_token` als NICHT-optionales Feld. Der vorige
        # Privacy-Pop (2026-06-16) entfernte es, wodurch JEDER Chat-/DM-History-
        # Decode mit keyNotFound fehlschlug; load()/pollOnce schlucken den
        # decode-Error still → der GESAMTE Server-Verlauf wurde verworfen.
        # Gesendete DMs überlebten dann nur als lokale Optimistic-Bubble, der
        # echte Verlauf (inkl. Gegenseite) lud nie. Der Client braucht den
        # author_token weiterhin als stabilen Per-Autor-Key (Gruppierung,
        # Avatar, Profil-Öffnen, Block-Target).
        # Privacy bleibt gewahrt: NUR die bereits gespeicherte GEKÜRZTE Form
        # (token[:16]+'…') wird ausgeliefert, nie der volle Token — defensiv
        # re-truncaten falls eine Legacy-Zeile doch einen längeren Wert trägt.
        at = m.get('author_token') or ''
        if at and ('…' not in at) and len(at) > 17:
            at = at[:16] + '…'
        mm['author_token'] = at
        # Token-Leak-Fix: alte Photo-Messages tragen Legacy-Bild-URLs (mit
        # vollem Token) im Text → auf den opaken Key umschreiben.
        if mm.get('text'):
            mm['text'] = _wall_img_sanitize_urls(mm['text'])
        out.append(mm)
    return jsonify({'channel': channel_id, 'messages': out})


@app.route('/api/crew-chat/<token>/channel/<channel_id>/send', methods=['POST'])
def send_chat_message(token, channel_id):
    """Body: {text}. Author = token."""
    body = request.get_json(silent=True) or {}
    text = (body.get('text') or '').strip()
    if not text: return jsonify({'ok': False, 'error': 'empty_text'}), 400
    if len(text) > 2000: return jsonify({'ok': False, 'error': 'text_too_long'}), 413
    if not _chat_path(channel_id):
        return jsonify({'ok': False, 'error': 'invalid_channel'}), 400
    # Membership-Gate (siehe get_chat_messages): kein Schreiben in fremde
    # Group-/DM-Channels nur weil die channel_id bekannt ist.
    _gate = _channel_access_error(token, channel_id)
    if _gate is not None:
        _, status = _gate
        err = 'not_a_member' if status == 403 else 'invalid_channel'
        return jsonify({'ok': False, 'error': err}), status
    # BUG-021-Fix: Rate-Limit wie bei DMs (30 msgs/min pro Token) — vorher konnte
    # ein Token unbegrenzt Channel-Messages senden (Spam/Flood).
    if _token_rate_limited(token, 'chat_send', limit=30, window_sec=60):
        return jsonify({'ok': False, 'error': 'rate_limited'}), 429
    import uuid, time
    try:
        msg = {
            'id': str(uuid.uuid4())[:12],
            'channel_id': channel_id,
            'author_token': token[:16] + '…',
            'text': text,
            'ts': time.time(),
            'iso': datetime.now().isoformat(),
        }
        # Per-Row-Insert (2026-07-01): nur die NEUE Message nach SB upserten
        # statt load-ALL (bis 2000) → append → save-ALL (bis 500 Rows) pro
        # Send. Disk-Cache lokal anhängen (SB-down-Fallback bleibt intakt).
        # J5-P1 (Sweep 2026-07-10): SB-Fail NICHT als „gesendet" maskieren —
        # Reads sind SB-or-Disk (Disk-only-Message unsichtbar sobald der Channel
        # SB-Rows hat) und die Disk ist ephemer. 503 → iOS-SyncQueue retryt.
        sb_ok = _dm_messages_save_to_supabase(channel_id, [msg])
        if not sb_ok and SB_AVAILABLE:
            return jsonify({'ok': False, 'error': 'storage_unavailable'}), 503
        disk_msgs = _dm_load_messages_from_disk(channel_id) or []
        disk_msgs.append(msg)
        _dm_save_messages_disk(channel_id, disk_msgs)
    except Exception as e:
        print(f'[send_chat_message] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    # Push an die Empfänger (DM: Gegenseite, Group: Mitglieder) — fire-and-
    # forget im Executor, blockiert den Send-Response nicht. HEADLINE-Fix
    # 2026-07-02: dieser generische Send-Pfad (den die iOS-App für Gruppen
    # nutzt und über den auch /dm/send läuft) hatte vorher KEINEN Push.
    try:
        _chat_push_fanout_async(token, channel_id, text, message_id=msg.get('id'))
    except Exception:
        pass
    return jsonify({'ok': True, 'message': msg})


def _soft_delete_chat_message(token, channel_id, message_id):
    """Markiert eine Message als geloescht (Soft-Delete) und persistiert das.

    Echte serverseitige Loeschung: ohne sie blieb das Original in SB/Disk und kam
    beim naechsten Poll/Reload (oder auf einem neuen Geraet) wieder hoch — der
    iOS-Client hielt es nur lokal versteckt. `deleted=True` ist KEINE bekannte
    SB-Spalte → landet in metadata-jsonb und wird beim Laden re-hydratisiert; das
    List-Route-Filter (`not m.get('deleted')`) blendet die Message dann ueberall aus.
    Nur der Autor darf loeschen (Author-Token PII-truncated `token[:16]+'…'`).
    """
    import time
    if not message_id:
        return jsonify({'ok': False, 'error': 'message_id_required'}), 400
    my_trunc = (token or '')[:16] + '…'
    try:
        msgs = _dm_load_messages(channel_id) or []
        found = None
        for m in msgs:
            if m.get('id') == message_id:
                found = m
                break
        if found is None:
            # Schon weg/nie existiert → idempotent ok (Client soll nicht retryen).
            return jsonify({'ok': True, 'already_gone': True})
        if found.get('author_token') != my_trunc:
            return jsonify({'ok': False, 'error': 'not_author'}), 403
        if found.get('deleted'):
            return jsonify({'ok': True, 'already_deleted': True})
        found['deleted'] = True
        found['deleted_ts'] = time.time()
        # Text nicht mehr ausliefern: falls ein alter Client doch mal eine
        # deleted-Message bekaeme, ist der Inhalt trotzdem fort.
        found['text'] = ''
        # Per-Row-Update (2026-07-01): nur DIESE Message nach SB upserten
        # (deleted-Flag landet in metadata-jsonb) statt alle ≤500 Messages.
        # J5-Muster wie send: SB-Fail ehrlich melden — sonst resurrectet die
        # „gelöschte" Message beim nächsten SB-Read (Client kann retryen).
        sb_ok = _dm_messages_save_to_supabase(channel_id, [found])
        if not sb_ok and SB_AVAILABLE:
            return jsonify({'ok': False, 'error': 'storage_unavailable'}), 503
        _dm_save_messages_disk(channel_id, msgs[-500:])
    except Exception as e:
        print(f'[_soft_delete_chat_message] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True, 'deleted': message_id})


@app.route('/api/crew-chat/<token>/channel/<channel_id>/message/<message_id>',
           methods=['DELETE'])
def delete_chat_message(token, channel_id, message_id):
    """Soft-Delete einer eigenen Message in einem (Group-/DM-)Channel."""
    if not _chat_path(channel_id):
        return jsonify({'ok': False, 'error': 'invalid_channel'}), 400
    _gate = _channel_access_error(token, channel_id)
    if _gate is not None:
        _, status = _gate
        err = 'not_a_member' if status == 403 else 'invalid_channel'
        return jsonify({'ok': False, 'error': err}), status
    return _soft_delete_chat_message(token, channel_id, message_id)


def _dm_lastseen_load_from_supabase(token):
    """{channel_id: last_seen_ts} aus SB. None bei SB-down."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('dm_lastseen').select('channel_id,last_seen_ts')
             .eq('user_token', token).execute())
        return {row['channel_id']: float(row.get('last_seen_ts') or 0)
                for row in (r.data or []) if row.get('channel_id')}
    except Exception as e:
        app.logger.warning(f'[dm-lastseen] sb_load_fail: {str(e)[:120]}')
        return None


def _dm_lastseen_sb_upsert(token, channel_id, ts):
    if not SB_AVAILABLE or not token or not channel_id:
        return False
    try:
        sb.table('dm_lastseen').upsert(
            {'user_token': token, 'channel_id': channel_id, 'last_seen_ts': float(ts)},
            on_conflict='user_token,channel_id').execute()
        return True
    except Exception as e:
        app.logger.warning(f'[dm-lastseen] sb_save_fail: {str(e)[:120]}')
        return False


def _dm_lastseen_load(token):
    """SB primary, Disk fallback, lazy-migrate. Returns {channel_id: ts}."""
    import os
    sb_data = _dm_lastseen_load_from_supabase(token)
    disk_p = os.path.join(_USER_HISTORY_DIR, f'dm_lastseen_{token}.json')
    if sb_data is not None:
        if not sb_data:
            # Lazy-migrate von Disk
            try:
                if os.path.exists(disk_p):
                    with open(disk_p) as f:
                        disk_data = json.load(f) or {}
                    if disk_data and SB_AVAILABLE:
                        for ch, ts in disk_data.items():
                            _dm_lastseen_sb_upsert(token, ch, ts)
                        app.logger.info(f'[dm-lastseen] lazy-migrated {len(disk_data)} channels')
                        return disk_data
            except Exception: pass
        return sb_data
    # SB down → Disk
    try:
        if os.path.exists(disk_p):
            with open(disk_p) as f:
                return json.load(f) or {}
    except Exception: pass
    return {}


@app.route('/api/crew-chat/<token>/inbox', methods=['GET'])
def get_dm_inbox(token):
    """Aggregierter Inbox für den Crew-Chat-Tab.

    Liest für jeden Friend den letzten Message-Eintrag (best-effort über die
    DM-Channel-Files) + zählt unread (Messages neuer als last_seen_<channel>).
    Vorher: Frontend musste N+1 Calls machen pro Friend.
    """
    friends = (_friends_load(token).get('friends') or [])
    last_seen = _dm_lastseen_load(token) or {}
    inbox = []
    # send_chat_message speichert author_token PII-truncated als
    # `token[:16] + "…"`. Beim Vergleich hier muessen wir gegen dieselbe
    # truncated Form pruefen — sonst zaehlt jede eigene Message faelschlich
    # als unread (Bug pre-2026-05-31).
    my_author_id = (token[:16] + '…') if token else ''
    for friend_token in friends:
        ch = _dm_channel(token, friend_token)
        if not ch: continue
        last_msg = None
        unread = 0
        try:
            # _dm_load_messages: SB primary, Disk fallback (P0 2026-06-01).
            # Soft-deletete Messages raus, sonst zeigt die Inbox eine geloeschte
            # Nachricht als letzte Preview bzw. zaehlt sie als unread.
            msgs = [m for m in (_dm_load_messages(ch) or []) if not m.get('deleted')]
            if msgs:
                last_msg = msgs[-1]
                seen_ts = float(last_seen.get(ch) or 0)
                unread = sum(1 for m in msgs
                             if m.get('author_token') != my_author_id
                             and float(m.get('ts') or 0) > seen_ts)
        except Exception:
            pass
        inbox.append({
            'friend_token': friend_token,
            'channel_id': ch,
            'last_message_at': (last_msg or {}).get('ts'),
            'last_message_preview': ((last_msg or {}).get('text') or '')[:80],
            'last_message_from_me': (last_msg or {}).get('author_token') == my_author_id,
            'unread_count': unread,
        })
    inbox.sort(key=lambda x: -(x.get('last_message_at') or 0))
    return jsonify({'count': len(inbox), 'inbox': inbox})


@app.route('/api/crew-chat/<token>/inbox/mark-read', methods=['POST'])
def dm_mark_read(token):
    """Body: {channel_id} — setzt last_seen_<channel> auf jetzt (für Unread-Counter).
    SB primary + Disk best-effort (Read-Cache)."""
    import os, time as _t
    body = request.get_json(silent=True) or {}
    channel = (body.get('channel_id') or '').strip()
    if not channel:
        return jsonify({'ok': False, 'error': 'channel_id_required'}), 400
    now = _t.time()
    sb_ok = _dm_lastseen_sb_upsert(token, channel, now)
    last_seen_p = os.path.join(_USER_HISTORY_DIR, f'dm_lastseen_{token}.json')
    data = {}
    try:
        if os.path.exists(last_seen_p):
            with open(last_seen_p) as f: data = json.load(f) or {}
    except Exception: pass
    data[channel] = now
    try:
        with open(last_seen_p, 'w') as f: json.dump(data, f)
    except Exception as e:
        if not sb_ok:
            print(f'[dm_mark_read] error: {type(e).__name__}: {str(e)[:300]}')
            return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True})


@app.route('/api/crew-chat/<token>/dm/<friend_token>', methods=['GET'])
def get_dm(token, friend_token):
    """Convenience-Wrapper für 1:1 DMs.

    Friend-Auth-Check ist Pflicht — sonst könnte jeder mit einem eigenen Token
    fremde DMs lesen, indem er beliebige andere Tokens als friend_token nutzt
    (das DM-Channel-File-Naming ist deterministisch).
    """
    friend_token = _resolve_friend_token(token, friend_token)
    ch = _dm_channel(token, friend_token)
    if not ch: return jsonify({'error':'invalid_tokens'}), 400
    # Friendship verifizieren — beide Richtungen prüfen, weil eine Seite
    # entfernt sein kann (z.B. nach asymmetrischem Block).
    try:
        my_friends = set((_friends_load(token).get('friends') or []))
        their_friends = set((_friends_load(friend_token).get('friends') or []))
    except Exception:
        my_friends = set(); their_friends = set()
    if friend_token not in my_friends and token not in their_friends:
        return jsonify({'error': 'not_friends'}), 403
    return get_chat_messages(token, ch)


@app.route('/api/crew-chat/<token>/dm/<friend_token>/send', methods=['POST'])
def send_dm(token, friend_token):
    if token.startswith('AT-GUEST-'):
        return jsonify({'ok': False, 'error': 'demo_mode_cannot_dm'}), 403
    friend_token = _resolve_friend_token(token, friend_token)
    ch = _dm_channel(token, friend_token)
    if not ch: return jsonify({'ok': False, 'error':'invalid_tokens'}), 400
    # J14-Fix: DM nur zwischen Friends. Vorher: jeder mit token konnte
    # jedem fremden DMs schicken → Spam/Harassment-Vektor.
    try:
        friends = set((_friends_load(token).get('friends') or []))
    except Exception:
        friends = set()
    if friend_token not in friends:
        # Empfänger muss erst Friend-Request annehmen
        return jsonify({'ok': False, 'error': 'not_friends',
                        'message': 'DMs sind nur an Buddies möglich. Sende erst eine Buddy-Anfrage.'}), 403
    # Rate-Limit: 30 DMs/min/User (Spam-Bremse)
    if _token_rate_limited(token, 'dm_send', limit=30, window_sec=60):
        return jsonify({'ok': False, 'error': 'rate_limited',
                        'message': 'Bitte langsamer.'}), 429
    # Push macht send_chat_message selbst (via _chat_push_fanout_async) —
    # der alte Inline-Push hier war (a) BLOCKING im Request-Pfad und (b) las
    # den Sender-Namen von der ephemeren Cloud-Run-Disk (fast immer leer →
    # Push hieß 'Crew'). Doppel-Push vermeiden: hier NICHT mehr senden.
    return send_chat_message(token, ch)


@app.route('/api/crew-chat/<token>/dm/<friend_token>/message/<message_id>',
           methods=['DELETE'])
def delete_dm_message(token, friend_token, message_id):
    """Soft-Delete einer eigenen Message in einem 1:1-DM (Convenience-Wrapper,
    spiegelt /channel/<id>/message/<id>). Channel deterministisch aus beiden Tokens."""
    friend_token = _resolve_friend_token(token, friend_token)
    ch = _dm_channel(token, friend_token)
    if not ch:
        return jsonify({'ok': False, 'error': 'invalid_tokens'}), 400
    return _soft_delete_chat_message(token, ch, message_id)


# ─── Social Wall: Posts / Likes / Comments ──────────────────────────────────

def _wall_dir():
    import os
    d = os.path.join(_USER_HISTORY_DIR, 'wall')
    os.makedirs(d, exist_ok=True)
    return d

def _wall_posts_path():
    import os
    return os.path.join(_wall_dir(), 'posts.json')

def _wall_likes_path(token):
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    return os.path.join(_wall_dir(), f'likes_{safe}.json') if safe else None

def _wall_comments_path(post_id):
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_-]', '', post_id or '')[:32]
    return os.path.join(_wall_dir(), f'comments_{safe}.json') if safe else None

# ── Dislikes + Reports (P0 Social-Feed, 2026-06-03) — Disk-only (kein SB-Table
#    nötig; analog der Disk-Fallback-Pfade der Likes). Reports keyed per post. ──
def _wall_dislikes_path(token):
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    return os.path.join(_wall_dir(), f'dislikes_{safe}.json') if safe else None

def _wall_dislikes_load(token):
    p = _wall_dislikes_path(token)
    if not p:
        return set()
    try:
        with open(p) as f:
            return set(json.load(f) or [])
    except Exception:
        return set()

# Wall-Report Auto-Hide-Schwelle: ab so vielen DISTINCT-Reportern wird ein
# Post im Feed versteckt (Logik in moderation_report, kind='wall_post').
_WALL_REPORT_HIDE_THRESHOLD = 3

# Anonyme Layover-Stories: stabiler, NICHT-umkehrbarer Handle pro Author.
# Gleicher Author → gleicher Handle (im Feed wiedererkennbar), aber kein
# Rückschluss auf Identität (sha256, kein Token im Response).
_ANON_ADJ = ['Silent', 'Night', 'Mach', 'Tail', 'Jet', 'Cloud', 'Sky', 'Delta', 'Echo',
             'Foxtrot', 'Cruise', 'Apron', 'Crosswind', 'Redeye', 'Galley', 'Standby']
_ANON_NOUN = ['Captain', 'Cruiser', 'Skipper', 'Nomad', 'Falcon', 'Albatross', 'Comet',
              'Voyager', 'Ranger', 'Drifter', 'Aviator', 'Wanderer', 'Phantom', 'Maverick']
def _anon_handle_secret():
    """Server-Secret für die Anon-Handle-HMAC. Primär AEROTAX_CRYPTO_KEY (ist
    in Production garantiert gesetzt, siehe _validate_crypto_key_on_boot).
    Local/Test-Fallback ist ein stabiler Prozess-String — Handles bleiben dann
    innerhalb eines Boots konsistent, sind aber nicht aus dem Token allein
    rekonstruierbar."""
    key = (os.environ.get('AEROTAX_CRYPTO_KEY') or '').strip()
    if key:
        return key.encode()
    return b'aerotax-anon-handle-local-fallback'


def _anon_handle_for(token, salt=None):
    """Pseudonymer Anon-Handle. SECURITY-FIX (2026-06-07): vorher
    sha256('anonwall:'+token) — deterministisch & aus dem (nicht-geheimen)
    Token rekonstruierbar, und alle Posts eines Users clusterten unter dem
    GLEICHEN Handle. Jetzt: HMAC-SHA256 mit Server-Secret (nicht aus dem Token
    allein berechenbar) + optionalem Per-Post-`salt` (z.B. post_id), damit die
    anonymen Posts eines Users NICHT mehr untereinander verkettbar sind.

    Bestehende Posts behalten ihren bereits gespeicherten anon_handle und
    bleiben lesbar — diese Funktion wird beim Read nur als Fallback für
    Legacy-Posts OHNE gespeicherten Handle aufgerufen.
    """
    msg = 'anonwall:' + (token or '')
    if salt:
        msg += ':' + str(salt)
    h = hmac.new(_anon_handle_secret(), msg.encode(), _hashlib.sha256).hexdigest()
    a = _ANON_ADJ[int(h[0:4], 16) % len(_ANON_ADJ)]
    n = _ANON_NOUN[int(h[4:8], 16) % len(_ANON_NOUN)]
    # h[8:11] → 3 hex chars → 0-4095; %1000 → 0-999 als :03d suffix.
    return f'{a}{n}{int(h[8:11], 16) % 1000:03d}'

# ── Wall-Posts SB persistence (P0 Worker-P1, 2026-06-01) ──
# Disk-only war auf Cloud Run ein Wipe-pro-Redeploy. Pattern wie _auth_load/_save:
#   primary = SB, fallback = Disk, einmal-Lazy-Migrate beim ersten SB-leeren Read.
# Schema: 1 Row pro Post mit Whitelist-Columns + metadata jsonb für Rest
# (author_short, author_name, author_airline, author_homebase, created_at, etc.).
_WALL_POST_KNOWN_COLS = {
    'id', 'author_token', 'ts', 'layover_iata', 'image_url',
    'hashtags', 'like_count', 'comment_count', 'deleted',
    # Privacy: explizite Spalten statt metadata-jsonb (02_supabase_rebuild.sql).
    # Load-bearing für "anonym posten" — anon_handle pseudonymisiert den Author.
    'is_anonymous', 'anon_handle',
}


def _wall_posts_load_from_supabase():
    """Liest alle nicht-gelöschten Wall-Posts aus SB. None bei SB-down/error.
    Paginiert in 1000er-Schritten. Re-hydrated post-dict shape (text/hashtags/
    author_* aus metadata zurückfalten)."""
    if not SB_AVAILABLE:
        return None
    try:
        out = []
        offset = 0
        page = 1000
        while True:
            r = (sb.table('wall_posts').select('*')
                 .eq('deleted', False)
                 .order('ts', desc=False)
                 .range(offset, offset + page - 1).execute())
            rows = r.data or []
            for row in rows:
                post = {}
                for k in _WALL_POST_KNOWN_COLS:
                    v = row.get(k)
                    if v is not None:
                        post[k] = v
                # body-column → text-feld (Frontend erwartet 'text'; die SB-
                # Spalte heisst 'body' weil das semantisch konsistent zu
                # forum_threads.body / forum_replies.body ist).
                if row.get('body') is not None:
                    post['text'] = row.get('body')
                md = row.get('metadata') or {}
                if isinstance(md, dict):
                    for k, v in md.items():
                        if k not in post:
                            post[k] = v
                out.append(post)
            if len(rows) < page:
                break
            offset += page
        return out
    except Exception as e:
        app.logger.warning(f'[wall] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _wall_posts_save_to_supabase(posts):
    """Bulk-upsert aller Wall-Posts nach SB. True bei vollem Erfolg, False sonst.
    Splittet in 500er Batches. Posts ohne id werden ignoriert."""
    if not SB_AVAILABLE or posts is None:
        return False
    rows = []
    for p in (posts or []):
        if not isinstance(p, dict):
            continue
        pid = p.get('id')
        if not pid:
            continue
        row = {'id': pid}
        meta = {}
        for k, v in p.items():
            if k == 'text':
                row['body'] = v
            elif k == 'body':
                row['body'] = v
            elif k in _WALL_POST_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        if row.get('author_token') is None:
            row['author_token'] = ''
        if row.get('ts') is None:
            row['ts'] = 0
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_WALL_POSTS)
    try:
        for i in range(0, len(rows), 500):
            sb.table('wall_posts').upsert(rows[i:i+500], on_conflict='id').execute()
        return True
    except Exception as e:
        app.logger.error(f'[wall] sb_save_fail err={type(e).__name__}: {str(e)[:200]}')
        return False


# ── Wall-Likes per User SB persistence (P1-Leftover, 2026-06-01) ──
# Eine Row pro (post_id, user_token). Disk-Cache als Fallback (likes_<token>.json).
def _wall_likes_load_from_supabase(token):
    """Set aller post_ids die dieser user_token geliked hat. None bei SB-down."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('wall_likes').select('post_id')
             .eq('user_token', token).execute())
        return {row['post_id'] for row in (r.data or []) if row.get('post_id')}
    except Exception as e:
        app.logger.warning(f'[wall-likes] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _wall_likes_sb_add(token, post_id):
    if not SB_AVAILABLE or not token or not post_id:
        return False
    try:
        sb.table('wall_likes').upsert(
            {'post_id': post_id, 'user_token': token},
            on_conflict='post_id,user_token').execute()
        return True
    except Exception as e:
        app.logger.warning(f'[wall-likes] sb_add_fail: {str(e)[:120]}')
        return False


def _wall_likes_sb_remove(token, post_id):
    if not SB_AVAILABLE or not token or not post_id:
        return False
    try:
        (sb.table('wall_likes').delete()
         .eq('user_token', token).eq('post_id', post_id).execute())
        return True
    except Exception as e:
        app.logger.warning(f'[wall-likes] sb_del_fail: {str(e)[:120]}')
        return False


def _wall_likes_load(token):
    """SB primary, Disk fallback, lazy-migrate. Returns set of post_ids."""
    sb_data = _wall_likes_load_from_supabase(token)
    if sb_data is not None:
        if not sb_data:
            # Lazy-migrate von Disk wenn SB leer
            disk_p = _wall_likes_path(token)
            if disk_p:
                try:
                    with open(disk_p) as f:
                        disk_ids = set(json.load(f) or [])
                    if disk_ids and SB_AVAILABLE:
                        rows = [{'post_id': pid, 'user_token': token} for pid in disk_ids]
                        try:
                            sb.table('wall_likes').upsert(
                                rows, on_conflict='post_id,user_token').execute()
                            app.logger.info(f'[wall-likes] lazy-migrated {len(disk_ids)} disk likes')
                            return disk_ids
                        except Exception:
                            pass
                    return disk_ids
                except (FileNotFoundError, json.JSONDecodeError, Exception):
                    pass
        return sb_data
    # SB down → Disk
    disk_p = _wall_likes_path(token)
    if not disk_p:
        return set()
    try:
        with open(disk_p) as f:
            return set(json.load(f) or [])
    except (FileNotFoundError, json.JSONDecodeError, Exception):
        return set()


# ── Wall-Comments SB persistence (P1-Leftover, 2026-06-01) ──
# Eine Row pro Comment. body ↔ text (analog wall_posts).
_WALL_COMMENT_KNOWN_COLS = {
    'id', 'post_id', 'author_token', 'ts', 'parent_id', 'image_url',
    # Privacy: explizite Spalten statt metadata-jsonb (02_supabase_rebuild.sql).
    'is_anonymous', 'anon_handle',
}


def _wall_comments_load_from_supabase(post_id):
    """Liest Comments für genau einen Post. None bei SB-down."""
    if not SB_AVAILABLE or not post_id:
        return None
    try:
        r = (sb.table('wall_comments').select('*')
             .eq('post_id', post_id)
             .order('ts', desc=False)
             .range(0, 999).execute())
        out = []
        for row in (r.data or []):
            c = {}
            for k in _WALL_COMMENT_KNOWN_COLS:
                v = row.get(k)
                if v is not None:
                    c[k] = v
            if row.get('body') is not None:
                c['text'] = row.get('body')
            # parent_comment_id ist iOS-Naming, SB-Spalte ist parent_id
            if 'parent_id' in c:
                c['parent_comment_id'] = c.pop('parent_id')
            md = row.get('metadata') or {}
            if isinstance(md, dict):
                for k, v in md.items():
                    if k not in c:
                        c[k] = v
            # iOS erwartet `created_at` als ISO-String — aus ts rekonstruieren
            if 'created_at' not in c and c.get('ts'):
                try:
                    c['created_at'] = datetime.fromtimestamp(float(c['ts'])).isoformat()
                except Exception:
                    pass
            out.append(c)
        return out
    except Exception as e:
        app.logger.warning(f'[wall-comments] sb_load_fail post={(post_id or "")[:8]}: {str(e)[:120]}')
        return None


def _wall_comments_save_to_supabase(post_id, comments):
    """Upsert für gesamten Comment-Stream eines Posts. Splittet in 200er Batches."""
    if not SB_AVAILABLE or not post_id or comments is None:
        return False
    rows = []
    import time as _t
    for c in (comments or []):
        if not isinstance(c, dict):
            continue
        cid = c.get('id')
        if not cid:
            continue
        row = {'id': cid, 'post_id': post_id}
        meta = {}
        for k, v in c.items():
            if k == 'text':
                row['body'] = v
            elif k == 'body':
                row['body'] = v
            elif k == 'parent_comment_id':
                row['parent_id'] = v
            elif k in _WALL_COMMENT_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        if row.get('author_token') is None:
            row['author_token'] = ''
        if row.get('ts') is None:
            # falls created_at vorhanden, dort parsen, sonst now()
            ca = c.get('created_at')
            if ca:
                try:
                    row['ts'] = datetime.fromisoformat(ca).timestamp()
                except Exception:
                    row['ts'] = _t.time()
            else:
                row['ts'] = _t.time()
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_WALL_COMMENTS)
    try:
        for i in range(0, len(rows), 200):
            sb.table('wall_comments').upsert(rows[i:i+200], on_conflict='id').execute()
        return True
    except Exception as e:
        app.logger.error(f'[wall-comments] sb_save_fail post={(post_id or "")[:8]} err={type(e).__name__}: {str(e)[:200]}')
        return False


def _wall_comments_load(post_id):
    """SB primary, Disk fallback, lazy-migrate."""
    sb_data = _wall_comments_load_from_supabase(post_id)
    cp = _wall_comments_path(post_id)
    if sb_data is None:
        # SB down → Disk
        try:
            with open(cp) as f:
                return json.load(f) or []
        except (FileNotFoundError, json.JSONDecodeError, Exception):
            return []
    if sb_data:
        return sb_data
    # SB ok aber leer → vielleicht Disk-Reste lazy-migraten
    try:
        with open(cp) as f:
            disk_data = json.load(f) or []
        if disk_data and SB_AVAILABLE:
            app.logger.info(f'[wall-comments] lazy-migrate {len(disk_data)} disk comments post={(post_id or "")[:8]}')
            _wall_comments_save_to_supabase(post_id, disk_data)
        return disk_data
    except (FileNotFoundError, json.JSONDecodeError, Exception):
        return []


def _wall_comments_save(post_id, comments):
    """SB primary + Disk best-effort. Cap auf 200 Comments."""
    capped = (comments or [])[-200:] if isinstance(comments, list) else comments
    sb_ok = _wall_comments_save_to_supabase(post_id, capped)
    cp = _wall_comments_path(post_id)
    if cp:
        try:
            _atomic_write_json(cp, capped, max_items=200)
        except Exception as e:
            app.logger.warning(f'[wall-comments] disk_save_fail (ok wenn SB lief): {e}')
            if not sb_ok:
                app.logger.error('[wall-comments] CRITICAL: weder SB noch Disk gesichert!')


def _wall_load_posts_from_disk():
    p = _wall_posts_path()
    try:
        with open(p) as f:
            return json.load(f) or []
    except FileNotFoundError:
        return []
    except Exception:
        return []


def _wall_load_posts():
    """SB+Disk merge, dedupe by id, sorted by ts.

    BUG-FIX (Wave-1 P0, 2026-06-02): Vorher war's SB-or-Disk (SB gewinnt wenn
    non-empty). Konsequenz: Wenn `_wall_save_posts` Supabase-upsert silent failt
    (caught Exception → warn-log only), aber Disk-Write succeeds, liefert der
    nächste `_wall_load_posts`-Call die *stale* SB-Daten zurück, der frische
    Post auf Disk ist invisible. Cross-Instance auf Cloud Run war's noch
    schlimmer: Disk ist per-Instance, neue Posts auf Instance-A blieben für
    Instance-B unsichtbar bis SB-Sync wieder lief.

    Fix: MERGE statt either-or. Lade beide Quellen, dedupliziere nach `id`,
    bei Konflikt gewinnt der höhere `ts` (frischere Daten). So sieht jede
    Instanz den letzten gesicherten Post — egal welche Quelle ihn hat.
    """
    sb_data = _wall_posts_load_from_supabase()
    disk_data = _wall_load_posts_from_disk()
    if sb_data is None:
        # SB down → reine Disk-Antwort
        return disk_data or []
    # Beide Quellen vorhanden — merge by id, neueres ts gewinnt
    merged = {}
    for p in (sb_data or []):
        pid = p.get('id') if isinstance(p, dict) else None
        if pid:
            merged[pid] = p
    for p in (disk_data or []):
        pid = p.get('id') if isinstance(p, dict) else None
        if not pid:
            continue
        existing = merged.get(pid)
        if existing is None:
            merged[pid] = p
        else:
            # Bei Konflikt: höheres ts (frischere Version) gewinnt. Bei GLEICHEM
            # ts gewinnt SB: seit dem Per-Row-Refactor (2026-07-01) mutieren
            # Counter (like/comment) NUR die SB-Row — das ts bleibt gleich, die
            # Disk-Kopie ist stale. Vorher (`>=`) hätte die Disk-Kopie die
            # frischen SB-Counter geclobbert.
            new_ts = float(p.get('ts') or 0)
            old_ts = float(existing.get('ts') or 0)
            if new_ts > old_ts:
                merged[pid] = p
    # Lazy-migrate disk → SB wenn SB leer + Disk-Daten vorhanden + SB up
    if not sb_data and disk_data and SB_AVAILABLE:
        app.logger.info(f'[wall] lazy-migrate {len(disk_data)} disk posts → supabase')
        _wall_posts_save_to_supabase(disk_data)
    out = list(merged.values())
    # Stable order by ts ascending (Append-Pattern erhalten — _wall_save_posts
    # cappt nach `-5000:` auf den hinteren Slice; das setzt aufsteigende Ordnung
    # voraus, sonst werden ältere Posts weggeschnitten).
    out.sort(key=lambda p: float(p.get('ts') or 0))
    return out


def _wall_save_posts(posts):
    """SB primary + Disk best-effort Read-Cache. Cap auf letzte 5000 Posts.

    BUG-FIX (Wave-1 P0, 2026-06-02): Returnt jetzt True/False statt None.
    Caller können entscheiden ob sie ein Schreib-Fehler propagieren wollen.
    `create_wall_post` macht das nicht (Best-Effort UX), aber neuere Routes
    sollen explizit prüfen können."""
    capped = (posts or [])[-5000:] if isinstance(posts, list) else posts
    sb_ok = _wall_posts_save_to_supabase(capped)
    p = _wall_posts_path()
    disk_ok = False
    try:
        _atomic_write_json(p, capped, max_items=5000)
        disk_ok = True
    except Exception as e:
        app.logger.warning(f'[wall] disk_save_fail (ok wenn SB läuft): {e}')
        if not sb_ok:
            app.logger.error('[wall] CRITICAL: weder SB noch Disk gesichert!')
    return bool(sb_ok or disk_ok)


# ── Wall per-Row-Operations (Data-Layer-Refactor 2026-07-01) ────────────────
# Vorher: JEDE Mutation lief als load-ALL (bis 5000 Posts, select *) →
# mutate-in-Python → save-ALL (10 Bulk-Upsert-Batches). Kosten/Latenz/Races
# (Lost-Updates über mehrere Cloud-Run-Instanzen trotz Prozess-Lock).
# Jetzt: 1 Insert pro Create, atomarer Counter-RPC pro Like/Comment, bounded
# SELECT für den Feed. Disk bleibt best-effort Read-Cache für SB-down.

def _wall_post_from_row(row):
    """SB-Row → Post-Dict (gleiche Re-Hydration wie _wall_posts_load_from_supabase)."""
    post = {}
    for k in _WALL_POST_KNOWN_COLS:
        v = row.get(k)
        if v is not None:
            post[k] = v
    if row.get('body') is not None:
        post['text'] = row.get('body')
    md = row.get('metadata') or {}
    if isinstance(md, dict):
        for k, v in md.items():
            if k not in post:
                post[k] = v
    return post


_WALL_POST_SELECT_COLS = ('id,author_token,ts,body,layover_iata,image_url,'
                          'hashtags,like_count,comment_count,deleted,'
                          'is_anonymous,anon_handle,metadata')


def _wall_posts_load_recent(limit, before_ts=0, author_in=None):
    """Bounded Feed-Read: neueste `limit` Posts (ts desc), optional Cursor +
    Author-Filter (friends-mode). None bei SB-down → Caller nutzt Disk."""
    if not SB_AVAILABLE:
        return None
    try:
        q = (sb.table('wall_posts').select(_WALL_POST_SELECT_COLS)
             .eq('deleted', False))
        if before_ts and before_ts > 0:
            q = q.lt('ts', before_ts)
        if author_in is not None:
            q = q.in_('author_token', list(author_in)[:300])
        r = q.order('ts', desc=True).limit(int(limit)).execute()
        return [_wall_post_from_row(row) for row in (r.data or [])]
    except Exception as e:
        app.logger.warning(f'[wall] recent_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _wall_post_sb_get(post_id):
    """Einzelner Post aus SB (per-Row statt load-ALL). None bei miss/SB-down."""
    if not SB_AVAILABLE or not post_id:
        return None
    try:
        r = (sb.table('wall_posts').select(_WALL_POST_SELECT_COLS)
             .eq('id', post_id).limit(1).execute())
        rows = r.data or []
        return _wall_post_from_row(rows[0]) if rows else None
    except Exception as e:
        app.logger.warning(f'[wall] sb_get_fail id={(post_id or "")[:8]}: {str(e)[:120]}')
        return None


def _wall_disk_posts_mutate(fn):
    """Wendet fn(list)->list|None auf den Disk-Read-Cache an (lokal, kein SB).
    fn returnt None ⇒ nichts geändert, kein Rewrite."""
    try:
        posts = _wall_load_posts_from_disk() or []
        new_posts = fn(posts)
        if new_posts is None:
            return
        _atomic_write_json(_wall_posts_path(), (new_posts or [])[-5000:],
                           max_items=5000)
    except Exception as e:
        app.logger.warning(f'[wall] disk_mutate_fail (ok wenn SB läuft): {e}')


def _wall_disk_append_post(post):
    _wall_disk_posts_mutate(lambda posts: posts + [post])


def _wall_disk_remove_post(post_id):
    def _rm(posts):
        new = [p for p in posts if p.get('id') != post_id]
        return new if len(new) != len(posts) else None
    _wall_disk_posts_mutate(_rm)


def _wall_disk_counter_bump(post_id, like_delta=0, dislike_delta=0,
                            comment_delta=0):
    """Per-Row-Counter-Bump im Disk-Cache. Returns dict der neuen Counts
    ({} wenn Post nicht auf Disk) — SB-down-Fallback für die Like-Routes."""
    out = {}

    def _bump(posts):
        for p in posts:
            if p.get('id') == post_id:
                if like_delta:
                    p['like_count'] = max(0, (p.get('like_count') or 0) + like_delta)
                if dislike_delta:
                    p['dislike_count'] = max(0, (p.get('dislike_count') or 0) + dislike_delta)
                if comment_delta:
                    p['comment_count'] = max(0, (p.get('comment_count') or 0) + comment_delta)
                out.update({'like_count': p.get('like_count') or 0,
                            'dislike_count': p.get('dislike_count') or 0,
                            'comment_count': p.get('comment_count') or 0})
                return posts
        return None
    _wall_disk_posts_mutate(_bump)
    return out


def _wall_post_apply_counters(post_id, like_delta=0, dislike_delta=0,
                              comment_delta=0):
    """Atomarer server-seitiger Counter-Bump (RPC wall_post_counters_apply,
    Migration 20260701_data_layer.sql). Fallback ohne RPC: best-effort
    read-modify-write auf EINER Row (immer noch kein load-ALL/save-ALL).
    Returns {'like_count','dislike_count','comment_count'} oder None wenn SB
    down / Post nicht in SB (Caller degradiert auf Disk-Bump)."""
    if not SB_AVAILABLE or not post_id:
        return None
    ok, data = _social_rpc_call('wall_post_counters_apply', {
        'p_post_id': post_id, 'p_like': int(like_delta),
        'p_dislike': int(dislike_delta), 'p_comment': int(comment_delta)})
    result = None
    if ok and isinstance(data, list) and data and isinstance(data[0], dict):
        row = data[0]
        result = {'like_count': int(row.get('like_count') or 0),
                  'dislike_count': int(row.get('dislike_count') or 0),
                  'comment_count': int(row.get('comment_count') or 0)}
    if result is None:
        # Degradierter Fallback (RPC fehlt): EINE Row lesen, mutieren, schreiben.
        try:
            r = (sb.table('wall_posts')
                 .select('like_count,comment_count,metadata')
                 .eq('id', post_id).limit(1).execute())
            rows = r.data or []
            if not rows:
                return None
            row = rows[0]
            md = row.get('metadata') if isinstance(row.get('metadata'), dict) else {}
            new_like = max(0, int(row.get('like_count') or 0) + int(like_delta))
            new_comment = max(0, int(row.get('comment_count') or 0) + int(comment_delta))
            try:
                cur_dis = int(md.get('dislike_count') or 0)
            except (TypeError, ValueError):
                cur_dis = 0
            new_dis = max(0, cur_dis + int(dislike_delta))
            upd = {'like_count': new_like, 'comment_count': new_comment}
            if dislike_delta:
                md = dict(md)
                md['dislike_count'] = new_dis
                upd['metadata'] = md
            sb.table('wall_posts').update(upd).eq('id', post_id).execute()
            result = {'like_count': new_like, 'dislike_count': new_dis,
                      'comment_count': new_comment}
        except Exception as e:
            app.logger.warning(f'[wall] counter_fallback_fail id={(post_id or "")[:8]}: {str(e)[:120]}')
            return None
    # Disk-Read-Cache per-Row nachziehen (sonst servierte der SB-down-Fallback
    # später stale Counts).
    _wall_disk_counter_bump(post_id, like_delta=like_delta,
                            dislike_delta=dislike_delta,
                            comment_delta=comment_delta)
    return result


def _sanitize_user_text(text, max_len=None):
    """UGC-Text-Sanitizer: HTML-Escape + Control-Char-Strip + optionaler Truncate.

    Wird auf JEDES User-generierte Textfeld angewendet das später irgendwo
    gerendert wird (Wall-Posts, Comments, Forum-Threads/Replies, DMs). iOS
    rendert mit Text() safe, aber sobald wir einen Web-Client oder ein PDF
    ausliefern, ist <script>-Stored-XSS möglich. Daher zentral hier blocken.
    """
    if not text:
        return ''
    import html as _html
    s = str(text)
    # Control-Chars (außer \n, \t) entfernen — diese können Render brechen.
    s = ''.join(c for c in s if c == '\n' or c == '\t' or ord(c) >= 32)
    # HTML-Escape — &<>" werden in Entities umgewandelt.
    s = _html.escape(s, quote=True)
    if max_len:
        s = s[:max_len]
    return s.strip()


def _detect_image_type(data: bytes):
    """Magic-Byte-Sniff. Returns ('jpeg'|'png'|'heic'|'webp'|None, extension).
    Verhindert dass jemand .jpg-Extension auf eine .html-Datei klebt.
    """
    if not data or len(data) < 12:
        return (None, None)
    head = data[:12]
    if head[:3] == b'\xff\xd8\xff':
        return ('jpeg', '.jpg')
    if head[:8] == b'\x89PNG\r\n\x1a\n':
        return ('png', '.png')
    if head[4:8] == b'ftyp' and (head[8:12] in (b'heic', b'heix', b'mif1', b'msf1', b'hevc', b'hevx')):
        return ('heic', '.heic')
    if head[:4] == b'RIFF' and head[8:12] == b'WEBP':
        return ('webp', '.webp')
    return (None, None)


# ── Wall-Image Token-Leak-Fix (2026-06-10) ──────────────────────────────────
# Vorher lag das volle AT-Token (= Bearer-Credential!) als Verzeichnis-Segment
# in der ÖFFENTLICHEN Bild-URL (/api/wall/image/<token>/<fname>) → Deanonymi-
# sierung anonymer Posts + Account-Takeover für jeden Feed-Leser. Jetzt: opaker,
# deterministisch abgeleiteter Key. Legacy-URLs in alten Posts/Kommentaren/
# Chat-Nachrichten bleiben serve-bar (Key→Dir-Mapping), werden aber in allen
# Responses auf den opaken Key umgeschrieben.

_WALL_IMG_LEGACY_URL_RE = re.compile(r'/api/wall/image/(AT-[A-Za-z0-9_-]{1,64})/')
_WALL_IMG_KEY_DIRS = {}  # opaque key → Legacy-Token-Verzeichnisname (lazy Cache)


def _wall_img_key(token):
    """Opaker Verzeichnis-Key, deterministisch aus dem Token abgeleitet —
    das Token selbst darf NIE in öffentlichen URLs auftauchen."""
    return _hashlib.sha256(('wall-img:' + (token or '')).encode()).hexdigest()[:32]


def _wall_img_legacy_dir(key):
    """Mappt einen opaken Key zurück auf das Legacy-Token-Verzeichnis
    (alte Uploads liegen noch unter wall_images/<token>/)."""
    d = _WALL_IMG_KEY_DIRS.get(key)
    if d:
        return d
    base = os.path.join(_USER_HISTORY_DIR, 'wall_images')
    try:
        for name in os.listdir(base):
            if name.startswith('AT-') and os.path.isdir(os.path.join(base, name)):
                _WALL_IMG_KEY_DIRS[_wall_img_key(name)] = name
        _cache_soft_cap(_WALL_IMG_KEY_DIRS, max_items=5000, drop=1000)
    except Exception:
        pass
    return _WALL_IMG_KEY_DIRS.get(key)


def _wall_img_sanitize_urls(text):
    """Ersetzt Legacy-Token-Segmente in Wall-Image-URLs durch den opaken Key.
    Arbeitet auf beliebigen Strings (image_url-Felder UND Chat-Texte mit
    eingebetteten Photo-URLs)."""
    if not text or '/api/wall/image/AT-' not in text:
        return text
    try:
        return _WALL_IMG_LEGACY_URL_RE.sub(
            lambda m: f'/api/wall/image/{_wall_img_key(m.group(1))}/', text)
    except Exception:
        return text


@app.route('/api/wall/<token>/upload-image', methods=['POST'])
def upload_wall_image(token):
    """Upload Bild für Wall-Post. Returns {url} zum nachträglichen Einbetten in /post."""
    # Rate-Limit: max 20 Bilder pro Stunde pro User (verhindert Storage-Flood)
    if _token_rate_limited(token, 'wall_image_upload', limit=20, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited',
                        'message': 'Zu viele Bild-Uploads. Bitte später erneut.'}), 429
    img = request.files.get('image')
    if not img:
        return jsonify({'ok': False, 'error': 'no_image'}), 400
    data = img.read()
    if len(data) > 5 * 1024 * 1024:
        return jsonify({'ok': False, 'error': 'too_large_5mb'}), 413
    # Magic-Byte-Validation — Extension-Check alleine ist unsicher
    detected_type, detected_ext = _detect_image_type(data)
    if not detected_type:
        return jsonify({'ok': False, 'error': 'invalid_image',
                        'message': 'Nur JPEG/PNG/HEIC/WebP-Bilder erlaubt.'}), 415
    import os, re, uuid
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    if not safe:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    # Token-Leak-Fix: opaker Key statt Token als öffentliches URL-Segment.
    dir_key = _wall_img_key(token)
    img_dir = os.path.join(_USER_HISTORY_DIR, 'wall_images', dir_key)
    os.makedirs(img_dir, exist_ok=True)
    ext = detected_ext  # Extension aus Magic-Byte, nicht aus filename
    fname = f'{uuid.uuid4().hex[:12]}{ext}'
    # DURABILITY (2026-06-30, User #43 „Bild nicht ladbar"): Cloud-Run-Disk ist
    # EPHEMER → Wall-/Chat-Bilder verschwanden bei jedem Redeploy. Wie bei Avataren
    # bevorzugt nach R2 (Zero-Egress, durabel) schreiben; Disk nur noch Fallback.
    # Die public URL bleibt der Backend-Serve-Pfad — serve_wall_image streamt aus R2.
    r2_ok = False
    if R2_AVATARS_ENABLED:
        try:
            _r2_put_bytes(f'wall/{dir_key}/{fname}', data, detected_type)
            r2_ok = True
        except Exception as e:
            app.logger.warning(f'[wall-img] r2_put_fail: {str(e)[:120]}')
    if not r2_ok:
        try:
            with open(os.path.join(img_dir, fname), 'wb') as f:
                f.write(data)
        except Exception as e:
            print(f'[upload_wall_image] error: {type(e).__name__}: {str(e)[:300]}')
            return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True, 'url': f'/api/wall/image/{dir_key}/{fname}'})


@app.route('/api/wall/image/<token_safe>/<fname>', methods=['GET'])
def serve_wall_image(token_safe, fname):
    """Serve uploaded image — public (kein Auth da im Feed-Kontext zugänglich)."""
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_.-]', '', fname or '')
    safe_t = re.sub(r'[^A-Za-z0-9_-]', '', token_safe or '')[:64]
    if not safe or not safe_t:
        return jsonify({'error': 'invalid'}), 400
    path = os.path.join(_USER_HISTORY_DIR, 'wall_images', safe_t, safe)
    if not os.path.exists(path):
        # Token-Leak-Fix: URLs tragen jetzt den opaken Key, ältere Dateien
        # liegen aber noch unter dem Legacy-Token-Verzeichnis → Mapping.
        legacy = _wall_img_legacy_dir(safe_t)
        if legacy:
            path = os.path.join(_USER_HISTORY_DIR, 'wall_images', legacy, safe)
    if not os.path.exists(path):
        # DURABILITY: Datei nicht (mehr) auf der ephemeren Disk → aus R2 streamen
        # (neue Uploads liegen in R2, Disk ist nur Fallback). Behebt „Bild nicht
        # ladbar" nach Redeploy (User #43).
        if R2_AVATARS_ENABLED:
            r2_data, r2_ctype = _r2_get_bytes(f'wall/{safe_t}/{safe}')
            # LEGACY-RECOVERY: trägt die (alte, evtl. un-sanitisierte) URL noch das
            # rohe Token (AT-…) statt des opaken Keys, dann liegt das R2-Objekt unter
            # dem opaken Key (R2-Uploads schreiben IMMER mit _wall_img_key). Einmal
            # mit dem abgeleiteten opaken Key nachfassen → rettet post-R2-Bilder,
            # deren gespeicherte URL der Sanitizer nicht erwischt hat.
            if not r2_data and safe_t.startswith('AT-'):
                try:
                    r2_data, r2_ctype = _r2_get_bytes(f'wall/{_wall_img_key(safe_t)}/{safe}')
                except Exception:
                    r2_data = None
            if r2_data:
                from flask import Response
                return Response(r2_data, mimetype=r2_ctype or 'image/jpeg',
                                headers={'Cache-Control': 'public, max-age=31536000, immutable'})
        # Pre-R2-Bilder lagen NUR auf der ephemeren Cloud-Run-Disk (kein R2-, kein
        # Supabase-Backup) → nach einem Redeploy unwiederbringlich weg. Hier sauber
        # 404 (JSON), damit die iOS-Tafel/Chat einen Platzhalter zeigt statt zu hängen.
        return jsonify({'error': 'not_found'}), 404
    from flask import send_file
    mime = 'image/jpeg'
    if safe.lower().endswith('.png'): mime = 'image/png'
    elif safe.lower().endswith('.heic'): mime = 'image/heic'
    elif safe.lower().endswith('.webp'): mime = 'image/webp'
    return send_file(path, mimetype=mime)


# ── Profil-Avatar Upload + Serve (2026-06-14) ───────────────────────────────
# Persistiert das Profilfoto des Users SERVER-SEITIG, damit es überall (Feed,
# Kommentare, Freunde) — auch für andere User — angezeigt werden kann, statt
# bloß lokal auf dem Gerät zu liegen (vorher: Emoji-Platzhalter für jeden).
# Storage reuse: gleiches file-based Pattern wie Wall-Images (opaker Dir-Key,
# kein Token-Leak in der public URL). Der `avatar_url`-Verweis landet auf der
# Profile-Row (SB-primary via _profile_sidekey_set) und ist bereits in
# _PUBLIC_PROFILE_FIELDS → fließt automatisch durch get_user_friends /
# get_user_profile zu anderen Usern.

def _avatar_img_key(token):
    """Opaker, deterministischer Verzeichnis-Key — Token nie in public URL.
    Eigener Salt ('avatar:') statt Wall-Img-Key, damit beide Namespaces
    getrennt bleiben."""
    return _hashlib.sha256(('avatar:' + (token or '')).encode()).hexdigest()[:32]


# ─── Cloudflare R2 (Avatare/Fotos) — Zero-Egress, durabel ────────────────────
# Kostenhebel AeroX: Bilder NICHT mehr als base64 in Supabase + ueber Cloud Run
# ausliefern (Egress + DB-Bloat + ephemere-Disk-Fragilitaet), sondern in R2 und
# direkt ueber die Cloudflare-Custom-Domain. Aktiv NUR wenn alle Env gesetzt sind
# (sonst alter Disk+base64-Pfad → null Risiko).
R2_AVATARS_BUCKET   = os.environ.get('R2_AVATARS_BUCKET', '')
R2_ENDPOINT         = os.environ.get('R2_ENDPOINT', '')
R2_ACCESS_KEY_ID    = os.environ.get('R2_ACCESS_KEY_ID', '')
R2_SECRET_ACCESS_KEY = os.environ.get('R2_SECRET_ACCESS_KEY', '')
R2_PUBLIC_BASE      = os.environ.get('R2_PUBLIC_BASE', '').rstrip('/')   # z.B. https://avatars.aerosteuer.de
R2_AVATARS_ENABLED  = bool(R2_AVATARS_BUCKET and R2_ENDPOINT and R2_ACCESS_KEY_ID
                           and R2_SECRET_ACCESS_KEY and R2_PUBLIC_BASE)
_r2_client_obj = None
def _r2_client():
    global _r2_client_obj
    if _r2_client_obj is None and R2_AVATARS_ENABLED:
        import boto3
        _r2_client_obj = boto3.client(
            's3', endpoint_url=R2_ENDPOINT,
            aws_access_key_id=R2_ACCESS_KEY_ID,
            aws_secret_access_key=R2_SECRET_ACCESS_KEY,
            region_name='auto')
    return _r2_client_obj
def _r2_put_bytes(key, data, content_type):
    """Bytes unter `key` nach R2 schreiben → oeffentliche URL. None bei Fehler."""
    cli = _r2_client()
    if cli is None:
        return None
    cli.put_object(Bucket=R2_AVATARS_BUCKET, Key=key, Body=data,
                   ContentType=content_type or 'application/octet-stream',
                   CacheControl='public, max-age=31536000, immutable')
    return f'{R2_PUBLIC_BASE}/{key}'
def _r2_put_avatar(dir_key, fname, data, content_type):
    return _r2_put_bytes(f'av/{dir_key}/{fname}', data, content_type)
def _r2_get_bytes(key):
    """Bytes aus R2 ziehen (mit Credentials). (data, content_type) oder (None,None).
    Wird zum DURCHREICHEN genutzt statt 302→r2.dev: die r2.dev-Public-Domain ist
    nicht aktiviert (liefert 403), also streamt das Backend die Bytes selbst —
    funktioniert unabhaengig von der Bucket-Public-Einstellung."""
    cli = _r2_client()
    if cli is None:
        return None, None
    try:
        obj = cli.get_object(Bucket=R2_AVATARS_BUCKET, Key=key)
        return obj['Body'].read(), obj.get('ContentType') or 'image/jpeg'
    except Exception:
        return None, None
def _r2_delete_key(key):
    """Löscht ein einzelnes R2-Objekt. True/False best-effort."""
    cli = _r2_client()
    if cli is None or not key:
        return False
    try:
        cli.delete_object(Bucket=R2_AVATARS_BUCKET, Key=key)
        return True
    except Exception:
        return False


@app.route('/api/user/avatar/<token>', methods=['POST'])
def upload_user_avatar(token):
    """Upload Profilfoto. Body: JSON {image_b64} ODER multipart {image}.
    Persistiert das Bild als Datei + speichert avatar_url auf der Profile-Row.
    Returns {ok, avatar_url}. Idempotent: überschreibt das vorhandene Avatar.
    """
    if _token_rate_limited(token, 'avatar_upload', limit=30, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited',
                        'message': 'Zu viele Uploads. Bitte später erneut.'}), 429
    import os, re, uuid
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    if not safe:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    # Bild aus Multipart ODER base64-JSON lesen (der Client base64-kodiert Bilder
    # bereits an anderer Stelle — beide Pfade unterstützen).
    data = None
    f = request.files.get('image')
    if f:
        data = f.read()
    else:
        body = request.get_json(silent=True) or {}
        b64 = body.get('image_b64') or body.get('image') or ''
        if b64:
            # Optionaler data:-URI-Prefix abschneiden.
            if ',' in b64 and b64.strip().startswith('data:'):
                b64 = b64.split(',', 1)[1]
            try:
                data = base64.b64decode(b64)
            except Exception:
                return jsonify({'ok': False, 'error': 'invalid_base64'}), 400
    if not data:
        return jsonify({'ok': False, 'error': 'no_image'}), 400
    if len(data) > 5 * 1024 * 1024:
        return jsonify({'ok': False, 'error': 'too_large_5mb'}), 413
    detected_type, detected_ext = _detect_image_type(data)
    if not detected_type:
        return jsonify({'ok': False, 'error': 'invalid_image',
                        'message': 'Nur JPEG/PNG/HEIC/WebP-Bilder erlaubt.'}), 415
    dir_key = _avatar_img_key(token)
    img_dir = os.path.join(_USER_HISTORY_DIR, 'avatars', dir_key)
    os.makedirs(img_dir, exist_ok=True)
    # Alte Avatare desselben Users entfernen (sonst Storage-Leak + stale Files).
    try:
        for old in os.listdir(img_dir):
            os.remove(os.path.join(img_dir, old))
    except Exception:
        pass
    # Cache-Buster im Dateinamen → Clients/CDN ziehen das neue Bild nach Wechsel.
    fname = f'{uuid.uuid4().hex[:12]}{detected_ext}'
    # NEU: bevorzugt nach R2 (Zero-Egress, durabel) → avatar_url = oeffentliche
    # R2-URL (die App handhabt absolute URLs bereits via hasPrefix("http")).
    r2_ok = False
    if R2_AVATARS_ENABLED:
        try:
            _r2_put_avatar(dir_key, fname, data, detected_type)
            r2_ok = True
        except Exception as e:
            app.logger.warning(f'[avatar] r2_put_fail tok={token[:8]}: {e}')
            r2_ok = False
    if not r2_ok:
        # Fallback (R2 aus/Fehler): wie bisher auf die (ephemere) Disk.
        try:
            with open(os.path.join(img_dir, fname), 'wb') as fp:
                fp.write(data)
        except Exception as e:
            print(f'[upload_user_avatar] error: {type(e).__name__}: {str(e)[:300]}')
            return jsonify({'ok': False, 'error': 'internal_error'}), 500
    # avatar_url IMMER der Backend-Serve-Pfad (nicht die rohe r2.dev-URL: deren
    # Public-Domain ist deaktiviert → 403). serve_user_avatar streamt aus R2.
    avatar_url = f'/api/user/avatar/{dir_key}/{fname}'
    # avatar_url auf die Profile-Row schreiben (SB-primary + Disk) — damit Feed/
    # Freunde/Profil den Verweis ausliefern können.
    #
    # DURABILITY-FIX (2026-06-15): Render's Filesystem ist EPHEMERAL — die oben
    # geschriebene Datei (`_USER_HISTORY_DIR/avatars/...`) verschwindet bei jedem
    # Redeploy/Restart. Vorher landete nur die `avatar_url` durabel in Supabase,
    # die Bild-DATEI aber nur auf der flüchtigen Disk → nach dem nächsten Deploy
    # lieferte `serve_user_avatar` 404 und überall erschienen die Emoji-/Fake-
    # Platzhalter. URSACHE des "Foto wird nicht gespeichert"-Bugs.
    # Lösung: die Bytes ZUSÄTZLICH base64 in die (Supabase-persistente) Profile-
    # Metadata schreiben — keyed mit dem opaken dir_key, damit `serve_user_avatar`
    # (das nur den dir_key kennt, nicht den Token) sie wiederfinden kann. Reuse
    # des bestehenden _profile_sidekey_set-Persistenz-Pfads (SB metadata-jsonb +
    # Disk-Cache), kein neues Schema. ~200 KB JPEG → ~270 KB base64, passt in JSONB.
    # Alle vier Keys in EINEM Load+Save schreiben (statt 4× _profile_sidekey_set
    # mit je einem SB-Roundtrip) — gleiche SB-primary+Disk-Persistenz, 1 Upsert.
    _persist_ok = False
    try:
        full = _profile_load(token) or {}
        profile = dict(full.get('profile') or {})
        profile['avatar_url'] = avatar_url
        profile['avatar_dir_key'] = dir_key
        profile['avatar_mime'] = detected_type
        if r2_ok:
            # R2 ist durabel → KEIN base64-Backup mehr in Supabase (spart DB+Egress).
            profile['avatar_b64'] = None
        else:
            profile['avatar_b64'] = base64.b64encode(data).decode()
        disk_full = dict(_profile_load_from_disk(token) or {})
        disk_full['token'] = token
        disk_full['profile'] = profile
        disk_full['avatar_url'] = avatar_url
        disk_full['_updated_at'] = datetime.now().isoformat()
        _persist_ok = bool(_profile_save(token, profile, full_disk_payload=disk_full))
    except Exception as e:
        app.logger.warning(f'[avatar] profile_set_fail tok={token[:8]}: {e}')
    # J5-Fix (Sweep 2026-07-10): landet avatar_url NICHT auf der Profile-Row,
    # sehen alle ANDEREN weiter den Platzhalter (der Uploader sein lokales Foto)
    # — Fehler ehrlich als 503 melden statt ok:true, iOS kann retryen.
    if not _persist_ok:
        return jsonify({'ok': False, 'error': 'profile_persist_failed'}), 503
    return jsonify({'ok': True, 'avatar_url': avatar_url})


def _avatar_bytes_from_supabase(dir_key):
    """Reverse-Lookup der durabel gespeicherten Avatar-Bytes über den opaken
    dir_key (für `serve_user_avatar`, wenn die ephemere Disk-Datei nach einem
    Render-Redeploy weg ist). Sucht die user_profiles-Row, deren metadata-jsonb
    `avatar_dir_key == dir_key` enthält. Returns (bytes, mime) oder (None, None)."""
    if not SB_AVAILABLE or not dir_key:
        return None, None
    try:
        def _do():
            return (sb.table('user_profiles')
                      .select('metadata')
                      .eq('metadata->>avatar_dir_key', dir_key)
                      .limit(1).execute())
        r, timed_out = _supabase_execute_with_timeout('avatar_lookup', _do, timeout_s=5)
        if timed_out or r is None:
            return None, None
        rows = getattr(r, 'data', None) or []
        if not rows:
            return None, None
        meta = rows[0].get('metadata') or {}
        b64 = meta.get('avatar_b64')
        mime = meta.get('avatar_mime') or 'image/jpeg'
        if not b64:
            return None, None
        return base64.b64decode(b64), mime
    except Exception as e:
        app.logger.warning(f'[avatar] sb_lookup_fail dir={dir_key[:8]}: {type(e).__name__}')
        return None, None


@app.route('/api/user/avatar/<key_safe>/<fname>', methods=['GET'])
def serve_user_avatar(key_safe, fname):
    """Serve Profilfoto — public (im Feed-/Friends-Kontext für alle sichtbar)."""
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_.-]', '', fname or '')
    safe_k = re.sub(r'[^A-Za-z0-9_-]', '', key_safe or '')[:64]
    if not safe or not safe_k:
        return jsonify({'error': 'invalid'}), 400
    mime = 'image/jpeg'
    if safe.lower().endswith('.png'): mime = 'image/png'
    elif safe.lower().endswith('.heic'): mime = 'image/heic'
    elif safe.lower().endswith('.webp'): mime = 'image/webp'
    # R2: liegt der Avatar in R2 → Bytes durchstreamen. NICHT mehr 302→r2.dev,
    # weil die r2.dev-Public-Domain nicht aktiviert ist (403). Das Backend zieht
    # die Bytes mit Credentials und liefert sie aus (Client-/CDN-cachebar via
    # immutable Cache-Control). Robust unabhaengig von der Bucket-Public-Setting.
    from flask import Response
    r2_key = f'av/{safe_k}/{safe}'
    if R2_AVATARS_ENABLED:
        r2_data, r2_ct = _r2_get_bytes(r2_key)
        if r2_data:
            resp = Response(r2_data, mimetype=r2_ct or mime)
            resp.headers['Cache-Control'] = 'public, max-age=31536000, immutable'
            return resp
    # Bytes holen: erst Disk (ephemer), sonst durabel aus Supabase (base64).
    path = os.path.join(_USER_HISTORY_DIR, 'avatars', safe_k, safe)
    data = None
    out_mime = mime
    if os.path.exists(path):
        try:
            with open(path, 'rb') as fp:
                data = fp.read()
        except Exception:
            data = None
    if data is None:
        data, sb_mime = _avatar_bytes_from_supabase(safe_k)
        if sb_mime:
            out_mime = sb_mime
    if not data:
        return jsonify({'error': 'not_found'}), 404
    # Beim ERSTEN Aufruf nach R2 schieben (Durabilitaet) → Bytes direkt ausliefern.
    if R2_AVATARS_ENABLED:
        try:
            _r2_put_bytes(r2_key, data, out_mime)
        except Exception as e:
            app.logger.warning(f'[avatar] r2_lazy_fail {safe_k}: {e}')
    # Disk rehydrieren (best-effort Cache) + Bytes ausliefern.
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, 'wb') as fp:
            fp.write(data)
    except Exception:
        pass
    resp = Response(data, mimetype=out_mime)
    resp.headers['Cache-Control'] = 'public, max-age=31536000, immutable'
    return resp


@app.route('/api/wall/<token>/post', methods=['POST'])
def create_wall_post(token):
    """Body: {text, image_url?, layover_iata?}. Author = token."""
    # Guest-Token-Block (J23): AT-GUEST-* sind Demo-Tokens die nicht posten dürfen
    if token.startswith('AT-GUEST-'):
        return jsonify({'ok': False, 'error': 'demo_mode_cannot_post'}), 403
    # Wave-1 BUG-004 (2026-06-02): Token-Auth wird zentral via @app.before_request
    # `_bug004_token_auth_gate` durchgesetzt — wir kommen hier nur an mit
    # bekanntem Token (oder AT-GUEST-*, das oben geblockt ist).
    # Rate-Limit: max 10 Wall-Posts pro Stunde pro User
    if _token_rate_limited(token, 'wall_post', limit=10, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited',
                        'message': 'Zu viele Posts in kurzer Zeit. Bitte später erneut.'}), 429
    body = request.get_json(silent=True) or {}
    raw_text = (body.get('text') or '').strip()
    image_url = (body.get('image_url') or '').strip() or None
    layover = (body.get('layover_iata') or '').strip().upper() or None
    if not raw_text and not image_url:
        return jsonify({'ok': False, 'error': 'empty_post'}), 400
    if len(raw_text) > 2000:
        return jsonify({'ok': False, 'error': 'text_too_long'}), 413
    text = _sanitize_user_text(raw_text, max_len=2000)
    # Hashtags aus Body extrahieren — analog Forum (FORUM_HASHTAG_RE).
    # Frontend hängt Picker-Tags als "#tag1 #tag2" an den Body an; das
    # Backend persistiert hier eine deduplizierte Liste für Display + Suche.
    extracted_tags = []
    try:
        seen = set()
        for m in FORUM_HASHTAG_RE.finditer(raw_text or ''):
            t = (m.group(1) or '').lower()
            if t and t not in seen and len(extracted_tags) < 20:
                seen.add(t)
                extracted_tags.append(t)
    except Exception:
        extracted_tags = []
    # Anonyme Layover-Story: KEIN Author-Snapshot, stattdessen stabiler
    # anon_handle. Load-bearing für "anonym posten" — sonst nur pseudonym.
    is_anonymous = bool(body.get('is_anonymous'))
    import uuid, time
    post = {
        'id': str(uuid.uuid4())[:12],
        'author_token': token,
        'author_short': None if is_anonymous else token[:8],
        'text': text,
        'image_url': image_url,
        'layover_iata': layover if layover and len(layover) == 3 else None,
        'hashtags': extracted_tags,
        'created_at': datetime.now().isoformat(),
        'ts': time.time(),
        'like_count': 0,
        'dislike_count': 0,
        'comment_count': 0,
        'is_anonymous': is_anonymous,
    }
    if is_anonymous:
        # Pseudonymer Handle, kein Profil. author_token bleibt server-seitig
        # NUR für Moderation/Ownership (wird im Feed wegstripped). Per-Post-Salt
        # (post-id) → anonyme Posts eines Users sind nicht mehr verkettbar.
        post['anon_handle'] = _anon_handle_for(token, salt=post['id'])
    else:
        # Author profile snapshot (nur bei nicht-anonym). SB-primary statt Disk —
        # auf Cloud Run ist die Disk-Datei ephemer → Posts erschienen als „Crew".
        try:
            pr = (_profile_load(token) or {}).get('profile', {}) or {}
            post['author_name'] = pr.get('name')
            post['author_airline'] = pr.get('airline')
            post['author_homebase'] = pr.get('homebase')
            # author_avatar: serverseitig persistiertes Profilfoto → andere User
            # sehen das echte Foto im Feed statt Emoji-Platzhalter.
            post['author_avatar'] = pr.get('avatar_url')
        except Exception:
            pass
    # Per-Row-Insert (Data-Layer-Refactor 2026-07-01): vorher load-ALL →
    # append → save-ALL (10 Bulk-Batches für EINEN Post). Disk-Append bleibt
    # als Read-Cache/SB-down-Fallback (Feed merged Disk-only-Posts ein).
    _wall_posts_save_to_supabase([post])
    _wall_disk_append_post(post)
    # author_token aus der Create-Response strippen (Privacy-Leak-Fix 2026-06-08):
    # im Feed/Listing wird er bereits entfernt, nur die unmittelbare POST-Response
    # echote ihn noch zurück. Nur opake/Short-Author-Felder bleiben.
    response_post = dict(post)
    response_post.pop('author_token', None)
    response_post['is_mine'] = True
    return jsonify({'ok': True, 'post': response_post})


@app.route('/api/wall/<token>/feed', methods=['GET'])
def get_wall_feed(token):
    """Feed = eigene Posts + Friends-Posts + globale Crew-Posts.
    Query: ?limit=30&before_ts=…&mode=friends|all (default all für lebendigeren Feed).

    User-Pain: "feed ist so leer.. social network feed.. sich immer aktualisieren".
    Vorher hart auf Friends-only — neue User sahen nichts. Jetzt zeigt der Feed
    standardmäßig alle public-Posts (außer blocked/muted), mit Friends als
    Sortier-Boost via has_friend-Flag im Response.
    """
    # BUG-FIX (#25, 2026-06-09): "Feed-Scroll meldet 'nicht erreichbar'".
    # Der Load-More-Pfad ist der EINZIGE, der `before_ts` schickt — ein
    # ValueError beim Parsen (iOS-Double in Scientific-Notation, NaN/Inf,
    # leerer Param nach `&before_ts=`) wurde zu einem 500, das iOS als
    # "nicht erreichbar" zeigt. Parsen daher defensiv: ungültige Cursor/Limits
    # fallen auf den Default zurück statt die ganze Seite zu killen.
    try:
        limit = min(int(float(request.args.get('limit') or 30)), 100)
    except (TypeError, ValueError):
        limit = 30
    if limit < 1:
        limit = 30
    try:
        before_ts = float(request.args.get('before_ts') or 0)
        # NaN/Inf würden den `< before_ts`-Filter unbrauchbar machen.
        if before_ts != before_ts or before_ts in (float('inf'), float('-inf')):
            before_ts = 0
    except (TypeError, ValueError):
        before_ts = 0
    mode = (request.args.get('mode') or 'all').lower()
    # Optionaler Airline-Filter (?airline=LH): Viewer will nur Posts der eigenen
    # Airline sehen (z.B. „LH-Crew sieht nur LH"). Default (kein Param) = alle
    # Airlines — Posting bleibt für alle offen, gefiltert wird NUR die Ansicht.
    # Anonyme Posts tragen kein author_airline (wird unten gestrippt) → fallen aus
    # einer airline-gefilterten Ansicht heraus (man kann sie keiner Airline
    # zuordnen, ohne die Anonymität zu brechen).
    airline_filter = (request.args.get('airline') or '').strip().upper() or None
    friends = set((_friends_load(token).get('friends') or []))
    friends.add(token)
    blocked = _blocked_by(token)
    muted = _muted_by(token)
    # Bounded Feed-Read (Data-Layer-Refactor 2026-07-01): statt load-ALL
    # (bis 5000 Posts, select *) nur ein Fenster der neuesten Posts holen —
    # überfetcht (×3, max 300) weil blocked/muted/hidden client-des-Tokens
    # unten noch rausfiltern. friends-mode filtert server-seitig via .in_().
    # Disk-only-Posts (SB war beim Erstellen down) werden dazugemischt; stale
    # Disk-Kopien bereits geladener IDs NICHT (SB-Counter sind frischer).
    _fetch_n = min(max(limit * 3, 60), 300)
    posts = _wall_posts_load_recent(
        _fetch_n, before_ts=before_ts,
        author_in=(friends if mode == 'friends' else None))
    if posts is None:
        # SB down → Disk-Fallback (altes Verhalten)
        posts = _wall_load_posts_from_disk() or []
    else:
        try:
            _have = {p.get('id') for p in posts}
            for p in (_wall_load_posts_from_disk() or []):
                if p.get('id') and p.get('id') not in _have:
                    posts.append(p)
        except Exception:
            pass
    # Auto-versteckte Posts (≥N Reports) raus — außer für den Author selbst.
    def _visible(p):
        if p.get('author_token') in blocked or p.get('author_token') in muted:
            return False
        if p.get('hidden') and p.get('author_token') != token:
            return False
        return True
    if mode == 'friends':
        feed = [p for p in posts if p.get('author_token') in friends and _visible(p)]
    else:
        # Default: alle Public-Posts (außer blocked/muted/hidden). Friends-Sort
        # kommt client-side über `from_friend`-Flag im Response.
        feed = [p for p in posts if _visible(p)]
    # Airline-Filter anwenden (falls ?airline gesetzt). Anonyme Posts explizit
    # raus — ihre author_airline würde sonst die Anonymität untergraben.
    if airline_filter:
        feed = [p for p in feed
                if not p.get('is_anonymous')
                and (p.get('author_airline') or '').strip().upper() == airline_filter]
    feed.sort(key=lambda p: -(p.get('ts') or 0))
    if before_ts > 0:
        feed = [p for p in feed if (p.get('ts') or 0) < before_ts]
    feed = feed[:limit]
    # Add liked/disliked-by-me flags (SB primary, Disk fallback)
    liked_ids = _wall_likes_load(token) or set()
    disliked_ids = _wall_dislikes_load(token) or set()
    # author_avatar LIVE aus dem Profil auflösen (statt dem evtl. veralteten
    # Post-Snapshot) — so zeigt ein neu gesetztes Profilfoto sofort auf ALLEN
    # alten Posts des Users. Pro-Author einmal cachen (Feed hat oft mehrere
    # Posts desselben Users).
    _avatar_cache = {}
    def _author_avatar(tok):
        if not tok:
            return None
        if tok in _avatar_cache:
            return _avatar_cache[tok]
        try:
            av = ((_profile_load(tok) or {}).get('profile', {}) or {}).get('avatar_url')
        except Exception:
            av = None
        _avatar_cache[tok] = av
        return av
    for p in feed:
        # `id` defensiv lesen — ein Post ohne id (Legacy/teil-migrierte SB-Row)
        # würde sonst per KeyError die ganze Feed-Seite mit 500 killen (#25).
        pid = p.get('id')
        p['liked_by_me'] = pid in liked_ids
        p['disliked_by_me'] = pid in disliked_ids
        p.setdefault('dislike_count', 0)
        # is_mine: Owner-Flag damit iOS-Client einen "Löschen"-Button
        # auf eigene Posts zeigen kann (DSGVO Art. 17 sub-right).
        p['is_mine'] = (p.get('author_token') == token)
        # from_friend: iOS kann Friends-Posts visuell hervorheben
        # (golden Border o.ä.) ohne separates Endpoint-Roundtrip.
        # from_friend MUSS vor dem anon-Strip berechnet werden (author_token noch vorhanden),
        # aber bei anonymen Posts auf False zwingen — sonst leakt from_friend=True die Identität
        # (goldener Border verrät: dieser anonyme Post kommt aus deiner Freundesliste).
        p['from_friend'] = (p.get('author_token') in friends
                            and p.get('author_token') != token
                            and not p.get('is_anonymous'))
        # Anonyme Posts: jeden Profil-Rest entfernen, nur anon_handle bleibt.
        if p.get('is_anonymous'):
            if not p.get('anon_handle'):
                p['anon_handle'] = _anon_handle_for(p.get('author_token'))
            for k in ('author_name', 'author_airline', 'author_homebase',
                      'author_short', 'author_avatar'):
                p.pop(k, None)
        else:
            # author_avatar live aus dem Profil (frisch) — überschreibt den
            # evtl. veralteten Snapshot. None wenn der User (noch) keins hat.
            av = _author_avatar(p.get('author_token'))
            if av:
                p['author_avatar'] = av
            else:
                p.pop('author_avatar', None)
        # Strip author_token for privacy in feed (NACH allen Flags).
        p.pop('author_token', None)
        # Token-Leak-Fix: Legacy-Bild-URLs tragen das volle Token im Pfad —
        # für ALLE Posts (nicht nur anonyme) auf den opaken Key umschreiben.
        if p.get('image_url'):
            p['image_url'] = _wall_img_sanitize_urls(p['image_url'])
    return jsonify({'count': len(feed), 'posts': feed})


# Per-Post-Lock-Dict für Like-Counter-Race-Schutz.
# Flask läuft mit gthread + threads=8 — ohne Lock können zwei parallele
# Like-Requests den Counter um nur +1 statt +2 erhöhen (read-modify-write race).
_LIKE_LOCKS_LOCK = __import__('threading').Lock()
_LIKE_LOCKS = {}

def _like_lock(post_id):
    with _LIKE_LOCKS_LOCK:
        lk = _LIKE_LOCKS.get(post_id)
        if lk is None:
            lk = __import__('threading').Lock()
            _LIKE_LOCKS[post_id] = lk
            # Cleanup wenn Dict zu groß (>5000 alte Locks)
            if len(_LIKE_LOCKS) > 5000:
                for k in list(_LIKE_LOCKS.keys())[:2500]:
                    _LIKE_LOCKS.pop(k, None)
        return lk


@app.route('/api/wall/<token>/like/<post_id>', methods=['POST'])
def toggle_like(token, post_id):
    """Toggle like on a post. SB primary + Disk fallback."""
    likes_p = _wall_likes_path(token)
    if not likes_p: return jsonify({'ok': False, 'error':'invalid_token'}), 400
    with _like_lock(post_id):
        liked = _wall_likes_load(token) or set()
        delta = 0
        if post_id in liked:
            liked.remove(post_id); delta = -1
            liked_by_me = False
            _wall_likes_sb_remove(token, post_id)
        else:
            liked.add(post_id); delta = +1
            liked_by_me = True
            _wall_likes_sb_add(token, post_id)
        # Disk best-effort als Read-Cache wenn SB ausfällt
        try:
            _atomic_write_json(likes_p, list(liked))
        except Exception:
            try:
                with open(likes_p, 'w') as f: json.dump(list(liked), f)
            except Exception: pass
        # Atomarer Per-Row-Counter (RPC / Single-Row-Fallback) statt
        # load-ALL → bump → save-ALL. SB-down ⇒ Disk-Cache-Bump.
        counters = _wall_post_apply_counters(post_id, like_delta=delta)
        if counters is None:
            counters = _wall_disk_counter_bump(post_id, like_delta=delta)
        new_count = int(counters.get('like_count') or 0) if counters else 0
    return jsonify({'ok': True, 'like_count': new_count, 'liked_by_me': liked_by_me})


@app.route('/api/wall/<token>/dislike/<post_id>', methods=['POST'])
def toggle_dislike(token, post_id):
    """Toggle dislike. Exklusiv zu Like (Disliken entfernt ein evtl. Like).
    Disk-only (kein SB-Table); gleiches Per-Post-Lock wie Likes gegen Races."""
    dp = _wall_dislikes_path(token)
    if not dp:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    with _like_lock(post_id):
        disliked = _wall_dislikes_load(token) or set()
        liked = _wall_likes_load(token) or set()
        d_delta = 0
        like_delta = 0
        if post_id in disliked:
            disliked.remove(post_id); d_delta = -1; disliked_by_me = False
        else:
            disliked.add(post_id); d_delta = +1; disliked_by_me = True
            # Mutual-Exclusivity: ein bestehendes Like zurücknehmen.
            if post_id in liked:
                liked.remove(post_id); like_delta = -1
                _wall_likes_sb_remove(token, post_id)
                lp = _wall_likes_path(token)
                if lp:
                    try: _atomic_write_json(lp, list(liked))
                    except Exception:
                        try:
                            with open(lp, 'w') as f: json.dump(list(liked), f)
                        except Exception: pass
        try:
            _atomic_write_json(dp, list(disliked))
        except Exception:
            try:
                with open(dp, 'w') as f: json.dump(list(disliked), f)
            except Exception: pass
        # Atomarer Per-Row-Counter (RPC / Single-Row-Fallback) statt
        # load-ALL → bump → save-ALL. SB-down ⇒ Disk-Cache-Bump.
        counters = _wall_post_apply_counters(post_id, like_delta=like_delta,
                                             dislike_delta=d_delta)
        if counters is None:
            counters = _wall_disk_counter_bump(post_id, like_delta=like_delta,
                                               dislike_delta=d_delta)
        new_dislike = int(counters.get('dislike_count') or 0) if counters else 0
        new_like = int(counters.get('like_count') or 0) if counters else 0
    return jsonify({'ok': True, 'dislike_count': new_dislike, 'like_count': new_like,
                    'disliked_by_me': disliked_by_me, 'liked_by_me': post_id in liked})


@app.route('/api/wall/<token>/post/<post_id>/comment', methods=['POST'])
def add_comment(token, post_id):
    body = request.get_json(silent=True) or {}
    text = (body.get('text') or '').strip()
    image_url = (body.get('image_url') or '').strip() or None
    parent_comment_id = (body.get('parent_comment_id') or '').strip() or None
    if not text and not image_url:
        return jsonify({'ok': False, 'error': 'empty_comment'}), 400
    if len(text) > 500: return jsonify({'ok': False, 'error': 'too_long'}), 413
    cp = _wall_comments_path(post_id)
    if not cp: return jsonify({'ok': False, 'error': 'invalid_post'}), 400
    is_anonymous = bool(body.get('is_anonymous'))
    import uuid, time as _t
    comments = _wall_comments_load(post_id) or []
    name = ''
    avatar_url = None
    if not is_anonymous:
        try:
            pr = (_profile_load(token) or {}).get('profile', {}) or {}
            name = pr.get('name', '') or ''
            avatar_url = pr.get('avatar_url')
        except Exception:
            pass
    now_ts = _t.time()
    _comment_id = str(uuid.uuid4())[:10]
    c = {
        'id': _comment_id,
        'post_id': post_id,
        'author_token': token,
        'author_short': None if is_anonymous else token[:8],
        'author_name': name,
        # author_avatar: persistiertes Profilfoto → Avatar im Kommentar-Thread.
        'author_avatar': avatar_url,
        'text': text,
        'image_url': image_url,
        'parent_comment_id': parent_comment_id,
        'is_anonymous': is_anonymous,
        # Per-Comment-Salt → anonyme Kommentare eines Users nicht verkettbar.
        'anon_handle': _anon_handle_for(token, salt=_comment_id) if is_anonymous else None,
        'ts': now_ts,
        'created_at': datetime.now().isoformat(),
    }
    comments.append(c)
    # Per-Row-Insert (Data-Layer-Refactor 2026-07-01): nur den NEUEN Kommentar
    # nach SB upserten statt den ganzen Stream; Disk-Cache lokal anhängen.
    _wall_comments_save_to_supabase(post_id, [c])
    if cp:
        try:
            _atomic_write_json(cp, comments[-200:], max_items=200)
        except Exception as e:
            app.logger.warning(f'[wall-comments] disk_save_fail (ok wenn SB lief): {e}')
    # Bump comment_count on post — atomar per-Row statt load-ALL/save-ALL.
    if _wall_post_apply_counters(post_id, comment_delta=1) is None:
        _wall_disk_counter_bump(post_id, comment_delta=1)
    response_c = dict(c)
    response_c.pop('author_token', None)
    # Push an Post-Author (wenn nicht self-comment)
    try:
        _tp = _wall_post_sb_get(post_id)
        if _tp is None:
            _tp = next((p for p in (_wall_load_posts_from_disk() or [])
                        if p.get('id') == post_id), None)
        post_author = (_tp or {}).get('author_token')
        if post_author and post_author != token:
            commenter_name = name or 'Crew'
            _push_notify_async(post_author,
                               f'{commenter_name} hat kommentiert',
                               (text or '')[:120],
                               data={'type': 'wall_comment', 'post_id': post_id},
                               idempotency_key=f'wall-comment:{c.get("id")}:{post_author}')
    except Exception:
        pass
    return jsonify({'ok': True, 'comment': response_c})


@app.route('/api/wall/<token>/post/<post_id>/comments', methods=['GET'])
def get_comments(token, post_id):
    cp = _wall_comments_path(post_id)
    if not cp: return jsonify({'comments': []})
    comments = _wall_comments_load(post_id) or []
    # PRIVACY-FIX (Bug-Hunt): Kommentare geblockter Autoren ausblenden.
    _blk = _blocked_by(token)
    if _blk:
        comments = [c for c in comments if c.get('author_token') not in _blk]
    # author_avatar pro Author live cachen (mehrere Kommentare desselben Users).
    _c_avatar_cache = {}
    def _c_author_avatar(tok):
        if not tok:
            return None
        if tok in _c_avatar_cache:
            return _c_avatar_cache[tok]
        try:
            av = ((_profile_load(tok) or {}).get('profile', {}) or {}).get('avatar_url')
        except Exception:
            av = None
        _c_avatar_cache[tok] = av
        return av
    # Strip author_token; anonyme Kommentare zusätzlich von Profil-Resten säubern.
    for c in comments:
        if c.get('is_anonymous'):
            if not c.get('anon_handle'):
                c['anon_handle'] = _anon_handle_for(c.get('author_token'))
            c.pop('author_name', None)
            c.pop('author_short', None)
            c.pop('author_avatar', None)
        else:
            # Live-Avatar (frisch) statt evtl. veraltetem Snapshot.
            av = _c_author_avatar(c.get('author_token'))
            if av:
                c['author_avatar'] = av
            else:
                c.pop('author_avatar', None)
        c.pop('author_token', None)
        # Token-Leak-Fix: Legacy-Bild-URLs auf opaken Key umschreiben.
        if c.get('image_url'):
            c['image_url'] = _wall_img_sanitize_urls(c['image_url'])
    return jsonify({'post_id': post_id, 'comments': comments})


@app.route('/api/wall/<token>/post/<post_id>', methods=['DELETE'])
def delete_wall_post(token, post_id):
    """Nur Author darf löschen. DSGVO Art. 17 sub-right.

    Räumt zusätzlich:
    - Comments-File des Posts
    - das image-File falls der Post ein Bild hatte (Storage-Leak verhindern)
    """
    # Per-Row-Lookup (Data-Layer-Refactor 2026-07-01): Ownership-Check über
    # EINE Row statt load-ALL; Disk-Cache gezielt bereinigen statt save-ALL.
    target_post = _wall_post_sb_get(post_id)
    if target_post is None:
        target_post = next((p for p in (_wall_load_posts_from_disk() or [])
                            if p.get('id') == post_id), None)
    if target_post is None or target_post.get('author_token') != token:
        return jsonify({'ok': False, 'error': 'not_found_or_not_author'}), 404
    _wall_disk_remove_post(post_id)
    # Post-Row aus SB + Comments + Likes entfernen (expliziter Row-Delete).
    if SB_AVAILABLE:
        try:
            sb.table('wall_posts').delete().eq('id', post_id).execute()
        except Exception as e:
            app.logger.warning(f'[wall-delete] sb post row delete failed: {e}')
        try:
            sb.table('wall_comments').delete().eq('post_id', post_id).execute()
        except Exception as e:
            app.logger.warning(f'[wall-delete] sb comments cleanup failed: {e}')
        try:
            sb.table('wall_likes').delete().eq('post_id', post_id).execute()
        except Exception as e:
            app.logger.warning(f'[wall-delete] sb likes cleanup failed: {e}')
    cp = _wall_comments_path(post_id)
    if cp:
        try:
            import os; os.remove(cp)
        except Exception:
            pass
    # Image-File entfernen (image_url-Pattern: /api/wall/image/<token_safe>/<fname>)
    img_url = (target_post.get('image_url') or '').strip()
    if img_url.startswith('/api/wall/image/'):
        try:
            parts = img_url.strip('/').split('/')
            # ['api','wall','image','<token_safe>','<fname>']
            if len(parts) >= 5:
                import os, re as _re
                safe_t = _re.sub(r'[^A-Za-z0-9_-]', '', parts[3] or '')[:64]
                safe_f = _re.sub(r'[^A-Za-z0-9_.-]', '', parts[4] or '')
                if safe_t and safe_f:
                    img_path = os.path.join(_USER_HISTORY_DIR, 'wall_images', safe_t, safe_f)
                    if not os.path.exists(img_path):
                        # Token-Leak-Fix: opaker Key → Legacy-Token-Verzeichnis
                        legacy = _wall_img_legacy_dir(safe_t)
                        if legacy:
                            img_path = os.path.join(_USER_HISTORY_DIR, 'wall_images', legacy, safe_f)
                    if os.path.exists(img_path):
                        os.remove(img_path)
        except Exception as e:
            app.logger.warning(f'[wall-delete] image cleanup failed: {e}')
    return jsonify({'ok': True})


