# ── Forum-Threads/Replies SB persistence (P0 Worker-P1, 2026-06-01) ──
# Disk-only war auf Cloud Run ein Wipe-pro-Redeploy.
# Threads-Schema: 1 Row pro Thread. ts ← created_ts. body ← body-text.
# Replies-Schema: 1 Row pro Reply, thread_id fkey-mässig referenziert.
_FORUM_THREAD_KNOWN_COLS = {
    'id', 'category_id', 'author_token', 'title', 'ts',
    'hashtags', 'like_count', 'reply_count', 'deleted',
}
_FORUM_REPLY_KNOWN_COLS = {
    'id', 'thread_id', 'author_token', 'ts', 'parent_reply_id',
    'mentioned_token', 'image_url', 'like_count',
}


def _forum_threads_load_from_supabase():
    """Liest alle nicht-gelöschten Forum-Threads aus SB. None bei SB-down.
    Re-hydrated Disk-Shape: ts ↔ created_ts, body ↔ Spalte body."""
    if not SB_AVAILABLE:
        return None
    try:
        out = []
        offset = 0
        page = 1000
        while True:
            r = (sb.table('forum_threads').select('*')
                 .eq('deleted', False)
                 .order('ts', desc=False)
                 .range(offset, offset + page - 1).execute())
            rows = r.data or []
            for row in rows:
                t = {}
                for k in _FORUM_THREAD_KNOWN_COLS:
                    v = row.get(k)
                    if v is not None:
                        t[k] = v
                # Spalte ts → Disk-Feld created_ts (legacy Naming)
                if 'ts' in t:
                    t.setdefault('created_ts', t['ts'])
                if row.get('body') is not None:
                    t['body'] = row.get('body')
                md = row.get('metadata') or {}
                if isinstance(md, dict):
                    for k, v in md.items():
                        if k not in t:
                            t[k] = v
                out.append(t)
            if len(rows) < page:
                break
            offset += page
        return out
    except Exception as e:
        app.logger.warning(f'[forum-threads] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _forum_threads_save_to_supabase(threads):
    """Bulk-upsert nach SB. True bei vollem Erfolg."""
    if not SB_AVAILABLE or threads is None:
        return False
    rows = []
    for t in (threads or []):
        if not isinstance(t, dict):
            continue
        tid = t.get('id')
        if not tid:
            continue
        row = {'id': tid}
        meta = {}
        for k, v in t.items():
            if k == 'body':
                row['body'] = v
            elif k == 'created_ts' and 'ts' not in t:
                row['ts'] = v
            elif k in _FORUM_THREAD_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        if row.get('category_id') is None:
            row['category_id'] = ''
        if row.get('author_token') is None:
            row['author_token'] = ''
        if row.get('ts') is None:
            row['ts'] = t.get('created_ts') or 0
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_FORUM_THREADS)
    try:
        for i in range(0, len(rows), 500):
            sb.table('forum_threads').upsert(rows[i:i+500], on_conflict='id').execute()
        return True
    except Exception as e:
        app.logger.error(f'[forum-threads] sb_save_fail err={type(e).__name__}: {str(e)[:200]}')
        return False


def _forum_threads_load_from_disk():
    p = _forum_threads_path()
    try:
        with open(p) as f:
            return json.load(f) or []
    except (FileNotFoundError, json.JSONDecodeError):
        return []
    except Exception:
        return []


def _forum_load_threads():
    """SB primary, Disk fallback, lazy-migrate."""
    sb_data = _forum_threads_load_from_supabase()
    if sb_data is None:
        return _forum_threads_load_from_disk()
    if sb_data:
        return sb_data
    disk_data = _forum_threads_load_from_disk()
    if disk_data and SB_AVAILABLE:
        app.logger.info(f'[forum-threads] lazy-migrate {len(disk_data)} disk threads → supabase')
        _forum_threads_save_to_supabase(disk_data)
        return disk_data
    return []


def _forum_save_threads(threads):
    """SB primary + Disk Read-Cache."""
    capped = (threads or [])[-10000:] if isinstance(threads, list) else threads
    sb_ok = _forum_threads_save_to_supabase(capped)
    p = _forum_threads_path()
    try:
        _atomic_write_json(p, capped, max_items=10000)
    except Exception as e:
        app.logger.warning(f'[forum-threads] disk_save_fail: {e}')
        if not sb_ok:
            app.logger.error('[forum-threads] CRITICAL: weder SB noch Disk gesichert!')


def _forum_replies_load_from_supabase(thread_id):
    """Liest alle Replies für thread_id aus SB. None bei SB-down."""
    if not SB_AVAILABLE or not thread_id:
        return None
    try:
        r = (sb.table('forum_replies').select('*')
             .eq('thread_id', thread_id)
             .order('ts', desc=False)
             .limit(2000).execute())
        rows = r.data or []
        out = []
        for row in rows:
            rep = {}
            for k in _FORUM_REPLY_KNOWN_COLS:
                v = row.get(k)
                if v is not None:
                    rep[k] = v
            if 'ts' in rep:
                rep.setdefault('created_ts', rep['ts'])
            if row.get('body') is not None:
                rep['body'] = row.get('body')
            md = row.get('metadata') or {}
            if isinstance(md, dict):
                for k, v in md.items():
                    if k not in rep:
                        rep[k] = v
            out.append(rep)
        return out
    except Exception as e:
        app.logger.warning(
            f'[forum-replies] sb_load_fail tid={(thread_id or "")[:8]} '
            f'err={type(e).__name__}: {str(e)[:120]}'
        )
        return None


def _forum_replies_save_to_supabase(thread_id, replies):
    """Bulk-upsert Replies eines Threads nach SB."""
    if not SB_AVAILABLE or not thread_id or replies is None:
        return False
    rows = []
    for rep in (replies or []):
        if not isinstance(rep, dict):
            continue
        rid = rep.get('id')
        if not rid:
            continue
        row = {'id': rid, 'thread_id': thread_id}
        meta = {}
        for k, v in rep.items():
            if k == 'body':
                row['body'] = v
            elif k == 'created_ts' and 'ts' not in rep:
                row['ts'] = v
            elif k == 'thread_id':
                # already forced above
                continue
            elif k in _FORUM_REPLY_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        if row.get('author_token') is None:
            row['author_token'] = ''
        if row.get('ts') is None:
            row['ts'] = rep.get('created_ts') or 0
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_FORUM_REPLIES)
    try:
        for i in range(0, len(rows), 500):
            sb.table('forum_replies').upsert(rows[i:i+500], on_conflict='id').execute()
        return True
    except Exception as e:
        app.logger.error(
            f'[forum-replies] sb_save_fail tid={(thread_id or "")[:8]} '
            f'err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


def _forum_replies_load_from_disk(thread_id):
    p = _forum_replies_path(thread_id)
    if not p:
        return []
    try:
        with open(p) as f:
            return json.load(f) or []
    except (FileNotFoundError, json.JSONDecodeError):
        return []
    except Exception:
        return []


def _forum_load_replies(thread_id):
    """SB primary, Disk fallback, lazy-migrate."""
    sb_data = _forum_replies_load_from_supabase(thread_id)
    if sb_data is None:
        return _forum_replies_load_from_disk(thread_id)
    if sb_data:
        return sb_data
    disk_data = _forum_replies_load_from_disk(thread_id)
    if disk_data and SB_AVAILABLE:
        app.logger.info(
            f'[forum-replies] lazy-migrate tid={(thread_id or "")[:8]} '
            f'{len(disk_data)} replies → supabase'
        )
        _forum_replies_save_to_supabase(thread_id, disk_data)
        return disk_data
    return []


def _forum_save_replies(thread_id, replies):
    """SB primary + Disk Read-Cache."""
    capped = (replies or [])[-2000:] if isinstance(replies, list) else replies
    sb_ok = _forum_replies_save_to_supabase(thread_id, capped)
    p = _forum_replies_path(thread_id)
    if not p:
        return
    try:
        _atomic_write_json(p, capped, max_items=2000)
    except Exception as e:
        app.logger.warning(f'[forum-replies] disk_save_fail thread={(thread_id or "")[:8]}: {e}')
        if not sb_ok:
            app.logger.error('[forum-replies] CRITICAL: weder SB noch Disk gesichert!')


# ── Forum per-Row-Operations (Data-Layer-Refactor 2026-07-01) ───────────────
# Gleiches Muster wie Wall: 1 Insert pro Create, atomare Counter-RPCs
# (forum_thread_counters_apply / forum_reply_like_apply, Migration
# 20260701_data_layer.sql), Row-Lookups statt load-ALL + Linear-Scan.

def _forum_thread_from_row(row):
    """SB-Row → Thread-Dict (gleiche Re-Hydration wie der Bulk-Loader)."""
    t = {}
    for k in _FORUM_THREAD_KNOWN_COLS:
        v = row.get(k)
        if v is not None:
            t[k] = v
    if 'ts' in t:
        t.setdefault('created_ts', t['ts'])
    if row.get('body') is not None:
        t['body'] = row.get('body')
    md = row.get('metadata') or {}
    if isinstance(md, dict):
        for k, v in md.items():
            if k not in t:
                t[k] = v
    return t


_FORUM_THREAD_SELECT_COLS = ('id,category_id,author_token,title,body,ts,'
                             'hashtags,like_count,reply_count,deleted,metadata')
_FORUM_REPLY_SELECT_COLS = ('id,thread_id,author_token,body,ts,parent_reply_id,'
                            'mentioned_token,image_url,like_count,metadata')


def _forum_threads_load_recent(limit=500):
    """Bounded Thread-Read (ts desc, aufsteigend zurückgegeben wie der
    Bulk-Loader). None bei SB-down → Caller nutzt Disk."""
    if not SB_AVAILABLE:
        return None
    try:
        r = (sb.table('forum_threads').select(_FORUM_THREAD_SELECT_COLS)
             .eq('deleted', False)
             .order('ts', desc=True).limit(int(limit)).execute())
        out = [_forum_thread_from_row(row) for row in (r.data or [])]
        out.reverse()
        return out
    except Exception as e:
        app.logger.warning(f'[forum-threads] recent_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _forum_thread_sb_get(thread_id):
    """Einzelner Thread aus SB. None bei miss/SB-down."""
    if not SB_AVAILABLE or not thread_id:
        return None
    try:
        r = (sb.table('forum_threads').select(_FORUM_THREAD_SELECT_COLS)
             .eq('id', thread_id).eq('deleted', False).limit(1).execute())
        rows = r.data or []
        return _forum_thread_from_row(rows[0]) if rows else None
    except Exception as e:
        app.logger.warning(f'[forum-threads] sb_get_fail id={(thread_id or "")[:8]}: {str(e)[:120]}')
        return None


def _forum_reply_sb_get(reply_id):
    """Einzelner Reply aus SB (inkl. thread_id — ersetzt den Linear-Scan über
    ALLE Threads × Replies). None bei miss/SB-down."""
    if not SB_AVAILABLE or not reply_id:
        return None
    try:
        r = (sb.table('forum_replies').select(_FORUM_REPLY_SELECT_COLS)
             .eq('id', reply_id).limit(1).execute())
        rows = r.data or []
        if not rows:
            return None
        row = rows[0]
        rep = {}
        for k in _FORUM_REPLY_KNOWN_COLS:
            v = row.get(k)
            if v is not None:
                rep[k] = v
        if 'ts' in rep:
            rep.setdefault('created_ts', rep['ts'])
        if row.get('body') is not None:
            rep['body'] = row.get('body')
        md = row.get('metadata') or {}
        if isinstance(md, dict):
            for k, v in md.items():
                if k not in rep:
                    rep[k] = v
        return rep
    except Exception as e:
        app.logger.warning(f'[forum-replies] sb_get_fail id={(reply_id or "")[:8]}: {str(e)[:120]}')
        return None


def _forum_disk_threads_mutate(fn):
    """fn(list)->list|None auf den Disk-Thread-Cache (lokal, kein SB)."""
    try:
        threads = _forum_threads_load_from_disk() or []
        new_threads = fn(threads)
        if new_threads is None:
            return
        _atomic_write_json(_forum_threads_path(), (new_threads or [])[-10000:],
                           max_items=10000)
    except Exception as e:
        app.logger.warning(f'[forum-threads] disk_mutate_fail (ok wenn SB läuft): {e}')


def _forum_disk_replies_mutate(thread_id, fn):
    """fn(list)->list|None auf den Disk-Reply-Cache eines Threads."""
    p = _forum_replies_path(thread_id)
    if not p:
        return
    try:
        replies = _forum_replies_load_from_disk(thread_id) or []
        new_replies = fn(replies)
        if new_replies is None:
            return
        _atomic_write_json(p, (new_replies or [])[-2000:], max_items=2000)
    except Exception as e:
        app.logger.warning(f'[forum-replies] disk_mutate_fail (ok wenn SB läuft): {e}')


def _forum_thread_apply_counters(thread_id, like_delta=0, reply_delta=0,
                                 last_reply_ts=None):
    """Atomarer Thread-Counter-Bump (RPC forum_thread_counters_apply).
    Fallback ohne RPC: read-modify-write auf EINER Row. Returns
    {'like_count','reply_count'} oder None (SB down / Thread nicht in SB)."""
    if not SB_AVAILABLE or not thread_id:
        return None
    ok, data = _social_rpc_call('forum_thread_counters_apply', {
        'p_thread_id': thread_id, 'p_like': int(like_delta),
        'p_reply': int(reply_delta), 'p_last_reply_ts': last_reply_ts})
    result = None
    if ok and isinstance(data, list) and data and isinstance(data[0], dict):
        row = data[0]
        result = {'like_count': int(row.get('like_count') or 0),
                  'reply_count': int(row.get('reply_count') or 0)}
    if result is None:
        try:
            r = (sb.table('forum_threads')
                 .select('like_count,reply_count,metadata')
                 .eq('id', thread_id).limit(1).execute())
            rows = r.data or []
            if not rows:
                return None
            row = rows[0]
            new_like = max(0, int(row.get('like_count') or 0) + int(like_delta))
            new_reply = max(0, int(row.get('reply_count') or 0) + int(reply_delta))
            upd = {'like_count': new_like, 'reply_count': new_reply}
            if last_reply_ts is not None:
                md = row.get('metadata') if isinstance(row.get('metadata'), dict) else {}
                md = dict(md)
                md['last_reply_ts'] = last_reply_ts
                upd['metadata'] = md
            sb.table('forum_threads').update(upd).eq('id', thread_id).execute()
            result = {'like_count': new_like, 'reply_count': new_reply}
        except Exception as e:
            app.logger.warning(f'[forum-threads] counter_fallback_fail id={(thread_id or "")[:8]}: {str(e)[:120]}')
            return None
    # Disk-Cache nachziehen (per-Row)
    def _bump(threads):
        for t in threads:
            if t.get('id') == thread_id:
                t['like_count'] = result['like_count']
                t['reply_count'] = result['reply_count']
                if last_reply_ts is not None:
                    t['last_reply_ts'] = last_reply_ts
                return threads
        return None
    _forum_disk_threads_mutate(_bump)
    return result


def _forum_reply_apply_like(reply_id, delta):
    """Atomarer Reply-Like-Bump (RPC forum_reply_like_apply). Fallback:
    read-modify-write auf EINER Row. Returns like_count (int) oder None."""
    if not SB_AVAILABLE or not reply_id:
        return None
    ok, data = _social_rpc_call('forum_reply_like_apply',
                                {'p_reply_id': reply_id, 'p_delta': int(delta)})
    if ok and isinstance(data, list) and data and isinstance(data[0], dict):
        return int(data[0].get('like_count') or 0)
    try:
        r = (sb.table('forum_replies').select('like_count')
             .eq('id', reply_id).limit(1).execute())
        rows = r.data or []
        if not rows:
            return None
        new_like = max(0, int(rows[0].get('like_count') or 0) + int(delta))
        sb.table('forum_replies').update({'like_count': new_like}).eq('id', reply_id).execute()
        return new_like
    except Exception as e:
        app.logger.warning(f'[forum-replies] like_fallback_fail id={(reply_id or "")[:8]}: {str(e)[:120]}')
        return None


def _forum_likes_load_from_supabase(token):
    """{'threads': set, 'replies': set} aller liked-IDs für user_token. None bei SB-down."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('forum_likes').select('target_type,target_id')
             .eq('user_token', token).execute())
        threads = set()
        replies = set()
        for row in (r.data or []):
            tt = row.get('target_type')
            tid = row.get('target_id')
            if not tid:
                continue
            if tt == 'thread':
                threads.add(tid)
            elif tt == 'reply':
                replies.add(tid)
        return {'threads': threads, 'replies': replies}
    except Exception as e:
        app.logger.warning(f'[forum-likes] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _forum_likes_sb_diff(token, kind, old_set, new_set):
    """Diff-Schreibe: nur add/remove was sich verändert hat (zwischen old und new)."""
    if not SB_AVAILABLE or not token or kind not in ('thread', 'reply'):
        return False
    added = list(new_set - old_set)
    removed = list(old_set - new_set)
    try:
        if added:
            rows = [{'user_token': token, 'target_type': kind, 'target_id': i} for i in added]
            sb.table('forum_likes').upsert(
                rows, on_conflict='user_token,target_type,target_id').execute()
        for tid in removed:
            (sb.table('forum_likes').delete()
             .eq('user_token', token).eq('target_type', kind).eq('target_id', tid).execute())
        return True
    except Exception as e:
        app.logger.warning(f'[forum-likes] sb_diff_fail kind={kind}: {str(e)[:120]}')
        return False


def _forum_load_likes(token):
    """SB primary + Disk fallback + lazy-migrate."""
    sb_data = _forum_likes_load_from_supabase(token)
    p = _forum_likes_path(token)
    if sb_data is not None:
        if not (sb_data['threads'] or sb_data['replies']):
            # Lazy-migrate von Disk
            if p:
                try:
                    with open(p) as f:
                        data = json.load(f) or {}
                    disk_threads = set(data.get('threads') or [])
                    disk_replies = set(data.get('replies') or [])
                    if (disk_threads or disk_replies) and SB_AVAILABLE:
                        _forum_likes_sb_diff(token, 'thread', set(), disk_threads)
                        _forum_likes_sb_diff(token, 'reply', set(), disk_replies)
                        app.logger.info(f'[forum-likes] lazy-migrated t={len(disk_threads)} r={len(disk_replies)}')
                        return {'threads': disk_threads, 'replies': disk_replies}
                except (FileNotFoundError, json.JSONDecodeError, Exception):
                    pass
        return sb_data
    # SB down → Disk
    if not p:
        return {'threads': set(), 'replies': set()}
    try:
        with open(p) as f:
            data = json.load(f) or {}
        return {
            'threads': set(data.get('threads') or []),
            'replies': set(data.get('replies') or []),
        }
    except (FileNotFoundError, json.JSONDecodeError, Exception):
        return {'threads': set(), 'replies': set()}


def _forum_save_likes(token, likes):
    """SB-Diff (gegenüber aktuellem SB-Stand) + Disk best-effort."""
    # SB-Diff: vergleiche neu vs SB-Snapshot, nicht vs vorher übergebenes likes-dict
    if SB_AVAILABLE:
        current_sb = _forum_likes_load_from_supabase(token)
        if current_sb is not None:
            new_threads = set(likes.get('threads') or [])
            new_replies = set(likes.get('replies') or [])
            _forum_likes_sb_diff(token, 'thread', current_sb['threads'], new_threads)
            _forum_likes_sb_diff(token, 'reply', current_sb['replies'], new_replies)
    p = _forum_likes_path(token)
    if not p:
        return
    data = {'threads': list(likes.get('threads') or []),
            'replies': list(likes.get('replies') or [])}
    try:
        _atomic_write_json(p, data)
    except Exception as e:
        app.logger.warning(f'[forum-likes] disk_save_fail (ok wenn SB lief): {e}')


def _forum_author_snapshot(token):
    """Returns dict with author_name / author_role / author_airline / author_homebase from profile."""
    try:
        # SB-primary statt Disk (Cloud-Run-ephemer) → Forum-Autoren namenlos sonst.
        pr = (_profile_load(token) or {}).get('profile', {}) or {}
        return {
            'author_name': pr.get('name') or '',
            'author_role': pr.get('role') or pr.get('position') or '',
            'author_airline': pr.get('airline') or '',
            'author_homebase': pr.get('homebase') or '',
            # Server-persistiertes Profilfoto → echtes Foto im Forum statt Emoji.
            'author_avatar': pr.get('avatar_url') or '',
        }
    except Exception:
        return {'author_name': '', 'author_role': '', 'author_airline': '',
                'author_homebase': '', 'author_avatar': ''}


def _wall_post_as_forum_thread(p):
    """Projiziert einen Wall-Post in die Forum-Thread-Form, FALLS er einen
    Forum-Kategorie-Hashtag trägt (#cabin/#cockpit/…). So erscheint ein im
    Crew-Feed erstellter Post auch im passenden Forum-Board (BUG-3: Feed und
    Forum sind getrennte Stores — wall_posts vs forum_threads — der Composer
    hängt die Kategorie als ersten Hashtag an, hier lesen wir sie wieder).

    Read-only-Brücke: id mit Prefix 'wall:' (kollidiert nicht mit echten
    Thread-IDs); Replies/Likes laufen im Forum gegen diese synthetische ID ins
    Leere — Interaktion bleibt im Crew-Feed. Anonyme Posts werden NICHT
    eingeblendet (kein Author-Snapshot, Identitäts-Schutz). Returns None wenn der
    Post in kein Forum-Board gehört.
    """
    if p.get('is_anonymous'):
        return None
    tags = [str(t).lower() for t in (p.get('hashtags') or [])]
    cat = next((t for t in tags if t in FORUM_CATEGORIES), None)
    if not cat:
        return None
    text = (p.get('text') or '').strip()
    # Titel = erste Zeile/erster Satz (gekürzt), Body = voller Text.
    first_line = text.splitlines()[0].strip() if text else ''
    title = (first_line or 'Crew-Feed Beitrag')[:200]
    return {
        'id': 'wall:' + str(p.get('id') or ''),
        'category_id': cat,
        'author_token': p.get('author_token'),
        'author_short': p.get('author_short'),
        'author_name': p.get('author_name'),
        'author_role': None,
        'author_airline': p.get('author_airline'),
        'author_homebase': p.get('author_homebase'),
        'title': title,
        'body': text,
        'image_url': p.get('image_url'),
        'gif_url': None,
        'hashtags': tags,
        'created_at': p.get('created_at'),
        'created_ts': p.get('ts') or 0,
        'like_count': p.get('like_count') or 0,
        'reply_count': p.get('comment_count') or 0,
        'last_reply_ts': None,
        'from_crew_feed': True,
    }


def _wall_posts_for_forum():
    """Alle Wall-Posts, die als Forum-Threads taugen (Kategorie-Hashtag)."""
    out = []
    try:
        for p in _wall_load_posts():
            proj = _wall_post_as_forum_thread(p)
            if proj is not None:
                out.append(proj)
    except Exception as e:
        app.logger.warning(f'[forum] wall→thread bridge failed: {str(e)[:120]}')
    return out


@app.route('/api/forum/<token>/threads', methods=['GET'])
def forum_list_threads(token):
    """Query: ?category=cabin&sort=hot|new|active&limit=50"""
    category = (request.args.get('category') or '').strip().lower()
    sort = (request.args.get('sort') or 'active').strip().lower()
    limit = min(int(request.args.get('limit') or 50), 200)

    import time
    # Bounded Read (Data-Layer-Refactor 2026-07-01): neueste 500 Threads statt
    # unbounded load-ALL. Disk-only-Threads (SB-down beim Erstellen) mischen
    # wir dazu; stale Disk-Kopien bekannter IDs nicht (SB-Counter frischer).
    threads = _forum_threads_load_recent(500)
    if threads is None:
        threads = _forum_threads_load_from_disk() or []
    else:
        _have = {t.get('id') for t in threads}
        for t in (_forum_threads_load_from_disk() or []):
            if t.get('id') and t.get('id') not in _have:
                threads.append(t)
    # BUG-3: Crew-Feed-Posts mit Forum-Kategorie-Hashtag im Forum mit-einblenden.
    # Dedup gegen evtl. doppelte IDs (sollte durch 'wall:'-Prefix nicht passieren).
    existing_ids = {t.get('id') for t in threads}
    for wt in _wall_posts_for_forum():
        if wt.get('id') not in existing_ids:
            threads.append(wt)
    if category and category in FORUM_CATEGORIES:
        threads = [t for t in threads if t.get('category_id') == category]

    # Geblockte Author-Tokens ausfiltern (Apple Guideline 1.4.1)
    blocked = _blocked_by(token)
    if blocked:
        threads = [t for t in threads if t.get('author_token') not in blocked]

    # Airline-Scope (User-Feature): (1) erzwungene Sichtbarkeit — Threads mit
    # scope='airline' sieht NUR die gleiche Airline; (2) optionaler Nutzer-Filter
    # ?airline_scope=mine → nur Threads der eigenen Airline.
    try:
        my_airline = (((_profile_load(token) or {}).get('profile', {}) or {})
                      .get('airline') or '').strip().upper()
    except Exception:
        my_airline = ''
    airline_filter = (request.args.get('airline_scope') or 'all').strip().lower()

    def _airline_visible(t):
        tscope = (t.get('scope') or 'all')
        tair = (t.get('author_airline') or '').strip().upper()
        # scope='airline' → NUR sichtbar wenn die Airline des Betrachters die des
        # Threads matcht. FIX (Bug-Hunt #7): vorher war ein airline-only-Thread für
        # jeden OHNE gesetzte Airline sichtbar (Leak). Jetzt restriktiv: kein
        # my_airline ODER kein tair ODER ungleich → verstecken.
        if tscope == 'airline':
            if not my_airline or not tair or tair != my_airline:
                return False
        # Nutzer-Filter „nur meine Airline".
        if airline_filter == 'mine' and my_airline and tair and tair != my_airline:
            return False
        return True
    threads = [t for t in threads if _airline_visible(t)]

    # Sort
    now = time.time()
    if sort == 'new':
        threads.sort(key=lambda t: -(t.get('created_ts') or 0))
    elif sort == 'hot':
        # Hot = (likes + replies*2) / age_hours^1.5
        def hot_score(t):
            age_h = max(1.0, (now - (t.get('created_ts') or now)) / 3600.0)
            engagement = (t.get('like_count') or 0) + (t.get('reply_count') or 0) * 2
            return -(engagement / (age_h ** 1.5))
        threads.sort(key=hot_score)
    else:  # active = last activity
        threads.sort(key=lambda t: -((t.get('last_reply_ts') or t.get('created_ts') or 0)))

    threads = threads[:limit]

    # Add liked_by_me + is_mine (Owner-Flag für eigene-Löschen-Button, DSGVO)
    likes = _forum_load_likes(token)
    # author_avatar LIVE auflösen (wie im Wall-Feed): der am Thread gespeicherte
    # Snapshot kann veraltet/leer sein (Thread vor dem Avatar-Feature erstellt,
    # oder User hat sein Foto nachträglich gesetzt). Pro Author 1× cachen.
    _av_cache = {}
    def _resolve_av(tok):
        if not tok:
            return None
        if tok in _av_cache:
            return _av_cache[tok]
        try:
            av = ((_profile_load(tok) or {}).get('profile', {}) or {}).get('avatar_url')
        except Exception:
            av = None
        _av_cache[tok] = av
        return av
    for t in threads:
        t['liked_by_me'] = t.get('id') in likes['threads']
        t['is_mine'] = (t.get('author_token') == token)
        av = _resolve_av(t.get('author_token'))
        if av:
            t['author_avatar'] = av
        elif not t.get('author_avatar'):
            t.pop('author_avatar', None)
        # Strip author_token from public response
        t.pop('author_token', None)
    return jsonify({'count': len(threads), 'threads': threads})


@app.route('/api/forum/<token>/threads', methods=['POST'])
def forum_create_thread(token):
    """Body: {category_id, title, body, image_url?, gif_url?, hashtags?}"""
    if token.startswith('AT-GUEST-'):
        return jsonify({'ok': False, 'error': 'demo_mode_cannot_post'}), 403
    # Max 5 Threads pro Stunde
    if _token_rate_limited(token, 'forum_thread', limit=5, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited',
                        'message': 'Zu viele Threads in kurzer Zeit.'}), 429
    body = request.get_json(silent=True) or {}
    category = (body.get('category_id') or '').strip().lower()
    raw_title = (body.get('title') or '').strip()
    raw_text = (body.get('body') or '').strip()
    image_url = (body.get('image_url') or '').strip() or None
    gif_url = (body.get('gif_url') or '').strip() or None
    explicit_tags = body.get('hashtags') or []
    # Sichtbarkeits-Scope (User-Feature): 'all' = alle Airlines sehen den Thread,
    # 'airline' = nur die eigene Airline. Default 'all'.
    scope = (body.get('scope') or 'all').strip().lower()
    if scope not in ('all', 'airline'):
        scope = 'all'

    if category not in FORUM_CATEGORIES:
        return jsonify({'ok': False, 'error': 'invalid_category'}), 400
    if not raw_title:
        return jsonify({'ok': False, 'error': 'empty_title'}), 400
    if len(raw_title) > 200:
        return jsonify({'ok': False, 'error': 'title_too_long'}), 413
    if not raw_text and not image_url:
        return jsonify({'ok': False, 'error': 'empty_body'}), 400
    if len(raw_text) > 5000:
        return jsonify({'ok': False, 'error': 'body_too_long'}), 413
    title = _sanitize_user_text(raw_title, max_len=200)
    text = _sanitize_user_text(raw_text, max_len=5000)

    # Extract hashtags from title + body, merge with explicit
    auto_tags = set()
    for m in FORUM_HASHTAG_RE.finditer(raw_title + ' ' + raw_text):
        auto_tags.add(m.group(1).lower())
    for t in explicit_tags:
        if isinstance(t, str):
            tag = t.strip().lstrip('#').lower()
            if 2 <= len(tag) <= 32:
                auto_tags.add(tag)
    hashtags = sorted(auto_tags)[:20]

    import uuid, time
    thread = {
        'id': str(uuid.uuid4())[:12],
        'category_id': category,
        'author_token': token,
        'author_short': token[:8],
        'title': title,
        'body': text,
        'image_url': image_url,
        'gif_url': gif_url,
        'hashtags': hashtags,
        'created_at': datetime.now().isoformat(),
        'created_ts': time.time(),
        'like_count': 0,
        'reply_count': 0,
        'last_reply_ts': None,
        'scope': scope,
    }
    thread.update(_forum_author_snapshot(token))

    # Per-Row-Insert statt load-ALL → append → save-ALL (2026-07-01).
    _forum_threads_save_to_supabase([thread])
    _forum_disk_threads_mutate(lambda ts: ts + [thread])

    # Return without author_token
    response_thread = dict(thread)
    response_thread.pop('author_token', None)
    response_thread['liked_by_me'] = False
    return jsonify({'ok': True, 'thread': response_thread})


@app.route('/api/forum/<token>/threads/<thread_id>', methods=['DELETE'])
def forum_delete_thread(token, thread_id):
    # Per-Row-Lookup + gezielter Disk-Filter (2026-07-01) statt load-ALL/save-ALL.
    target = _forum_thread_sb_get(thread_id)
    if target is None:
        target = next((t for t in (_forum_threads_load_from_disk() or [])
                       if t.get('id') == thread_id), None)
    if target is None or target.get('author_token') != token:
        return jsonify({'ok': False, 'error': 'not_found_or_not_author'}), 404

    def _rm(threads):
        new = [t for t in threads if t.get('id') != thread_id]
        return new if len(new) != len(threads) else None
    _forum_disk_threads_mutate(_rm)
    # Thread-Row + zugehörige Replies aus SB entfernen (expliziter Row-Delete).
    if SB_AVAILABLE:
        try:
            sb.table('forum_threads').delete().eq('id', thread_id).execute()
        except Exception as e:
            app.logger.warning(f'[forum-delete] sb thread row delete failed: {e}')
        try:
            sb.table('forum_replies').delete().eq('thread_id', thread_id).execute()
        except Exception as e:
            app.logger.warning(f'[forum-delete] sb replies cleanup failed: {e}')
    # Delete replies file
    rp = _forum_replies_path(thread_id)
    if rp:
        try:
            import os
            os.remove(rp)
        except Exception:
            pass
    return jsonify({'ok': True})


@app.route('/api/forum/<token>/threads/<thread_id>/like', methods=['POST'])
def forum_toggle_thread_like(token, thread_id):
    if token.startswith('AT-GUEST-'):
        return jsonify({'ok': False, 'error': 'demo_mode_cannot_post'}), 403
    likes = _forum_load_likes(token)
    # Per-Row-Lookup statt load-ALL (2026-07-01).
    target = _forum_thread_sb_get(thread_id)
    if target is None:
        target = next((t for t in (_forum_threads_load_from_disk() or [])
                       if t.get('id') == thread_id), None)
    if not target:
        return jsonify({'ok': False, 'error': 'not_found'}), 404
    if thread_id in likes['threads']:
        likes['threads'].discard(thread_id)
        delta = -1
        liked_by_me = False
    else:
        likes['threads'].add(thread_id)
        delta = +1
        liked_by_me = True
    _forum_save_likes(token, likes)
    # Atomarer Counter (RPC / Single-Row-Fallback); SB-down ⇒ Disk-Bump.
    counters = _forum_thread_apply_counters(thread_id, like_delta=delta)
    if counters is not None:
        new_count = counters['like_count']
    else:
        new_count = max(0, (target.get('like_count') or 0) + delta)

        def _bump(threads):
            for t in threads:
                if t.get('id') == thread_id:
                    t['like_count'] = new_count
                    return threads
            return None
        _forum_disk_threads_mutate(_bump)
    return jsonify({'ok': True, 'like_count': new_count, 'liked_by_me': liked_by_me})


@app.route('/api/forum/<token>/threads/<thread_id>/replies', methods=['GET'])
def forum_list_replies(token, thread_id):
    replies = _forum_load_replies(thread_id)
    # PRIVACY-FIX (Bug-Hunt): Replies geblockter Autoren ausblenden (wie die
    # Thread-Liste). Vorher sah der Blocker die Antworten der geblockten Person.
    _blk = _blocked_by(token)
    if _blk:
        replies = [r for r in replies if r.get('author_token') not in _blk]
    likes = _forum_load_likes(token)
    # author_avatar live auflösen (echtes Foto im Reply-Thread) + is_mine, damit
    # der Client das eigene Profilfoto an seinen Replies zeigt. Pro Author cachen.
    _av_cache = {}
    def _resolve_av(tok):
        if not tok:
            return None
        if tok in _av_cache:
            return _av_cache[tok]
        try:
            av = ((_profile_load(tok) or {}).get('profile', {}) or {}).get('avatar_url')
        except Exception:
            av = None
        _av_cache[tok] = av
        return av
    for r in replies:
        r['liked_by_me'] = r.get('id') in likes['replies']
        r['is_mine'] = (r.get('author_token') == token)
        av = _resolve_av(r.get('author_token'))
        if av:
            r['author_avatar'] = av
        else:
            r.pop('author_avatar', None)
        r.pop('author_token', None)
    replies.sort(key=lambda r: (r.get('created_ts') or 0))
    return jsonify({'thread_id': thread_id, 'count': len(replies), 'replies': replies})


@app.route('/api/forum/<token>/threads/<thread_id>/reply', methods=['POST'])
def forum_create_reply(token, thread_id):
    """Body: {body, image_url?, gif_url?, parent_reply_id?, mentioned_token?}"""
    # BUG-022-Fix: Guest-Block + Rate-Limit wie bei forum_create_thread —
    # Demo-Mode darf nicht posten, und max 20 Replies/Stunde gegen Flood.
    if token.startswith('AT-GUEST-'):
        return jsonify({'ok': False, 'error': 'demo_mode_cannot_post'}), 403
    if _token_rate_limited(token, 'forum_reply', limit=20, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited'}), 429
    body = request.get_json(silent=True) or {}
    raw_text = (body.get('body') or '').strip()
    image_url = (body.get('image_url') or '').strip() or None
    gif_url = (body.get('gif_url') or '').strip() or None
    parent_reply_id = (body.get('parent_reply_id') or '').strip() or None
    mentioned_token = (body.get('mentioned_token') or '').strip() or None

    if not raw_text and not image_url:
        return jsonify({'ok': False, 'error': 'empty_reply'}), 400
    if len(raw_text) > 3000:
        return jsonify({'ok': False, 'error': 'too_long'}), 413
    text = _sanitize_user_text(raw_text, max_len=3000)

    # Per-Row-Lookup statt load-ALL (2026-07-01).
    target = _forum_thread_sb_get(thread_id)
    if target is None:
        target = next((t for t in (_forum_threads_load_from_disk() or [])
                       if t.get('id') == thread_id), None)
    if not target:
        return jsonify({'ok': False, 'error': 'thread_not_found'}), 404

    import uuid, time
    reply = {
        'id': str(uuid.uuid4())[:10],
        'thread_id': thread_id,
        'author_token': token,
        'author_short': token[:8],
        'body': text,
        'image_url': image_url,
        'gif_url': gif_url,
        'parent_reply_id': parent_reply_id,
        'mentioned_token': mentioned_token,
        'created_at': datetime.now().isoformat(),
        'created_ts': time.time(),
        'like_count': 0,
    }
    reply.update(_forum_author_snapshot(token))
    # Add mentioned-user name snapshot (so UI can show "@Maria K." even after token is gone)
    if mentioned_token:
        try:
            m_pr = (_profile_load(mentioned_token) or {}).get('profile', {}) or {}
            reply['mentioned_name'] = m_pr.get('name') or ''
        except Exception:
            reply['mentioned_name'] = ''

    # Per-Row-Insert (nur der NEUE Reply nach SB) + lokaler Disk-Append.
    _forum_replies_save_to_supabase(thread_id, [reply])
    _forum_disk_replies_mutate(thread_id, lambda reps: reps + [reply])

    # Bump reply_count + last_reply_ts — atomar per-Row statt save-ALL.
    if _forum_thread_apply_counters(thread_id, reply_delta=1,
                                    last_reply_ts=reply['created_ts']) is None:
        def _bump(threads):
            for t in threads:
                if t.get('id') == thread_id:
                    t['reply_count'] = (t.get('reply_count') or 0) + 1
                    t['last_reply_ts'] = reply['created_ts']
                    return threads
            return None
        _forum_disk_threads_mutate(_bump)

    response_reply = dict(reply)
    response_reply.pop('author_token', None)
    response_reply['liked_by_me'] = False
    # Push an Thread-Author (nicht-self) + optional an mentioned-User
    try:
        author_name = reply.get('author_name') or 'Crew'
        thread_author_token = target.get('author_token')
        if thread_author_token and thread_author_token != token:
            _push_notify_async(thread_author_token,
                               f'{author_name} hat geantwortet',
                               (text or '')[:120],
                               data={'type': 'forum_reply'},
                               idempotency_key=(
                                   f'forum-reply:{reply.get("id")}:{thread_author_token}'))
        # Mentioned-User extra benachrichtigen (nicht doppelt wenn = thread-author)
        if mentioned_token and mentioned_token != token and mentioned_token != thread_author_token:
            _push_notify_async(mentioned_token,
                               f'{author_name} hat dich erwähnt',
                               (text or '')[:120],
                               data={'type': 'forum_mention'},
                               idempotency_key=(
                                   f'forum-mention:{reply.get("id")}:{mentioned_token}'))
    except Exception:
        pass
    return jsonify({'ok': True, 'reply': response_reply})


@app.route('/api/forum/<token>/replies/<reply_id>', methods=['DELETE'])
def forum_delete_reply(token, reply_id):
    """Per-Row-Lookup über die Reply-ID (2026-07-01) statt Linear-Scan über
    ALLE Threads × Replies (das waren N+1 SB-Queries pro Delete). SB-down:
    Disk-Scan als degradierter Fallback."""
    parent_thread_id = None
    rep = _forum_reply_sb_get(reply_id)
    if rep is not None:
        if rep.get('author_token') != token:
            return jsonify({'ok': False, 'error': 'not_found_or_not_author'}), 404
        parent_thread_id = rep.get('thread_id')
        try:
            sb.table('forum_replies').delete().eq('id', reply_id).execute()
        except Exception as e:
            app.logger.warning(f'[forum-delete] sb reply row delete failed: {e}')
        if parent_thread_id:
            def _rm(reps):
                new = [r for r in reps if r.get('id') != reply_id]
                return new if len(new) != len(reps) else None
            _forum_disk_replies_mutate(parent_thread_id, _rm)
    else:
        # SB down / Reply nur auf Disk → lokaler Scan (alte Semantik).
        for t in (_forum_threads_load_from_disk() or []):
            tid = t.get('id')
            if not tid:
                continue
            replies = _forum_replies_load_from_disk(tid)
            new_replies = [r for r in replies
                           if not (r.get('id') == reply_id
                                   and r.get('author_token') == token)]
            if len(new_replies) != len(replies):
                parent_thread_id = tid

                def _rm(reps):
                    return [r for r in reps
                            if not (r.get('id') == reply_id
                                    and r.get('author_token') == token)]
                _forum_disk_replies_mutate(tid, _rm)
                if SB_AVAILABLE:
                    try:
                        sb.table('forum_replies').delete().eq('id', reply_id).execute()
                    except Exception as e:
                        app.logger.warning(f'[forum-delete] sb reply row delete failed: {e}')
                break
        if parent_thread_id is None:
            return jsonify({'ok': False, 'error': 'not_found_or_not_author'}), 404

    if parent_thread_id:
        # reply_count dekrementieren — atomar per-Row; SB-down ⇒ Disk-Bump.
        if _forum_thread_apply_counters(parent_thread_id, reply_delta=-1) is None:
            def _dec(threads):
                for t in threads:
                    if t.get('id') == parent_thread_id:
                        t['reply_count'] = max(0, (t.get('reply_count') or 0) - 1)
                        return threads
                return None
            _forum_disk_threads_mutate(_dec)
    return jsonify({'ok': True})


@app.route('/api/forum/<token>/replies/<reply_id>/like', methods=['POST'])
def forum_toggle_reply_like(token, reply_id):
    """Per-Row-Lookup über die Reply-ID (2026-07-01) statt Linear-Scan über
    alle Threads. SB-down: lokaler Disk-Scan als Fallback."""
    if token.startswith('AT-GUEST-'):
        return jsonify({'ok': False, 'error': 'demo_mode_cannot_post'}), 403
    target_thread_id = None
    target_reply = _forum_reply_sb_get(reply_id)
    if target_reply is not None:
        target_thread_id = target_reply.get('thread_id')
    else:
        for t in (_forum_threads_load_from_disk() or []):
            tid = t.get('id')
            if not tid:
                continue
            for r in _forum_replies_load_from_disk(tid):
                if r.get('id') == reply_id:
                    target_thread_id = tid
                    target_reply = r
                    break
            if target_reply:
                break
    if not target_reply:
        return jsonify({'ok': False, 'error': 'not_found'}), 404

    likes = _forum_load_likes(token)
    if reply_id in likes['replies']:
        likes['replies'].discard(reply_id)
        delta = -1
        liked_by_me = False
    else:
        likes['replies'].add(reply_id)
        delta = +1
        liked_by_me = True
    _forum_save_likes(token, likes)
    # Atomarer Counter (RPC / Single-Row-Fallback); SB-down ⇒ Disk-Bump.
    new_count = _forum_reply_apply_like(reply_id, delta)
    if new_count is None:
        new_count = max(0, (target_reply.get('like_count') or 0) + delta)
        if target_thread_id:
            def _bump(reps):
                for r in reps:
                    if r.get('id') == reply_id:
                        r['like_count'] = new_count
                        return reps
                return None
            _forum_disk_replies_mutate(target_thread_id, _bump)
    return jsonify({'ok': True, 'like_count': new_count, 'liked_by_me': liked_by_me})


@app.route('/api/forum/<token>/trending', methods=['GET'])
def forum_trending_hashtags(token):
    """Top hashtags in threads created in last 7 days."""
    import time
    from collections import Counter
    # Bounded Read (2026-07-01): 7-Tage-Fenster braucht kein load-ALL.
    threads = _forum_threads_load_recent(500)
    if threads is None:
        threads = _forum_threads_load_from_disk() or []
    cutoff = time.time() - 7 * 86400
    counter = Counter()
    for t in threads:
        if (t.get('created_ts') or 0) < cutoff:
            continue
        for tag in (t.get('hashtags') or []):
            counter[tag] += 1
    top = [{'tag': k, 'count': v} for k, v in counter.most_common(15)]
    return jsonify({'count': len(top), 'tags': top})


# ─── Crew Layover Recommendations (per Airport) ─────────────────────────────
# Kategorien: food | sight | sleep | gym | transport | nightlife | shopping
LAYOVER_CATEGORIES = {'food','sight','sleep','gym','transport','nightlife','shopping','coffee','other'}

def _recs_dir():
    import os
    d = os.path.join(_USER_HISTORY_DIR, 'layover_recs')
    os.makedirs(d, exist_ok=True)
    return d

def _recs_path(iata):
    import os, re
    safe = re.sub(r'[^A-Z]', '', (iata or '').upper())[:3]
    if len(safe) != 3: return None
    return os.path.join(_recs_dir(), f'{safe}.json')

def _votes_path(token):
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    if not safe: return None
    return os.path.join(_recs_dir(), f'votes_{safe}.json')


# ── Layover-Recs SB persistence (P0 Fix, 2026-06-07) ──
# Vorher disk-only → Cloud-Run-Redeploy wipte alle Tipps/Votes/Kommentare.
# SB-primary + Disk-Read-Cache, gleiches Muster wie wall_posts/forum_threads.
# Tabellen: layover_recs, layover_rec_votes, layover_rec_comments
# (siehe supabase_migrations/20260607_layover_recs.sql).
_SB_SCHEMA_LAYOVER_RECS = {
    'id': '', 'iata': '', 'category': 'other', 'title': None,
    'description': None, 'rating': 0, 'price_band': '',
    'location_hint': None, 'author_token': '', 'author_short': None,
    'ts': 0, 'vote_score': 0, 'vote_count': 0, 'deleted': False,
    'metadata': {},
}
_LAYOVER_REC_KNOWN_COLS = set(_SB_SCHEMA_LAYOVER_RECS.keys())
_SB_SCHEMA_LAYOVER_COMMENTS = {
    'id': '', 'rec_id': '', 'author_token': '', 'author_short': None,
    'author_name': None, 'body': None, 'image_url': None,
    'parent_comment_id': None, 'ts': 0, 'metadata': {},
}
_LAYOVER_COMMENT_KNOWN_COLS = set(_SB_SCHEMA_LAYOVER_COMMENTS.keys())


def _layover_recs_load_from_supabase(iata):
    """Alle nicht-gelöschten Recs für IATA aus SB. None bei SB-down/Tabelle-fehlt."""
    if not SB_AVAILABLE:
        return None
    safe = re.sub(r'[^A-Z]', '', (iata or '').upper())[:3]
    if len(safe) != 3:
        return None
    try:
        r = (sb.table('layover_recs').select('*')
             .eq('iata', safe).eq('deleted', False)
             .order('vote_score', desc=True).limit(500).execute())
        out = []
        for row in (r.data or []):
            rec = {}
            for k in _LAYOVER_REC_KNOWN_COLS:
                if k == 'metadata':
                    continue
                v = row.get(k)
                if v is not None:
                    rec[k] = v
            md = row.get('metadata') or {}
            if isinstance(md, dict):
                for k, v in md.items():
                    rec.setdefault(k, v)
            out.append(rec)
        return out
    except Exception as e:
        app.logger.warning(f'[layover-recs] sb_load_fail iata={safe} err={type(e).__name__}: {str(e)[:120]}')
        return None


def _layover_recs_save_to_supabase(recs):
    """Bulk-upsert Recs nach SB. True bei vollem Erfolg."""
    if not SB_AVAILABLE or recs is None:
        return False
    rows = []
    for rec in (recs or []):
        if not isinstance(rec, dict):
            continue
        rid = rec.get('id')
        if not rid:
            continue
        row = {'id': rid}
        meta = {}
        for k, v in rec.items():
            if k in _LAYOVER_REC_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_LAYOVER_RECS)
    try:
        for i in range(0, len(rows), 500):
            sb.table('layover_recs').upsert(rows[i:i+500], on_conflict='id').execute()
        return True
    except Exception as e:
        app.logger.error(f'[layover-recs] sb_save_fail err={type(e).__name__}: {str(e)[:200]}')
        return False


def _layover_recs_delete_from_supabase(rec_id):
    if not SB_AVAILABLE or not rec_id:
        return False
    try:
        sb.table('layover_recs').update({'deleted': True}).eq('id', rec_id).execute()
        return True
    except Exception as e:
        app.logger.warning(f'[layover-recs] sb_delete_fail err={type(e).__name__}: {str(e)[:120]}')
        return False


def _layover_votes_load_from_supabase(token):
    """{rec_id: direction} aus SB für diesen User. None bei SB-down."""
    if not SB_AVAILABLE or not token:
        return None
    try:
        r = (sb.table('layover_rec_votes').select('rec_id,direction')
             .eq('user_token', token).limit(5000).execute())
        return {row['rec_id']: int(row.get('direction') or 0)
                for row in (r.data or []) if row.get('rec_id')}
    except Exception as e:
        app.logger.warning(f'[layover-votes] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _layover_vote_sb_set(token, rec_id, direction):
    """direction ∈ {-1,1} → upsert; 0 → delete. True bei Erfolg."""
    if not SB_AVAILABLE or not token or not rec_id:
        return False
    try:
        if direction == 0:
            sb.table('layover_rec_votes').delete().eq('user_token', token).eq('rec_id', rec_id).execute()
        else:
            sb.table('layover_rec_votes').upsert(
                {'user_token': token, 'rec_id': rec_id, 'direction': int(direction)},
                on_conflict='user_token,rec_id').execute()
        return True
    except Exception as e:
        app.logger.warning(f'[layover-votes] sb_save_fail err={type(e).__name__}: {str(e)[:120]}')
        return False


def _layover_vote_tally_from_supabase(rec_id):
    """Aggregiert vote_score (Σ direction) + vote_count (#Stimmen) für rec_id
    direkt aus der idempotenten Tabelle layover_rec_votes (PK user_token,rec_id).

    Source-of-Truth statt denormalisiertem Zähler: der read-modify-write auf
    rec.vote_score hat unter gleichzeitigen Votes verloren (9 Upvotes → netto 0).
    Weil layover_rec_votes per composite-PK pro User idempotent ist, ist die
    Summe daraus rennsicher. Returns (vote_score, vote_count) oder None bei
    SB-down — dann fällt der Caller auf den alten Inkrement-Wert zurück."""
    if not SB_AVAILABLE or sb is None or not rec_id:
        return None
    try:
        r = (sb.table('layover_rec_votes').select('direction')
             .eq('rec_id', rec_id).limit(100000).execute())
        rows = r.data or []
        score = sum(int(row.get('direction') or 0) for row in rows)
        count = sum(1 for row in rows if int(row.get('direction') or 0) != 0)
        return score, count
    except Exception as e:
        app.logger.warning(f'[layover-votes] tally_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _layover_comments_load_from_supabase(rec_id):
    """Alle Kommentare für rec_id aus SB. None bei SB-down."""
    if not SB_AVAILABLE or not rec_id:
        return None
    try:
        r = (sb.table('layover_rec_comments').select('*')
             .eq('rec_id', rec_id).order('ts', desc=False).limit(2000).execute())
        out = []
        for row in (r.data or []):
            c = {}
            for k in _LAYOVER_COMMENT_KNOWN_COLS:
                if k == 'metadata':
                    continue
                v = row.get(k)
                if v is not None:
                    c[k] = v
            # SB-Spalte ts → disk-Feld created_ts (Reader nutzt created_ts)
            if 'ts' in c:
                c.setdefault('created_ts', c['ts'])
            md = row.get('metadata') or {}
            if isinstance(md, dict):
                for k, v in md.items():
                    c.setdefault(k, v)
            out.append(c)
        return out
    except Exception as e:
        app.logger.warning(f'[layover-comments] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _layover_comments_save_to_supabase(rec_id, comments):
    """Bulk-upsert Kommentare eines Recs nach SB."""
    if not SB_AVAILABLE or not rec_id or comments is None:
        return False
    rows = []
    for c in (comments or []):
        if not isinstance(c, dict):
            continue
        cid = c.get('id')
        if not cid:
            continue
        row = {'id': cid, 'rec_id': rec_id}
        meta = {}
        for k, v in c.items():
            if k == 'created_ts' and 'ts' not in c:
                row['ts'] = v
            elif k == 'rec_id':
                continue
            elif k in _LAYOVER_COMMENT_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return True
    rows = _sb_normalize_rows(rows, _SB_SCHEMA_LAYOVER_COMMENTS)
    try:
        for i in range(0, len(rows), 200):
            sb.table('layover_rec_comments').upsert(rows[i:i+200], on_conflict='id').execute()
        return True
    except Exception as e:
        app.logger.error(f'[layover-comments] sb_save_fail err={type(e).__name__}: {str(e)[:200]}')
        return False


def _layover_find_rec_iata(rec_id):
    """Findet die IATA eines Recs by id — SB primär, sonst Disk-Scan.
    Returns iata-string oder None."""
    if SB_AVAILABLE:
        try:
            r = (sb.table('layover_recs').select('iata')
                 .eq('id', rec_id).limit(1).execute())
            if r.data:
                return (r.data[0].get('iata') or '').upper() or None
        except Exception as e:
            app.logger.warning(f'[layover-recs] find_iata_fail err={type(e).__name__}: {str(e)[:120]}')
    # Disk-Scan fallback
    import os
    rdir = _recs_dir()
    try:
        for fname in os.listdir(rdir):
            if not fname.endswith('.json') or fname.startswith(('votes_', 'comments_', 'reviews_')):
                continue
            try:
                with open(os.path.join(rdir, fname)) as f:
                    recs = json.load(f) or []
            except Exception:
                continue
            for r in recs:
                if r.get('id') == rec_id:
                    return (r.get('iata') or fname[:-5]).upper()
    except Exception:
        pass
    return None


def _recs_load_from_disk(iata):
    rp = _recs_path(iata)
    if not rp:
        return []
    try:
        with open(rp) as f:
            return json.load(f) or []
    except (FileNotFoundError, json.JSONDecodeError):
        return []
    except Exception:
        return []


def _recs_load(iata):
    """SB primary, Disk fallback, lazy-migrate (gleiches Muster wie Forum)."""
    sb_data = _layover_recs_load_from_supabase(iata)
    if sb_data is None:
        return _recs_load_from_disk(iata)
    if sb_data:
        return sb_data
    disk_data = _recs_load_from_disk(iata)
    if disk_data and SB_AVAILABLE:
        app.logger.info(f'[layover-recs] lazy-migrate {len(disk_data)} disk recs → supabase')
        _layover_recs_save_to_supabase(disk_data)
        return disk_data
    return []


def _recs_save(iata, recs):
    """SB primary + Disk Read-Cache."""
    capped = (recs or [])[-500:]
    sb_ok = _layover_recs_save_to_supabase(capped)
    rp = _recs_path(iata)
    if rp:
        try:
            with open(rp, 'w') as f:
                json.dump(capped, f, ensure_ascii=False)
        except Exception as e:
            app.logger.warning(f'[layover-recs] disk_save_fail: {e}')
            if not sb_ok:
                app.logger.error('[layover-recs] CRITICAL: weder SB noch Disk gesichert!')
    return sb_ok


def _recs_save_disk(iata, recs):
    """NUR den Disk-Read-Cache schreiben (Data-Layer-Refactor 2026-07-01):
    für Mutationen, die ihre SB-Änderung bereits per-Row geschrieben haben —
    _recs_save würde sonst ALLE Recs des Airports erneut bulk-upserten."""
    rp = _recs_path(iata)
    if not rp:
        return False
    try:
        with open(rp, 'w') as f:
            json.dump((recs or [])[-500:], f, ensure_ascii=False)
        return True
    except Exception as e:
        app.logger.warning(f'[layover-recs] disk_save_fail (ok wenn SB lief): {e}')
        return False


def _layover_rec_sb_update(rec_id, fields):
    """Per-Row-Update einzelner Spalten (z.B. vote_score/vote_count)."""
    if not SB_AVAILABLE or not rec_id or not fields:
        return False
    try:
        sb.table('layover_recs').update(fields).eq('id', rec_id).execute()
        return True
    except Exception as e:
        app.logger.warning(f'[layover-recs] sb_update_fail id={(rec_id or "")[:8]}: {str(e)[:120]}')
        return False


def _votes_load_from_disk(token):
    vp = _votes_path(token)
    if not vp:
        return {}
    try:
        with open(vp) as f:
            return json.load(f) or {}
    except (FileNotFoundError, json.JSONDecodeError):
        return {}
    except Exception:
        return {}


def _votes_load(token):
    """SB primary, Disk fallback, lazy-migrate."""
    sb_data = _layover_votes_load_from_supabase(token)
    if sb_data is None:
        return _votes_load_from_disk(token)
    if sb_data:
        return sb_data
    disk_data = _votes_load_from_disk(token)
