# ── CREW-HOTEL-AUTORISIERUNG (Owner 2026-07-13, „als Fake-Eurowings-Crew sah ich
#    die Lufthansa-Crewhotels" — Sicherheits-/Datenschutz-P0): Crew-Hotels sind
#    AIRLINE-VERTRAULICH. Ein Crew-Hotel = Layover-Rec der Kategorie 'sleep' MIT
#    gesetztem author_airline (von der Airline-Crew crowdsourced). Es wird NUR
#    ausgeliefert, wenn BEIDE Bedingungen erfüllt sind (doppelt sicher):
#      (1) das Profil des Betrachters trägt DIESELBE Airline, UND
#      (2) am Profil hängt ein GÜLTIGER Kalender/Roster (echter iCal-Import).
#    Keine Airline mischt mit einer anderen — Swiss-Crewhotels nur für Swiss-Crew
#    mit Kalender, Condor nur für Condor, usw. Generische Tipps (food/sight/…) und
#    'sleep'-Einträge OHNE author_airline bleiben crowdsourced sichtbar.
_CREW_HOTEL_CATS = {'sleep'}


def _viewer_airline_and_calendar(token):
    """(AIRLINE_UPPER, has_valid_calendar) des anfragenden Tokens. ('', False) unbekannt.
    Kalender-gültig = mindestens ein iCal-Briefing mit `ical_imported_at` (echter
    Roster-Import, nicht bloß eine manuelle Notiz). Wirft nie."""
    if not token:
        return ('', False)
    airline = ''
    try:
        airline = (((_profile_load(token) or {}).get('profile') or {}).get('airline') or '').strip().upper()
    except Exception:
        airline = ''
    has_cal = False
    try:
        ic = _ical_briefings_load(token) or {}
        has_cal = any(isinstance(v, dict) and v.get('ical_imported_at') for v in ic.values())
    except Exception:
        has_cal = False
    return (airline, has_cal)


def _filter_crew_hotels(recs, token):
    """Entfernt airline-vertrauliche Crew-Hotels, die der Betrachter NICHT sehen darf.
    Fail-CLOSED: ohne passende Airline + gültigen Kalender werden fremde/alle
    airline-getaggten Crew-Hotels ausgeblendet (Sicherheit vor Vollständigkeit)."""
    airline, has_cal = _viewer_airline_and_calendar(token)
    def _ok(r):
        if (r.get('category') or '').lower() not in _CREW_HOTEL_CATS:
            return True  # kein Crew-Hotel → crowdsourced sichtbar
        # Der Autor darf den eigenen Eintrag immer sehen. Das ist kein Cross-
        # Airline-Leak und verhindert, dass ein gerade geposteter Schlaf-Tipp
        # wegen eines noch nicht synchronisierten Kalender-Nachweises sofort
        # wieder aus seiner eigenen Liste verschwindet.
        if token and r.get('author_token') == token:
            return True
        aa = (r.get('author_airline') or '').strip().upper()
        if not aa:
            return True  # generischer Schlaf-Tipp ohne Airline-Bezug → sichtbar
        # Airline-vertrauliches Crew-Hotel: nur gleiche Airline MIT gültigem Kalender
        return bool(airline and has_cal and aa == airline)
    return [r for r in recs if _ok(r)]


def _public_layover_rec(rec):
    """Public API projection. The durable owner token is authorization data,
    never social response data (including the author-facing add response)."""
    out = {k: v for k, v in (rec or {}).items() if k != 'author_token'}
    if out.get('is_anonymous'):
        # author_airline remains stored internally because it is needed for the
        # cross-airline crew-hotel gate; anonymity only removes its public face.
        for key in ('author_short', 'author_name', 'author_airline'):
            out.pop(key, None)
    return out


def _public_layover_recs(recs):
    return [_public_layover_rec(r) for r in (recs or [])]


def _request_token():
    """Token aus ?token= ODER Authorization: Bearer <t>."""
    t = (request.args.get('token') or '').strip()
    if t:
        return t
    auth = request.headers.get('Authorization', '')
    return auth[7:].strip() if auth.startswith('Bearer ') else ''


@app.route('/api/layover-recs/<iata>', methods=['GET'])
def get_layover_recs(iata):
    """Liefert alle Recs für Airport, sortiert nach vote_score absteigend.
    Query: ?category=food → filter; ?token=… → markiert eigene Votes.
    Crew-Hotels werden airline-vertraulich gegated (siehe _filter_crew_hotels).
    """
    rp = _recs_path(iata)
    if not rp: return jsonify({'error': 'invalid_iata'}), 400
    cat = (request.args.get('category') or '').lower()
    if cat:
        if cat not in LAYOVER_CATEGORIES:
            return jsonify({'ok': False, 'error': 'invalid_category',
                            'allowed_categories': sorted(LAYOVER_CATEGORIES)}), 400
    recs = _recs_load(iata)
    if cat:
        recs = [r for r in recs if r.get('category') == cat]
    token = _request_token()
    # SICHERHEITS-GATE: fremde Airline-Crewhotels raus (Airline + gültiger Kalender).
    recs = _filter_crew_hotels(recs, token)
    recs.sort(key=lambda r: -(r.get('vote_score') or 0))
    # Apply voted-by-me
    voted = _votes_load(token) if token else {}
    for r in recs:
        r['my_vote'] = voted.get(r.get('id'), 0)
    return jsonify({'iata': iata.upper(), 'count': len(recs),
                    'recs': _public_layover_recs(recs)})


def _layover_img_key(token):
    """Opaker, deterministischer Verzeichnis-Key — Token nie in public URL
    (gleiches Muster wie _wall_img_key/_avatar_img_key, eigener Salt)."""
    return _hashlib.sha256(('layover:' + (token or '')).encode()).hexdigest()[:32]


@app.route('/api/layover-recs/<token>/upload-image', methods=['POST'])
def upload_layover_image(token):
    """Photo-Upload für Layover-Rec oder Comment. Returns {url} zum Einbetten."""
    # Rate-Limit: max 20 Bilder pro Stunde (gleiches Pattern wie wall/upload-image)
    if _token_rate_limited(token, 'layover_image_upload', limit=20, window_sec=3600):
        return jsonify({'ok': False, 'error': 'rate_limited',
                        'message': 'Zu viele Bild-Uploads. Bitte später erneut.'}), 429
    img = request.files.get('image')
    if not img:
        return jsonify({'ok': False, 'error': 'no_image'}), 400
    data = img.read()
    if len(data) > 5 * 1024 * 1024:
        return jsonify({'ok': False, 'error': 'too_large_5mb'}), 413
    detected_type, detected_ext = _detect_image_type(data)
    if not detected_type:
        return jsonify({'ok': False, 'error': 'invalid_image',
                        'message': 'Nur JPEG/PNG/HEIC/WebP erlaubt.'}), 415
    import os, re, uuid
    safe = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    if not safe:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    # Wall/R2-Muster (Tipps-Fotos 2026-07-10): Disk ist EPHEMER → Bilder ver-
    # schwanden bei jedem Redeploy (gleiche Klasse wie Wall-User #43). R2 primär
    # (durabel, Zero-Egress), Disk nur Fallback; serve_layover_image streamt aus
    # R2. Opaker dir_key statt Token als public URL-Segment (Token-Leak-Fix).
    dir_key = _layover_img_key(token)
    fname = f'{uuid.uuid4().hex[:12]}{detected_ext}'
    r2_ok = False
    if R2_AVATARS_ENABLED:
        try:
            _r2_put_bytes(f'layover/{dir_key}/{fname}', data, detected_type)
            r2_ok = True
        except Exception as e:
            app.logger.warning(f'[layover-img] r2_put_fail: {str(e)[:120]}')
    if not r2_ok:
        try:
            img_dir = os.path.join(_USER_HISTORY_DIR, 'layover_images', dir_key)
            os.makedirs(img_dir, exist_ok=True)
            with open(os.path.join(img_dir, fname), 'wb') as f:
                f.write(data)
        except Exception as e:
            print(f'[upload_layover_image] error: {type(e).__name__}: {str(e)[:300]}')
            return jsonify({'ok': False, 'error': 'internal_error'}), 500
    return jsonify({'ok': True, 'url': f'/api/layover-recs/image/{dir_key}/{fname}'})


@app.route('/api/layover-recs/image/<token_safe>/<fname>', methods=['GET'])
def serve_layover_image(token_safe, fname):
    """Serve uploaded Layover-Bild — public (Layover-Recs sind allgemein sichtbar)."""
    import os, re
    safe = re.sub(r'[^A-Za-z0-9_.-]', '', fname or '')
    safe_t = re.sub(r'[^A-Za-z0-9_-]', '', token_safe or '')[:64]
    if not safe or not safe_t:
        return jsonify({'error': 'invalid'}), 400
    path = os.path.join(_USER_HISTORY_DIR, 'layover_images', safe_t, safe)
    if not os.path.exists(path):
        # DURABILITY: neue Uploads liegen in R2 (Disk nur Fallback/Legacy) →
        # aus R2 streamen, gleiches Muster wie serve_wall_image.
        if R2_AVATARS_ENABLED:
            r2_data, r2_ctype = _r2_get_bytes(f'layover/{safe_t}/{safe}')
            if r2_data:
                from flask import Response
                return Response(r2_data, mimetype=r2_ctype or 'image/jpeg',
                                headers={'Cache-Control': 'public, max-age=31536000, immutable'})
        return jsonify({'error': 'not_found'}), 404
    from flask import send_file
    mime = 'image/jpeg'
    if safe.lower().endswith('.png'): mime = 'image/png'
    elif safe.lower().endswith('.heic'): mime = 'image/heic'
    elif safe.lower().endswith('.webp'): mime = 'image/webp'
    return send_file(path, mimetype=mime)


@app.route('/api/layover-recs/<token>/add', methods=['POST'])
def add_layover_rec(token):
    """Body: {iata, category, title, description, rating, price_band, location_hint?, lat?, lon?, image_url?}"""
    body = request.get_json(silent=True) or {}
    iata = (body.get('iata') or '').strip().upper()
    cat = (body.get('category') or 'other').lower()
    title = (body.get('title') or '').strip()
    desc = (body.get('description') or '').strip()
    rating = body.get('rating')
    price = (body.get('price_band') or '').strip()
    location_hint = (body.get('location_hint') or '').strip()[:200]
    # Optionales Ort-Foto (Vertrag mit iOS 2026-07-10): NUR eigene Serve-Pfade
    # aus upload_layover_image akzeptieren — keine fremden/absoluten URLs
    # (gleiche Schutz-Idee wie _wall_img_sanitize_urls). Ungültig → still None.
    image_url = (body.get('image_url') or '').strip() or None
    if image_url and not re.match(
            r'^/api/layover-recs/image/[A-Za-z0-9_-]{1,64}/[A-Za-z0-9_.-]{1,80}$',
            image_url):
        image_url = None
    # Optionale, vom Autor gepickte Pin-Koordinate (Karten-Picker im Composer).
    # Backward-compatible: fehlt/ungültig → None (Rec wird per Titel/Katalog gemappt).
    def _parse_coord(v, lo, hi):
        try:
            f = float(v)
        except (TypeError, ValueError):
            return None
        if f != f or f < lo or f > hi:  # NaN / out-of-range
            return None
        return f
    lat = _parse_coord(body.get('lat'), -90.0, 90.0)
    lon = _parse_coord(body.get('lon'), -180.0, 180.0)
    # (0,0) = „nichts gesetzt"-Sentinel (Null-Insel), kein echter Pick.
    if (lat == 0.0 and lon == 0.0) or lat is None or lon is None:
        lat = lon = None
    if len(iata) != 3 or not iata.isalpha():
        return jsonify({'ok': False, 'error': 'invalid_iata'}), 400
    if cat not in LAYOVER_CATEGORIES:
        return jsonify({'ok': False, 'error': 'invalid_category',
                        'allowed_categories': sorted(LAYOVER_CATEGORIES)}), 400
    if not title or len(title) > 120: return jsonify({'ok': False, 'error': 'invalid_title'}), 400
    if len(desc) > 800: return jsonify({'ok': False, 'error': 'desc_too_long'}), 413
    try:
        rating_n = int(rating) if rating is not None else 0
        rating_n = max(0, min(5, rating_n))
    except Exception:
        rating_n = 0
    if price not in ('€','€€','€€€','€€€€',''):
        price = ''
    rp = _recs_path(iata)
    if not rp: return jsonify({'ok': False, 'error': 'invalid_iata'}), 400
    import uuid, time
    rec = {
        'id': str(uuid.uuid4())[:12],
        'iata': iata,
        'category': cat,
        'title': title[:120],
        'description': desc,
        'rating': rating_n,
        'price_band': price,
        'location_hint': location_hint,
        'lat': lat,
        'lon': lon,
        'image_url': image_url,
        # Full token is stored only for exact owner authorization and is removed
        # from every public response by _public_layover_rec().
        'author_token': token,
        'created_at': datetime.now().isoformat(),
        'ts': time.time(),
        'vote_score': 1,  # Author auto-up-votes
        'vote_count': 1,
    }
    is_anonymous = body.get('is_anonymous') is True
    rec['is_anonymous'] = is_anonymous
    if not is_anonymous:
        rec['author_short'] = token[:8]
    # Author profile snapshot (SB-primary, Cloud-Run-ephemer-Disk sonst namenlos).
    # Airline stays internal even for anonymous sleep posts so anonymity cannot
    # accidentally bypass the cross-airline crew-hotel gate.
    try:
        pr = (_profile_load(token) or {}).get('profile', {}) or {}
        rec['author_airline'] = pr.get('airline')
        if not is_anonymous:
            rec['author_name'] = pr.get('name')
    except Exception:
        pass
    # Per-Row-Insert (2026-07-01): nur den NEUEN Rec nach SB upserten statt
    # alle Recs des Airports; Disk-Cache lokal anhängen.
    sb_ok = _layover_recs_save_to_supabase([rec])
    if SB_AVAILABLE:
        # Supabase is the durable source in production. Never answer ok=true
        # when its insert failed: the composer would dismiss although the next
        # GET/discover (possibly on another instance) cannot see the new tip.
        if not sb_ok:
            return jsonify({'ok': False, 'error': 'persist_failed',
                            'message': 'Tipp konnte nicht gespeichert werden.'}), 503
        # Disk is only a read cache once durable persistence acknowledged.
        _recs_save_disk(iata, _recs_load_from_disk(iata) + [rec])
    else:
        # Local/degraded mode has no Supabase. Disk is then the only persistence
        # layer and must acknowledge before the API may claim success.
        disk_ok = _recs_save_disk(iata, _recs_load_from_disk(iata) + [rec])
        if not disk_ok:
            return jsonify({'ok': False, 'error': 'persist_failed',
                            'message': 'Tipp konnte nicht gespeichert werden.'}), 503
    # Auto-record author's +1 vote
    votes = _votes_load(token)
    votes[rec['id']] = 1
    _layover_vote_sb_set(token, rec['id'], 1)
    _votes_save_disk(token, votes)
    return jsonify({'ok': True, 'rec': _public_layover_rec(rec)})


@app.route('/api/layover-recs/<token>/vote/<rec_id>', methods=['POST'])
def vote_layover_rec(token, rec_id):
    """Body: {direction: 1 (up) | -1 (down) | 0 (clear)}"""
    body = request.get_json(silent=True) or {}
    try:
        direction = int(body.get('direction') or 0)
    except Exception:
        direction = 0
    if direction not in (-1, 0, 1):
        return jsonify({'ok': False, 'error':'invalid_direction'}), 400
    if not _votes_path(token):
        return jsonify({'ok': False, 'error':'invalid_token'}), 400
    votes = _votes_load(token)
    prev = int(votes.get(rec_id) or 0)
    delta = direction - prev
    # Rec finden (SB-primär) und Score idempotent neu berechnen.
    iata = _layover_find_rec_iata(rec_id)
    if not iata:
        return jsonify({'ok': False, 'error':'rec_not_found'}), 404
    recs = _recs_load(iata)
    target = next((r for r in recs if r.get('id') == rec_id), None)
    if not target:
        return jsonify({'ok': False, 'error':'rec_not_found'}), 404
    # P0-Concurrency-Fix (2026-06-08): ZUERST die per-User-Stimme persistieren
    # (idempotent via composite-PK), DANN vote_score/count aus layover_rec_votes
    # neu ableiten — statt den denormalisierten Zähler read-modify-write
    # hochzuzählen. Gleichzeitige Upvotes konnten den Zähler clobbern
    # (9 Upvotes → netto 0); die abgeleitete Summe ist rennsicher.
    if direction == 0:
        votes.pop(rec_id, None)
    else:
        votes[rec_id] = direction
    _layover_vote_sb_set(token, rec_id, direction)
    _votes_save_disk(token, votes)
    tally = _layover_vote_tally_from_supabase(rec_id)
    if tally is not None:
        target['vote_score'], target['vote_count'] = tally
    else:
        # SB-down → degradierter Inkrement-Fallback (best-effort, nicht rennsicher).
        target['vote_score'] = (target.get('vote_score') or 0) + delta
        target['vote_count'] = max(0, (target.get('vote_count') or 0) + (
            1 if prev == 0 and direction != 0
            else (-1 if direction == 0 and prev != 0 else 0)))
    new_score = target['vote_score']
    # Per-Row-Update (2026-07-01): nur vote_score/vote_count DIESES Recs nach
    # SB schreiben statt alle Recs des Airports bulk-upserten; Disk-Cache lokal.
    _layover_rec_sb_update(rec_id, {'vote_score': target['vote_score'],
                                    'vote_count': target['vote_count']})
    _recs_save_disk(iata, recs)
    return jsonify({'ok': True, 'vote_score': new_score, 'my_vote': direction})


@app.route('/api/layover-recs/<token>/<rec_id>', methods=['DELETE'])
def delete_layover_rec(token, rec_id):
    """Author löscht eigene Empfehlung."""
    iata = _layover_find_rec_iata(rec_id)
    if iata:
        recs = _recs_load(iata)
        def _is_owned_target(r):
            if r.get('id') != rec_id:
                return False
            # New rows use exact owner identity. author_short remains a legacy
            # fallback for rows created before author_token was persisted.
            owner = r.get('author_token')
            return owner == token if owner else r.get('author_short') == token[:8]
        new_recs = [r for r in recs if not _is_owned_target(r)]
        if len(new_recs) != len(recs):
            # SB: soft-delete (deleted=true) per-Row; Disk-Cache lokal
            # überschreiben (2026-07-01: kein Bulk-Re-Upsert aller Recs mehr).
            _layover_recs_delete_from_supabase(rec_id)
            _recs_save_disk(iata, new_recs)
            return jsonify({'ok': True})
    return jsonify({'ok': False, 'error':'not_found_or_not_author'}), 404


# ─── Layover Reviews (Sterne-Ratings pro Stadt + Kategorie) ─────────────────
# Worker P6, 2026-06-01: zusätzlich zu den per-Tipp-Votes ein aggregiertes
# Stadt-Rating. Persistenz: SB-Tabelle `layover_reviews` (PK iata, user_token,
# category). Disk-Fallback bei SB-down — file-Mode pro IATA, atomarer rewrite.
LAYOVER_REVIEW_CATEGORIES = ('overall', 'hotel', 'food', 'safety', 'nightlife')


def _layover_reviews_disk_path(iata):
    """Disk-Fallback wenn Supabase nicht verfügbar. Pro IATA eine JSON-Datei
    mit der Liste aller Reviews (jedes Item: user_token, category, stars, ts).
    """
    import os, re
    safe = re.sub(r'[^A-Z]', '', (iata or '').upper())[:3]
    if len(safe) != 3:
        return None
    return os.path.join(_recs_dir(), f'reviews_{safe}.json')


def _layover_reviews_load_all(iata):
    """Lädt alle Reviews für IATA — SB primär, Disk-Fallback.
    Returns list[{user_token, category, stars, ...}] oder [] bei Fehler.
    Wichtig: user_token wird im Response NICHT exposed (kommt nur intern
    für PK-Match in rate_layover/Aggregate-Computation rein).
    """
    if SB_AVAILABLE:
        try:
            r = sb.table('layover_reviews') \
                .select('user_token,category,stars,created_at,updated_at') \
                .eq('iata', iata).execute()
            return list(r.data or [])
        except Exception as e:
            app.logger.warning(
                f'[lreview] sb_load_fail iata={iata} err={type(e).__name__}: {str(e)[:120]}'
            )
            # Fall-through zu Disk-Read damit Aggregate noch funktioniert
    p = _layover_reviews_disk_path(iata)
    if not p:
        return []
    try:
        with open(p) as f:
            data = json.load(f) or []
        return data if isinstance(data, list) else []
    except (FileNotFoundError, json.JSONDecodeError):
        return []
    except Exception:
        return []


def _layover_reviews_upsert(iata, user_token, category, stars):
    """Schreibt 1 Review. SB primär, Disk-Fallback bei SB-down.
    Re-Rate ist idempotent (PK-Upsert auf SB, Replace-in-list auf Disk).
    Returns True/False.
    """
    now_iso = datetime.now(timezone.utc).isoformat()
    row = {
        'iata': iata,
        'user_token': user_token,
        'category': category,
        'stars': int(stars),
        'updated_at': now_iso,
    }
    if SB_AVAILABLE:
        try:
            sb.table('layover_reviews').upsert(
                row, on_conflict='iata,user_token,category'
            ).execute()
            return True
        except Exception as e:
            app.logger.warning(
                f'[lreview] sb_upsert_fail iata={iata} cat={category} '
                f'err={type(e).__name__}: {str(e)[:200]}'
            )
            # Fall-through zu Disk-Write
    p = _layover_reviews_disk_path(iata)
    if not p:
        return False
    try:
        try:
            with open(p) as f:
                data = json.load(f) or []
            if not isinstance(data, list):
                data = []
        except (FileNotFoundError, json.JSONDecodeError):
            data = []
        new_data = [
            x for x in data
            if not (
                isinstance(x, dict)
                and x.get('user_token') == user_token
                and x.get('category') == category
            )
        ]
        row_disk = dict(row)
        row_disk['created_at'] = now_iso
        new_data.append(row_disk)
        with open(p, 'w') as f:
            json.dump(new_data[-5000:], f, ensure_ascii=False)
        return True
    except Exception as e:
        app.logger.error(
            f'[lreview] disk_upsert_fail iata={iata} err={type(e).__name__}: {str(e)[:200]}'
        )
        return False


@app.route('/api/layover-rec/<iata>/rate', methods=['POST'])
def rate_layover(iata):
    """Body: {token, stars: 1-5, category: overall|hotel|food|safety|nightlife}.

    Best-Effort: kein Token → 401, ungültige Category/Stars → 400. Doppel-Rate
    ist idempotent (PK-Upsert auf iata+user_token+category).
    """
    import re as _re
    safe_iata = _re.sub(r'[^A-Z]', '', (iata or '').upper())[:3]
    if len(safe_iata) != 3:
        return jsonify({'ok': False, 'error': 'invalid_iata'}), 400
    body = request.get_json(silent=True) or {}
    token = (body.get('token') or '').strip()
    if not token:
        return jsonify({'ok': False, 'error': 'no_token'}), 401
    # SECURITY (IDOR-Fix): Body-Token umgeht das Pfad-Binding-Gate → Bearer-Match,
    # sonst kann man Ratings unter fremder Identität abgeben (Rating-Spoofing).
    if not _request_bearer_matches(token):
        return jsonify({'ok': False, 'error': 'token_binding_required'}), 401
    try:
        stars = int(body.get('stars') or 0)
    except Exception:
        return jsonify({'ok': False, 'error': 'invalid_stars'}), 400
    if stars < 1 or stars > 5:
        return jsonify({'ok': False, 'error': 'invalid_stars'}), 400
    category = (body.get('category') or '').strip().lower()
    if category not in LAYOVER_REVIEW_CATEGORIES:
        return jsonify({'ok': False, 'error': 'invalid_category'}), 400
    ok = _layover_reviews_upsert(safe_iata, token, category, stars)
    if not ok:
        return jsonify({'ok': False, 'error': 'persistence_failed'}), 500
    return jsonify({'ok': True, 'iata': safe_iata, 'category': category, 'stars': stars})


@app.route('/api/layover-rec/<iata>/aggregate', methods=['GET'])
def aggregate_layover(iata):
    """Aggregiert Sterne pro Kategorie + Gesamt.

    Response:
      {iata, avg_stars (= overall avg if any, else avg über alle Kategorien),
       total_reviews (distinct user_token count über alle categories),
       breakdown: {overall: 4.2, hotel: 3.8, ...},
       counts:    {overall: 12,  hotel: 9,   ...}}

    Kategorien ohne Reviews erscheinen im breakdown NICHT (App-Side zeigt "—").
    Werte gerundet auf 1 Nachkommastelle.
    """
    import re as _re
    safe_iata = _re.sub(r'[^A-Z]', '', (iata or '').upper())[:3]
    if len(safe_iata) != 3:
        return jsonify({'error': 'invalid_iata'}), 400
    reviews = _layover_reviews_load_all(safe_iata)
    by_cat = {}
    distinct_users = set()
    for r in reviews:
        if not isinstance(r, dict):
            continue
        cat = r.get('category')
        if cat not in LAYOVER_REVIEW_CATEGORIES:
            continue
        try:
            s = int(r.get('stars') or 0)
        except Exception:
            continue
        if s < 1 or s > 5:
            continue
        by_cat.setdefault(cat, []).append(s)
        ut = r.get('user_token')
        if isinstance(ut, str) and ut:
            distinct_users.add(ut)
    breakdown = {}
    counts = {}
    for cat, lst in by_cat.items():
        if lst:
            breakdown[cat] = round(sum(lst) / len(lst), 1)
            counts[cat] = len(lst)
    if 'overall' in breakdown:
        avg_stars = breakdown['overall']
    elif by_cat:
        all_stars = [s for lst in by_cat.values() for s in lst]
        avg_stars = round(sum(all_stars) / len(all_stars), 1) if all_stars else 0.0
    else:
        avg_stars = 0.0
    return jsonify({
        'iata': safe_iata,
        'avg_stars': avg_stars,
        'total_reviews': len(distinct_users),
        'breakdown': breakdown,
        'counts': counts,
    })


# ─── LayoverRec Comments (per Rec) ──────────────────────────────────────────

def _layover_comments_path(rec_id):
    import os
    safe = re.sub(r'[^A-Za-z0-9_-]', '', rec_id or '')[:32]
    return os.path.join(_recs_dir(), f'comments_{safe}.json') if safe else None


def _layover_load_comments_from_disk(rec_id):
    p = _layover_comments_path(rec_id)
    if not p: return []
    try:
        with open(p) as f: return json.load(f) or []
    except (FileNotFoundError, json.JSONDecodeError):
        return []
    except Exception:
        return []


def _layover_load_comments(rec_id):
    """SB primary, Disk fallback, lazy-migrate."""
    sb_data = _layover_comments_load_from_supabase(rec_id)
    if sb_data is None:
        return _layover_load_comments_from_disk(rec_id)
    if sb_data:
        return sb_data
    disk_data = _layover_load_comments_from_disk(rec_id)
    if disk_data and SB_AVAILABLE:
        app.logger.info(f'[layover-comments] lazy-migrate {len(disk_data)} disk comments → supabase')
        _layover_comments_save_to_supabase(rec_id, disk_data)
        return disk_data
    return []


def _layover_save_comments(rec_id, comments):
    """SB primary + Disk Read-Cache."""
    comments = comments[-500:]
    _layover_comments_save_to_supabase(rec_id, comments)
    _layover_save_comments_disk(rec_id, comments)


def _layover_save_comments_disk(rec_id, comments):
    """NUR Disk-Cache (2026-07-01) — für Mutationen deren SB-Änderung bereits
    per-Row geschrieben wurde (Insert/Row-Delete)."""
    p = _layover_comments_path(rec_id)
    if not p: return
    try:
        with open(p, 'w') as f: json.dump((comments or [])[-500:], f, ensure_ascii=False)
    except Exception as e:
        app.logger.warning(f'[layover-comments] disk_save_fail: {e}')


@app.route('/api/layover-recs/<token>/<rec_id>/comments', methods=['GET'])
def layover_rec_get_comments(token, rec_id):
    comments = _layover_load_comments(rec_id)
    comments.sort(key=lambda c: (c.get('created_ts') or 0))
    return jsonify({'rec_id': rec_id, 'count': len(comments), 'comments': comments})


@app.route('/api/layover-recs/<token>/<rec_id>/comments', methods=['POST'])
def layover_rec_add_comment(token, rec_id):
    """Body: {body, image_url?, parent_comment_id?}"""
    body = request.get_json(silent=True) or {}
    text = (body.get('body') or '').strip()
    image_url = (body.get('image_url') or '').strip() or None
    parent_comment_id = (body.get('parent_comment_id') or '').strip() or None
    if not text and not image_url:
        return jsonify({'ok': False, 'error': 'empty'}), 400
    if len(text) > 1500:
        return jsonify({'ok': False, 'error': 'too_long'}), 413

    import uuid, time
    name = ''
    try:
        name = ((_profile_load(token) or {}).get('profile', {}) or {}).get('name') or ''
    except Exception:
        pass
    comment = {
        'id': str(uuid.uuid4())[:10],
        'rec_id': rec_id,
        'author_token': token,
        'author_short': token[:8],
        'author_name': name,
        'body': text,
        'image_url': image_url,
        'parent_comment_id': parent_comment_id,
        'created_at': datetime.now().isoformat(),
        'created_ts': time.time(),
    }
    comments = _layover_load_comments(rec_id)
    comments.append(comment)
    # Per-Row-Insert (2026-07-01): nur den NEUEN Kommentar nach SB.
    _layover_comments_save_to_supabase(rec_id, [comment])
    _layover_save_comments_disk(rec_id, comments)
    response_c = dict(comment)
    response_c.pop('author_token', None)
    # Push an Parent-Comment-Author (Reply-to-User)
    try:
        if parent_comment_id:
            parent = next((c for c in comments if c.get('id') == parent_comment_id), None)
            parent_token = parent.get('author_token') if parent else None
            if parent_token and parent_token != token:
                commenter = name or 'Crew'
                _push_notify_async(parent_token,
                                   f'{commenter} hat dir geantwortet',
                                   (text or '')[:120],
                                   data={'type': 'wall_comment_reply'},
                                   idempotency_key=(
                                       f'layover-comment:{comment.get("id")}:{parent_token}'))
    except Exception:
        pass
    return jsonify({'ok': True, 'comment': response_c})


@app.route('/api/layover-recs/<token>/<rec_id>/comments/<comment_id>', methods=['DELETE'])
def layover_rec_delete_comment(token, rec_id, comment_id):
    comments = _layover_load_comments(rec_id)
    new_comments = [c for c in comments if not (c.get('id') == comment_id and c.get('author_token') == token)]
    if len(new_comments) == len(comments):
        return jsonify({'ok': False, 'error': 'not_found_or_not_author'}), 404
    # Disk-Cache lokal (2026-07-01: kein Bulk-Re-Upsert der übrigen Kommentare).
    _layover_save_comments_disk(rec_id, new_comments)
    # Comment-Row explizit aus SB löschen (per-Row). Best-effort, guarded.
    if SB_AVAILABLE:
        try:
            sb.table('layover_rec_comments').delete().eq('id', comment_id).execute()
        except Exception as e:
            app.logger.warning(f'[layover-comments] sb comment row delete failed: {e}')
    return jsonify({'ok': True})


@app.route('/api/layover-recs/discover/<token>', methods=['GET'])
def discover_layover_recs(token):
    """„Trending"-Recs für Layover-Airports der nächsten 4 Wochen des Users."""
    sess = _store.get(token) or {}
    rd = sess.get('result_data') or {}
    tage = rd.get('_tage_detail') or []
    if not tage:
        # _store ist in-memory/per-Instanz → persistenter Snapshot-Fallback.
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    from datetime import date as _date, timedelta as _td
    today = _date.today()
    horizon = today + _td(days=28)
    upcoming_iatas = set()
    for t in tage:
        if not isinstance(t, dict): continue
        try:
            d = _date.fromisoformat(t.get('datum'))
        except Exception:
            continue
        if not (today <= d <= horizon): continue
        # Nightstop = letzte Tages-Ankunft (nicht blind reader_facts.layover_ort,
        # das bei Multi-Leg-Turnaround-Tagen einen Vortags-/Kontext-Wert trug).
        lo = (_feed_nightstop_ort(t) or '').upper().strip()
        if lo and len(lo) == 3:
            upcoming_iatas.add(lo)
    out = []
    for iata in upcoming_iatas:
        rp = _recs_path(iata)
        if not rp: continue
        # SB-primary wie ALLE anderen layover-recs-Routen (_recs_load): der rohe
        # Disk-Read hier war der einzige Rest — nach jedem Cloud-Run-Restart war
        # die ephemere Disk leer → discover lieferte KEINE User-Tipps mehr, der
        # Feed (recsForRealIATA) sah frisch gepostete Tipps nicht (Tibor/BLL).
        recs = _recs_load(iata)
        # SICHERHEITS-GATE (wie get_layover_recs): fremde Airline-Crewhotels raus.
        recs = _filter_crew_hotels(recs, token)
        top = sorted(recs, key=lambda r: -(r.get('vote_score') or 0))[:3]
        if top:
            out.append({'iata': iata, 'top_recs': _public_layover_recs(top)})
    return jsonify({'upcoming_iatas': sorted(upcoming_iatas), 'recommendations': out})


@app.route('/api/user/stats/<token>', methods=['GET'])
def get_user_stats(token):
    """Aggregiert Statistik über jüngste Auswertung."""
    session = _store.get(token) or {}
    rd = session.get('result_data') or {}
    tage = rd.get('_tage_detail') or []
    if not tage:
        # _store ist in-memory/per-Instanz → persistenter Snapshot-Fallback.
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    # Aggregate
    from collections import Counter
    klass_ct = Counter()
    layover_ct = Counter()
    z76_eur_by_country = {}
    monthly = {}
    for t in tage:
        if not isinstance(t, dict): continue
        datum = t.get('datum', '')
        klass = (t.get('klass') or '').upper()
        klass_ct[klass] += 1
        rf = t.get('reader_facts') or {}
        place = (rf.get('layover_ort') or '').upper().strip()
        if place and len(place) == 3 and place != 'FRA':
            layover_ct[place] += 1
        # Z76 € by country (from classifier_result.bmf_land)
        cr = t.get('classifier_result') or {}
        if klass == 'Z76':
            land = (cr.get('bmf_land') or '').strip()
            eur = float(cr.get('amount', 0) or 0)
            if land:
                z76_eur_by_country[land] = round(z76_eur_by_country.get(land, 0) + eur, 2)
        # Monthly
        if datum and len(datum) >= 7:
            ym = datum[:7]
            if ym not in monthly:
                monthly[ym] = {'tour_days': 0, 'hotel': 0, 'free': 0, 'office': 0}
            m = monthly[ym]
            if klass in ('Z72', 'Z73', 'Z74', 'Z76'):
                m['tour_days'] += 1
            if klass in ('FREI', 'URLAUB', 'KRANK', 'ZERODAY'):
                m['free'] += 1
            if klass == 'OFFICE':
                m['office'] += 1
            if (cr.get('counted_as_hotel_nacht')):
                m['hotel'] += 1

    # Sickness + Off-Days monthly
    sickness_monthly = {}
    off_monthly = {}
    duty_min_monthly = {}
    for t in tage:
        if not isinstance(t, dict): continue
        datum = t.get('datum', '')
        if not datum or len(datum) < 7: continue
        ym = datum[:7]
        klass = (t.get('klass') or '').upper()
        marker_lower = (t.get('marker') or '').lower()
        # Sickness: explizite Krankheits-Marker oder Klass = KRANK
        is_sick = (klass == 'KRANK' or 'krank' in marker_lower
                   or 'sick' in marker_lower or marker_lower in ('k', 'kk'))
        is_off = klass in ('FREI', 'URLAUB', 'ZERODAY') and not is_sick
        sickness_monthly[ym] = sickness_monthly.get(ym, 0) + (1 if is_sick else 0)
        off_monthly[ym] = off_monthly.get(ym, 0) + (1 if is_off else 0)
        # Duty-Minuten je Monat
        rf = t.get('reader_facts') or {}
        s_raw = rf.get('start_time')
        e_raw = rf.get('end_time')
        try:
            if s_raw and e_raw:
                sh, sm = [int(x) for x in s_raw.split(':')]
                eh, em = [int(x) for x in e_raw.split(':')]
                s_m = sh * 60 + sm
                e_m = eh * 60 + em
                dm = (e_m - s_m) if e_m > s_m else (24*60 - s_m) + e_m
                duty_min_monthly[ym] = duty_min_monthly.get(ym, 0) + dm
        except Exception:
            pass

    top_layovers = [{'place': k, 'count': v} for k, v in layover_ct.most_common(10)]
    by_country = sorted(z76_eur_by_country.items(), key=lambda x: -x[1])[:15]
    return jsonify({
        'token': token,
        'klass_distribution': dict(klass_ct),
        'top_layovers': top_layovers,
        'z76_by_country': [{'country': k, 'eur': v} for k, v in by_country],
        'monthly': monthly,
        'sickness_monthly': sickness_monthly,
        'off_days_monthly': off_monthly,
        'duty_min_monthly': duty_min_monthly,
        'totals': {
            'tour_days': sum(klass_ct[k] for k in ('Z72', 'Z73', 'Z74', 'Z76')),
            'hotel_nights': int(rd.get('hotel_naechte', 0) or 0),
            'fahr_tage': int(rd.get('fahr_tage', 0) or 0),
            'arbeitstage': int(rd.get('arbeitstage', 0) or 0),
            'z76_eur': float(rd.get('vma_aus', 0) or 0),
            'gesamt': float(rd.get('gesamt', 0) or 0),
            'sickness_days': sum(sickness_monthly.values()),
            'off_days': sum(off_monthly.values()),
            'duty_min_total': sum(duty_min_monthly.values()),
        }
    })


# ─── Trip-Stats (YTD + Lifetime; FlightOps + tage_detail) ─────────────────────
# Info-Reichtum, den FollowMe/OFFblock nicht bieten: km, Länder, Top-Airline,
# Top-Aircraft, Sparkline pro Monat, Achievements. 5-min Memory-Cache.
_AIRPORTS_COMPACT_CACHE = None   # {IATA: (lat, lon, country)}
_TRIP_STATS_CACHE = {}            # token -> (expires_ts, payload)


def _airports_compact_lookup():
    """Lazy-loaded IATA → (lat, lon, country) Map aus airports_compact.json."""
    global _AIRPORTS_COMPACT_CACHE
    if _AIRPORTS_COMPACT_CACHE is not None:
        return _AIRPORTS_COMPACT_CACHE
    out = {}
    try:
        ap_path = os.path.join(os.path.dirname(__file__), 'airports_compact.json')
        with open(ap_path) as f:
            data = json.load(f)
        fields = data.get('fields') or []
        rows = data.get('rows') or []
        try:
            i_iata = fields.index('iata')
            i_lat = fields.index('lat')
            i_lon = fields.index('lon')
            i_country = fields.index('country')
        except ValueError:
            _AIRPORTS_COMPACT_CACHE = {}
            return _AIRPORTS_COMPACT_CACHE
        for r in rows:
            try:
                iata = (r[i_iata] or '').upper()
                if not iata or len(iata) != 3:
                    continue
                lat = float(r[i_lat]); lon = float(r[i_lon])
                country = (r[i_country] or '').upper()
                out[iata] = (lat, lon, country)
            except (ValueError, TypeError, IndexError):
                continue
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        pass
    _AIRPORTS_COMPACT_CACHE = out
    return _AIRPORTS_COMPACT_CACHE


def _haversine_km(lat1, lon1, lat2, lon2):
    """Great-circle distance in km via Haversine. R=6371.0088 km."""
    import math
    R = 6371.0088
    phi1, phi2 = math.radians(lat1), math.radians(lat2)
    dphi = math.radians(lat2 - lat1)
    dlam = math.radians(lon2 - lon1)
    a = math.sin(dphi/2)**2 + math.cos(phi1)*math.cos(phi2)*math.sin(dlam/2)**2
    return 2 * R * math.asin(min(1.0, math.sqrt(a)))


# Flughafen → Bahn-Station-Snap (User 2026-06-29): Setzt die ÖPNV-Route auf das
# geometrische Terminal-ZENTRUM eines Groß-Flughafens, routet HAFAS zur Terminal-
# Haltestelle und hängt einen Flughafen-People-Mover an (FRA „SkyLine", DUS
# „SkyTrain") — ein längerer, falscher Weg. Crew steigt real am REGIONAL-/S-BAHNHOF
# UNTER dem Terminal aus und läuft ~10 Min zur Basis. Liegt das Routing-Ziel
# < _AIRPORT_RAIL_SNAP_KM an einem bekannten Flughafen, das Ziel auf dessen
# Bahn-Station-Koordinate snappen → Route endet am Bahnhof, kein People-Mover-Leg.
# NUR exakt (OSM) verifizierte Stationen — keine geratenen Koordinaten. (lat, lon, label)
_AIRPORT_RAIL_SNAP = [
    (50.05130, 8.57175, 'Frankfurt Flughafen Regionalbahnhof'),   # FRA — OSM-verifiziert
    (48.35377, 11.78613, 'München Flughafen Terminal (S1/S8)'),   # MUC — OSM-verifiziert
]
_AIRPORT_RAIL_SNAP_KM = 3.0


def _snap_to_airport_rail(lat, lon):
    """Liegt (lat,lon) < _AIRPORT_RAIL_SNAP_KM an einem bekannten Flughafen-Bahnhof,
    gib (snap_lat, snap_lon, label) der nächsten Station zurück, sonst None.
    Defensiv & additiv: kein Match → None → Routing verhält sich exakt wie zuvor."""
    best = None
    for slat, slon, label in _AIRPORT_RAIL_SNAP:
        d = _haversine_km(lat, lon, slat, slon)
        if d <= _AIRPORT_RAIL_SNAP_KM and (best is None or d < best[3]):
            best = (slat, slon, label, d)
    return (best[0], best[1], best[2]) if best else None


def _trip_stats_achievements(life):
    """Achievement-Badges; nur tatsächlich verdiente werden zurückgegeben."""
    out = []
    hrs = life['hours_flown_min'] / 60.0
    for threshold, key, label in [
        (1000, 'h1k', '1000h Captain'),
        (5000, 'h5k', '5000h Veteran'),
        (10000, 'h10k', '10000h Legend'),
    ]:
        if hrs >= threshold:
            out.append({'key': key, 'label': label, 'tier': 'gold'})
    for threshold, key, label in [
        (25, 'c25', '25 Länder'),
        (50, 'c50', '50 Länder'),
        (100, 'c100', '100 Länder'),
    ]:
        if len(life['countries']) >= threshold:
            out.append({'key': key, 'label': label, 'tier': 'gold'})
    for threshold, key, label in [
        (100_000, 'km100k', '100k km'),
        (500_000, 'km500k', '500k km'),
        (1_000_000, 'km1m', '1M km'),
    ]:
        if life['distance_km'] >= threshold:
            out.append({'key': key, 'label': label, 'tier': 'gold'})
    if life['flights'] >= 500:
        out.append({'key': 'fl500', 'label': '500 Flüge', 'tier': 'gold'})
    if life['flights'] >= 1000:
        out.append({'key': 'fl1k', 'label': '1000 Flüge', 'tier': 'gold'})
    return out


def _trip_stats_compute(token):
    """Berechnet YTD + Lifetime Trip-Stats aus session.result_data._tage_detail
    + FlightOps. Returns dict mit ehrlichem Empty-State wenn beide leer.
    """
    from collections import Counter
    session = _store.get(token) or {}
    rd = session.get('result_data') or {}
    tage = rd.get('_tage_detail') or []
    if not tage:
        # _store ist in-memory/per-Instanz → persistenter Snapshot-Fallback.
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []

    fops = {}
    p = _flight_ops_path(token)
    if p:
        try:
            with open(p) as f:
                fops = json.load(f) or {}
        except (FileNotFoundError, json.JSONDecodeError, OSError):
            fops = {}

    current_year = datetime.utcnow().year
    ap_lookup = _airports_compact_lookup()

    def _zero():
        return {
            'hours_flown_min': 0,
            'flights': 0,
            'distance_km': 0.0,
            'countries': set(),
            'airlines': Counter(),
            'aircraft_types': Counter(),
            'aircraft_regs': Counter(),
            'frei_days': 0,
            'sickness_days': 0,
            'standby_days': 0,
            'tour_days': 0,
            'spesen_eur': 0.0,
            'spesen_days': 0,
        }
    life = _zero()
    ytd = _zero()
    monthly_hours = {}
    monthly_flights = {}
    longest_layover_days = 0
    longest_layover_place = None
    fastest_turn_min = None
    longest_tour_days = 0
    longest_tour_routing = ''
    destinations_ct = Counter()

    def _accumulate_distance(routing_str, target):
        if not routing_str or not isinstance(routing_str, str):
            return 0
        parts = [pp.strip().upper() for pp in routing_str.split('-')
                if pp and len(pp.strip()) == 3]
        if len(parts) < 2:
            return 0
        legs = 0
        for a, b in zip(parts[:-1], parts[1:]):
            ca = ap_lookup.get(a)
            cb = ap_lookup.get(b)
            if ca and cb:
                target['distance_km'] += _haversine_km(ca[0], ca[1], cb[0], cb[1])
                legs += 1
        return legs

    for t in tage:
        if not isinstance(t, dict): continue
        datum = t.get('datum') or ''
        if not datum or len(datum) < 10:
            continue
        try:
            year = int(datum[:4])
        except ValueError:
            continue
        ym = datum[:7]
        klass = (t.get('klass') or '').upper()
        marker_lower = (t.get('marker') or '').lower()
        rf = t.get('reader_facts') or {}
        cr = t.get('classifier_result') or {}
        # Per-Tag VMA-Betrag (Spesen-Schätzbasis, Issue #spesen-honest).
        spesen_amt = float(cr.get('amount', 0) or 0)
        is_sick = (klass == 'KRANK' or 'krank' in marker_lower or 'sick' in marker_lower
                   or marker_lower in ('k', 'kk'))
        is_standby = ('standby' in marker_lower or marker_lower in ('sby', 'st'))
        is_frei = klass in ('FREI', 'URLAUB', 'ZERODAY') and not is_sick

        targets = [life]
        if year == current_year:
            targets.append(ytd)
        for tg in targets:
            if is_sick: tg['sickness_days'] += 1
            if is_standby: tg['standby_days'] += 1
            if is_frei: tg['frei_days'] += 1
            if klass in ('Z72', 'Z73', 'Z74', 'Z76'):
                tg['tour_days'] += 1
                # Spesen-Schätzung: Summe der pro-Tag-VMA aus dem importierten Plan.
                # KEIN geprüfter Jahres-Wert → wird ehrlich als Schätzung markiert.
                if spesen_amt > 0:
                    tg['spesen_eur'] += spesen_amt
                    tg['spesen_days'] += 1

        routing = t.get('routing') or ''
        legs = _accumulate_distance(routing, life)
        if year == current_year:
            _accumulate_distance(routing, ytd)
        if legs > 0:
            life['flights'] += legs
            if year == current_year:
                ytd['flights'] += legs
            monthly_flights[ym] = monthly_flights.get(ym, 0) + legs

        for code in [pp.strip().upper() for pp in routing.split('-')
                    if pp and len(pp.strip()) == 3]:
            ent = ap_lookup.get(code)
            if ent and ent[2]:
                life['countries'].add(ent[2])
                if year == current_year:
                    ytd['countries'].add(ent[2])
        lo = (rf.get('layover_ort') or '').upper().strip()
        if lo and len(lo) == 3 and lo != 'FRA':
            # Top-Ziele = wie OFT man da war (Besuche/Hinflüge), NICHT Nächte.
            # Die eigentliche Besuchszählung passiert weiter unten in der
            # chronologisch sortierten Schleife (sorted_tage), weil ein
            # Aufenthalt über mehrere Nächte EIN Besuch ist und sich nur in
            # Datums-Reihenfolge zuverlässig als ein zusammenhängender Block
            # erkennen lässt. Hier nur noch Länder-Aggregation.
            ent = ap_lookup.get(lo)
            if ent and ent[2]:
                life['countries'].add(ent[2])
                if year == current_year:
                    ytd['countries'].add(ent[2])

        s_raw = rf.get('start_time')
        e_raw = rf.get('end_time')
        try:
            if s_raw and e_raw:
                sh, sm = [int(x) for x in s_raw.split(':')]
                eh, em = [int(x) for x in e_raw.split(':')]
                s_m = sh * 60 + sm
                e_m = eh * 60 + em
                dm = (e_m - s_m) if e_m > s_m else (24*60 - s_m) + e_m
                if klass in ('Z72', 'Z73', 'Z74', 'Z76'):
                    life['hours_flown_min'] += dm
                    if year == current_year:
                        ytd['hours_flown_min'] += dm
                    monthly_hours[ym] = monthly_hours.get(ym, 0.0) + dm / 60.0
        except (ValueError, TypeError):
            pass

    # FlightOps für Airline + Aircraft-Type
    for datum, ops in (fops.items() if isinstance(fops, dict) else []):
        if not isinstance(ops, dict): continue
        try:
            year = int((datum or '')[:4])
        except ValueError:
            continue
        targets = [life]
        if year == current_year:
            targets.append(ytd)
        fn = (ops.get('flightNumber') or '').strip().upper()
        if fn:
            airline = ''.join(c for c in fn if c.isalpha())[:3]
            if airline:
                for tg in targets:
                    tg['airlines'][airline] += 1
        ac_type = (ops.get('aircraftType') or '').strip().upper()
        if ac_type:
            for tg in targets:
                tg['aircraft_types'][ac_type] += 1
        ac_reg = (ops.get('aircraftReg') or '').strip().upper()
        if ac_reg:
            for tg in targets:
                tg['aircraft_regs'][ac_reg] += 1

    # Tour/Layover-Längen + fastest turn
    cur_tour_len = 0
    cur_tour_routing = ''
    cur_layover = None
    cur_layover_len = 0
    sorted_tage = sorted([t for t in tage if isinstance(t, dict) and t.get('datum')],
                        key=lambda x: x.get('datum'))
    visit_prev_lo = None   # letzter Ort eines zusammenhängenden Übernacht-Blocks
    for t in sorted_tage:
        klass = (t.get('klass') or '').upper()
        rf = t.get('reader_facts') or {}
        cr = t.get('classifier_result') or {}
        lo = (rf.get('layover_ort') or '').upper().strip()
        if klass in ('Z72', 'Z73', 'Z74', 'Z76'):
            if cur_tour_len == 0:
                cur_tour_routing = t.get('routing') or ''
            cur_tour_len += 1
        else:
            if cur_tour_len > longest_tour_days:
                longest_tour_days = cur_tour_len
                longest_tour_routing = cur_tour_routing
            cur_tour_len = 0
            cur_tour_routing = ''
        # Top-Ziele nach BESUCHEN zählen: wie oft man da war = wie oft man einen
        # Hinflug dahin hatte. Ein Aufenthalt über mehrere Nächte = EIN Besuch.
        # Ein neuer Besuch beginnt, sobald eine Auswärts-Übernachtung an einem
        # Ort startet, der NICHT der unmittelbar vorhergehende Übernacht-Ort ist
        # (gleiches Gating wie zuvor: counted_as_hotel_nacht / overnight_after_day).
        overnight = bool(cr.get('counted_as_hotel_nacht')) or bool(rf.get('overnight_after_day'))
        if lo and len(lo) == 3 and lo != 'FRA' and overnight:
            if lo != visit_prev_lo:
                destinations_ct[lo] += 1   # ein Besuch je Aufenthalt (Hinflug)
            visit_prev_lo = lo
        else:
            visit_prev_lo = None
        if lo and lo != 'FRA':
            if cur_layover == lo:
                cur_layover_len += 1
            else:
                cur_layover = lo
                cur_layover_len = 1
            if cur_layover_len > longest_layover_days:
                longest_layover_days = cur_layover_len
                longest_layover_place = lo
        else:
            cur_layover = None
            cur_layover_len = 0
    if cur_tour_len > longest_tour_days:
        longest_tour_days = cur_tour_len
        longest_tour_routing = cur_tour_routing

    for i in range(len(sorted_tage) - 1):
        a = sorted_tage[i]; b = sorted_tage[i+1]
        if (a.get('klass') or '').upper() not in ('Z72', 'Z73', 'Z74', 'Z76'): continue
        if (b.get('klass') or '').upper() not in ('Z72', 'Z73', 'Z74', 'Z76'): continue
        rfa = a.get('reader_facts') or {}
        rfb = b.get('reader_facts') or {}
        e_raw = rfa.get('end_time'); s_raw = rfb.get('start_time')
        try:
            if e_raw and s_raw:
                eh, em = [int(x) for x in e_raw.split(':')]
                sh, sm = [int(x) for x in s_raw.split(':')]
                e_m = eh*60 + em
                s_m = sh*60 + sm
                gap = (24*60 - e_m) + s_m
                if gap > 0 and gap < (fastest_turn_min if fastest_turn_min is not None else 24*60 + 1):
                    fastest_turn_min = gap
        except (ValueError, TypeError):
            pass

    has_data = bool(tage) or bool(fops)

    def _serialize(bucket):
        return {
            'hours_flown': round(bucket['hours_flown_min'] / 60.0, 1),
            'flights': bucket['flights'],
            'distance_km': round(bucket['distance_km']),
            'countries_visited': len(bucket['countries']),
            'countries_list': sorted(list(bucket['countries'])),
            'top_airline': (bucket['airlines'].most_common(1)[0][0]
                           if bucket['airlines'] else None),
            'top_aircraft': (bucket['aircraft_types'].most_common(1)[0][0]
                            if bucket['aircraft_types'] else None),
            'top_aircraft_reg': (bucket['aircraft_regs'].most_common(1)[0][0]
                                if bucket['aircraft_regs'] else None),
            'frei_days': bucket['frei_days'],
            'sickness_days': bucket['sickness_days'],
            'standby_days': bucket['standby_days'],
            'tour_days': bucket['tour_days'],
            # Spesen: ehrlich als SCHÄTZUNG aus dem importierten Plan markiert,
            # KEIN geprüfter Jahres-Wert (Issue: "Jahr-Spesen ohne Beweise").
            # Client soll labeln: "geschätzt aus deinem Plan (X Tage)".
            'spesen_estimate': round(bucket['spesen_eur'], 2),
            'spesen_is_estimate': True,
            'spesen_basis_days': bucket['spesen_days'],
        }

    return {
        'token': token,
        'has_data': has_data,
        'empty_reason': None if has_data else 'no_tax_eval_no_flightops',
        'empty_hint': (None if has_data else
                      'Importiere zuerst deinen Dienstplan + Tax-Auswertung.'),
        'current_year': current_year,
        'lifetime': _serialize(life),
        'ytd': _serialize(ytd),
        'monthly_hours_flown': {k: round(v, 1) for k, v in sorted(monthly_hours.items())},
        'monthly_flights': dict(sorted(monthly_flights.items())),
        'top_destinations': [{'place': k, 'count': v}
                            for k, v in destinations_ct.most_common(10)],
        'longest_tour': ({'days': longest_tour_days, 'routing': longest_tour_routing}
                        if longest_tour_days > 0 else None),
        'longest_layover': ({'place': longest_layover_place, 'days': longest_layover_days}
                           if longest_layover_place else None),
        'fastest_turnaround_min': fastest_turn_min,
        'achievements': _trip_stats_achievements(life),
    }


@app.route('/api/user/trip-stats/<token>', methods=['GET'])
def get_trip_stats(token):
    """Trip-Stats YTD + Lifetime. 5-min Memory-Cache.
    Empty-State (`has_data=False`) wenn _tage_detail UND FlightOps leer.
    """
    import time
    now = time.time()
    cached = _TRIP_STATS_CACHE.get(token)
    if cached and cached[0] > now:
        return jsonify(cached[1])
    payload = _trip_stats_compute(token)
    _TRIP_STATS_CACHE[token] = (now + 300, payload)
    _cache_soft_cap(_TRIP_STATS_CACHE)
    # #111: anonymisierte YTD-Kernmetriken ins Community-Aggregat (best-effort).
    if payload.get('has_data'):
        _community_upsert_stats(token, payload.get('ytd') or {})
    return jsonify(payload)


def _community_token_hash(token):
    import hashlib
    return hashlib.sha256((token or '').encode('utf-8')).hexdigest()[:32]


def _community_upsert_stats(token, ytd):
    """Best-effort: persistiert die ANONYMISIERTEN YTD-Kernmetriken des Users in der
    Supabase-Tabelle `community_stats` für den AeroX-weiten Benchmark (#111). Der
    Token wird gehasht (keine Klartext-Identität). Fehlertolerant — blockiert den
    Stats-Call nie. Tabelle (einmalig in Supabase anlegen):
        create table community_stats (
          token_hash text primary key,
          hours_flown float8, flights int, countries int,
          tour_days int, distance_km float8, updated timestamptz
        );
    """
    if sb is None:
        return
    try:
        row = {
            'token_hash': _community_token_hash(token),
            'hours_flown': float(ytd.get('hours_flown') or 0),
            'flights': int(ytd.get('flights') or 0),
            'countries': int(ytd.get('countries_visited') or 0),
            'tour_days': int(ytd.get('tour_days') or 0),
            'distance_km': float(ytd.get('distance_km') or 0),
            'updated': datetime.utcnow().isoformat(),
        }
        def _do():
            return sb.table('community_stats').upsert(row, on_conflict='token_hash').execute()
        _supabase_execute_with_timeout('community_upsert', _do, timeout_s=4)
    except Exception as e:
        app.logger.warning(f'[community] upsert-fail: {str(e)[:120]}')


def _community_metrics_from_ical(token):
    """YTD-Kernmetriken aus den PERSISTENTEN iCal-Briefings (Supabase) berechnen —
    Fallback für die Community-Aggregation (#111), wenn keine Tax-Auswertung
    vorliegt. So zählt jeder iCal-verbundene User mit, unabhängig von der ephemeren
    In-Memory-Session. Liefert dieselben Keys wie der trip-stats `ytd`-Bucket.
    """
    try:
        briefings = _ical_briefings_load(token) or {}
    except Exception:
        briefings = {}
    if not isinstance(briefings, dict) or not briefings:
        return None

    year = datetime.utcnow().year
    ap_lookup = _airports_compact_lookup()
    total_min = 0.0
    flights = 0
    distance_km = 0.0
    countries = set()
    tour_days = 0

    def _parse_iso(s):
        if not s or not isinstance(s, str):
            return None
        try:
            return datetime.fromisoformat(s.replace('Z', '+00:00'))
        except ValueError:
            return None

    for d, b in briefings.items():
        if not isinstance(d, str) or len(d) < 4 or not d[:4].isdigit():
            continue
        if int(d[:4]) != year:
            continue
        if not isinstance(b, dict):
            continue
        secs = b.get('ical_sectors') or []
        day_has_flight = False
        for s in secs:
            if not isinstance(s, dict):
                continue
            frm = (s.get('from') or '').upper()
            to = (s.get('to') or '').upper()
            dep = _parse_iso(s.get('dep_iso'))
            arr = _parse_iso(s.get('arr_iso'))
            if dep and arr:
                mins = (arr - dep).total_seconds() / 60.0
                if mins < 0:
                    mins += 24 * 60  # Mitternachts-Wrap
                if 0 < mins < 20 * 60:  # plausibler Flug
                    total_min += mins
            flights += 1
            day_has_flight = True
            ca = ap_lookup.get(frm); cb = ap_lookup.get(to)
            if ca and cb:
                distance_km += _haversine_km(ca[0], ca[1], cb[0], cb[1])
            for code in (frm, to):
                ent = ap_lookup.get(code)
                if ent and ent[2]:
                    countries.add(ent[2])
        lo = ((b.get('reader_facts') or {}).get('layover_ort') or '').upper().strip()
        if len(lo) == 3:
            ent = ap_lookup.get(lo)
            if ent and ent[2]:
                countries.add(ent[2])
        if day_has_flight:
            tour_days += 1

    if flights == 0:
        return None
    return {
        'hours_flown': round(total_min / 60.0, 1),
        'flights': flights,
        'distance_km': round(distance_km),
        'countries_visited': len(countries),
        'tour_days': tour_days,
    }


# ── CREW-PASSPORT (Feature A, 2026-07-12) ─────────────────────────────────
# Profil-Statistik im Flighty-„Passport"-Stil: Aggregation über ALLE
# gespeicherten Roster-Sektoren des Users (dieselbe Quelle wie get_briefings:
# ical_sectors der manual- + iCal-Briefings, Merge-Semantik identisch —
# manual gewinnt bei vorhandenen Sektoren, sonst iCal). KEINE neue
# Datenquelle, kein Paid-Spend — nur ehrliche Aggregation des Vorhandenen.
_PASSPORT_STATS_CACHE = {}      # (token, range) -> (expires_ts, payload)
_PASSPORT_ROUTE_DUR_CACHE = {}  # 'FRA-JFK' -> (expires_ts, minutes|None)


def _passport_briefings_merged(token):
    """Alle Tagessätze des Users (manual + iCal gemerged) — NUR fürs Lesen der
    ical_sectors. Gleiche Prioritäts-Semantik wie get_briefings (setdefault:
    manual-Sektoren gewinnen, iCal füllt Lücken), aber OHNE die teuren
    Serve-Time-Anreicherungen (Kalender-Refresh, Live-Delays) — der Passport
    braucht nur die historischen Legs, keine Live-Zahlen."""
    try:
        data = dict(_manual_briefings_load(token) or {})
    except Exception:
        data = {}
    try:
        for k, v in (_ical_briefings_load(token) or {}).items():
            if not isinstance(v, dict):
                continue
            cur = data.get(k)
            if not isinstance(cur, dict):
                data[k] = v
                continue
            has_cur = isinstance(cur.get('ical_sectors'), list) and cur.get('ical_sectors')
            has_new = isinstance(v.get('ical_sectors'), list) and v.get('ical_sectors')
            if not has_cur and has_new:
                cur = dict(cur)
                cur['ical_sectors'] = v['ical_sectors']
                data[k] = cur
    except Exception:
        pass
    return data


def _passport_route_duration_min(frm, to, budget):
    """Typische Block-Minuten einer Strecke aus der route-history (Median der
    duration_min der letzten 7 Tage) — Fallback für Sektoren OHNE arr_iso.
    Prozess-Cache 6 h (auch Negativ-Treffer, sonst scannt jeder Passport-
    Compute dieselbe tote Strecke erneut). `budget` ist ein mutierbarer
    Zähler ({'n': int}) und deckelt die teuren Board-Scans pro Compute —
    ist er aufgebraucht, wird ehrlich None geliefert (Leg fällt aus der
    Flugzeit-Summe, NICHTS wird erfunden). Wirft nie."""
    key = f'{frm}-{to}'
    now = time.time()
    ent = _PASSPORT_ROUTE_DUR_CACHE.get(key)
    if ent and ent[0] > now:
        return ent[1]
    if not isinstance(budget, dict) or budget.get('n', 0) <= 0:
        return None
    budget['n'] = budget.get('n', 0) - 1
    dur = None
    try:
        # Interner View-Reuse (Muster flight-detail-Aggregat): route-history
        # in einem test_request_context aufrufen statt HTTP-Roundtrip.
        with app.test_request_context(f'/api/ax/route-history/{frm}/{to}?days=7'):
            resp = ax_route_history(frm, to)
        body = resp[0] if isinstance(resp, tuple) else resp
        payload = body.get_json(silent=True) or {}
        vals = []
        for d in payload.get('recent_days') or []:
            for f in (d or {}).get('flights') or []:
                dm = f.get('duration_min')
                if isinstance(dm, (int, float)) and 0 < dm < 20 * 60:
                    vals.append(float(dm))
        if vals:
            vals.sort()
            dur = int(vals[len(vals) // 2])
    except Exception:
        dur = None
    _PASSPORT_ROUTE_DUR_CACHE[key] = (now + 6 * 3600, dur)
    _cache_soft_cap(_PASSPORT_ROUTE_DUR_CACHE)
    return dur


def _passport_range_match(datum, rng):
    """True wenn ein YYYY-MM-DD-Datum in den Range fällt (all | YYYY | YYYY-MM)."""
    if rng == 'all':
        return True
    if len(rng) == 4:
        return datum[:4] == rng
    return datum[:7] == rng


def _passport_stats_compute(token, rng):
    """Crew-Passport-Aggregat für einen Range:
      flights / distance_km (Großkreis) / minutes_flown (arr−dep, Fallback
      route-history-Median, sonst Leg ehrlich AUS der Zeit-Summe raus) /
      Airports- / Airlines- (Flugnummern-Präfix) / Länder-Sets (ISO-2 aus der
      Referenz-DB) + deduplizierte Routen-Liste mit Koordinaten (max 80,
      häufigste zuerst). `years` trägt IMMER alle Jahre mit Flug-Daten
      (unabhängig vom Range) — daraus baut der Client seine Zeitraum-Pills."""
    from collections import Counter
    days = _passport_briefings_merged(token)
    ap_lookup = _airports_compact_lookup()

    flights = 0
    distance_km = 0.0
    minutes = 0.0
    legs_without_duration = 0
    airports = set()
    airlines = set()
    countries = set()
    routes = Counter()
    years = set()
    first_date = None
    last_date = None
    dur_budget = {'n': 5}   # max teure route-history-Lookups pro Compute

    def _parse_iso(s):
        if not s or not isinstance(s, str):
            return None
        try:
            return datetime.fromisoformat(s.replace('Z', '+00:00'))
        except ValueError:
            return None

    for datum in sorted(days.keys()):
        day = days.get(datum)
        if not isinstance(day, dict) or not isinstance(datum, str):
            continue
        if not re.match(r'^\d{4}-\d{2}-\d{2}$', datum):
            continue
        secs = day.get('ical_sectors') or []
        day_counted = False
        for s in secs:
            if not isinstance(s, dict):
                continue
            frm = (s.get('from') or '').strip().upper()
            to = (s.get('to') or '').strip().upper()
            if len(frm) != 3 or len(to) != 3 or frm == to:
                continue
            years.add(datum[:4])
            if not _passport_range_match(datum, rng):
                continue
            flights += 1
            day_counted = True
            airports.add(frm)
            airports.add(to)
            routes[(frm, to)] += 1
            fn = (s.get('flight') or s.get('flight_no') or '').replace(' ', '').upper()
            m = re.match(r'^([A-Z]{2,3})\d', fn)
            if m:
                airlines.add(m.group(1))
            ca = ap_lookup.get(frm)
            cb = ap_lookup.get(to)
            if ca and cb:
                distance_km += _haversine_km(ca[0], ca[1], cb[0], cb[1])
            for ent in (ca, cb):
                if ent and ent[2]:
                    countries.add(ent[2])
            # Flugzeit: arr−dep wenn beide da und plausibel; sonst der
            # route-history-Median; sonst fällt das Leg aus der Zeit-Summe.
            dep = _parse_iso(s.get('dep_iso'))
            arr = _parse_iso(s.get('arr_iso'))
            mins = None
            if dep and arr:
                delta = (arr - dep).total_seconds() / 60.0
                if delta < 0:
                    delta += 24 * 60   # Mitternachts-Wrap (naive iCal-Zeiten)
                if 0 < delta < 20 * 60:
                    mins = delta
            if mins is None:
                mins = _passport_route_duration_min(frm, to, dur_budget)
            if mins is not None:
                minutes += float(mins)
            else:
                legs_without_duration += 1
        if day_counted:
            if first_date is None:
                first_date = datum
            last_date = datum

    routes_out = []
    for (frm, to), n in routes.most_common(80):
        ca = ap_lookup.get(frm)
        cb = ap_lookup.get(to)
        if not (ca and cb):
            continue   # ohne Koordinaten kein Bogen — ehrlich weglassen
        routes_out.append({'from': frm, 'to': to, 'n': n,
                           'lat1': round(ca[0], 3), 'lon1': round(ca[1], 3),
                           'lat2': round(cb[0], 3), 'lon2': round(cb[1], 3)})

    return {
        'ok': True,
        'has_data': flights > 0,
        'range': rng,
        'flights': flights,
        'distance_km': round(distance_km),
        'minutes_flown': int(round(minutes)),
        'legs_without_duration': legs_without_duration,
        'airports': sorted(airports),
        'airports_count': len(airports),
        'airlines': sorted(airlines),
        'airlines_count': len(airlines),
        'countries': sorted(countries),
        'countries_count': len(countries),
        'routes': routes_out,
        'first_date': first_date,
        'last_date': last_date,
        'years': sorted(years, reverse=True),
    }


@app.route('/api/user/passport-stats/<token>', methods=['GET'])
def get_passport_stats(token):
    """Crew-Passport (Profil-Statistik) — GET /api/user/passport-stats/<token>
    ?range=all|YYYY|YYYY-MM. Owner-Route mit Bearer-PFLICHT (der Passport
    aggregiert die komplette Roster-Historie = PII; zusätzlich zum bug004-
    Prefix-Gate hier hart gebunden). 60-s-Memo pro (token, range)."""
    if not token:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    if not _request_bearer_matches(token):
        return jsonify({'ok': False, 'error': 'unauthorized'}), 401
    rng = (request.args.get('range') or 'all').strip()
    if not re.match(r'^(all|\d{4}|\d{4}-\d{2})$', rng):
        return jsonify({'ok': False, 'error': 'bad_range'}), 400
    now = time.time()
    key = (token, rng)
    cached = _PASSPORT_STATS_CACHE.get(key)
    if cached and cached[0] > now:
        return jsonify(cached[1])
    try:
        payload = _passport_stats_compute(token, rng)
    except Exception as e:
        print(f'[passport-stats] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    _PASSPORT_STATS_CACHE[key] = (now + 60, payload)
    _cache_soft_cap(_PASSPORT_STATS_CACHE)
    return jsonify(payload)


@app.route('/api/user/friend-passport/<token>', methods=['GET'])
def get_friend_passport(token):
    """Crew-Passport eines FREUNDES (P3, Owner 2026-07-12: „Freunde sehen es
    zusammen mit dem Kalender … Profil halt") —
    GET /api/user/friend-passport/<token>?friend=<match|token>&range=all|YYYY|YYYY-MM.

    Privacy = der friend-roster-Pfad: Bearer muss dem EIGENEN Pfad-Token
    entsprechen (401), der Friend-Parameter wird via _resolve_friend_token
    aufgelöst (PII-gekürzte Tokens aus friends-today), dann MUSS die
    Freundschafts-Kante bestehen (sonst 403 not_friends) UND der Freund darf
    share_roster nicht explizit abgeschaltet haben (sonst 403 not_shared —
    spiegelt friends-today/Leaderboard, die Opt-out-Profile ebenfalls
    ausblenden). Compute + 60-s-Memo sind EXAKT die des eigenen Passports
    (_passport_stats_compute / _PASSPORT_STATS_CACHE, gekeyt auf den
    FREUND-Token → owner- und friend-Reads teilen sich den Cache-Eintrag)."""
    if not token:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    if not _request_bearer_matches(token):
        return jsonify({'ok': False, 'error': 'unauthorized'}), 401
    friend_raw = (request.args.get('friend') or '').strip()
    if not friend_raw:
        return jsonify({'ok': False, 'error': 'missing_friend'}), 400
    rng = (request.args.get('range') or 'all').strip()
    if not re.match(r'^(all|\d{4}|\d{4}-\d{2})$', rng):
        return jsonify({'ok': False, 'error': 'bad_range'}), 400
    friend = _resolve_friend_token(token, friend_raw)
    me = _friends_load(token)
    if friend not in (me.get('friends') or []):
        return jsonify({'ok': False, 'shared': False, 'error': 'not_friends'}), 403
    prof = _profile_load(friend) or {}
    if prof.get('share_roster') is False:
        return jsonify({'ok': False, 'shared': False, 'error': 'not_shared'}), 403
    now = time.time()
    key = (friend, rng)
    cached = _PASSPORT_STATS_CACHE.get(key)
    if cached and cached[0] > now:
        return jsonify(cached[1])
    try:
        payload = _passport_stats_compute(friend, rng)
    except Exception as e:
        print(f'[friend-passport] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500
    _PASSPORT_STATS_CACHE[key] = (now + 60, payload)
    _cache_soft_cap(_PASSPORT_STATS_CACHE)
    return jsonify(payload)


@app.route('/api/community/benchmark/<token>', methods=['GET'])
def community_benchmark(token):
    """AeroX-weiter Vergleich (#111): die YTD-Kernmetriken des Users gegen den
    Durchschnitt ALLER AeroX-User (anonymisiert, Supabase-Aggregat). Ehrlicher
    Empty-State wenn der User noch keine Daten hat (has_data=False) oder zu wenige
    Vergleichs-User existieren (community=null, < 3 Profile).
    """
    payload = _trip_stats_compute(token)
    you = payload.get('ytd') or {}
    has_data = payload.get('has_data', False)
    # Fallback auf die PERSISTENTEN iCal-Briefings, wenn keine (oder leere) Tax-
    # Auswertung vorliegt — sonst zählt ein nur-iCal-User nie mit (#111).
    if not has_data or float(you.get('hours_flown') or 0) == 0:
        ical_you = _community_metrics_from_ical(token)
        if ical_you:
            you = ical_you
            has_data = True
    # Eigene Werte gleich mit-persistieren — hält das Aggregat frisch.
    if has_data:
        _community_upsert_stats(token, you)

    community = None
    percentile_hours = None
    if sb is not None:
        try:
            def _do():
                return sb.table('community_stats').select(
                    'hours_flown,flights,countries,tour_days,distance_km').execute()
            res, timed_out = _supabase_execute_with_timeout('community_select', _do, timeout_s=5)
            rows = (res.data if res and hasattr(res, 'data') else []) or []
            n = len(rows)
            if n >= 3:  # erst ab 3 Profilen ein ehrlicher Durchschnitt
                def _avg(key):
                    vals = [float(r.get(key) or 0) for r in rows]
                    return (sum(vals) / len(vals)) if vals else 0.0
                community = {
                    'sample_size': n,
                    'avg_hours_flown': round(_avg('hours_flown'), 1),
                    'avg_flights': round(_avg('flights')),
                    'avg_countries': round(_avg('countries')),
                    'avg_tour_days': round(_avg('tour_days')),
                    'avg_distance_km': round(_avg('distance_km')),
                }
                my_hours = float(you.get('hours_flown') or 0)
                below = sum(1 for r in rows if float(r.get('hours_flown') or 0) < my_hours)
                percentile_hours = round(100.0 * below / n)
        except Exception as e:
            app.logger.warning(f'[community] benchmark-fail: {str(e)[:120]}')

    return jsonify({
        'token': token,
        'has_data': has_data,
        'you': you,
        'community': community,
        'percentile_hours': percentile_hours,
    })


_FLIGHT_TIMES_CACHE = {}

@app.route('/api/flight-times/<flightno>', methods=['GET'])
def flight_times(flightno):
    """Echte geplante/aktuelle Ab-/Ankunftszeiten einer Flugnummer (#139) via
    AeroDataBox (RapidAPI). Key NUR server-seitig (Cloud-Run-Env AERODATABOX_KEY),
    Antwort 10 min gecacht → ein Key, geteilt, bleibt im Free-Limit (10k User)."""
    import time
    import requests as _requests
    from blueprints.aerox_data_blueprint import _paid_budget_ok, _paid_budget_inc
    key = os.environ.get('AERODATABOX_KEY', '')
    fn = (flightno or '').strip().upper().replace(' ', '')
    date = request.args.get('date') or datetime.utcnow().strftime('%Y-%m-%d')
    require_board = (request.args.get('require_board') or '').lower() in (
        '1', 'true', 'yes')
    ckey = f"{fn}|{date}|board:{int(require_board)}"
    now = time.time()
    if (hit := _FLIGHT_TIMES_CACHE.get(ckey)) and hit[0] > now:
        return jsonify(hit[1])

    def _cache(out, ttl):
        _FLIGHT_TIMES_CACHE[ckey] = (now + ttl, out)
        if len(_FLIGHT_TIMES_CACHE) > 800:
            for k in list(_FLIGHT_TIMES_CACHE.keys())[:400]:
                _FLIGHT_TIMES_CACHE.pop(k, None)
        return jsonify(out)

    # ── FREE-FIRST (Increment 2, Owner 2026-07-06): dieselbe EINE Quelle wie
    #    Status/Suche — der zentrale Dual-Side-Merge (eigene Beobachtungs-DB
    #    airport_delay_obs + freie Live-Boards, free_only=True). KEIN AeroDataBox-
    #    Spend pro User-Request; ADB unten nur als budget-gedeckelter Notnagel.
    #    Gleiche JSON-Shape (departure/arrival), nur die Quelle wechselt. ──
    free_out = None
    try:
        m = _flight_obs_merged(fn, date=date, free_only=True)
    except Exception:
        m = None
    if m and (m.get('dep_iata') or m.get('arr_iata')):
        def _side(iata_k, name_k, sched_k, est_k, term_k, gate_k):
            return {'iata': m.get(iata_k), 'name': m.get(name_k), 'city': None,
                    'scheduled': m.get(sched_k), 'revised': m.get(est_k),
                    'terminal': m.get(term_k), 'gate': m.get(gate_k)}
        # Museums-Tail-Wächter (Regressions-Sweep 2026-07-12 #11): auch dieser
        # Board-Ausgang lieferte die Fraport-Altlast (LH781→D-ABTL) ungefiltert.
        # Typ fällt mit — er stammt aus derselben Museums-Row.
        _reg_ft = m.get('reg')
        _type_ft = m.get('aircraft')
        if _reg_ft and not _tail_recently_active(_reg_ft):
            _reg_ft = None
            _type_ft = None
        out = {'ok': True, 'flight': fn,
               'airline': m.get('airline'), 'aircraft': _type_ft,
               'reg': _reg_ft,
               'status': ('cancelled' if m.get('cancelled') else m.get('status')),
               'departure': _side('dep_iata', 'origin_name', 'sched_dep',
                                  'esti_dep', 'terminal_dep', 'gate_dep'),
               'arrival': _side('arr_iata', 'dest_name', 'sched_arr',
                                'esti_arr', 'terminal_arr', 'gate_arr'),
               'source': 'aerox_obs_merged'}
        has_board = any((side or {}).get(k) for side in (
            out.get('departure'), out.get('arrival')) for k in ('gate', 'terminal'))
        if not require_board or has_board:
            return _cache(out, 300)
        # Route/Zeiten sind schon kostenlos vorhanden, aber Gate/Terminal fehlen.
        # Nur der ausdrückliche Bordkarten-Aufruf darf deshalb bis zum
        # budget-gegateten Detail-Fallback weiterlaufen. Bei dessen Ausfall bleibt
        # diese kostenlose Teilantwort erhalten.
        free_out = out

    # ── BEZAHLT (letzter Notnagel): AeroDataBox NUR mit Key UND Tages-Budget. ──
    if not key:
        return _cache(free_out or {'ok': False, 'error': 'not_configured'}, 120)
    if not _paid_budget_ok():
        return _cache(free_out or {'ok': False, 'error': 'budget_exhausted'}, 120)

    url = f"https://aerodatabox.p.rapidapi.com/flights/number/{fn}/{date}"
    try:
        r = _requests.get(url, headers={'x-rapidapi-key': key,
                                        'x-rapidapi-host': 'aerodatabox.p.rapidapi.com'}, timeout=8)
        try:
            _paid_budget_inc(units=2)   # AeroDataBox flights/number = Tier 2 (2 Units)
        except Exception:
            pass
        if r.status_code != 200:
            return _cache(free_out or {'ok': False, 'error': f'http_{r.status_code}'}, 300)
        flights = r.json() if isinstance(r.json(), list) else []
        if not flights:
            return _cache(free_out or {'ok': False, 'error': 'no_flight'}, 600)
        f = flights[0]
        def ap(side):
            a = (f.get(side) or {}); air = (a.get('airport') or {})
            return {
                'iata': air.get('iata'),
                'name': air.get('name') or air.get('shortName'),
                'city': air.get('municipalityName'),
                'scheduled': (a.get('scheduledTime') or {}).get('local'),
                'revised': (a.get('revisedTime') or {}).get('local')
                           or (a.get('predictedTime') or {}).get('local'),
                'terminal': a.get('terminal'),
                'gate': a.get('gate'),   # FIX: Gate wurde nie extrahiert (Google-Panel-Feld)
            }
        out = {'ok': True, 'flight': fn,
               'airline': (f.get('airline') or {}).get('name'),
               'aircraft': (f.get('aircraft') or {}).get('model'),
               'reg': (f.get('aircraft') or {}).get('reg'),
               'status': f.get('status'),
               'departure': ap('departure'), 'arrival': ap('arrival')}
        return _cache(out, 600)
    except Exception as e:
        app.logger.warning(f'[flighttimes] {str(e)[:120]}')
        return _cache(free_out or {'ok': False, 'error': 'exception'}, 120)


def _age_from_built_date(bd):
    """YYYY-MM-DD → {'age_years': X, 'age_months': Y} (tagesgenau, kalendrisch).
    Leeres Dict bei unparsbar. Gleiche Logik wie /api/ax/aircraft, damit das Radar
    überall ein konsistentes „X Jahre Y Monate"-Alter zeigt (User-Wunsch
    Tag/Monat/Jahr)."""
    try:
        import datetime as _d
        d = _d.date.fromisoformat(str(bd)[:10])
        t = _d.date.today()
        months = (t.year - d.year) * 12 + (t.month - d.month) - (1 if t.day < d.day else 0)
        if 0 <= months < 1200:
            return {'age_years': months // 12, 'age_months': months % 12}
    except Exception:
        pass
    return {}


@app.route('/api/aircraft-age/<hex>', methods=['GET'])
def aircraft_age(hex):
    """AeroX-eigene, WACHSENDE Flieger-Alters-DB (#127, User-Idee): einmal pro Hex
    AeroDataBox abfragen (Baujahr aus rollout/firstFlight/delivery) und in Supabase
    `aircraft_age` CACHEN/TEILEN → über echte Nutzung baut AeroX eine globale
    Alters-DB auf, free-tier-schonend (ein Key, geteilter Cache). Tabelle einmalig:
        create table aircraft_age (hex text primary key, year int, reg text,
          type text, updated timestamptz);
    """
    h = (hex or '').strip().lower()
    if len(h) != 6:
        return jsonify({'ok': False})
    # 1) Geteilter Supabase-Cache (AeroX-DB).
    if sb is not None:
        try:
            def _do(): return sb.table('aircraft_age').select('*').eq('hex', h).limit(1).execute()
            res, _ = _supabase_execute_with_timeout('age_get', _do, timeout_s=4)
            rows = (res.data if res and hasattr(res, 'data') else []) or []
            if rows:
                r = rows[0]
                bd = r.get('built_date')
                out = {'ok': r.get('year') is not None, 'hex': h, 'year': r.get('year'),
                       'reg': r.get('reg'), 'type': r.get('type'), 'cached': True}
                # Tagesgenaues Baujahr (YYYY-MM-DD) + abgeleitetes Alter, falls
                # vorhanden (LH-Gruppe via AeroDataBox rollout/firstFlight/delivery).
                if bd:
                    out['built_date'] = bd
                    out.update(_age_from_built_date(bd))
                return jsonify(out)
        except Exception as e:
            app.logger.warning(f'[age] cache-get {str(e)[:100]}')
    # 2) AeroDataBox-Lookup (Baujahr).
    key = os.environ.get('AERODATABOX_KEY', '')
    if not key:
        return jsonify({'ok': False, 'error': 'not_configured'})
    try:
        import requests
        r = requests.get(f"https://aerodatabox.p.rapidapi.com/aircrafts/icao24/{h}",
                         headers={'x-rapidapi-key': key,
                                  'x-rapidapi-host': 'aerodatabox.p.rapidapi.com'}, timeout=8)
        if r.status_code != 200:
            return jsonify({'ok': False, 'error': f'http_{r.status_code}'})
        d = r.json() or {}
        year = None
        built_date = None
        # AeroDataBox liefert volle ISO-Daten (YYYY-MM-DD). Reihenfolge = best:
        # rollout > firstFlight > delivery. Wir behalten das ERSTE volle Datum als
        # tagesgenaues Baujahr (User: „LH-Flugzeuge brauchen Baujahr Tag/Monat/Jahr"),
        # damit die ganze LH-Gruppe — die in der gebackenen OpenSky-DB KEIN built hat —
        # ein echtes Datum bekommt, nicht nur das Jahr.
        for f in ('rolloutDate', 'firstFlightDate', 'deliveryDate'):
            v = d.get(f)
            if isinstance(v, str) and len(v) >= 4 and v[:4].isdigit():
                y = int(v[:4])
                if 1950 <= y <= 2026:
                    year = y
                    if len(v) >= 10 and v[4] == '-' and v[7] == '-':
                        built_date = v[:10]
                    break
        reg = d.get('reg'); typ = d.get('typeName')
        # 3) In die AeroX-DB schreiben (auch ohne Jahr → kein Re-Fetch-Sturm).
        #    built_date (tagesgenau) mitschreiben, sofern AeroDataBox es lieferte.
        if sb is not None:
            try:
                row = {'hex': h, 'year': year, 'built_date': built_date,
                       'reg': reg, 'type': typ, 'updated': datetime.utcnow().isoformat()}
                def _up(): return sb.table('aircraft_age').upsert(row, on_conflict='hex').execute()
                _supabase_execute_with_timeout('age_put', _up, timeout_s=4)
            except Exception as e:
                app.logger.warning(f'[age] cache-put {str(e)[:100]}')
        out = {'ok': year is not None, 'hex': h, 'year': year, 'reg': reg, 'type': typ}
        if built_date:
            out['built_date'] = built_date
            out.update(_age_from_built_date(built_date))
        return jsonify(out)
    except Exception as e:
        app.logger.warning(f'[age] {str(e)[:120]}')
        return jsonify({'ok': False, 'error': 'exception'})


@app.route('/api/user/friend-compare/<token>/<friend_token>', methods=['GET'])
def friend_compare(token, friend_token):
    """Side-by-side Vergleich der KPIs zwischen User und Friend.
    Beide müssen eine Auswertung gemacht haben.
    """
    def _summary(tok):
        sess = _store.get(tok) or {}
        rd = sess.get('result_data') or {}
        tage = rd.get('_tage_detail') or []
        if not tage:
            # _store ist in-memory/per-Instanz → persistenter Snapshot-Fallback.
            tage = (_roster_snapshot_read(tok) or {}).get('tage') or []
        from collections import Counter
        klass_ct = Counter()
        layover_ct = Counter()
        for t in tage:
            if not isinstance(t, dict): continue
            klass_ct[(t.get('klass') or '').upper()] += 1
            place = ((t.get('reader_facts') or {}).get('layover_ort') or '').upper().strip()
            if place and len(place) == 3 and place != 'FRA':
                layover_ct[place] += 1
        return {
            'tour_days': sum(klass_ct[k] for k in ('Z72', 'Z73', 'Z74', 'Z76')),
            'hotel_nights': int(rd.get('hotel_naechte', 0) or 0),
            'fahr_tage': int(rd.get('fahr_tage', 0) or 0),
            'arbeitstage': int(rd.get('arbeitstage', 0) or 0),
            'z76_eur': float(rd.get('vma_aus', 0) or 0),
            'gesamt': float(rd.get('gesamt', 0) or 0),
            'top_layovers': [{'place': k, 'count': v} for k, v in layover_ct.most_common(5)],
        }

    # Friend muss tatsächlich Freund sein
    friends = (_friends_load(token).get('friends') or [])
    if friend_token not in friends:
        return jsonify({'ok': False, 'error': 'not_friends'}), 403

    me = _summary(token)
    them = _summary(friend_token)
    # Friend-Profil
    ppath = _user_profile_path(friend_token)
    friend_prof = {}
    try:
        with open(ppath) as f:
            friend_prof = (json.load(f) or {}).get('profile', {})
    except Exception:
        pass
    return jsonify({
        'me': me,
        'friend': them,
        'friend_name': friend_prof.get('name', friend_token[:8] + '…'),
    })


@app.route('/api/user/ical/<token>', methods=['GET'])
def get_user_ical(token):
    """Generiert iCal-Datei der Touren aus jüngster Auswertung.
    Kann in iPhone-Kalender importiert werden.
    """
    session = _store.get(token) or {}
    rd = session.get('result_data') or {}
    tage = rd.get('_tage_detail') or []
    if not tage:
        # _store ist in-memory/per-Instanz → persistenter Snapshot-Fallback.
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    # Group into tours
    lines = [
        'BEGIN:VCALENDAR',
        'VERSION:2.0',
        'PRODID:-//AeroTax//Mobile//DE',
        'CALSCALE:GREGORIAN',
        'METHOD:PUBLISH',
        f'X-WR-CALNAME:AeroTax Touren {rd.get("year", "")}',
        'X-WR-TIMEZONE:Europe/Berlin',
    ]
    current = None
    for t in tage:
        if not isinstance(t, dict): continue
        klass = (t.get('klass') or '').upper()
        datum = t.get('datum', '')
        rf = t.get('reader_facts') or {}
        if klass in ('Z72', 'Z73', 'Z74', 'Z76'):
            if not current:
                current = {'start': datum, 'end': datum, 'klass': klass,
                          'places': [], 'markers': []}
            else:
                current['end'] = datum
            place = (rf.get('layover_ort') or '').upper().strip()
            if place and place not in current['places']:
                current['places'].append(place)
            mk = rf.get('marker_raw') or t.get('marker') or ''
            if mk and mk not in current['markers']:
                current['markers'].append(mk)
        else:
            if current:
                _ics_emit_tour(lines, current)
                current = None
    if current:
        _ics_emit_tour(lines, current)
    lines.append('END:VCALENDAR')
    body = '\r\n'.join(lines) + '\r\n'
    response = app.response_class(body, mimetype='text/calendar')
    response.headers['Content-Disposition'] = f'attachment; filename="aerotax_touren_{rd.get("year", "")}.ics"'
    return response


@app.route('/api/user/logbook-pdf/<token>', methods=['GET'])
def get_user_logbook_pdf(token):
    """Generiert ein einfaches Logbuch-PDF aus dem User-State.
    Achtung: Duty-Zeit (Briefing→Onblock), nicht echte Block-Time.
    Nicht AMC1-FCL.050-konform — explizit so beschriftet.
    """
    session = _store.get(token) or {}
    rd = session.get('result_data') or {}
    tage = rd.get('_tage_detail') or []
    if not tage:
        # _store ist in-memory/per-Instanz → persistenter Snapshot-Fallback.
        tage = (_roster_snapshot_read(token) or {}).get('tage') or []
    pname = ''
    ppath = _user_profile_path(token)
    try:
        with open(ppath) as f:
            pname = ((json.load(f) or {}).get('profile') or {}).get('name', '')
    except Exception:
        pass

    flight_days = []
    for t in tage:
        if not isinstance(t, dict): continue
        if (t.get('klass') or '').upper() not in ('Z72', 'Z73', 'Z74', 'Z76'): continue
        rf = t.get('reader_facts') or {}
        if not (rf.get('start_time') or rf.get('end_time')): continue
        flight_days.append(t)

    from io import BytesIO
    buf = BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=1.5*cm, rightMargin=1.5*cm,
                            topMargin=1.5*cm, bottomMargin=1.5*cm)
    styles = getSampleStyleSheet()
    elems = []
    title_style = ParagraphStyle('title', parent=styles['Heading1'],
                                 fontSize=18, textColor=HexColor('#0a0e1a'))
    sub_style = ParagraphStyle('sub', parent=styles['Normal'],
                               fontSize=10, textColor=HexColor('#666666'))
    cell_style = ParagraphStyle('cell', parent=styles['Normal'],
                                fontSize=9, leading=11)

    elems.append(Paragraph(f'Logbuch · {rd.get("year", "")}', title_style))
    if pname:
        elems.append(Paragraph(pname, sub_style))
    elems.append(Paragraph('Erstellt mit AeroTax · '
        + datetime.now().strftime('%d.%m.%Y'), sub_style))
    elems.append(Spacer(1, 0.4*cm))
    elems.append(Paragraph(
        '<b>Hinweis:</b> Duty-Zeit (Briefing → Onblock), nicht AMC1-FCL.050-konform. '
        'Für offizielle Logbuch-Submissions sind tatsächliche Off-/On-Block-Zeiten erforderlich.',
        sub_style))
    elems.append(Spacer(1, 0.4*cm))

    header = ['Datum', 'Routing', 'Briefing', 'Onblock', 'Duty', 'Klass.']
    data = [header]
    total_min = 0
    for t in flight_days:
        rf = t.get('reader_facts') or {}
        s = rf.get('start_time') or ''
        e = rf.get('end_time') or ''
        duty = ''
        try:
            if s and e:
                sh, sm = [int(x) for x in s.split(':')]
                eh, em = [int(x) for x in e.split(':')]
                s_min = sh * 60 + sm
                e_min = eh * 60 + em
                d_min = (e_min - s_min) if e_min > s_min else (24*60 - s_min) + e_min
                duty = f'{d_min // 60}:{d_min % 60:02d}'
                total_min += d_min
        except Exception:
            pass
        data.append([
            t.get('datum', ''),
            (t.get('routing') or '')[:18],
            s, e, duty, t.get('klass', ''),
        ])
    if len(data) == 1:
        elems.append(Paragraph('Keine Flugtage mit Zeitangaben verfügbar.', cell_style))
    else:
        col_widths = [2.4*cm, 4.5*cm, 2.2*cm, 2.2*cm, 1.8*cm, 2.0*cm]
        tbl = Table(data, colWidths=col_widths, repeatRows=1)
        tbl.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), HexColor('#0a0e1a')),
            ('TEXTCOLOR', (0, 0), (-1, 0), white),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, -1), 8),
            ('ROWBACKGROUNDS', (0, 1), (-1, -1), [white, HexColor('#f5f5f5')]),
            ('BOX', (0, 0), (-1, -1), 0.5, HexColor('#cccccc')),
            ('INNERGRID', (0, 0), (-1, -1), 0.25, HexColor('#dddddd')),
            ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
            ('LEFTPADDING', (0, 0), (-1, -1), 4),
            ('RIGHTPADDING', (0, 0), (-1, -1), 4),
        ]))
        elems.append(tbl)
        elems.append(Spacer(1, 0.4*cm))
        elems.append(Paragraph(
            f'<b>Summe Duty-Zeit:</b> {total_min // 60}:{total_min % 60:02d} '
            f'({len(flight_days)} Flugtage)',
            styles['Normal']))

    doc.build(elems)
    pdf_bytes = buf.getvalue()
    # ETag-Cache (H16): PDF wird aus _tage_detail deterministisch generiert —
    # solange sich der Inhalt nicht ändert, identisches Output. ETag basiert auf
    # SHA-256 der PDF-Bytes. Bei If-None-Match-Match → 304 ohne Body.
    import hashlib
    etag = '"' + hashlib.sha256(pdf_bytes).hexdigest()[:32] + '"'
    if_match = request.headers.get('If-None-Match', '')
    if if_match == etag:
        return ('', 304, {'ETag': etag, 'Cache-Control': 'private, max-age=300'})
    response = app.response_class(pdf_bytes, mimetype='application/pdf')
    response.headers['Content-Disposition'] = f'attachment; filename="aerotax_logbuch_{rd.get("year", "")}.pdf"'
    response.headers['ETag'] = etag
    response.headers['Cache-Control'] = 'private, max-age=300'
    return response


@app.route('/api/user/calendar-pdf/<token>', methods=['GET'])
def get_user_calendar_pdf(token):
    """Generiert einen druckbaren Monatskalender.
    Query: ?month=YYYY-MM (Default: aktueller Monat).
    Zeigt pro Tag Klassifikation + Routing-Kürzel.
    """
    from datetime import date, timedelta
    import calendar as _cal
    from io import BytesIO

    month_q = (request.args.get('month') or '').strip()
    try:
        y, m = [int(x) for x in month_q.split('-')]
    except Exception:
        today = date.today()
        y, m = today.year, today.month

    session = _store.get(token) or {}
    rd = session.get('result_data') or {}
    tage_by_date = {}
    for t in (rd.get('_tage_detail') or []):
        if isinstance(t, dict) and t.get('datum'):
            tage_by_date[t['datum']] = t

    # FALLBACK (Root-Cause „Monatsplan leer", 2026-06-23): Die meisten User haben
    # KEINE volle Steuer-Auswertung laufen lassen (kein `_tage_detail`), aber sie
    # haben ihren Dienstplan via iCal/EKEventStore importiert. Dann ist die Tabelle
    # leer, obwohl 44 Briefings vorliegen. Für jeden Tag ohne `_tage_detail`-Eintrag
    # synthetisieren wir aus dem Briefing-Store (gleicher Merge wie `get_briefings`)
    # ein {klass, routing}-Surrogat, damit die Tabelle die echten Diensttage zeigt.
    try:
        _briefings_for_pdf = dict(_manual_briefings_load(token) or {})
        _ical_for_pdf = _ical_briefings_load(token) or {}
        for _bk, _bv in (_ical_for_pdf or {}).items():
            if not isinstance(_bv, dict):
                continue
            _merged = dict(_briefings_for_pdf.get(_bk) or {})
            for _fld in ('ical_summary', 'ical_location', 'ical_start_iso',
                         'ical_end_iso', 'legs'):
                if _bv.get(_fld) is not None:
                    _merged[_fld] = _bv.get(_fld)
            for _fk, _fv in _bv.items():
                _merged.setdefault(_fk, _fv)
            _briefings_for_pdf[_bk] = _merged
    except Exception:
        _briefings_for_pdf = {}

    # Audit-Fix 2026-07-06: Homebase war hier als 'FRA' HARDCODIERT — für
    # MUC/BER-Crews wurde FRA als „Ziel" gedruckt bzw. die eigene Homebase
    # als Routing (CLAUDE.md: „FRA wird nicht hardcoded"). Jetzt Profil-Homebase.
    try:
        _pdf_hb = str(((_profile_load(token) or {}).get('profile') or {})
                      .get('homebase') or '').strip().upper()
    except Exception:
        _pdf_hb = ''
    if len(_pdf_hb) != 3:
        _pdf_hb = 'FRA'

    def _briefing_to_klass_routing(bv):
        """Leitet (klass_label, routing_kuerzel) aus einem Briefing-Item ab.
        Heuristik auf `ical_summary` + `legs` — KEINE Steuerklassifikation, nur
        ein menschenlesbares Label für den gedruckten Monatsplan."""
        summary = (bv.get('ical_summary') or '').strip()
        low = summary.lower()
        legs = bv.get('legs') if isinstance(bv.get('legs'), list) else []
        # Routing-Kürzel: erstes Nicht-Homebase-Ziel aus den Legs, sonst aus dem Summary.
        routing = ''
        for lg in legs:
            if not isinstance(lg, dict):
                continue
            to = (lg.get('to') or '').strip().upper()
            if len(to) == 3 and to != _pdf_hb:
                routing = to
                break
        if not routing:
            import re as _re2
            # Summary-Form „FRA-BUD" / „BUD-FRA" → erstes 3-Letter ≠ Homebase
            for tok in _re2.findall(r'\b([A-Z]{3})\b', summary):
                if tok != _pdf_hb:
                    routing = tok
                    break
        # Label-Mapping (Anzeigeklassen, decken sich grob mit KLASS_BG-Keys).
        if 'off day' in low or low == 'off' or 'rest day' in low:
            return 'Frei', ''
        if 'absence' in low or 'urlaub' in low or 'vacation' in low or 'leave' in low:
            return 'Urlaub', ''
        if 'office' in low or 'training' in low or 'schulung' in low or 'ground' in low:
            return 'Office', ''
        if 'standby' in low or 'sby' in low or 'reserve' in low or 'bereitschaft' in low:
            return 'Standby', ''
        if 'layover' in low or legs or '-' in summary.replace(' ', ''):
            # Aktiver Flugdiensttag / Layover → Z76 (Auslandstour) als Default-Farbe.
            return 'Z76', routing
        if summary:
            return 'Duty', routing
        return '', ''

    for _bk, _bv in (_briefings_for_pdf or {}).items():
        if _bk in tage_by_date:
            continue  # echte Auswertung gewinnt
        if not isinstance(_bv, dict):
            continue
        _klass, _routing = _briefing_to_klass_routing(_bv)
        if not _klass:
            continue
        tage_by_date[_bk] = {
            'datum': _bk,
            'klass': _klass,
            'routing': _routing,
        }

    KLASS_BG = {
        'Z76': HexColor('#fde68a'),
        'Z74': HexColor('#fef3c7'),
        'Z73': HexColor('#fef9c3'),
        'Z72': HexColor('#fefce8'),
        'Office': HexColor('#dbeafe'),
        'Standby': HexColor('#e9d5ff'),
        'Frei': HexColor('#dcfce7'),
        'Urlaub': HexColor('#bbf7d0'),
    }

    buf = BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=1*cm, rightMargin=1*cm,
                            topMargin=1*cm, bottomMargin=1*cm)
    styles = getSampleStyleSheet()
    elems = []
    month_name = ['', 'Januar', 'Februar', 'März', 'April', 'Mai', 'Juni',
                  'Juli', 'August', 'September', 'Oktober', 'November', 'Dezember'][m]
    elems.append(Paragraph(f'<b>{month_name} {y}</b> · AeroTax Monatsplan',
                            ParagraphStyle('t', parent=styles['Heading1'],
                                           fontSize=16, alignment=TA_CENTER,
                                           textColor=HexColor('#0a0e1a'))))
    elems.append(Spacer(1, 0.4*cm))

    weekdays = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So']
    cal = _cal.Calendar(firstweekday=0)
    weeks = cal.monthdatescalendar(y, m)

    grid = [weekdays]
    grid_bg = [[HexColor('#0a0e1a')] * 7]
    for week in weeks:
        row = []
        bg_row = []
        for d in week:
            ds = d.isoformat()
            entry = tage_by_date.get(ds)
            in_month = (d.month == m)
            if not in_month:
                row.append('')
                bg_row.append(white)
                continue
            line1 = str(d.day)
            line2 = ''
            line3 = ''
            if entry:
                line2 = entry.get('klass', '') or ''
                routing = (entry.get('routing') or '').strip()
                if routing and routing != '-':
                    parts = [p for p in routing.split('-') if p and len(p) == 3 and p != 'FRA']
                    if parts:
                        line3 = parts[0]
            row.append(f'<b>{line1}</b><br/><font size="7">{line2}</font><br/><font size="7" color="#666666">{line3}</font>')
            bg_row.append(KLASS_BG.get(line2, white) if in_month else white)
        grid.append(row)
        grid_bg.append(bg_row)

    cell_style = ParagraphStyle('c', parent=styles['Normal'], fontSize=9, leading=12)
    grid_paras = []
    for row in grid:
        grid_paras.append([Paragraph(c, cell_style) if c else '' for c in row])

    col_w = (A4[0] - 2*cm) / 7
    tbl = Table(grid_paras, colWidths=[col_w]*7, rowHeights=[0.8*cm] + [2.2*cm]*len(weeks))
    cell_styles = [
        ('BACKGROUND', (0, 0), (-1, 0), HexColor('#0a0e1a')),
        ('TEXTCOLOR', (0, 0), (-1, 0), white),
        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
        ('FONTSIZE', (0, 0), (-1, 0), 10),
        ('ALIGN', (0, 0), (-1, 0), 'CENTER'),
        ('VALIGN', (0, 0), (-1, 0), 'MIDDLE'),
        ('VALIGN', (0, 1), (-1, -1), 'TOP'),
        ('BOX', (0, 0), (-1, -1), 0.5, HexColor('#cccccc')),
        ('INNERGRID', (0, 0), (-1, -1), 0.25, HexColor('#dddddd')),
        ('LEFTPADDING', (0, 1), (-1, -1), 4),
        ('TOPPADDING', (0, 1), (-1, -1), 4),
    ]
    for r_idx, row_bgs in enumerate(grid_bg[1:], start=1):
        for c_idx, bg in enumerate(row_bgs):
            if bg != white:
                cell_styles.append(('BACKGROUND', (c_idx, r_idx), (c_idx, r_idx), bg))
    tbl.setStyle(TableStyle(cell_styles))
    elems.append(tbl)
    elems.append(Spacer(1, 0.4*cm))
    elems.append(Paragraph(
        '<font size="8" color="#666666">Generiert mit AeroTax am '
        + datetime.now().strftime('%d.%m.%Y') + ' · '
        + 'Z76 Ausland · Z73/Z74 Inland · Office Schulung/Homebase</font>',
        styles['Normal']))

    doc.build(elems)
    pdf_bytes = buf.getvalue()
    response = app.response_class(pdf_bytes, mimetype='application/pdf')
    response.headers['Content-Disposition'] = f'attachment; filename="aerotax_kalender_{y}_{m:02d}.pdf"'
    return response


def _ics_emit_tour(lines, tour):
    """Hängt VEVENT für eine Tour an die ICS-Lines."""
    dt_start = tour['start'].replace('-', '')
    # End-Datum exklusiv: end+1
    try:
        from datetime import datetime as _dt, timedelta
        end_d = _dt.strptime(tour['end'], '%Y-%m-%d').date() + timedelta(days=1)
        dt_end = end_d.strftime('%Y%m%d')
    except Exception:
        dt_end = tour['end'].replace('-', '')
    places = ', '.join(tour['places']) or 'Tour'
    summary = f"{places}"
    uid = f"{tour['start']}-{places.replace(' ','').replace(',','-')}@aerotax"
    lines.extend([
        'BEGIN:VEVENT',
        f'UID:{uid}',
        f'DTSTAMP:{datetime.utcnow().strftime("%Y%m%dT%H%M%SZ")}',
        f'DTSTART;VALUE=DATE:{dt_start}',
        f'DTEND;VALUE=DATE:{dt_end}',
        f'SUMMARY:{summary}',
        f'DESCRIPTION:AeroTax-Tour. Klassifikation: {tour["klass"]}. Marker: {", ".join(tour["markers"][:3])}',
        'END:VEVENT',
    ])


@app.route('/api/user/push-token/<token>', methods=['POST'])
def register_push_token(token):
    """Registriert einen Push-Token (Expo *oder* APNs) für diesen User.

    Backwards-Compat: Akzeptiert sowohl `push_token` (Expo-Legacy, Web-Clients)
    als auch `apns_token` (native iOS, R47). Beide werden im selben File
    persistiert — `_send_push_notification` bevorzugt APNs wenn beides da ist.
    """
    body = request.get_json(silent=True) or {}
    expo_token = (body.get('push_token') or '').strip()
    apns_token = (body.get('apns_token') or '').strip()
    if not expo_token and not apns_token:
        return jsonify({'ok': False, 'error': 'missing push_token or apns_token'}), 400
    if not token:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    existing = _push_load(token) or {}
    merged = {
        'token': token,
        'push_token': expo_token or existing.get('push_token') or '',
        'apns_token': apns_token or existing.get('apns_token') or '',
        'platform': body.get('platform') or existing.get('platform') or ('ios' if apns_token else 'expo'),
        'bundle_id': body.get('bundle_id') or existing.get('bundle_id') or 'aerotax.AeroTax',
        'device_id': (body.get('device_id')
                      or (existing.get('device_id')
                          if apns_token and apns_token == existing.get('apns_token')
                          else '') or ''),
        'registered_at': datetime.now().isoformat(),
        'registered_via': 'legacy_path',
    }
    # Prefs + gelerntes apns_env überleben die Re-Registrierung (Save ersetzt
    # die metadata-jsonb komplett). apns_env nur bei UNVERÄNDERTEM Device-Token
    # behalten — neues Token = evtl. anderer Build/Umgebung → neu lernen.
    if isinstance(existing.get('prefs'), dict):
        merged['prefs'] = existing.get('prefs')
    if merged['apns_token'] and merged['apns_token'] == (existing.get('apns_token') or '') \
            and existing.get('apns_env'):
        merged['apns_env'] = existing.get('apns_env')
    # Security ordering matters during an account switch: first atomically
    # rebind the globally unique APNs installation, then update the one-row
    # legacy compatibility store. Saving legacy first could leave the old
    # account's durable installation active when the RPC is briefly down.
    unregister_token = _secrets.token_urlsafe(32)
    installation_id = (_push_installation_register(
        token, merged, unregister_token=unregister_token)
                       if merged.get('apns_token') else None)
    if (merged.get('apns_token') and SB_AVAILABLE and sb is not None
            and not installation_id):
        response = jsonify({'ok': False, 'error': 'push_registry_unavailable'})
        response.status_code = 503
        response.headers['Retry-After'] = '5'
        return response
    if not _push_save(token, merged):
        return jsonify({'ok': False, 'error': 'persist_failed'}), 500
    response = {'ok': True}
    if installation_id:
        response['installation_id'] = installation_id
        response['unregister_token'] = unregister_token
    return jsonify(response)


@app.route('/api/push/register-apns', methods=['POST'])
def register_push_apns():
    """Native iOS Push-Registration. Body: {token, apns_token, platform}.

    Eigener Endpoint (zusätzlich zum legacy `/api/user/push-token/<token>`), damit
    der iOS-Client einen klaren APNs-Pfad hat — der alte Endpoint bleibt aus
    Backwards-Compat-Gründen bestehen.
    """
    body = request.get_json(silent=True) or {}
    user_token = (body.get('token') or '').strip()
    apns_token = (body.get('apns_token') or '').strip()
    if not user_token or not apns_token:
        return jsonify({'ok': False, 'error': 'missing token or apns_token'}), 400
    # SECURITY (IDOR-Fix): Body-Token umgeht das Pfad-Binding-Gate → expliziter
    # Bearer-Match. Sonst könnte ein Angreifer das APNs-Device eines fremden Users
    # überschreiben (Push-Hijack: fremde DM-/Anfrage-Notifications abgreifen).
    if not _request_bearer_matches(user_token):
        return jsonify({'ok': False, 'error': 'token_binding_required'}), 401
    existing = _push_load(user_token) or {}
    merged = {
        'token': user_token,
        'push_token': existing.get('push_token') or '',  # Expo nicht überschreiben
        'apns_token': apns_token,
        'platform': body.get('platform', 'ios'),
        'bundle_id': body.get('bundle_id') or existing.get('bundle_id') or 'aerotax.AeroTax',
        'device_id': (body.get('device_id')
                      or (existing.get('device_id')
                          if apns_token == existing.get('apns_token') else '')
                      or ''),
        'registered_at': datetime.now().isoformat(),
        'registered_via': 'native_apns',
    }
    # Preference-Filter (2026-07-03): User-Prefs überleben eine Re-Registrierung
    # (der Save überschreibt die metadata-jsonb komplett — ohne Carry-over wären
    # die Einstellungen nach jedem App-Start weg).
    if isinstance(existing.get('prefs'), dict):
        merged['prefs'] = existing.get('prefs')
    # CLIENT-HINT gewinnt (2026-07-04, Tibor-Push-Ausfall): Die App WEISS ihre
    # APNs-Umgebung (Debug-Build=sandbox, TestFlight/AppStore=prod) und darf sie
    # mitschicken — zuverlässiger als jedes serverseitige Lernen, weil Sandbox-
    # APNs fremde Tokens teils mit 200 annimmt ohne zuzustellen.
    env_hint = (body.get('apns_env') or '').strip().lower()
    if env_hint in ('sandbox', 'prod'):
        merged['apns_env'] = env_hint
        merged['apns_env_source'] = 'client'
    # Sonst: gelerntes apns_env nur behalten, wenn das Device-Token UNVERÄNDERT
    # ist — ein NEUES Token (anderer Build/Reinstall) kann die Umgebung
    # gewechselt haben → neu lernen lassen.
    elif (existing.get('apns_token') or '') == apns_token and existing.get('apns_env'):
        merged['apns_env'] = existing.get('apns_env')
    # Rebind first. This prevents a failed registry RPC from leaving a newly
    # saved legacy token alongside the previous account's active installation.
    unregister_token = _secrets.token_urlsafe(32)
    installation_id = _push_installation_register(
        user_token, merged, unregister_token=unregister_token)
    if SB_AVAILABLE and sb is not None and not installation_id:
        # Do not claim durable registration when the installation RPC failed.
        # Old legacy state remains as a delivery fallback; client retries this
        # additive endpoint and account-switch binding is never silently lost.
        response = jsonify({'ok': False, 'error': 'push_registry_unavailable'})
        response.status_code = 503
        response.headers['Retry-After'] = '5'
        return response
    legacy_ok = _push_save(user_token, merged)
    if not legacy_ok:
        return jsonify({'ok': False, 'error': 'persist_failed'}), 500
    response = {'ok': True}
    if installation_id:
        response['installation_id'] = installation_id
        response['unregister_token'] = unregister_token
    return jsonify(response)


@app.route('/api/push/unregister-apns', methods=['POST'])
def unregister_push_apns():
    """Entfernt den Push-Token eines Geräts für diesen User. Body: {token}.

    Multi-Agent-Review 2026-06-10 (Welle A): Beim Logout blieb die APNs-Registrierung
    unter dem alten user_token bestehen → loggte sich auf demselben Gerät ein anderer
    Account ein, bekam er weiter Pushes (Roster/Chat) des VORIGEN Users (Cross-User-PII
    auf geteilten Geräten). iOS ruft das beim Logout best-effort auf.
    """
    body = request.get_json(silent=True) or {}
    raw_installation_id = body.get('installation_id')
    raw_unregister_token = body.get('unregister_token')
    installation_id = (raw_installation_id.strip()
                       if isinstance(raw_installation_id, str) else None)
    unregister_token = (raw_unregister_token.strip()
                        if isinstance(raw_unregister_token, str) else None)
    if installation_id and unregister_token:
        try:
            installation_id = str(uuid.UUID(installation_id))
        except (ValueError, TypeError, AttributeError):
            return jsonify({'ok': False,
                            'error': 'invalid_installation_id'}), 400
        capability_result = _push_installation_tombstone_by_capability(
            installation_id, unregister_token)
        if capability_result is None:
            response = jsonify({'ok': False, 'error': 'push_registry_unavailable'})
            response.status_code = 503
            response.headers['Retry-After'] = '5'
            return response
        if capability_result:
            return jsonify({'ok': True, 'tombstoned': 1,
                            'via': 'installation_capability'})
        return jsonify({'ok': False, 'error': 'invalid_unregister_capability'}), 401
    raw_user_token = body.get('token')
    user_token = (raw_user_token.strip()
                  if isinstance(raw_user_token, str) else '')
    if not user_token:
        return jsonify({'ok': False, 'error': 'missing token'}), 400
    bearer_matches = _request_bearer_matches(user_token)
    # SECURITY (Audit 2026-07-05): wie register-apns/prefs — Body-Token umgeht das
    # Pfad-Binding-Gate → expliziter Bearer-Match VOR jedem Registry-Zugriff.
    # Sonst könnte ein Angreifer mit beliebigem fremden user_token dessen
    # APNs-/Expo-Registrierung leeren (Push-Abschalt-DoS: Opfer bekommt still
    # keine DM-/Roster-Pushes mehr, bis die App sich neu registriert).
    if not bearer_matches:
        return jsonify({'ok': False, 'error': 'token_binding_required'}), 401
    existing = _push_load(user_token) or {}
    apns_token = (body.get('apns_token') or '').strip() or None
    bundle_id = (body.get('bundle_id') or '').strip() or None
    apns_env = (body.get('apns_env') or '').strip() or None
    tombstoned = _push_installation_tombstone(
        user_token, installation_id=installation_id, apns_token=apns_token,
        bundle_id=bundle_id, apns_env=apns_env, reason='logout')
    if SB_AVAILABLE and sb is not None and tombstoned is None:
        response = jsonify({'ok': False, 'error': 'push_registry_unavailable'})
        response.status_code = 503
        response.headers['Retry-After'] = '5'
        return response
    if not existing:
        return jsonify({'ok': True, 'noop': not bool(tombstoned),
                        'tombstoned': int(tombstoned or 0)})
    # apns/expo-Token leeren → _send_push_notification sendet nichts mehr an dieses
    # Gerät. Registry-Eintrag bleibt (kein neuer SB-Delete-Pfad nötig).
    has_specific_identity = bool(installation_id or apns_token or bundle_id or apns_env)
    legacy_matches = (not has_specific_identity
                      or (apns_token and apns_token == existing.get('apns_token'))
                      or (installation_id and installation_id == existing.get('installation_id')))
    cleared = dict(existing)
    if legacy_matches:
        cleared.update({'apns_token': '', 'push_token': '',
                        'unregistered_at': datetime.now().isoformat()})
    if _push_save(user_token, cleared):
        return jsonify({'ok': True, 'tombstoned': int(tombstoned or 0)})
    return jsonify({'ok': False, 'error': 'persist_failed'}), 500


@app.route('/api/push/prefs', methods=['POST'])
def set_push_prefs():
    """Server-seitige Push-Preferences. Body: {token, prefs: {dm: bool, …}}.

    Erlaubte Keys: dm, group_message, friend_request, friend_accepted,
    roster_change, community (_PUSH_PREF_KEYS) — unbekannte Keys werden
    ignoriert, Werte zu bool gecoerct. _send_push_notification unterdrückt
    Kategorien mit pref==False; fehlende prefs/keys → normal senden (fail-open).
    """
    body = request.get_json(silent=True) or {}
    user_token = (body.get('token') or '').strip()
    prefs_in = body.get('prefs')
    if not user_token or not isinstance(prefs_in, dict):
        return jsonify({'ok': False, 'error': 'missing token or prefs'}), 400
    # SECURITY (IDOR): wie register-apns — Body-Token umgeht das Pfad-Binding-
    # Gate → expliziter Bearer-Match. Sonst könnte ein Angreifer fremde
    # Push-Kategorien stummschalten (Notification-DoS) oder reaktivieren.
    if not _request_bearer_matches(user_token):
        return jsonify({'ok': False, 'error': 'token_binding_required'}), 401
    existing = _push_load(user_token) or {}
    old_prefs = existing.get('prefs')
    merged_prefs = dict(old_prefs) if isinstance(old_prefs, dict) else {}
    for k, v in prefs_in.items():
        if k in _PUSH_PREF_KEYS:
            merged_prefs[k] = bool(v)
    # WICHTIG: bestehende Registry-Felder (apns_token, push_token, bundle_id, …)
    # mitnehmen — _push_save persistiert das GANZE dict inkl. metadata-jsonb
    # (Metadata-Clobber-Gotcha, siehe Avatar-Persist-Bug).
    merged = {**existing, 'token': user_token, 'prefs': merged_prefs}
    if _push_save(user_token, merged):
        return jsonify({'ok': True, 'prefs': merged_prefs})
    return jsonify({'ok': False, 'error': 'persist_failed'}), 500


# ── APNs HTTP/2 Sender ───────────────────────────────────────────────────
# Konfig via env-vars:
#   APNS_AUTH_KEY      base64-encoded .p8 Datei (von Apple Developer Console)
#   APNS_KEY_ID        10-Zeichen Key-ID (z.B. "ABCD123456")
#   APNS_TEAM_ID       10-Zeichen Apple Team-ID
#   APNS_TOPIC         Bundle-ID (default "aerotax.AeroTax", per-Gerät via bundle_id)
#   APNS_USE_SANDBOX   "1" für api.sandbox.push.apple.com (Dev-Builds)
#
# Wenn APNS_AUTH_KEY nicht gesetzt ist → wird übersprungen (warning gelogged,
# kein Crash, keine Exception nach oben).

_APNS_JWT_CACHE = {'token': None, 'iat': 0}
_APNS_HTTP_CLIENT = None
import threading as _push_threading
_APNS_HTTP_CLIENT_LOCK = _push_threading.Lock()


def _apns_http_client():
    """One process-wide, thread-safe HTTP/2 connection pool for APNs."""
    global _APNS_HTTP_CLIENT
    if _APNS_HTTP_CLIENT is not None:
        return _APNS_HTTP_CLIENT
    with _APNS_HTTP_CLIENT_LOCK:
        if _APNS_HTTP_CLIENT is None:
            import httpx
            _APNS_HTTP_CLIENT = httpx.Client(http2=True, timeout=10.0)
    return _APNS_HTTP_CLIENT


def _apns_get_jwt():
    """Generiert ein ES256-JWT für APNs Token-Auth. Cached für 50 Minuten
    (Apple invalidiert Tokens nach 60 min, wir refreshen 10 min früher)."""
    import os, time
    now = int(time.time())
    cached = _APNS_JWT_CACHE.get('token')
    iat = _APNS_JWT_CACHE.get('iat', 0)
    if cached and (now - iat) < 50 * 60:
        return cached
    auth_key_b64 = os.environ.get('APNS_AUTH_KEY', '').strip()
    key_id = os.environ.get('APNS_KEY_ID', '').strip()
    team_id = os.environ.get('APNS_TEAM_ID', '').strip()
    if not (auth_key_b64 and key_id and team_id):
        return None
    try:
        import base64
        from cryptography.hazmat.primitives import serialization, hashes
        from cryptography.hazmat.primitives.asymmetric import ec
        from cryptography.hazmat.primitives.asymmetric.utils import decode_dss_signature
        pem = base64.b64decode(auth_key_b64)
        private_key = serialization.load_pem_private_key(pem, password=None)
        header = {'alg': 'ES256', 'kid': key_id, 'typ': 'JWT'}
        payload = {'iss': team_id, 'iat': now}

        def _b64url(b):
            return base64.urlsafe_b64encode(b).rstrip(b'=').decode('ascii')
        header_b64 = _b64url(json.dumps(header, separators=(',', ':')).encode())
        payload_b64 = _b64url(json.dumps(payload, separators=(',', ':')).encode())
        signing_input = f"{header_b64}.{payload_b64}".encode('ascii')
        der_sig = private_key.sign(signing_input, ec.ECDSA(hashes.SHA256()))
        r, s = decode_dss_signature(der_sig)
        # JOSE: raw R||S, 32 bytes each
        sig_raw = r.to_bytes(32, 'big') + s.to_bytes(32, 'big')
        jwt = f"{header_b64}.{payload_b64}.{_b64url(sig_raw)}"
        _APNS_JWT_CACHE['token'] = jwt
        _APNS_JWT_CACHE['iat'] = now
        return jwt
    except Exception as e:
        print(f"[APNS] JWT generation failed: {e}")
        return None


def _send_apns(apns_token, title, body, data=None, topic=None,
               thread_id=None, badge=None, use_sandbox=None,
               retry_env_planned=False, category=None):
    """Sendet eine Push-Notification via APNs HTTP/2.
    Returns (ok: bool, reason: str|None). `reason` = APNs-Fehler-reason
    (z.B. 'BadDeviceToken', 'Unregistered') — der Caller nutzt sie für
    Token-Hygiene (tote Device-Tokens aus der Registry löschen).

    Braucht `httpx[http2]` im Environment (HTTP/2 ist Pflicht — Apple lehnt
    HTTP/1.1 ab). Wenn httpx/h2 fehlt → return (False, …) mit warning.

    `topic` = APNs-Topic (= Bundle-ID des Ziel-Geräts). Caller übergibt die pro
    Gerät gespeicherte bundle_id; Fallback auf APNS_TOPIC-env, dann die korrekte
    App-Bundle-ID. (Vorher war der Default 'de.aerosteuer.aeris' — die App nutzt
    aber 'aerotax.AeroTax', sodass Apple JEDEN Push mit 400 BadTopic ablehnte.)

    `thread_id` gruppiert Pushes in Notification-Center (z.B. pro Chat-Channel),
    `badge` setzt die App-Icon-Zahl (None = unverändert lassen).
    `category` = aps.category (Notification-Action-Buttons): muss EXAKT einer in
    der App registrierten UNNotificationCategory entsprechen (iOS PushService.
    registerActionCategories, aktuell 'DUTY_CHANGE' → Annehmen/Ablehnen auf dem
    Lockscreen). None = keine Buttons (wie bisher).
    """
    import os
    jwt = _apns_get_jwt()
    if not jwt:
        return False, 'no_jwt'  # caller handles fallback / skip
    topic = (topic or os.environ.get('APNS_TOPIC') or 'aerotax.AeroTax').strip()
    # use_sandbox=None → env-Default; explizit True/False = per-Gerät-Override
    # (Debug-Builds haben SANDBOX-Tokens, TestFlight/App Store PROD-Tokens).
    if use_sandbox is None:
        use_sandbox = os.environ.get('APNS_USE_SANDBOX', '').strip() == '1'
    host = 'api.sandbox.push.apple.com' if use_sandbox else 'api.push.apple.com'
    aps = {'alert': {'title': title, 'body': body}, 'sound': 'default'}
    if category:
        aps['category'] = str(category)[:64]
    if thread_id:
        aps['thread-id'] = str(thread_id)[:128]
    if badge is not None:
        try:
            aps['badge'] = int(badge)
        except (TypeError, ValueError):
            pass
    payload = {'aps': aps}
    if data and isinstance(data, dict):
        for k, v in data.items():
            if k != 'aps':
                payload[k] = v
    try:
        client = _apns_http_client()
    except ImportError:
        print("[APNS] httpx not installed — add 'httpx[http2]' to requirements.txt")
        return False, 'no_httpx'
    try:
        resp = client.post(
            f"https://{host}/3/device/{apns_token}",
            headers={
                'authorization': f'bearer {jwt}',
                'apns-topic': topic,
                'apns-push-type': 'alert',
                'apns-priority': '10',
            },
            content=json.dumps(payload).encode('utf-8'),
        )
        if resp.status_code == 200:
            return True, None
        reason = None
        try:
            reason = (resp.json() or {}).get('reason')
        except Exception:
            pass
        # 410 Unregistered / 400 BadDeviceToken → Caller löscht den Token.
        # Alert-Hygiene (2026-07-06): Der Log-Metric-Alert `apns_send_failed`
        # matcht "[APNS] send failed". Ein Erstversuch in der falschen
        # Umgebung (Debug-Build = Sandbox-Token, prod antwortet
        # BadDeviceToken; sandbox darf per Design nie GELERNT werden, also
        # zahlt so ein Gerät den prod-Fehlversuch bei JEDEM Push) ist
        # ERWARTET und wird vom Caller sofort per Gegen-Umgebung geheilt →
        # der darf den Alert nicht triggern. Nur finale/echte Fehler
        # (beide Umgebungen tot, TooManyRequests, BadTopic, Cert/JWT …)
        # loggen weiterhin "send failed".
        if retry_env_planned and reason in (
                'Unregistered', 'BadDeviceToken', 'ExpiredToken'):
            print(f"[APNS] env probe rejected status={resp.status_code} "
                  f"env={'sandbox' if use_sandbox else 'prod'} "
                  f"reason={reason} (retrying other env)")
        else:
            print(f"[APNS] send failed status={resp.status_code} "
                  f"env={'sandbox' if use_sandbox else 'prod'} body={resp.text[:200]}")
        return False, reason or f'http_{resp.status_code}'
    except Exception as e:
        print(f"[APNS] transport error: {e}")
        return False, 'transport_error'


def _send_push_notification(token, title, body, data=None,
                            thread_id=None, badge=None, category=None,
                            _return_detail=False):
    """Fan out to every active installation, with one legacy Expo fallback.

    The public/legacy return value remains bool. The durable outbox asks for a
    small detailed result so preference/no-installation outcomes complete
    terminally while transport failures retry.
    """
    import os

    def _result(ok, terminal, reason, delivered=0, attempted=0):
        detail = {'ok': bool(ok), 'terminal': bool(terminal), 'reason': reason,
                  'delivered': delivered, 'attempted': attempted}
        return detail if _return_detail else bool(ok)

    if not token:
        return _result(False, True, 'missing_user')
    registrations, legacy = _push_delivery_registrations(token)

    # Preferences remain account-wide in the legacy compatibility row.
    prefs = (legacy or {}).get('prefs')
    push_type = (data or {}).get('type')
    if isinstance(prefs, dict) and push_type:
        pref_key = _PUSH_TYPE_TO_PREF.get(push_type)
        if pref_key is not None and prefs.get(pref_key) is False:
            print(f"[PUSH] suppressed user_ref={_push_token_ref(token)} "
                  f"type={push_type} pref={pref_key}")
            return _result(True, True, 'suppressed_by_preference')

    apns_configured = bool(os.environ.get('APNS_AUTH_KEY', '').strip())
    delivered = 0
    attempted = 0
    reasons = []
    dead_reasons = ('Unregistered', 'BadDeviceToken', 'ExpiredToken')

    # Defensive de-duplication in case a partially migrated table contains the
    # same endpoint twice. The DB unique constraint is the primary boundary.
    seen = set()
    for reg in registrations:
        apns_token = (reg.get('apns_token') or '').strip()
        if not apns_token:
            continue
        topic = (reg.get('bundle_id') or 'aerotax.AeroTax').strip()
        env_pref = _push_normalized_environment(reg.get('apns_env'))
        endpoint_key = (apns_token, topic, env_pref)
        if endpoint_key in seen:
            continue
        seen.add(endpoint_key)
        if not apns_configured:
            reasons.append('no_jwt')
            continue

        attempted += 1
        if env_pref in ('sandbox', 'prod'):
            first_sandbox = env_pref == 'sandbox'
        else:
            first_sandbox = os.environ.get('APNS_USE_SANDBOX', '').strip() == '1'
        ok, reason = _send_apns(
            apns_token, title, body, data=data, topic=topic,
            thread_id=thread_id, badge=badge, use_sandbox=first_sandbox,
            retry_env_planned=True, category=category)
        used_env = 'sandbox' if first_sandbox else 'prod'
        if not ok and reason in dead_reasons:
            alt_sandbox = not first_sandbox
            ok2, reason2 = _send_apns(
                apns_token, title, body, data=data, topic=topic,
                thread_id=thread_id, badge=badge, use_sandbox=alt_sandbox,
                category=category)
            if ok2:
                ok, reason = True, None
                used_env = 'sandbox' if alt_sandbox else 'prod'
                # Keep the legacy environment hint for old fallback paths. New
                # clients send the authoritative environment at registration.
                if not reg.get('installation_id') and used_env == 'prod':
                    try:
                        _push_save(token, {**legacy, 'apns_env': used_env})
                    except Exception:
                        pass
            else:
                reason = reason2 or reason
        if ok:
            delivered += 1
            _push_installation_delivery_update(reg, True)
            print(f"[PUSH] apns ok user_ref={_push_token_ref(token)} "
                  f"installation={str(reg.get('installation_id') or 'legacy')[:8]} "
                  f"env={used_env}")
            continue

        reasons.append(reason or 'send_failed')
        _push_installation_delivery_update(reg, False, reason=reason)
        if reason in dead_reasons:
            if reg.get('installation_id'):
                _push_installation_tombstone(
                    token, installation_id=reg.get('installation_id'),
                    reason='apns_' + str(reason).lower())
            else:
                try:
                    _push_save(token, {**legacy, 'apns_token': ''})
                except Exception:
                    pass
            print(f"[PUSH] tombstoned dead installation "
                  f"user_ref={_push_token_ref(token)} reason={reason}")

    # Expo is a compatibility fallback, not an additional duplicate channel.
    expo_token = ((legacy or {}).get('push_token') or '').strip()
    if delivered == 0 and expo_token:
        attempted += 1
        try:
            import urllib.request
            payload = json.dumps({
                'to': expo_token, 'title': title, 'body': body,
                'sound': 'default', 'priority': 'high',
                **({'data': data} if data else {}),
            }).encode('utf-8')
            req = urllib.request.Request(
                'https://exp.host/--/api/v2/push/send',
                data=payload, method='POST',
                headers={'Content-Type': 'application/json',
                         'Accept': 'application/json'},
            )
            urllib.request.urlopen(req, timeout=10).read()
            delivered += 1
        except Exception:
            reasons.append('expo_transport_error')

    if delivered:
        return _result(True, True, 'delivered', delivered, attempted)
    if (legacy or {}).get('_durable_registry_unavailable'):
        return _result(False, False, 'push_registry_unavailable', 0, attempted)
    if not seen and not expo_token:
        return _result(True, True, 'no_active_installations', 0, attempted)
    if seen and reasons and all(reason in dead_reasons for reason in reasons):
        return _result(True, True, 'all_installations_tombstoned', 0, attempted)
    return _result(False, False, ','.join(sorted(set(reasons))) or 'send_failed',
                   0, attempted)


# ── Fire-and-forget Push (2026-07-02) ────────────────────────────────────
# _send_push_notification macht Netz-I/O (SB-Registry-Load + APNs HTTP/2, bis
# ~10s Timeout) — INLINE im Request-Pfad blockierte das jeden Send-Endpoint.
# Alle Event-Pushes laufen jetzt über diesen Executor: der Request antwortet
# sofort, der Push passiert im Hintergrund, Fehler werden gelogged statt den
# Response zu kippen.
_PUSH_EXECUTOR = None
_PUSH_OUTBOX_MAX_ATTEMPTS = 8
_PUSH_OUTBOX_BATCH = 20
_PUSH_OUTBOX_WORKER_ID = f'{os.getpid()}-{uuid.uuid4().hex[:8]}'
_PUSH_OUTBOX_METRICS = {
    'enqueued': 0, 'deduplicated': 0, 'claimed': 0, 'delivered': 0,
    'retried': 0, 'dead': 0, 'enqueue_fallback': 0,
}
_PUSH_OUTBOX_METRICS_LOCK = _push_threading.Lock()
_PUSH_OUTBOX_DAEMON = None
_PUSH_OUTBOX_WAKE = _push_threading.Event()


def _push_metric(name, amount=1):
    with _PUSH_OUTBOX_METRICS_LOCK:
        _PUSH_OUTBOX_METRICS[name] = _PUSH_OUTBOX_METRICS.get(name, 0) + amount


def _push_outbox_retry_seconds(attempts):
    """Bounded exponential backoff: 15s, 30s, …, max 1h."""
    try:
        attempts = max(1, int(attempts))
    except Exception:
        attempts = 1
    return min(3600, 15 * (2 ** min(attempts - 1, 8)))


def _push_outbox_key(token, title, body, data, thread_id, badge, category,
                     idempotency_key=None):
    """Hash the producer key so DB/logs never contain account credentials."""
    if idempotency_key:
        raw = 'explicit:' + str(idempotency_key)
    else:
        identifiers = {
            str(k): v for k, v in (data or {}).items()
            if str(k) == 'id' or str(k).endswith('_id')
        } if isinstance(data, dict) else {}
        if identifiers:
            raw = 'event:' + json.dumps(identifiers, sort_keys=True, default=str)
        else:
            # Payload-identical producer retries within one minute coalesce;
            # later genuinely repeated reminders/reactions remain deliverable.
            bucket = int(datetime.now(timezone.utc).timestamp() // 60)
            raw = f'window:{bucket}'
    material = json.dumps({
        'key': raw, 'recipient': token, 'title': title, 'body': body,
        'data': data or {}, 'thread_id': thread_id, 'badge': badge,
        'category': category,
    }, sort_keys=True, ensure_ascii=False, default=str)
    return _hashlib.sha256(material.encode('utf-8')).hexdigest()


def _push_outbox_enqueue(token, title, body, data=None, thread_id=None,
                         badge=None, category=None, idempotency_key=None):
    if not (SB_AVAILABLE and sb is not None and token):
        return None
    payload = {
        'title': str(title or '')[:200],
        'body': str(body or '')[:1000],
        'data': data if isinstance(data, dict) else {},
        'thread_id': str(thread_id)[:128] if thread_id else None,
        'badge': badge,
        'category': str(category)[:64] if category else None,
    }
    key = _push_outbox_key(token, title, body, data, thread_id, badge,
                           category, idempotency_key=idempotency_key)
    try:
        result = sb.rpc('enqueue_push_outbox', {
            'p_idempotency_key': key,
            'p_user_token': token,
            'p_payload': payload,
        }).execute()
        row = result.data
        if isinstance(row, list):
            row = row[0] if row else None
        if not isinstance(row, dict):
            return None
        outbox_id = row.get('outbox_id') or row.get('id')
        _push_metric('enqueued' if bool(row.get('inserted')) else 'deduplicated')
        return str(outbox_id) if outbox_id else None
    except Exception as e:
        app.logger.error(
            f'[push-outbox] enqueue_fail user_ref={_push_token_ref(token)} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return None


def _push_outbox_claim():
    if not (SB_AVAILABLE and sb is not None):
        return None
    try:
        result = sb.rpc('claim_push_outbox', {
            'p_worker_id': _PUSH_OUTBOX_WORKER_ID,
            'p_limit': _PUSH_OUTBOX_BATCH,
            'p_lock_timeout_seconds': 120,
        }).execute()
        rows = [row for row in (result.data or []) if isinstance(row, dict)]
        _push_metric('claimed', len(rows))
        return rows
    except Exception as e:
        app.logger.error(
            f'[push-outbox] claim_fail worker={_PUSH_OUTBOX_WORKER_ID} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return None


def _push_outbox_mark(row, delivery):
    if not (SB_AVAILABLE and sb is not None and row.get('id')):
        return False
    attempts = int(row.get('attempts') or 1)
    now = datetime.now(timezone.utc)
    reason = str(delivery.get('reason') or 'send_failed')[:300]
    terminal_success = bool(delivery.get('ok')) and bool(delivery.get('terminal'))
    if terminal_success:
        patch = {
            'status': 'delivered', 'delivered_at': now.isoformat(),
            'updated_at': now.isoformat(), 'locked_at': None, 'locked_by': None,
            'last_error': None, 'payload': {}, 'user_token': None,
        }
        metric = 'delivered'
    elif attempts >= _PUSH_OUTBOX_MAX_ATTEMPTS or delivery.get('terminal'):
        patch = {
            'status': 'dead', 'dead_at': now.isoformat(),
            'updated_at': now.isoformat(), 'locked_at': None, 'locked_by': None,
            'last_error': reason,
        }
        metric = 'dead'
    else:
        available = now + timedelta(seconds=_push_outbox_retry_seconds(attempts))
        patch = {
            'status': 'retry', 'available_at': available.isoformat(),
            'updated_at': now.isoformat(), 'locked_at': None, 'locked_by': None,
            'last_error': reason,
        }
        metric = 'retried'
    try:
        # Only the worker that still owns the processing lease may finalize.
        # Without these predicates, a slow first worker could overwrite the
        # result after its expired row was reclaimed by another process.
        (sb.table('push_outbox').update(patch)
         .eq('id', row['id']).eq('status', 'processing')
         .eq('locked_by', _PUSH_OUTBOX_WORKER_ID).execute())
        _push_metric(metric)
        print(f"[PUSH-OUTBOX] {metric} id={str(row['id'])[:8]} "
              f"attempt={attempts} reason={reason}")
        return True
    except Exception as e:
        app.logger.error(
            f'[push-outbox] mark_fail id={str(row.get("id"))[:8]} '
            f'err={type(e).__name__}: {str(e)[:160]}'
        )
        return False


def _push_outbox_drain(max_batches=4):
    """Claim and deliver bounded batches; safe to run concurrently."""
    for _ in range(max_batches):
        rows = _push_outbox_claim()
        if not rows:
            return
        for row in rows:
            payload = row.get('payload') or {}
            token = row.get('user_token')
            if not token or not isinstance(payload, dict):
                delivery = {'ok': False, 'terminal': True,
                            'reason': 'invalid_outbox_payload'}
            else:
                try:
                    internal_job = ((payload.get('data') or {}).get('_internal_job')
                                    if isinstance(payload.get('data'), dict)
                                    else None)
                    if internal_job == 'chat_fanout':
                        job_data = payload.get('data') or {}
                        ok = _chat_push_fanout_async(
                            token, job_data.get('channel_id') or '',
                            payload.get('body') or '',
                            message_id=job_data.get('message_id'),
                            _from_outbox=True)
                        delivery = {
                            'ok': bool(ok), 'terminal': bool(ok),
                            'reason': ('chat_fanout_enqueued' if ok
                                       else 'chat_fanout_retry'),
                        }
                    else:
                        delivery = _send_push_notification(
                            token, payload.get('title') or '',
                            payload.get('body') or '', data=payload.get('data'),
                            thread_id=payload.get('thread_id'),
                            badge=payload.get('badge'),
                            category=payload.get('category'),
                            _return_detail=True)
                except Exception as e:
                    delivery = {'ok': False, 'terminal': False,
                                'reason': f'{type(e).__name__}: {str(e)[:180]}'}
            _push_outbox_mark(row, delivery)


def _push_outbox_worker_loop():
    """Periodic wake-up makes future retries and post-restart rows progress."""
    while True:
        _PUSH_OUTBOX_WAKE.wait(timeout=30.0)
        _PUSH_OUTBOX_WAKE.clear()
        try:
            _push_outbox_drain()
        except Exception as e:
            app.logger.error(
                f'[push-outbox] worker_loop_fail {type(e).__name__}: {str(e)[:160]}'
            )


def _ensure_push_outbox_worker():
    global _PUSH_OUTBOX_DAEMON
    if not (SB_AVAILABLE and sb is not None):
        return False
    if _PUSH_OUTBOX_DAEMON is None or not _PUSH_OUTBOX_DAEMON.is_alive():
        with _PUSH_OUTBOX_METRICS_LOCK:
            if _PUSH_OUTBOX_DAEMON is None or not _PUSH_OUTBOX_DAEMON.is_alive():
                _PUSH_OUTBOX_DAEMON = _push_threading.Thread(
                    target=_push_outbox_worker_loop,
                    name='push-outbox-daemon', daemon=True)
                _PUSH_OUTBOX_DAEMON.start()
    _PUSH_OUTBOX_WAKE.set()
    return True


def _push_executor():
    global _PUSH_EXECUTOR
    if _PUSH_EXECUTOR is None:
        from concurrent.futures import ThreadPoolExecutor
        _PUSH_EXECUTOR = ThreadPoolExecutor(max_workers=4,
                                            thread_name_prefix='push')
    return _PUSH_EXECUTOR


def _push_notify_async(token, title, body, data=None, thread_id=None,
                       badge=None, category=None, idempotency_key=None):
    """Durably enqueue, then schedule non-blocking delivery.

    If the additive schema/store is unavailable, preserve old clients via the
    previous direct executor send. That path is metered and never called durable.
    """
    outbox_id = _push_outbox_enqueue(
        token, title, body, data=data, thread_id=thread_id, badge=badge,
        category=category, idempotency_key=idempotency_key)
    if outbox_id:
        _ensure_push_outbox_worker()
        return outbox_id
    else:
        _push_metric('enqueue_fallback')

        def job():
            try:
                _send_push_notification(token, title, body, data=data,
                                        thread_id=thread_id, badge=badge,
                                        category=category)
            except Exception as e:
                print(f"[PUSH] fallback send failed user_ref={_push_token_ref(token)}: "
                      f"{type(e).__name__}: {str(e)[:200]}")
    try:
        _push_executor().submit(job)
    except Exception as e:
        print(f"[PUSH] executor submit failed: {e}")
    return outbox_id


# Reclaim persisted pending/processing rows after a process restart, even when
# no new notification is produced immediately.
_ensure_push_outbox_worker()


def _chat_push_preview(text):
    """Menschlich lesbare Push-Vorschau aus dem rohen Chat-`text`. Rich-Message-
    Marker (Foto/Meetup/Standort/Voice + Reply-Header, siehe ChatRichMessage.swift)
    dürfen NICHT roh in der Notification landen (User-Bug 2026-07-02: Push zeigte
    „[aerox:photo]/api/wall/image/…jpg" statt „📷 Foto")."""
    s = (text or '').strip()
    if not s:
        return ''
    # Reply-Header vorne abtrennen ("[aerox:re]{json}\n<payload>").
    if s.startswith('[aerox:re]'):
        nl = s.find('\n')
        s = s[nl + 1:].strip() if nl != -1 else ''
    low = s.lower()
    if '[aerox:photo]' in low:
        # optionale Caption steht hinter dem -Trenner NACH der URL
        after = s[low.index('[aerox:photo]') + len('[aerox:photo]'):]
        cap = ''
        if '\x1f' in after:
            cap = after.split('\x1f', 1)[1].strip()
        return f'📷 Foto — {cap[:120]}' if cap else '📷 Foto'
    if '[aerox:voice]' in low:
        return '🎤 Sprachnachricht'
    if '[aerox:meetup]' in low:
        return '📅 Treffen vorgeschlagen'
    if '[aerox:loc]' in low:
        return '📍 Standort geteilt'
    if '[aerox:' in low:
        # unbekannter Marker → generisch, nie roh
        return 'Neue Nachricht'
    return s[:140]


def _chat_push_fanout_async(author_token, channel_id, text, message_id=None,
                            _from_outbox=False):
    """Push-Fanout für Chat-Messages (DM- UND Group-Channels) — der HEADLINE-
    Fix für 'keine Push bei neuer Nachricht' (2026-07-02): der generische
    Send-Endpoint /api/crew-chat/<t>/channel/<id>/send hatte NIE einen
    Push-Pfad; nur der /dm-Wrapper pushte (blocking + Name von der ephemeren
    Disk). Jetzt EINE Fanout-Stelle für beide Entry-Points.

    - DM (`dm__a__b`): Empfänger = der andere Teilnehmer.
    - Group (`group__gid`/`grp__gid`): Owner + members aus user_friend_groups
      (best-effort — per-Code-Beigetretene ohne Members-Eintrag sind nicht
      adressierbar, Capability-Modell hat keine vollständige Mitgliederliste).
    - NIE an den Autor selbst; Block-/Mute-Listen des Empfängers respektiert.
    The request path first persists one lightweight fanout job. The outbox
    worker resolves recipients and atomically/idempotently enqueues one child
    delivery per recipient. `_from_outbox` is worker-internal only.
    """
    if not _from_outbox:
        fanout_id = _push_outbox_enqueue(
            author_token, '__internal_chat_fanout__', text,
            data={'_internal_job': 'chat_fanout',
                  'channel_id': channel_id,
                  'message_id': message_id},
            idempotency_key=(f'chat-fanout:{message_id}'
                             if message_id else None))
        if fanout_id:
            _ensure_push_outbox_worker()
            return fanout_id
        # Additive-schema/store outage: preserve the old best-effort behavior
        # for rollout compatibility. This path is observable and intentionally
        # not described as durable.
        _push_metric('enqueue_fallback')

    def _job():
        try:
            recipients = []
            group_name = None
            recipient_lookup_failed = False
            cid = channel_id or ''
            if cid.startswith('dm__'):
                parts = cid[len('dm__'):].split('__')
                recipients = [p for p in parts if p and p != author_token]
            else:
                gid = _group_id_from_channel(cid)
                if gid and SB_AVAILABLE:
                    try:
                        r = (sb.table('user_friend_groups')
                             .select('owner_token,name,members')
                             .eq('id', gid).limit(1).execute())
                        rows = r.data or []
                        if rows:
                            row = rows[0]
                            group_name = (row.get('name') or '').strip() or None
                            mem = row.get('members')
                            mem_list = mem if isinstance(mem, list) else []
                            # FANOUT-LÜCKE (Audit 2026-07-12): per Invite-Code
                            # Beigetretene stehen nicht in members → bekamen NIE
                            # Gruppen-Pushes. Selbst-heilend: wer POSTET, wird
                            # hier best-effort in members nachgetragen (Cap 40).
                            # Owner-Group-Saves können das überschreiben — der
                            # nächste Post des Joiners repariert es wieder.
                            try:
                                if (author_token
                                        and author_token != row.get('owner_token')
                                        and author_token not in mem_list
                                        and len(mem_list) < 40):
                                    sb.table('user_friend_groups') \
                                      .update({'members': mem_list + [author_token]}) \
                                      .eq('id', gid).execute()
                            except Exception:
                                pass
                            cand = [row.get('owner_token')] + mem_list
                            seen = set()
                            for m in cand:
                                if (isinstance(m, str) and m
                                        and m != author_token
                                        and m not in seen):
                                    seen.add(m)
                                    recipients.append(m)
                            recipients = recipients[:25]  # Fanout-Cap
                    except Exception as e:
                        print(f"[PUSH] group lookup failed gid={str(gid)[:12]}: "
                              f"{type(e).__name__}: {str(e)[:120]}")
                        recipient_lookup_failed = True
            if not recipients:
                return not recipient_lookup_failed
            sender_name = ''
            try:
                sender_name = ((_profile_load(author_token) or {})
                               .get('profile', {}) or {}).get('name') or ''
            except Exception:
                pass
            sender_name = sender_name.strip() or 'Crew'
            preview = _chat_push_preview(text)
            is_group = not cid.startswith('dm__')
            for rcpt in recipients:
                try:
                    # Empfänger hat den Autor stummgeschaltet/geblockt → kein Push.
                    if author_token in _muted_by(rcpt) or \
                       author_token in _blocked_by(rcpt):
                        continue
                except Exception:
                    # Block/mute state is privacy-sensitive. Retry the durable
                    # fanout instead of guessing "not blocked" during outage.
                    if _from_outbox:
                        return False
                    continue
                if is_group:
                    title = f"{sender_name} · {group_name}" if group_name else sender_name
                    payload_type = 'group_message'
                else:
                    title = sender_name
                    payload_type = 'dm'
                try:
                    kwargs = {
                        'data': {'type': payload_type, 'channel_id': cid,
                                 'from': author_token},
                        'thread_id': cid,
                        'badge': 1,
                        'idempotency_key': (f'chat:{message_id}:{rcpt}'
                                            if message_id else None),
                    }
                    if _from_outbox:
                        child_id = _push_outbox_enqueue(
                            rcpt, title, preview, **kwargs)
                        if not child_id:
                            return False
                    else:
                        _push_notify_async(rcpt, title, preview, **kwargs)
                except Exception as e:
                    print(f"[PUSH] chat fanout send failed "
                          f"rcpt_ref={_push_token_ref(rcpt)}: "
                          f"{type(e).__name__}: {str(e)[:200]}")
                    return False
            return True
        except Exception as e:
            print(f"[PUSH] chat fanout failed ch={str(channel_id)[:24]}: "
                  f"{type(e).__name__}: {str(e)[:200]}")
            return False
    if _from_outbox:
        return _job()
    try:
        _push_executor().submit(_job)
    except Exception as e:
        print(f"[PUSH] executor submit failed: {e}")
    return None


@app.route('/api/user/history/<token>/clear', methods=['POST'])
def clear_user_history(token):
    """Löscht die Historie eines Tokens (DSGVO: User-Right-to-Delete)."""
    p = _user_history_path(token)
    if not p:
        return jsonify({'ok': False, 'error': 'invalid token'}), 400
    try:
        import os
        if os.path.exists(p):
            os.remove(p)
        return jsonify({'ok': True})
    except Exception as e:
        print(f'[clear_user_history] error: {type(e).__name__}: {str(e)[:300]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 500


# ── Auth-System (email/password optional auf Token-Flow) ──────────────

def _user_auth_path():
    import os
    os.makedirs(_USER_HISTORY_DIR, exist_ok=True)
    return os.path.join(_USER_HISTORY_DIR, 'auth_users.json')


_AUTH_KNOWN_COLS = {
    'password_hash', 'token', 'apple_sub', 'reset_token', 'reset_expires',
    'reset_used_at', 'hash_migrated_at', 'created_at', 'last_login_at',
}


def _auth_load_from_supabase():
    """Liest alle Auth-Records aus Supabase. None bei SB-down/Fehler.
    Paginiert (Supabase default range-Limit ist 1000)."""
    if not SB_AVAILABLE:
        return None
    try:
        out = {}
        offset = 0
        page = 1000
        while True:
            r = sb.table('auth_users').select('*').range(offset, offset + page - 1).execute()
            rows = r.data or []
            for row in rows:
                email = row.get('email')
                if not email:
                    continue
                rec = {}
                for k in _AUTH_KNOWN_COLS:
                    v = row.get(k)
                    if v is not None:
                        rec[k] = v
                md = row.get('metadata') or {}
                if isinstance(md, dict):
                    rec.update(md)
                out[email] = rec
            if len(rows) < page:
                break
            offset += page
        return out
    except Exception as e:
        app.logger.warning(f'[auth] sb_load_fail err={type(e).__name__}: {str(e)[:120]}')
        return None


def _auth_save_to_supabase(d):
    """Bulk-upsert aller Auth-Records nach Supabase. True bei vollem Erfolg,
    False bei Fehler. Splittet in 500er Batches."""
    if not SB_AVAILABLE or not d:
        return False
    rows = []
    for email, rec in (d or {}).items():
        if not email:
            continue
        row = {'email': email}
        meta = {}
        for k, v in (rec or {}).items():
            if k in _AUTH_KNOWN_COLS:
                row[k] = v
            else:
                meta[k] = v
        row['metadata'] = meta
        rows.append(row)
    if not rows:
        return False
    try:
        for i in range(0, len(rows), 500):
            sb.table('auth_users').upsert(rows[i:i+500], on_conflict='email').execute()
        return True
    except Exception as e:
        app.logger.error(f'[auth] sb_save_fail err={type(e).__name__}: {str(e)[:200]}')
        return False


def _auth_load_from_disk():
    """Read auth_users.json from disk. Returns dict (possibly empty)."""
    import os, json
    p = _user_auth_path()
    if not os.path.exists(p):
        return {}
    try:
        with open(p) as f:
            return json.load(f) or {}
    except Exception:
        return {}


def _auth_load():
    """P0-Fix 2026-05-31: Supabase primary (ohne wäre auf Cloud Run jeder
    Redeploy = Wipe). Bei leerer SB + Disk-Daten: einmalige Migration."""
    sb_data = _auth_load_from_supabase()
    if sb_data is None:
        # SB-Ausfall — Disk-Fallback. Auf Cloud Run ist die Disk nach jedem
        # Deploy/Scale-Event LEER: ein leerer Disk-Cache heißt dann NICHT
        # „0 User", sondern „keine Daten verfügbar" → None als Fehlersignal,
        # damit _refresh_token_cache den bisherigen Cache BEHÄLT statt ihn
        # mit einer leeren Map zu überschreiben. (Root cause der Logout-
        # Wellen 2026-07-01: sb_load_fail → leere tmap „erfolgreich" gecacht
        # → Gate 401 unauthorized → App-Logout.)
        disk_data = _auth_load_from_disk()
        return disk_data if disk_data else None
    if sb_data:
        return sb_data
    # SB erreichbar aber leer — prüfen ob Disk Legacy-Daten hat, einmalig migrieren
    disk_data = _auth_load_from_disk()
    if disk_data and SB_AVAILABLE:
        app.logger.info(f'[auth] lazy-migrate {len(disk_data)} disk users → supabase')
        _auth_save_to_supabase(disk_data)
        return disk_data
    return {}


def _auth_save(d):
    """P0-Fix 2026-05-31: schreibt zu Supabase (primary) + Disk (best-effort
    Read-Cache). Atomic-Write garantiert dass disk nie halb-geschrieben ist.
    Returns True wenn mindestens ein Pfad gehalten hat."""
    disk_ok = False
    try:
        _atomic_write_json(_user_auth_path(), d)
        disk_ok = True
    except Exception as e:
        app.logger.warning(f'[auth] disk_save_fail (ok wenn SB läuft): {e}')
    sb_ok = _auth_save_to_supabase(d)
    if not (sb_ok or disk_ok):
        app.logger.error('[auth] CRITICAL: weder Supabase noch Disk gesichert — Daten verloren!')
        return False
    return True


def _auth_delete_disk_row(user_email):
    """Entfernt NUR die eine email-Row aus dem Disk-Auth-Cache, ohne den Rest
    des Dicts neu zu schreiben (re-read → drop → write).

    WARUM nicht _auth_save(users): _auth_save macht einen Bulk-Upsert des GANZEN
    users-Dicts. Unter gleichzeitigen Deletes (Cloud Run = mehrere Instanzen)
    re-inserted dieser Bulk-Upsert genau die Rows, die ein paralleler Delete
    gerade gelöscht hat — lost-update / Wiederauferstehung gelöschter Accounts.
    Der SB-seitige Row-Delete (.delete().eq('email', ...)) ist atomar pro Row und
    bleibt der Source-of-Truth; hier räumen wir nur den lokalen Read-Cache auf."""
    try:
        p = _user_auth_path()
        import os
        if not os.path.exists(p):
            return
        with open(p) as f:
            disk = json.load(f) or {}
        if user_email in disk:
            del disk[user_email]
            _atomic_write_json(p, disk)
    except Exception as e:
        app.logger.warning(f'[auth-delete] disk_row_delete_fail: {type(e).__name__}: {str(e)[:120]}')


# ── SCALE-FIX (2026-06-25): Single-Row Auth-Pfade ────────────────────
# Problem: _auth_load()/_auth_save() lesen + schreiben die GANZE auth_users-
# Tabelle bei JEDEM Login/Signup. Bei 5k gleichzeitigen Logins schmilzt SB.
# Lösung: indizierter Single-Row-SELECT (email/token/apple_sub) + Single-Row-
# UPSERT statt Load-All/Save-All. Semantik bleibt IDENTISCH — die Row-Bau-/
# Row-Parse-Logik ist exakt aus _auth_save_to_supabase / _auth_load_from_supabase
# herauskopiert, damit Spalten-Payload (und damit das ON-CONFLICT-Verhalten)
# bit-für-bit gleich bleibt. _auth_load/_auth_save bleiben für den 60s-Token-
# Cache + Nicht-Hot-Path-Aufrufer erhalten.

def _auth_user_row(email, rec):
    """Baut die Supabase-Row für genau einen User — identisch zur Bulk-Logik
    in _auth_save_to_supabase (known cols → Spalten, Rest → metadata)."""
    row = {'email': email}
    meta = {}
    for k, v in (rec or {}).items():
        if k in _AUTH_KNOWN_COLS:
            row[k] = v
        else:
            meta[k] = v
    row['metadata'] = meta
    return row


def _auth_row_to_rec(row):
    """Supabase-Row → in-memory rec — identisch zur Logik in
    _auth_load_from_supabase (known cols + metadata-merge)."""
    rec = {}
    for k in _AUTH_KNOWN_COLS:
        v = row.get(k)
        if v is not None:
            rec[k] = v
    md = row.get('metadata') or {}
    if isinstance(md, dict):
        rec.update(md)
    return rec


def _auth_get_user_sb(email):
    """Indizierter Single-Row-SELECT by email. Returns (rec_or_None, sb_ok).
    sb_ok=False → Supabase nicht erreichbar (Caller nimmt Disk-Fallback)."""
    if not SB_AVAILABLE or sb is None:
        return (None, False)
    try:
        r = sb.table('auth_users').select('*').eq('email', email).limit(1).execute()
        rows = r.data or []
        if not rows:
            return (None, True)
        return (_auth_row_to_rec(rows[0]), True)
    except Exception as e:
        app.logger.warning(f'[auth] sb_get_user_fail err={type(e).__name__}: {str(e)[:120]}')
        return (None, False)


def _auth_get_user(email):
    """Hot-Path Single-User-Read: SB primary (indiziert by email), Disk-Fallback
    bei SB-Ausfall ODER für noch nicht migrierte Legacy-Disk-User.
    Ersetzt `(_auth_load() or {}).get(email)` ohne Full-Table-Read.
    Returns rec dict oder None."""
    if not email:
        return None
    rec, sb_ok = _auth_get_user_sb(email)
    if rec is not None:
        return rec
    # SB-Miss (sb_ok=True) ODER SB-down (sb_ok=False) → Disk prüfen:
    # deckt Legacy-un-migrated User UND SB-Outage ab (nie User aussperren).
    disk_rec = _auth_load_from_disk().get(email)
    if disk_rec is not None and sb_ok and SB_AVAILABLE:
        # Legacy Disk-only User, SB erreichbar → diese eine Row lazy-migrieren
        try: _auth_upsert_user_sb(email, disk_rec)
        except Exception: pass
    return disk_rec


def _auth_find_user_by(col, value):
    """Single-Row-SELECT über eine known/indizierbare Spalte (token/apple_sub).
    Returns (email, rec) oder (None, None). Bei SB-Miss/SB-down: Disk-Fallback-
    Scan (selten — nur Apple-Sign-In / Delete-Account / Entitlement, kein
    Login-Storm-Pfad)."""
    if not value:
        return (None, None)
    if SB_AVAILABLE and sb is not None:
        try:
            r = sb.table('auth_users').select('*').eq(col, value).limit(1).execute()
            rows = r.data or []
            if rows:
                row = rows[0]
                return (row.get('email'), _auth_row_to_rec(row))
        except Exception as e:
            app.logger.warning(f'[auth] sb_find_{col}_fail err={type(e).__name__}: {str(e)[:120]}')
    # Disk-Fallback (SB-down ODER Legacy-un-migrated)
    for em, rec in (_auth_load_from_disk() or {}).items():
        if (rec or {}).get(col) == value:
            return (em, rec)
    return (None, None)


def _auth_upsert_user_sb(email, rec):
    """Single-Row-UPSERT (on_conflict='email'). True bei Erfolg.
    Payload exakt wie _auth_save_to_supabase pro Row → identisches Verhalten."""
    if not SB_AVAILABLE or sb is None or not email:
        return False
    try:
        sb.table('auth_users').upsert(_auth_user_row(email, rec), on_conflict='email').execute()
        return True
    except Exception as e:
        app.logger.error(f'[auth] sb_upsert_user_fail err={type(e).__name__}: {str(e)[:200]}')
        return False


def _auth_upsert_disk_row(email, rec):
    """Schreibt NUR die eine email-Row in den Disk-Read-Cache (re-read → set →
    write), analog _auth_delete_disk_row. True bei Erfolg."""
    if not email:
        return False
    try:
        import os
        p = _user_auth_path()
        disk = {}
        if os.path.exists(p):
            with open(p) as f:
                disk = json.load(f) or {}
        disk[email] = rec
        _atomic_write_json(p, disk)
        return True
    except Exception as e:
        app.logger.warning(f'[auth] disk_row_upsert_fail: {type(e).__name__}: {str(e)[:120]}')
        return False


def _auth_upsert_user(email, rec):
    """Single-Row-Save: SB primary + targeted Disk-Row. Ersetzt `_auth_save(users)`
    auf dem Hot-Path ohne den ganzen Table neu zu schreiben.
    Returns True wenn mindestens ein Pfad gehalten hat."""
    sb_ok = _auth_upsert_user_sb(email, rec)
    disk_ok = _auth_upsert_disk_row(email, rec)
    if not (sb_ok or disk_ok):
        app.logger.error('[auth] CRITICAL: single-row weder SB noch Disk gesichert — Daten verloren!')
    return sb_ok or disk_ok


# ── Wave-1 BUG-004 (2026-06-02): Token-Auth Helper ──────────────────
# In-process TTL-Cache (60s) damit _validate_token_exists nicht jeden
# Auth-Check zu einem voll-SB-Read macht. _auth_load selbst liest 1000er-
# Batches aus Supabase — bei 100 RPS würden wir SB unnötig belasten.
_TOKEN_VALIDATE_CACHE = {'tokens': None, 'expires': 0.0}
_TOKEN_VALIDATE_CACHE_TTL = 60.0


class _TokenValidationState(Enum):
    """Tri-state result: outages are neither valid nor invalid credentials."""
    VALID = 'valid'
    INVALID = 'invalid'
    UNAVAILABLE = 'unavailable'


class _TokenValidationResult:
    __slots__ = ('state', 'email')

    def __init__(self, state, email=None):
        self.state = state
        self.email = email


class _AuthStoreUnavailable(RuntimeError):
    """Raised by the legacy scalar wrapper so request routes become retryable."""


def _validate_token(token):
    """Validate a token without conflating an auth-store outage with a miss.

    Verwendet 60s in-process Cache. Bei Cache-Miss für ein unbekanntes
    Token wird der Cache einmal nachgeladen (cover-Pfad für frische Signups
    die noch nicht im Cache stehen) — danach bleibt der Cache für 60s gültig.

    Semantik:
      VALID       bekannte Credentials, auch aus einem stale-but-known Cache
      INVALID     Store war erreichbar und Credential ist sicher unbekannt
      UNAVAILABLE Store war nicht erreichbar und ein unbekanntes Credential
                  kann nicht sicher klassifiziert werden (Caller antwortet 503)
    """
    if not token or not isinstance(token, str):
        return _TokenValidationResult(_TokenValidationState.INVALID)
    # Guest-Demo-Tokens werden separat behandelt (rejected vor diesem Helper)
    import time as _t
    now = _t.time()
    cached = _TOKEN_VALIDATE_CACHE['tokens']
    cache_stale = cached is None or _TOKEN_VALIDATE_CACHE['expires'] < now
    refresh_unavailable = False
    if cache_stale:
        refreshed = _refresh_token_cache(now)
        if refreshed is not None:
            cached = refreshed
            cache_stale = False
        elif cached is not None:
            # STALE-KNOWN-SAFE (User 2026-07-01 „App loggt mich IMMER WIEDER
            # aus"): der Reload
            # (auth_users aus Supabase) schlug TRANSIENT fehl (Cold-Start/DB-Hickup/Timeout)
            # → bekannte Credentials aus dem STALE (aber echten) Cache bleiben
            # VALID. Ein darin unbekanntes Token wird dagegen UNAVAILABLE, nie
            # mehr fail-open VALID.
            refresh_unavailable = True
        else:
            # Cold start + Store-Ausfall: Credential-Wahrheit ist unbekannt.
            return _TokenValidationResult(_TokenValidationState.UNAVAILABLE)
    hit = (cached or {}).get(token)
    if hit is not None:
        return _TokenValidationResult(_TokenValidationState.VALID, hit)
    if refresh_unavailable:
        return _TokenValidationResult(_TokenValidationState.UNAVAILABLE)
    if hit is None and not cache_stale:
        # Token nicht im Cache, aber Cache ist nicht stale. Möglich: neuer
        # Signup seit letztem Refresh. Einmal force-refresh, dann erneut checken.
        fresh = _refresh_token_cache(now, force=True)
        if fresh is None:
            # Das Token könnte ein frischer Signup sein: 503 statt 401 verhindert
            # Client-Logout, ohne einen Angreifer als authentifiziert zu behandeln.
            return _TokenValidationResult(_TokenValidationState.UNAVAILABLE)
        hit = fresh.get(token)
    if hit is not None:
        return _TokenValidationResult(_TokenValidationState.VALID, hit)
    return _TokenValidationResult(_TokenValidationState.INVALID)


def _validate_token_exists(token):
    """Compatibility wrapper for legacy scalar call sites.

    Returns only a verified email, `None` only for a proven invalid credential,
    and raises `_AuthStoreUnavailable` for an outage. The Flask error handler
    maps that exception to the same retryable 503 as the explicit auth gates;
    this prevents old boolean call sites from treating UNAVAILABLE as either
    valid (the old fail-open sentinel) or invalid (logout-prone 401).
    """
    result = _validate_token(token)
    if result.state is _TokenValidationState.UNAVAILABLE:
        raise _AuthStoreUnavailable('auth store unavailable')
    return result.email if result.state is _TokenValidationState.VALID else None


def _auth_store_unavailable_response():
    """Transient auth failure that clients must retry and must not treat as logout."""
    response = jsonify({'ok': False, 'error': 'auth_store_unavailable'})
    response.status_code = 503
    response.headers['Retry-After'] = '5'
    return response


@app.errorhandler(_AuthStoreUnavailable)
def _handle_auth_store_unavailable(_exc):
    return _auth_store_unavailable_response()


def _refresh_token_cache(now=None, force=False):
    """Lädt _TOKEN_VALIDATE_CACHE neu aus auth_users. Returns das tmap
    oder None bei Fehler."""
    import time as _t
    if now is None:
        now = _t.time()
    try:
        users = _auth_load()
        if users is None:
            # Auth-Store nicht verfügbar (SB-Hickup + leere Cloud-Run-Disk):
            # KEIN „erfolgreicher" Refresh mit leerer Map — bisherigen Cache
            # behalten, Caller nutzt den Stale-Fail-Safe.
            app.logger.warning('[token-auth] cache_refresh_fail: auth store unavailable — keeping previous cache')
            return None
        tmap = {}
        for email, rec in (users or {}).items():
            tok = (rec or {}).get('token')
            if tok:
                tmap[tok] = email
        prev = _TOKEN_VALIDATE_CACHE['tokens']
        if not tmap and prev:
            # Shrink-Guard: eine nicht-leere Token-Map wird NIE durch eine
            # leere ersetzt (leere auth_users in Prod = Datenfehler, nicht
            # „alle User gelöscht").
            app.logger.warning('[token-auth] refresh returned EMPTY map — keeping previous non-empty cache')
            return None
        _TOKEN_VALIDATE_CACHE['tokens'] = tmap
        _TOKEN_VALIDATE_CACHE['expires'] = now + _TOKEN_VALIDATE_CACHE_TTL
        return tmap
    except Exception as e:
        try:
            app.logger.warning(f'[token-auth] cache_refresh_fail: {type(e).__name__}: {str(e)[:120]}')
        except Exception:
            pass
        return None


def _invalidate_token_cache():
    """Force-refresh beim nächsten _validate_token_exists call. Wird von
    Signup/Login/Delete-Account aufgerufen damit eben gemachte Token-Mutations
    sofort im Auth-Gate sichtbar sind."""
    _TOKEN_VALIDATE_CACHE['expires'] = 0.0


def _token_auth_required(token):
    """Wrapper für POST/PUT/DELETE-Routes mit <token>-Pfad.
    Returns (None, None) wenn ok, sonst (jsonify-response, status-code).

    Usage:
        @app.route('/api/foo/<token>/bar', methods=['POST'])
        def my_route(token):
            err = _token_auth_required(token)
            if err: return err
            # ... continue ...
    """
    # Guest-Demo-Tokens haben kein Auth-Record — eigene Block-Logik in jeder
    # Route (z.B. wall/post sendet 403 demo_mode). Hier behandeln wir nur den
    # Real-User-Case.
    if not token:
        return jsonify({'ok': False, 'error': 'unauthorized'}), 401
    if token.startswith('AT-GUEST-'):
        # Guest tokens haben keinen Auth-Record. Eigene Routes müssen
        # explizit 403 returnen wenn sie Guest blocken. Hier: pass-through.
        return None
    validation = _validate_token(token)
    if validation.state is _TokenValidationState.UNAVAILABLE:
        return _auth_store_unavailable_response()
    if validation.state is _TokenValidationState.INVALID:
        return jsonify({'ok': False, 'error': 'unauthorized'}), 401
    return None


_PBKDF2_ITERATIONS = 600_000  # OWASP 2023 für PBKDF2-SHA256
_PBKDF2_DKLEN = 32

def _password_hash(pw):
    """PBKDF2-SHA256 600k iters mit 16-byte salt.
    Format: pbkdf2$<iters>$<salt-hex>$<hash-hex>.
    Hashlib.scrypt ist auf manchen Python-Builds nicht verfügbar (OpenSSL-
    config), PBKDF2 ist stdlib-garantiert. ~100ms login auf Cloud-Run-CPU."""
    import hashlib, os
    salt = os.urandom(16)
    h = hashlib.pbkdf2_hmac('sha256', (pw or '').encode('utf-8'),
                            salt, _PBKDF2_ITERATIONS, _PBKDF2_DKLEN)
    return f'pbkdf2${_PBKDF2_ITERATIONS}${salt.hex()}${h.hex()}'


def _password_verify(pw, stored):
    """Verifiziert pw gegen stored. Supports beide Formate:
    - pbkdf2$<iters>$<salt>$<hash>: neuer Hash
    - 64-hex-string: legacy sha256
    Returns (ok: bool, needs_rehash: bool)."""
    import hashlib, hmac
    if not stored or not pw:
        return (False, False)
    if stored.startswith('pbkdf2$'):
        try:
            _, iters_s, salt_hex, hash_hex = stored.split('$')
            iters = int(iters_s)
            salt = bytes.fromhex(salt_hex)
            expected = bytes.fromhex(hash_hex)
            actual = hashlib.pbkdf2_hmac('sha256', pw.encode('utf-8'),
                                        salt, iters, len(expected))
            ok = hmac.compare_digest(actual, expected)
            # Re-hash wenn unter aktueller Iterations-Anforderung
            needs_rehash = ok and iters < _PBKDF2_ITERATIONS
            return (ok, needs_rehash)
        except Exception:
            return (False, False)
    # Legacy sha256 path (unsalted, alte Accounts vor Wave 21)
    legacy = hashlib.sha256(pw.encode('utf-8')).hexdigest()
    ok = hmac.compare_digest(legacy, stored)
    return (ok, ok)  # ok → also needs rehash


def _password_policy_ok(pw):
    """Min 8 Zeichen + mind. 1 Buchstabe + mind. 1 Ziffer.
    Verhindert die schwächsten Passwörter ("12345678", "password").
    Returns (ok, error_message)."""
    if not pw or len(pw) < 8:
        return (False, 'password_too_short')
    has_digit = any(c.isdigit() for c in pw)
    has_letter = any(c.isalpha() for c in pw)
    if not (has_digit and has_letter):
        return (False, 'password_too_weak')
    # Block top-25 common passwords (kurz-Liste)
    common = {'password', 'password1', 'qwerty123', '12345678', 'iloveyou',
              'admin123', 'welcome1', 'letmein1', 'monkey123', 'football1'}
    if pw.lower() in common:
        return (False, 'password_too_common')
    return (True, None)


_EMAIL_RX = re.compile(r'^[^@\s]+@[^@\s]+\.[^@\s]{2,}$')

def _email_valid(email: str) -> bool:
    """Server-seitige Email-Plausi.
    Akzeptiert: max-length, mind. 1 Punkt nach @, kein Whitespace, Plus-Addresses
    (`foo+bar@x.de`), Akzente / IDN-Hosts werden vom Backend nicht punkt-genau
    verifiziert — sind aber kein hartes Verbot (manche Crew-Mitglieder haben
    realen Umlaut im Username-Part). 'a@b' wird abgelehnt (kein TLD).
    """
    if not email or len(email) > 254:
        return False
    return bool(_EMAIL_RX.match(email))


def _notify_owner_new_signup(email, method='email'):
    """Echtzeit-Benachrichtigung an den Owner bei JEDER neuen Anmeldung, inkl.
    laufendem Gesamt-Zähler (Owner-Wunsch 2026-07-15). Läuft fire-and-forget im
    Hintergrund-Thread → verlangsamt den Signup nicht und darf ihn NIE
    fehlschlagen lassen (best-effort, alle Fehler geschluckt/geloggt)."""
    def _run():
        try:
            api_key = os.environ.get('RESEND_API_KEY', '').strip()
            # Persönlicher Owner-Posteingang (Echtzeit-Push aufs iPhone). Bewusst
            # NICHT der Support-Verteiler (SUPPORT_NOTIFY_EMAIL=aerox@aerosteuer.de) —
            # per SIGNUP_NOTIFY_EMAIL-Env übersteuerbar.
            to_email = (os.environ.get('SIGNUP_NOTIFY_EMAIL')
                        or 'miguel.schumann@icloud.com').strip()
            if not api_key or not to_email:
                app.logger.info('[signup-notify] kein RESEND_API_KEY/Empfänger — übersprungen')
                return
            # Laufender Gesamt-Zähler: leichtgewichtiges count=exact (keine Rows).
            total = None
            try:
                if SB_AVAILABLE and sb is not None:
                    r = sb.table('auth_users').select('token', count='exact').limit(1).execute()
                    total = getattr(r, 'count', None)
            except Exception:
                total = None
            from_addr = os.environ.get('SIGNUP_FROM_EMAIL',
                                       'AeroX <noreply@aerosteuer.de>').strip()
            total_str = f' #{total}' if isinstance(total, int) else ''
            total_html = (f'<p style="font-size:22px;color:#0F1A3D;margin:12px 0">'
                          f'<b>Gesamt: {total} Accounts</b></p>'
                          if isinstance(total, int) else '')
            html_body = f"""
            <div style="font-family:-apple-system,sans-serif;max-width:520px;margin:0 auto;padding:20px">
              <h2 style="color:#0F1A3D;margin:0 0 8px">Neue AeroX-Anmeldung</h2>
              <p style="font-size:16px;color:#222;margin:4px 0"><b>{email}</b></p>
              <p style="font-size:13px;color:#777;margin:2px 0">Methode: {method}</p>
              {total_html}
              <p style="color:#999;font-size:11px;margin-top:28px">
                AeroX · automatische Echtzeit-Benachrichtigung, bitte nicht antworten.
              </p>
            </div>
            """
            import urllib.request
            payload = json.dumps({
                'from': from_addr,
                'to': [to_email],
                'subject': f'AeroX: neuer Account{total_str} · {email}',
                'html': html_body,
            }).encode()
            req = urllib.request.Request(
                'https://api.resend.com/emails',
                data=payload,
                headers={'Authorization': f'Bearer {api_key}',
                         'Content-Type': 'application/json',
                         'User-Agent': 'AeroX-Backend/1.0'})
            with urllib.request.urlopen(req, timeout=10) as resp:
                if 200 <= resp.status < 300:
                    app.logger.info(f'[signup-notify] mail an {to_email[:3]}*** (total={total})')
                else:
                    app.logger.warning(f'[signup-notify] resend status {resp.status}')
        except Exception as e:
            app.logger.warning(f'[signup-notify] send failed: {e}')
    try:
        import threading as _threading
        _threading.Thread(target=_run, daemon=True).start()
    except Exception as e:
        app.logger.warning(f'[signup-notify] thread start failed: {e}')


@app.route('/api/auth/signup', methods=['POST'])
def auth_signup():
    # Anti-Abuse: IP-Rate-Limit gegen Massen-Account-Erstellung (Enumeration,
    # Reset-Token-Brute-Force, Squatting). 15 Signups/Stunde/IP ist großzügig für
    # NAT (mehrere echte User), stoppt aber Bots.
    _ip = (request.headers.get('X-Forwarded-For', '') or request.remote_addr or '').split(',')[0].strip()
    if _ip and _ip_rate_limited(_ip, 'signup', limit=15, window_sec=3600):
        return jsonify({'ok': False, 'error': 'too_many_signups'}), 429
    # ZUSÄTZLICH durable (Supabase, instanz-übergreifend, fail-open).
    if _ip and _durable_auth_rate_limited(_ip, 'auth_signup_ip'):
        return jsonify({'ok': False, 'error': 'too_many_signups'}), 429
    body = request.get_json(silent=True) or {}
    email = (body.get('email') or '').strip().lower()
    pw = body.get('password') or ''
    if not _email_valid(email):
        return jsonify({'ok': False, 'error': 'email_invalid'}), 400
    ok_pw, err = _password_policy_ok(pw)
    if not ok_pw:
        return jsonify({'ok': False, 'error': err}), 400
    # SCALE-FIX: indizierter Single-Row-Check statt Full-Table-Load.
    if _auth_get_user(email) is not None:
        return jsonify({'ok': False, 'error': 'email_already_exists'}), 409
    import uuid as _u
    token = 'AT-' + _u.uuid4().hex[:16].upper()
    rec = {
        'password_hash': _password_hash(pw),
        'token': token,
        'created_at': datetime.now().isoformat(),
    }
    # SCALE-FIX: Single-Row-Upsert (on_conflict email) statt Full-Table-Save.
    _auth_upsert_user(email, rec)
    # Wave-1 BUG-004: cache-invalidate damit der eben erstellte Token sofort
    # im before_request-Auth-Gate sichtbar ist (sonst 401 bis 60s-TTL abläuft).
    try: _invalidate_token_cache()
    except Exception: pass
    # Echtzeit-Owner-Mail + Zähler (fire-and-forget, blockt den Signup nicht).
    _notify_owner_new_signup(email, method='E-Mail')
    return jsonify({'ok': True, 'token': token, 'email': email})


@app.route('/api/auth/login', methods=['POST'])
def auth_login():
    body = request.get_json(silent=True) or {}
    email = (body.get('email') or '').strip().lower()
    pw = body.get('password') or ''
    # Leere Felder direkt ablehnen — sonst landen wir mit pw='' im hash-vergleich,
    # was unnötig CPU kostet und das Email-rate-limit unnötig hochzieht.
    if not email or not pw:
        return jsonify({'ok': False, 'error': 'invalid_credentials'}), 401
    # Brute-Force-Schutz: 10 Login-Versuche pro Email + 30 pro IP pro 10 Min.
    # Email-Limit verhindert gezieltes Knacken eines Accounts; IP-Limit blockt
    # User-Enumeration über viele Emails von gleicher Quelle.
    if email and _token_rate_limited(f'login:{email}', 'auth_login', limit=10, window_sec=600):
        return jsonify({'ok': False, 'error': 'too_many_attempts',
                        'message': 'Zu viele Login-Versuche. Bitte in einigen Minuten erneut.'}), 429
    client_ip = request.headers.get('X-Forwarded-For', request.remote_addr or '').split(',')[0].strip()
    if client_ip and _ip_rate_limited(client_ip, endpoint='auth_login', limit=30, window_sec=600):
        return jsonify({'ok': False, 'error': 'too_many_attempts',
                        'message': 'Zu viele Login-Versuche. Bitte in einigen Minuten erneut.'}), 429
    # ZUSÄTZLICH durable (instanz-übergreifend, überlebt Container-Restarts).
    # Fail-open — blockiert NIE wegen Supabase-Problemen (siehe Helper).
    if client_ip and _durable_auth_rate_limited(client_ip, 'auth_login_ip'):
        return jsonify({'ok': False, 'error': 'too_many_attempts',
                        'message': 'Zu viele Login-Versuche. Bitte in einigen Minuten erneut.'}), 429
    # SCALE-FIX: indizierter Single-Row-Read statt Full-Table-Load.
    user = _auth_get_user(email)
    if not user:
        return jsonify({'ok': False, 'error': 'invalid_credentials'}), 401
    ok, needs_rehash = _password_verify(pw, user.get('password_hash', ''))
    if not ok:
        return jsonify({'ok': False, 'error': 'invalid_credentials'}), 401
    if needs_rehash:
        # Transparente Migration: alter sha256-Hash → neuer scrypt-Hash
        try:
            user['password_hash'] = _password_hash(pw)
            user['hash_migrated_at'] = datetime.now().isoformat()
            # SCALE-FIX: Single-Row-Upsert statt Full-Table-Save.
            _auth_upsert_user(email, user)
            app.logger.info(f'[auth] migrated hash for {email[:3]}***')
        except Exception as e:
            app.logger.warning(f'[auth] rehash failed: {e}')
    return jsonify({'ok': True, 'token': user['token'], 'email': email})


# Apple JWKS-Cache (15 Min TTL — Apple rotiert Keys selten)
_APPLE_JWKS_CACHE = {'keys': None, 'expires': 0.0}
APPLE_BUNDLE_ID = os.environ.get('APPLE_BUNDLE_ID', 'aerotax.AeroTax')

def _fetch_apple_jwks():
    now = time.time()
    if _APPLE_JWKS_CACHE['keys'] and _APPLE_JWKS_CACHE['expires'] > now:
        return _APPLE_JWKS_CACHE['keys']
    try:
        import urllib.request as _u
        with _u.urlopen('https://appleid.apple.com/auth/keys', timeout=5) as r:
            jwks = json.loads(r.read().decode('utf-8'))
        _APPLE_JWKS_CACHE['keys'] = jwks.get('keys') or []
        _APPLE_JWKS_CACHE['expires'] = now + 900
        return _APPLE_JWKS_CACHE['keys']
    except Exception as e:
        app.logger.warning(f'[apple-jwt] JWKS fetch failed: {e}')
        return []

def _verify_apple_identity_token(token, expected_sub=None):
    """Verifiziert Apple identity_token (JWT).
    Returns: (ok, sub, email) — wenn ok=False sind sub/email None.
    Verifiziert: Signatur (RS256 via JWKS), iss, aud, exp, nbf.
    """
    if not token or token.count('.') != 2:
        return (False, None, None)
    try:
        import base64
        def b64dec(s):
            s += '=' * (-len(s) % 4)
            return base64.urlsafe_b64decode(s)
        header_b64, payload_b64, sig_b64 = token.split('.')
        header = json.loads(b64dec(header_b64))
        payload = json.loads(b64dec(payload_b64))
        # Claims-Check
        if payload.get('iss') != 'https://appleid.apple.com':
            return (False, None, None)
        if payload.get('aud') != APPLE_BUNDLE_ID:
            return (False, None, None)
        now = int(time.time())
        if int(payload.get('exp') or 0) < now:
            return (False, None, None)
        if int(payload.get('nbf') or 0) > now + 60:
            return (False, None, None)
        sub = payload.get('sub')
        if expected_sub and sub != expected_sub:
            return (False, None, None)
        # Signatur-Check via JWKS
        kid = header.get('kid')
        keys = _fetch_apple_jwks()
        jwk = next((k for k in keys if k.get('kid') == kid), None)
        if not jwk:
            app.logger.warning(f'[apple-jwt] kid {kid} not in JWKS')
            return (False, None, None)
        try:
            from cryptography.hazmat.primitives.asymmetric.rsa import RSAPublicNumbers
            from cryptography.hazmat.primitives.asymmetric import padding
            from cryptography.hazmat.primitives import hashes
            n = int.from_bytes(b64dec(jwk['n']), 'big')
            e = int.from_bytes(b64dec(jwk['e']), 'big')
            pubkey = RSAPublicNumbers(e, n).public_key()
            signed = f'{header_b64}.{payload_b64}'.encode('ascii')
            pubkey.verify(b64dec(sig_b64), signed, padding.PKCS1v15(), hashes.SHA256())
        except Exception as e:
            app.logger.warning(f'[apple-jwt] signature verify failed: {e}')
            return (False, None, None)
        return (True, sub, payload.get('email'))
    except Exception as e:
        app.logger.warning(f'[apple-jwt] parse failed: {e}')
        return (False, None, None)


@app.route('/api/auth/apple', methods=['POST'])
def auth_apple():
    """Sign-in-with-Apple. Verifiziert identity_token kryptographisch
    (RS256 via Apple JWKS). identity_token ist PFLICHT — kein Legacy-Pfad
    (sonst koennte jeder mit beliebigem apple_sub einen Account uebernehmen).

    Body: {apple_sub, email?, name?, identity_token}
    """
    body = request.get_json(silent=True) or {}
    apple_sub = (body.get('apple_sub') or '').strip()
    email = (body.get('email') or '').strip().lower()
    name = (body.get('name') or '').strip()
    identity_token = (body.get('identity_token') or '').strip()
    if not apple_sub:
        return jsonify({'ok': False, 'error': 'apple_sub_required'}), 400
    # identity_token ist Pflicht — Security-Hardening (kein anonymes
    # apple_sub-Trust mehr, sonst koennte jeder einen Account uebernehmen).
    if not identity_token:
        return jsonify({'ok': False, 'error': 'identity_token_required',
                        'message': 'iOS-Client muss identity_token mitschicken.'}), 400

    ok, verified_sub, verified_email = _verify_apple_identity_token(
        identity_token, expected_sub=apple_sub)
    if not ok:
        return jsonify({'ok': False, 'error': 'invalid_apple_token'}), 401
    # Email aus dem Token bevorzugen wenn vorhanden (kann private relay sein)
    if verified_email and '@' in verified_email:
        email = verified_email.lower()
    # Apple liefert manchmal eine "private-relay" Email · ok als unique key
    if not email or '@' not in email:
        # Fallback: use sub as pseudo-email
        email = f'apple-{apple_sub[:20]}@privaterelay.aerox'
    # SCALE-FIX: Single-Row-Lookup by apple_sub statt Full-Table-Scan.
    ex_email, ex_user = _auth_find_user_by('apple_sub', apple_sub)
    if ex_user is not None:
        return jsonify({'ok': True, 'token': ex_user['token'], 'email': ex_email})
    # Existing user via email match: NICHT automatisch linken — Sicherheit.
    # Jemand koennte sonst per Apple-Sign-In Zugriff auf einen fremden
    # Email/Password-Account erlangen, falls die Email zufaellig matched.
    # User muss sich erst klassisch einloggen und dann manuell verknuepfen.
    if _auth_get_user(email) is not None:
        return jsonify({'ok': False, 'error': 'account_exists_unlink',
                        'message': 'Es existiert bereits ein Account mit dieser E-Mail. '
                                   'Bitte logge dich erst per Passwort ein und verknuepfe '
                                   'dann Apple-Sign-In im Profil.'}), 409
    # Neuer Account
    import uuid as _u
    token = 'AT-' + _u.uuid4().hex[:16].upper()
    rec = {
        'token': token,
        'apple_sub': apple_sub,
        'created_at': datetime.now().isoformat(),
        # kein password_hash · klassischer login wäre für diesen Account disabled
    }
    # SCALE-FIX: Single-Row-Upsert statt Full-Table-Save.
    _auth_upsert_user(email, rec)
    try: _invalidate_token_cache()
    except Exception: pass
    # Echtzeit-Owner-Mail + Zähler bei NEUEM Apple-Account (fire-and-forget).
    _notify_owner_new_signup(email, method='Apple')
    # Wenn Apple einen name geliefert hat (nur beim ersten Login) · ins Profile vorbefüllen
    if name:
        try:
            with open(_user_profile_path(token), 'w') as f:
                json.dump({'profile': {'name': name}, '_updated_at': datetime.now().isoformat()}, f)
        except Exception:
            pass
    return jsonify({'ok': True, 'token': token, 'email': email})


def _send_password_reset_email(to_email, reset_token):
    """Schickt Reset-Token via Resend. Failures werden geloggt, User-Response
    bleibt 200 (kein Email-Enumeration). Returns True/False für Telemetrie."""
    api_key = os.environ.get('RESEND_API_KEY', '').strip()
    from_addr = os.environ.get('RESET_FROM_EMAIL',
                               'AeroX <noreply@aerosteuer.de>').strip()
    if not api_key:
        app.logger.warning(
            '[auth-reset] RESEND_API_KEY nicht gesetzt — '
            f'Token für {to_email[:3]}*** wäre: {reset_token[:6]}…')
        return False
    try:
        import urllib.request
        html_body = f"""
        <div style="font-family:-apple-system,sans-serif;max-width:560px;margin:0 auto;padding:24px;">
          <h2 style="color:#0F1A3D;margin:0 0 16px">Passwort zurücksetzen</h2>
          <p style="color:#3a3a3a;line-height:1.5;font-size:14px">
            Wir haben eine Anfrage erhalten dein AeroX-Passwort zurückzusetzen.
            Verwende diesen Token in der App:
          </p>
          <div style="background:#f5f5f7;border-radius:12px;padding:20px;margin:20px 0;
                      text-align:center;font-family:'SF Mono',Menlo,monospace;
                      font-size:18px;letter-spacing:1.5px;color:#0F1A3D;
                      border:1px solid #e0e0e6">
            {reset_token}
          </div>
          <p style="color:#666;font-size:13px;line-height:1.5">
            Der Token ist 2 Stunden gültig. Wenn du das Reset nicht angefordert
            hast, ignoriere diese E-Mail — dein Passwort bleibt unverändert.
          </p>
          <p style="color:#888;font-size:11px;margin-top:32px">
            AeroX · aerosteuer.de · automatische Nachricht, bitte nicht antworten.
          </p>
        </div>
        """
        payload = json.dumps({
            'from': from_addr,
            'to': [to_email],
            'subject': 'AeroX · Passwort zurücksetzen',
            'html': html_body,
        }).encode()
        req = urllib.request.Request(
            'https://api.resend.com/emails',
            data=payload,
            headers={'Authorization': f'Bearer {api_key}',
                     'Content-Type': 'application/json',
                     'User-Agent': 'AeroX-Backend/1.0'},
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            ok = 200 <= resp.status < 300
            if ok:
                app.logger.info(f'[auth-reset] mail sent to {to_email[:3]}***')
            else:
                app.logger.warning(f'[auth-reset] resend status {resp.status}')
            return ok
    except Exception as e:
        app.logger.warning(f'[auth-reset] send failed: {e}')
        return False


@app.route('/api/auth/forgot', methods=['POST'])
def auth_forgot():
    body = request.get_json(silent=True) or {}
    email = (body.get('email') or '').strip().lower()
    # Rate-Limit: 5 Forgot-Versuche pro Email + 10 pro IP pro 10 Min.
    # Verhindert Email-Bombing (Spammer fluten User mit Reset-Mails).
    if email and _token_rate_limited(f'forgot:{email}', 'auth_forgot', limit=5, window_sec=600):
        return jsonify({'ok': True, 'sent': True}), 200  # silent, kein Enumeration
    client_ip = request.headers.get('X-Forwarded-For', request.remote_addr or '').split(',')[0].strip()
    if client_ip and _ip_rate_limited(client_ip, endpoint='auth_forgot', limit=10, window_sec=600):
        return jsonify({'ok': True, 'sent': True}), 200
    # ZUSÄTZLICH durable per-Email (Supabase, instanz-übergreifend, fail-open):
    # Mail-Bombing eines Opfers von VIELEN IPs/Instanzen wird sonst nicht gefangen.
    # Antwort bleibt neutral-200 (kein Enumeration-Leak).
    if email and _durable_auth_rate_limited(email, 'auth_forgot_email'):
        return jsonify({'ok': True, 'sent': True}), 200
    # SCALE-FIX: Single-Row-Read/Upsert statt Full-Table-Load/Save.
    # Antwortet immer 200 ohne Detail (kein E-Mail-Enumeration).
    user = _auth_get_user(email)
    if user is not None:
        import uuid as _u
        reset_token = _u.uuid4().hex[:24]
        user['reset_token'] = reset_token
        user['reset_expires'] = (datetime.now() + timedelta(hours=2)).isoformat()
        user.pop('reset_used_at', None)  # alter used_at-Marker entfernen, neuer Token
        _auth_upsert_user(email, user)
        sent_ok = _send_password_reset_email(email, reset_token)
        if not sent_ok:
            # Resend-Key fehlt oder API-Fehler — User-Antwort bleibt neutral (kein
            # Enumeration), aber Admin-Log macht den Fehler sichtbar.
            app.logger.error(f'[auth-forgot] reset-mail NICHT versendet für {email[:3]}*** — Resend-Key prüfen!')
    return jsonify({'ok': True, 'sent': True})


@app.route('/api/auth/reset', methods=['POST'])
def auth_reset():
    body = request.get_json(silent=True) or {}
    email = (body.get('email') or '').strip().lower()
    reset_token = (body.get('reset_token') or '').strip()
    new_pw = body.get('new_password') or ''
    ok_pw, err = _password_policy_ok(new_pw)
    if not ok_pw:
        return jsonify({'ok': False, 'error': err}), 400
    # SCALE-FIX: indizierter Single-Row-Read statt Full-Table-Load.
    user = _auth_get_user(email)
    if not user or user.get('reset_token') != reset_token:
        return jsonify({'ok': False, 'error': 'invalid_token'}), 400
    # Single-Use-Audit: wenn used_at gesetzt ist, wurde der Token bereits einmal
    # verwendet — verweigern (Replay-Schutz auch wenn Token noch nicht abgelaufen).
    if user.get('reset_used_at'):
        return jsonify({'ok': False, 'error': 'token_already_used'}), 400
    try:
        from datetime import datetime as _d
        if _d.fromisoformat(user.get('reset_expires', '1970-01-01T00:00:00')) < datetime.now():
            return jsonify({'ok': False, 'error': 'token_expired'}), 400
    except Exception:
        pass
    user['password_hash'] = _password_hash(new_pw)
    user['reset_used_at'] = datetime.now().isoformat()  # Audit-Marker
    user.pop('reset_token', None)
    user.pop('reset_expires', None)
    # SCALE-FIX: Single-Row-Upsert statt Full-Table-Save. ON-CONFLICT-Verhalten
    # identisch zum alten Bulk-Save (gepoppte Spalten bleiben SB-seitig stehen,
    # Replay-Schutz greift über reset_used_at — unverändert).
    _auth_upsert_user(email, user)
    app.logger.info(f'[auth-reset] PW erfolgreich gesetzt für {email[:3]}***')
    return jsonify({'ok': True})


@app.route('/api/auth/delete-account', methods=['POST'])
def auth_delete_account():
    """DSGVO Art. 17 · Apple Guideline 5.1.1(v) — kompletter Account-Wipe.

    Auth-Modi:
    - Email/Password: body{email, password} → verifiziert via hash
    - Token-based (Apple-Sign-In oder loggedin): body{token} → identifiziert
      user via token-match in users-dict (apple-sign-in user hat keinen
      password_hash, daher diese Variante)
    """
    body = request.get_json(silent=True) or {}
    email = (body.get('email') or '').strip().lower()
    pw = body.get('password') or ''
    bearer_token = (body.get('token') or '').strip()
    # SCALE-FIX: Single-Row-Lookups statt Full-Table-Load.
    user = None
    user_email = None
    if email and pw:
        user = _auth_get_user(email)
        if not user:
            return jsonify({'ok': False, 'error': 'invalid_credentials'}), 401
        ok, _ = _password_verify(pw, user.get('password_hash', ''))
        if not ok:
            return jsonify({'ok': False, 'error': 'invalid_credentials'}), 401
        user_email = email
    elif bearer_token:
        # Find user via stored token (Apple-Sign-In / authenticated session)
        ex_email, ex_user = _auth_find_user_by('token', bearer_token)
        if ex_user is not None:
            user = ex_user
            user_email = ex_email
        if not user:
            return jsonify({'ok': False, 'error': 'invalid_token'}), 401
        # SECURITY (P0, 2026-06-09): ein Email/Passwort-Account MUSS auch auf dem
        # Token-Pfad das Passwort re-verifizieren. Vorher genügte der Token allein
        # (ODER ein leeres Passwort fiel still in diesen Branch) → ein geleakter/
        # eingeloggter Token konnte den Account ohne Passwort-Kenntnis löschen.
        # Apple-Sign-In-Accounts haben KEIN password_hash → Token-Identität genügt
        # (sie haben kein Passwort; Re-Auth läuft über Apple).
        if user.get('password_hash'):
            ok, _ = _password_verify(pw, user.get('password_hash', ''))
            if not ok:
                return jsonify({'ok': False, 'error': 'invalid_credentials'}), 401
    else:
        return jsonify({'ok': False, 'error': 'auth_required'}), 400

    token = user.get('token')
    # P0 GDPR/Data-Loss-Fix (2026-06-08): NUR den eigenen Account-Row gezielt
    # löschen — KEIN _auth_save(users) Bulk-Upsert mehr. Der alte Bulk-Upsert des
    # gesamten Rest-Dicts hat unter gleichzeitigen Deletes (multi-instance) Rows
    # wieder eingefügt, die ein paralleler Delete gerade entfernt hatte
    # (10 concurrent deletes → 6 überlebten). Jetzt: SB-Row-Delete (atomar pro
    # Row) + gezieltes Disk-Row-Remove. Kein stale-Snapshot-Re-Insert.
    if SB_AVAILABLE and sb is not None and user_email:
        try:
            sb.table('auth_users').delete().eq('email', user_email).execute()
        except Exception as e:
            app.logger.warning(f'[auth-delete] sb_row_delete_fail: {type(e).__name__}: {str(e)[:120]}')
    _auth_delete_disk_row(user_email)
    # Wave-1 BUG-004: cache-invalidate damit der gerade gelöschte Token im
    # before_request-Gate ab sofort als unbekannt zählt.
    try: _invalidate_token_cache()
    except Exception: pass

    import os, shutil
    deleted = []
    safe_token = re.sub(r'[^A-Za-z0-9_-]', '', token or '')[:64]
    # 1. Direkte Token-Files (Moderation + Roster + Auth-Daten)
    direct_files = [
        f'history_{token}.json', f'profile_{token}.json',
        f'friends_{token}.json', f'push_{token}.json',
        f'crashes_{token}.json',
        f'blocks_{token}.json', f'mutes_{token}.json',
        f'wall_likes_{token}.json', f'forum_likes_{token}.json',
        f'roster_snapshot_{token}.json', f'roster_changes_{token}.json',
        f'crew_aircraft_{token}.json',
    ]
    for fn in direct_files:
        p = os.path.join(_USER_HISTORY_DIR, fn)
        if os.path.exists(p):
            try: os.remove(p); deleted.append(fn)
            except Exception: pass

    # 2. Briefings + Voice-Notes pro Token (sub-dirs/<safe-token>.json oder <safe-token>/)
    for subdir, suffix in (('briefings', '.json'), ('voice_notes', None)):
        if suffix:
            sub_p = os.path.join(_USER_HISTORY_DIR, subdir, safe_token + suffix)
            if os.path.exists(sub_p):
                try: os.remove(sub_p); deleted.append(f'{subdir}/{safe_token}{suffix}')
                except Exception: pass
        else:
            # voice_notes/<token>/ enthält mehrere m4a-Dateien
            sub_dir = os.path.join(_USER_HISTORY_DIR, subdir, safe_token)
            if os.path.isdir(sub_dir):
                try: shutil.rmtree(sub_dir); deleted.append(f'{subdir}/{safe_token}/')
                except Exception: pass

    # 2b. Wall-Images-Verzeichnis pro Token (Legacy-Token-Dir + opaker Key-Dir
    # aus dem Token-Leak-Fix — neue Uploads liegen unter dem opaken Key)
    for _wi in (safe_token, _wall_img_key(token)):
        img_dir = os.path.join(_USER_HISTORY_DIR, 'wall_images', _wi)
        if os.path.isdir(img_dir):
            try: shutil.rmtree(img_dir); deleted.append(f'wall_images/{_wi}/')
            except Exception: pass

    # 2c. DM-Channel-Files in denen dieser Token Teilnehmer ist
    try:
        cm_root = os.path.join(_USER_HISTORY_DIR, 'chat_messages')
        if os.path.isdir(cm_root):
            for fn in os.listdir(cm_root):
                # Format: dm__<sortedA>__<sortedB>.json
                if not fn.endswith('.json'): continue
                if f'__{token}__' in fn or fn.endswith(f'__{token}.json') or fn.startswith(f'dm__{token}__'):
                    try: os.remove(os.path.join(cm_root, fn)); deleted.append(fn[:40])
                    except Exception: pass
    except Exception: pass

    # 2d. Layover-Recs + Comments des Users (best-effort, anhand author_token)
    try:
        from glob import glob
        for pat in ('layover_recs.json', 'layover_recs_comments_*.json'):
            for fp in glob(os.path.join(_USER_HISTORY_DIR, pat)):
                try:
                    with open(fp) as f: items = json.load(f) or []
                    new_items = [it for it in items if it.get('author_token') != token]
                    if len(new_items) != len(items):
                        with open(fp, 'w') as f: json.dump(new_items, f)
                        deleted.append(os.path.basename(fp))
                except Exception: pass
    except Exception: pass

    # 3. Wall-Posts mit diesem author_token entfernen
    try:
        posts = _wall_load_posts()
        new_posts = [p for p in posts if p.get('author_token') != token]
        if len(new_posts) != len(posts):
            _wall_save_posts(new_posts)
            deleted.append(f'wall_posts:{len(posts) - len(new_posts)}')
    except Exception:
        pass

    # 3b. Briefings (SB + Disk) — beide Tabellen per Token leeren
    if SB_AVAILABLE and token:
        try:
            sb.table('user_ical_briefings').delete().eq('token', token).execute()
            deleted.append('sb:user_ical_briefings')
        except Exception as _e:
            app.logger.warning(f'[delete] sb_ical_briefings_fail: {str(_e)[:120]}')
        try:
            sb.table('user_manual_briefings').delete().eq('token', token).execute()
            deleted.append('sb:user_manual_briefings')
        except Exception as _e:
            app.logger.warning(f'[delete] sb_manual_briefings_fail: {str(_e)[:120]}')

    # 3b2. Voice-Notes: R2-Bytes löschen (SB-Metadata-Rows kommen in der Cascade
    # unten via user_voice_notes). Keys aus der SB-Metadata ableiten.
    if token:
        try:
            for _d in (_voice_note_meta_list(token) or []):
                _vk = _voice_note_r2_key(token, _d)
                if R2_AVATARS_ENABLED and _vk:
                    _r2_delete_key(_vk)
        except Exception as _e:
            app.logger.warning(f'[delete] voice_r2_fail: {str(_e)[:120]}')

    # 3c. DSGVO Art. 17 — vollständige Supabase-Cascade. Vorher überlebten die
    # sensibelsten User-Daten (Steuer-Sessions, Profile, Wall/Forum/DM, Friends,
    # Licenses, Push-Tokens, Family-Shares, Crew-Reports) den Account-Delete in
    # SB, weil _auth_save nur upsert macht und der alte Delete nur Disk + 3 SB-
    # Tabellen anfasste. Jeder Delete ist STRIKT token-scoped (nur Rows die DIESEM
    # Token gehören) und best-effort (eine fehlschlagende Tabelle bricht den
    # gesamten Delete nicht ab). Key-Spalte je Tabelle stammt aus dem jeweiligen
    # Write-Pfad (upsert/insert) — siehe Kommentare.
    if SB_AVAILABLE and sb is not None and token:
        sb_deleted = {}
        # (table, column) — column ist die im Write-Pfad genutzte Owner-Spalte.
        _cascade = [
            ('user_profiles',     'token'),         # upsert on_conflict='token'
            ('wall_posts',        'author_token'),  # row['author_token']
            ('wall_comments',     'author_token'),  # row['author_token']
            ('wall_likes',        'user_token'),    # {'post_id','user_token'}
            ('forum_threads',     'author_token'),  # row['author_token']
            ('forum_replies',     'author_token'),  # row['author_token']
            ('forum_likes',       'user_token'),    # {'user_token',...}
            ('dm_messages',       'author_token'),  # row['author_token']
            ('dm_lastseen',       'user_token'),    # {'user_token','channel_id'}
            ('user_friends',      'owner_token'),   # {'owner_token','friend_token'}
            ('user_friend_groups','owner_token'),   # {'owner_token',...}
            ('crew_edges',        'self_token'),    # on_conflict='self_token,other_id'
            ('briefings',         'user_token'),    # .eq('user_token', token)
            ('ical_events',       'user_token'),    # .eq('user_token', token)
            ('user_licenses',     'user_token'),    # .eq('user_token', token)
            ('user_push_tokens',  'user_token'),    # on_conflict='user_token'
            ('push_installations','user_token'),    # multi-device APNs bindings
            ('push_outbox',       'user_token'),    # undelivered push intent/PII
            ('layover_reviews',   'user_token'),    # on_conflict='iata,user_token,category'
            ('aircraft_health_reports', 'reported_by_token'),  # row['reported_by_token']
            ('hotel_room_reports',      'reported_by_token'),  # row['reported_by_token']
            ('trade_posts',             'author_token'),       # .eq('author_token', token)
            ('user_flight_ops',         'token'),              # upsert on_conflict='token,datum'
            ('user_voice_notes',        'token'),              # upsert on_conflict='token,day_key'
        ]
        for _tbl, _col in _cascade:
            try:
                _r = sb.table(_tbl).delete().eq(_col, token).execute()
                _n = len((_r and getattr(_r, 'data', None)) or [])
                sb_deleted[_tbl] = _n
            except Exception as _e:
                app.logger.warning(f'[delete] sb_cascade_fail {_tbl}: {type(_e).__name__}: {str(_e)[:100]}')

        # Friend-Edges anderer User auf diesen Token (crew_edges.other_id ist die
        # Gegenrichtung — Rows in denen DIESER Token referenziert wird). Strikt
        # token-scoped: eq auf den fremd-referenzierenden Wert, kein Broad-Delete.
        try:
            _r = sb.table('crew_edges').delete().eq('other_id', token).execute()
            sb_deleted['crew_edges_other'] = len((_r and getattr(_r, 'data', None)) or [])
        except Exception as _e:
            app.logger.warning(f'[delete] sb_cascade_fail crew_edges_other: {str(_e)[:100]}')

        # ── Steuer-Sessions / Jobs / Job-Chunks ──────────────────────────────
        # Die sensibelste Tabelle: sessions.result_data (komplette Steuer-Aus-
        # wertung). sessions ist NICHT per Auth-Token gekeyed, sondern per kurz-
        # lebigem session_token; SB-Row trägt aber eine job_id-Spalte. Die job_ids
        # des Users stehen in seiner History-Datei (_user_history). Wir leiten die
        # job_ids daraus ab und löschen sessions/jobs/job_chunks STRIKT per job_id
        # (nur Jobs die DIESER User ausgewertet hat).
        try:
            _hist = _user_history_load(token) or {}
            _job_ids = []
            for _e in (_hist.get('entries') or []):
                _jid = _e.get('job_id') if isinstance(_e, dict) else None
                if _jid and _jid not in _job_ids:
                    _job_ids.append(_jid)
            _sess_n = _jobs_n = _chunks_n = 0
            for _jid in _job_ids:
                try:
                    _r = sb.table('sessions').delete().eq('job_id', _jid).execute()
                    _sess_n += len((_r and getattr(_r, 'data', None)) or [])
                except Exception: pass
                try:
                    _r = sb.table('jobs').delete().eq('job_id', _jid).execute()
                    _jobs_n += len((_r and getattr(_r, 'data', None)) or [])
                except Exception: pass
                try:
                    _r = sb.table('job_chunks').delete().eq('job_id', _jid).execute()
                    _chunks_n += len((_r and getattr(_r, 'data', None)) or [])
                except Exception: pass
            if _job_ids:
                sb_deleted['sessions'] = _sess_n
                sb_deleted['jobs'] = _jobs_n
                sb_deleted['job_chunks'] = _chunks_n
        except Exception as _e:
            app.logger.warning(f'[delete] sb_sessions_cascade_fail: {str(_e)[:120]}')

        # ── Family-Shares (beide Richtungen) ─────────────────────────────────
        # family_shares-Row: {crew_token, family_token}. Dieser Token kann als
        # Crew (teilt) ODER als Family (empfängt) auftreten → beide Spalten.
        try:
            _r = sb.table('family_shares').delete().eq('crew_token', token).execute()
            sb_deleted['family_shares_crew'] = len((_r and getattr(_r, 'data', None)) or [])
        except Exception as _e:
            app.logger.warning(f'[delete] sb_family_shares_crew_fail: {str(_e)[:100]}')
        try:
            _r = sb.table('family_shares').delete().eq('family_token', token).execute()
            sb_deleted['family_shares_family'] = len((_r and getattr(_r, 'data', None)) or [])
        except Exception as _e:
            app.logger.warning(f'[delete] sb_family_shares_family_fail: {str(_e)[:100]}')

        # family_scoped_tokens (KV: key=family_token, data.crew_token) +
        # family_pair_codes (KV: key=code, data.crew_token). Beide Tabellen tragen
        # die crew_token-Referenz IN der jsonb-`data`-Spalte → laden, eigene Keys
        # ermitteln, einzeln per Key löschen (kein Broad-Delete).
        for _kv_tbl, _kv_key in (('family_scoped_tokens', 'family_token'),
                                 ('family_pair_codes', 'code')):
            try:
                _all = sb.table(_kv_tbl).select('*').execute()
                _del_keys = []
                for _row in (_all.data or []):
                    _d = _row.get('data') or {}
                    _k = _row.get(_kv_key)
                    if _k and isinstance(_d, dict) and _d.get('crew_token') == token:
                        _del_keys.append(_k)
                for _k in _del_keys:
                    try:
                        sb.table(_kv_tbl).delete().eq(_kv_key, _k).execute()
                    except Exception: pass
                if _del_keys:
                    sb_deleted[_kv_tbl] = len(_del_keys)
            except Exception as _e:
                app.logger.warning(f'[delete] sb_{_kv_tbl}_fail: {str(_e)[:100]}')

        _summary = ', '.join(f'{k}={v}' for k, v in sb_deleted.items() if v)
        app.logger.info(f'[delete] sb_cascade_done token={(token or "")[:8]} {_summary or "(no rows)"}')
        deleted.append(f'sb_cascade:{{{_summary}}}')

    # 4. Forum-Threads mit diesem author_token
    try:
        threads = _forum_load_threads()
        new_threads = [t for t in threads if t.get('author_token') != token]
        if len(new_threads) != len(threads):
            _forum_save_threads(new_threads)
            deleted.append(f'forum_threads:{len(threads) - len(new_threads)}')
    except Exception:
        pass

    # 5. Wall-Likes-File
    likes_p = _wall_likes_path(token)
    if likes_p and os.path.exists(likes_p):
        try: os.remove(likes_p); deleted.append('wall_likes')
        except Exception: pass

    # 6. Forum-Likes-File
    flikes_p = _forum_likes_path(token)
    if flikes_p and os.path.exists(flikes_p):
        try: os.remove(flikes_p); deleted.append('forum_likes')
        except Exception: pass

    # 7. Aus friends-Liste anderer User entfernen (best-effort)
    try:
        friends_dir = os.path.join(_USER_HISTORY_DIR)
        for fn in os.listdir(friends_dir):
            if not fn.startswith('friends_'): continue
            fp = os.path.join(friends_dir, fn)
            try:
                with open(fp) as f: data = json.load(f) or {}
                fl = data.get('friends') or []
                if token in fl:
                    data['friends'] = [t for t in fl if t != token]
                    with open(fp, 'w') as f: json.dump(data, f)
            except Exception: pass
    except Exception:
        pass

    return jsonify({'ok': True, 'deleted': deleted})


# ════════════════════════════════════════════════════════════════════
#  DSGVO Art. 15 — Auskunftsrecht / Datenexport  (Wave-1 BUG-005, 2026-06-02)
# ════════════════════════════════════════════════════════════════════

# Credential-artige Feldnamen, die NIE in den herunterladbaren Export gehören
# (Owner-Fund 2026-07-15: der Export gab lebende Auth-Tokens — eigene UND fremde
# aus Wall/Forum/DM/Friends/Family — sowie Push-Tokens preis). Art. 15 gibt dem
# Nutzer SEINE Daten, aber keine Credentials.
_EXPORT_SECRET_KEYS = {
    'token', 'author_token', 'owner_token', 'friend_token', 'family_token',
    'crew_token', 'user_token', 'mentioned_token', 'session_token',
    'apns_token', 'expo_token', 'device_token', 'push_token', 'access_token',
    'refresh_token',
}

def _export_friend_entries(raw_friends):
    """SECURITY (2026-07-15): Friends-Export ohne lebende Credentials.

    Die Disk-Friends-Liste besteht aus NACKTEN Voll-Tokens (= Bearer-
    Credentials der Freunde); `_redact_export_secrets` maskiert nur dict-Werte
    per Key, blanke Listen-Strings liefen durch. Export deshalb ausschließlich
    als pseudonyme, nicht zurückrechenbare Kennung (SHA-256-Stub; bewusst KEIN
    [:8]-Klartext-Präfix — das dient anderswo als Legacy-Ownership-Schlüssel).
    """
    out = []
    for t in (raw_friends or []):
        out.append({
            'friend_id': hashlib.sha256(str(t).encode('utf-8')).hexdigest()[:12],
            'friend_token': '[redacted]',
        })
    return out


def _redact_export_secrets(obj):
    """Maskiert rekursiv Auth-/Push-Tokens und die geheime iCal-Feed-URL im
    DSGVO-Export. Struktur und alle nicht-geheimen Inhalte bleiben unverändert;
    fremde Account-Tokens (Freunde/Family/Autoren) werden NIE mit ausgegeben."""
    if isinstance(obj, dict):
        # Eine iCal-Feed-URL (`{url, events, ...}`) trägt oft ein Crew-Portal-
        # Secret in der Query → maskieren; normale `*_url` (Avatar) bleiben.
        is_feed = 'url' in obj and 'events' in obj
        out = {}
        for k, v in obj.items():
            kl = str(k).lower()
            if kl in _EXPORT_SECRET_KEYS and isinstance(v, str) and v:
                out[k] = '[redacted]'
            elif kl == 'url' and is_feed and isinstance(v, str) and v:
                out[k] = '[redacted]'
            else:
                out[k] = _redact_export_secrets(v)
        return out
    if isinstance(obj, list):
        return [_redact_export_secrets(x) for x in obj]
    return obj

@app.route('/api/auth/export-data', methods=['GET', 'POST'])
def auth_export_data():
    """DSGVO Art. 15 — User exportiert alle gespeicherten Daten als JSON.

    Auth via Bearer-Token im Authorization-Header ODER per ?token=... Query-Param
    ODER per body.token (POST). iOS APIClient.exportData() schickt den Header.

    Response: application/json mit Content-Disposition attachment header
    (iOS speichert direkt als file). Felder: profile, wall_posts (own),
    wall_comments (own), friends, employers, voice_notes_metadata,
    briefings, ical_events, license_wallet_items.
    """
    # Token aus Header > Query > Body
    auth_h = (request.headers.get('Authorization') or '').strip()
    token = None
    if auth_h.lower().startswith('bearer '):
        token = auth_h[7:].strip()
    if not token:
        token = (request.args.get('token') or '').strip()
    if not token and request.method == 'POST':
        body = request.get_json(silent=True) or {}
        token = (body.get('token') or '').strip()
    if not token:
        return jsonify({'ok': False, 'error': 'missing_token'}), 401

    # Validate via auth_users (gleiche Quelle wie _validate_token_exists)
    user_email = _validate_token_exists(token)
    if user_email is None:
        return jsonify({'ok': False, 'error': 'unauthorized'}), 401

    export = {
        'meta': {
            'token': token,
            'email': user_email,
            'exported_at': datetime.now().isoformat(),
            'export_version': '1.0',
            'dsgvo_article': 'Art. 15 EU-DSGVO (Right to Access)',
        },
        'profile': {},
        'friends': [],
        'wall_posts': [],
        'wall_comments': [],
        'voice_notes_metadata': [],
        'briefings': [],
        'ical_events': [],
        'license_wallet_items': [],
        'family_shares_granted': [],
    }

    # ── Profile ────────────────────────────────────────────────────────
    try:
        pp = _user_profile_path(token)
        if pp and os.path.exists(pp):
            with open(pp) as f:
                export['profile'] = json.load(f) or {}
    except Exception as e:
        export['profile'] = {'_read_error': str(e)[:200]}

    # ── Friends ────────────────────────────────────────────────────────
    try:
        fr = _friends_load(token) or {}
        # SECURITY (Rest-Leak-Fix 2026-07-15): nackte Friend-Tokens NIE
        # exportieren — Details am Helper `_export_friend_entries`.
        export['friends'] = _export_friend_entries(fr.get('friends'))
    except Exception as e:
        export['friends'] = []
        export['_friends_error'] = str(e)[:200]

    # ── Wall-Posts (own) + Wall-Comments (own) ─────────────────────────
    try:
        all_posts = _wall_load_posts() or []
        export['wall_posts'] = [p for p in all_posts if p.get('author_token') == token]
        # Comments: pro Post-Datei lesen, filtern auf author_token
        own_comments = []
        for p in all_posts:
            try:
                cmts = _wall_comments_load(p.get('id')) or []
                for c in cmts:
                    if c.get('author_token') == token:
                        own_comments.append({**c, 'post_id': p.get('id')})
            except Exception:
                pass
        export['wall_comments'] = own_comments
    except Exception as e:
        export['_wall_error'] = str(e)[:200]

    # ── Voice-Notes (Metadata-only, KEIN m4a-Inhalt) ────────────────────
    try:
        safe = re.sub(r'[^A-Za-z0-9_-]', '', token)[:64]
        vn_dir = os.path.join(_USER_HISTORY_DIR, 'voice_notes', safe)
        if os.path.isdir(vn_dir):
            for fn in os.listdir(vn_dir):
                fp = os.path.join(vn_dir, fn)
                try:
                    st = os.stat(fp)
                    export['voice_notes_metadata'].append({
                        'filename': fn,
                        'size_bytes': st.st_size,
                        'modified_iso': datetime.fromtimestamp(st.st_mtime).isoformat(),
                    })
                except Exception:
                    pass
    except Exception as e:
        export['_voice_notes_error'] = str(e)[:200]

    # ── Flight-Ops (Per-Flight-Operational-Details, SB-primary) ─────────
    # Vom User getippte Catering/Pax/Fuel/SSR/Endorsement-Daten. Fehlte bisher
    # im DSGVO-Export (Audit-Fund) — jetzt aus _flight_ops_load (SB→Disk).
    try:
        export['flight_ops'] = _flight_ops_load(token) or {}
    except Exception as e:
        export['_flight_ops_error'] = str(e)[:200]

    # ── Supabase-Quellen (DSGVO Art. 15: vollständig, SB-primary) ───────
    # Vorher kam der Export grösstenteils von der ephemeren Disk (auf Cloud Run
    # leer/teilweise) und LIESS die sensibelsten Daten aus: die Steuer-Sessions
    # (sessions.result_data), DM-Nachrichten, Push-Tokens, Profil (SB-Version).
    # Jetzt aus SB für dieselben Tabellen wie die Delete-Cascade, best-effort.
    if SB_AVAILABLE and sb is not None:
        # Profil (SB-Version ergänzt/überschreibt die Disk-Version)
        try:
            r = sb.table('user_profiles').select('*').eq('token', token).execute()
            if r.data:
                export['profile'] = {**(export.get('profile') or {}), '_supabase': r.data}
        except Exception:
            pass
        try:
            r = sb.table('briefings').select('*').eq('user_token', token).execute()
            export['briefings'] = r.data or []
        except Exception as e:
            export['_briefings_error'] = str(e)[:200]
        try:
            r = sb.table('ical_events').select('*').eq('user_token', token).execute()
            export['ical_events'] = r.data or []
        except Exception:
            pass
        try:
            r = sb.table('user_licenses').select('*').eq('user_token', token).execute()
            export['license_wallet_items'] = r.data or []
        except Exception:
            pass
        try:
            r = (sb.table('family_shares').select('*')
                 .eq('crew_token', token).eq('deleted', False).execute())
            export['family_shares_granted'] = r.data or []
        except Exception:
            pass
        # Family-Shares die DIESER Token als Family EMPFÄNGT
        try:
            r = (sb.table('family_shares').select('*')
                 .eq('family_token', token).eq('deleted', False).execute())
            export['family_shares_received'] = r.data or []
        except Exception:
            pass
        # Wall-Posts/Comments (SB-Version, eigene)
        try:
            r = sb.table('wall_posts').select('*').eq('author_token', token).execute()
            export['wall_posts_supabase'] = r.data or []
        except Exception:
            pass
        try:
            r = sb.table('wall_comments').select('*').eq('author_token', token).execute()
            export['wall_comments_supabase'] = r.data or []
        except Exception:
            pass
        # Forum (eigene Threads + Replies)
        try:
            r = sb.table('forum_threads').select('*').eq('author_token', token).execute()
            export['forum_threads'] = r.data or []
        except Exception:
            pass
        try:
            r = sb.table('forum_replies').select('*').eq('author_token', token).execute()
            export['forum_replies'] = r.data or []
        except Exception:
            pass
        # Direct-Messages (eigene gesendete Nachrichten)
        try:
            r = sb.table('dm_messages').select('*').eq('author_token', token).execute()
            export['dm_messages'] = r.data or []
        except Exception:
            pass
        # Friends (SB-Version)
        try:
            r = sb.table('user_friends').select('*').eq('owner_token', token).execute()
            export['friends_supabase'] = r.data or []
        except Exception:
            pass
        # Push-Tokens
        try:
            r = sb.table('user_push_tokens').select('*').eq('user_token', token).execute()
            export['push_tokens'] = r.data or []
        except Exception:
            pass
        try:
            # Installation metadata is personal data; raw APNs bearer-like
            # endpoint tokens are intentionally omitted from the export JSON.
            r = (sb.table('push_installations').select(
                'id,bundle_id,environment,device_id,platform,active,'
                'registered_at,account_bound_at,tombstoned_at,tombstone_reason')
                .eq('user_token', token).execute())
            export['push_installations'] = r.data or []
        except Exception:
            pass
        # Layover-Reviews (eigene)
        try:
            r = sb.table('layover_reviews').select('*').eq('user_token', token).execute()
            export['layover_reviews'] = r.data or []
        except Exception:
            pass
        # ── Steuer-Sessions (DAS sensibelste Datum: result_data) ─────────
        # sessions ist per session_token gekeyed; die job_ids des Users stehen in
        # seiner History. Wir exportieren die kompletten Session-Rows (inkl.
        # result_data) für jede eigene job_id.
        try:
            hist = _user_history_load(token) or {}
            job_ids = []
            for e in (hist.get('entries') or []):
                jid = e.get('job_id') if isinstance(e, dict) else None
                if jid and jid not in job_ids:
                    job_ids.append(jid)
            tax_sessions = []
            for jid in job_ids:
                try:
                    r = sb.table('sessions').select('*').eq('job_id', jid).execute()
                    tax_sessions.extend(r.data or [])
                except Exception:
                    pass
            export['tax_sessions'] = tax_sessions
            export['tax_history'] = hist.get('entries') or []
        except Exception as e:
            export['_tax_sessions_error'] = str(e)[:200]

    # ── Sicherheit: Credentials maskieren, BEVOR die Datei rausgeht ─────
    # Art. 15 gibt dem Nutzer seine Daten, aber keine lebenden Auth-Tokens
    # (eigene ODER fremde), Push-Tokens oder das Geheimnis in der iCal-Feed-URL
    # (Owner-Fund 2026-07-15). Rekursiv über den gesamten Export.
    export = _redact_export_secrets(export)

    # JSON-Response mit attachment-Header (iOS speichert als File)
    today_str = datetime.now().date().isoformat()
    fname = f'aerox-export-{today_str}.json'
    payload = json.dumps(export, ensure_ascii=False, indent=2, default=str)
    resp = make_response(payload)
    resp.headers['Content-Type'] = 'application/json; charset=utf-8'
    resp.headers['Content-Disposition'] = f'attachment; filename="{fname}"'
    return resp


# ── UGC-Moderation (Apple Guideline 1.4.1) ─────────────────────────────
# Report (Inhalts-Meldung), Block (User komplett ausblenden), Mute (nur
# Notifications stumm). Globale reports_log.json sammelt für Review,
# per-User blocks_<token>.json / mutes_<token>.json filtern Feed/Forum.

def _safe_token(t):
    return re.sub(r'[^A-Za-z0-9_-]', '', t or '')[:64]

def _blocks_path(token):
    s = _safe_token(token)
    return os.path.join(_USER_HISTORY_DIR, f'blocks_{s}.json') if s else None

def _mutes_path(token):
    s = _safe_token(token)
    return os.path.join(_USER_HISTORY_DIR, f'mutes_{s}.json') if s else None

def _load_set_file(path):
    if not path or not os.path.exists(path): return set()
    try:
        with open(path) as f:
            return set(json.load(f) or [])
    except Exception:
        return set()

def _save_set_file(path, s):
    if not path: return
    try:
        _atomic_write_json(path, sorted(list(s)))
    except Exception:
        try:
            with open(path, 'w') as f: json.dump(sorted(list(s)), f)
        except Exception: pass

def _blocked_by(token):
    """Set von Tokens die der User geblockt hat."""
    return _load_set_file(_blocks_path(token))

def _muted_by(token):
    return _load_set_file(_mutes_path(token))


# ── Airport Live-Board (FRA) — KOSTENLOSE öffentliche Fraport-JSON-Quelle ──
# https://www.frankfurt-airport.com/de/_jcr_content.flights.json (?page=N) liefert
# Abflüge mit reg/gate/status/delay. Wir proxyen + cachen serverseitig (iOS hätte
# ATS/CORS-Probleme + die Quelle blockt evtl. Direct-Clients). KEINE Erfindung —
# 1:1 was Fraport liefert; bei Quelle-down → ehrlicher source_unavailable.
_AIRPORT_BOARD_CACHE = {}     # key -> (ts, list)
_AIRPORT_BOARD_TTL = 120      # 2 Min — Board ändert sich nicht schneller sinnvoll.
# Volle Tages-Tafel (für Pünktlichkeit) separat + länger gecacht — viele Seiten,
# teurer zu holen, ändert sich für die Tagesstatistik nicht im Minutentakt.
_AIRPORT_DAY_CACHE = {}        # key -> (ts, list)
_AIRPORT_DAY_TTL = 180         # 3 Min — für Delay-Capture-Genauigkeit reduziert (war 5 Min).
# AeroDataBox-Pünktlichkeit (Nicht-FRA-Airports, RapidAPI, env-gated). Aggressiv
# gecacht — Free-Tier = 600 Units/Monat, also pro (airport,airline) 15 Min TTL.
# key (airport, airline) -> (ts, result-dict).
_AERODATABOX_CACHE = {}
_AERODATABOX_TTL = 900         # 15 Min.

# ── EINE Pünktlichkeits-Schwelle für ALLE Pfade (Live-Board-Flag, Store-Replay,
# historische Aggregation, AeroDataBox) ───────────────────────────────────────
# DELAY_THRESHOLD_MIN: ein Abflug gilt ab dieser Verspätung (Minuten) als
# „verspätet". 15 Minuten ist die international übliche On-Time-Performance-
# Definition (D15: „pünktlich = innerhalb 15 Min nach Plan", wie Eurocontrol/
# OAG/Lufthansa-OTP). Vorher 5 Min — das klassifizierte deutlich mehr Flüge als
# verspätet als die offizielle Branchenkennzahl und machte die Quote unnötig
# pessimistisch. Mit 15 Min ist „Pünktlichkeit heute" vergleichbar mit der
# veröffentlichten Airline-OTP. Die Schwelle ist EHRLICH dokumentiert und wird
# in der API-Antwort als `delay_threshold_min` mitgeliefert, damit die UI sie
# benennen kann („pünktlich = max. 15 Min Verspätung"). EINE Quelle der Wahrheit:
# alle delayed-Flags + alle Aggregationspfade lesen diesen Wert, sonst springt
# das Urteil eines Fluges beim Wechsel Live→Replay.
_DELAY_THRESHOLD_MIN = 15
_AERODATABOX_DELAY_THRESHOLD = _DELAY_THRESHOLD_MIN  # identisch zu FRA/Store.

# Per-Airport-Board-Cache (native Scraper + AeroDataBox-Board). Eigener Topf,
# getrennt vom FRA-Board. key (IATA, type, source) -> (ts, list). 12 Min TTL —
# Board-Daten ändern sich nicht schneller sinnvoll, und schont fremde Quellen.
_NATIVE_BOARD_CACHE = {}
_NATIVE_BOARD_TTL = 720        # 12 Min.

# „Last-known-good"-Board-Snapshot je (airport, type, airline). Wenn ALLE Live-
# Quellen (Fraport/native/AeroDataBox/OpenSky) im Moment down/leer sind, serviert
# das Board die ZULETZT erfolgreich zusammengestellte, fertige Liste (als `stale`
# markiert) statt einer leeren Tafel / source_unavailable. Hintergrund (User: „bei
# der Tafel fehlen wieder Flüge … will dass sie nur mit Backend kommuniziert um die
# richtigen fertigen Infos zu holen"): die App liest weiter backend-fertige Infos,
# auch wenn die externe Quelle gerade einen Schluckauf hat. Nach _MAX_AGE lieber
# ehrlich „nicht erreichbar" als eine veraltete Tafel.
_BOARD_LAST_GOOD = {}          # (airport, type, airline) -> (ts, flights, departed)
_BOARD_LAST_GOOD_MAX_AGE = 1800  # 30 Min.


def _clean_city_name(name, iata=''):
    """Fraport `apname` kann nicht-lateinische Schreibweisen liefern (z.B.
    chinesische Stadtnamen wie '多特蒙德'). HARTE Anforderung: KEINE CJK/nicht-
    lateinischen Zeichen in der iOS-Tafel. Strategie: enthält der Name Zeichen
    außerhalb des Latin-1/Latin-Extended-Bereichs (oder gängiger Akzente), fällt
    er auf den IATA-Code zurück. Sonst 1:1 der Name."""
    s = (name or '').strip()
    if not s:
        return (iata or '').strip()
    # Erlaubt: ASCII + Latin-1-Supplement/Extended (Umlaute, Akzente, ß),
    # Satzzeichen/Leerzeichen. Alles ab U+0250 (IPA/CJK/Kyrillisch/Arabisch/…)
    # gilt als nicht-lateinisch → Code-Fallback.
    for ch in s:
        o = ord(ch)
        if o > 0x024F:
            return (iata or '').strip() or s
    return s


# ── Bahn/Bus-Filter (Lufthansa Express Rail / AIRail) ──────────────────────
# Produkt-Vorgabe: "es sollen nur Flieger sein". Fraport listet ICE-Züge unter
# LH-Flugnummern auf der Tafel (Lufthansa Express Rail, früher AIRail). Diese
# Einträge sind KEINE Flüge und dürfen weder im Board noch in der Pünktlichkeits-
# quote auftauchen.
#
# Live verifizierte Marker im Fraport-Feed (2026-06, dep+arr):
#   ac  == 'TRS'   → Fraport-„Aircraft"-Code für AIRail-Züge (jeder Zug-Eintrag)
#   reg  startswith 'ICE' → ICE-Zugnummer statt Luftfahrzeug-Kennung (z.B. ICE616)
#   apname endet auf Bahnhof ("… Central St.", "… Main St.", "… Railway St")
# Beispiel-Ziele: ZMB Hamburg, ZMU München, QPP Berlin, QDU Düsseldorf, DTZ
# Dortmund. ACHTUNG: NICHT auf rohem IATA-Prefix Z*/X* filtern — ZRH (Zürich)
# und andere echte Airports beginnen ebenfalls mit Z, und Bahnhöfe haben auch
# Q*/D*-Codes (QPP, QDU, DTZ). Darum: ac/reg/Stationsname als Marker, plus eine
# kuratierte Whitelist bekannter LH-Express-Rail-Bahnhofs-IATA-Codes als Backstop.

# Bekannte Lufthansa-Express-Rail-/AIRail-Bahnhofs-IATA-Codes (Fraport/IATA-
# „City/Rail"-Codes). Backstop, falls der ac/reg-Marker mal fehlt.
_RAIL_STATION_IATA = {
    'ZPP',  # Siegburg/Bonn ICE
    'QKL',  # Köln Hbf (alt)
    'QDU',  # Düsseldorf Hbf
    'DTZ',  # Dortmund Hbf
    'ZMB',  # Hamburg Hbf
    'ZMU',  # München Hbf
    'QPP',  # Berlin Hbf
    'ZWS',  # Stuttgart Hbf
    'QFB',  # Freiburg Hbf
    'XHQ',  # Stuttgart (Rail)
    'ZNV',  # Nürnberg Hbf
    'BNF',  # Bonn (Rail)
    'ZBA',  # Basel Bad Bahnhof
    'XIK',  # Karlsruhe Hbf
    'QWU',  # Würzburg Hbf
    'ZCB',  # Ulm Hbf
}

# „Aircraft"-/Equipment-Codes, die KEIN Luftfahrzeug sind (Bahn/Bus).
_NON_AIRCRAFT_EQUIP = {'TRS', 'RAIL', 'TRN', 'TRA', 'BUS', 'ICE', 'BAH', 'AIR'}

# Reg-/Kennungs-Präfixe, die einen Zug/Bus statt eines Flugzeugs markieren.
_RAIL_REG_PREFIXES = ('ICE', 'IC ', 'RAIL', 'TRN', 'BUS', 'TRS')


def _is_rail_or_bus(flight):
    """True, wenn der Eintrag ein Bahn-/Bus-Segment ist (Lufthansa Express Rail /
    AIRail, ICE-Züge unter LH-Flugnummern) — KEIN echtes Flugzeug-Segment.

    Robust gegen Feld-Varianten: prüft Equipment-Code (`aircraft`/`ac`),
    Registrierung (`reg`, z.B. 'ICE616'), kuratierte Bahnhofs-IATA-Whitelist und
    den Stationsnamen ('… Hbf'/'… Railway St'/'Bahnhof'). Greift sowohl auf die
    normalisierte FRA-Zeile als auch direkt auf das rohe Fraport-/AeroDataBox-
    Dict (Keys `ac`/`aircraft`)."""
    if not isinstance(flight, dict):
        return False
    # 1) Equipment-/Aircraft-Code (normalisiert: 'aircraft'; roh: 'ac').
    equip = (flight.get('aircraft') or flight.get('ac') or '').strip().upper()
    if equip in _NON_AIRCRAFT_EQUIP:
        return True
    # 2) Registrierung — ICE-Zugnummer statt Luftfahrzeug-Kennung.
    reg = (flight.get('reg') or '').strip().upper()
    if reg:
        for p in _RAIL_REG_PREFIXES:
            if reg.startswith(p):
                return True
    # 3) Kuratierte Bahnhofs-IATA-Whitelist (Backstop).
    dest = (flight.get('dest_iata') or flight.get('iata') or '').strip().upper()
    if dest and dest in _RAIL_STATION_IATA:
        return True
    # 4) Stationsname als letzte Absicherung (Bahnhof/Railway/Hbf).
    name = (flight.get('dest_name') or flight.get('apname') or '').strip().lower()
    if name:
        for marker in ('railway st', 'central st.', 'central station',
                       'main st.', 'main station', 'hauptbahnhof', 'hbf',
                       'bahnhof', ' bf', 'train station'):
            if marker in name:
                return True
    return False


# Fraport liefert `status` teils CJK-/fremdsprachig (z.B. '登机' = Boarding) — analog
# zu _clean_city_name (das Städtenamen entCJK-t) auf sauberes Deutsch normalisieren,
# sonst stehen chinesische Zeichen auf Tafel + Flug-Info (User: „chinesische zahlen").
_FRA_STATUS_DE = {
    '登机': 'Boarding', '登机口开放': 'Boarding', '登机口即将关闭': 'Last Call',
    '登机口关闭': 'Gate zu', '最后登机': 'Last Call', '值机': 'Check-in',
    '已起飞': 'Abgeflogen', '起飞': 'Abgeflogen', '出发': 'Abgeflogen',
    '已降落': 'Gelandet', '降落': 'Gelandet', '抵达': 'Gelandet',
    '取消': 'Annulliert', '已取消': 'Annulliert', '延误': 'Verspätet',
    '准时': 'Pünktlich', '预计': 'Erwartet', '计划': 'Geplant',
    # Live verifiziert 2026-07-05 (Vergangenheits-Seiten + Arrivals-Filter-Feed
    # liefern weitere CJK-Varianten — vorher fielen sie auf '' und die Zeile
    # verlor ihren IST-Status → delay_known blieb fälschlich unbekannt):
    '已着陆': 'Gelandet',           # gelandet (Varianten-Schreibweise)
    '至机位': 'Gelandet',           # on position / at gate
    '托运行李领取': 'Gelandet',      # baggage claim → definitiv angekommen
    '在飞行中': 'Unterwegs',        # in flight (Ankunfts-Kontext)
    '延誤的航班': 'Verspätet',       # verspäteter Flug (traditionell)
    '延误的航班': 'Verspätet',       # verspäteter Flug (vereinfacht)
}
# Fraport liefert ZUSÄTZLICH englische Status-Strings (approaching/landed/departed
# /boarding…). KONTEXT IST KRITISCH: bei einer ANKUNFT heißt `departed`, dass der
# Inbound-Flieger seinen HERKUNFTS-Flughafen verlassen hat (= unterwegs nach FRA) —
# NICHT „Abgeflogen" (Bug „Ankunftstafel sagt ab obwohl es an ist", User 2026-06-25).
_EN_STATUS_COMMON = {
    'cancelled': 'Annulliert', 'canceled': 'Annulliert', 'delayed': 'Verspätet',
    'scheduled': 'Geplant', 'planned': 'Geplant', 'on time': 'Pünktlich',
    'boarding': 'Boarding', 'last call': 'Last Call', 'gate closed': 'Gate zu',
    'gate open': 'Gate offen', 'check-in': 'Check-in', 'expected': 'Erwartet',
    'delayed departure': 'Verspätet', 'diverted': 'Umgeleitet',
}
_EN_STATUS_ARR = {   # Ankunfts-Kontext
    'departed': 'Unterwegs', 'en route': 'Unterwegs', 'enroute': 'Unterwegs',
    'in flight': 'Unterwegs', 'approaching': 'Im Anflug', 'expected': 'Erwartet',
    'landed': 'Gelandet', 'on position': 'Gelandet', 'on blocks': 'Gelandet',
    'arrived': 'Gelandet', 'at gate': 'Gelandet',
}
_EN_STATUS_DEP = {   # Abflugs-Kontext
    'departed': 'Abgeflogen', 'lifted off': 'Abgeflogen', 'airborne': 'Abgeflogen',
    # Fraport-DE „Position verlassen" = off-blocks/Pushback → der Flug ist weg
    # (Vergangenheits-Seiten tragen den Status; ohne Mapping stünde er als
    # „anstehend" auf der Tafel und ohne IST-Signal im Warehouse).
    'position verlassen': 'Abgeflogen',
}
def _de_flight_status(raw, is_arr=False):
    """Fraport-Status → sauberes Deutsch, ANKUNFTS-/ABFLUGS-bewusst. Bekannte CJK-
    und englische Strings gemappt; unbekanntes CJK → LEER (iOS leitet den Zustand
    aus delay_min/cancelled ab), nie rohe chinesische Zeichen anzeigen."""
    s = (raw or '').strip()
    if not s:
        return ''
    if s in _FRA_STATUS_DE:
        return _FRA_STATUS_DE[s]
    low = s.lower()
    if is_arr and low in _EN_STATUS_ARR:
        return _EN_STATUS_ARR[low]
    if (not is_arr) and low in _EN_STATUS_DEP:
        return _EN_STATUS_DEP[low]
    if low in _EN_STATUS_COMMON:
        return _EN_STATUS_COMMON[low]
    # CJK (Chinesisch/Japanisch/Koreanisch) erkannt → nicht anzeigen.
    if any('　' <= c <= '鿿' or '가' <= c <= '힯' for c in s):
        return ''
    return s


_PRE_DEP_STATUS = {'', 'geplant', 'boarding', 'gate', 'gate zu', 'gate offen',
                   'check-in', 'erwartet', 'last call', 'planned', 'scheduled'}
def _departed_status(stored, cancelled, is_arr):
    """Status einer BEREITS ABGEFLOGENEN „Früher heute"-Zeile: ein veralteter
    Vor-Abflug-Status (Geplant/Boarding/Gate) wird durch Abgeflogen/Gelandet ersetzt
    (der Flug ist weg, „Geplant" ist falsch — User). Echte Info (verspätet etc.) bleibt."""
    if cancelled:
        return 'Annulliert'
    s = _de_flight_status(stored)
    if s.lower() in _PRE_DEP_STATUS:
        return 'Gelandet' if is_arr else 'Abgeflogen'
    return s


# Wie viele VERGANGENHEITS-Seiten (page=-1, -2, …) der Fraport-Feed mitliest.
# WAREHOUSE-ROOT-CAUSE-FIX 2026-07-05 („LH918/LH919/LH1455 landen NIE in
# airport_delay_obs"): der Fraport-Feed ist NOW-relativ — Seite 1 beginnt bei
# „jetzt", gelandete/abgeflogene Flüge wandern BINNEN MINUTEN auf negative
# Seiten (live verifiziert: `minpage:-60`, page=-1 trägt die Flüge der letzten
# ~15-25 min inkl. finalem Status/esti/Reg). Der bisherige Scrape (nur Seiten
# 1..N) sah Vergangenheit also NIE; persistiert wurde nur, was in der
# Minuten-Lücke „sched gerade passiert, aber noch auf Seite 1" von einem
# 10-min-Poll zufällig erwischt wurde → Ankünfte fehlten fast komplett,
# Abflüge lückenhaft. 6 Seiten ≈ 150 Flüge ≈ ~2 h Vergangenheit — deckt jede
# Poll-Lücke sicher ab (In-Memory-Store + SB akkumulieren den Rest des Tages).
_FRA_PAST_PAGES = 6


def _fetch_fra_flights(flight_type='departure', max_pages=3, past_pages=0):
    # `requests` ist in app.py NICHT module-level importiert → lokaler Import.
    # flight_type='arrival' → Fraport-Filter-Endpoint; `iata`/`apname` ist dann
    # der HERKUNFTS-Flughafen (iOS labelt "von X" via `type`).
    try:
        import requests
    except Exception:
        return None
    base = 'https://www.frankfurt-airport.com/de/_jcr_content.flights.json'
    if flight_type == 'arrival':
        base = base + '/filter'
    headers = {
        'User-Agent': 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) '
                      'AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.0 Mobile/15E148',
        'Accept': 'application/json',
    }

    def _fetch_page(page):
        """(normalisierte Rows, Roh-Anzahl) einer Feed-Seite oder None bei
        HTTP-Fehler. page=1 ohne Param (wie die echte Webseite), sonst ?page=N —
        auch NEGATIV (Vergangenheit); page=0 existiert nicht (Fraport coerct auf 1)."""
        params = {}
        if flight_type == 'arrival':
            # FIX 2026-06-25: Fraport-Filter-Param ist `flighttype=arrivals`
            # (so ruft die echte Ankunfts-Seite ankuenfte.html den /filter-
            # Endpoint auf). Der bisherige `type=arrival` wurde von Fraport
            # IGNORIERT → der Endpoint lieferte ABFLÜGE, die wir fälschlich als
            # Ankünfte zeigten (FRA-Ankunftstafel = Abflüge mit Zielen/„Boarding").
            params['flighttype'] = 'arrivals'
        if page != 1:
            params['page'] = page
        r = requests.get(base, params=params, headers=headers, timeout=8)
        if r.status_code != 200:
            return None
        data = (r.json() or {}).get('data') or []
        rows = []
        for f in data:
            # Bahn/Bus (LH Express Rail / AIRail ICE) raus — nur Flieger.
            # Roh-Dict prüfen (ac/iata/apname/reg) BEVOR normalisiert wird.
            if _is_rail_or_bus(f):
                continue
            rows.append({
                'airline': (f.get('al') or '').strip(),
                'airline_name': (f.get('alname') or '').strip(),
                'flight': (f.get('fnr') or '').replace(' ', ''),
                # bei Ankunft = Herkunft, bei Abflug = Ziel.
                'dest_iata': (f.get('iata') or '').strip(),
                # CJK/nicht-lateinische Stadtnamen → IATA-Code-Fallback
                # (harte iOS-Anforderung, kein '多特蒙德' auf der Tafel).
                'dest_name': _clean_city_name(f.get('apname'), f.get('iata')),
                'sched': f.get('sched'),
                # `esti` = geschätzte Zeit → ECHTE Verspätung (esti vs sched).
                # `s` (Fraport-Delay-Flag) ist bei Vorab-Flügen immer False,
                # daher unbrauchbar → wir rechnen aus esti. Auf VERGANGENHEITS-
                # Seiten ist esti die IST-Zeit (tatsächlich gelandet/abgeflogen).
                'esti': f.get('esti'),
                'delay_min': _fra_delay_min(f.get('sched'), f.get('esti')),
                'gate': (f.get('gate') or '').strip(),
                'terminal': (f.get('terminal') or '').strip(),
                'hall': (f.get('halle') or '').strip(),
                'status': _de_flight_status(f.get('status'), is_arr=(flight_type == 'arrival')),
                'delayed': (_fra_delay_min(f.get('sched'), f.get('esti'))
                            >= _PUNCTUALITY_DELAY_THRESHOLD_MIN),
                'reg': (f.get('reg') or '').strip(),
                'aircraft': (f.get('ac') or '').strip(),
            })
        return rows, len(data)

    out = []
    # VERGANGENHEIT zuerst (Seiten -past_pages..-1, chronologisch aufsteigend
    # zusammengesetzt): NUR so sieht der Poller gelandete Ankünfte/abgeflogene
    # Abflüge mit finalem Status/esti/Reg — die Basis der Warehouse-Persistenz
    # (`_merge_into_delay_store` persistiert nur `passed`-Flüge).
    past_blocks = []
    for page in range(-1, -int(past_pages or 0) - 1, -1):
        try:
            got = _fetch_page(page)
        except Exception:
            got = None
        if not got or not got[1]:
            break
        past_blocks.append(got[0])
        if got[1] < 25:
            break                       # Feed-Anfang erreicht
    for block in reversed(past_blocks):
        out.extend(block)
    for page in range(1, max_pages + 1):
        try:
            got = _fetch_page(page)
        except Exception:
            break
        if got is None or not got[1]:
            break
        out.extend(got[0])
        if got[1] < 25:
            break
    return out


def _fra_delay_min(sched, esti):
    """Verspätung in Minuten aus geplanter vs geschätzter Zeit (Fraport `esti`)."""
    if not sched or not esti:
        return 0
    try:
        from datetime import datetime
        ds = datetime.fromisoformat(sched)
        de = datetime.fromisoformat(esti)
        return max(0, int((de - ds).total_seconds() / 60))
    except Exception:
        return 0


def _opensky_headers():
    """Auth-Header für OpenSky-Flights-Calls. Nutzt den zentralen Header-Helfer aus
    dem ADS-B-Blueprint (OAuth2-Bearer bevorzugt, sonst HTTP-Basic aus
    OPENSKY_USERNAME/PASSWORD, sonst anonym). Wirft NIE — {} bei Import-Problem.
    Authentifiziert liefert OpenSky deutlich mehr Credits + verlässlichere Flights-
    Endpunkte (departure/arrival je Airport), die Basis der EU-Warehouse-Befüllung."""
    try:
        from blueprints.adsb_blueprint import _opensky_auth_header
        return _opensky_auth_header() or {}
    except Exception:
        return {}


def _fetch_opensky_board(icao, flight_type='departure'):
    """Per-Airport-Board via OpenSky (GRATIS, jeder ICAO). Liefert die ZULETZT
    tatsächlich abgeflogenen/angekommenen Flüge (~letzte 2h) — KEINE Gates/
    Scheduled (das hat nur Fraport für FRA). Ehrlich gelabelt source='opensky'."""
    try:
        import requests
        import time as _t
        from datetime import datetime, timezone
    except Exception:
        return None
    icao = (icao or '').upper().strip()
    if len(icao) != 4:
        return None
    now = int(_t.time())
    begin = now - 2 * 3600
    ep = 'arrival' if flight_type == 'arrival' else 'departure'
    try:
        r = requests.get('https://opensky-network.org/api/flights/' + ep,
                         params={'airport': icao, 'begin': begin, 'end': now},
                         headers=_opensky_headers(), timeout=10)
        # 404 = OpenSky-Konvention „keine Flüge im Fenster" (kein Fehler) → [].
        if r.status_code == 404:
            return []
        if r.status_code != 200:
            return None
        rows = r.json() or []
    except Exception:
        return None
    out = []
    for f in rows:
        cs = (f.get('callsign') or '').strip()
        if not cs:
            continue
        other = f.get('estArrivalAirport') if ep == 'departure' else f.get('estDepartureAirport')
        ts = f.get('firstSeen') if ep == 'departure' else f.get('lastSeen')
        try:
            sched = datetime.fromtimestamp(ts, tz=timezone.utc).isoformat() if ts else None
        except Exception:
            sched = None
        out.append({
            'airline': cs[:3],            # ICAO-Airline-Prefix (DLH=LH)
            'airline_name': '',
            'flight': cs,
            'dest_iata': (other or '').strip(),   # ICAO des anderen Flughafens
            'dest_name': '',
            'sched': sched,
            'gate': '', 'terminal': '', 'hall': '',
            'status': '', 'delayed': False, 'reg': '', 'aircraft': '',
        })
    out.sort(key=lambda x: x.get('sched') or '', reverse=True)
    return out


# ──────────────────────────────────────────────────────────────────────────
# Per-Airport NATIVE Boards (echte Abflug-/Ankunfts-Tafeln deutscher Airports)
# ──────────────────────────────────────────────────────────────────────────
# Grundsatz: jede Helper-Funktion FÄNGT alle Fehler ab und gibt [] oder None
# zurück — niemals raise/500. Liefert Rows im selben Contract wie _fetch_fra_
# flights (airline/airline_name/flight/dest_iata/dest_name/sched/esti/delay_min/
# gate/terminal/status/delayed/...). Stadtnamen laufen durch _clean_city_name
# (keine CJK/nicht-lateinischen Zeichen auf der iOS-Tafel).
#
# Native-Quellen (verifiziert per curl, ohne JS-Rendering, ohne Datacenter-Block):
#   MUC → munich-airport.com/flightsearch/departures?day=  (server-rendered HTML)
#   DUS → dus.com/api/sitecore/flightapi/SearchFlightsWithOutParams (JSON, X-Requested-With)
#   HAJ → hannover-airport.de/.../departures|arrivals/ (server-rendered HTML)
#   FMO → fmo.de/en/arrival-departure/ (server-rendered HTML)
#   LEJ → mdf-ag.com/.../leipzig-halle-airport/.../departures-arrivals/ (HTML, dep+arr in einer Page)
#   DRS → mdf-ag.com/.../dresden-airport/.../departures-arrivals/ (gleiches Vendor-Template)
#   BER → ber.berlin-airport.de/api.flights.json (JSON, AEM-Sling-Selector, Browser-Header gg. CloudFront-403)

_BOARD_UA = ('Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 '
             '(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36')


def _board_delay_min(sched_iso, revised_iso):
    """Verspätung in Minuten aus ISO-geplant vs ISO-erwartet/-tatsächlich."""
    if not sched_iso or not revised_iso:
        return 0
    try:
        from datetime import datetime
        ds = datetime.fromisoformat(str(sched_iso).replace('Z', '+00:00'))
        de = datetime.fromisoformat(str(revised_iso).replace('Z', '+00:00'))
        return max(0, int((de - ds).total_seconds() / 60))
    except Exception:
        return 0


def _empty_board_row():
    return {'airline': '', 'airline_name': '', 'flight': '', 'dest_iata': '',
            'dest_name': '', 'sched': None, 'esti': None, 'delay_min': 0,
            'gate': '', 'terminal': '', 'hall': '', 'status': '',
            'delayed': False, 'reg': '', 'aircraft': ''}


def _split_flightno(raw):
    """'4Y 1410 (A320)' → ('4Y', '4Y 1410', 'A320'). 'EW3590' → ('EW','EW 3590','').
    Airline-Code = führende Buchstaben + max. 1 Ziffer (IATA: 2 alnum, z.B. 4Y/LH/2L);
    Rest = Flugnummer. Bei vorhandenem Leerzeichen wird auf diesem getrennt
    (zuverlässiger als die Regex-Heuristik)."""
    import re as _re
    raw = (raw or '').strip()
    ac = ''
    m = _re.search(r'\(([^)]+)\)\s*$', raw)
    if m:
        ac = m.group(1).strip()
        raw = raw[:m.start()].strip()
    raw = _re.sub(r'\s+', ' ', raw)
    code = ''
    flight = raw
    if ' ' in raw:
        # Auf erstem Leerzeichen trennen: 'LH 441' / '4Y 1410'.
        head, _, tail = raw.partition(' ')
        if _re.match(r'^[A-Z0-9]{2,3}$', head) and _re.match(r'^\d{1,4}[A-Z]?$', tail.strip()):
            return head, head + ' ' + tail.strip(), ac
    # Kein/uneindeutiges Leerzeichen → IATA-Designator = 2 Zeichen (alnum) bevorzugt,
    # sonst 2 Buchstaben + optional 1 Ziffer.
    compact = raw.replace(' ', '')
    m2 = (_re.match(r'^([A-Z]\d|\d[A-Z]|[A-Z]{2})(\d{1,4}[A-Z]?)$', compact)
          or _re.match(r'^([A-Z0-9]{3})(\d{1,4}[A-Z]?)$', compact))
    if m2:
        code = m2.group(1)
        flight = code + ' ' + m2.group(2)
    else:
        parts = raw.split(' ')
        code = (parts[0] or '')[:3] if parts else ''
    return code, flight, ac


def _muc_board(flight_type='departure'):
    """MUC — munich-airport.com/flightsearch/{departures|arrivals}?day=YYYY-MM-DD.
    Server-rendered HTML-Tabelle (kein JS). Spalten: Airline / Nach(Von) (IATA) /
    Flugnr (Typ) / Status / MUC-Zeit (Geplant | Erwartet) / Andere-Zeit / Bereich."""
    try:
        import requests
        from bs4 import BeautifulSoup
        from datetime import datetime, timezone, timedelta
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    path = 'arrivals' if arr else 'departures'
    try:
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        day = None
    url = 'https://www.munich-airport.com/flightsearch/' + path
    try:
        r = requests.get(url, params={'day': day} if day else {},
                         headers={'User-Agent': _BOARD_UA,
                                  'X-Requested-With': 'XMLHttpRequest',
                                  'Accept': 'text/html'},
                         timeout=12)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
    except Exception:
        return None
    out = []
    seen = {}   # data-flight-id → Index in out (Dedup gegen die Mobile-Variantzeile).
    # WICHTIG: munich-airport.com rendert JEDEN Flug ZWEIMAL als tr.fp-flight-item:
    #   (1) Desktop-Tabellenzeile  → Spalte .fp-flight-time-muc trägt „Geplant | Erwartet".
    #   (2) Responsive Mobile-Zeile → td.fp-flight-details + verschachtelte Tabelle
    #       .fp-flight-schedule (Label/Wert: Status/Geplant/Erwartet/Ankunft/Bereich).
    # Der alte Parser kannte nur .fp-flight-time-muc → die Mobile-Zeile wurde als
    # PHANTOM ohne Zeit übernommen (sched=null). Diese null-sched-Phantome dominierten
    # die Tafel (die echten Desktop-Zeilen sind vormittägliche, schon abgeflogene Flüge,
    # die der _is_past-Filter entfernt) → iOS wirft Zeilen ohne Soll- UND Ist-Zeit raus
    # → MUC-Tafel praktisch leer. Jetzt: Zeit aus BEIDEN Varianten lesen (Mobile via
    # Schedule-Tabelle) und über data-flight-id deduppen (Variante mit Soll-Zeit gewinnt).
    for tr in soup.select('tr.fp-flight-item'):
        try:
            row = _empty_board_row()
            fid = (tr.get('data-flight-id') or '').strip()
            # Airline-Name aus dem Tooltip / aria-label (nur Desktop-Variante trägt ihn).
            al = tr.select_one('.fp-flight-airline .info-content') \
                or tr.select_one('.fp-flight-airline [aria-label]')
            if al:
                row['airline_name'] = (al.get('aria-label') or al.get_text(strip=True) or '').strip()
            # Ziel/Herkunft: 'Varna (VAR)' — in beiden Varianten unter .fp-flight-airport.
            ap = tr.select_one('.fp-flight-airport')
            if ap:
                txt = ap.get_text(' ', strip=True)
                m = _re.search(r'\(([A-Z]{3})\)\s*$', txt)
                if m:
                    row['dest_iata'] = m.group(1)
                    city = _re.sub(r'\s*\([A-Z]{3}\)\s*$', '', txt).strip()
                else:
                    city = txt
                row['dest_name'] = _clean_city_name(city, row['dest_iata'])
            # Flugnummer '4Y 1410 (A320)'.
            fn = tr.select_one('.fp-flight-number')
            if fn:
                code, flight, ac = _split_flightno(fn.get_text(' ', strip=True))
                row['airline'] = code or row['airline']
                row['flight'] = flight
                row['aircraft'] = ac
            # ── Zeiten + Status: Desktop-Zelle bevorzugt, sonst Mobile-Schedule-Tabelle.
            tcell = tr.select_one('.fp-flight-time-muc')
            if tcell:
                # Desktop-Variante: Status-Spalte + Zeit-Zelle 'HH:MM | HH:MM'.
                st = tr.select_one('.fp-flight-status')
                if st:
                    row['status'] = st.get_text(' ', strip=True)
                ttxt = tcell.get_text(' ', strip=True)
                tm = _re.findall(r'(\d{2}:\d{2})', ttxt)
                if tm and day:
                    row['sched'] = day + 'T' + tm[0] + ':00'
                    if len(tm) > 1 and tm[1] != tm[0]:
                        row['esti'] = day + 'T' + tm[1] + ':00'
                area = tr.select_one('.fp-flight-area')
                if area:
                    row['terminal'] = area.get_text(' ', strip=True)
            else:
                # Mobile-Variante: Label/Wert-Tabelle (Status/Geplant/Erwartet/Bereich).
                labels = {}
                sched_tbl = tr.select_one('.fp-flight-schedule')
                if sched_tbl:
                    for r2 in sched_tbl.select('tr'):
                        tds = r2.find_all('td')
                        if len(tds) >= 2:
                            labels[tds[0].get_text(strip=True).lower()] = tds[1].get_text(' ', strip=True)
                row['status'] = labels.get('status', '')
                if day:
                    gm = _re.search(r'(\d{2}:\d{2})', labels.get('geplant', ''))
                    em = _re.search(r'(\d{2}:\d{2})', labels.get('erwartet', ''))
                    if gm:
                        row['sched'] = day + 'T' + gm.group(1) + ':00'
                    if em and (not gm or em.group(1) != gm.group(1)):
                        row['esti'] = day + 'T' + em.group(1) + ':00'
                row['terminal'] = labels.get('bereich', '')
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = row['delay_min'] >= _DELAY_THRESHOLD_MIN
            if not (row['flight'] or row['dest_iata']):
                continue
            # Dedup über data-flight-id: die Variante mit Soll-Zeit (Desktop) gewinnt;
            # fehlt ihr der Airline-Name, aus der anderen Variante nachziehen.
            if fid and fid in seen:
                idx = seen[fid]
                if not out[idx].get('sched') and row.get('sched'):
                    kept_name = out[idx].get('airline_name')
                    out[idx] = row
                    if not out[idx].get('airline_name') and kept_name:
                        out[idx]['airline_name'] = kept_name
                elif not out[idx].get('airline_name') and row.get('airline_name'):
                    out[idx]['airline_name'] = row['airline_name']
                continue
            if fid:
                seen[fid] = len(out)
            out.append(row)
        except Exception:
            continue
    return out


def _dus_board(flight_type='departure'):
    """DUS — dus.com/api/sitecore/flightapi/SearchFlightsWithOutParams (JSON).
    Braucht X-Requested-With + Referer (sonst 400). arrival=true|false."""
    try:
        import requests
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    url = 'https://www.dus.com/api/sitecore/flightapi/SearchFlightsWithOutParams'
    try:
        r = requests.get(url,
                         params={'lang': 'en', 'arrival': 'true' if arr else 'false',
                                 'offset': 0, 'count': 80, 'codeshare': 'true',
                                 'showDetails': 'false'},
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json, text/plain, */*',
                                  'X-Requested-With': 'XMLHttpRequest',
                                  'Referer': 'https://www.dus.com/en/flights/'
                                             + ('arrivals' if arr else 'departures')},
                         timeout=12)
        if r.status_code != 200:
            return None
        flights = ((r.json() or {}).get('data') or {}).get('flights') or []
    except Exception:
        return None
    out = []
    for f in flights:
        try:
            row = _empty_board_row()
            airline = f.get('airline') or {}
            other = f.get('destination') or {}   # bei Ankunft = Herkunft
            row['airline'] = (airline.get('iataCode') or '').strip()
            row['airline_name'] = (airline.get('name') or '').strip()
            row['flight'] = (f.get('flightNumber') or '').strip()
            row['dest_iata'] = (other.get('iataCode') or '').strip()
            row['dest_name'] = _clean_city_name(other.get('name'), row['dest_iata'])
            row['sched'] = f.get('scheduledTime')
            row['esti'] = f.get('estimatedTime') or f.get('actualTime')
            stat = f.get('status') or {}
            pub = (stat.get('publicStatus') or {}).get('name') or stat.get('description') or ''
            row['status'] = (pub or '').strip()
            g = f.get('gate')
            row['gate'] = ', '.join(str(x) for x in g) if isinstance(g, list) else (str(g or '')).strip()
            # Terminal aus airline-Mapping (Checkin/Gate je nach Richtung).
            term = airline.get('terminalGateArrival' if arr else 'terminalCheckin')
            if isinstance(term, list):
                term = ', '.join(str(x) for x in term)
            row['terminal'] = (str(term or '')).strip()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = row['delay_min'] >= _DELAY_THRESHOLD_MIN
            if 'cancel' in row['status'].lower() or 'annul' in row['status'].lower():
                row['delayed'] = False
            out.append(row)
        except Exception:
            continue
    return out


def _haj_board(flight_type='departure'):
    """HAJ — hannover-airport.de/.../{departures|arrivals}/ (server-rendered HTML).
    .flightplan-item: Zeit / Ziel / FlightNo / Check-in / Terminal / Airline / Status."""
    try:
        import requests
        from bs4 import BeautifulSoup
        from datetime import datetime, timezone, timedelta
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    seg = 'arrivals' if arr else 'departures'
    url = 'https://www.hannover-airport.de/en/all-about-your-flight/' + seg + '/'
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA, 'Accept': 'text/html'},
                         timeout=12)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        return None
    out = []
    for it in soup.select('.flightplan-item'):
        try:
            row = _empty_board_row()
            tnode = it.select_one('.flightplan-item-time')
            if tnode:
                m = _re.search(r'(\d{2}:\d{2})', tnode.get_text(' ', strip=True))
                if m:
                    row['sched'] = day + 'T' + m.group(1) + ':00'
            info = it.select_one('.flightplan-item-info')
            if info:
                a = info.find('a')
                if a:
                    row['dest_name'] = _clean_city_name(a.get_text(' ', strip=True))
            summ = it.select_one('.flightplan-item-info-summary')
            if summ:
                spans = [s.get_text(' ', strip=True) for s in summ.find_all('span')]
                strong = summ.find('strong')
                if strong:
                    code, flight, ac = _split_flightno(strong.get_text(' ', strip=True))
                    row['airline'] = code
                    row['flight'] = flight
                for s in spans:
                    sl = s.lower()
                    if 'check-in' in sl:
                        row['hall'] = s.split(':', 1)[-1].strip()
                    elif 'terminal' in sl:
                        row['terminal'] = _re.sub(r'(?i)terminal', '', s).strip()
                    else:
                        # 'Eurowings (EW)' → airline name.
                        am = _re.search(r'^(.*?)\s*\(([A-Z0-9]{2,3})\)\s*$', s)
                        if am and not row['airline_name']:
                            row['airline_name'] = am.group(1).strip()
                            row['airline'] = row['airline'] or am.group(2)
            st = it.select_one('.flightplan-item-status')
            if st:
                row['status'] = st.get_text(' ', strip=True)
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out


def _fmo_board(flight_type='departure'):
    """FMO — fmo.de/en/arrival-departure/ (server-rendered HTML). Eine Page mit
    Abflügen UND Ankünften: .flight-list-item, data-destination=IATA. Richtung über
    den Detail-Link / die Item-Gruppierung — wir nehmen data-destination + den
    Listen-Kontext. FMO mischt dep/arr in EINER Liste, daher filtern wir grob auf
    Basis der Sektion-Überschrift."""
    try:
        import requests
        from bs4 import BeautifulSoup
        from datetime import datetime, timezone, timedelta
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    url = 'https://www.fmo.de/en/arrival-departure/'
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA, 'Accept': 'text/html'},
                         timeout=12)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        return None
    # FMO trennt Abflug/Ankunft über zwei tab-panes: #abflug / #ankunft.
    scope = soup.find(id='ankunft' if arr else 'abflug')
    items = (scope or soup).select('.flight-list-item')
    out = []
    for it in items:
        try:
            # Header-/Titelzeilen (class 'title') überspringen.
            if 'title' in (it.get('class') or []):
                continue
            row = _empty_board_row()
            tnode = it.select_one('.flight-list-item-time')
            if tnode:
                m = _re.search(r'(\d{2}:\d{2})', tnode.get_text(' ', strip=True))
                if m:
                    row['sched'] = day + 'T' + m.group(1) + ':00'
            row['dest_iata'] = (it.get('data-destination') or '').strip().upper()
            dest = it.select_one('.flight-list-item-destination-target')
            if dest:
                # Der Stadtname steht im ersten <span> (das verschachtelte <p> mit
                # der Flugnummer NICHT mitnehmen — FMO nestet ungültig).
                city_span = dest.find('span')
                city = (city_span.get_text(' ', strip=True) if city_span
                        else dest.get_text(' ', strip=True))
                row['dest_name'] = _clean_city_name(city, row['dest_iata'])
            num = it.select_one('.flight-list-item-destination-number')
            if num:
                code, flight, ac = _split_flightno(num.get_text(' ', strip=True))
                row['airline'] = code
                row['flight'] = flight
            st = it.select_one('.flight-list-item-status')
            if st:
                row['status'] = st.get_text(' ', strip=True)
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out


def _mdfag_board(slug, iata, flight_type='departure'):
    """LEJ/DRS — mdf-ag.com TYPO3-Vendor (nrc-flightplan). EINE Page rendert dep+arr:
    #collapse-parent-departure / #collapse-parent-arrival. Row=tr.tx-nrc-flightplan__
    table-overview: .flightnumber / .airlinename / Route(>) / Zeit(durchgestrichen=
    geplant, darunter=erwartet/aktuell) / Status / GATE."""
    try:
        import requests
        from bs4 import BeautifulSoup
        from datetime import datetime, timezone, timedelta
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    url = ('https://www.mdf-ag.com/en/passengers-and-visitors/' + slug
           + '/flights/departures-arrivals/')
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA, 'Accept': 'text/html'},
                         timeout=12)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        return None
    scope = soup.select_one('#collapse-parent-arrival' if arr
                            else '#collapse-parent-departure')
    if scope is None:
        return None
    out = []
    for tr in scope.select('tr.tx-nrc-flightplan__table-overview'):
        try:
            row = _empty_board_row()
            fn = tr.select_one('.flightnumber')
            if fn:
                code, flight, ac = _split_flightno(fn.get_text(' ', strip=True))
                row['airline'] = code
                row['flight'] = flight
            an = tr.select_one('.airlinename')
            if an:
                row['airline_name'] = (an.get('title') or an.get_text(' ', strip=True) or '').strip()
            # Route-Zelle: 'Leipzig/Halle > Nottingham East Midl'. Die andere Seite
            # (nicht der Heimatflughafen) ist Ziel/Herkunft.
            route_td = None
            for td in tr.find_all('td'):
                if td.select_one('[class*="flightplan-destination-"]'):
                    route_td = td
                    break
            if route_td:
                parts = [p.strip() for p in route_td.get_text(' ', strip=True).split('>')]
                parts = [p for p in parts if p]
                if len(parts) >= 2:
                    other = parts[0] if arr else parts[-1]
                    row['dest_name'] = _clean_city_name(other)
            # Zeit-Zelle: durchgestrichen = geplant; sichtbar = erwartet/aktuell.
            sched_t = esti_t = None
            for td in tr.find_all('td'):
                strikes = td.select('[style*="line-through"]')
                if strikes:
                    sm = _re.search(r'(\d{2}:\d{2})', strikes[0].get_text())
                    if sm:
                        sched_t = sm.group(1)
                    # erste nicht-durchgestrichene Zeit in derselben Zelle
                    for div in td.find_all('div'):
                        style = (div.get('style') or '')
                        if 'line-through' in style:
                            continue
                        em = _re.search(r'^(\d{2}:\d{2})$', div.get_text(strip=True))
                        if em:
                            esti_t = em.group(1)
                            break
                    break
            if sched_t:
                row['sched'] = day + 'T' + sched_t + ':00'
            if esti_t and esti_t != sched_t:
                row['esti'] = day + 'T' + esti_t + ':00'
            # GATE (im Mobile/Status-Text als 'GATE 14').
            gm = _re.search(r'GATE\s*([0-9A-Z]+)', tr.get_text(' ', strip=True))
            if gm:
                row['gate'] = gm.group(1)
            # Status: letzte sinnvolle Statuszelle ('departed','landed','cancelled').
            for td in reversed(tr.find_all('td')):
                t = td.get_text(' ', strip=True).lower()
                if t in ('departed', 'landed', 'cancelled', 'boarding', 'on time',
                         'delayed', 'expected', 'arrived', 'gate closed'):
                    row['status'] = td.get_text(' ', strip=True)
                    break
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = row['delay_min'] >= _DELAY_THRESHOLD_MIN
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out


def _ham_board(flight_type='departure'):
    """HAM — Hamburg Airport. FREIER JSON-Feed (reverse-engineered aus dem Board-JS,
    LIVE verifiziert 2026-06-24):
        GET https://www.hamburg-airport.de/service/flightdata/{departures|arrivals}
    → JSON-Array. Felder pro Flug: flightnumber ('KL 1758'), airline2LCode, airlineName,
    {destination|origin}Airport3LCode + …Name, planned/expected/actual{Departure|Arrival}Time
    (ISO **UTC**), gate (nur Abflug), {departure|arrival}Terminal, aircraftType (Klartext,
    KEIN Code), flightStatus{Departure|Arrival}, cancelled. HAM publiziert KEINE Tail-Reg
    → reg bleibt leer, Muster (aircraftType) wird übernommen.

    Der Feed ist ein MEHR-TAGE-Fenster → wir filtern auf den heutigen Betriebstag
    (Europe/Berlin) und rechnen die UTC-Zeiten in Berlin-Lokalzeit um (gleiche naive
    'YYYY-MM-DDTHH:MM:00'-Form wie alle anderen Board-Quellen)."""
    try:
        import requests
        from datetime import datetime
        try:
            from zoneinfo import ZoneInfo
            _berlin = ZoneInfo('Europe/Berlin')
        except Exception:
            _berlin = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    path = 'arrivals' if arr else 'departures'
    url = 'https://www.hamburg-airport.de/service/flightdata/' + path
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA,
                                       'Accept': 'application/json'}, timeout=14)
        if r.status_code != 200:
            return None
        data = r.json()
        if not isinstance(data, list):
            return None
    except Exception:
        return None
    try:
        today = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        today = None

    def _to_local(iso):
        """ISO-UTC ('…Z') → naive Europe/Berlin 'YYYY-MM-DDTHH:MM:00'. None bei leer."""
        if not iso or not isinstance(iso, str):
            return None
        try:
            dt = datetime.fromisoformat(iso.replace('Z', '+00:00'))
            if _berlin is not None:
                dt = dt.astimezone(_berlin)
            return dt.strftime('%Y-%m-%dT%H:%M:00')
        except Exception:
            return None

    k_iata = 'originAirport3LCode' if arr else 'destinationAirport3LCode'
    k_name = 'originAirportName' if arr else 'destinationAirportName'
    k_term = 'arrivalTerminal' if arr else 'departureTerminal'
    k_plan = 'plannedArrivalTime' if arr else 'plannedDepartureTime'
    k_exp = 'expectedArrivalTime' if arr else 'expectedDepartureTime'
    k_act = 'actualArrivalTime' if arr else 'actualDepartureTime'
    k_stat = 'flightStatusArrival' if arr else 'flightStatusDeparture'
    out = []
    for f in data:
        try:
            row = _empty_board_row()
            code, _flight, _ac = _split_flightno(f.get('flightnumber') or '')
            # Flugnummer leerzeichen-frei + großgeschrieben speichern (wie FRA) —
            # sonst matcht /api/ax/flight-info (Query: upper, no-space) nicht.
            row['flight'] = (f.get('flightnumber') or '').replace(' ', '').strip().upper()
            row['airline'] = (f.get('airline2LCode') or code or '').strip().upper()
            row['airline_name'] = (f.get('airlineName') or '').strip()
            row['dest_iata'] = (f.get(k_iata) or '').strip().upper()
            row['dest_name'] = _clean_city_name(f.get(k_name), row['dest_iata'])
            planned = _to_local(f.get(k_plan))
            est = _to_local(f.get(k_exp)) or _to_local(f.get(k_act))
            row['sched'] = planned
            if est and est != planned:
                row['esti'] = est
            row['gate'] = (f.get('gate') or '').strip()      # nur Abflug belegt
            row['terminal'] = (f.get(k_term) or '').strip()
            row['status'] = (f.get(k_stat) or '').strip()
            row['aircraft'] = (f.get('aircraftType') or '').strip()
            row['cancelled'] = bool(f.get('cancelled'))
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = row['delay_min'] >= _DELAY_THRESHOLD_MIN
            # Nur heutiger Betriebstag (der Feed liefert mehrere Tage).
            if today and row['sched'] and not row['sched'].startswith(today):
                continue
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _ber_board(flight_type='departure'):
    """BER — Berlin Brandenburg Airport (ber.berlin-airport.de).

    Datenquelle (reverse-engineered, LIVE verifiziert 2026-06-06):
      GET https://ber.berlin-airport.de/api.flights.json
          ?arrivalDeparture={D|A}
          &dateFrom=YYYY-MM-DDT00:00:00
          &dateUntil=YYYY-MM-DD            (Folgetag)
          &search=&lang=EN&page=1&terminal=&itemsPerPage=100
    Die Seite /en/flying/departures-arrivals.html fetcht genau diese AEM-Sling-
    Selector-JSON (apiUrl = "/api.flights.json" im clientlib-base-Bundle). CloudFront
    blockt ohne Browser-Header (403) → Referer + Sec-Fetch-* + Accept-Language mit.
    Response: {"data":{"updated_at":..., "items":[ {flight…} ]}}.

    Feld-Mapping (aus dem JS-Renderer, je Richtung):
      flight_number, airline_code, airline_name
      Abflug (D): arr_airport_iata/_name = Ziel,  gate, checkin_counter, dep_estimated_time
      Ankunft (A): dep_airport_iata/_name = Herkunft, arr_belt, arr_exit, arr_estimated_time
      scheduled_time (richtungsabhängig), terminal, flight_status_label/_id,
      aircraft_type, aircraft_reg.
    Status-Beispiele: 'Departed'/'departed', 'Arrived'/'arrived', i.d.R. auch
    'Cancelled'/'cancelled' (BER liefert flight_status_label als Klartext)."""
    try:
        import requests
        from datetime import timedelta
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        now = _fra_local_now()
        day = now.strftime('%Y-%m-%d')
        tomorrow = (now + timedelta(days=1)).strftime('%Y-%m-%d')
    except Exception:
        return None
    url = 'https://ber.berlin-airport.de/api.flights.json'
    headers = {
        'User-Agent': _BOARD_UA,
        'Accept': 'application/json, text/plain, */*',
        'Accept-Language': 'en-US,en;q=0.9,de;q=0.8',
        'Referer': 'https://ber.berlin-airport.de/en/flying/departures-arrivals.html',
        'X-Requested-With': 'XMLHttpRequest',
        'Sec-Fetch-Site': 'same-origin',
        'Sec-Fetch-Mode': 'cors',
        'Sec-Fetch-Dest': 'empty',
    }
    params = {
        'arrivalDeparture': 'A' if arr else 'D',
        'dateFrom': day + 'T00:00:00',
        'dateUntil': tomorrow,
        'search': '',
        'lang': 'EN',
        'page': 1,
        'terminal': '',
        'itemsPerPage': 100,
    }
    try:
        r = requests.get(url, params=params, headers=headers, timeout=14)
        if r.status_code != 200:
            return None
        data = (r.json() or {}).get('data') or {}
        flights = data.get('items') or []
    except Exception:
        return None
    if not flights:
        return None

    def _strip_iata_suffix(name, iata):
        # BER hängt manchmal den Code an den Stadtnamen ('Izmir ADB').
        s = (name or '').strip()
        if iata and s.upper().endswith(' ' + iata.upper()):
            s = s[: -(len(iata) + 1)].strip()
        return s

    out = []
    for f in flights:
        try:
            row = _empty_board_row()
            row['flight'] = _re.sub(r'\s+', ' ', (f.get('flight_number') or '').strip()).upper()
            row['airline'] = (f.get('airline_code') or '').strip().upper()
            row['airline_name'] = (f.get('airline_name') or '').strip()
            if not row['airline'] and row['flight']:
                row['airline'] = (row['flight'].split(' ')[0] or '')[:3]
            if arr:
                # Bei Ankunft = HERKUNFT.
                other_iata = (f.get('dep_airport_iata') or '').strip().upper()
                other_name = f.get('dep_airport_name')
                row['gate'] = (f.get('arr_belt') or '').strip()      # Gepäckband
                row['hall'] = (f.get('arr_exit') or '').strip()      # Ausgang
                esti = f.get('arr_estimated_time')
            else:
                other_iata = (f.get('arr_airport_iata') or '').strip().upper()
                other_name = f.get('arr_airport_name')
                row['gate'] = (f.get('gate') or '').strip()
                row['hall'] = (f.get('checkin_counter') or '').strip()
                esti = f.get('dep_estimated_time')
            row['dest_iata'] = other_iata
            row['dest_name'] = _clean_city_name(_strip_iata_suffix(other_name, other_iata), other_iata)
            row['sched'] = f.get('scheduled_time') or None
            if esti and esti != row['sched']:
                row['esti'] = esti
            row['terminal'] = (f.get('terminal') or '').strip()
            row['status'] = (f.get('flight_status_label') or f.get('flight_status_id') or '').strip()
            row['aircraft'] = (f.get('aircraft_type') or '').strip()
            row['reg'] = (f.get('aircraft_reg') or '').strip()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            sid = (f.get('flight_status_id') or '').lower()
            cancelled = ('cancel' in sid or 'cancel' in row['status'].lower()
                         or 'annul' in row['status'].lower())
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN) and not cancelled
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _avinor_board(iata, flight_type='departure', tz='Europe/Oslo'):
    """AVINOR-Gruppe (ALLE norwegischen Airports: OSL/BGO/TRD/SVG/TOS/BOO/AES/KRS…).

    EINE freie XML-Quelle für die ganze Gruppe (LIVE verifiziert 2026-07-02):
      GET https://asrv.avinor.no/XmlFeed/v1.0
          ?TimeFrom=1&TimeTo=16&airport=<IATA>&direction={D|A}
    → <airport><flights><flight>…: airline (IATA-2L), flight_id ('BA783'),
      dom_int (D/S/I), schedule_time (ISO **UTC**), airport (Ziel/Herkunft-IATA),
      via_airport, check_in ('1-3'), gate ('F16'), belt (Ankunft-Gepäckband),
      status code+time, delayed ('Y').

    Status-Codes (Avinor XmlFeed-Doku): N=neue Info, E=neue (verspätete) Zeit,
    D=abgeflogen, A=gelandet, C=annulliert. status.time = erwartete/tatsächliche
    Zeit → esti. UTC → Flughafen-Ortszeit (Europe/Oslo) wie HAM (naive
    'YYYY-MM-DDTHH:MM:00'-Form). GROSSER GRUPPEN-HEBEL: eine Quelle, viele Airports.
    """
    try:
        import requests
        import xml.etree.ElementTree as ET
        from datetime import datetime
        try:
            from zoneinfo import ZoneInfo
            _z = ZoneInfo(tz)
        except Exception:
            _z = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    direction = 'A' if arr else 'D'
    try:
        r = requests.get('https://asrv.avinor.no/XmlFeed/v1.0',
                         params={'TimeFrom': 1, 'TimeTo': 16, 'airport': iata,
                                 'direction': direction},
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/xml,text/xml,*/*'},
                         timeout=12)
        if r.status_code != 200 or not r.content:
            return None
        root = ET.fromstring(r.content)
    except Exception:
        return None

    def _to_local(iso):
        if not iso:
            return None
        try:
            dt = datetime.fromisoformat(str(iso).replace('Z', '+00:00'))
            if _z is not None:
                dt = dt.astimezone(_z)
            return dt.strftime('%Y-%m-%dT%H:%M:00')
        except Exception:
            return None

    _statmap = {'E': 'Delayed', 'D': 'Departed', 'A': 'Arrived',
                'C': 'Cancelled', 'N': 'New info'}
    out = []
    for f in root.iter('flight'):
        try:
            row = _empty_board_row()
            fid = (f.findtext('flight_id') or '').strip().upper()
            row['flight'] = fid
            row['airline'] = (f.findtext('airline') or (fid[:2] if fid else '')).strip().upper()
            other = (f.findtext('airport') or '').strip().upper()   # Ziel (D) / Herkunft (A)
            row['dest_iata'] = other
            row['dest_name'] = _clean_city_name('', other)
            sched = _to_local(f.findtext('schedule_time'))
            row['sched'] = sched
            st = f.find('status')
            code = ''
            if st is not None:
                code = (st.get('code') or '').strip().upper()
                stime = _to_local(st.get('time'))
                if code in ('E', 'D', 'A') and stime and stime != sched:
                    row['esti'] = stime
            if arr:
                row['gate'] = (f.findtext('belt') or '').strip()      # Gepäckband
            else:
                row['gate'] = (f.findtext('gate') or '').strip()
                row['hall'] = (f.findtext('check_in') or '').strip()  # Check-in-Schalter
            row['status'] = _statmap.get(code, '')
            row['cancelled'] = (code == 'C')
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = ((str(f.findtext('delayed') or '').strip().upper() == 'Y')
                              or row['delay_min'] >= _DELAY_THRESHOLD_MIN)
            if row['cancelled']:
                row['delayed'] = False
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _waw_board(flight_type='departure'):
    """WAW — Warschau-Chopin (lotnisko-chopina.pl). Server-rendert die LIVE-Tafel
    (CodeRed/Wagtail-CMS) direkt ins HTML: div.flight-row mit .column-time,
    .column-expected, .column-origin-destination ('Pisa (PSA)'), .column-flight-no
    ('FR 6146'), .column-airline img[alt] (Airline-Name), .column-terminal ('Exit 1'),
    .column-belt ('Tape 7'), .column-status ('Landed').

    WICHTIG: Die Seite /en/arrivals-and-departures/ rendert server-seitig NUR die
    ANKUNFTS-Tafel (Abflüge lädt sie client-seitig per JS nach — kein sauber
    scrapebarer Endpunkt gefunden). Darum liefert diese Funktion nur ANKÜNFTE und
    gibt für 'departure' None zurück (ehrlich → Poller meldet no_flights, kein
    fälschlich als Abflug etikettiertes Ankunfts-Datum)."""
    if flight_type != 'arrival':
        return None
    try:
        import requests
        from bs4 import BeautifulSoup
        import re as _re
    except Exception:
        return None
    try:
        r = requests.get('https://www.lotnisko-chopina.pl/en/arrivals-and-departures/',
                         headers={'User-Agent': _BOARD_UA, 'Accept': 'text/html'},
                         timeout=12)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        return None
    out = []
    for it in soup.select('.flight-row'):
        try:
            row = _empty_board_row()

            def g(c):
                e = it.select_one('.' + c)
                return e.get_text(' ', strip=True) if e else ''
            tm = _re.search(r'(\d{1,2}:\d{2})', g('column-time'))
            if tm:
                row['sched'] = day + 'T' + tm.group(1).zfill(5) + ':00'
            em = _re.search(r'(\d{1,2}:\d{2})', g('column-expected'))
            if em and (not tm or em.group(1) != tm.group(1)):
                row['esti'] = day + 'T' + em.group(1).zfill(5) + ':00'
            dest = g('column-origin-destination')
            m = _re.search(r'\(([A-Z]{3})\)\s*$', dest)
            if m:
                row['dest_iata'] = m.group(1)
                dest = _re.sub(r'\s*\([A-Z]{3}\)\s*$', '', dest).strip()
            row['dest_name'] = _clean_city_name(dest, row['dest_iata'])
            code, flight, ac = _split_flightno(g('column-flight-no'))
            row['airline'] = code
            row['flight'] = flight
            al = it.select_one('.column-airline img')
            if al:
                row['airline_name'] = (al.get('alt') or '').strip()
            row['terminal'] = g('column-terminal')          # 'Exit 1'
            row['gate'] = g('column-belt')                   # Gepäckband 'Tape 7'
            row['status'] = g('column-status')
            sl = row['status'].lower()
            row['cancelled'] = 'cancel' in sl or 'odwoł' in sl
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN) and not row['cancelled']
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _board_origin_iata(name, code=None):
    """Stadt-/Airport-NAME → IATA über den geteilten eu_scraper-Resolver
    (airports_compact.json Name/ICAO→IATA + Hub-Map, gleiche Quelle wie die
    LIS/BUD-Arrival-Fixes). Einige deutsche Boards (NRN/FDH/FKB) liefern die
    Gegenseite nur als Stadtnamen — ohne Auflösung könnten Arrivals nicht
    mit ihrem Herkunfts-Airport ins Warehouse. FAIL-SAFE: unauflösbar → ''
    (nie ein falscher Code). Import guarded: fehlt eu_scraper im Image,
    degradieren die Boards still auf leere dest_iata."""
    try:
        from eu_scraper import airports_ref as _ref
        return _ref.resolve(name, code) or ''
    except Exception:
        return ''


def _cgn_board(flight_type='departure'):
    """CGN — koeln-bonn-airport.de fsjson (offene JSON-POST-API der Tafel-Seite,
    TYPO3 cgn_flightschedule). mode=D|A, 25 Rows/Seite → wir blättern bis zu 4
    Seiten ab Tagesbeginn (deckt den CGN-Tag ab). Felder: destination = IATA der
    Gegenseite (bei Ankunft = HERKUNFT), STT = Soll lokal, expected = 'HH:MM'
    erwartet/tatsächlich, statusF = Status-HTML, gate."""
    try:
        import requests
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        from datetime import datetime as _dt
        day = _dt.utcnow().strftime('%Y-%m-%d')
    url = ('https://www.koeln-bonn-airport.de/fluggaeste/fluege/'
           'abflug-ankunft/fsjson')
    out, seen = [], set()
    for page in range(4):
        try:
            r = requests.post(
                url,
                data={'mode': 'A' if arr else 'D', 'tolerance': '', 'page': page,
                      'START': '', 'END': '', 'destination': '',
                      'date': day + 'T00:00'},
                headers={'User-Agent': _BOARD_UA,
                         'X-Requested-With': 'XMLHttpRequest',
                         'Accept': 'application/json, text/plain, */*',
                         'Referer': 'https://www.koeln-bonn-airport.de/'
                                    'fluggaeste/fluege/abflug-ankunft.html'},
                timeout=12)
            if r.status_code != 200:
                break
            flights = (r.json() or {}).get('flights') or []
        except Exception:
            break
        for f in flights:
            try:
                fid = f.get('id') or ''
                if fid and fid in seen:
                    continue
                seen.add(fid)
                row = _empty_board_row()
                raw_no = _re.sub(r'\s+', ' ', (f.get('number') or '').strip())
                code, flight, _ac = _split_flightno(raw_no)
                row['airline'] = code
                row['flight'] = flight
                row['airline_name'] = (f.get('operating_carrier_name') or '').strip()
                row['dest_iata'] = (f.get('destination') or '').strip().upper()
                row['dest_name'] = _clean_city_name(
                    f.get('destination_expanded'), row['dest_iata'])
                stt = (f.get('STT') or '').strip()           # '2026-07-03 09:50:00'
                if len(stt) >= 16:
                    row['sched'] = stt[:10] + 'T' + stt[11:16] + ':00'
                exp = (f.get('expected') or '').strip()      # 'HH:MM' oder ''
                if exp and _re.match(r'^\d{2}:\d{2}$', exp) and row['sched']:
                    if exp != row['sched'][11:16]:
                        row['esti'] = row['sched'][:10] + 'T' + exp + ':00'
                # statusF trägt HTML (<i class=…> gestartet) → Tags strippen.
                st = _re.sub(r'<[^>]+>', '', f.get('statusF') or '').strip()
                row['status'] = st
                sl = st.lower()
                row['cancelled'] = ('annull' in sl or 'gestrichen' in sl
                                    or 'cancel' in sl)
                row['gate'] = (str(f.get('gate') or '')).strip()
                row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
                row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                                  and not row['cancelled'])
                if row['flight'] or row['dest_iata']:
                    out.append(row)
            except Exception:
                continue
        if len(flights) < 25:
            break
    return out if out else None


def _nue_board(flight_type='departure'):
    """NUE — offene JSON-API des Scrivito-Frontends (airportnue-service
    .justrelate.io/production/api/flight-status/{departures|arrivals}).
    REICH: toAirport/fromAirport.iata direkt (Ankunft = Herkunfts-IATA!),
    scheduledTime UTC, status.time = erwartete/tatsächliche Zeit UTC,
    gate/terminal + aircraft.registration (TAIL!) und aircraft.iata (Typ).
    Feed spannt ~4 Tage → nur der heutige lokale Tag wird übernommen."""
    try:
        import requests
        from datetime import datetime as _dt, timezone as _tz
        try:
            from zoneinfo import ZoneInfo as _zi
        except Exception:
            _zi = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    seg = 'arrivals' if arr else 'departures'
    url = ('https://airportnue-service.justrelate.io/production/api/'
           'flight-status/' + seg + '?lang=de')
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA,
                                       'Accept': 'application/json'},
                         timeout=12)
        if r.status_code != 200:
            return None
        data = r.json() or []
    except Exception:
        return None
    if not isinstance(data, list):
        return None
    tzname = 'Europe/Berlin'

    def _loc(iso_utc):
        # '2026-07-02T08:15:00.000Z' → naive lokale ISO 'YYYY-MM-DDTHH:MM:00'
        if not iso_utc:
            return None
        try:
            d = _dt.fromisoformat(str(iso_utc).replace('Z', '+00:00'))
            if _zi is not None:
                d = d.astimezone(_zi(tzname))
            return d.strftime('%Y-%m-%dT%H:%M:00')
        except Exception:
            return None
    try:
        today = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        today = _dt.now(_tz.utc).strftime('%Y-%m-%d')
    out = []
    for f in data:
        try:
            sched = _loc(f.get('scheduledTime'))
            if not sched or not sched.startswith(today):
                continue
            row = _empty_board_row()
            fl = f.get('flight') or {}
            al = (fl.get('airline') or {})
            row['airline'] = (al.get('iata') or '').strip().upper()
            row['airline_name'] = (al.get('name') or '').strip()
            num = (fl.get('number') or '').strip()
            if row['airline'] and num:
                row['flight'] = row['airline'] + ' ' + num
            other = f.get('fromAirport' if arr else 'toAirport') or {}
            row['dest_iata'] = (other.get('iata') or '').strip().upper()
            row['dest_name'] = _clean_city_name(other.get('name'), row['dest_iata'])
            row['sched'] = sched
            st = f.get('status') or {}
            label = (st.get('label') or '').strip()
            row['status'] = label.replace('-', ' ')
            esti = _loc(st.get('time'))
            if esti and esti != sched:
                row['esti'] = esti
            row['gate'] = (f.get('gate') or '').strip()
            row['terminal'] = (f.get('terminal') or '').strip()
            ac = f.get('aircraft') or {}
            row['reg'] = (ac.get('registration') or '').strip().upper()
            row['aircraft'] = (ac.get('iata') or '').strip().upper()
            ll = label.lower()
            row['cancelled'] = 'cancel' in ll or 'annull' in ll
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _nrn_board(flight_type='departure'):
    """NRN (Weeze) — EIN offener GET airport-weeze.com/api/flights.json liefert
    BEIDE Richtungen als server-gerendertes HTML-Fragment (WordPress
    nrn_plugin). Felder je .fs__row.fs__body: Flugnr, Von/Nach (nur STADTNAME →
    airports_ref-Resolver), Geplant/Erwartet 'HH:MM', Status. Zeiten lokal."""
    try:
        import requests
        from bs4 import BeautifulSoup
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        r = requests.get('https://airport-weeze.com/api/flights.json',
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json'},
                         timeout=12)
        if r.status_code != 200:
            return None
        payload = r.json() or {}
    except Exception:
        return None
    html = payload.get('return_html_arrivals' if arr
                       else 'return_html_departures') or ''
    if not html:
        return None
    try:
        soup = BeautifulSoup(html, 'html.parser')
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        return None
    out = []
    for it in soup.select('.fs__row.fs__body'):
        try:
            row = _empty_board_row()

            def g(label):
                node = it.select_one('[data-label="' + label + '"]')
                return node.get_text(' ', strip=True) if node else ''
            code, flight, _ac = _split_flightno(g('Flugnr.'))
            row['airline'] = code
            row['flight'] = flight
            city = g('Von' if arr else 'Nach')
            row['dest_name'] = _clean_city_name(city, '')
            row['dest_iata'] = _board_origin_iata(city)
            tm = _re.search(r'(\d{1,2}:\d{2})', g('Geplant'))
            if tm:
                row['sched'] = day + 'T' + tm.group(1).zfill(5) + ':00'
            em = _re.search(r'(\d{1,2}:\d{2})', g('Erwartet'))
            if em and (not tm or em.group(1) != tm.group(1)):
                row['esti'] = day + 'T' + em.group(1).zfill(5) + ':00'
            stat = it.select_one('.status__name')
            row['status'] = stat.get_text(' ', strip=True) if stat else g('Status')
            sl = row['status'].lower()
            row['cancelled'] = ('annull' in sl or 'gestrichen' in sl
                                or 'cancel' in sl)
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _fdh_board(flight_type='departure'):
    """FDH (Friedrichshafen) — server-gerenderte Tages-Tafel auf
    bodensee-airport.eu (beide Richtungen in EINER Seite, tbody
    data-table-type=departure|arrival). Spalten: Logo / Flug / Von / Nach /
    Geplant / Tatsächlich / Status. Gegenseite nur als STADTNAME →
    airports_ref-Resolver. Kleiner Airport (wenige Flüge/Tag) — ehrlich klein."""
    try:
        import requests
        from bs4 import BeautifulSoup
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    url = ('https://www.bodensee-airport.eu/passagiere-besucher/'
           'rund-ums-fliegen/ankunft-abflug/')
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA,
                                       'Accept': 'text/html'}, timeout=14)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
        day = _fra_local_now().strftime('%Y-%m-%d')
    except Exception:
        return None
    tbody = soup.select_one('tbody[data-table-type="'
                            + ('arrival' if arr else 'departure') + '"]')
    if tbody is None:
        return None
    out = []
    for tr in tbody.select('tr'):
        try:
            tds = tr.find_all('td')
            if len(tds) < 7:
                continue
            row = _empty_board_row()
            code, flight, _ac = _split_flightno(tds[1].get_text(' ', strip=True))
            row['airline'] = code
            row['flight'] = flight
            # Gegenseite: bei Abflug die 'Nach'-Spalte, bei Ankunft die 'Von'.
            other = tds[2 if arr else 3].get_text(' ', strip=True)
            row['dest_name'] = _clean_city_name(other, '')
            row['dest_iata'] = _board_origin_iata(other)
            tm = _re.search(r'(\d{1,2}:\d{2})', tds[4].get_text(' ', strip=True))
            if tm:
                row['sched'] = day + 'T' + tm.group(1).zfill(5) + ':00'
            em = _re.search(r'(\d{1,2}:\d{2})', tds[5].get_text(' ', strip=True))
            if em and (not tm or em.group(1) != tm.group(1)):
                row['esti'] = day + 'T' + em.group(1).zfill(5) + ':00'
            row['status'] = tds[6].get_text(' ', strip=True)
            sl = row['status'].lower()
            row['cancelled'] = ('annull' in sl or 'gestrichen' in sl
                                or 'cancel' in sl)
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _fkb_board(flight_type='departure'):
    """FKB (Karlsruhe/Baden-Baden) — offener WordPress-admin-ajax-GET
    (action=flight-results-block-{departures|arrivals}) liefert die
    Tages-Tafel als HTML-Items (je ein Datums-Block mit flight-table__row-
    Zeilen). Zellen: origin-Spalte = Stadt + Flugnr, status-Spalte = Soll-Zeit,
    comment-Spalte = tatsächliche Zeit + Status, gate, airline. Nur der
    heutige Block wird übernommen; Stadt → airports_ref-Resolver."""
    try:
        import requests
        from bs4 import BeautifulSoup
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    action = 'flight-results-block-' + ('arrivals' if arr else 'departures')
    try:
        r = requests.get('https://www.baden-airpark.de/wp/wp-admin/admin-ajax.php',
                         params={'action': action,
                                 'path': '/passagiere-besucher/fluege/'
                                         'tagesaktueller-flugplan/',
                                 'p': 122},
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json',
                                  'Referer': 'https://www.baden-airpark.de/'
                                             'passagiere-besucher/fluege/'
                                             'tagesaktueller-flugplan/'},
                         timeout=14)
        if r.status_code != 200:
            return None
        items = ((r.json() or {}).get('data') or {}).get('items') or []
    except Exception:
        return None
    try:
        now_local = _fra_local_now()
        day = now_local.strftime('%Y-%m-%d')
        day_de = now_local.strftime('%d.%m.%Y')
    except Exception:
        return None
    out = []
    for item_html in items:
        try:
            # Jeder Item-Block beginnt mit seinem Datum ('Freitag, 03.07.2026') —
            # nur der HEUTIGE Block zählt (die Tafel listet auch Folgetage).
            mdate = _re.search(r'(\d{2}\.\d{2}\.\d{4})', item_html or '')
            if not mdate or mdate.group(1) != day_de:
                continue
            soup = BeautifulSoup(item_html, 'html.parser')
        except Exception:
            continue
        for tr in soup.select('.flight-table__row'):
            try:
                row = _empty_board_row()
                org = tr.select_one('.flight-table__col__origin')
                if org is None:
                    continue
                spans = [s.get_text(' ', strip=True) for s in org.select('span')]
                spans = [s for s in spans if s]
                city = spans[0] if spans else ''
                rawno = spans[1] if len(spans) > 1 else ''
                code, flight, _ac = _split_flightno(rawno)
                row['airline'] = code
                row['flight'] = flight
                row['dest_name'] = _clean_city_name(city, '')
                row['dest_iata'] = _board_origin_iata(city)
                stat_col = tr.select_one('.flight-table__col__status')
                if stat_col is not None:
                    tm = _re.search(r'(\d{1,2}:\d{2})',
                                    stat_col.get_text(' ', strip=True))
                    if tm:
                        row['sched'] = day + 'T' + tm.group(1).zfill(5) + ':00'
                com = tr.select_one('.flight-table__col__comment')
                if com is not None:
                    ctext = com.get_text(' ', strip=True)
                    em = _re.search(r'(\d{1,2}:\d{2})', ctext)
                    if em and (not row['sched']
                               or em.group(1).zfill(5) != row['sched'][11:16]):
                        row['esti'] = day + 'T' + em.group(1).zfill(5) + ':00'
                    row['status'] = _re.sub(r'\d{1,2}:\d{2}\s*', '', ctext).strip()
                gate = tr.select_one('.flight-table__col__gate')
                if gate is not None:
                    row['gate'] = gate.get_text(' ', strip=True)
                alink = tr.select_one('.flight-table__col__airline')
                if alink is not None:
                    row['airline_name'] = alink.get_text(' ', strip=True)
                sl = row['status'].lower()
                row['cancelled'] = ('annull' in sl or 'gestrichen' in sl
                                    or 'cancel' in sl)
                row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
                row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                                  and not row['cancelled'])
                if row['flight'] or row['dest_name']:
                    out.append(row)
            except Exception:
                continue
    return out if out else None


def _board_utc_to_local(iso, zinfo):
    """ISO-Zeit (UTC 'Z', '+0000' oder mit Offset) → naive Airport-Ortszeit
    'YYYY-MM-DDTHH:MM:00' (gleiche Form wie alle Board-Quellen). None bei
    leer/unparsbar. Geteilter Helfer der EU-Adapter (Finavia/CPH/BRU/PRG…)."""
    if not iso:
        return None
    try:
        from datetime import datetime
        import re as _re
        s = str(iso).strip().replace('Z', '+00:00')
        s = _re.sub(r'([+-]\d{2})(\d{2})$', r'\1:\2', s)   # '+0000' → '+00:00' (PRG)
        dt = datetime.fromisoformat(s)
        if dt.tzinfo is not None and zinfo is not None:
            dt = dt.astimezone(zinfo)
        return dt.strftime('%Y-%m-%dT%H:%M:00')
    except Exception:
        return None


def _finavia_board(iata, flight_type='departure'):
    """FINAVIA-Gruppe (Finnland: HEL/OUL/RVN/TMP/TKU/VAA — eine Quelle für alle).

    Freies JSON-API (LIVE verifiziert 2026-07-06, keine Auth):
      GET https://www.finavia.fi/en/api/flights/all/<iata-LOWERCASE>/now
    → {'arr':[…], 'dep':[…]}. GOTCHAS (verifiziert): Airport-Code MUSS lowercase
    sein (…/all/HEL/now → 500); Pfad-Reihenfolge all/{airport}/{date}; 'uti' ist
    tot (404); ohne Browser-UA intermittierend 406. sdt/newTime/actualTime sind
    UTC ('Z') → Europe/Helsinki-Ortszeit wie _avinor_board. flightNumbers ist bei
    Codeshares KOMMASEPARIERT (erste Nummer = operierender Carrier). Departures:
    gate/terminal/chkdsk; Arrivals: gate + belt/bltarea. statusCode: DEP/LAN/EST/
    DLU/GTO/GTC/BRR/CNL/RMV/ETA (leer = nur Plan). KEIN Tail/Reg. Fenster ~8 Tage
    → Filter auf den heutigen Betriebstag (Helsinki)."""
    try:
        import requests
        try:
            from zoneinfo import ZoneInfo
            _z = ZoneInfo('Europe/Helsinki')
        except Exception:
            _z = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    code = (iata or '').strip().lower()
    if len(code) != 3:
        return None
    try:
        r = requests.get('https://www.finavia.fi/en/api/flights/all/' + code + '/now',
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json'}, timeout=12)
        if r.status_code != 200:
            return None
        body = r.json() or {}
        flights = body.get('arr' if arr else 'dep')
        if not isinstance(flights, list):
            return None
    except Exception:
        return None
    try:
        today = _airport_local_now(iata).strftime('%Y-%m-%d')
    except Exception:
        today = None
    out = []
    for f in flights:
        try:
            row = _empty_board_row()
            fno = (f.get('flightNumbers') or '').split(',')[0].strip().upper()
            acode, flight, _ac = _split_flightno(fno)
            row['airline'] = acode
            row['flight'] = flight or fno
            sched = _board_utc_to_local(f.get('sdt') or f.get('scheduled'), _z)
            row['sched'] = sched
            # Nur heutiger Betriebstag — der 'now'-Feed liefert ~8 Tage.
            if today and (not sched or not sched.startswith(today)):
                continue
            esti = (_board_utc_to_local(f.get('actualTime'), _z)
                    or _board_utc_to_local(f.get('newTime'), _z))
            if esti and esti != sched:
                row['esti'] = esti
            other = (f.get('originAirport') if arr else f.get('destinationAirport')) or {}
            row['dest_iata'] = (other.get('iataCode') or '').strip().upper()
            row['dest_name'] = _clean_city_name(
                f.get('origin') if arr else f.get('destination'), row['dest_iata'])
            row['gate'] = (f.get('gate') or (f.get('belt') if arr else '') or '').strip()
            row['terminal'] = (f.get('terminal') or '').strip()
            row['hall'] = ((f.get('bltarea') if arr else f.get('chkdsk')) or '').strip()
            row['status'] = (f.get('statusText') or '').strip()
            scode = (f.get('statusCode') or '').strip().upper()
            row['cancelled'] = scode in ('CNL', 'RMV') or 'cancel' in row['status'].lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _fraport_gr_board(iata, flight_type='departure'):
    """FRAPORT-GREECE-Gruppe (SKG/RHO/CFU/CHQ/KGS/ZTH — 14 regionale GR-Airports,
    gleiche AEM/JCR-Plattform wie frankfurt-airport.com, deutsche Feldnamen!).

    Freier JSON-Endpoint (LIVE verifiziert 2026-07-06, keine Auth):
      GET https://www.<iata>-airport.gr/en/_jcr_content.{departures|arrivals}.json
    OHNE time-Param (der ist quirky: CFU gab mit time=10:00 0 Rows) → aktuelles
    Board ab jetzt. GOTCHAS (verifiziert): Content-Type lügt (octet-stream, Body
    ist JSON); esti/lu-Sentinel '-0001-11-30 00:00:00' = leer; status-Leerwert ist
    literal '&nbsp;'; Actuals stecken NUR im status-Text ('Departed 10:23'). sched
    ist LOKALE Airport-Zeit (Europe/Athens) ohne Zone. apname = Stadt-Klartext
    ('Berlin BER') → Resolver. Departures: gate + schalter; Arrivals: ausgang
    (praktisch immer leer). al = ICAO-Airline. KEIN Tail/Reg."""
    try:
        import requests
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    code = (iata or '').strip().lower()
    if len(code) != 3:
        return None
    url = ('https://www.' + code + '-airport.gr/en/_jcr_content.'
           + ('arrivals' if arr else 'departures') + '.json')
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA,
                                       'Accept': 'application/json'}, timeout=12)
        if r.status_code != 200:
            return None
        data = (r.json() or {}).get('data')
        if not isinstance(data, list):
            return None
    except Exception:
        return None
    _SENTINEL = '-0001-11-30'
    out = []
    for f in data:
        try:
            row = _empty_board_row()
            fnr = (f.get('fnr') or '').strip().upper()
            acode, flight, _ac = _split_flightno(fnr)
            row['airline'] = acode
            row['flight'] = flight or fnr
            row['airline_name'] = (f.get('alname') or '').strip()
            sched = (f.get('sched') or '').strip()          # 'YYYY-MM-DD HH:MM:SS' lokal
            if sched and not sched.startswith(_SENTINEL):
                row['sched'] = sched[:10] + 'T' + sched[11:16] + ':00'
            esti = (f.get('esti') or '').strip()
            if esti and not esti.startswith(_SENTINEL):
                e = esti[:10] + 'T' + esti[11:16] + ':00'
                if e != row['sched']:
                    row['esti'] = e
            status = (f.get('status') or '').replace('&nbsp;', '').strip()
            row['status'] = status
            # Actuals nur im Status-Text ('Departed 10:23' / 'Arrived 10:15').
            if not row['esti'] and row['sched']:
                m = _re.search(r'(?:Departed|Arrived)\s+(\d{1,2}:\d{2})', status)
                if m:
                    e = row['sched'][:10] + 'T' + m.group(1).zfill(5) + ':00'
                    if e != row['sched']:
                        row['esti'] = e
            name = (f.get('apname') or '').strip()
            row['dest_iata'] = _board_origin_iata(name)
            row['dest_name'] = _clean_city_name(name, row['dest_iata'])
            row['terminal'] = str(f.get('terminal') or '').strip()
            if arr:
                row['gate'] = (f.get('ausgang') or '').strip()
            else:
                row['gate'] = (f.get('gate') or '').strip()
                row['hall'] = (f.get('schalter') or '').strip()   # Check-in-Counter
            row['cancelled'] = 'cancel' in status.lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _cph_board(flight_type='departure'):
    """CPH — Kopenhagen-Kastrup (cph.dk). Freies JSON-API (LIVE verifiziert
    2026-07-06, keine Auth):
      GET https://www.cph.dk/api/FlightInformation/GetFlightInfoTable
          ?direction={D|A}&userQuery=*:*&startDateTime=…Z&endDateTime=…Z&language=en
    GOTCHAS (verifiziert): userQuery MUSS '*:*' sein (sonst HTTP 500, sieht wie
    Botwall aus); Fenster-Params in UTC mit Millisekunden ('.000Z'), Response-
    Zeiten aber LOKAL mit Offset (+02:00). Kein separates Actual-Feld —
    ExpectedDateTime dient als est UND act (bei gelandeten sekundengenau).
    Delayed = bool. Bei Arrivals bedeutet IataDestination die HERKUNFT. KEIN
    Tail/Reg. Fenster = ganzer Betriebstag (Europe/Copenhagen)."""
    try:
        import requests
        from datetime import datetime, timedelta, timezone
        try:
            from zoneinfo import ZoneInfo
            _z = ZoneInfo('Europe/Copenhagen')
        except Exception:
            _z = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        now_l = datetime.now(_z) if _z is not None else datetime.now(timezone.utc)
        day_start = now_l.replace(hour=0, minute=0, second=0, microsecond=0)
        day_end = day_start + timedelta(days=1)
        fmt = '%Y-%m-%dT%H:%M:%S.000Z'
        r = requests.get('https://www.cph.dk/api/FlightInformation/GetFlightInfoTable',
                         params={'direction': 'A' if arr else 'D',
                                 'userQuery': '*:*',
                                 'startDateTime': day_start.astimezone(timezone.utc).strftime(fmt),
                                 'endDateTime': day_end.astimezone(timezone.utc).strftime(fmt),
                                 'language': 'en'},
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json'}, timeout=12)
        if r.status_code != 200:
            return None
        data = r.json()
        if not isinstance(data, list):
            return None
    except Exception:
        return None
    out = []
    for f in data:
        try:
            row = _empty_board_row()
            fno = (f.get('Iata') or '').strip().upper()
            acode, flight, _ac = _split_flightno(fno)
            row['airline'] = (f.get('IataAirline') or acode or '').strip().upper()
            row['flight'] = flight or fno
            row['airline_name'] = (f.get('Airline') or '').strip()
            sched = _board_utc_to_local(f.get('ScheduledDateTime'), _z)
            row['sched'] = sched
            esti = _board_utc_to_local(f.get('ExpectedDateTime'), _z)
            if esti and esti != sched:
                row['esti'] = esti
            row['dest_iata'] = (f.get('IataDestination') or '').strip().upper()
            row['dest_name'] = _clean_city_name(
                f.get('DestinationName') or f.get('Destination'), row['dest_iata'])
            row['gate'] = (f.get('Gate') or '').strip()
            row['terminal'] = (f.get('Terminal') or '').strip()
            row['status'] = (f.get('Status') or '').strip()
            sc = (f.get('StatusClass') or '').strip().lower()
            row['cancelled'] = sc == 'cancelled' or 'cancel' in row['status'].lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = ((bool(f.get('Delayed'))
                               or row['delay_min'] >= _DELAY_THRESHOLD_MIN)
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _bru_board(flight_type='departure'):
    """BRU — Brussels Airport (digitalservices-webapi.brusselsairport.be). Freies
    JSON-API (LIVE verifiziert 2026-07-06):
      GET /api/v1/ffp/flights?direction={DEPARTURE|ARRIVAL}&page=N
    → {'results':[…]} fix 50/Seite, Fenster = ganzer heutiger Tag (~14 Seiten) —
    wir paginieren bis leer (Cap 14). GOTCHAS (verifiziert): CloudFront blockt den
    curl-Default-UA (403) → Browser-UA reicht; sporadische Lambda-503 → Seite wird
    still übersprungen; Codeshare-Duplikate tragen id-Suffix 'DA'/'DB' → nur ids
    behalten, die (getrimmt) exakt auf den Richtungs-Buchstaben enden. Zeiten UTC
    ('Z') → Europe/Brussels. DEP: departure_flight.take_off_time.{scheduled,
    estimated,actual}_take_off_time; ARR: arrival_flight.landing_time.…_landing_
    time. KEIN Gate/Terminal/Tail im Listen-Objekt."""
    try:
        import requests
        import time as _t
        try:
            from zoneinfo import ZoneInfo
            _z = ZoneInfo('Europe/Brussels')
        except Exception:
            _z = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    dchar = 'A' if arr else 'D'
    items = []
    for page in range(1, 15):
        try:
            r = requests.get('https://digitalservices-webapi.brusselsairport.be'
                             '/api/v1/ffp/flights',
                             params={'direction': 'ARRIVAL' if arr else 'DEPARTURE',
                                     'page': page},
                             headers={'User-Agent': _BOARD_UA,
                                      'Accept': 'application/json'}, timeout=12)
            if r.status_code != 200:
                if page == 1:
                    return None
                break
            results = (r.json() or {}).get('results')
        except Exception:
            if page == 1:
                return None
            break
        if not results:
            break
        items.extend(results)
        if len(results) < 50:
            break
        _t.sleep(0.2)   # Lambda-Throttle-Schonung (~1 req/s war ok)
    out = []
    for f in items:
        try:
            fid = (f.get('id') or '').strip()
            # Codeshare-Duplikate ('…DA'/'…DB') überspringen — nur der operierende
            # Flug endet exakt auf den Richtungs-Buchstaben.
            if fid and not fid.endswith(dchar):
                continue
            row = _empty_board_row()
            row['airline'] = (f.get('carrier_code') or '').strip().upper()
            num = str(f.get('number') or '').strip()
            row['flight'] = (row['airline'] + ' ' + num).strip()
            if arr:
                tt = ((f.get('arrival_flight') or {}).get('landing_time') or {})
                sched = tt.get('scheduled_landing_time')
                act = tt.get('actual_landing_time')
                est = tt.get('estimated_landing_time')
                other_iata = (f.get('origin') or '').strip().upper()
                other_ap = f.get('origin_airport') or {}
            else:
                tt = ((f.get('departure_flight') or {}).get('take_off_time') or {})
                sched = tt.get('scheduled_take_off_time')
                act = tt.get('actual_take_off_time')
                est = tt.get('estimated_take_off_time')
                other_iata = (f.get('destination') or '').strip().upper()
                other_ap = f.get('destination_airport') or {}
            row['sched'] = _board_utc_to_local(sched, _z)
            esti = _board_utc_to_local(act, _z) or _board_utc_to_local(est, _z)
            if esti and esti != row['sched']:
                row['esti'] = esti
            row['dest_iata'] = other_iata
            row['dest_name'] = _clean_city_name(
                ((other_ap.get('name') or {}).get('en') if isinstance(other_ap.get('name'), dict)
                 else other_ap.get('name')), other_iata)
            status = (f.get('status') or '').strip()
            row['status'] = status.replace('_', ' ').title() if status else ''
            row['cancelled'] = status.upper() == 'CANCELLED'
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _lhr_board(flight_type='departure'):
    """LHR — Heathrow pihub-API (LIVE verifiziert 2026-07-06):
      GET https://api-dp-prod.dp.heathrow.com/pihub/flights/{departures|arrivals}
    GOTCHA (KRITISCH, verifiziert): Pflicht-Header ist `Origin:
    https://www.heathrow.com` — ohne → 403, UA egal. Antwort = JSON-Liste von
    {flightService:…} für den heutigen Betriebstag inkl. CODESHARE-Duplikaten
    (codeShareStatus 'CODESHARE_PARTNER…' → skippen). sched NUR als
    operatingTimes.scheduled.{utc,local} am eigenen portOfCall (LHR); est/act
    stecken in aircraftMovementStatus[].statusData[].data (HH:MM, Code AB/TX=act
    dep, LD/FB/LB=act arr, ES/EX=est). CX=cancelled. Gate/Terminal/Stand am
    LHR-Port; aircraftTransport trägt den Typ-Code. KEIN Tail/Reg."""
    try:
        import requests
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    url = ('https://api-dp-prod.dp.heathrow.com/pihub/flights/'
           + ('arrivals' if arr else 'departures'))
    try:
        r = requests.get(url, headers={'User-Agent': _BOARD_UA,
                                       'Origin': 'https://www.heathrow.com',
                                       'Accept': 'application/json'}, timeout=12)
        if r.status_code != 200:
            return None
        data = r.json()
        if not isinstance(data, list):
            return None
    except Exception:
        return None
    out = []
    for item in data:
        try:
            fs = (item or {}).get('flightService') or {}
            css = (fs.get('codeShareStatus') or '').upper()
            # Codeshare-Duplikate skippen: der Feed listet JEDE Marketing-Nummer
            # als eigenen Record (live gezählt: 1917 MARKETING vs 614 OPERATING
            # + 62 NORMAL = ~671 echte Movements).
            if 'MARKETING' in css or 'PARTNER' in css:
                continue
            row = _empty_board_row()
            fno = (fs.get('iataFlightIdentifier') or '').strip().upper()
            acode, flight, _ac = _split_flightno(fno)
            row['airline'] = ((fs.get('airlineParty') or {}).get('iataIdentifier')
                              or acode or '').strip().upper()
            row['flight'] = flight or fno
            row['airline_name'] = ((fs.get('airlineParty') or {}).get('name') or '').strip()
            mv = fs.get('aircraftMovement') or {}
            ports = ((mv.get('route') or {}).get('portsOfCall')) or []
            ours = other = None
            for p in ports:
                af = (p or {}).get('airportFacility') or {}
                if (af.get('iataIdentifier') or '').upper() == 'LHR':
                    ours = p
                else:
                    other = p
            if ours is None or other is None:
                continue
            sched_l = (((ours.get('operatingTimes') or {}).get('scheduled') or {})
                       .get('local') or '')
            if sched_l and len(sched_l) >= 16:
                row['sched'] = sched_l[:16] + ':00'
            oaf = (other.get('airportFacility') or {})
            row['dest_iata'] = (oaf.get('iataIdentifier') or '').strip().upper()
            row['dest_name'] = _clean_city_name(
                ((oaf.get('airportCityLocation') or {}).get('name'))
                or oaf.get('name'), row['dest_iata'])
            tf = ((ours.get('airportFacility') or {}).get('terminalFacility')) or {}
            row['terminal'] = (tf.get('code') or '').strip()
            row['gate'] = ((tf.get('gateFacility') or {}).get('gateNumber') or '').strip()
            row['aircraft'] = ((fs.get('aircraftTransport') or {}).get('icaoTypeCode')
                               or '').strip()
            code = ''
            for st in (mv.get('aircraftMovementStatus') or []):
                code = (st.get('statusCode') or '').strip().upper()
                row['status'] = (st.get('message') or '').strip()
                tm = None
                for sd in (st.get('statusData') or []):
                    m = _re.match(r'^(\d{1,2}:\d{2})$', str(sd.get('data') or '').strip())
                    if m:
                        tm = m.group(1).zfill(5)
                        break
                if tm and row['sched']:
                    e = row['sched'][:10] + 'T' + tm + ':00'
                    if e != row['sched']:
                        row['esti'] = e
                break   # erster Status-Eintrag = Board-Status der eigenen Seite
            row['cancelled'] = code == 'CX' or 'cancel' in row['status'].lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _prg_board(flight_type='departure'):
    """PRG — Prag (api.prg.aero, offener JSON-Host, LIVE verifiziert 2026-07-06):
      GET https://api.prg.aero/en/{departures|arrivals}-shorttime
          ?offset=0&limit=200&to=DD-MM-YYYY_HH-mm
    GOTCHAS (verifiziert): OHNE 'to' liefert das API Flüge von GESTERN → 'to' =
    Prag-Lokalzeit +12h als Obergrenze setzen (Liste = letzte `limit` Flüge bis
    'to'). time/time-new sind UTC ('+0000'!), state-Text trägt LOKALE Zeit —
    nicht mischen. destination-id = echtes IATA. gates = nur Pier-BUCHSTABE.
    state_id '5'=departed, '2'=arrived (String!), null=künftig. company-id =
    ICAO → airline aus flyNumber. KEIN Tail. Filter auf heutigen Prag-Tag
    (Fenster reicht ~24h zurück)."""
    try:
        import requests
        from datetime import datetime, timedelta, timezone
        try:
            from zoneinfo import ZoneInfo
            _z = ZoneInfo('Europe/Prague')
        except Exception:
            _z = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        now_l = datetime.now(_z) if _z is not None else datetime.now(timezone.utc)
        to = (now_l + timedelta(hours=12)).strftime('%d-%m-%Y_%H-%M')
        r = requests.get('https://api.prg.aero/en/'
                         + ('arrivals' if arr else 'departures') + '-shorttime',
                         params={'offset': 0, 'limit': 200, 'to': to},
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json'}, timeout=12)
        if r.status_code != 200:
            return None
        data = r.json()
        if not isinstance(data, list):
            return None
        today = now_l.strftime('%Y-%m-%d')
    except Exception:
        return None
    out = []
    for f in data:
        try:
            row = _empty_board_row()
            fno = (f.get('flyNumber') or '').strip().upper()
            acode, flight, _ac = _split_flightno(fno)
            row['airline'] = acode
            row['flight'] = flight or fno
            row['airline_name'] = (f.get('company') or '').strip()
            sched = _board_utc_to_local(f.get('time'), _z)
            row['sched'] = sched
            # Fenster reicht ~24h zurück → nur heutiger Prag-Betriebstag.
            if not sched or not sched.startswith(today):
                continue
            esti = _board_utc_to_local(f.get('time-new'), _z)
            if esti and esti != sched:
                row['esti'] = esti
            row['dest_iata'] = (f.get('destination-id') or '').strip().upper()
            dest = (f.get('destination') or '').strip()
            if dest.endswith(')') and '(' in dest:
                dest = dest[:dest.rfind('(')].strip()
            row['dest_name'] = _clean_city_name(dest, row['dest_iata'])
            row['gate'] = (f.get('gates') or '').strip()     # nur Pier-Buchstabe
            row['terminal'] = (f.get('terminal') or '').strip()
            row['hall'] = (f.get('hall') or '').strip()
            state = (f.get('state') or '').strip()
            row['status'] = '' if state == '-' else state
            row['cancelled'] = 'cancel' in state.lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _bud_board(flight_type='departure'):
    """BUD — Budapest (bud.hu Laravel-ajax, LIVE verifiziert 2026-07-06):
      GET https://www.bud.hu/ajax/flight-search
          ?locale=en&direction={departures|arrivals}&date=YYYY-MM-DD&time=HH:MM
    GOTCHAS (verifiziert): WAF blockt Default-curl-UA (403) → Browser-UA Pflicht;
    direction MUSS voll ausgeschrieben sein; Antwort-Fenster ist NUR ~2h ab
    time (Cap ~32 Rows) → wir holen 4 Slots (-2h/jetzt/+2h/+4h, Dedup über
    uniqueAutoId). planned/expected sind LOKALE 'HH:MM' + date DD.MM.YYYY
    (Europe/Budapest). registration-Feld existiert, war aber in ALLEN Samples
    leer → nicht als Tail-Quelle einplanen. Ziel nur als Stadtname ('London
    STN') → Resolver. Departures: gate+terminal+checkIn.rangeAllocated;
    Arrivals: baggageClaim."""
    try:
        import requests
        from datetime import datetime, timedelta, timezone
        try:
            from zoneinfo import ZoneInfo
            _z = ZoneInfo('Europe/Budapest')
        except Exception:
            _z = None
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        now_l = datetime.now(_z) if _z is not None else datetime.now(timezone.utc)
    except Exception:
        return None
    seen = set()
    out = []
    got_any = False
    for off_h in (-2, 0, 2, 4):
        slot = now_l + timedelta(hours=off_h)
        try:
            r = requests.get('https://www.bud.hu/ajax/flight-search',
                             params={'locale': 'en',
                                     'direction': 'arrivals' if arr else 'departures',
                                     'date': slot.strftime('%Y-%m-%d'),
                                     'time': slot.strftime('%H:%M')},
                             headers={'User-Agent': _BOARD_UA,
                                      'Accept': 'application/json'}, timeout=12)
            if r.status_code != 200:
                continue
            data = r.json()
            if not isinstance(data, list):
                continue
            got_any = True
        except Exception:
            continue
        for f in data:
            try:
                uid = f.get('uniqueAutoId') or (str(f.get('flightNumber'))
                                                + str(f.get('timestamp')))
                if uid in seen:
                    continue
                seen.add(uid)
                row = _empty_board_row()
                fno = (f.get('flightNumber') or '').strip().upper()
                acode, flight, _ac = _split_flightno(fno)
                row['airline'] = acode
                row['flight'] = flight or fno
                row['airline_name'] = ((f.get('airline') or {}).get('name') or '').strip()
                d = (f.get('date') or '').strip()            # 'DD.MM.YYYY'
                day = ''
                if len(d) == 10:
                    day = d[6:10] + '-' + d[3:5] + '-' + d[0:2]
                planned = (f.get('planned') or '').strip()
                if day and planned:
                    row['sched'] = day + 'T' + planned.zfill(5) + ':00'
                expected = (f.get('expected') or '').strip() if f.get('expected') else ''
                if day and expected and expected != planned:
                    row['esti'] = day + 'T' + expected.zfill(5) + ':00'
                name = (f.get('city') or f.get('destination') or '').strip()
                row['dest_iata'] = _board_origin_iata(name)
                row['dest_name'] = _clean_city_name(name, row['dest_iata'])
                row['gate'] = (f.get('gate') or '').strip()
                row['terminal'] = (f.get('terminal') or '').strip()
                if arr:
                    row['hall'] = str(f.get('baggageClaim') or '').strip()
                else:
                    row['hall'] = ((f.get('checkIn') or {}).get('rangeAllocated')
                                   or '').strip()
                row['reg'] = (f.get('registration') or '').strip()
                st = f.get('status') or {}
                row['status'] = (st.get('text') or '').strip()
                row['cancelled'] = (st.get('type') or '').strip().lower() == 'cancelled'
                row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
                row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                                  and not row['cancelled'])
                if row['flight'] or row['dest_name']:
                    out.append(row)
            except Exception:
                continue
    if not got_any:
        return None
    return out if out else None


def _ana_board(iata, flight_type='departure'):
    """ANA-PORTUGAL-Gruppe (LIS/OPO/FAO/FNC — ein Drupal-Proxy für alle ANA-
    Airports, LIVE verifiziert 2026-07-06, keine Auth):
      GET https://www.ana.pt/en/flights_proxy?day=hoje&movtype={D|A}&IATA=<IATA>
    GOTCHAS (verifiziert): Content-Type lügt (text/html, Body = JSON);
    state.value hat führendes Leerzeichen (' 08:07'); sharedAirlinesFlights ist
    mal Liste, mal ''-String. Zeiten sind bereits LOKALE Airport-Zeit (Europe/
    Lisbon bzw. Atlantic/Madeira für FNC — KEINE Konversion nötig), day =
    DD/MM/YYYY. state.label: Estimated/Boarding/Final Call/Closed/Departed/
    Arrived/Cancelled/'' — est vs act nur über das Label unterscheidbar.
    destination = Stadtname ggf. mit Zusatz ('London, Heathrow') → Resolver.
    KEIN Gate, KEIN Tail/Reg."""
    try:
        import requests
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    code = (iata or '').strip().upper()
    if len(code) != 3:
        return None
    try:
        r = requests.get('https://www.ana.pt/en/flights_proxy',
                         params={'day': 'hoje', 'movtype': 'A' if arr else 'D',
                                 'IATA': code},
                         headers={'User-Agent': _BOARD_UA,
                                  'Accept': 'application/json'}, timeout=12)
        if r.status_code != 200:
            return None
        flights = (r.json() or {}).get('flights')
        if not isinstance(flights, list):
            return None
    except Exception:
        return None
    out = []
    for f in flights:
        try:
            row = _empty_board_row()
            fno = (f.get('flightNumber') or '').strip().upper()
            acode, flight, _ac = _split_flightno(fno)
            row['airline'] = acode
            row['flight'] = flight or fno
            row['airline_name'] = (f.get('airline') or '').strip().title()
            d = (f.get('day') or '').strip()                 # 'DD/MM/YYYY' lokal
            day = ''
            if len(d) == 10:
                day = d[6:10] + '-' + d[3:5] + '-' + d[0:2]
            tm = (f.get('time') or '').strip()
            if day and tm:
                row['sched'] = day + 'T' + tm.zfill(5) + ':00'
            st = f.get('state') or {}
            label = (st.get('label') or '').strip()
            val = (st.get('value') or '').strip()            # führendes Leerzeichen!
            if day and _re.match(r'^\d{1,2}:\d{2}$', val):
                e = day + 'T' + val.zfill(5) + ':00'
                if e != row['sched']:
                    row['esti'] = e
            name = (f.get('destination') or '').strip()
            row['dest_iata'] = _board_origin_iata(name)
            row['dest_name'] = _clean_city_name(name, row['dest_iata'])
            row['terminal'] = (f.get('terminal') or '').strip()
            row['status'] = label
            row['cancelled'] = 'cancel' in label.lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _fco_board(flight_type='departure'):
    """FCO — Rom-Fiumicino (adr.it Liferay-Realtime-Portlet, server-gerendertes
    HTML — LIVE verifiziert 2026-07-06, sauber parsebar ohne Playwright):
      GET pax-fco-realtime-flight?p_p_id=3_WAR_realtimeflightsportlet&…
          &_3_WAR_realtimeflightsportlet_tab={departure|arrival}
          &_3_WAR_realtimeflightsportlet_searchType=completeSmall&…_delta=75
    GOTCHAS (verifiziert): UA-Blacklist (Default-curl/python-requests-UA → 403,
    Browser-UA ok); ohne searchType=completeSmall liefert der arrival-Tab 0 Rows.
    Row = tr[data-qa-id=row]: .date-estimated__time = SOLL (Label heißt
    verwirrend 'Actual time', bei Delay strikethrough), .date-actual__time =
    'Effective time' (est/act), .flight-code strong = 'LH 1873', .blue-title =
    'MUNICH (MUC)', .terminal-icon = T1/T3, Status-h5 (Landed/Estimated/
    Departed/Cancelled). Zeiten LOKAL (Europe/Rome) ohne Datum → heutiger Tag.
    KEIN Tail/Reg; Gate nur auf der Detail-Seite (nicht geholt)."""
    try:
        import requests
        from bs4 import BeautifulSoup
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        r = requests.get('https://www.adr.it/web/aeroporti-di-roma-en/'
                         'pax-fco-realtime-flight',
                         params={'p_p_id': '3_WAR_realtimeflightsportlet',
                                 'p_p_lifecycle': '0', 'p_p_state': 'normal',
                                 'p_p_mode': 'view',
                                 '_3_WAR_realtimeflightsportlet_tab':
                                     'arrival' if arr else 'departure',
                                 '_3_WAR_realtimeflightsportlet_searchType':
                                     'completeSmall',
                                 '_3_WAR_realtimeflightsportlet_delta': '75'},
                         headers={'User-Agent': _BOARD_UA, 'Accept': 'text/html'},
                         timeout=15)
        if r.status_code != 200 or not r.text:
            return None
        soup = BeautifulSoup(r.text, 'html.parser')
        day = _airport_local_now('FCO').strftime('%Y-%m-%d')
    except Exception:
        return None
    out = []
    for tr in soup.select('tr[data-qa-id="row"]'):
        try:
            row = _empty_board_row()
            sc = tr.select_one('.date-estimated__time')
            if sc is not None:
                m = _re.search(r'(\d{1,2}:\d{2})', sc.get_text(' ', strip=True))
                if m:
                    row['sched'] = day + 'T' + m.group(1).zfill(5) + ':00'
            ec = tr.select_one('.date-actual__time')
            if ec is not None:
                m = _re.search(r'(\d{1,2}:\d{2})', ec.get_text(' ', strip=True))
                if m:
                    e = day + 'T' + m.group(1).zfill(5) + ':00'
                    if e != row['sched']:
                        row['esti'] = e
            fc = tr.select_one('.flight-code strong') or tr.select_one('.flight-code')
            if fc is not None:
                acode, flight, _ac = _split_flightno(fc.get_text(' ', strip=True))
                row['airline'] = acode
                row['flight'] = flight
            logo = tr.select_one('.carrier-logo img')
            if logo is not None:
                row['airline_name'] = (logo.get('alt') or '').strip().title()
            bt = tr.select_one('.blue-title')
            if bt is not None:
                # Innen-Whitespace kollabieren ('DETROIT     MI' → 'DETROIT MI').
                dest = _re.sub(r'\s+', ' ', bt.get_text(' ', strip=True)).strip()
                m = _re.search(r'\(([A-Z]{3})\)\s*$', dest)
                if m:
                    row['dest_iata'] = m.group(1)
                    dest = _re.sub(r'\s*\([A-Z]{3}\)\s*$', '', dest).strip()
                row['dest_name'] = _clean_city_name(dest.title(), row['dest_iata'])
            ti = tr.select_one('.terminal-icon')
            if ti is not None:
                row['terminal'] = ti.get_text(' ', strip=True)
            stc = tr.select_one('.lfr-flight-status-column h5')
            if stc is not None:
                row['status'] = stc.get_text(' ', strip=True)
            row['cancelled'] = 'cancel' in row['status'].lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_iata']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


def _lgw_board(flight_type='departure'):
    """LGW — London-Gatwick (Demandware-Controller, HTML-Fragment — LIVE
    verifiziert 2026-07-06, keine Auth):
      GET /on/demandware.store/Sites-Gatwick-Site/en_GB/LiveFlights-FetchFlights
          ?page=N&terminal=&destination={D|A}&search=
    → tr.flight-line, id='EZY8287_2026-07-06_D' (Flugnr+DATUM+Richtung!).
    Zellen (Desktop-Row): [logo, ZEIT, ZIEL/HERKUNFT, toggle, FLUGNR, STATUS,
    (GATE nur Dep), TERMINAL North/South, …]. GOTCHAS (verifiziert): jede Info
    erscheint doppelt (mobile-sub-menu-Rows id='mob_…' → NICHT selektieren);
    Status-Text trägt die est/act-Zeit ('Departed 09:38'/'Landed 09:42'/
    'Expected 11:20'/'Bags delivered 09:28'); 'Enquire Airline' = kein Status.
    Zeiten = Europe/London Board-Zeit, Datum aus der Row-id. Ziel nur Stadtname
    → Resolver. Wir blättern page 0-2 (~65-70 Rows/Seite). KEIN Tail/Reg."""
    try:
        import requests
        from bs4 import BeautifulSoup
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    trs = []
    for page in range(0, 3):
        try:
            r = requests.get('https://www.gatwickairport.com/on/demandware.store/'
                             'Sites-Gatwick-Site/en_GB/LiveFlights-FetchFlights',
                             params={'page': page, 'terminal': '',
                                     'destination': 'A' if arr else 'D',
                                     'search': ''},
                             headers={'User-Agent': _BOARD_UA, 'Accept': 'text/html'},
                             timeout=12)
            if r.status_code != 200 or not r.text:
                break
            soup = BeautifulSoup(r.text, 'html.parser')
            page_rows = soup.select('tr.flight-line')
        except Exception:
            break
        if not page_rows:
            break
        trs.extend(page_rows)
    if not trs:
        return None
    _status_re = _re.compile(
        r'^(Departed|Taxied|Landed|Expected|Delayed|Cancelled|Diverted|Boarding|'
        r'Final Call|Gate\b|Bags delivered|On time)', _re.I)
    out = []
    seen = set()
    for tr in trs:
        try:
            rid = (tr.get('id') or '').strip()               # 'EZY8287_2026-07-06_D'
            if not rid or rid.startswith('mob_') or rid in seen:
                continue
            seen.add(rid)
            parts = rid.split('_')
            row = _empty_board_row()
            day = parts[1] if len(parts) >= 2 and len(parts[1]) == 10 else ''
            acode, flight, _ac = _split_flightno(parts[0] if parts else '')
            row['airline'] = acode
            row['flight'] = flight
            tds = tr.find_all('td')
            texts = [td.get_text(' ', strip=True) for td in tds]
            tcell = tr.select_one('td.time')
            if tcell is not None and day:
                m = _re.search(r'(\d{1,2}:\d{2})', tcell.get_text(' ', strip=True))
                if m:
                    row['sched'] = day + 'T' + m.group(1).zfill(5) + ':00'
            dcell = tr.select_one('td.destination')
            if dcell is not None:
                name = dcell.get_text(' ', strip=True)
                row['dest_iata'] = _board_origin_iata(name)
                row['dest_name'] = _clean_city_name(name, row['dest_iata'])
            status_idx = None
            for i, t in enumerate(texts):
                if t and _status_re.match(t):
                    status_idx = i
                    row['status'] = t
                    break
            if row['status'] and day:
                m = _re.search(r'(\d{1,2}:\d{2})', row['status'])
                if m:
                    e = day + 'T' + m.group(1).zfill(5) + ':00'
                    if e != row['sched']:
                        row['esti'] = e
            for t in texts:
                if t in ('North', 'South'):
                    row['terminal'] = t
                    break
            # Gate (nur Departures): Zelle zwischen Status und Terminal.
            if not arr and status_idx is not None:
                for t in texts[status_idx + 1:]:
                    if t in ('North', 'South'):
                        break
                    if t and _re.match(r'^[0-9]{1,3}[A-Z]?$', t):
                        row['gate'] = t
                        break
            row['cancelled'] = 'cancel' in row['status'].lower()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _DELAY_THRESHOLD_MIN
                              and not row['cancelled'])
            if row['flight'] or row['dest_name']:
                out.append(row)
        except Exception:
            continue
    return out if out else None


