# Airports, deren native Quelle KEIN echtes „now"-Fenster liefern kann und darum
# unbrauchbar für die anstehende Tafel ist → AeroDataBox BEVORZUGEN (now→+24h mit
# Soll-Zeit), nativer Scraper nur als Fallback (kein Key / Quelle down).
#   MUC: munich-airport.com/flightsearch liefert nur die ersten ~20 Abflüge des Tages
#        ab 00:00 (keine Pagination, kein Zeit-Parameter) → nachmittags ist alles davon
#        längst abgeflogen und die anstehende Tafel wäre leer.
_BOARD_PREFER_AERODATABOX = {'MUC'}


def _aerodatabox_board(iata, flight_type='departure'):
    """Board (Abflug/Ankunft) eines beliebigen IATA-Airports via AeroDataBox
    (RapidAPI, env-gated AERODATABOX_KEY). Liefert Rows im FRA-Contract oder None
    (kein Key / Quelle down / leer → Caller degradiert ehrlich). KEINE Erfindung."""
    import os as _os
    key = _os.environ.get('AERODATABOX_KEY')
    if not key:
        return None
    iata = (iata or '').upper().strip()
    if len(iata) != 3:
        return None
    try:
        import requests
        from datetime import datetime, timezone, timedelta
        import re as _re
    except Exception:
        return None
    arr = (flight_type == 'arrival')
    try:
        now = _airport_local_now(iata)
    except Exception:
        now = datetime.now(timezone.utc)

    def _adb_window(frm_dt, to_dt):
        """Ein AeroDataBox-Call für ein <=12h-Fenster. Rohe Items oder None."""
        frm = frm_dt.strftime('%Y-%m-%dT%H:%M')
        to = to_dt.strftime('%Y-%m-%dT%H:%M')
        url = ('https://aerodatabox.p.rapidapi.com/flights/airports/iata/'
               + iata + '/' + frm + '/' + to)
        try:
            r = requests.get(url,
                             params={'direction': 'Arrival' if arr else 'Departure',
                                     'withLocation': 'false', 'withCancelled': 'true',
                                     'withCodeshared': 'false', 'withCargo': 'true',
                                     'withPrivate': 'false'},
                             headers={'X-RapidAPI-Key': key,
                                      'X-RapidAPI-Host': 'aerodatabox.p.rapidapi.com'},
                             timeout=15)
            if r.status_code != 200:
                return None
            body = r.json() or {}
        except Exception:
            return None
        return body.get('arrivals' if arr else 'departures') or []

    # AeroDataBox: max 12h pro Call. EIN 12h-Fenster ab jetzt schnitt Langstrecken-
    # Flüge ab, die erst später am Tag abfliegen (LH-Langstrecke). Darum ZWEI
    # aufeinanderfolgende 12h-Fenster (= 24h ab jetzt) holen und mergen → der ganze
    # verbleibende Betriebstag ist sichtbar. Dedup über (number, scheduledTime).
    # KEINE Erfindung — nur nicht mehr droppen. Schlägt der erste Call fehl → None
    # (ehrlich Quelle-down); der zweite ist best-effort (None → einfach kein Extra).
    first = _adb_window(now, now + timedelta(hours=12))
    if first is None:
        return None
    second = _adb_window(now + timedelta(hours=12), now + timedelta(hours=24)) or []
    items = []
    seen_keys = set()
    for f in list(first) + list(second):
        try:
            mv0 = (f.get('movement') or f.get('arrival' if arr else 'departure')
                   or f.get('departure' if arr else 'arrival') or {})
            sch0 = ((mv0.get('scheduledTime') or {}).get('local')
                    or (mv0.get('scheduledTime') or {}).get('utc') or '')
            dk = ((f.get('number') or '').strip(), sch0)
        except Exception:
            dk = None
        if dk is not None:
            if dk in seen_keys:
                continue
            seen_keys.add(dk)
        items.append(f)

    def _t_local(v):
        node = v or {}
        return ((node.get('local') or node.get('utc')) or None)

    out = []
    for f in items:
        try:
            row = _empty_board_row()
            al = f.get('airline') or {}
            row['airline'] = (al.get('iata') or '').strip().upper()
            row['airline_name'] = (al.get('name') or '').strip()
            row['flight'] = (f.get('number') or '').replace('  ', ' ').strip()
            if not row['airline'] and row['flight']:
                row['airline'] = (row['flight'].split(' ')[0] or '')[:3]
            # Beim Board-Eintrag steht das ANDERE Ende unter movement.airport.
            # AeroDataBox liefert je nach API-Variante 'movement' ODER ein nach der
            # Richtung benanntes Sub-Objekt ('departure'/'arrival') — beides stützen.
            mv = (f.get('movement') or f.get('arrival' if arr else 'departure')
                  or f.get('departure' if arr else 'arrival') or {})
            ap = mv.get('airport') or {}
            row['dest_iata'] = (ap.get('iata') or '').strip().upper()
            row['dest_name'] = _clean_city_name(ap.get('name'), row['dest_iata'])
            sched = _t_local(mv.get('scheduledTime'))
            revised = (_t_local(mv.get('revisedTime'))
                       or _t_local(mv.get('predictedTime'))
                       or _t_local(mv.get('actualTime')))
            row['sched'] = (sched or '').replace(' ', 'T') if sched else None
            if revised:
                rev = revised.replace(' ', 'T')
                if rev != row['sched']:
                    row['esti'] = rev
            row['gate'] = (mv.get('gate') or '').strip()
            row['terminal'] = (mv.get('terminal') or '').strip()
            row['status'] = (f.get('status') or '').strip()
            acft = f.get('aircraft') or {}
            row['aircraft'] = (acft.get('model') or '').strip()
            row['reg'] = (acft.get('reg') or '').strip()
            row['delay_min'] = _board_delay_min(row['sched'], row['esti'])
            row['delayed'] = (row['delay_min'] >= _AERODATABOX_DELAY_THRESHOLD
                              and 'cancel' not in row['status'].lower())
            # Bahn/Bus (falls AeroDataBox mal Nicht-Luftfahrzeug liefert) raus.
            if _is_rail_or_bus(row):
                continue
            out.append(row)
        except Exception:
            continue
    return out


def _native_board_cached(iata, flight_type, allow_paid=True):
    """Gecachtes Native-Board (12 Min TTL). Reihenfolge: nativer Scraper →
    AeroDataBox-Board → None. Gibt (rows, source) zurück; None-rows = alle
    (erlaubten) Quellen down/leer/kein-Key → Caller degradiert ehrlich.
    Niemals raise.

    allow_paid=False (free_only-Fan-out, Friends/Family/Radar): BEIDE
    AeroDataBox-Zweige (prefer-ADB UND Scraper-None-Fallback) werden
    STRUKTURELL übersprungen — liefert der (gratis) native Scraper nichts,
    kommt schlicht (None, None) zurück statt bezahlter Spend. Der bezahlte
    Pfad (Default) bleibt unverändert."""
    import time as _t
    iata = (iata or '').upper().strip()
    ft = 'arrival' if flight_type == 'arrival' else 'departure'
    ckey = (iata, ft)
    cached = _NATIVE_BOARD_CACHE.get(ckey)
    if cached and (_t.time() - cached[0]) < _NATIVE_BOARD_TTL:
        return cached[1]
    prefer_adb = iata in _BOARD_PREFER_AERODATABOX
    if not allow_paid and prefer_adb:
        # Free-Pfad eines PREFER-ADB-Airports (MUC): EIGENER Cache-Slot. Die
        # (degradierten) nativen Rows dürfen den geteilten Slot nicht 12 Min
        # „vergiften" — sonst servierte der bezahlte Pfad statt des bevorzugten
        # ADB-Boards die kaputte native Tafel. Der geteilte Slot oben wird
        # trotzdem zuerst gelesen (bereits bezahlte Daten lesen kostet nichts).
        ckey = (iata, ft, 'free')
        cached = _NATIVE_BOARD_CACHE.get(ckey)
        if cached and (_t.time() - cached[0]) < _NATIVE_BOARD_TTL:
            return cached[1]
    result = (None, None)
    scraper = _NATIVE_BOARD_SCRAPERS.get(iata)
    # MUC-Sonderfall: AeroDataBox ZUERST (echtes now→+24h-Fenster mit Soll-Zeit).
    # Ohne Key/Quelle down → None → fällt auf den (reparierten) nativen Scraper
    # zurück. NUR wenn bezahlter Spend erlaubt ist.
    if prefer_adb and allow_paid:
        try:
            rows = _aerodatabox_board(iata, ft)
        except Exception:
            rows = None
        if rows:
            result = (rows, 'aerodatabox')
    if result[0] is None and scraper:
        try:
            rows = scraper(ft)
        except Exception:
            rows = None
        if rows:   # nur cachen/zurückgeben wenn nicht-leer
            result = (rows, iata.lower() + '_native')
    if result[0] is None and allow_paid and not prefer_adb:
        try:
            rows = _aerodatabox_board(iata, ft)
        except Exception:
            rows = None
        if rows is not None:
            result = (rows, 'aerodatabox')
    # Nur erfolgreiche/definitive Ergebnisse cachen (None nicht — sonst bleibt ein
    # transienter Quellen-Ausfall 12 Min „kleben").
    if result[0] is not None:
        _NATIVE_BOARD_CACHE[ckey] = (_t.time(), result)
        _cache_soft_cap(_NATIVE_BOARD_CACHE)
    return result


def _fra_board_cached(flight_type):
    """Gecachtes FRA-Board (dep/arr). None bei Quelle-down."""
    import time as _t
    ckey = 'FRA_' + ('arr' if flight_type == 'arrival' else 'dep')
    cached = _AIRPORT_BOARD_CACHE.get(ckey)
    if cached and (_t.time() - cached[0]) < _AIRPORT_BOARD_TTL:
        return cached[1]
    # Viele Seiten holen — der Fraport-Feed ist eine now-relative, nach sched
    # sortierte Rolling-Liste (~25 Flüge/Seite). Mit nur 3 Seiten (~75 Flüge)
    # fielen Langstrecken-Flüge, die erst später am Tag abfliegen (viele LH-
    # Langstrecken), aus dem Fenster — nach dem "Nur LH"-Filter fehlten sie ganz.
    # Gleiche Tiefe wie die Tages-Tafel (`_fra_day_board_cached`), damit ALLE
    # echten Flüge des Tages sichtbar sind. KEINE Erfindung — nur nicht mehr droppen.
    # + VERGANGENHEITS-Seiten (siehe _FRA_PAST_PAGES): gelandete/abgeflogene Flüge
    # wandern binnen Minuten auf negative Feed-Seiten — ohne sie sah der Poller
    # Ankünfte praktisch nie und die Warehouse-Historie blieb löchrig. Die
    # Display-Seite filtert Vergangenes ohnehin (raus aus „anstehend", rein in
    # „Früher heute") — hier geht es um die Persistenz.
    flights = _fetch_fra_flights(flight_type, max_pages=20,
                                 past_pages=_FRA_PAST_PAGES)
    if flights is None:
        return None
    _AIRPORT_BOARD_CACHE[ckey] = (_t.time(), flights)
    return flights


# Betriebstag-Anker: der Tag beginnt um 05:00 Ortszeit (Europe/Berlin). Alles vor
# 05:00 (Frühschicht-Vorlauf / Nacht-Restflüge des Vortags) zählt NICHT zum heutigen
# Pünktlichkeits-Tag. So ist das Fenster TAGES-fixiert (immer ab 05:00) statt
# now-relativ → stabile %-Zahl, die nur wächst statt zu springen.
_FRA_OPERATING_DAY_START_HOUR = 5


def _fra_local_now():
    """Aktuelle Europe/Berlin-Lokalzeit als naive datetime (gleiche Basis wie die
    Fraport-`sched`-Strings, die lokal ohne Offset kommen). DST-robust via ZoneInfo,
    Fallback +2 (CEST) / grob, ohne harte pytz-Abhängigkeit."""
    from datetime import datetime, timezone, timedelta
    try:
        from zoneinfo import ZoneInfo
        return datetime.now(ZoneInfo('Europe/Berlin')).replace(tzinfo=None)
    except Exception:
        # Fallback: CEST (+2). Im Winter minimal off, aber 05:00-Anker bleibt stabil.
        return datetime.now(timezone(timedelta(hours=2))).replace(tzinfo=None)


def _airport_local_now(iata):
    """Aktuelle LOKALZEIT am Flughafen `iata` als naive datetime — gleiche Basis
    wie die `sched`-Strings, die die Board-Quellen (Fraport/native/AeroDataBox)
    lokal (ohne verlässlichen Offset) liefern. FRA/None/unbekannt → Europe/Berlin.

    WARUM (BUGFIX 2026-06-13 „Tafel speichert nicht vollständig"): Der
    `passed`-Check (`_flight_sched_passed`) verglich JEDEN Flughafen gegen die
    Berlin-Zeit. Für einen Flughafen in einer anderen Zeitzone (z.B. JFK, UTC-4)
    war „jetzt" so um Stunden verschoben → noch nicht abgeflogene Flüge wurden
    voreilig als abgeflogen persistiert (Phantom) ODER bereits abgeflogene gar
    nicht als „passed" erkannt → die Tages-Stichprobe war systematisch falsch/
    unvollständig. Jetzt ankern wir an der ECHTEN Flughafen-Ortszeit."""
    from datetime import datetime, timezone, timedelta
    tzname = None
    try:
        ap = (iata or '').upper().strip().split('#', 1)[0]  # '#ARR'-Suffix entfernen
        ap = _DE_ICAO_TO_IATA.get(ap, ap)
        if ap and ap not in ('FRA', 'EDDF'):
            tzname = airport_tz(ap)
    except Exception:
        tzname = None
    if not tzname:
        return _fra_local_now()
    try:
        from zoneinfo import ZoneInfo
        return datetime.now(ZoneInfo(tzname)).replace(tzinfo=None)
    except Exception:
        # Kein zoneinfo/unbekannte TZ → ehrlich auf Berlin zurückfallen.
        return _fra_local_now()


def _parse_local_iso(s):
    """Parst einen Fraport-ISO-String (lokal, evtl. mit Offset) zu naiver
    Lokalzeit. None bei Unparsbar."""
    if not s:
        return None
    from datetime import datetime
    try:
        dt = datetime.fromisoformat(str(s))
        if dt.tzinfo is not None:
            dt = dt.replace(tzinfo=None)
        return dt
    except Exception:
        # Fallback: nur Datum+Uhrzeit-Prefix.
        try:
            return datetime.strptime(str(s)[:19], '%Y-%m-%dT%H:%M:%S')
        except Exception:
            return None


def _fra_day_board_cached(flight_type='departure'):
    """Gecachte VOLLE Tages-Tafel (für Pünktlichkeit), TAGES-ANKERT ab 05:00
    Ortszeit (Europe/Berlin). Holt deutlich mehr Seiten als das normale Board und
    behält jeden Flug mit `sched` >= heute 05:00 lokal → echte Tagesaggregation,
    fixiertes Fenster statt now-relative Momentaufnahme. None bei Quelle-down.
    Dedupliziert über (flight, sched).

    WICHTIG: Hier ist KEINE now-Obergrenze — die volle Liste (auch noch nicht
    abgeflogene Flüge) wird gecacht, damit Ticker/Cancellations/Busiest-Routes den
    ganzen Tag sehen. Die Pünktlichkeits-Quote (`_punctuality_stats`) zählt davon
    nur die bereits abgeflogenen (sched <= now) → stabile, nur-wachsende Zahl."""
    import time as _t
    ckey = 'FRA_DAY_' + ('arr' if flight_type == 'arrival' else 'dep')
    cached = _AIRPORT_DAY_CACHE.get(ckey)
    if cached and (_t.time() - cached[0]) < _AIRPORT_DAY_TTL:
        return cached[1]
    # Viele Seiten → so viel vom Tag wie Fraport ausliefert — inkl. der
    # VERGANGENHEITS-Seiten (negative Pages), sonst besteht die „Tages"-Tafel
    # nur aus Zukunft und die Pünktlichkeits-Stichprobe hängt am Poll-Zufall.
    flights = _fetch_fra_flights(flight_type, max_pages=20,
                                 past_pages=_FRA_PAST_PAGES)
    if flights is None:
        return None
    # Betriebstag-Start = heute 05:00 Ortszeit (Europe/Berlin).
    try:
        local_now = _fra_local_now()
        day_start = local_now.replace(hour=_FRA_OPERATING_DAY_START_HOUR,
                                      minute=0, second=0, microsecond=0)
    except Exception:
        day_start = None
    seen = set()
    day = []
    for f in flights:
        sch = (f.get('sched') or '')
        key = (f.get('flight') or '', sch)
        if key in seen:
            continue
        seen.add(key)
        if day_start is not None:
            sdt = _parse_local_iso(sch)
            # Nur Flüge des heutigen Betriebstags (sched >= heute 05:00 lokal).
            if sdt is None or sdt < day_start:
                continue
        day.append(f)
    # Proactive delay-capture: auch ohne Pünktlichkeits-Endpoint-Aufruf persistieren.
    try:
        today_str = _fra_local_now().strftime('%Y-%m-%d')
        _merge_into_delay_store(day, today_str)
    except Exception:
        pass
    _AIRPORT_DAY_CACHE[ckey] = (_t.time(), day)
    return day


# ICAO→IATA für die großen deutschen Bases (iOS kann ICAO schicken). FRA bleibt
# der einzige Sonderweg (Fraport-Gratis-Feed). Native-Scraper + AeroDataBox laufen
# über IATA.
_DE_ICAO_TO_IATA = {
    'EDDF': 'FRA', 'EDDM': 'MUC', 'EDDL': 'DUS', 'EDDH': 'HAM', 'EDDB': 'BER',
    'EDDV': 'HAJ', 'EDDK': 'CGN', 'EDDS': 'STR', 'EDDN': 'NUE', 'EDDP': 'LEJ',
    'EDDC': 'DRS', 'EDLW': 'DTM', 'EDDW': 'BRE', 'EDLV': 'NRN', 'EDJA': 'FMM',
    'EDDG': 'FMO', 'EDLP': 'PAD', 'EDHL': 'LBC', 'EDHI': 'XFW',
}


def _store_key_for(airport, ftype):
    """Store-/Persistenz-Schlüssel pro Airport+Richtung. Departures behalten den
    nackten IATA-Key ('FRA') — abwärtskompatibel mit bereits persistierten Rows.
    Arrivals bekommen den Suffix '#ARR' ('FRA#ARR'), damit An- und Abflüge sich im
    selben airport_delay_obs nicht überschreiben (gleiche Flugnummer+Zeit kann in
    beiden Richtungen vorkommen) und jede Tafel ihre eigene Historie aufbaut."""
    ap = (airport or 'FRA').upper().strip()
    return (ap + '#ARR') if ftype == 'arrival' else ap


def _store_key_base(airport):
    """Nackter IATA-Code aus einem Store-Key ('FRA#ARR' → 'FRA') — für TZ-Lookup."""
    ap = (airport or 'FRA').upper().strip()
    return ap.split('#', 1)[0]


def _departed_rows_from_store(airport):
    """Bereits abgeflogene Flüge des heutigen Betriebstags aus dem Delay-Store
    rekonstruieren — für die „früher heute"-Ansicht der Tafel (User-Wunsch:
    zurück in der Zeit). Quelle ist die akkumulierte Pünktlichkeits-Beobachtung
    (airport_delay_obs), die der Poller über den Tag füllt. SPARSE: Flugnummer,
    Soll-Zeit, Verspätung/Status — KEIN Gate/Ziel (im Store nicht gehalten).
    Für FRA der einzige Weg an abgeflogene Flüge (der Live-Feed ist now-relativ)."""
    ap = (airport or 'FRA').upper()
    is_arr = ap.endswith('#ARR')
    try:
        # Betriebstag in der FLUGHAFEN-Ortszeit (nicht stur Berlin) — sonst trifft
        # der Tages-Read für Nicht-Europa-Flughäfen den falschen Kalendertag.
        today = _airport_local_now(ap).strftime('%Y-%m-%d')
    except Exception:
        return []
    try:
        _delay_store_load_from_sb(today, ap)
    except Exception:
        pass
    rows = []
    for (d, a, fn, sc), max_delay in list(_delay_store.items()):
        if d != today or a != ap or not isinstance(sc, str) or sc.endswith('_cancelled'):
            continue
        if len(sc) != 5:
            continue
        cancelled = bool(_delay_store_cancelled.get((d, a, fn, sc)))
        meta = _delay_store_meta.get((d, a, fn, sc)) or {}
        try:
            al, _num = _split_flightno(fn)
        except Exception:
            al = (fn[:2] if fn else '')
        # „Unbekannt ≠ Pünktlich" (LH400-Bug): delay_min nur ausgeben, wenn der
        # Delay WIRKLICH beobachtet wurde (Meta-Flag aus dem Merge ODER Signal-
        # Rekonstruktion esti/IST-Status/delay>0/cancelled) — sonst null, damit
        # iOS ehrlich „keine Daten" zeigt statt „Pünktlich".
        md_i = int(max_delay or 0)
        known = _obs_delay_known(md_i, cancelled, meta.get('esti'),
                                 meta.get('status'), is_arr,
                                 flag=meta.get('delay_known'))
        # VOLLE Felder aus dem Meta-Store (dest/gate/terminal/esti) — so zeigt die
        # „Früher heute"-Ansicht von→nach + Gate, nicht nur die nackte Flugnummer.
        rows.append({
            'airline': (meta.get('airline') or al), 'airline_name': '', 'flight': fn,
            'dest_iata': (meta.get('dest_iata') or ''),
            'dest_name': (meta.get('dest_name') or ''),
            'sched': today + 'T' + sc + ':00', 'esti': (meta.get('esti') or None),
            'delay_min': (md_i if known else None),
            'delay_known': known,
            'delayed': bool(known and md_i >= _PUNCTUALITY_DELAY_THRESHOLD_MIN),
            'cancelled': cancelled,
            'gate': (meta.get('gate') or ''),
            'terminal': (meta.get('terminal') or ''), 'hall': '',
            'status': _departed_status(meta.get('status'), cancelled, is_arr),
            # reg/type_code AUS dem Meta-Store mit ausgeben (User: Tail-Reg + Muster
            # gehören auch auf die „Früher heute"-Zeilen, nicht nur auf die Live-Flüge
            # — sie liegen seit dem Aircraft-Meta-Merge ohnehin im Store).
            'reg': (meta.get('reg') or ''), 'aircraft': (meta.get('type_code') or ''),
            # Give-up-Marker (Audit 2026-07-05): ohne Signal als 0 geschlossen —
            # route-history nimmt solche Rows aus dem Quoten-Nenner (Anzeige bleibt).
            'gaveup': bool(meta.get('gaveup')),
            'departed': True,
        })
    rows.sort(key=lambda f: f.get('sched') or '')
    return rows


def _fn_norm(fn):
    """Flugnummern-Normalisierung fürs Gruppieren: Leerzeichen raus, führende
    Nullen der Nummer strippen ('SQ 026' == 'SQ026' == 'SQ26' → 'SQ26').
    Owner-Bug 2026-07-04: SQ026 und SQ26 standen als ZWEI Zeilen in der
    Strecken-Historie. Carrier-Prefix: IATA 2-stellig (auch '4Y'/'X3') oder
    ICAO 3-stellig. Unparsebares kommt unverändert (nur upper/space) zurück."""
    s = str(fn or '').replace(' ', '').upper()
    m = re.match(r'^([A-Z]{2}|[A-Z]\d|\d[A-Z]|[A-Z]{3})0*(\d{1,4})([A-Z]?)$', s)
    if not m:
        return s
    return f'{m.group(1)}{int(m.group(2))}{m.group(3)}'


# Warehouse-codeshares (mkt_carrier/mkt_flight_no → flights.op_flight_no) als
# Prozess-Cache. Die Tabelle ist klein (~430 Zeilen, wachsend) → EIN Read alle
# 6 h reicht; bei SB-Fehlschlag bleibt die alte Map und der nächste Versuch
# ist in ~10 min (kein Hammering).
_AX_CODESHARE_CACHE = {'ts': 0.0, 'map': {}}
_AX_CODESHARE_TTL_S = 6 * 3600


def _ax_codeshare_map():
    """dict: Marketing-Flugnummer (norm) → Operating-Flugnummer (norm), aus der
    Flight-Warehouse-Tabelle `codeshares` (embedded read auf flights.op_flight_no).
    Leere Map wenn SB down/Tabelle leer — Aufrufer fällt dann auf die
    sched±3min-Heuristik zurück. Wirft nie."""
    now = time.time()
    if _AX_CODESHARE_CACHE['map'] and now - _AX_CODESHARE_CACHE['ts'] < _AX_CODESHARE_TTL_S:
        return _AX_CODESHARE_CACHE['map']
    if not SB_AVAILABLE or sb is None:
        return _AX_CODESHARE_CACHE['map']
    def _do():
        return (sb.table('codeshares')
                .select('mkt_carrier,mkt_flight_no,flights(op_flight_no)')
                .limit(8000).execute())
    res, failed = _supabase_execute_with_timeout('ax_codeshares', _do, timeout_s=5)
    rows = (getattr(res, 'data', None) or []) if res is not None else []
    if rows and not failed:
        mp = {}
        for r in rows:
            fl = r.get('flights')
            op = (fl.get('op_flight_no') or '') if isinstance(fl, dict) else ''
            # mkt_flight_no trägt im Warehouse bereits den Carrier-Prefix
            # ('AM6820', verifiziert 2026-07-04 an 1000 Rows) — Carrier nur
            # voranstellen, wenn die Nummer nackt-numerisch wäre (defensiv).
            mk = (r.get('mkt_flight_no') or '').strip()
            if mk.isdigit():
                mk = f"{(r.get('mkt_carrier') or '').strip()}{mk}"
            op_n, mk_n = _fn_norm(op), _fn_norm(mk)
            if op_n and mk_n and op_n != mk_n:
                mp[mk_n] = op_n
        _AX_CODESHARE_CACHE['map'] = mp
        _AX_CODESHARE_CACHE['ts'] = now
    else:
        # Fehlschlag/leer: alte Map behalten, Retry in ~10 min statt 6 h.
        _AX_CODESHARE_CACHE['ts'] = now - _AX_CODESHARE_TTL_S + 600
    return _AX_CODESHARE_CACHE['map']


def _fold_codeshare_flights(flights, cs_map):
    """Faltet Codeshare-Duplikate EINES Tages der Strecken-Historie zu einer
    Zeile (Owner-Screenshot 2026-07-04: TG7722/UA8841/ET1610/SN7230/NZ4226/
    LH400 alle 13:35 = derselbe physische Flug, 6 Zeilen + 6-fach in der
    Pünktlichkeits-Quote).

    Zwei Stufen: (1) Warehouse-Mapping `cs_map` (Marketing→Operating, norm),
    (2) Heuristik: Gruppen mit gleicher sched ±3 min (gleiche Strecke ist hier
    durch den Endpoint gegeben) werden zusammengelegt — ausser BEIDE Nummern
    sind als Operating bekannt (zwei echte Flüge knapp hintereinander).
    Repräsentant = Operating-Nummer (bzw. der Eintrag mit den besten Daten);
    Marketing-Nummern additiv als `also_as`, Zähl-Basis = EINE Stimme.
    Liefert eine NEUE Liste (sched-sortiert); Original-Einträge unverändert."""
    if not flights or len(flights) < 2:
        return flights
    def _sched_minutes(e):
        m = re.search(r'(\d{1,2}):(\d{2})', str(e.get('sched') or ''))
        return int(m.group(1)) * 60 + int(m.group(2)) if m else None
    known_ops = set(cs_map.values())
    def _op_rank(key):
        # kleiner = eher der Operating Carrier: als Operating im Warehouse
        # bekannt < wenige Ziffern (LH400) < hohe 4-stellige Marketing-Nummer.
        digits = re.sub(r'\D', '', key or '')
        return (0 if key in known_ops else 1, len(digits),
                int(digits) if digits else 9999, key or '')
    groups, order = {}, []
    for e in flights:
        n = _fn_norm(e.get('flight'))
        op = cs_map.get(n, n)
        if op not in groups:
            groups[op] = []
            order.append(op)
        groups[op].append((e, n))
    def _grp_sched(k):
        vals = [_sched_minutes(e) for e, _ in groups[k]]
        vals = [v for v in vals if v is not None]
        return min(vals) if vals else None
    # Heuristik-Merge (sched±3min) — iterativ bis stabil.
    changed = True
    while changed:
        changed = False
        keys = [k for k in order if k in groups]
        for i in range(len(keys)):
            for j in range(i + 1, len(keys)):
                a, b = keys[i], keys[j]
                if a in known_ops and b in known_ops:
                    continue      # zwei ECHTE Operating-Flüge → nie falten
                sa, sb2 = _grp_sched(a), _grp_sched(b)
                if sa is None or sb2 is None or abs(sa - sb2) > 3:
                    continue
                win, lose = (a, b) if _op_rank(a) <= _op_rank(b) else (b, a)
                groups[win].extend(groups.pop(lose))
                changed = True
                break
            if changed:
                break
    out = []
    for k in order:
        members = groups.get(k)
        if not members:
            continue
        if len(members) == 1:
            out.append(members[0][0])
            continue
        def _data_rank(e):
            return (0 if e.get('obs') == 'both' else 1,
                    0 if e.get('delay_known') else 1)
        # Repräsentant: der Eintrag, dessen Nummer die Operating-Nummer der
        # Gruppe ist; sonst der plausibelste (Operating-Rang) Eintrag.
        rep_src = next((e for e, n in members if n == k), None)
        if rep_src is None:
            rep_src = min((e for e, _ in members),
                          key=lambda e: _op_rank(_fn_norm(e.get('flight'))))
        rep = dict(rep_src)
        # Bester Daten-Spender (both > delay_known) füllt fehlende Urteile auf.
        donor = min((e for e, _ in members), key=_data_rank)
        if donor is not rep_src and _data_rank(donor) < _data_rank(rep_src):
            for kk in ('delay_min', 'delay_known', 'status', 'dep_delay_min',
                       'arr_delay_min', 'sched_arr', 'obs'):
                if donor.get(kk) is not None:
                    rep[kk] = donor[kk]
        if any(bool(e.get('cancelled')) for e, _ in members):
            rep['cancelled'] = True
            rep['status'] = 'cancelled'
        rep_norm = _fn_norm(rep.get('flight'))
        if rep_src is None and k in known_ops and k != rep_norm:
            # Kein Member trägt die Operating-Nummer selbst (nur Marketing-
            # Rows beobachtet) → Zeile auf die Warehouse-bekannte Operating-
            # Nummer umlabeln; die beobachteten Marketing-Nummern landen unten
            # in also_as. Das IST der physische Flug — kein Erfinden.
            rep['flight'] = k
            rep['airline'] = k[:2]
            rep_norm = k
        also, seen_norm = [], {rep_norm}
        for e, n in members:
            if n in seen_norm:
                continue
            seen_norm.add(n)
            also.append(e.get('flight'))
        if also:
            rep['also_as'] = also          # additiv — iOS 1.6(1) ignoriert es
        rep['codeshares_folded'] = len(members) - 1
        out.append(rep)
    out.sort(key=lambda f: (f.get('sched') or ''))
    return out


# RESPONSE-MEMO für /api/ax/route-history (Perf-Fund 174, Audit 2026-07-15):
# der Endpoint kostete in Prod 21–23 s bei days=7 (iOS-Default) und rechnete
# bei JEDEM Detail-Öffnen komplett neu. Historie ändert sich langsam, Tag-0
# höchstens im Minutentakt → 120-s-Memo pro (Route, Fenster); identisches
# Muster wie _FRIENDS_TODAY_MEMO (90 s). Wird in tests/conftest.py pro Test
# geleert (Test-Isolation).
_ROUTE_HISTORY_MEMO = {}              # (frm, to, ndays) → (monotonic_ts, payload)
_ROUTE_HISTORY_MEMO_TTL_S = 120


def _route_track_flight_set(frm, to, day, lo_iso, hi_iso):
    """Set der (auf `_fn_norm` normalisierten) Flugnummern, für die auf der
    Strecke frm→to am UTC-Tag `day` eine ECHTE geflogene Spur in aircraft_track
    existiert (Breadcrumbs vom Harvester + FR24-Rückschreibung) — dieselbe
    Wahrheit wie Tier 1 (`_flown_track_db`) des /api/ax/flown-track-Endpoints,
    nur als billiger Existenz-Check. EINE gebündelte Query pro Tag (origin/dest
    scoped bereits eng, plus seen_ts-Fenster), NICHT N Abfragen pro Flug. Der
    aircraft_track.flight-Wert ist die rohe FR24-Nummer (LH174) → hier wie in der
    Historie mit `_fn_norm` normalisiert, damit der Vergleich mit dem
    normalisierten entry['flight'] (SQ026→SQ26) trifft. Best-effort: bei
    fehlendem SB/Fehler leeres Set (has_track fällt auf False, nie Exception)."""
    if sb is None or not frm or not to:
        return set()
    try:
        rows = (sb.table('aircraft_track')
                .select('flight')
                .eq('origin', frm).eq('dest', to)
                .gte('seen_ts', lo_iso).lt('seen_ts', hi_iso)
                .limit(4000).execute()).data or []
    except Exception:
        return set()
    return {_fn_norm(r.get('flight')) for r in rows if r.get('flight')}


@app.route('/api/ax/route-history/<frm>/<to>', methods=['GET'])
def ax_route_history(frm, to):
    """Strecken-Historie (Pünktlichkeit pro Tag) für ein Städtepaar — aus den
    bereits gesammelten Abflug-Beobachtungen (airport_delay_obs, je Flug mit
    dest_iata + max_delay_min + cancelled). Liefert pro Tag die Flüge frm→to mit
    Status (ontime ≤15 / minor ≤45 / late / cancelled) plus eine Pünktlichkeits-
    Quote. KEINE neue Datenquelle/kein Drittanbieter-Spend — nur Aggregation des
    Vorhandenen. Fenster = was gespeichert ist (bis ?days=7), ehrlich begrenzt."""
    frm = _DE_ICAO_TO_IATA.get((frm or '').upper().strip()[:4], (frm or '').upper().strip()[:4])
    to = _DE_ICAO_TO_IATA.get((to or '').upper().strip()[:4], (to or '').upper().strip()[:4])
    if not frm or not to:
        return jsonify({'ok': False, 'error': 'bad_route'}), 400
    board_ap = 'FRA' if frm in ('FRA', 'EDDF') else frm
    try:
        ndays = max(1, min(int(request.args.get('days') or 7), 7))
    except Exception:
        ndays = 7
    # 120-s-Response-Memo (Perf-Fund 174) — Doku am Modul-Global. Im
    # Test-Modus KOMPLETT umgangen: die Suite mockt die Row-Quellen pro Test
    # unterschiedlich, und der sys.modules['app']-Swap (test_calculation)
    # kann das Original-Modul dem conftest-Cache-Reset entziehen — ein
    # memoisiertes Ergebnis würde dann einen späteren Test vergiften.
    _rh_memo_on = not app.testing
    _rh_key = (frm, to, ndays)
    if _rh_memo_on:
        _rh_hit = _ROUTE_HISTORY_MEMO.get(_rh_key)
        if _rh_hit and (time.monotonic() - _rh_hit[0]) < _ROUTE_HISTORY_MEMO_TTL_S:
            return jsonify(_rh_hit[1])
    store_key = _store_key_for(board_ap, 'departure')
    # ZWEITE QUELLE (2026-07-03, User-Idee): Flüge von nicht gescrapten Abflug-
    # Flughäfen stehen trotzdem als ANKÜNFTE am (gescrapten) Ziel im Warehouse —
    # Route frm→to = dep-Obs@frm ∪ arr-Obs@to mit Herkunft==frm. Arrival-Rows
    # tragen die HERKUNFT im Feld dest_iata (Board-Konvention). Der Delay ist
    # dort der Ankunfts-Delay — für Strecken-Pünktlichkeit die ehrlichere Metrik.
    arr_key = None
    try:
        arr_key = _store_key_for(to, 'arrival')
    except Exception:
        arr_key = None
    from datetime import timedelta as _td
    base = _airport_local_now(store_key)
    if base is None:
        return jsonify({'ok': True, 'origin': board_ap, 'dest': to, 'days': ndays,
                        'on_time_pct': None, 'total': 0, 'unknown': 0,
                        'recent_days': [], 'source': 'airport_delay_obs'})
    on_time = late = cancelled_cnt = total = unknown_cnt = 0
    days_out = []
    # Codeshare-Mapping EINMAL pro Request (Prozess-Cache, 6 h TTL).
    cs_map = _ax_codeshare_map()
    # HISTORIE = VERGANGENHEIT (Owner-Screenshot 2026-07-12, LH781 SIN→FRA:
    # „MORGEN · 06:40 → 06:40 · pünktlich"): der Tag-0-Bucket trägt das Datum
    # des ORIGIN-lokalen Heute (SIN = schon der 13.), die Live-Store-Rows beider
    # Seiten aber je den Betriebstag IHRER Station (FRA-Ankünfte = noch der 12.).
    # Ohne Datums-Gate landeten heutige FRA-Ankünfte im MORGEN-Bucket (und
    # doppelt: dieselbe Row nochmal im richtigen Tag aus der DB). Dazu das
    # Zukunfts-Gate: ein Flug, dessen sched-Wandzeit an seiner Station noch in
    # der Zukunft liegt, ist NICHT geflogen — er gehört nicht in „zuletzt"
    # (Board-Prognosen sind keine Historie). Rein für die Tag-0-Store-Rows;
    # die DB-Tage (i>0) sind date-gekeyt und vergangen.
    def _row_in_day_and_flown(r, day, station_iata):
        sc = str(r.get('sched') or '')
        if len(sc) >= 10 and sc[:10] != day:
            return False
        try:
            now_st = _airport_local_now(station_iata)
            if now_st is not None and len(sc) >= 16:
                sched_dt = datetime.strptime(sc[:16], '%Y-%m-%dT%H:%M')
                if sched_dt > now_st.replace(tzinfo=None):
                    return False
        except Exception:
            pass          # unparsebar → nicht filtern (kein Datenverlust)
        return True

    # PARALLEL-PREFETCH (2026-07-14, Owner „Detail-Kaltstart reduzieren"): die per-Tag-
    # Board-Reads (dep + arr) waren der Kalt-Latenz-Pol — je Tag bis zu 2 sequentielle
    # Supabase-Reads × ndays liefen SERIELL (~6 Round-Trips bei days=3, ~2–4,6 s). Die
    # Tage sind voneinander UNABHÄNGIG (verschiedene Datums-Buckets) → I/O parallel
    # vorziehen, Reihenfolge über den Index rekonstruiert. Die Fetch-Fns nutzen KEINEN
    # Flask-Kontext (reine Supabase-Reads, thread-safe wie der Friend-Roster-Fan-out
    # app.py:~12455) → kein app_context nötig. Die Merge-/Filter-/Quoten-Logik unten
    # bleibt BYTE-IDENTISCH — nur das Laden wird nebenläufig.
    # INTRA-TAG-PARALLELITÄT (Perf-Fund 173, Audit 2026-07-15): die DREI
    # voneinander unabhängigen I/O-Reads eines Tages (dep-Board, arr-Board,
    # has_track-Set) liefen bisher SERIELL innerhalb von `_fetch_day_rows`.
    # Für Tag 0 ist das der Kalt-Latenz-Pol: `_departed_rows_from_store` zieht
    # beim ersten Airport-Kontakt des Workers eine VOLLE Tages-Ladung des
    # Delay-Stores aus Supabase (`_delay_store_load_from_sb`, ~3 s an einem
    # Hub wie FRA), danach kommen arr-Store (~1 s) und Track-Query (~0,5 s) —
    # in Summe ~4,7 s (days=1 misst live genau das). Die drei Reads berühren
    # keinen Flask-Kontext (reine Supabase-Reads, thread-safe wie der Roster-
    # Fan-out) → nebenläufig ziehen, Merge-/Filter-/Quoten-Logik bleibt BYTE-
    # IDENTISCH (nur das Laden wird parallel). Erwartung: Tag 0 ≈ max(dep, arr,
    # track) statt Summe.
    def _fetch_dep(i, d_i):
        return (_departed_rows_from_store(store_key) if i == 0
                else _board_rows_from_obs_for_date(
                    d_i, store_key, None, dest_iata=to))

    def _fetch_arr(i, d_i):
        if not arr_key:
            return []
        try:
            return (_departed_rows_from_store(arr_key) if i == 0
                    else _board_rows_from_obs_for_date(
                        d_i, arr_key, None, dest_iata=frm))
        except Exception:
            return []

    def _fetch_trk(d_i):
        # has_track-Existenz-Set (Perf-Fund 175): eine gebündelte Query je Tag.
        try:
            from datetime import datetime as _dtc, timezone as _tzc
            _d0 = _dtc.strptime(d_i, '%Y-%m-%d').replace(tzinfo=_tzc.utc)
            return _route_track_flight_set(
                frm, to, d_i,
                _d0.strftime('%Y-%m-%dT00:00:00Z'),
                (_d0 + _td(days=1)).strftime('%Y-%m-%dT00:00:00Z'))
        except Exception:
            return set()

    def _fetch_day_rows(i):
        from concurrent.futures import ThreadPoolExecutor as _RH_TPE
        d_i = (base - _td(days=i)).strftime('%Y-%m-%d')
        # Die drei Reads dieses Tages nebenläufig ziehen. Jeder Worker gibt
        # danach seinen thread-lokalen Supabase-Pool frei (kurzlebige Threads,
        # wie beim Tag-Fan-out) — sonst überleben tote HTTP/2-Pools den map().
        def _dep_task():
            try:
                return _fetch_dep(i, d_i)
            finally:
                _close_current_thread_supabase_client()

        def _arr_task():
            try:
                return _fetch_arr(i, d_i)
            finally:
                _close_current_thread_supabase_client()

        def _trk_task():
            try:
                return _fetch_trk(d_i)
            finally:
                _close_current_thread_supabase_client()

        with _RH_TPE(max_workers=3) as _sub_ex:
            f_dep = _sub_ex.submit(_dep_task)
            f_arr = _sub_ex.submit(_arr_task)
            f_trk = _sub_ex.submit(_trk_task)
            r = f_dep.result()
            ar = f_arr.result()
            trk = f_trk.result()
        return i, (r, ar, trk)
    _day_rows = {}
    if ndays > 1:
        from concurrent.futures import ThreadPoolExecutor as _RH_TPE
        # Tage parallel, und JEDER Tag intern seine 3 Reads parallel — der
        # Worker-Cap bleibt an der Tages-Achse (min(ndays,4)); die Intra-Tag-
        # Pools sind kurzlebig und je 3 Threads.
        with _RH_TPE(max_workers=min(ndays, 4)) as _rh_ex:
            for _i, _pair in _rh_ex.map(_fetch_day_rows, range(ndays)):
                _day_rows[_i] = _pair
    else:
        _day_rows[0] = _fetch_day_rows(0)[1]

    for i in range(ndays):
        d = (base - _td(days=i)).strftime('%Y-%m-%d')
        rows, arr_rows, trk_prefetch = _day_rows[i]
        if i == 0:
            rows = [r for r in (rows or [])
                    if _row_in_day_and_flown(r, d, board_ap)]
            arr_rows = [r for r in (arr_rows or [])
                        if _row_in_day_and_flown(r, d, to)]
        flights = []
        by_fn = {}
        # DUAL-SIDE-MERGE (Owner-Direktive 2026-07-03): haben BEIDE Seiten
        # denselben Flug beobachtet, wird NICHT mehr gedroppt (vorher: dep
        # gewinnt, arr-Beobachtung weg), sondern EIN Eintrag mit dep_delay_min
        # UND arr_delay_min gebaut — 'obs': 'both'. Status/delay_min kommen dann
        # von der arr-Seite (Ankunfts-Delay = die ehrlichere Strecken-Metrik,
        # D15-OTP). 'sched' bleibt die Abflug-Zeit der dep-Row (iOS-kompatibel),
        # die Ankunfts-Zeit kommt additiv als 'sched_arr'.
        # BUGFIX-HISTORIE (2026-07-03 „alle Flieger pünktlich"): Row-Builder
        # mappen die SB-Spalte max_delay_min auf den Ausgabe-Key 'delay_min' —
        # hier IMMER 'delay_min' lesen, nie 'max_delay_min'.
        for side, rws, match in (('dep', rows or [], to),
                                 ('arr', arr_rows or [], frm)):
            for r in rws:
                if (r.get('dest_iata') or '').upper() != match:
                    continue
                # Normalisiert (SQ026==SQ26), damit auch der dep/arr-Dual-Side-
                # Merge Schreibweisen-Varianten derselben Nummer trifft.
                fn_key = _fn_norm(r.get('flight'))
                # „Unbekannt ≠ Pünktlich" (LH400): die Row-Builder liefern
                # delay_min bereits als None + delay_known=False, wenn der Delay
                # NIE wirklich beobachtet wurde (nur vor Abflug gesehen, kein
                # esti/IST-Status). So eine Zeile wird 'unknown' — sie zählt
                # NICHT als pünktlich und fliegt aus dem Quoten-Nenner (total
                # bleibt als Info erhalten).
                known = bool(r.get('delay_known',
                                   r.get('delay_min') is not None))
                delay = int(r.get('delay_min') or 0)
                canc = bool(r.get('cancelled'))
                # Give-up-Rows (Finalizer schloss ohne Signal als 0, Audit
                # 2026-07-05): Anzeige bleibt „pünktlich", aber die Quote unten
                # zählt sie als unknown — und sie überschreiben im Dual-Side-
                # Merge nie eine echt beobachtete Gegenseite.
                gaveup = bool(r.get('gaveup'))
                prev = by_fn.get(fn_key) if fn_key else None
                if side == 'dep' or prev is None:
                    if prev is not None:
                        continue   # doppelte Row derselben Seite → wie bisher skip
                    status = ('cancelled' if canc else
                              'unknown' if not known else
                              'ontime' if delay <= 15 else
                              'minor' if delay <= 45 else 'late')
                    # Anzeige-Label normalisiert (SQ026→SQ26): sonst gruppiert
                    # der Client dieselbe Nummer über Tage hinweg als zwei Flüge.
                    entry = {'flight': (fn_key or r.get('flight')),
                             'airline': r.get('airline'),
                             'sched': r.get('sched'),
                             'delay_min': (delay if known else None),
                             'delay_known': known,
                             'cancelled': canc, 'status': status,
                             'obs': side}
                    if gaveup:
                        entry['gaveup'] = True
                    if side == 'dep':
                        entry['dep_delay_min'] = (delay if known else None)
                    else:
                        entry['arr_delay_min'] = (delay if known else None)
                        entry['sched_arr'] = r.get('sched')
                    if fn_key:
                        by_fn[fn_key] = entry
                    flights.append(entry)
                else:
                    if prev.get('obs') != 'dep':
                        continue   # zweite arr-Row derselben Flugnummer → skip
                    # arr-Row zu bestehendem dep-Eintrag → MERGEN statt droppen.
                    prev['arr_delay_min'] = (delay if known else None)
                    prev['sched_arr'] = r.get('sched')
                    prev['cancelled'] = bool(prev.get('cancelled')) or canc
                    prev['obs'] = 'both'
                    # arr = beste Zahl — aber NUR wenn die arr-Seite den Delay
                    # KENNT: arr known schlägt dep unknown (LH400: dep 0-ohne-
                    # Wissen, arr +86 → 86 gewinnt) UND dep known bleibt gegen
                    # eine arr-Seite ohne Wissen stehen. Eine gaveup-arr-Row
                    # (known nur per Finalizer-Flag, ohne Signal) zählt hier
                    # NICHT als Wissen — sonst klemmt ihre 0 einen echt
                    # beobachteten dep-Delay weg (Audit 2026-07-05).
                    if known and not gaveup:
                        prev['delay_min'] = delay
                        prev['delay_known'] = True
                        prev.pop('gaveup', None)   # echtes Signal ersetzt Give-up
                    if prev['cancelled']:
                        prev['status'] = 'cancelled'
                    elif not prev.get('delay_known'):
                        prev['status'] = 'unknown'
                    elif known and not gaveup:
                        # gaveup-arr aktualisiert auch den STATUS nicht — der
                        # gehört zur (nicht übernommenen) 0 der Give-up-Row.
                        prev['status'] = ('ontime' if delay <= 15 else
                                          'minor' if delay <= 45 else 'late')
        # CODESHARE-FALTUNG (Owner 2026-07-04): derselbe physische Flug unter
        # mehreren Marketing-Nummern → EINE Zeile (operating gewinnt, Rest als
        # `also_as`) — VOR dem Zählen, sonst stimmt die Quote N-fach ab.
        if flights:
            try:
                flights = _fold_codeshare_flights(flights, cs_map)
            except Exception as _fe:
                app.logger.warning(f'[route-history] fold-fail: {str(_fe)[:120]}')
        # Quote NACH dem Merge zählen (ein Flug = eine Stimme; nur Flüge mit
        # echtem Urteil in den Nenner — 'unknown' ist Info, keine Pünktlichkeit).
        for e in flights:
            total += 1
            # Flugdauer GRATIS aus Soll-Ab/-An ableiten — nur wenn die dep-Seite
            # beobachtet ist (obs 'dep'/'both'): dann ist e['sched'] die echte
            # Abflug-Zeit @frm und e['sched_arr'] die Ankunft @to. Bei reinen arr-
            # Rows ist sched==sched_arr (beides Ankunft) → keine Dauer erfinden.
            if e.get('sched_arr') and e.get('obs') in ('dep', 'both'):
                dm = _sched_block_min(e.get('sched'), frm, e.get('sched_arr'), to)
                if dm is not None:
                    e['duration_min'] = dm
            if e.get('cancelled'):
                cancelled_cnt += 1
            elif not e.get('delay_known') or e.get('gaveup'):
                # gaveup = Finalizer schloss ohne Signal als 0 (Audit 2026-07-05):
                # fürs Listing „pünktlich", für die QUOTE unknown — sonst drücken
                # signal-lose Give-up-Rows die Strecken-Quote künstlich hoch.
                unknown_cnt += 1
            elif int(e.get('delay_min') or 0) <= 15:
                on_time += 1
            else:
                late += 1
        if flights:
            # has_track (2026-07-10): pro Flug UPFRONT markieren, ob eine ECHTE
            # geflogene Spur in aircraft_track liegt (Tier-1-Wahrheit des
            # /api/ax/flown-track). EINE gebündelte Query je Tag — seit
            # 2026-07-15 im PARALLEL-PREFETCH (_fetch_day_rows) statt seriell
            # hier im Loop (Perf-Fund 175). Additiv — fehlt/False bricht
            # keinen bestehenden Consumer.
            trk_set = trk_prefetch or set()
            for e in flights:
                e['has_track'] = bool(_fn_norm(e.get('flight')) in trk_set)
            # Hinweis: arr-Zeilen tragen die ANKUNFTS-Zeit als sched — die
            # Sortierung bleibt chronologisch-genug fürs Tages-Listing.
            flights.sort(key=lambda f: (f.get('sched') or ''))
            days_out.append({'date': d, 'count': len(flights), 'flights': flights})
    # Nenner = nur Flüge mit echtem Urteil (on_time/late/cancelled) — 'unknown'
    # fliegt raus, sonst drückten nie-bestätigte 0-Rows die Quote künstlich hoch.
    judged = on_time + late + cancelled_cnt
    pct = round(100 * on_time / judged) if judged else None
    payload = {'ok': True, 'origin': board_ap, 'dest': to, 'days': ndays,
               'on_time_pct': pct, 'total': total, 'on_time': on_time,
               'late': late, 'cancelled': cancelled_cnt,
               'unknown': unknown_cnt,
               'recent_days': days_out, 'source': 'airport_delay_obs'}
    if _rh_memo_on:
        # Memo bounded halten (Cap ~256 Routen — ältester Eintrag kippt).
        if len(_ROUTE_HISTORY_MEMO) > 256:
            _ROUTE_HISTORY_MEMO.pop(next(iter(_ROUTE_HISTORY_MEMO)), None)
        _ROUTE_HISTORY_MEMO[_rh_key] = (time.monotonic(), payload)
    return jsonify(payload)


def _flight_from_live_board(iata, fn):
    """Sucht eine Flugnummer im LIVE-Board-Feed (gratis, gecacht) eines Abflug-
    Flughafens — für HEUTE/künftig abfliegende Flüge, die noch NICHT in der
    airport_delay_obs-Historie stehen (die hält nur bereits ABGEFLOGENE). Damit
    findet der eigene Umlauf in ein paar Stunden seinen bereits zugeteilten Tail
    (Fraport-Feed: now→+27h, ~95 % Tail-Fill <15h). Liefert die Board-Zeile (inkl.
    reg/aircraft, sofern die Quelle sie schon trägt) + `_arr`-Richtung, sonst None.
    Niemals raise — reiner Best-Effort-Enrich."""
    iata = (iata or 'FRA').upper().strip()
    iata = _DE_ICAO_TO_IATA.get(iata, iata)
    fn = (fn or '').replace(' ', '').upper()
    for ftype in ('departure', 'arrival'):
        try:
            if iata in ('FRA', 'EDDF'):
                flights = (_fra_day_board_cached(ftype) if ftype == 'departure'
                           else _fra_board_cached(ftype))
            else:
                rows, _src = (_native_board_cached(iata, ftype) or (None, None))
                flights = rows
        except Exception:
            flights = None
        for bf in (flights or []):
            if (bf.get('flight') or '').replace(' ', '').upper() == fn:
                return dict(bf, _arr=(ftype == 'arrival'))
    return None


def _flight_from_free_board(iata, fn):
    """Wie `_flight_from_live_board`, aber STRUKTURELL ohne bezahlten Spend —
    der Pflicht-Pfad für free_only-Fan-outs (Friends/Family/Radar):
      (1) Null-Fetch-Scan über die BEREITS GECACHTEN Boards beider Richtungen
          (`_cached_board_rows` — rein Dict+TTL; auch ein früher von einem
          bezahlten Request/Poller gecachtes ADB-Board darf gelesen werden,
          Cache lesen kostet nichts).
      (2) Echter Fetch NUR für gratis Quellen: FRA (Fraport-Feed,
          `_fra_day_board_cached`/`_fra_board_cached`) und Airports mit
          nativem Scraper via `_native_board_cached(…, allow_paid=False)`,
          das beide AeroDataBox-Zweige überspringt.
    Airports ohne freie Quelle und ohne warmen Cache → None (ehrlich, KEIN
    AeroDataBox-Call — `_aerodatabox_board` ist von hier aus unerreichbar).
    Niemals raise."""
    iata = (iata or '').upper().strip()
    iata = _DE_ICAO_TO_IATA.get(iata, iata)
    fn = (fn or '').replace(' ', '').upper()
    if len(iata) != 3 or not fn:
        return None
    for ftype in ('departure', 'arrival'):
        try:
            rows = _cached_board_rows(iata, ftype)   # Null-Fetch (Dict+TTL)
        except Exception:
            rows = None
        if rows is None:
            try:
                if iata in ('FRA', 'EDDF'):
                    rows = (_fra_day_board_cached(ftype) if ftype == 'departure'
                            else _fra_board_cached(ftype))
                elif iata in _NATIVE_BOARD_SCRAPERS:
                    rows, _src = (_native_board_cached(iata, ftype,
                                                       allow_paid=False)
                                  or (None, None))
            except Exception:
                rows = None
        for bf in (rows or []):
            if (bf.get('flight') or '').replace(' ', '').upper() == fn:
                return dict(bf, _arr=(ftype == 'arrival'))
    return None


def _arrival_gate_terminal(dest_iata, fn):
    """Ankunfts-Gate/-Terminal des ZIEL-Flughafens für eine Flugnummer — aus dem
    ANKUNFTS-Board des Ziels (gratis, gecacht). Der Abflug-Board-Scan liefert nur
    Abflug-Gate/-Terminal; das Ankunfts-Gate steht auf der Ankunftstafel des Ziels
    (`mv` = arrival-movement → row['gate']/['terminal'] sind dort das Ankunfts-
    Gate/-Terminal). Liefert (gate, terminal) als (str|None, str|None). Niemals
    raise — reiner Best-Effort-Enrich (Ziel unbekannt/Quelle down → (None, None))."""
    dest = (dest_iata or '').upper().strip()
    dest = _DE_ICAO_TO_IATA.get(dest, dest)
    if len(dest) != 3:
        return (None, None)
    fn = (fn or '').replace(' ', '').upper()
    try:
        if dest in ('FRA', 'EDDF'):
            rows = _fra_board_cached('arrival')
        else:
            rows, _src = (_native_board_cached(dest, 'arrival') or (None, None))
    except Exception:
        rows = None
    for bf in (rows or []):
        if (bf.get('flight') or '').replace(' ', '').upper() == fn:
            g = (bf.get('gate') or '').strip() or None
            t = (bf.get('terminal') or '').strip() or None
            return (g, t)
    return (None, None)


# ── ZENTRALER DUAL-SIDE-RESOLVER (Owner-Direktive 2026-07-03) ────────────────
# „Immer Abflug UND Ankunft einbeziehen, damit es wirklich genau ist — und wenn
# nur eins existiert, das eine benutzen." Ein Flug hat ZWEI Beobachtungsseiten:
# das Abflug-Board/-Warehouse am Origin (dep-Delay, Abflug-Gate) und das
# Ankunfts-Board/-Warehouse am Ziel (arr-Delay, Ankunfts-Gate, Herkunft im Feld
# dest_iata — Board-Konvention). Alle Live-Konsumenten (Flight-Info, Radar/
# Inbound, Friends/Family-Live-Status, Tafel-Enrich, Route-History) laufen durch
# DIESEN einen Resolver statt jeweils nur eine Seite zu sehen.

# Prozess-Memo pro (flight, date, dep, arr, live, free_only) — Feed-Renders rufen
# denselben Flug mehrfach pro Request auf (mehrere Karten/Konsumenten); der Memo
# verhindert wiederholte Board-Scans/Store-Reads. Kurzer TTL, damit frische
# Board-Polls (2–12 Min TTL) zeitnah durchschlagen. Auch None wird gecacht
# (negative-cache — sonst zahlt jeder Fan-out-Miss erneut).
_FLIGHT_MERGE_CACHE: dict = {}
_FLIGHT_MERGE_TTL = 90


def _flight_obs_merged(flight_no, date=None, dep_iata=None, arr_iata=None,
                       live=True, free_only=False, arr_date=None):
    """EIN gemergter Record für einen Flug aus ALLEN verfügbaren Beobachtungen
    beider Seiten:
      • dep-Seite: Live-Board + Warehouse (airport_delay_obs) am ABFLUG-Flughafen
      • arr-Seite: Live-Board + Warehouse ('<AP>#ARR') am ZIEL — Arrival-Rows
        tragen die HERKUNFT in dest_iata, der Delay dort ist der ANKUNFTS-Delay.
    Live-Boards (via `_flight_from_live_board`, das dep+arr scannt) nur für den
    HEUTIGEN Betriebstag des jeweiligen Flughafens; Warehouse für heute (In-
    Memory-Store, SB-hydriert) und vergangene Tage (`?date=`).

    Args:
      date:      'YYYY-MM-DD' oder None (= heute am jeweiligen Flughafen).
      arr_date:  ÜBERNACHT-LEG (Owner/Fable 2026-07-16, Nico LH423 BOS→FRA): der
                 Betriebstag der ANKUNFTS-Seite, wenn er vom Abflugtag ABWEICHT
                 (dep 15.07 abends → arr 16.07 früh). Ohne diesen Parameter keyt der
                 gesamte Merge am Abflugtag (`date`) und die arr-Seite findet die
                 gleichnamige, aber FALSCHE date-Row der gestrigen Rotation
                 (esti 07:44 'Geplant' statt der echten date+1-Landung 08:16
                 'baggage delivery'). Ist `arr_date` gesetzt und ≠ `date`, wird die
                 arr-Seite (Live-Board-Gate UND Warehouse-Read) vom ANKUNFTSTAG
                 gelesen; die dep-Seite bleibt am Abflugtag. None = altes Verhalten.
      dep_iata / arr_iata: bekannte Seiten; fehlt eine, wird sie best-effort aus
                 der gefundenen Gegenseite abgeleitet (Board-Row dest_iata).
      live:      False = nur Warehouse (kein Board-Scan).
      free_only: True = Live-Scan nur für gratis erreichbare/bereits gecachte
                 Boards (kein AeroDataBox-Spend) — Pflicht für Fan-out-Pfade.

    Ergebnis (dict) mit getrennten Feldern beider Seiten oder None (keine Seite
    hat Daten — EHRLICH, nichts erfunden):
      flight, date, dep_iata, arr_iata, airline, dest_name, origin_name,
      sched_dep/esti_dep/dep_delay_min/gate_dep/terminal_dep/status_dep/dep_cancelled,
      sched_arr/esti_arr/arr_delay_min/gate_arr/terminal_arr/status_arr/arr_cancelled,
      status (arr gewinnt), cancelled (OR beider Seiten),
      delay_min (beste Zahl: arr wenn vorhanden, sonst dep), delay_side ('arr'|'dep'),
      reg/aircraft (von der Seite, die es hat — NUE-Arrivals liefern Tails),
      sides {'dep': 'live'|'obs'|None, 'arr': …}, has_dep, has_arr.
    Niemals raise — reiner Best-Effort-Merge, gecacht (TTL s.o.)."""
    import time as _t
    fn = (flight_no or '').replace(' ', '').upper().strip()
    if len(fn) < 3:
        return None

    def _norm_ap(x):
        x = (x or '').upper().strip()
        x = _DE_ICAO_TO_IATA.get(x, x)
        return x if (len(x) == 3 and x.isalpha()) else None

    dep = _norm_ap(dep_iata)
    arr = _norm_ap(arr_iata)
    date_q = (date or '').strip()[:10] or None
    # ÜBERNACHT-ANKUNFTSTAG (Nico LH423): eigener Betriebstag für die arr-Seite.
    # Nur wirksam, wenn explizit gesetzt UND vom Abflugtag verschieden — sonst
    # bleibt die arr-Seite exakt wie bisher an `date_q` gekeyt (kein Verhalten
    # geändert für Nicht-Übernacht-Legs).
    date_arr_q = (arr_date or '').strip()[:10] or None
    if date_arr_q == date_q:
        date_arr_q = None
    ckey = (fn, date_q or '', dep or '', arr or '', bool(live), bool(free_only),
            date_arr_q or '')
    hit = _FLIGHT_MERGE_CACHE.get(ckey)
    if hit and (_t.time() - hit[0]) < _FLIGHT_MERGE_TTL:
        return dict(hit[1]) if hit[1] is not None else None

    def _is_today_at(ap, day=None):
        """`day` (Default date_q) ist None oder der heutige Betriebstag am
        Flughafen ap. Für die arr-Seite eines Übernacht-Legs wird `date_arr_q`
        durchgereicht (der Live-Board-Scan der Ankunft gilt für den ANKUNFTSTAG)."""
        dq = day if day is not None else date_q
        if dq is None:
            return True
        try:
            return _airport_local_now(ap).strftime('%Y-%m-%d') == dq
        except Exception:
            return False

    dep_row = arr_row = None
    dep_src = arr_src = None    # 'live' | 'obs'

    def _live_scan(ap, day=None):
        """Board-Scan (dep+arr) EINES Flughafens; klassifiziert den Treffer als
        dep-/arr-Seite über das _arr-Flag. Best-effort, nie raise.
        free_only=True → NUR `_flight_from_free_board` (gecachte Boards +
        gratis Quellen FRA/native, allow_paid=False) — `_flight_from_live_board`
        und damit jeder AeroDataBox-Zweig sind auf diesem Pfad unerreichbar.
        `day` (Übernacht-Ankunft): das Board dieses Flughafens für den ANGE-
        gebenen Betriebstag gaten (Default date_q)."""
        nonlocal dep_row, arr_row, dep_src, arr_src
        if not ap or not _is_today_at(ap, day):
            return
        try:
            bf = (_flight_from_free_board(ap, fn) if free_only
                  else _flight_from_live_board(ap, fn))
        except Exception:
            bf = None
        if not bf:
            return
        # BETRIEBSTAG-GATE für den Live-Scan (Nico LH423 2026-07-16): das Live-
        # Board zeigt mittags bereits den MORGIGEN Lauf derselben täglichen
        # Flugnummer („Geplant", sched=17.07 06:50) — der wurde hier ungeprüft
        # als arr_row übernommen und verdrängte die echte Landung des heutigen
        # Laufs aus dem Warehouse (arr_date-Read kam nie dran, weil arr_row
        # schon belegt war). Trägt die Board-Row ein VOLLES sched-Datum
        # (Fraport tut das), muss es zum angefragten Betriebstag passen —
        # sonst ist es eine fremde Instanz. Bare HH:MM bleibt ungeprüft (kein
        # Datum vorhanden → altes Verhalten).
        _want_day = day or date_q
        _bsched = str(bf.get('sched') or '').strip()
        if (_want_day and len(_bsched) >= 10 and _bsched[4:5] == '-'
                and _bsched[:10] != _want_day):
            return
        if bf.get('_arr'):
            if arr_row is None:
                arr_row, arr_src = dict(bf), 'live'
                arr_row.pop('_arr', None)
        else:
            if dep_row is None:
                dep_row, dep_src = dict(bf), 'live'
                dep_row.pop('_arr', None)

    if live:
        _live_scan(dep)
        if arr and arr != dep:
            _live_scan(arr, day=date_arr_q)

    # Fehlende Seite aus der gefundenen ableiten: dep-Row.dest_iata = Ziel,
    # arr-Row.dest_iata = HERKUNFT (Board-Konvention) — dann EINEN Nachzieh-Scan.
    if dep is None and arr_row is not None:
        dep = _norm_ap(arr_row.get('dest_iata'))
        if live and dep and dep_row is None:
            _live_scan(dep)
    if arr is None and dep_row is not None:
        arr = _norm_ap(dep_row.get('dest_iata'))
        if live and arr and arr_row is None:
            _live_scan(arr, day=date_arr_q)

    def _obs_lookup(ap, ftype, want_other, lookup_date=None):
        """Warehouse-Row (heute: In-Memory-Store; sonst: SB-Read des Tages) für
        fn am Store-Key ap+ftype. Bevorzugt die Row, deren dest_iata zur
        bekannten Gegenseite passt (Mehrfach-Legs gleicher Flugnummer)."""
        if not ap:
            return None
        key = _store_key_for(ap, ftype)
        try:
            row_date = (lookup_date or date_q)
            if row_date is None or row_date == _airport_local_now(ap).strftime('%Y-%m-%d'):
                rows = _departed_rows_from_store(key)
            else:
                # ZUKUNFTS-Guard: für ein künftiges Datum kann es keine
                # Beobachtung geben — den SB-Read gar nicht erst machen (Fan-out-
                # Konsumenten fragen auch künftige Roster-Tage an).
                try:
                    if row_date > _airport_local_now(ap).strftime('%Y-%m-%d'):
                        return None
                except Exception:
                    pass
                rows = _board_rows_from_obs_for_date(row_date, key, None)
        except Exception:
            rows = []
        cands = [r for r in (rows or [])
                 if (r.get('flight') or '').replace(' ', '').upper() == fn]
        if not cands:
            # Führende-Null-Toleranz (SQ026 vs SQ26): nur als FALLBACK, damit
            # exakte Treffer unverändert bleiben — gleiche Norm wie route-history.
            _fnn = _fn_norm(fn)
            cands = [r for r in (rows or []) if _fn_norm(r.get('flight')) == _fnn]
        if not cands:
            return None
        if want_other:
            for r in cands:
                if (r.get('dest_iata') or '').upper() == want_other:
                    return r
        return cands[0]

    if dep_row is None:
        o = _obs_lookup(dep, 'departure', arr)
        if o is not None:
            dep_row, dep_src = dict(o), 'obs'
    if arr_row is None:
        # ÜBERNACHT: arr-Warehouse-Read vom ANKUNFTSTAG (date_arr_q), sonst wie bisher.
        o = _obs_lookup(arr, 'arrival', dep, lookup_date=date_arr_q)
        if o is not None:
            arr_row, arr_src = dict(o), 'obs'
    # Zweite Ableitungs-Chance: Airports erst durch die obs-Row bekannt geworden.
    if dep is None and arr_row is not None:
        dep = _norm_ap(arr_row.get('dest_iata'))
        if dep and dep_row is None:
            o = _obs_lookup(dep, 'departure', arr)
            if o is not None:
                dep_row, dep_src = dict(o), 'obs'
    if arr is None and dep_row is not None:
        arr = _norm_ap(dep_row.get('dest_iata'))
        if arr and arr_row is None:
            o = _obs_lookup(arr, 'arrival', dep, lookup_date=date_arr_q)
            if o is not None:
                arr_row, arr_src = dict(o), 'obs'

    # DAY-BOUNDARY-GUARD (Owner 2026-07-09 „LH752 steht Gelandet, hebt aber erst
    # ab"): ein Nachtflug (Abflug heute, Ankunft morgen früh) darf NICHT die
    # ANKUNFT VON GESTERN an den heutigen Abflug kleben. Ein reales Flug-Exemplar
    # landet IMMER nach seinem Abflug — ist die (nach UTC gerechnete) Ankunft VOR
    # dem Abflug, gehört die arr-Row zu einem FRÜHEREN Betriebstag → verwerfen,
    # damit der heutige Flug nicht fälschlich „Arrived/Gelandet" zeigt.
    if dep_row is not None and arr_row is not None:
        _dsched = (dep_row.get('sched') or '').strip() or None
        _asched = (arr_row.get('sched') or '').strip() or None
        _du = _board_local_to_utc_iso(_dsched, dep) if _dsched else None
        _au = _board_local_to_utc_iso(_asched, arr) if _asched else None
        if _du and _au and _au < _du:
            arr_row, arr_src = None, None
            # Bei einem expliziten Betriebstag kann die passende ARR-Obs am Ziel
            # auf dem lokalen Folgetag liegen (LH455 SFO->FRA). Erst nachdem die
            # gleiche-Tags-Row als vorige Rotation verworfen wurde, genau d+1
            # pruefen und nur physikalisch plausible 0..36 h akzeptieren.
            if date_q and arr:
                try:
                    from datetime import datetime as _dt_bd, timedelta as _td_bd
                    _next_date = (_dt_bd.strptime(date_q, '%Y-%m-%d')
                                  + _td_bd(days=1)).strftime('%Y-%m-%d')
                    _next_arr = _obs_lookup(arr, 'arrival', dep,
                                            lookup_date=_next_date)
                    _ns = ((_next_arr or {}).get('sched') or '').strip() or None
                    _nu = _board_local_to_utc_iso(_ns, arr) if _ns else None
                    if _nu:
                        _dd = _dt_bd.fromisoformat(_du.replace('Z', '+00:00'))
                        _nd = _dt_bd.fromisoformat(_nu.replace('Z', '+00:00'))
                        if 0 <= (_nd - _dd).total_seconds() <= 36 * 3600:
                            arr_row, arr_src = _next_arr, 'obs'
                except Exception:
                    pass

    if dep_row is None and arr_row is None:
        _FLIGHT_MERGE_CACHE[ckey] = (_t.time(), None)
        _cache_soft_cap(_FLIGHT_MERGE_CACHE)
        return None

    def _s(row, k):
        v = (row or {}).get(k)
        v = (v.strip() if isinstance(v, str) else v)
        return v or None

    def _d(row):
        if row is None:
            return None
        try:
            return int(row.get('delay_min') or 0)
        except Exception:
            return 0

    dep_delay = _d(dep_row)
    arr_delay = _d(arr_row)
    dep_cxl = bool((dep_row or {}).get('cancelled'))
    arr_cxl = bool((arr_row or {}).get('cancelled'))
    # „Unbekannt ≠ Pünktlich" (LH400): weiß die jeweilige Seite ihren Delay
    # WIRKLICH? Obs-Rows tragen das Flag ('delay_known' aus den Row-Buildern),
    # Live-Rows werden aus esti/IST-Status beurteilt (+ Kriterium (c): noch im
    # Live-Feed nach sched+Puffer sichtbar = bestätigt pünktlich).
    dep_known = _row_delay_known(dep_row, False, src=dep_src, ap=dep)
    arr_known = _row_delay_known(arr_row, True, src=arr_src, ap=arr)
    # Beste Ein-Zahl für Konsumenten, die nur eine zeigen: der Ankunfts-Delay ist
    # die ehrlichere Metrik (D15-OTP) — aber nur eine Seite mit BEKANNTEM Delay
    # darf sie liefern: arr known schlägt dep unknown (LH400: dep-Row 0-ohne-
    # Wissen, arr-Row +86 → 86) UND dep known schlägt arr unknown. Wissen beide
    # nichts → delay_min None (iOS zeigt neutral statt „Pünktlich").
    if arr_row is not None and arr_known:
        best_delay, delay_side = arr_delay, 'arr'
    elif dep_row is not None and dep_known:
        best_delay, delay_side = dep_delay, 'dep'
    elif arr_row is not None:
        best_delay, delay_side = None, 'arr'
    else:
        best_delay, delay_side = None, 'dep'
    rec = {
        'ok': True, 'flight': fn,
        'date': (date_q or (_s(dep_row, 'sched') or _s(arr_row, 'sched') or '')[:10] or None),
        'dep_iata': dep, 'arr_iata': arr,
        'airline': _s(dep_row, 'airline') or _s(arr_row, 'airline'),
        'dest_name': _s(dep_row, 'dest_name'),      # Ziel-Name (nur dep-Row korrekt)
        'origin_name': _s(arr_row, 'dest_name'),    # arr-Row.dest_name = Herkunft
        # dep-Seite (Zeiten in Ortszeit des Abflug-Flughafens, wie die Boards).
        'sched_dep': _s(dep_row, 'sched'), 'esti_dep': _s(dep_row, 'esti'),
        # dep-/arr_delay_min: null wenn die Seite fehlt ODER ihren Delay nicht
        # wirklich kennt (nur-vor-Abflug-0 ist KEIN „pünktlich").
        'dep_delay_min': (dep_delay if (dep_row is not None and dep_known)
                          else None),
        'gate_dep': _s(dep_row, 'gate'), 'terminal_dep': _s(dep_row, 'terminal'),
        'status_dep': _s(dep_row, 'status'), 'dep_cancelled': dep_cxl,
        # arr-Seite (Zeiten in Ortszeit des Ziel-Flughafens).
        'sched_arr': _s(arr_row, 'sched'), 'esti_arr': _s(arr_row, 'esti'),
        'arr_delay_min': (arr_delay if (arr_row is not None and arr_known)
                          else None),
        'gate_arr': _s(arr_row, 'gate'), 'terminal_arr': _s(arr_row, 'terminal'),
        'status_arr': _s(arr_row, 'status'), 'arr_cancelled': arr_cxl,
        # Merged-Sicht.
        'status': _s(arr_row, 'status') or _s(dep_row, 'status'),
        'cancelled': (dep_cxl or arr_cxl),
        'delay_min': best_delay, 'delay_side': delay_side,
        'delay_known': bool(dep_known or arr_known),
        'reg': _s(dep_row, 'reg') or _s(arr_row, 'reg'),
        'aircraft': _s(dep_row, 'aircraft') or _s(arr_row, 'aircraft'),
        'sides': {'dep': dep_src, 'arr': arr_src},
        'has_dep': dep_row is not None, 'has_arr': arr_row is not None,
    }
    # ANGEKÜNDIGTEN DELAY MATERIALISIEREN (Owner/Fable 2026-07-16, Julien LH423
    # BOS→FRA + Tibor LH455 SFO→FRA): manche Boards posten die Verspätung NUR im
    # Status-TEXT („Delayed 75 Minutes") und lassen `delay_min`/`esti` leer. Der
    # gemergte Record trug dann dep_delay_min=None + esti_dep=None → JEDE Anzeige-
    # Fläche (Bordkarten-Status, friend-roster est_dep_iso, flight-info) sah „kein
    # Delay", obwohl das Board 75 min ankündigte. Hier — an der EINEN geteilten
    # Merge-Grenze, damit alle Consumer es erben — materialisieren wir den
    # angekündigten Delay in die harten Felder, WENN die Seite noch keinen kennt.
    # Nur mit expliziter Minuten-Zahl (KEIN „Delayed" ohne Zahl → nichts erfinden).
    # Die abgeleiteten est_*-Werte durchlaufen danach dieselbe est_*_iso-Ableitung
    # UND denselben Wrong-Day-/Physik-Scrub wie echte esti (kein Guard-Bypass).
    def _announced_delay_min_from_status(status_text):
        try:
            mm = re.search(r'(\d+)\s*min', str(status_text or ''), re.IGNORECASE)
            if mm:
                return max(0, int(mm.group(1)))
        except Exception:
            pass
        return None

    def _sched_plus_minutes(sched, n):
        """`sched` (bare 'HH:MM' ODER Voll-/Teil-ISO) + n Minuten, im GLEICHEN
        Format wie der Nachbar-`esti` der jeweiligen Seite (bare bleibt bare,
        ISO bleibt ISO) — sodass _board_local_to_utc_iso denselben Pfad nimmt.
        None wenn unparsbar. Wirft nie."""
        if not sched or n is None:
            return None
        try:
            from datetime import datetime as _dtm, timedelta as _tdm
            s = str(sched).strip()
            mm = re.match(r'^(\d{1,2}):(\d{2})$', s)
            if mm:
                base = _dtm(2000, 1, 1, int(mm.group(1)), int(mm.group(2)))
                return (base + _tdm(minutes=int(n))).strftime('%H:%M')
            dt = _dtm.fromisoformat(s.replace('Z', '+00:00'))
            out = dt + _tdm(minutes=int(n))
            if s.endswith('Z'):
                return out.strftime('%Y-%m-%dT%H:%M:%SZ')
            return out.isoformat()
        except Exception:
            return None

    # dep-Seite: Delay nur ankündigt (kein hartes dep_delay_min) → materialisieren.
    if rec.get('dep_delay_min') is None and rec.get('sched_dep'):
        _ann_dep = _announced_delay_min_from_status(rec.get('status_dep'))
        if _ann_dep is not None:
            _mat_dep = _sched_plus_minutes(rec.get('sched_dep'), _ann_dep)
            if _mat_dep is not None:
                rec['dep_delay_min'] = _ann_dep
                if not rec.get('esti_dep'):
                    rec['esti_dep'] = _mat_dep
                rec['delay_known'] = True
                # best-delay/-side neu wählen: eine echte arr-Zahl behält Vorrang
                # (arr-OTP ist die ehrlichere Metrik), sonst trägt jetzt die dep-Seite.
                if rec.get('arr_delay_min') is None:
                    rec['delay_min'] = _ann_dep
                    rec['delay_side'] = 'dep'
    # arr-Seite: analog, falls die ANKUNFTS-Tafel den Delay nur im Text trägt.
    if rec.get('arr_delay_min') is None and rec.get('sched_arr'):
        _ann_arr = _announced_delay_min_from_status(rec.get('status_arr'))
        if _ann_arr is not None:
            _mat_arr = _sched_plus_minutes(rec.get('sched_arr'), _ann_arr)
            if _mat_arr is not None:
                rec['arr_delay_min'] = _ann_arr
                if not rec.get('esti_arr'):
                    rec['esti_arr'] = _mat_arr
                rec['delay_known'] = True
                # arr gewinnt als beste Ein-Zahl (D15-OTP).
                rec['delay_min'] = _ann_arr
                rec['delay_side'] = 'arr'
    # ABSOLUTE-UTC EST-ZEITEN (ADDITIV, Owner 2026-07-13 „Live-Karte 8:40, Radar
    # paar Min später"): `esti_dep`/`esti_arr` sind ROH station-lokal (bare/naive,
    # oft OHNE Offset) — wer sie naiv als UTC parst, verschiebt sie um die
    # Stations-TZ (der bekannte Doppel-TZ-Fall). Der Radar zeigt aber die
    # abgeleitete ABSOLUTE est_arr (flights.est_arr / <arr>#ARR über
    # _board_local_to_utc_iso), während der Crew-State bisher nur `sched_arr +
    # arr_delay_min` kannte und bei UNBEKANNTEM (aber existierendem esti) Delay
    # auf die Plan-Zeit zurückfiel → Divergenz. Deshalb hier EINMAL zentral (dort,
    # wo die airport_tz-Kenntnis lebt) die absolute UTC-Variante mitgeben; der
    # Crew-Resolver liest sie 1:1 wie der Radar (EINE Wahrheit). Nur echte Werte,
    # None wenn kein esti / TZ unbekannt (nie ein naiver String).
    rec['est_dep_iso'] = _board_local_to_utc_iso(rec['esti_dep'], dep) if (
        rec['esti_dep'] and dep) else None
    rec['est_arr_iso'] = _board_local_to_utc_iso(rec['esti_arr'], arr) if (
        rec['esti_arr'] and arr) else None
    # SELBSTKONSISTENZ-INVARIANTE (Owner/Fable 2026-07-15, LH423 BOS→FRA): dieselbe
    # geteilte Schranke wie am blueprint-Merge-Ausgang (_flight_facts_from_obs). Der
    # Dual-Side-Board-Merge kann eine Fremd-Tages-ARR-Row an die heutige DEP-Seite
    # kleben (est_arr 07:44 HEUTE neben sched_arr 06:50 MORGEN, weit vor dem eigenen
    # Soll-Abflug). Liegt die absolute Ist-Ankunft > 90 min vor dem Soll-Abflug (oder
    # > 6 h vor der Soll-Ankunft) → est/status/delay der Ist-Seite verwerfen, Soll
    # behalten. Das est_*_iso wird mitgescrubbt (es leitet sich aus esti_* ab).
    # Der DAY-BOUNDARY-GUARD oben greift nur bei ZWEI vorhandenen Seiten; diese
    # Invariante schützt auch den Ein-Seiten-/ARR-only-Fall. Fail-open, wirft nie.
    try:
        from blueprints.aerox_data_blueprint import _scrub_wrong_day_esti as _scrub
        # WRONG-DAY-SCHUTZ MIT AUFGELÖSTEM DATUM (Owner/Fable 2026-07-16, Fix 2b):
        # NICHT das ROHE, bare `esti_arr`/`esti_dep` in den Probe geben — bare
        # 'HH:MM' würde _scrub mit dem ABFLUGTAG (service_date) datieren, sodass
        # eine legitime Übernacht-Ankunft (d+1) wie „vor dem Start gelandet" aussieht
        # und fälschlich als Fremd-Instanz gescrubbt würde (Datenverlust). Stattdessen
        # die eine Zeile weiter oben bereits korrekt d/d+1-aufgelösten absoluten UTC-
        # ISO (est_arr_iso/est_dep_iso via _board_local_to_utc_iso) reichen — der
        # Übernacht-Fall ist dort schon richtig auf den Folgetag gehoben.
        _probe = {
            'sched_dep': rec.get('sched_dep'),
            'est_dep': rec.get('est_dep_iso') or rec.get('esti_dep'),
            'sched_arr': rec.get('sched_arr'),
            'est_arr': rec.get('est_arr_iso') or rec.get('esti_arr'),
            'dep_iata': dep, 'arr_iata': arr,
            'arr_status': rec.get('status_arr'), 'dep_status': rec.get('status_dep'),
            'arr_delay_min': rec.get('arr_delay_min'),
            'dep_delay_min': rec.get('dep_delay_min'),
        }
        _scrub(_probe, service_date=date_q)
        if _probe.get('esti_scrubbed'):
            # est_arr/-dep + alle Ist-abgeleiteten Ankunfts-Felder der Fremd-Rotation
            # verwerfen (Soll-Felder + Route/Reg unberührt).
            rec['esti_arr'] = _probe.get('est_arr')      # None → gescrubbt
            rec['esti_dep'] = _probe.get('est_dep')
            rec['est_arr_iso'] = _board_local_to_utc_iso(rec['esti_arr'], arr) if (
                rec['esti_arr'] and arr) else None
            rec['est_dep_iso'] = _board_local_to_utc_iso(rec['esti_dep'], dep) if (
                rec['esti_dep'] and dep) else None
            rec['status_arr'] = _probe.get('arr_status')
            rec['arr_delay_min'] = _probe.get('arr_delay_min')
            # Merged-Sicht neu ableiten: status (arr gewinnt) + best_delay/-side.
            rec['status'] = rec.get('status_arr') or rec.get('status_dep')
            if rec.get('delay_side') == 'arr' and rec.get('arr_delay_min') is None:
                rec['delay_min'] = (rec.get('dep_delay_min'))
                rec['delay_side'] = 'dep' if rec.get('dep_delay_min') is not None else 'arr'
            rec['esti_scrubbed'] = True
    except Exception:
        pass
    _FLIGHT_MERGE_CACHE[ckey] = (_t.time(), dict(rec))
    _cache_soft_cap(_FLIGHT_MERGE_CACHE)
    return rec


# ─── Board-Status-Buckets (Owner 2026-07-04 „echter Status statt Uhr") ───────
# Normalisierte, kleingeschriebene Signalwörter. Board-Provider liefern DE + EN
# gemischt (Poller: „Gelandet 14:23", AeroDataBox: „Landed"). Substring-Match,
# damit Zeit-Suffixe/Umlaute nicht stören. Wiederverwendet von lay_eff (Crew-
# Standort), Inbound-Kette und dem iOS-Status-Passthrough. Reihenfolge im
# Bucket-Resolver: landed vor airborne vor grounded (arrived ist definitiv).
_FLIGHT_AIRBORNE_STATES = {
    'departed', 'airborne', 'en-route', 'enroute', 'en route', 'in air',
    'in-air', 'inair', 'abgeflogen', 'gestartet', 'im flug', 'unterwegs',
    'approach', 'approaching', 'final approach', 'on final', 'im anflug',
}
_FLIGHT_LANDED_STATES = {
    'landed', 'arrived', 'at gate', 'on ground', 'on blocks', 'on-blocks',
    'gelandet', 'angekommen', 'baggage', 'gepäck', 'gepaeck',
}
_FLIGHT_GROUNDED_STATES = {
    'scheduled', 'boarding', 'gate open', 'gate-open', 'delayed', 'estimated',
    'planmäßig', 'planmaessig', 'erwartet', 'verspätet', 'verspaetet',
    'boarding gate', 'go to gate', 'final call',
    # FRA liefert nach Ende des Boardings häufig nur das einzelne deutsche
    # Wort „geschlossen" (ohne „Gate"). Das ist dasselbe Ground-Signal wie
    # „Gate closed", kein Airborne-Beweis. Ohne diesen Token fiel der Status
    # auf die Plan-Uhr zurück und machte LH890 nach STD fälschlich „flying".
    'geschlossen', 'gate zu',
}


def _flight_status_bucket(status):
    """Board-Status-String → 'landed' | 'airborne' | 'grounded' | None.
    None = kein/unbekanntes Signal (Aufrufer fällt auf Uhr/Grace zurück)."""
    s = (status or '').strip().lower()
    if not s:
        return None
    for t in _FLIGHT_LANDED_STATES:
        if t in s:
            return 'landed'
    for t in _FLIGHT_AIRBORNE_STATES:
        if t in s:
            return 'airborne'
    for t in _FLIGHT_GROUNDED_STATES:
        if t in s:
            return 'grounded'
    return None


def _board_local_to_utc_iso(esti, iata):
    """Board-lokalen Esti-Zeitstempel (Station-Ortszeit, evtl. OHNE Offset) →
    absoluter UTC-ISO 'YYYY-MM-DDTHH:MM:SSZ'. None wenn esti leer, die Stations-TZ
    unbekannt oder unparsbar ist — NIE ein naiver/unkonvertierter String.

    WARUM (TZ-Fix 2026-07-04, Tibor-Doppelverschiebung): est_dep_iso/est_arr_iso
    reihen sich auf iOS in EXAKT denselben isoInstant()->stationLocalHHMM()-Pfad
    wie dep_iso ein. dep_iso ist echt-UTC; ein naiver Board-String OHNE 'Z' wird
    von iOS entweder gar nicht geparst (keine Zeit) oder als UTC gelesen UND danach
    nochmal um die Station-TZ verschoben = doppelt falsche Ist-Zeit. Wir wandeln
    darum genau EINMAL board-lokal→UTC — dort, wo die airport_tz-Kenntnis lebt
    (gleiches Muster wie _airport_local_now/_parse_local_iso) — sodass iOS den Wert
    ohne jede Parser-Änderung wie dep_iso behandeln kann. delay_min bleibt die
    autoritative Delta-Zahl; est_* ist reine Anzeige.

    dep-Seite wird mit airport_tz(from), arr-Seite mit airport_tz(to) konvertiert
    (jedes Board-Esti steht in SEINER eigenen Stations-Ortszeit)."""
    if not esti:
        return None
    try:
        from datetime import datetime, timezone
        # 'Z' → '+00:00' (Python <3.11 parst 'Z' nicht; gleiches Muster wie dep_iso).
        dt = datetime.fromisoformat(str(esti).strip().replace('Z', '+00:00'))
        if dt.tzinfo is not None:
            # Board lieferte bereits einen Offset (z.B. …Z) → direkt normalisieren.
            return dt.astimezone(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
        # Naiver Board-String = Station-Ortszeit. TZ der Station bestimmen:
        # FRA/EDDF (airport_tz liefert dort None) → Europe/Berlin, sonst airport_tz.
        ap = (iata or '').upper().strip().split('#', 1)[0]
        ap = _DE_ICAO_TO_IATA.get(ap, ap)
        if ap in ('FRA', 'EDDF'):
            tzname = 'Europe/Berlin'
        else:
            tzname = airport_tz(ap)
        if not tzname:
            return None        # TZ unbekannt → lieber None als naiver String
        from zoneinfo import ZoneInfo
        tz = ZoneInfo(tzname)
        return dt.replace(tzinfo=tz).astimezone(timezone.utc) \
                 .strftime('%Y-%m-%dT%H:%M:%SZ')
    except Exception:
        return None


# Sicherheitsmarge (min), analog crew_live_state._WRONG_DAY_MARGIN_MIN: um sie darf
# eine ECHTE (delay-korrigierte) Ankunft ihren EIGENEN Soll-Abflug unterschreiten,
# bevor die Beobachtung als „falscher Tag" verworfen wird. Ein Flug landet NIE vor
# seinem Abflug — nur ein Board-Record einer ANDEREN Tages-Instanz kann das.
_FLIGHTS_LIVE_WRONG_DAY_MARGIN_MIN = 60


def _flights_live_obs_wrong_day(m, leg_dep_iso, arr_iata):
    """Gehört der (datums-agnostisch gematchte) `_flight_obs_merged`-Record `m`
    zu einer ANDEREN Tages-Instanz als das iCal-Leg mit Soll-Abflug `leg_dep_iso`?

    Vorbild: crew_live_state._obs_is_wrong_day — genau dieselbe physikalische
    Schranke, hier für das PARALLELE flights_live-Array (friends-today), das die
    Obs an der crew_state-Gate-Stelle VORBEI direkt aus `_flight_obs_merged` baut.
    Ein täglich fliegender Flug (LH423 BOS→FRA) liefert am Rückflugtag längst die
    GESTRIGE, in FRA gelandete Instanz („status=LANDED, est_arr heute früh"),
    während das echte Leg der Crew erst abends abfliegt.

    Signal (physikalisch, unmissverständlich): die beobachtete Ankunft liegt VOR
    dem Soll-Abflug DIESES Legs — plus Marge. Ein korrekter Lauf landet NIE vor
    seinem Abflug; nur ein Fremd-Tag-Match kann das. Fail-open (False) wenn der
    Soll-Abflug fehlt (Tax-Pfad ohne ical-Zeiten) oder keine Ankunft parsebar ist.
    Wirft nie."""
    try:
        if not isinstance(m, dict) or not leg_dep_iso:
            return False
        from datetime import datetime as _dt2, timedelta as _td2
        dep = _dt2.fromisoformat(str(leg_dep_iso).strip().replace('Z', '+00:00'))
        if dep.tzinfo is None:
            return False
        # Beobachtete Ankunft (UTC): esti_arr bevorzugt, sonst sched_arr — beide
        # stehen board-lokal (Stations-Ortszeit am Ziel) und werden mit derselben
        # TZ-Kenntnis wie die flights_live-Ausgabe nach UTC gewandelt. Bare 'HH:MM'
        # (ohne eigenes Datum) mit dem Beobachtungstag der Obs (m['date']) datieren,
        # sonst könnte _board_local_to_utc_iso sie nicht parsen und das Gate liefe leer.
        def _dated(v):
            v = (str(v).strip() if v else '')
            if not v:
                return None
            if re.match(r'^\d{1,2}:\d{2}$', v):
                _obsd = (str(m.get('date') or '').strip()[:10])
                if not re.match(r'^\d{4}-\d{2}-\d{2}$', _obsd):
                    return None
                hh, mm = v.split(':')
                v = '%sT%02d:%02d:00' % (_obsd, int(hh), int(mm))
            return _board_local_to_utc_iso(v, arr_iata)
        obs_arr_iso = _dated(m.get('esti_arr')) or _dated(m.get('sched_arr'))
        if not obs_arr_iso:
            return False
        obs_arr = _dt2.fromisoformat(obs_arr_iso.replace('Z', '+00:00'))
        # ÜBERNACHT-HEBUNG (Owner/Fable 2026-07-16, LH423 BOS→FRA d+1): eine bare
        # 'HH:MM'-Ist-Ankunft wird oben mit dem ABFLUGTAG (m['date']) datiert. Bei
        # einem legitimen Übernacht-Leg (dep abends, arr am nächsten Morgen) landet
        # die so datierte obs_arr fälschlich VOR dem Abflug → das Gate würde die
        # echte airborne-Overnight-Obs aus flights_live droppen (Datenverlust). Ist
        # die datierte Soll-Ankunft (sched_arr) selbst >= dep (also der Plan ist ein
        # Übernachtflug), die obs_arr aber davor, dann gehört die obs auf den Folgetag
        # → +1 Tag heben, DANN erst vergleichen. Echter Wrong-Day (est_arr ~1 Tag vor
        # der eigenen Soll-Ankunft) bleibt danach weiterhin < dep und wird verworfen.
        if obs_arr < dep - _td2(minutes=_FLIGHTS_LIVE_WRONG_DAY_MARGIN_MIN):
            sched_arr_iso = _dated(m.get('sched_arr'))
            if sched_arr_iso:
                try:
                    sched_arr = _dt2.fromisoformat(
                        sched_arr_iso.replace('Z', '+00:00'))
                    if sched_arr >= dep and (obs_arr + _td2(days=1)) >= dep:
                        obs_arr = obs_arr + _td2(days=1)
                except Exception:
                    pass
        return obs_arr < dep - _td2(minutes=_FLIGHTS_LIVE_WRONG_DAY_MARGIN_MIN)
    except Exception:
        return False


def _sched_block_min(dep_local, dep_iata, arr_local, arr_iata):
    """Planmäßige Blockzeit (Flugdauer) in MINUTEN aus lokalen Soll-Ab-/Ankunfts-
    zeiten. WICHTIG: dep und arr stehen jeweils in IHRER eigenen Stations-Ortszeit
    (FRA-Abflug in Europe/Berlin, JFK-Ankunft in America/New_York) — eine simple
    String-Subtraktion wäre bei zeitzonenübergreifenden Strecken grob falsch.
    Darum beide Seiten erst via `_board_local_to_utc_iso` (dieselbe TZ-Kenntnis wie
    die Board-Zeiten) nach UTC, dann Differenz.

    Liefert einen int nur wenn plausibel (0 < min <= 20 h) — sonst None (fehlende/
    unparsbare Eingabe, unbekannte Stations-TZ, negativ, oder unrealistisch lang).
    NIE eine erfundene oder negative Dauer. Frei, kein Drittanbieter — reine
    Ableitung aus bereits vorhandenen Soll-Zeiten. Overnight-Flüge korrekt, weil die
    Board-Soll-Strings ihr Datum tragen."""
    if not (dep_local and arr_local and dep_iata and arr_iata):
        return None
    du = _board_local_to_utc_iso(dep_local, dep_iata)
    au = _board_local_to_utc_iso(arr_local, arr_iata)
    if not (du and au):
        return None
    try:
        from datetime import datetime
        d = datetime.fromisoformat(du.replace('Z', '+00:00'))
        a = datetime.fromisoformat(au.replace('Z', '+00:00'))
        m = int(round((a - d).total_seconds() / 60.0))
    except Exception:
        return None
    return m if 0 < m <= 20 * 60 else None


_PROFILE_HB_MEMO = {}              # token → (expires_ts, 'FRA' | '')
_PROFILE_HB_MEMO_TTL = 600.0       # 10 min — Homebase ändert sich praktisch nie


def _profile_homebase_cached(token):
    """Echte Profil-Homebase (3-Letter-IATA) eines Users — für die Tail-
    Turnaround-Weitergabe (Audit 2026-07-05): der Duty-Origin-Proxy in
    _carry_forward_turnaround_tails (sectors[0].from) versagt am RÜCKREISETAG
    (erster Abflug = Outstation) → ein Leg erbte den Tail über einen Homebase-
    Hub-Turnaround, was der Owner explizit verboten hat („bei 3h turnaround IN
    der homebase kann man sehr wohl Flieger wechseln").
    10-min-Memo pro Token (höchstens EIN Profil-Read pro Request-Burst).
    None wenn unbekannt — der Caller fällt auf den Proxy zurück. Wirft nie."""
    tok = (token or '').strip()
    if not tok:
        return None
    import time as _t
    now = _t.time()
    hit = _PROFILE_HB_MEMO.get(tok)
    if hit and hit[0] > now:
        return hit[1] or None
    hb = ''
    try:
        prof = (_profile_load(tok) or {}).get('profile') or {}
        hb = str(prof.get('homebase') or '').strip().upper()
        if len(hb) != 3 or not hb.isalpha():
            hb = ''
    except Exception:
        hb = ''
    if len(_PROFILE_HB_MEMO) > 5000:   # Memo-Cap (gleiche Klasse wie ADSBLol-OOM)
        _PROFILE_HB_MEMO.clear()
    _PROFILE_HB_MEMO[tok] = (now + _PROFILE_HB_MEMO_TTL, hb)
    return hb or None


# Übernacht-ARR-Physik-Marge (Tibor LH455-R4, 2026-07-16): liegt eine
# facts-materialisierte est_arr mehr als so viele Stunden VOR der Leg-eigenen
# Soll-Ankunft, gehört sie zu einer FREMDEN Tagesrotation (der datums-agnostische
# ARR-Match griff die gestrige Ankunft) → verwerfen. 6 h deckt jeden realen
# Delay/Frühankunft ab, ohne die ~24-h-Fremd-Rotation je durchzulassen.
_OVERNIGHT_ARR_MARGIN_H = 6


def _gate_facts_arr_against_leg(facts, leg_arr_iso):
    """PUR: verwirft die ARR-Seite eines `_flight_facts_from_obs`-Ergebnisses,
    wenn dessen `est_arr` physikalisch unmöglich weit VOR der Soll-Ankunft des
    Legs (`leg_arr_iso`) liegt — das ist die datums-agnostisch gematchte Ankunft
    einer FREMDEN Tagesrotation (Tibor LH455-R4). Der Rest der Facts (dep-Seite,
    reg) bleibt unangetastet. Gibt `facts` (evtl. mutiert) zurück. Wirft nie."""
    try:
        if not isinstance(facts, dict) or not leg_arr_iso:
            return facts
        _ea = facts.get('est_arr')
        if not _ea:
            return facts
        _ea_dt = datetime.fromisoformat(str(_ea).replace('Z', '+00:00'))
        _la_dt = datetime.fromisoformat(str(leg_arr_iso).replace('Z', '+00:00'))
        if _ea_dt.tzinfo is None:
            _ea_dt = _ea_dt.replace(tzinfo=timezone.utc)
        if _la_dt.tzinfo is None:
            _la_dt = _la_dt.replace(tzinfo=timezone.utc)
        if _ea_dt < _la_dt - timedelta(hours=_OVERNIGHT_ARR_MARGIN_H):
            # Fremd-Rotations-Ankunft: arr-Seite verwerfen (dep/reg behalten).
            for _k in ('est_arr', 'arr_delay_min', 'arr_status',
                       'arr_gate', 'arr_terminal'):
                facts[_k] = None
        return facts
    except Exception:
        return facts


def _enrich_leg_delays(sectors, date, free_only=True, homebase=None,
                       past_horizon_h=30):
    """Reichert die Pro-Leg-Sektoren EINES Roster-Tages (ical_sectors[]) IN PLACE
    um Live-/Warehouse-Delay-Felder an (Owner 2026-07-04 „alle Live-Sachen an-
    binden", Serve-Time-Enrichment — NICHT im iCal-Sync eingefroren).

    `homebase` (optional, Audit 2026-07-05): echte Profil-Homebase für die
    Tail-Turnaround-Weitergabe — der Duty-Origin-Proxy versagt am Rückreisetag
    (sectors[0].from = Outstation), s. _carry_forward_turnaround_tails.

    Pro Sektor-dict (braucht flight/from/to):
      (a) Flugnummer via `_fn_norm` normalisieren (LH839 == LH0839),
      (b) Codeshare→Operating falten (`_ax_codeshare_map`), damit EIN physischer
          Flug EIN Delay-Verdikt bekommt (Marketing-Nr additiv als `also_as`),
      (c) `_flight_obs_merged(fn, date, dep_iata=from, arr_iata=to,
          free_only=…)` — gecacht (~90 s), Fan-out über N Crew = O(1) je
          (fn,date,dep,arr), free_only=True → KEIN AeroDataBox-Spend,
      (d) neue OPTIONALE Keys anhängen: delay_min, delay_known, delay_side,
          dep_delay_min, arr_delay_min, status, cancelled, est_dep_iso,
          est_arr_iso, reg, obs_sides.

    HARTE GUARDS:
      • Zeitfenster: nur anreichern, wenn der Leg-Abflug (dep_iso, sonst `date`)
        im Fenster [jetzt−`past_horizon_h` h .. jetzt+27 h] liegt — reine
        Zukunfts-/Tief-Vergangenheits-Legs überspringen (spart Board-Scans, ehrt
        die >27h-Zukunfts-Regel). `past_horizon_h` (Default 30) öffnet NUR den
        datums-gezielten Warehouse-Read weiter in die Vergangenheit (Friend-
        Roster: 30-Tage-Tour). Der Live-Board-Scan bleibt via _flight_obs_merged
        (`_is_today_at`) hart auf HEUTE begrenzt — nur der persistente SB-Read
        bedient ältere Tage.
      • merged is None → GAR NICHTS schreiben (Legacy/kein Signal = Feld fehlt).
      • merged.delay_known False → delay_known=False, delay_min=None (NIEMALS
        eine erfundene 0). Echte Beobachtungen (status/est/reg) dürfen dennoch
        durchgereicht werden — sie sind gemessen, nicht erfunden.

    Gibt dieselbe Liste zurück (in-place mutiert). Wirft nie."""
    if not sectors or not isinstance(sectors, list):
        return sectors
    # „BOARD SCHLÄGT INFERENZ" (Owner 2026-07-09): einen zuvor per Turnaround
    # ABGELEITETEN Tail (`tail_inferred`) vor der Neu-Anreicherung verwerfen. So
    # überschreibt eine ECHTE Board-/Warehouse-Beobachtung den geratenen Tail und
    # ein veralteter inferierter Tail (Maschine wurde inzwischen getauscht) bleibt
    # NIE kleben. Direkt gemessene Tails (ohne `tail_inferred`) sind belastbar und
    # bleiben unangetastet; die Turnaround-Weitergabe unten setzt Inferenzen frisch.
    _strip_inferred_tails(sectors)
    now = datetime.now(timezone.utc)
    cs_map = None
    for s in sectors:
        if not isinstance(s, dict):
            continue
        raw_fn = str(s.get('flight') or '').strip()
        frm = str(s.get('from') or '').strip().upper()
        to = str(s.get('to') or '').strip().upper()
        if len(raw_fn) < 3 or len(frm) != 3 or not frm.isalpha() \
                or len(to) != 3 or not to.isalpha():
            continue
        # ── Zeitfenster-Guard ────────────────────────────────────────────────
        dep_dt = None
        try:
            dr = s.get('dep_iso')
            if dr:
                dep_dt = datetime.fromisoformat(str(dr).replace('Z', '+00:00'))
                if dep_dt.tzinfo is None:
                    dep_dt = dep_dt.replace(tzinfo=timezone.utc)
        except Exception:
            dep_dt = None
        if dep_dt is not None:
            if dep_dt > now + timedelta(hours=27):
                continue        # tiefe Zukunft: kein Board-Scan
            if dep_dt < now - timedelta(hours=past_horizon_h):
                continue        # tiefe Vergangenheit: kein SB-Read (Horizont)
        else:
            # OHNE präzises dep_iso greift der Stunden-Guard nicht → grobe
            # DATUMS-Guard (Fix 2026-07-04: Legs ohne dep_iso umgingen das
            # Fenster ganz). Nur Tag-von / ±1 Tag anreichern; alles Tiefere
            # überspringen (ehrt die >27h-Zukunfts-Regel grob). Der Vergangenheits-
            # Rand skaliert mit `past_horizon_h` (Friend-Roster: 30-Tage-Tour).
            try:
                from datetime import date as _dt_date
                _draw = str(s.get('date') or date or '')[:10]
                d = _dt_date.fromisoformat(_draw)
                # LOKALE Uhr, nicht UTC: die Tages-Keys der Caller (get_briefings
                # `_live_days` etc.) kommen aus `date.today()` — mit `now.date()`
                # (UTC) fiele „morgen" zwischen lokaler Mitternacht und UTC-
                # Mitternacht fälschlich in die tiefe Zukunft (+2 UTC-Tage).
                today = _dt_date.today()
                # grober Vergangenheits-Rand in Tagen aus dem Stunden-Horizont
                # (Default 30h → 1 Tag; weiter Horizont deckt die Tour-Retention).
                _past_days = max(1, int((past_horizon_h + 23) // 24))
                if d > today + timedelta(days=1):
                    continue        # tiefe Zukunft (grob)
                if d < today - timedelta(days=_past_days):
                    continue        # tiefe Vergangenheit (grob, Horizont)
            except Exception:
                pass        # kein parsbares Datum → wie bisher weiter (nie werfen)
        # ── Flugnummer normalisieren + Codeshare→Operating ───────────────────
        fn = _fn_norm(raw_fn)
        if len(fn) < 3:
            continue
        if cs_map is None:
            try:
                cs_map = _ax_codeshare_map() or {}
            except Exception:
                cs_map = {}
        op_fn = cs_map.get(fn, fn)
        # Datum: bevorzugt der ECHTE Abflugtag des Legs (dep_iso, korrekt an der
        # Tag-Grenze / in West-Zeitzonen), sonst der Tages-Key.
        leg_date = None
        if dep_dt is not None:
            try:
                leg_date = dep_dt.strftime('%Y-%m-%d')
            except Exception:
                leg_date = None
        leg_date = leg_date or (str(date or '')[:10] or None)
        # MITTERNACHTS-LÜCKE (Flake test_friend_roster_free_only…, 2026-07-16):
        # ein Leg, das kurz VOR UTC-Mitternacht abflog und noch in der Luft ist
        # (dep < now < arr), hat einen leg_date = GESTERN (aus dep_iso), während das
        # LIVE-Board an beiden Enden HEUTE ist. `_flight_obs_merged` gated seinen
        # Live-Free-Board-Scan über `_is_today_at(date_q)` → mit date=gestern lief
        # er GAR NICHT und der aktive Flug bekam 00:00–00:14 UTC keine Anreicherung
        # (delay/status/tail = None). Für ein JETZT laufendes Leg das Live-Datum
        # neutralisieren (date=None → Board wird gescannt); der datums-gezielte
        # SB-Read pro Airport nutzt intern weiter `_airport_local_now`, bleibt also
        # korrekt. Nur der Live-Scan-Gate wird geöffnet — kein Mehr-Spend
        # (free_only unverändert). Fenster wie _active_sector_flight_numbers.
        _merge_date = leg_date
        try:
            _arr_dt = None
            _ar = s.get('arr_iso')
            if _ar:
                _arr_dt = datetime.fromisoformat(str(_ar).replace('Z', '+00:00'))
                if _arr_dt.tzinfo is None:
                    _arr_dt = _arr_dt.replace(tzinfo=timezone.utc)
            if (dep_dt is not None and _arr_dt is not None
                    and dep_dt - timedelta(minutes=15) <= now
                    <= _arr_dt + timedelta(minutes=10)
                    and leg_date != now.strftime('%Y-%m-%d')):
                _merge_date = None
        except Exception:
            _merge_date = leg_date
        # ── ÜBERNACHT-LEG: ARR-SEITE VOM ANKUNFTSTAG LESEN (Owner/Fable 2026-07-16,
        # Nico LH423 BOS→FRA) ────────────────────────────────────────────────────
        # Ein Übernacht-Leg (dep 15.07 abends → arr 16.07 früh) keyt am ABFLUGTAG.
        # `_flight_obs_merged(date=leg_date=15)` findet dann die gleichnamige
        # FRA#ARR-Row des ABFLUGTAGS — bei Übernacht-Legs strukturell die FALSCHE
        # Instanz (die gestrige Rotation: esti 07:44 'Geplant') — und meldet „bedient".
        # Die echte Landung steht am ANKUNFTSTAG (date=16: esti 08:16 'baggage
        # delivery'). Darum die arr-Seite grundsätzlich vom Ankunftstag lesen, wenn
        # das Leg über Nacht geht. „Über Nacht" = das ARR-Datum in der STATIONS-
        # ORTSZEIT des Ziels ist ein anderer Kalendertag als der Leg-Tag. arr_iso ist
        # echt-UTC → in die Ziel-TZ wandeln und den lokalen Tag nehmen (nicht den
        # UTC-Tag: eine 07:45-CEST-Ankunft ist um 05:45Z schon der Ortstag 16.). Nur
        # gesetzt, wenn wirklich verschieden — Nicht-Übernacht-Legs bleiben unberührt.
        _arr_date_q = None
        try:
            _ar2 = s.get('arr_iso')
            if _ar2 and leg_date:
                _adt2 = datetime.fromisoformat(str(_ar2).replace('Z', '+00:00'))
                if _adt2.tzinfo is None:
                    _adt2 = _adt2.replace(tzinfo=timezone.utc)
                _to_norm = _DE_ICAO_TO_IATA.get(to, to)
                _tzname = ('Europe/Berlin' if _to_norm in ('FRA', 'EDDF')
                           else airport_tz(_to_norm))
                if _tzname:
                    from zoneinfo import ZoneInfo as _ZI
                    _arr_local_day = _adt2.astimezone(
                        _ZI(_tzname)).strftime('%Y-%m-%d')
                    if _arr_local_day != leg_date:
                        _arr_date_q = _arr_local_day
        except Exception:
            _arr_date_q = None
        try:
            m = _flight_obs_merged(op_fn, date=_merge_date, dep_iata=frm,
                                   arr_iata=to, live=True, free_only=free_only,
                                   arr_date=_arr_date_q)
        except Exception:
            m = None
        # ── VERGANGENHEITS-FALLBACK auf die persistente Blueprint-Quelle
        # (Owner/Fable 2026-07-15, LH893 RIX→FRA): der obs-Merge oben bevorzugt
        # für Vortage teils eine spätere nackte „Geplant/Delayed"-Repoll-Row bzw.
        # findet die reine ARR-Row nicht → das persistierte Ist (esti_arr in
        # airport_delay_obs) fällt weg und das Freunde-Sheet zeigt nur nacktes
        # „Gelandet/Abgeflogen". `_flight_facts_from_obs` liest genau dieses Ist
        # korrekt (DEP+ARR-Merge, Station-Offset-ISO). Nur für VERGANGENE Legs und
        # nur, wenn der Merge keine Ankunfts-Esti hat (m None ODER m ohne esti_arr)
        # — Vorrang haben stets vorhandene m-Werte, Facts füllen NUR Lücken. Der
        # Aufruf trifft dieselbe gratis SB-Tabelle (kein Paid-Spend). Wirft nie.
        _facts = None
        _is_past = False
        try:
            if dep_dt is not None:
                _is_past = dep_dt < now
            elif leg_date:
                from datetime import date as _dt_date2
                _is_past = _dt_date2.fromisoformat(leg_date) < _dt_date2.today()
        except Exception:
            _is_past = False
        if _is_past and (m is None or not m.get('esti_arr')):
            try:
                from blueprints.aerox_data_blueprint import (
                    _flight_facts_from_obs as _facts_from_obs)
                _fc = _facts_from_obs(op_fn, leg_date, dep_iata=frm, arr_iata=to)
                if isinstance(_fc, dict) and _fc:
                    _facts = _fc
                # ── ÜBERNACHT-ARR-DATUM (Tibor LH455-R4, 2026-07-16) ──────────
                # Ein Nachtflug (dep 15.07 abends → arr 16.07 08:25) wird über
                # den DEP-Tag (15.07) gekeyt. `_flight_facts_from_obs` matcht
                # die ARR-Row datums-genau am Tages-Key → für date=15 lieferte es
                # die Ankunft der GESTRIGEN Rotation (est_arr 15.07 08:39) und
                # hängte sie ans heutige Leg → est_arr lag ~24 h VOR sched_arr.
                # Physik-Gate: liegt die facts-est_arr mehr als
                # _OVERNIGHT_ARR_MARGIN_H VOR der Leg-eigenen Soll-Ankunft
                # (arr_iso), ist es eine Fremd-Rotation → die arr-Seite verwerfen
                # und, wenn das Leg tatsächlich über Nacht geht, mit dem ARR-Tag
                # (arr_iso-Datum) neu abfragen. Nie eine implausible Ist-Ankunft
                # ans Leg hängen. Wirft nie.
                _facts = _gate_facts_arr_against_leg(_facts, s.get('arr_iso'))
                _arr_day = None
                try:
                    _ar = s.get('arr_iso')
                    if _ar:
                        _adt = datetime.fromisoformat(
                            str(_ar).replace('Z', '+00:00'))
                        if _adt.tzinfo is None:
                            _adt = _adt.replace(tzinfo=timezone.utc)
                        _arr_day = _adt.strftime('%Y-%m-%d')
                except Exception:
                    _arr_day = None
                if (_arr_day and leg_date and _arr_day != leg_date
                        and (not _facts or not _facts.get('est_arr'))):
                    _fc2 = _facts_from_obs(op_fn, _arr_day,
                                           dep_iata=frm, arr_iata=to)
                    _fc2 = _gate_facts_arr_against_leg(_fc2, s.get('arr_iso'))
                    if isinstance(_fc2, dict) and _fc2 and _fc2.get('est_arr'):
                        # ARR-Tag-Row bringt die richtige Ist-Ankunft; die DEP-Tag-
                        # Facts (dep-Seite) bleiben Vorrang für dep_*/reg, die arr-
                        # Seite kommt aus _fc2 (Lücken-Merge, nie überschreiben).
                        if not _facts:
                            _facts = _fc2
                        else:
                            for _ak in ('est_arr', 'arr_delay_min', 'arr_status',
                                        'sched_arr', 'arr_gate', 'arr_terminal'):
                                if _facts.get(_ak) is None and _fc2.get(_ak) is not None:
                                    _facts[_ak] = _fc2.get(_ak)
            except Exception:
                _facts = None
        if m is None:
            # Kein Merge-Signal: nur weitermachen, wenn die persistente Quelle für
            # dieses Vergangenheits-Leg wirklich Ist-Fakten liefert. Sonst wie
            # bisher überspringen (Legacy-Form, keine erfundenen Felder). Aus den
            # Facts einen minimalen Merge-artigen Datensatz bauen, damit der
            # restliche Pfad (Status-Gate, Reg-Wächter …) uniform läuft.
            if not _facts:
                continue
            _f_status = _facts.get('arr_status') or _facts.get('dep_status')
            _f_delay = (_facts.get('arr_delay_min')
                        if _facts.get('arr_delay_min') is not None
                        else _facts.get('dep_delay_min'))
            m = {
                'delay_known': _f_delay is not None,
                'delay_min': _f_delay,
                'delay_side': ('arr' if _facts.get('arr_delay_min') is not None
                               else ('dep' if _facts.get('dep_delay_min')
                                     is not None else None)),
                'dep_delay_min': _facts.get('dep_delay_min'),
                'arr_delay_min': _facts.get('arr_delay_min'),
                'status': _f_status,
                'cancelled': bool(_facts.get('cancelled')),
                # Facts liefern bereits Station-Offset-ISO (nicht das rohe Board-
                # Format) → NICHT nochmal durch _board_local_to_utc_iso schicken;
                # unten direkt in est_*_iso übernehmen (esti_dep/arr bleiben None).
                'esti_dep': None, 'esti_arr': None,
                'reg': _facts.get('reg'), 'sides': {'dep': None, 'arr': None},
                'sched_dep': None, 'sched_arr': _facts.get('sched_arr'),
            }
        known = bool(m.get('delay_known'))
        s['delay_known'] = known
        s['delay_min'] = (m.get('delay_min') if known else None)
        s['delay_side'] = m.get('delay_side')
        s['dep_delay_min'] = m.get('dep_delay_min')
        s['arr_delay_min'] = m.get('arr_delay_min')
        s['cancelled'] = bool(m.get('cancelled'))
        # est_*: bester Ist/Erwartet-Zeitstempel des Resolvers. Board-Esti steht in
        # STATIONS-Ortszeit (evtl. ohne Offset) → hier genau EINMAL nach echt-UTC
        # wandeln (dep mit airport_tz(from), arr mit airport_tz(to)), damit iOS den
        # Wert wie dep_iso durch den station-lokalen Formatter schicken kann OHNE
        # Doppelverschiebung. None wenn keine Esti / TZ unbekannt / unparsbar —
        # nie ein naiver String. delay_min bleibt die autoritative Zahl.
        # (Vor dem Status-Gate berechnet: est_arr_iso ist eine Plausi-Schranke.)
        s['est_dep_iso'] = _board_local_to_utc_iso(m.get('esti_dep'), frm)
        s['est_arr_iso'] = _board_local_to_utc_iso(m.get('esti_arr'), to)
        # ── PERSISTENTE-FACTS-LÜCKENFÜLLUNG (Vergangenheits-Legs): fehlt nach dem
        # Merge eine Ist-Zeit / ein Delay / ein Status / eine Reg, aber die
        # persistente Blueprint-Quelle hat sie (est_dep/est_arr sind dort schon
        # Station-Offset-ISO, unmissverständlich) → NUR die Lücken auffüllen,
        # nie einen vorhandenen m-Wert überschreiben. delay_known wird ehrlich
        # nachgezogen, wenn erst die Facts eine Delay-Zahl liefern.
        if _facts:
            if s.get('est_dep_iso') is None and _facts.get('est_dep'):
                s['est_dep_iso'] = _facts.get('est_dep')
            if s.get('est_arr_iso') is None and _facts.get('est_arr'):
                s['est_arr_iso'] = _facts.get('est_arr')
            if s.get('dep_delay_min') is None \
                    and _facts.get('dep_delay_min') is not None:
                s['dep_delay_min'] = _facts.get('dep_delay_min')
            if s.get('arr_delay_min') is None \
                    and _facts.get('arr_delay_min') is not None:
                s['arr_delay_min'] = _facts.get('arr_delay_min')
            if not known and s.get('delay_min') is None:
                _fd = (s.get('arr_delay_min') if s.get('arr_delay_min') is not None
                       else s.get('dep_delay_min'))
                if _fd is not None:
                    s['delay_known'] = True
                    s['delay_min'] = _fd
                    if not s.get('delay_side'):
                        s['delay_side'] = ('arr'
                                           if s.get('arr_delay_min') is not None
                                           else 'dep')
            if _facts.get('cancelled') and not s.get('cancelled'):
                s['cancelled'] = True
        # ── STATUS PLAUSIBILITÄTS-/PHYSIK-GATE (Owner/Fable 2026-07-13, LH454→SFO)
        # Bisher: der ROHE Board-Status floss ungegatet in dieses Feld und weiter
        # in Kalender-Leg-Anzeige, Feed-Bordkarte und flights_live[].status. Manche
        # Boards flippen für eine Flugnummer fälschlich früh auf „gelandet HH:MM";
        # bei einem 11-h-Langstreckenflug ist das physikalisch unmöglich. Die
        # FlightState-Engine verwirft eine solche Landung strukturell (Airborne-
        # Gate/Monotonie/Physik) — diese Fläche fährt jetzt dieselbe Wahrheit: ein
        # TERMINALER 'landed'-Status gilt nur, wenn die früheste physikalisch
        # mögliche Ankunft (est_dep + Großkreis / v_max) ODER die Fahrplan-Ankunft
        # (−15 min Slack) erreicht ist. Sonst wird der terminale Status verworfen
        # (None) statt eine erfundene Landung zu behaupten. Nicht-terminale Status
        # (airborne/delayed/boarding) laufen unverändert durch; fehlen die Belege
        # → fail-open (Rohstatus bleibt). Rein additiv, konservativ, wirft nie.
        _raw_status = m.get('status')
        # Persistente-Facts-Status-Lücke: hat der Merge KEINEN Status, die Blueprint-
        # Quelle aber einen (arr gewinnt vor dep) → nachziehen (Facts füllen Lücken).
        if not _raw_status and _facts:
            _raw_status = _facts.get('arr_status') or _facts.get('dep_status') \
                or _raw_status
        # ── FIX 3: STALE VERGANGENHEITS-STATUS EHRLICH (Owner/Fable 2026-07-15) ─
        # Zwei Leichen aus dem Freunde-Roster (Vortage) ehrlich auf 'landed' setzen,
        # OHNE eine Ist-Zeit zu erfinden:
        #   (A) „ABGEFLOGEN"-LEICHE: dep-seitig airborne/abgeflogen/departed
        #       gemeldet, KEINE Ankunfts-Beobachtung, Plan-Ankunft > 6 h vor jetzt
        #       → längst gelandet, der Airborne-Status ist veraltet (LH890 FRA→RIX).
        #   (B) „GEPLANT"-LEICHE: Status noch im scheduled-Bucket ('Geplant'/
        #       'scheduled'/None), ABER es LIEGT eine Ist-Ankunft (est_arr) vor und
        #       die Plan-Ankunft ist > 6 h vorbei → der Flug ist gelandet, nur der
        #       nackte Repoll-Status hängt (LH893 RIX→FRA).
        # PLAN-ANKUNFT (Kern des LH890-Bugs): RIX wird nie geharvestet → weder Board
        # noch Facts liefern sched_arr. Darum als Fallback die Leg-eigene arr_iso der
        # ical_sectors, und wenn auch die fehlt, die dep-Zeit + Großkreis/v_max (die
        # FRÜHESTE physikalisch mögliche Ankunft — konservativ, unterschätzt nie den
        # Ist-Zeitpunkt) als Plan-Ankunfts-Proxy. Cancelled-Flüge sind NIE gelandet.
        # `_stale_forced_landed` merkt sich, dass diese Physik-Staleness-Regel den
        # Status auf 'landed' gehoben hat — damit der FlightState-Engine-Block unten
        # (der ohne Ankunfts-Position nur „airborne" projiziert) die überfällige
        # Landung NICHT wieder zurückdreht (Live-vs-Test-Diskrepanz LH890: die Regel
        # feuerte im Test, wurde live aber vom Engine-Override überschrieben).
        _stale_forced_landed = False
        try:
            _bucket = _flight_status_bucket(_raw_status)
            _has_est_arr = bool(s.get('est_arr_iso')
                                or (_facts and _facts.get('est_arr')))
            _has_arr_obs = bool(
                _has_est_arr or s.get('arr_delay_min') is not None
                or (_facts and _facts.get('arr_status')))
            if not s.get('cancelled'):
                # PLAN-Ankunft (UTC): Sektor-arr_iso (echt-UTC) bevorzugt, sonst
                # Board/Facts-Soll (station-lokal → UTC), sonst dep + Großkreis/v_max.
                _sched_arr_utc = None
                for _sa_cand, _sa_conv in (
                        (s.get('arr_iso'), False),
                        (m.get('sched_arr'), True),
                        ((_facts or {}).get('sched_arr'), False)):
                    if not _sa_cand:
                        continue
                    try:
                        _sa_iso = (_board_local_to_utc_iso(_sa_cand, to)
                                   if _sa_conv else str(_sa_cand))
                        if not _sa_iso:
                            continue
                        _sa_dt = datetime.fromisoformat(
                            _sa_iso.replace('Z', '+00:00'))
                        if _sa_dt.tzinfo is None:
                            _sa_dt = _sa_dt.replace(tzinfo=timezone.utc)
                        _sched_arr_utc = _sa_dt
                        break
                    except Exception:
                        continue
                # Fallback: früheste physikalisch mögliche Ankunft aus dep-Zeit +
                # Großkreis / v_max (LH890: kein sched_arr, keine arr_iso → hier).
                if _sched_arr_utc is None:
                    try:
                        from blueprints.leg_status_gate import (
                            earliest_possible_arrival_ts as _epa)
                        from blueprints.aerox_data_blueprint import (
                            _iata_latlon as _ll3)
                        _dep_epoch = None
                        for _dc in (s.get('est_dep_iso'), s.get('dep_iso')):
                            if not _dc:
                                continue
                            try:
                                _dd = datetime.fromisoformat(
                                    str(_dc).replace('Z', '+00:00'))
                                if _dd.tzinfo is None:
                                    _dd = _dd.replace(tzinfo=timezone.utc)
                                _dep_epoch = _dd.timestamp()
                                break
                            except Exception:
                                continue
                        _eta = _epa(_dep_epoch, _ll3(frm), _ll3(to))
                        if _eta is not None:
                            _sched_arr_utc = datetime.fromtimestamp(
                                _eta, tz=timezone.utc)
                    except Exception:
                        _sched_arr_utc = None
                _overdue = (_sched_arr_utc is not None
                            and _sched_arr_utc < now - timedelta(hours=6))
                # (A) Airborne-Leiche: airborne + keine Ankunfts-Obs + überfällig.
                if _bucket == 'airborne' and not _has_arr_obs and _overdue:
                    _raw_status = 'landed'
                    _stale_forced_landed = True
                # (B) Geplant-Leiche: scheduled-Bucket (oder gar kein Status),
                #     aber Ist-Ankunft vorhanden + überfällig → gelandet.
                elif (_bucket in ('grounded', None) and _has_est_arr
                        and _overdue):
                    _raw_status = 'landed'
                    _stale_forced_landed = True
        except Exception:
            pass
        # (C) BEOBACHTETE FACTS-LANDUNG SOFORT (Sebastian LH1139 2026-07-16):
        # der Live-Merge trug mittags nur noch die dep-Seite ('Boarding' vom
        # Morgen — das Live-Board rotiert gelandete Flüge raus), die
        # persistenten Facts aber eine ankunfts-plausible Landung
        # ('Gepäckausgabe beendet') MIT Ist-Ankunft in der Vergangenheit.
        # Das ist eine BEOBACHTETE Landung — sie darf nicht 6 h auf die
        # Überfällig-Regel warten (Sektor stand bis dahin als 'grounded' =
        # iOS „Erwartet"). Cancelled schlägt weiterhin alles.
        if not _stale_forced_landed and not s.get('cancelled'):
            try:
                _fa_st = (_facts or {}).get('arr_status')
                if _fa_st and _flight_status_bucket(_fa_st) == 'landed':
                    _ea_raw = s.get('est_arr_iso') or (_facts or {}).get('est_arr')
                    if _ea_raw:
                        _ea_dt = datetime.fromisoformat(
                            str(_ea_raw).replace('Z', '+00:00'))
                        if _ea_dt.tzinfo is None:
                            _ea_dt = _ea_dt.replace(tzinfo=timezone.utc)
                        if _ea_dt <= now:
                            _raw_status = 'landed'
                            _stale_forced_landed = True
            except Exception:
                pass
        # Physik-Schranken-Inputs vorab binden (auch der Engine-Block unten liest
        # sie): so bleibt der Feinschliff-1-Status-Gate auch dann definiert, wenn
        # der Import unten scheitert (fail-open statt NameError).
        _dep_ts = None
        _dep_ll = _arr_ll = None
        try:
            from blueprints.leg_status_gate import gated_leg_status as _gate_status
            # eff. Abflug (Epoch) für die physikalische Schranke: bester Ist-
            # Zeitstempel (est_dep_iso, schon echt-UTC) vor dem Plan-dep_iso.
            for _dep_cand in (s.get('est_dep_iso'), s.get('dep_iso')):
                if _dep_cand:
                    try:
                        _dts = datetime.fromisoformat(
                            str(_dep_cand).replace('Z', '+00:00'))
                        if _dts.tzinfo is None:
                            _dts = _dts.replace(tzinfo=timezone.utc)
                        _dep_ts = _dts.timestamp()
                        break
                    except Exception:
                        pass
            _dep_ll = _arr_ll = None
            try:
                from blueprints.aerox_data_blueprint import _iata_latlon as _ll
                _dep_ll = _ll(frm)
                _arr_ll = _ll(to)
            except Exception:
                pass
            s['status'] = _gate_status(
                _raw_status, now=now.timestamp(),
                sched_arr_iso=_board_local_to_utc_iso(m.get('sched_arr'), to),
                est_arr_iso=s.get('est_arr_iso'), dep_ts=_dep_ts,
                dep_ll=_dep_ll, arr_ll=_arr_ll)
        except Exception:
            s['status'] = _raw_status        # Gate-Fehler → Rohstatus (nie brechen)
        # status_observed_at = ENRICH-Zeitpunkt (UTC), NICHT die Board-Zeit: die
        # Quelle (_flight_obs_merged) trägt keinen eigenen Beobachtungs-Zeitstempel,
        # ihr Memo ist ≤~90 s alt → ehrlich „Stand jetzt"; iOS muss die Frische
        # der Status-Felder damit nicht mehr raten.
        s['status_observed_at'] = now.strftime('%Y-%m-%dT%H:%M:%SZ')
        # ── FLIGHTSTATE-ENGINE (additiv): kanonische Phase/Phase-Konfidenz an den
        # Sektor hängen — DIESELBE Wahrheit wie crew_state/flights_live (r111–r114).
        # Reuse des schon geladenen `m` (obs_from_board_merged) + optional der
        # aircraft_live-Position → resolve_flight_state → phase/phase_conf. KEIN
        # neuer I/O außer dem gratis, memoisierten aircraft_live-Read (wie
        # flights_live). Shadow (FLIGHTSTATE_SHADOW=1) loggt Diffs; der Roh-`status`
        # oben ist bereits physik-gegatet, die Engine-Phase kommt additiv dazu.
        # Best-effort, nie werfend.
        try:
            from blueprints.flight_state_shadow import shadow_enabled as _fs_se
            _fs_on = (_fs_se() or os.environ.get(
                'FLIGHTSTATE_LIVE_FRIENDS', '') in ('1', 'true', 'yes'))
            if _fs_on:
                from blueprints.flight_state_collectors import (
                    build_keys as _fs_bk, obs_from_board_merged as _fs_obm,
                    obs_from_aircraft_live as _fs_oal)
                from blueprints.flight_state import (
                    resolve_flight_state as _fs_resolve, prior_state as _fs_prior,
                    remember_state as _fs_remember)
                from blueprints.flight_state_shadow import shadow_record as _fs_shadow
                from blueprints.aerox_data_blueprint import (
                    _iata_latlon as _fs_ll, _iata_elev_ft as _fs_elev)
                _fs_keys = _fs_bk(
                    op_fn, leg_date, frm, to, roster_tail=m.get('reg'),
                    sched_dep_iso=s.get('est_dep_iso') or _board_local_to_utc_iso(
                        m.get('sched_dep'), frm),
                    sched_arr_iso=_board_local_to_utc_iso(m.get('sched_arr'), to),
                    dep_ll=_fs_ll(frm), arr_ll=_fs_ll(to),
                    dep_elev_ft=_fs_elev(frm))
                _fs_obs = _fs_obm(m, _fs_keys, board_to_iso=_board_local_to_utc_iso)
                # optional: gratis, memoisierter aircraft_live-Positions-Read
                # (füllt das Airborne-/Taxi-Gate über Ozean/Russland — dieselbe
                # Quelle wie flights_live). Best-effort, on_ground egal (die Engine
                # entscheidet selbst per Kinematik).
                _fs_cp = _fs_cr = _fs_crg = _fs_cty = None
                try:
                    from blueprints.aerox_data_blueprint import _aircraft_live_pos as _fs_alp
                    _fs_cp, _fs_cr, _fs_crg, _fs_cty = _fs_alp(flight=op_fn, dep=to)
                    _fs_obs += _fs_oal(_fs_cp, _fs_cr, _fs_crg, _fs_cty)
                except Exception:
                    pass
                _fs = _fs_resolve(_fs_keys, _fs_obs, prior=_fs_prior(op_fn, leg_date))
                _fs_remember(_fs)
                if _fs_se():
                    _fs_shadow('enrich_leg_delays', _fs_keys, _fs_obs,
                               {'status': s.get('status'), 'cancelled': s.get('cancelled')},
                               fs=_fs)
                # additiv: kanonische Phase/Konfidenz (iOS ≥ Build 95 nutzt sie;
                # alte Builds ignorieren die Extra-Keys).
                s['phase'] = _fs['phase']
                s['phase_conf'] = _fs['phase_conf']
                # 100%-GLEICHLAUT (Owner/Fable 2026-07-13, Feinschliff 1): der
                # Kalender-Sektor-`status` zeigt jetzt die VOLLE Engine-Phase —
                # DIESELBE Wahrheit wie crew_state/flights_live —, nicht mehr nur
                # den physik-gegateten ROHEN Board-Status. Vorher konnte der Roh-
                # Status „Boarding" durchlaufen, während dieselbe Engine über
                # flights_live schon „fliegt/rollt" projizierte (Divergenz zwischen
                # Kalender-Leg und Feed-Bordkarte). Wir leiten den Status kanonisch
                # ab (`project_friend_leg().status` = die Engine-Phase) und
                # übersetzen ihn in genau das Board-Vokabular, das iOS `DelayLogic.
                # phase` schon versteht (airborne/landed/grounded/cancelled) —
                # dasselbe Mapping wie warehouse_reader/family_watch/aerox_data.
                #
                # LANDUNG-PLAUSI BLEIBT GEWAHRT: die Engine gewährt einen arr-
                # seitigen harten „gelandet" OHNE eigene Physik-Schranke (board_arr
                # LANDED wins outright, flight_state.py T2). Ein terminaler Engine-
                # Status wird darum durch DASSELBE Physik-Gate geschickt wie der
                # Roh-Status oben (`gated_leg_status`) — ist die Landung physisch
                # unmöglich (11h-Flug, gerade erst abgeflogen), wird sie verworfen
                # und der bereits physik-gegatete Roh-`status` bleibt stehen (keine
                # erfundene/bogus „gelandet 13:03"). Nicht-terminale Engine-Phasen
                # (airborne/grounded/cancelled) laufen unverändert durch.
                # Fail-open: keine kartierbare Phase (UNKNOWN) → Roh-Status bleibt.
                try:
                    from blueprints.flight_state import (
                        project_friend_leg as _fs_proj)
                    from blueprints.warehouse_reader import (
                        _ENGINE_PHASE_TO_LEGACY as _fs_phase_vocab)
                    from blueprints.leg_status_gate import (
                        gated_leg_status as _gate_status2)
                    _canon_phase = _fs_proj(_fs).get('status')
                    _canon_status = _fs_phase_vocab.get(_canon_phase)
                    if _canon_status and _canon_status != 'unknown':
                        # terminale Engine-Landung DERSELBEN Physik-Prüfung wie der
                        # Roh-Status unterziehen (gleiche Schranken wie _gate_status
                        # oben); übersteht sie das Gate nicht → Roh-Status behalten.
                        _gated_canon = _gate_status2(
                            _canon_status, now=now.timestamp(),
                            sched_arr_iso=_board_local_to_utc_iso(
                                m.get('sched_arr'), to),
                            est_arr_iso=s.get('est_arr_iso'), dep_ts=_dep_ts,
                            dep_ll=_dep_ll, arr_ll=_arr_ll)
                        if _gated_canon is not None:
                            # STALE-LANDUNG NICHT ZURÜCKDREHEN (Owner/Fable 2026-07-16,
                            # LH890 FRA→RIX): hat die Physik-Staleness-Regel oben schon
                            # 'landed' erzwungen (airborne + keine Ankunfts-Obs + Plan-
                            # Ankunft > 6 h vorbei bzw. Geplant-Leiche mit Ist-Ankunft),
                            # darf die Engine-Projektion — die ohne Ankunfts-Position nur
                            # „airborne/grounded" kennt — die überfällige Landung nicht
                            # wieder auf einen nicht-terminalen Status senken. Nur ein
                            # ebenfalls terminaler Engine-Status (landed) darf gewinnen.
                            _canon_bucket = _flight_status_bucket(_gated_canon)
                            if _stale_forced_landed and _canon_bucket != 'landed':
                                pass        # Stale-'landed' behalten
                            else:
                                s['status'] = _gated_canon
                except Exception:
                    pass        # Projektion/Import-Fehler → Roh-Status bleiben lassen
        except Exception:
            pass
        # `tail` = Flugzeug-Kennzeichen fürs Kalender-Leg (Owner 2026-07-04:
        # „Tails auf jedem Leg im Kalender bei Crew UND Freunde"). Reines Alias auf
        # das GEMESSENE `reg` — NUR bei echtem Board/Warehouse-Treffer setzen, nie
        # erfunden; kein reg → Feld bleibt abwesend (additiv, abwärtskompatibel).
        # AUSGEMUSTERTE-TAILS-WÄCHTER (Owner 2026-07-12, LH780→D-ABVU): manche
        # Board-Quellen (Fraport-Feed) tragen für Langstrecken-Flugnummern
        # Museums-Regs. reg/tail nur durchreichen, wenn die Reg in den letzten
        # 60 Tagen wirklich fliegend gesehen wurde (aircraft_live/aircraft_track,
        # 24 h-Memo) — sonst beide Felder ehrlich weglassen.
        _tail = m.get('reg') or (_facts.get('reg') if _facts else None)
        if isinstance(_tail, str):
            _tail = _tail.strip()
        if _tail and not _tail_recently_active(_tail):
            _tail = None
        s['reg'] = _tail or None
        if _tail:
            s['tail'] = _tail
        s['obs_sides'] = m.get('sides')
        if op_fn != fn and 'also_as' not in s:
            s['also_as'] = raw_fn        # gefaltete Marketing-Nummer bewahren
    # ── KETTEN-LANDUNG (Owner/Fable 2026-07-16, Sebastian LH880 FRA→TLL) ──────
    # Wer den FOLGEFLUG derselben Rotation fliegt, ist mit dem vorherigen
    # gelandet. Tallinn (TLL) wird nie geharvestet → LH880 FRA→TLL bekommt keine
    # Ankunfts-Beobachtung und klebt bis zur 6h-Überfällig-Regel auf „Abgeflogen".
    # ABER der BEWEIS ist längst da: LH881 TLL→FRA (der nächste Sektor derselben
    # Tages-Liste) ist bereits abgeflogen. Ein Sektor, der NACHWEISLICH den Boden
    # verlassen hat, beweist die Landung des unmittelbar vorausgehenden Sektors.
    #
    # BEWEIS-SCHWELLE (Verspätungs-Realität): der spätere Sektor gilt nur als
    # abgeflogen bei ECHTEM Signal — Status-Bucket airborne/landed ODER eine
    # BEOBACHTETE est_dep in der Vergangenheit —, NICHT bloß weil seine Planzeit
    # vorbei ist (er könnte selbst noch verspätet am Boden stehen).
    #
    # PHYSISCHER GUARD: nur wenn der spätere Sektor am selben Airport STARTET, an
    # dem der frühere ANKOMMT (arr == nächster dep) — dann ist die Kette zwingend
    # (dieselbe Person/Maschine musste erst landen). Sonst Regel NICHT anwenden.
    #
    # KEINE erfundene Ist-Zeit: nur `status='landed'`, est_arr bleibt wie es ist
    # (leer wenn unbeobachtet). Cancelled wird NIE gelandet. Der frühere Sektor
    # muss aktuell in einem NICHT-terminalen Bucket hängen (airborne/grounded/None).
    #
    # NACH dem Engine-Override (dieser Block läuft nach der GESAMTEN Enrichment-
    # Schleife, wenn jeder Sektor seinen finalen `status`/`est_dep_iso` hat) → kein
    # Engine-Block dreht die Ketten-Landung mehr zurück. Es wird KEIN Extra-Key an
    # den Sektor gehängt (Golden-/Byte-Kompatibilität), nur `status='landed'`.
    try:
        def _dep_instant(_sec):
            # frühester ECHTER Ist-Abflug (est_dep_iso, schon UTC) vor Plan-dep_iso;
            # als UTC-datetime zum Vergleich der Reihenfolge (nicht Listen-Index —
            # Über-Mitternacht-Sicherheit).
            for _c in (_sec.get('est_dep_iso'), _sec.get('dep_iso')):
                if not _c:
                    continue
                try:
                    _d = datetime.fromisoformat(str(_c).replace('Z', '+00:00'))
                    if _d.tzinfo is None:
                        _d = _d.replace(tzinfo=timezone.utc)
                    return _d
                except Exception:
                    continue
            return None

        def _observed_departed(_sec):
            # ECHTER Abflug-Beweis: Status-Bucket airborne/landed ODER beobachtete
            # est_dep_iso in der Vergangenheit. NICHT: bloß Planzeit vorbei.
            _b = _flight_status_bucket(_sec.get('status'))
            if _b in ('airborne', 'landed'):
                return True
            _ed = _sec.get('est_dep_iso')
            if _ed:
                try:
                    _d = datetime.fromisoformat(str(_ed).replace('Z', '+00:00'))
                    if _d.tzinfo is None:
                        _d = _d.replace(tzinfo=timezone.utc)
                    if _d <= now:
                        return True
                except Exception:
                    pass
            return False

        # Sektoren mit gültigem dep-Instant chronologisch (dep-Instant, nicht Index).
        _ordered = []
        for _sec in sectors:
            if not isinstance(_sec, dict):
                continue
            _di = _dep_instant(_sec)
            if _di is not None:
                _ordered.append((_di, _sec))
        _ordered.sort(key=lambda p: p[0])
        for _i, (_di, _sec) in enumerate(_ordered):
            if _sec.get('cancelled'):
                continue
            _bucket = _flight_status_bucket(_sec.get('status'))
            if _bucket == 'landed':
                continue        # schon terminal
            if _bucket not in ('airborne', 'grounded', None):
                continue
            _arr = str(_sec.get('to') or '').strip().upper()
            if len(_arr) != 3 or not _arr.isalpha():
                continue
            # ein SPÄTERER Sektor (dep-Instant > dieser), der am selben Airport
            # startet UND nachweislich abgeflogen ist → Landung dieses Sektors.
            for _dj, _later in _ordered[_i + 1:]:
                if _dj <= _di:
                    continue
                _ldep = str(_later.get('from') or '').strip().upper()
                if _ldep != _arr:
                    continue        # physischer Guard: arr == nächster dep
                if _observed_departed(_later):
                    _sec['status'] = 'landed'
                    break
    except Exception:
        pass        # Ketten-Regel best-effort, nie werfend
    # Rückflug-Turnaround erbt den Tail — mit ECHTER Homebase, wo der Caller sie
    # kennt (Audit 2026-07-05: Proxy allein ließ am Rückreisetag einen Homebase-
    # Hub-Turnaround durch, vom Owner explizit verboten).
    _carry_forward_turnaround_tails(sectors, homebase=homebase)
    return sectors


# ── Ausgemusterte-Tails-Wächter (Owner-Screenshot 2026-07-12 17:43) ──────────
# Root-Cause: der Fraport-Feed (und damit airport_delay_obs/`flights`) liefert
# für manche Langstrecken-Flugnummern MUSEUMS-Regs (LH780→D-ABVU, LH781→D-ABTL,
# beides seit Jahren ausgemusterte 747-400) — die Board-Quelle selbst ist die
# Altlast, nicht unser Merge. Ein Tail wird darum NUR noch attached/ausgeliefert,
# wenn die Reg in den letzten 60 Tagen WIRKLICH FLIEGEND gesehen wurde
# (aircraft_live ODER aircraft_track, beide reg-normalisiert A-Z0-9). Sonst
# ehrlich KEIN Tail statt Museums-Flieger.
_TAIL_ACTIVE_CACHE = {}          # reg_norm -> (expires_ts, bool)
_TAIL_ACTIVE_TTL = 24 * 3600     # POSITIVES Verdikt: 24 h pro Reg
# NEGATIVE Verdikte nur KURZ cachen (Regressions-Sweep 2026-07-12 #14): kein
# Schreibpfad (NAS-Harvester, observe_adsb_breadcrumbs, observed-track)
# invalidiert diesen Cache — eine Reg, die nach >60 Tagen Pause WIEDER fliegt
# (C-Check-Rückkehr, Neuauslieferung, Wet-Lease), blieb sonst bis zu 24 h
# app-weit unterdrückt, obwohl sie längst in aircraft_live steht (Radar
# zeigte sie, Detail/Kalender versteckten sie). 30 min → das legitime
# Nein→Ja heilt binnen einer halben Stunde; echte Museums-Regs kosten
# weiterhin nur eine billige EXISTS-Query pro halber Stunde.
_TAIL_ACTIVE_NEG_TTL = 1800
_TAIL_ACTIVE_ERR_TTL = 300       # Query-Fehler: 5 min nicht erneut hämmern
_TAIL_ACTIVE_WINDOW_DAYS = 60


def _tail_recently_active(reg):
    """True, wenn die Reg in den letzten 60 Tagen in `aircraft_live` ODER
    `aircraft_track` gesehen wurde (billige EXISTS-Query, in-process gecacht
    pro Reg: True 24 h, False nur 30 min — s. _TAIL_ACTIVE_NEG_TTL).

    FAIL-OPEN bei Nicht-Verifizierbarkeit (SB down/Tabelle fehlt/Query-Fehler):
    dann True zurückgeben, damit ein Infrastruktur-Schluckauf nicht ALLE Tails
    app-weit wegräumt — der Wächter richtet sich gegen die systematische
    Altquelle, nicht gegen transiente DB-Fehler. Leere Reg → False. Wirft nie."""
    import time as _t
    rn = str(reg or '').replace('-', '').replace(' ', '').upper().strip()
    if not rn or not rn.isalnum():
        return False
    now = _t.time()
    hit = _TAIL_ACTIVE_CACHE.get(rn)
    if hit and now < hit[0]:
        return hit[1]
    if not SB_AVAILABLE or sb is None:
        return True                     # nicht verifizierbar → fail-open (nicht cachen)
    cutoff = datetime.now(timezone.utc) - timedelta(days=_TAIL_ACTIVE_WINDOW_DAYS)
    cutoff_iso = cutoff.strftime('%Y-%m-%dT%H:%M:%SZ')
    try:
        r = (sb.table('aircraft_live').select('reg')
             .eq('reg', rn).gt('updated_at', cutoff_iso).limit(1).execute())
        ok = bool(getattr(r, 'data', None))
        if not ok:
            r = (sb.table('aircraft_track').select('reg')
                 .eq('reg', rn).gte('seen_ts', cutoff_iso).limit(1).execute())
            ok = bool(getattr(r, 'data', None))
        _TAIL_ACTIVE_CACHE[rn] = (
            now + (_TAIL_ACTIVE_TTL if ok else _TAIL_ACTIVE_NEG_TTL), ok)
        _cache_soft_cap(_TAIL_ACTIVE_CACHE, max_items=2000, drop=500)
        return ok
    except Exception:
        # Fehler kurz negativ-TTL'en (nur gegen Hämmern), Antwort fail-open.
        _TAIL_ACTIVE_CACHE[rn] = (now + _TAIL_ACTIVE_ERR_TTL, True)
        return True


def _leg_tail(flight_no, date=None, dep_iata=None, arr_iata=None):
    """Flugzeug-Kennzeichen (`reg`/Tail) EINES Legs — NUR aus echten Board-/
    Warehouse-Beobachtungen, sonst None.

    DOMÄNENREGEL (hart): NIE einen Tail raten. Keine Flugnummer↔Callsign-
    Zahlengleichheit, kein Fallback-Kennzeichen, kein „ähnlicher" Tail. Ohne
    echten Treffer → None, und der Aufrufer lässt das Feld weg.

    Nutzt `_flight_obs_merged(..., free_only=True)` — denselben ~90 s-Memo wie
    die übrigen Board-Reads, also KEIN AeroDataBox-Spend; der Fan-out über viele
    Legs/Freunde bleibt billig (O(1) je (fn,date,dep,arr)). Flugnummer via
    `_fn_norm` normalisiert (LH0839 == LH839) und — wo bekannt — Codeshare→
    Operating gefaltet, damit der PHYSISCHE Flug (der den Tail trägt) matcht.
    Wirft nie."""
    try:
        fn = _fn_norm(flight_no)
    except Exception:
        fn = None
    if not fn or len(fn) < 3:
        return None
    try:
        cs_map = _ax_codeshare_map() or {}
    except Exception:
        cs_map = {}
    op_fn = cs_map.get(fn, fn)
    frm = (str(dep_iata or '').strip().upper() or None)
    to = (str(arr_iata or '').strip().upper() or None)
    d = (str(date or '')[:10] or None)
    try:
        m = _flight_obs_merged(op_fn, date=d, dep_iata=frm, arr_iata=to,
                               live=True, free_only=True)
    except Exception:
        m = None
    if not m:
        return None
    reg = m.get('reg')
    if isinstance(reg, str):
        reg = reg.strip()
    if not reg:
        return None
    # Ausgemusterte-Tails-Wächter: Board-Quellen (Fraport) liefern für manche
    # Flugnummern historische Regs (LH780→D-ABVU, retired 744). Nur ausliefern,
    # wenn die Reg in den letzten 60 Tagen wirklich fliegend gesehen wurde.
    if not _tail_recently_active(reg):
        return None
    return reg


def _enrich_leg_tails(sectors, date=None, homebase=None):
    """Ergänzt pro Leg (ical_sectors[]) ein optionales `tail` (Flugzeug-
    Kennzeichen) NUR bei echtem Board/Warehouse-Treffer — additiv, nie erfunden,
    nie werfen. `homebase` = echte Profil-Homebase des ROSTER-BESITZERS für die
    Turnaround-Weitergabe (Audit 2026-07-05, s. _carry_forward_turnaround_tails).

    Für die FREUNDE-/FAMILIEN-Roster-Sheets, die NICHT durch `_enrich_leg_delays`
    laufen (im eigenen Roster setzt die Delay-Anreicherung `tail` bereits mit —
    dort wird `_enrich_leg_tails` NICHT gebraucht). Respektiert einen schon
    gesetzten Tail (kein Doppel-Fetch). Gleicher grober Zeitfenster-Guard wie
    `_enrich_leg_delays` (dep_iso −30h..+27h, sonst Datum today ±1), damit tiefe
    Zukunfts-/Vergangenheits-Legs KEINE Board-Scans auslösen. Gibt dieselbe Liste
    zurück (in-place mutiert). Wirft nie."""
    if not sectors or not isinstance(sectors, list):
        return sectors
    # „BOARD SCHLÄGT INFERENZ" (Owner 2026-07-09): abgeleitete (`tail_inferred`)
    # Tails vor der Neu-Anreicherung wegwerfen, damit ein echter Board-Treffer sie
    # überschreibt und der Skip-auf-vorhandenen-Tail unten NUR direkt gemessene
    # Tails schont — nie eine veraltete Inferenz. Carry-Forward setzt sie frisch.
    _strip_inferred_tails(sectors)
    now = datetime.now(timezone.utc)
    for s in sectors:
        if not isinstance(s, dict) or s.get('tail'):
            continue
        raw_fn = str(s.get('flight') or '').strip()
        frm = str(s.get('from') or '').strip().upper()
        to = str(s.get('to') or '').strip().upper()
        if len(raw_fn) < 3 or len(frm) != 3 or not frm.isalpha() \
                or len(to) != 3 or not to.isalpha():
            continue
        # ── Zeitfenster-Guard (spiegelt _enrich_leg_delays) ──────────────────
        dep_dt = None
        try:
            dr = s.get('dep_iso')
            if dr:
                dep_dt = datetime.fromisoformat(str(dr).replace('Z', '+00:00'))
                if dep_dt.tzinfo is None:
                    dep_dt = dep_dt.replace(tzinfo=timezone.utc)
        except Exception:
            dep_dt = None
        leg_date = None
        if dep_dt is not None:
            if dep_dt > now + timedelta(hours=27):
                continue        # tiefe Zukunft: kein Board-Scan
            if dep_dt < now - timedelta(hours=30):
                continue        # tiefe Vergangenheit: kein SB-Read
            try:
                leg_date = dep_dt.strftime('%Y-%m-%d')
            except Exception:
                leg_date = None
        else:
            try:
                from datetime import date as _dt_date
                _draw = str(s.get('date') or date or '')[:10]
                d0 = _dt_date.fromisoformat(_draw)
                today = now.date()
                if d0 > today + timedelta(days=1):
                    continue        # tiefe Zukunft (grob)
                if d0 < today - timedelta(days=1):
                    continue        # tiefe Vergangenheit (grob)
            except Exception:
                pass        # kein parsbares Datum → wie bisher weiter (nie werfen)
        leg_date = leg_date or (str(s.get('date') or date or '')[:10] or None)
        tail = _leg_tail(raw_fn, date=leg_date, dep_iata=frm, arr_iata=to)
        if tail:
            s['tail'] = tail
    _carry_forward_turnaround_tails(sectors, homebase=homebase)
    return sectors


def _strip_inferred_tails(sectors):
    """Verwirft pro-Leg NUR die per Turnaround ABGELEITETEN Tails (`tail_inferred`),
    damit die Neu-Anreicherung eine echte Board-Beobachtung darüber setzen kann und
    keine veraltete Inferenz kleben bleibt (Owner 2026-07-09: „wenn falsch, überstimmt
    das Board"). Direkt gemessene Tails bleiben. In-place; wirft nie."""
    try:
        if not sectors or not isinstance(sectors, list):
            return sectors
        for s in sectors:
            if isinstance(s, dict) and s.get('tail_inferred'):
                s.pop('tail', None)
                s.pop('tail_inferred', None)
    except Exception:
        pass
    return sectors


def _carry_forward_turnaround_tails(sectors, homebase=None):
    """Turnaround-Weitergabe (Owner: „Tails auf jedem Leg", präzisiert 2026-07-04).

    Der „PHYSISCH dieselbe Maschine"-Schluss gilt NUR beim echten OUTSTATION-
    Turnaround — dem Rückflug ZUR Homebase (Owner: „gleiche Maschine geht nur auf
    dem return zur homebase … bei 3h turnaround IN der homebase kann man sehr wohl
    Flieger wechseln"). Am Homebase-Hub rotieren die Maschinen durch; selbst 3-4h
    Bodenzeit reichen für einen Fliegerwechsel → dort NIE weitergeben.

    Ein Rückleg erbt den beobachteten Tail des Vorlegs also nur, wenn ALLE gelten:
      • Vorleg hat belegten Tail, dieses Leg hat (noch) keinen
      • kontinuierlich: `cur.from == prev.to` (Umsteige-Airport identisch)
      • RAUS-&-ZURÜCK: `cur.to == prev.from` (echtes Return-Leg, kein Hub-Weiterflug)
      • Turnaround-Airport `cur.from` ist NICHT die Homebase
        (Homebase = übergeben, sonst Duty-Origin `sectors[0].from` als Proxy)
      • Bodenzeit 0…4h (Übernacht-Layover / Aircraft-Swap bricht die Kette)
    Sonst bleibt das Leg tail-los = ehrlich. In-place; wirft nie."""
    try:
        if not sectors or not isinstance(sectors, list):
            return sectors
        # Homebase: expliziter Wert oder Duty-Origin (erstes Leg) als Proxy.
        hb = str(homebase or '').strip().upper()
        if len(hb) != 3:
            hb = ''
            for s0 in sectors:
                if isinstance(s0, dict):
                    f0 = str(s0.get('from') or '').strip().upper()
                    if len(f0) == 3 and f0.isalpha():
                        hb = f0
                        break
        for i in range(1, len(sectors)):
            cur, prev = sectors[i], sectors[i - 1]
            if not isinstance(cur, dict) or not isinstance(prev, dict):
                continue
            if cur.get('tail') or not prev.get('tail'):
                continue
            prev_to = str(prev.get('to') or '').strip().upper()
            prev_from = str(prev.get('from') or '').strip().upper()
            cur_from = str(cur.get('from') or '').strip().upper()
            cur_to = str(cur.get('to') or '').strip().upper()
            if len(cur_from) != 3 or prev_to != cur_from:
                continue                      # nicht kontinuierlich → keine Weitergabe
            if len(cur_to) != 3 or cur_to != prev_from:
                continue                      # kein Raus-&-Zurück → kein sicherer Turnaround
            if hb and cur_from == hb:
                continue                      # Turnaround AN der Homebase → Hub-Rotation, Flieger wechselt
            pa, cd = prev.get('arr_iso'), cur.get('dep_iso')
            if not pa or not cd:
                continue                      # ohne Zeiten kein sicherer Turnaround
            try:
                pad = datetime.fromisoformat(str(pa).replace('Z', '+00:00'))
                cdd = datetime.fromisoformat(str(cd).replace('Z', '+00:00'))
                gap_h = (cdd - pad).total_seconds() / 3600.0
            except Exception:
                continue
            if gap_h < 0 or gap_h > 4:
                continue                      # Übernacht/lang → nicht dieselbe Maschine
            cur['tail'] = prev['tail']
            cur['tail_inferred'] = True       # aus Outstation-Turnaround abgeleitet (nicht direkt beobachtet)
    except Exception:
        pass
    return sectors


def _cached_board_rows(iata, ftype):
    """Board-Zeilen NUR aus dem bereits gefüllten In-Memory-Cache — löst KEINEN
    Fetch aus (Null-Kosten-Lookup fürs Cross-Side-Tafel-Enrich). None wenn für
    diesen Flughafen (noch) nichts Frisches gecacht ist."""
    import time as _t
    ap = (iata or '').upper().strip()
    ap = _DE_ICAO_TO_IATA.get(ap, ap)
    if ap in ('FRA', 'EDDF'):
        c = _AIRPORT_BOARD_CACHE.get('FRA_' + ('arr' if ftype == 'arrival' else 'dep'))
        if c and (_t.time() - c[0]) < _AIRPORT_BOARD_TTL:
            return c[1]
        c = _AIRPORT_DAY_CACHE.get('FRA_DAY_' + ('arr' if ftype == 'arrival' else 'dep'))
        if c and (_t.time() - c[0]) < _AIRPORT_DAY_TTL:
            return c[1]
        return None
    c = _NATIVE_BOARD_CACHE.get((ap, 'arrival' if ftype == 'arrival' else 'departure'))
    if c and (_t.time() - c[0]) < _NATIVE_BOARD_TTL:
        return (c[1] or (None, None))[0]
    return None


def _board_cross_side_enrich(rows, ftype):
    """Tafel-Zeilen mit der GEGENSEITE anreichern (Owner-Direktive 2026-07-03) —
    ausschließlich aus BEREITS GECACHTEN Boards (kein Fetch, kein Spend, der
    Poller hält die deutschen Boards ohnehin warm): eine Abflug-Zeile bekommt
    Ankunfts-Delay/-Status/-Esti/-Gate ihres Ziels (arr_*-Felder), eine
    Ankunfts-Zeile den Abflug-Delay ihres Origins (dep_*-Felder). Tail/Typ
    werden GEFÜLLT, wenn nur die Gegenseite sie kennt (NUE-Arrivals tragen
    Tails); cancelled wird ge-OR-t. Gibt KOPIEN zurück (Cache-Zeilen bleiben
    unangetastet). Additiv & ehrlich: Felder fehlen einfach, wenn die
    Gegenseite gerade nicht gecacht ist."""
    other_ft = 'departure' if ftype == 'arrival' else 'arrival'
    prefix = 'dep_' if ftype == 'arrival' else 'arr_'
    idx_cache = {}
    out = []
    for f in (rows or []):
        f = dict(f)
        out.append(f)
        other_ap = (f.get('dest_iata') or '').upper().strip()
        fn = (f.get('flight') or '').replace(' ', '').upper()
        if len(other_ap) != 3 or not fn:
            continue
        if other_ap not in idx_cache:
            idx = {}
            for r in (_cached_board_rows(other_ap, other_ft) or []):
                k = (r.get('flight') or '').replace(' ', '').upper()
                if k and k not in idx:
                    idx[k] = r
            idx_cache[other_ap] = idx
        o = idx_cache[other_ap].get(fn)
        if not o:
            continue
        try:
            f[prefix + 'delay_min'] = int(o.get('delay_min') or 0)
        except Exception:
            f[prefix + 'delay_min'] = 0
        f[prefix + 'status'] = (o.get('status') or '') or None
        f[prefix + 'esti'] = o.get('esti') or None
        f[prefix + 'gate'] = (o.get('gate') or '').strip() or None
        if o.get('cancelled') and not f.get('cancelled'):
            f['cancelled'] = True
        if not f.get('reg') and o.get('reg'):
            f['reg'] = o.get('reg')
            if not f.get('aircraft') and o.get('aircraft'):
                f['aircraft'] = o.get('aircraft')
    return out


@app.route('/api/ax/flight-info/<flightno>', methods=['GET'])
def ax_flight_info(flightno):
    """Flugnummer → Strecke/Gate/Terminal/Status/TAIL — ZUERST GRATIS aus der self-
    growing `airport_delay_obs`-DB (Board-Poll-Historie: abgeflogene Flüge mit
    origin/dest/gate/reg/type). Findet die Historie keinen Tail (oder der Flug ist
    HEUTE/künftig → noch nicht abgeflogen), wird der LIVE-Board-Feed des Abflug-
    Flughafens (`?airport=`, Default FRA) als Fallback gescannt — so trägt der
    eigene bevorstehende Umlauf seinen bereits zugeteilten Tail. `found:false` nur,
    wenn weder Historie noch Live-Feed etwas haben → Client holt /api/flight-times
    (AeroDataBox) on-tap. Nur GRATIS-Quellen, gecacht."""
    fn = (flightno or '').upper().replace(' ', '').strip()
    if len(fn) < 3:
        return jsonify({'ok': False, 'error': 'bad_flight'}), 400
    board_ap = (request.args.get('airport') or 'FRA').upper().strip()
    # NEU: optionaler `?date=YYYY-MM-DD` → Tail/Ist-Zeit/Delay für EINEN konkreten
    # Flugtag (statt nur der jüngsten Beobachtung). Der Kalender braucht das, um pro
    # Leg den echten Tail + Delay genau dieses Datums zu zeigen (gratis aus dem
    # Warehouse, keine bezahlte API).
    date_param = (request.args.get('date') or '').strip()
    out = None        # Historien-Ergebnis (falls vorhanden)
    if SB_AVAILABLE and sb is not None:
        try:
            q = sb.table('airport_delay_obs').select('*').eq('flight', fn)
            if date_param:
                q = q.eq('date', date_param)
            r = (q.order('date', desc=True).order('updated_at', desc=True)
                 .limit(60).execute())
            rows = r.data or []
            # ABFLUG-Record bevorzugen: dort ist `airport` = Origin + `dest_iata` =
            # Ziel (korrekte Richtung). Ankunfts-Records ('<AP>#ARR') haben die
            # Richtung gespiegelt → würden Origin/Dest vertauschen. Fallback: erster.
            dep = next((x for x in rows if '#' not in (x.get('airport') or '')), None)
            if rows:
                o = dep or rows[0]
                o = dict(o)
                # „Unbekannt ≠ Pünktlich" (LH400): max_delay_min 0 ohne jedes
                # Signal (kein esti, kein IST-Status) heißt NICHT pünktlich —
                # dann delay_min: null, iOS zeigt neutral statt „Pünktlich".
                obs_is_arr = '#' in (o.get('airport') or '')
                obs_known = _obs_delay_known(
                    o.get('max_delay_min'), o.get('cancelled'),
                    o.get('esti'), o.get('status'), obs_is_arr)
                o['airport'] = (o.get('airport') or '').split('#', 1)[0]   # Store-Key säubern
                if obs_is_arr:
                    # RICHTUNGS-FIX 2026-07-05 (LH1455/LH919): gibt es NUR eine
                    # Ankunfts-Row ('<AP>#ARR'), ist `airport` das ZIEL und
                    # `dest_iata` die HERKUNFT — ohne Entspiegelung stünde
                    # origin/dest vertauscht (LH1455 TIA→FRA wurde als „FRA→TIA"
                    # serviert und der Dual-Side-Resolver suchte an den falschen
                    # Flughäfen). dest_name der ARR-Row ist der HERKUNFTS-Name →
                    # nicht als Ziel-Name ausgeben (ehrlich None statt falsch).
                    _arr_ap = o.get('airport')
                    o['airport'] = (o.get('dest_iata') or '').strip() or None
                    o['dest_iata'] = _arr_ap
                    o['dest_name'] = None
                # Letzte beobachtete Maschine: jüngster Record mit reg/type.
                ac_row = next((x for x in rows if (x.get('reg') or x.get('type_code'))), None)
                # Tail-Historie über die letzten Tage (dedupe nach reg, jüngste zuerst).
                seen_reg = set(); regs = []
                for x in rows:
                    rg = (x.get('reg') or '').strip().upper()
                    if rg and rg not in seen_reg:
                        seen_reg.add(rg)
                        regs.append({'reg': rg, 'type': x.get('type_code'),
                                     'date': x.get('date')})
                out = {
                    'ok': True, 'found': True, 'flight': fn, 'source': 'aerox_obs',
                    'origin': o.get('airport'), 'dest': o.get('dest_iata'),
                    'dest_name': o.get('dest_name'), 'airline': o.get('airline'),
                    'gate': o.get('gate'), 'terminal': o.get('terminal'),
                    'status': o.get('status'), 'sched': o.get('sched'),
                    'esti': o.get('esti'),
                    'delay_min': (o.get('max_delay_min') if obs_known else None),
                    'delay_known': obs_known,
                    'cancelled': o.get('cancelled'), 'date': o.get('date'),
                    'reg': (ac_row or {}).get('reg'),
                    'type': (ac_row or {}).get('type_code'),
                    'recent_regs': regs[:8], 'observations': len(rows),
                }
                # WRONG-DAY-PHYSIK-GATE für die freie Zeiten-Kette (Owner/Fable
                # 2026-07-15, LH423 BOS→FRA): fragt der Client EIN Datum + den
                # ABFLUG-Flughafen (`?date=&airport=BOS`) und es existiert für
                # diesen Tag NUR eine ARR-Seite (BOS ist nicht geharvestet → keine
                # DEP-Row) desselben täglichen Fluges, dann ist diese Ankunft die
                # in FRA gelandete GESTRIGE Rotation (Über-Nacht-Leg: das heutige
                # LH423 startet erst abends und landet am 16.). Ihr `esti/status`
                # (07:44 „Gelandet") als HEUTIGE Ist-Zeit auszuliefern ist derselbe
                # Fremd-Tag-Fehler wie im crew_state. Physik-Prüfung über die EINE
                # datums-disziplinierte Quelle _flight_facts_from_obs (dieselbe wie
                # Radar/Detail): findet sie für DIESEN Abflugtag KEINE gültige, zum
                # Abflug passende Ankunft, sind die operativen Ist-Felder foreign-day
                # → scrubben (Strecke/Tail/recent_regs = ehrliche Identität bleiben),
                # der Live-Board-/free-first-Pfad unten füllt die echte Abendabfahrt.
                # NUR wenn der Abflug-Flughafen bewusst benannt wurde (nicht Default
                # FRA) und die Query genau diesen Tag adressiert (kein Über-Scrub der
                # gleichtägigen Innereuropa-Legs mit vorhandener DEP-Row).
                if (date_param and obs_is_arr and dep is None
                        and (request.args.get('airport') or '').strip()
                        and (o.get('airport') or '').upper() == board_ap):
                    try:
                        from blueprints.aerox_data_blueprint import _flight_facts_from_obs as _ff_gate
                        _gate_facts = _ff_gate(fn, date_param, board_ap,
                                               o.get('dest_iata'))
                    except Exception:
                        _gate_facts = None
                    # Keine physikalisch zum Abflug gepaarte Ankunft für DIESEN Tag
                    # (leer, stale-Fallback, oder ohne Ist/Soll-Ankunft) ⇒ die im
                    # Top-Block gewählte ARR-Row gehört zur Fremd-Rotation.
                    if (not _gate_facts or _gate_facts.get('stale')
                            or not (_gate_facts.get('est_arr')
                                    or _gate_facts.get('sched_arr'))):
                        # `date`/`obs_date` bleiben der ehrliche Beobachtungstag der
                        # ARR-Row (= date_param, weil die Ankunft am Ziel nach dem
                        # lokalen Ankunftstag archiviert wird). Der iOS-stale-Gate
                        # (obs_date==date) hängt daran — nicht verfälschen. Wir
                        # verwerfen nur die OPERATIVEN Ist-Felder der Fremd-Rotation
                        # und markieren den Grund transparent.
                        out['foreign_day_arr'] = True
                        for _k in ('status', 'esti', 'sched', 'gate', 'terminal',
                                   'delay_min', 'cancelled'):
                            out[_k] = None
                        out['delay_known'] = False
        except Exception as e:
            app.logger.warning(f'[flight-info] obs_fail {str(e)[:120]}')
    # FRISCHE-CHECK (Bug-Fix Flight-Check-up 2026-07-02): die Board-Historie ist pro
    # Flugnummer keyed und liefert die JÜNGSTE Beobachtung — auch wenn ihr Tag ALT ist.
    # Operative "heute"-Felder (Status/Erwartet/Gate/Delay/Tail) eines VERGANGENEN
    # Betriebstags dürfen NICHT als "heute live" durchgereicht werden. Beobachtet:
    #   • LH327 zeigte gestern's ERWARTET 16:00 < Plan 16:10 (verspätet, aber früher!)
    #   • LH326 hing 3 Tage auf Status "Boarding" (ADS-B war längst wieder am Boden)
    #   • Muster/Tail vom falschen Tag (DAISC/A321 statt heutigem DAIZD/A320)
    # Bei explizitem ?date= (Kalender fragt genau diesen Tag) gilt die Frische-Regel NICHT.
    obs_date = (out.get('date') if (out and str(out.get('source') or '').startswith('aerox_obs'))
                else None)
    try:
        today_local = _airport_local_now((out or {}).get('origin') or board_ap).strftime('%Y-%m-%d')
    except Exception:
        today_local = None
    stale = bool(obs_date and today_local and obs_date != today_local and not date_param)

    # LIVE-ENRICH: kein Tail aus der Historie (oder gar kein Treffer) ODER die Historie
    # ist von einem alten Tag (stale) → Live-Board des Abflug-Flughafens scannen. So
    # bekommt ein HEUTE/künftig abfliegender Flug seinen bereits zugeteilten Tail +
    # frische Zeiten/Status, die die (nur-abgeflogen-)Historie nie hätte.
    if out is None or not out.get('reg') or stale:
        try:
            bf = _flight_from_live_board(board_ap, fn)
        except Exception:
            bf = None
        if bf is not None:
            arr = bf.get('_arr')
            b_reg = (bf.get('reg') or '').strip().upper() or None
            b_type = (bf.get('aircraft') or '').strip() or None
            if out is None:
                # Origin/Dest richtungsrichtig: Abflug-Board → origin=board_ap;
                # Ankunfts-Board → der Flug kommt VON dest_iata, geht NACH board_ap.
                origin = (bf.get('dest_iata') if arr else board_ap)
                dest = (board_ap if arr else bf.get('dest_iata'))
                out = {
                    'ok': True, 'found': True, 'flight': fn, 'source': 'live_board',
                    'origin': origin, 'dest': dest,
                    'dest_name': bf.get('dest_name'), 'airline': bf.get('airline'),
                    'gate': bf.get('gate'), 'terminal': bf.get('terminal'),
                    'status': bf.get('status'), 'sched': bf.get('sched'),
                    'esti': bf.get('esti'), 'delay_min': bf.get('delay_min'),
                    'cancelled': bf.get('cancelled'), 'date': (bf.get('sched') or '')[:10] or None,
                    'reg': b_reg, 'type': b_type,
                    'recent_regs': ([{'reg': b_reg, 'type': b_type,
                                      'date': (bf.get('sched') or '')[:10]}] if b_reg else []),
                    'observations': 0,
                }
                stale = False
            elif stale:
                # Historie war von einem alten Tag, aber das Live-Board hat den
                # HEUTIGEN Umlauf → das Board ist die Wahrheit für alle operativen
                # Felder. Strecke/recent_regs (Identität/Historie) bleiben erhalten.
                out['date'] = (bf.get('sched') or '')[:10] or out.get('date')
                out['sched'] = bf.get('sched') or out.get('sched')
                out['esti'] = bf.get('esti')
                out['status'] = bf.get('status')
                out['delay_min'] = bf.get('delay_min')
                out['cancelled'] = bf.get('cancelled')
                out['gate'] = bf.get('gate') or None
                out['terminal'] = bf.get('terminal') or None
                if b_reg:
                    out['reg'] = b_reg
                    out['type'] = b_type or out.get('type')
                out['source'] = 'aerox_obs+live'
                stale = False
            else:
                # Historie hatte Strecke/Gate, aber keinen Tail → nur Tail/Typ + frische
                # Live-Zeiten ergänzen, Quelle markieren.
                if b_reg:
                    out['reg'] = b_reg
                    if b_type and not out.get('type'):
                        out['type'] = b_type
                    out['source'] = 'aerox_obs+live'
                    if not out.get('recent_regs'):
                        out['recent_regs'] = [{'reg': b_reg, 'type': b_type,
                                               'date': (bf.get('sched') or '')[:10]}]
                if bf.get('gate') and not out.get('gate'):
                    out['gate'] = bf.get('gate')
                if bf.get('esti'):
                    out['esti'] = bf.get('esti')

    # Immer noch stale (Live-Board hatte den heutigen Umlauf nicht — z.B. Flug ist
    # heute schon abgeflogen und aus dem now→+27h-Fenster raus): die operativen
    # "heute"-Felder eines vergangenen Tages NICHT als live ausgeben. Strecke +
    # recent_regs (mit Datum) bleiben als ehrliche Identität/Historie erhalten.
    if out is not None and stale:
        out['stale'] = True
        out['obs_date'] = obs_date
        for _k in ('status', 'esti', 'delay_min', 'cancelled', 'gate', 'terminal', 'sched'):
            out[_k] = None
        out['reg'] = None
        out['type'] = None

    # ANKUNFTS-GATE/-TERMINAL (Flight-Check-up 2026-07-02, User: „kein Ankunfts-Gate"):
    # der Abflug-Board-Scan liefert nur Abflug-Gate/-Terminal. Das Ankunfts-Gate steht
    # auf der ANKUNFTSTAFEL des Ziels → dort nachschlagen und als NEUE Felder ergänzen
    # (arr_gate/arr_terminal), rückwärtskompatibel (alte Clients ignorieren sie). Nur
    # für frische (nicht-stale) Ergebnisse mit bekanntem Ziel — ein alter Betriebstag
    # bekäme sonst das heutige Ankunfts-Gate eines fremden Umlaufs.
    if out is not None and not stale and out.get('dest'):
        try:
            arr_g, arr_t = _arrival_gate_terminal(out.get('dest'), fn)
        except Exception:
            arr_g, arr_t = (None, None)
        out['arr_gate'] = arr_g
        out['arr_terminal'] = arr_t

    # DUAL-SIDE (Owner-Direktive 2026-07-03): beide Seiten über den zentralen
    # Resolver einbeziehen — die arr-Seite (Ankunfts-Board/-Warehouse am Ziel)
    # liefert den ANKUNFTS-Delay, Ankunfts-Status/-Zeiten und ggf. den Tail, den
    # das dep-Board nicht kennt (NUE-Arrivals tragen Tails). Rein ADDITIVE Felder
    # (dep_delay_min/arr_delay_min/sched_arr/esti_arr/arr_status/arr_cancelled/
    # obs_sides/delay_side) — bestehende Felder bleiben für iOS unverändert; nur
    # leere reg/arr_gate/cancelled werden mit ehrlicheren Werten GEFÜLLT.
    if out is not None and not out.get('stale'):
        try:
            merged = _flight_obs_merged(fn, date=(date_param or None),
                                        dep_iata=(out.get('origin') or board_ap),
                                        arr_iata=out.get('dest'))
        except Exception:
            merged = None
        if merged:
            out['dep_delay_min'] = merged.get('dep_delay_min')
            out['arr_delay_min'] = merged.get('arr_delay_min')
            out['sched_arr'] = merged.get('sched_arr')
            out['esti_arr'] = merged.get('esti_arr')
            out['arr_status'] = merged.get('status_arr')
            out['arr_cancelled'] = merged.get('arr_cancelled')
            out['delay_side'] = merged.get('delay_side')
            out['obs_sides'] = merged.get('sides')
            # Cancelled = OR beider Seiten (nur eine Seite meldet die Streichung).
            if merged.get('cancelled') and not out.get('cancelled'):
                out['cancelled'] = True
            # Tail/Typ von der Seite, die ihn hat (nur FÜLLEN, nie überschreiben).
            if not out.get('reg') and merged.get('reg'):
                out['reg'] = merged.get('reg')
                if not out.get('type') and merged.get('aircraft'):
                    out['type'] = merged.get('aircraft')
            if not out.get('arr_gate') and merged.get('gate_arr'):
                out['arr_gate'] = merged.get('gate_arr')
            if not out.get('arr_terminal') and merged.get('terminal_arr'):
                out['arr_terminal'] = merged.get('terminal_arr')
            if out.get('delay_min') is None and merged.get('dep_delay_min') is not None:
                out['delay_min'] = merged.get('dep_delay_min')
            # SELBSTKONSISTENZ (Owner/Fable 2026-07-15, LH423): hat der Merge eine
            # Fremd-Tages-Instanz erkannt und ihre Ist-Ankunft verworfen
            # (`esti_scrubbed`), dann stammen auch die im Top-Block gesetzten
            # operativen Ist-Felder (esti/status/delay_min) aus derselben Fremd-Row
            # (ARR-only-Query ohne DEP-Seite: `o` = ebendiese Ankunft) → ehrlich
            # leeren, damit der esti/esti_arr-Widerspruch nicht ausgeliefert wird.
            # Nur wenn KEINE eigene Abflug-Ist-Zeit existiert (sonst wäre esti die
            # legitime DEP-Zeit und darf bleiben). Soll/Route/Reg unberührt.
            if (merged.get('esti_scrubbed') and not merged.get('esti_dep')):
                out['foreign_day_arr'] = True
                for _k in ('esti', 'status', 'delay_min'):
                    out[_k] = None
                out['delay_known'] = False
                out['esti_arr'] = None
                out['arr_status'] = None
                out['arr_delay_min'] = None

    # UNIFIED FLIGHT-INFO (P5): die ANKUNFTSZEIT aus der geteilten Obs-Quelle
    # (`<Ziel>#ARR`-Row) nachziehen, falls oben nicht gesetzt — so trägt der
    # Dienstplan (axFlightInfo) UND das Detail-Aggregat (info) die echte Landezeit
    # (sched_arr/esti_arr), nicht nur die Abflugseite. Dieselbe Merge-Funktion wie
    # Radar/Detail (_flight_facts_from_obs) → EINE Quelle. Nur füllen, nie überschreiben.
    # NICHT bei stale-gescrubbten Antworten (gleiches Gate wie der Dual-Side-Merge
    # oben) — sonst käme die Geister-Ankunft durch die Hintertür zurück.
    if out is not None and out.get('found') and not out.get('stale'):
        try:
            from blueprints.aerox_data_blueprint import _flight_facts_from_obs
            _ff = _flight_facts_from_obs(fn, out.get('date') or date_param)
            # facts['stale'] = Vortags-Fallback der Obs-Quelle → gestrige Geister-
            # Ankunft NICHT durch die Hintertür füllen (gleiches Gate wie oben).
            if _ff and not _ff.get('stale'):
                if not out.get('sched_arr') and _ff.get('sched_arr'):
                    out['sched_arr'] = _ff['sched_arr']
                if not out.get('esti_arr') and _ff.get('est_arr'):
                    out['esti_arr'] = _ff['est_arr']
                if not out.get('arr_status') and _ff.get('arr_status'):
                    out['arr_status'] = _ff['arr_status']
                if out.get('arr_delay_min') is None and _ff.get('arr_delay_min') is not None:
                    out['arr_delay_min'] = _ff['arr_delay_min']
        except Exception:
            pass

    # BEWUSSTER DETAIL-/INFO-FALLBACK: nur authentifiziert + ?paid=1. Listen,
    # Radar-Fan-out und automatische Polls setzen diesen Schalter nie. Bei einem
    # vergangenen/aktiven Flug mit Planzeiten, aber ohne jede operative Zeit,
    # free-first versuchen und erst danach den budgetierten Paid-Tier nutzen.
    if out is not None and out.get('found') and not out.get('stale'):
        try:
            _paid_requested = ((request.args.get('paid') or '').lower()
                               in ('1', 'true', 'yes'))
            _authed = (request.headers.get('Authorization') or '').strip() \
                .lower().startswith('bearer ')
            _svc = (date_param or out.get('date') or '')[:10]
            _status_text = ' '.join(str(x or '').lower() for x in (
                out.get('status'), out.get('arr_status')))
            _active = any(x in _status_text for x in (
                'depart', 'airborn', 'enroute', 'en route', 'land', 'arriv',
                'abgeflogen', 'gestartet', 'gelandet', 'angekommen'))
            _past = bool(_svc and _svc < datetime.now(timezone.utc).strftime('%Y-%m-%d'))
            if (_paid_requested and _authed and (_active or _past)
                    and not (out.get('esti') or out.get('esti_arr'))):
                from blueprints.aerox_data_blueprint import _flight_times_free_first
                _tf = _flight_times_free_first(
                    fn, _svc, out.get('origin'), out.get('dest'),
                    allow_paid=True, require_operational=True)
                for _src, _dst in (('sched_dep', 'sched'), ('est_dep', 'esti'),
                                   ('sched_arr', 'sched_arr'), ('est_arr', 'esti_arr')):
                    if _tf.get(_src) and not out.get(_dst):
                        out[_dst] = _tf[_src]
        except Exception:
            pass

    # STATUS PLAUSIBILITÄTS-/PHYSIK-GATE auch auf der axFlightInfo/DETAIL-Ausgabe
    # (Owner-Screenshot 2026-07-13, LH454 FRA→SFO „gelandet 13:03"): der iOS-
    # Kalender (`TourTimeline.isLanded`) liest bevorzugt `arr_status` (Ankunfts-
    # seite) — die floss hier UNGEGATET aus dem Dual-Side-Board-Merge (Zeile
    # ~30114 `out['arr_status'] = merged['status_arr']`). r116 gatete nur den
    # Kalender-SEKTOR-`status` (_enrich_leg_delays), NICHT diesen Endpoint → ein
    # falscher/früher Ankunfts-Board-Flip „gelandet HH:MM" bei einem 11-h-Lang-
    # streckenflug kam durch die Hintertür zurück. Dieselbe reine Physik-Schranke
    # (gated_leg_status) wie im Sektor-Pfad: ein terminaler 'landed'-Status auf
    # arr_status/status gilt nur, wenn `now` die früheste physikalisch mögliche
    # Ankunft (est_dep + Großkreis / v_max) ODER die Fahrplan-Ankunft (−15 min
    # Slack) erreicht hat; sonst wird er verworfen (None) statt eine erfundene
    # Landung zu behaupten. Nicht-terminale Status laufen unverändert durch;
    # fehlen die Belege → fail-open. Konservativ, additiv, wirft nie.
    if out is not None and not out.get('stale'):
        try:
            from blueprints.leg_status_gate import gated_leg_status as _gate_st
            _o_origin = out.get('origin')
            _o_dest = out.get('dest')
            # eff. Abflug (Epoch): bester Ist (esti) vor Plan (sched), board-lokal
            # → echt-UTC (mit Origin-TZ), dann Epoch. None → sched_arr-Gate allein.
            _o_dep_ts = None
            for _o_dc in (out.get('esti'), out.get('sched')):
                _o_iso = (_board_local_to_utc_iso(_o_dc, _o_origin)
                          if _o_dc else None)
                if _o_iso:
                    try:
                        _o_d = datetime.fromisoformat(
                            str(_o_iso).replace('Z', '+00:00'))
                        if _o_d.tzinfo is None:
                            _o_d = _o_d.replace(tzinfo=timezone.utc)
                        _o_dep_ts = _o_d.timestamp()
                        break
                    except Exception:
                        pass
            _o_dep_ll = _o_arr_ll = None
            try:
                from blueprints.aerox_data_blueprint import _iata_latlon as _o_ll
                _o_dep_ll = _o_ll(_o_origin)
                _o_arr_ll = _o_ll(_o_dest)
            except Exception:
                pass
            _o_sa = (_board_local_to_utc_iso(out.get('sched_arr'), _o_dest)
                     if out.get('sched_arr') else None)
            _o_ea = (_board_local_to_utc_iso(out.get('esti_arr'), _o_dest)
                     if out.get('esti_arr') else None)
            _o_now = time.time()
            for _o_k in ('arr_status', 'status'):
                if out.get(_o_k):
                    out[_o_k] = _gate_st(
                        out[_o_k], now=_o_now, sched_arr_iso=_o_sa,
                        est_arr_iso=_o_ea, dep_ts=_o_dep_ts,
                        dep_ll=_o_dep_ll, arr_ll=_o_arr_ll)
        except Exception:
            pass        # Gate-Fehler → Rohstatus unangetastet (nie brechen)

    # AUSGEMUSTERTE-TAILS-WÄCHTER auch auf der DETAIL-Ausgabe (Owner-Screenshot
    # 2026-07-12 LH781: „MASCHINE DABTL · Boeing 747-400" — die Board-Quelle
    # trägt Museums-Regs, siehe _tail_recently_active). reg/type UND die
    # recent_regs-Historie nur mit Regs ausliefern, die in den letzten 60 Tagen
    # wirklich fliegend gesehen wurden — sonst Feld ehrlich weglassen. Wirft nie
    # (der Wächter selbst ist fail-open bei Infrastruktur-Fehlern).
    if out is not None:
        try:
            if out.get('reg') and not _tail_recently_active(out['reg']):
                out['reg'] = None
                out['type'] = None
            rr = out.get('recent_regs')
            if isinstance(rr, list) and rr:
                out['recent_regs'] = [
                    x for x in rr
                    if isinstance(x, dict)
                    and _tail_recently_active(x.get('reg'))]
        except Exception:
            pass
        # FINALER SELBSTKONSISTENZ-GUARD (Fable 2026-07-15, LH423-Livefall):
        # die Merge-Schichten sehen bei arr-only-Rows z.T. nur HH:MM-Zeiten
        # (kein absoluter Anker → deren Wrong-Day-Scrub fail-open). HIER, an
        # der fertigen Antwort, liegen esti_arr UND sched_arr aber als volle
        # ISO-Instants vor — eine est-Ankunft >6h VOR der eigenen Soll-Ankunft
        # ist physikalisch die fremde Vortages-Instanz ⇒ Ist-Felder ehrlich
        # leeren, Soll/Route/Reg bleiben. Fail-open bei Parse-Problemen.
        try:
            _ea, _sa = out.get('esti_arr'), out.get('sched_arr')
            if isinstance(_ea, str) and isinstance(_sa, str)                     and len(_ea) >= 16 and len(_sa) >= 16:
                _dea = datetime.fromisoformat(_ea.replace('Z', '+00:00'))
                _dsa = datetime.fromisoformat(_sa.replace('Z', '+00:00'))
                if _dea.tzinfo is not None and _dsa.tzinfo is not None                         and (_dsa - _dea).total_seconds() > 6 * 3600:
                    out['foreign_day_arr'] = True
                    for _k in ('esti', 'esti_arr', 'status', 'arr_status'):
                        out[_k] = None
                    out['delay_min'] = None
                    out['arr_delay_min'] = None
                    out['delay_known'] = False
        except Exception:
            pass
        return _public_cache_headers(jsonify(out))
    # Weder Historie noch Live-Feed → Client fällt auf AeroDataBox zurück.
    return jsonify({'ok': True, 'found': False, 'flight': fn, 'source': 'none'})


@app.route('/api/ax/aircraft-history/<reg>', methods=['GET'])
def ax_aircraft_history(reg):
    """Tail-Historie: welche Flüge/Strecken hat eine konkrete Registrierung (z.B.
    D-AIXG) geflogen — GRATIS aus der self-growing `airport_delay_obs`-DB (von den
    Board-Polls aufgebaut, jetzt mit reg/type pro Flug). Liefert die letzten
    Beobachtungen (Datum, Flugnummer, von→nach, Status) + den typischen Typ-Code.
    `found:false` → noch keine Beobachtung dieser Reg in unserer DB. Keine
    Drittanbieter-Calls, kein Spend — nur Aggregation des Vorhandenen."""
    rg = (reg or '').upper().replace(' ', '').strip()[:12]
    if len(rg) < 3:
        return jsonify({'ok': False, 'error': 'bad_reg'}), 400
    if SB_AVAILABLE and sb is not None:
        try:
            r = (sb.table('airport_delay_obs').select('*')
                 .eq('reg', rg)
                 .order('date', desc=True).order('updated_at', desc=True)
                 .limit(120).execute())
            rows = r.data or []
            if rows:
                from collections import Counter as _C
                types = _C((x.get('type_code') or '').strip()
                           for x in rows if (x.get('type_code') or '').strip())
                flights = []
                for x in rows:
                    ap = (x.get('airport') or '').split('#', 1)[0]
                    flights.append({
                        'date': x.get('date'), 'flight': x.get('flight'),
                        'origin': ap, 'dest': x.get('dest_iata'),
                        'dest_name': x.get('dest_name'), 'airline': x.get('airline'),
                        'sched': x.get('sched'), 'delay_min': x.get('max_delay_min'),
                        'cancelled': x.get('cancelled'), 'status': x.get('status'),
                    })
                resp = jsonify({
                    'ok': True, 'found': True, 'reg': rg, 'source': 'aerox_obs',
                    'typical_type': (types.most_common(1)[0][0] if types else None),
                    'observations': len(rows), 'flights': flights[:60],
                })
                return _public_cache_headers(resp)
        except Exception as e:
            app.logger.warning(f'[aircraft-history] obs_fail {str(e)[:120]}')
    return jsonify({'ok': True, 'found': False, 'reg': rg, 'source': 'none'})


@app.route('/api/ax/flight-route/<callsign>', methods=['GET'])
def ax_flight_route(callsign):
    """Globaler Flug-Route-Lookup (Airline + Origin→Destination) — auch für Nicht-
    LH-Carrier (z.B. LATAM „TAM8071") und wenn der Flieger NICHT live ist. So zeigt
    die Suche etwas Sinnvolles (Airline + Strecke) statt „keine Ergebnisse".

    Increment 2 (2026-07-06, Owner „alles aus EINER Quelle"): zieht jetzt aus der
    kanonischen EINEN Route-Kaskade `warehouse_reader.route_for_flight` (free-first:
    eigener Cache → airport_delay_obs → Warehouse → fr24 → freie Generik adsbdb/
    adsb.lol/hexdb; bezahlt NUR budget-gedeckelt, hier via allow_paid=False ganz
    aus). Die eigene adsbdb-Generik entfällt — dieselbe Antwort wie Live-Tap/Status.
    Airport-Details (Name/Stadt/Land/Koordinaten) + Airline kommen aus der gebackenen
    Referenz-DB (frei, offline). `found:false` nur, wenn KEINE Quelle die Route kennt.
    Suche ohne Live-Position → for_search=True (Leg-Zeitfenster-Gate)."""
    cs = (callsign or '').upper().replace(' ', '').strip()[:12]
    if len(cs) < 3:
        return jsonify({'ok': False, 'error': 'bad_callsign'}), 400
    reg_q = (request.args.get('reg') or '').strip().upper() or None
    date_q = (request.args.get('date') or '').strip()[:10] or None
    try:
        from blueprints.warehouse_reader import route_for_flight
        from blueprints.aerox_data_blueprint import (
            _airport_row, _airline_row, _callsign_to_iata_flightno)
        route = route_for_flight(callsign=cs, reg=reg_q, for_search=True,
                                 allow_paid=False, date=date_q)
        if not route or not (route.get('src') or route.get('src_icao')
                             or route.get('dst') or route.get('dst_icao')):
            return _public_cache_headers(
                jsonify({'ok': True, 'found': False, 'callsign': cs}))

        def _ap(iata, icao):
            r = _airport_row(iata or icao) or {}
            return {'iata': r.get('iata') or iata, 'icao': r.get('icao') or icao,
                    'name': r.get('name'), 'city': r.get('city'),
                    'country': r.get('country'),
                    'lat': r.get('lat'), 'lon': r.get('lon')}
        origin = _ap(route.get('src'), route.get('src_icao'))
        destination = _ap(route.get('dst'), route.get('dst_icao'))
        try:
            fn_iata = _callsign_to_iata_flightno(cs)
        except Exception:
            fn_iata = None
        air = _airline_row(cs[:3]) or _airline_row(cs[:2]) or {}
        out = {
            'ok': True, 'found': True, 'callsign': cs,
            'flight_iata': fn_iata, 'flight_icao': cs,
            'airline': air.get('name'), 'airline_iata': air.get('iata'),
            'airline_icao': air.get('icao'),
            'origin': origin, 'destination': destination,
        }
        # CROWDSOURCE / CREW-WACHSTUM (Owner 2026-07-04): schickt der Client den LIVE
        # beobachteten Tail mit (`?reg=D-AIXG` — z.B. Freund/Crew fliegt gerade, Reg
        # aus dem GRATIS ADS-B-Feed), spiegeln wir „Flug X = Reg X auf Route A→B heute"
        # ins Warehouse. So wächst die DB aus echten Live-Crew-Daten OHNE bezahlten
        # Call — der Tail steht anderen dann gratis zur Verfügung. Nur der Tail wird
        # als Fakt gespeichert; Pünktlichkeit bleibt hier ehrlich UNBEKANNT (keine
        # Zeiten aus der Route). NIE geraten: ohne echte Reg passiert nichts.
        try:
            live_reg = (request.args.get('reg') or '').strip().upper()
            fn_iata = (out.get('flight_iata') or '').strip().upper()
            dep_iata = (origin.get('iata') or '').strip().upper() if origin else ''
            if live_reg and fn_iata and len(dep_iata) == 3:
                obs_date = (request.args.get('date') or '').strip()[:10]
                if not obs_date:
                    obs_date = datetime.now(timezone.utc).strftime('%Y-%m-%d')
                _crowdsource_flight_obs({
                    'flight': fn_iata, 'reg': live_reg,
                    'dep_iata': dep_iata,
                    'arr_iata': (destination.get('iata') or '') if destination else '',
                    'arr_name': (destination.get('name') or '') if destination else '',
                    'airline': out.get('airline_iata') or '',
                    'sched_dep': None, 'status': None, 'dep_delay_min': None,
                }, obs_date, source='live_adsb')
        except Exception:
            pass
        return _public_cache_headers(jsonify(out))
    except Exception as e:
        app.logger.warning(f'[ax_flight_route] {cs} {str(e)[:120]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 200


# Fernverkehr-Linien-Präfixe (für Post-Filter, falls products-Keys nicht greifen)
_FERN_PREFIXES = ('ICE', 'IC', 'EC', 'ECE', 'RJ', 'RJX', 'TGV', 'NJ', 'EN', 'FLX')


def _leg_is_fern(name):
    n = (name or '').upper().replace(' ', '')
    # "IC2045" / "ICE 599" → Fern; "S8"/"U4"/"RE"/"RB"/"Bus" → Nah
    for p in _FERN_PREFIXES:
        if n.startswith(p):
            # "ICE..." ja, aber NICHT "ICExyz"-Fehlmatch wie "IC E..." abdecken:
            rest = n[len(p):]
            if not rest or rest[0].isdigit() or rest[0] == ' ':
                return True
    return False


@app.route('/api/ax/transit', methods=['GET'])
def ax_transit():
    """ÖPNV-Route Haus→Flughafen über GRATIS, kein-Key Router (Multi-Source):
    im Großraum München ZUERST MVV-EFA (authoritative Verbund-Auskunft, echte U4/
    S8-Linien), sonst/zusätzlich Transitous/MOTIS (DE-weit) und db-rest v6/v5
    (DB-HAFAS-Proxy) als Fallback — erster mit Treffer gewinnt, jeder eigener
    try (langsamer/down Provider blockt nicht). Nahverkehr-only per Default (S-/U-/
    Bus/RE/RB/Tram); Fernverkehr (ICE/IC/EC) wird per Produkt-/Mode-Filter UND per
    Linien-Post-Filter ausgeschlossen (`?fern=1` erlaubt Fern). Native arrive-by-
    Suche → `leave_at` (wann aus dem Haus inkl. Fußweg zur ersten Station) + Legs
    [Fuß/U4/S8 mit dep/arr]. ALLES in try/except → kann den Live-Service nie
    crashen; die App fällt zur Not auf Apple-Transit-ETA zurück.
    Query: from_lat,from_lon,to_lat,to_lon,arrival(ISO mit TZ),fern(0/1),debug(0/1)."""
    # Abuse-Guard (Audit 2026-07-05): offener Endpoint ohne Auth — ein per-IP-
    # Limit schützt die fremden Gratis-Quotas (MVV-EFA/RMV/Transitous/db-rest)
    # vor anonymem Drain. Großzügig fürs echte Nutzungsmuster (App fragt pro
    # Pickup-Berechnung EINMAL); Muster wie ax_callsign/_ax_rate_limited.
    try:
        _tip = _client_ip()
        if _tip and _ip_rate_limited(_tip, endpoint='ax_transit',
                                     limit=30, window_sec=60):
            return jsonify({'ok': False, 'error': 'rate_limited'}), 429
    except Exception:
        pass
    try:
        flat = float(request.args.get('from_lat'))
        flon = float(request.args.get('from_lon'))
        tlat = float(request.args.get('to_lat'))
        tlon = float(request.args.get('to_lon'))
    except (TypeError, ValueError):
        return jsonify({'ok': False, 'error': 'bad_coords'}), 400
    # ISO „spätestens da sein". Ein `+` im TZ-Offset wird in der Query als Leerzeichen
    # dekodiert ("…09:00:00 02:00") → fromisoformat/Provider failen. ISO-Strings haben
    # sonst keine Leerzeichen → Space wieder zu `+` machen ist sicher. (Die App sendet
    # ohnehin UTC-„Z" ohne `+`; das hier rettet `+offset`-Clients/Tests.)
    arrival_s = (request.args.get('arrival') or '').strip().replace(' ', '+')
    want_fern = request.args.get('fern') == '1'
    try:
        import requests
        from datetime import datetime, timedelta
        UA = {'User-Agent': 'AeroX/1.0 (+https://aerosteuer.de; aerox@aerosteuer.de)'}

        def _get_json(url, params, timeout):
            r = requests.get(url, params=params, headers=UA, timeout=timeout)
            r.raise_for_status()
            return r.json()

        def _post_json(url, body, timeout, headers=None):
            r = requests.post(url, json=body, timeout=timeout,
                              headers=headers or {**UA, 'Accept': 'application/json',
                                                  'Content-Type': 'application/json'})
            r.raise_for_status()
            return r.json()

        def _delay_min(planned_iso, rt_iso):
            """Echtzeit-Verspätung in Minuten = Echtzeit − Plan. None wenn unbekannt
            (kein Echtzeit-Wert oder unparsebar). Beide Strings sind ISO mit TZ
            (Europe/Berlin oder „Z") → Subtraktion ist zonensicher. Kann negativ sein
            (Zug ist früh/Plan-Verschiebung), wird NICHT auf 0 geklemmt."""
            try:
                p = datetime.fromisoformat((planned_iso or '').replace('Z', '+00:00'))
                r = datetime.fromisoformat((rt_iso or '').replace('Z', '+00:00'))
                return int((r - p).total_seconds() // 60)
            except Exception:
                return None

        def _thin_path(coords, max_pts=200):
            """Per-Leg-Routen-GEOMETRIE [[lat,lon],…] kompakt machen: auf
            ≤max_pts ausdünnen (gleichmäßig, erster+letzter Punkt bleiben) und
            auf 5 Nachkommastellen (~1 m) runden. iOS zeichnet damit die Linie
            ENTLANG DER GLEISE statt Stopp-zu-Stopp-Luftlinie (Owner 2026-07-04:
            „öpnv hat die linie nicht wie die bahn fährt"). None wenn keine
            brauchbare Geometrie (<2 Punkte) — das `path`-Feld entfällt dann."""
            try:
                pts = []
                for c in (coords or []):
                    if isinstance(c, (list, tuple)) and len(c) >= 2:
                        la, lo = float(c[0]), float(c[1])
                        if -90.0 <= la <= 90.0 and -180.0 <= lo <= 180.0:
                            pts.append([round(la, 5), round(lo, 5)])
                if len(pts) < 2:
                    return None
                if len(pts) > max_pts:
                    step = (len(pts) - 1) / float(max_pts - 1)
                    pts = [pts[min(int(round(i * step)), len(pts) - 1)]
                           for i in range(max_pts)]
                return pts
            except Exception:
                return None

        def _dec_hafas_poly(enc, prec=1e5):
            """HAFAS-mgate-Leg-Geometrie `crdEncYX` = Google-Encoded-Polyline
            (delta-kodiert, Reihenfolge lat,lon = „YX", Präzision 1e5 — live
            gegen RMV verifiziert 2026-07-05: erster/letzter Punkt == Frankfurt
            Hbf/Flughafen Regionalbahnhof). → [[lat,lon],…]; [] bei Müll."""
            try:
                pts, idx, la, lo = [], 0, 0, 0
                while idx < len(enc):
                    vals = []
                    for _ in (0, 1):
                        shift = result = 0
                        while True:
                            b = ord(enc[idx]) - 63
                            idx += 1
                            result |= (b & 0x1f) << shift
                            shift += 5
                            if b < 0x20:
                                break
                        vals.append(~(result >> 1) if (result & 1) else (result >> 1))
                    la += vals[0]
                    lo += vals[1]
                    pts.append([la / prec, lo / prec])
                return pts
            except Exception:
                return []

        # bahn.de hängt hinter Akamai-Bot-Protection → braucht Browser-ähnliche Header
        # (echte SPA-Header), sonst 403. Origin/Referer = die echte Fahrplan-Suche.
        _BAHN_HEADERS = {
            'User-Agent': ('Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) '
                           'AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.0 '
                           'Mobile/15E148 Safari/604.1'),
            'Accept': 'application/json', 'Accept-Language': 'de-DE,de;q=0.9',
            'Content-Type': 'application/json',
            'Origin': 'https://www.bahn.de',
            'Referer': 'https://www.bahn.de/buchung/fahrplan/suche',
        }

        def _norm_bahnde(data):
            """bahn.de-Vendo (dbweb) Verbindungen → normalisierte Leg-Listen. DIES ist
            die einzige Quelle die von Cloud Run aus GANZ Deutschland abdeckt (FRA,
            Köln, Berlin, Mainz, Wiesbaden …): www.bahn.de ist öffentlich auflösbar,
            anders als DBs interne Vendo-Hosts (app.vendo.noncd.db.de = NXDOMAIN von
            Google aus). Fußweg = verkehrsmittel.typ FUSSWEG; Linie = name/kurzText."""
            out = []
            for v in (data or {}).get('verbindungen', []) or []:
                vb = v.get('verbindung') or v
                legs = []
                for ab in vb.get('verbindungsAbschnitte', []) or []:
                    vm = ab.get('verkehrsmittel') or {}
                    typ = (vm.get('typ') or '').upper()
                    kat = (vm.get('produktGattung') or vm.get('kategorie') or '').upper()
                    is_walk = typ in ('FUSSWEG', 'WALK', 'TRANSFER') or kat == 'FUSSWEG'
                    name = vm.get('name') or vm.get('kurzText') or vm.get('mittelText')
                    is_fern = kat in ('ICE', 'EC_IC', 'IR') or _leg_is_fern(name)
                    # bahn.de-Vendo: `*Zeitpunkt` = Fahrplan, `ez*Zeitpunkt` = Echtzeit.
                    dep_plan = ab.get('abfahrtsZeitpunkt')
                    arr_plan = ab.get('ankunftsZeitpunkt')
                    dep_rt = ab.get('ezAbfahrtsZeitpunkt')
                    arr_rt = ab.get('ezAnkunftsZeitpunkt')
                    legs.append({
                        'mode': 'walk' if is_walk else 'transit',
                        'line': None if is_walk else name, 'product': kat,
                        'fern': is_fern,
                        'from': ab.get('abfahrtsOrt'), 'to': ab.get('ankunftsOrt'),
                        'from_lat': None, 'from_lon': None,
                        'dep': dep_rt or dep_plan,
                        'arr': arr_rt or arr_plan,
                        'dep_planned': dep_plan,
                        'arr_planned': arr_plan,
                        'delay_min': (None if is_walk or not (dep_rt and dep_plan)
                                      else _delay_min(dep_plan, dep_rt)),
                    })
                if legs:
                    out.append(legs)
            return out

        # MOTIS-Fern-Modes (Transitous) → bei Nahverkehr-only ausschließen.
        _MOTIS_FERN = ('HIGHSPEED_RAIL', 'LONG_DISTANCE', 'NIGHT_RAIL', 'COACH', 'AIRPLANE')

        def _norm_motis(data):
            """Transitous/MOTIS-Itineraries → normalisierte Leg-Listen."""
            out = []
            for it in (data or {}).get('itineraries', []) or []:
                legs = []
                for leg in it.get('legs', []) or []:
                    mode = (leg.get('mode') or '').upper()
                    is_walk = mode in ('WALK', 'BIKE', 'CAR')
                    short = leg.get('routeShortName') or leg.get('displayName') or leg.get('headsign')
                    f = leg.get('from') or {}
                    t = leg.get('to') or {}
                    is_fern = (mode in _MOTIS_FERN) or _leg_is_fern(short)
                    # MOTIS: startTime/endTime sind bereits Echtzeit-korrigiert, ein
                    # separater Fahrplan-Wert wird nicht geliefert → delay_min unbekannt.
                    legs.append({
                        'mode': 'walk' if is_walk else 'transit',
                        'line': None if is_walk else short, 'product': mode.lower(),
                        'fern': is_fern,
                        'from': f.get('name'), 'to': t.get('name'),
                        'from_lat': f.get('lat'), 'from_lon': f.get('lon'),
                        'dep': leg.get('startTime'), 'arr': leg.get('endTime'),
                        'dep_planned': leg.get('scheduledStartTime') or leg.get('startTime'),
                        'arr_planned': leg.get('scheduledEndTime') or leg.get('endTime'),
                        'delay_min': (None if is_walk
                                      else _delay_min(leg.get('scheduledStartTime'),
                                                      leg.get('startTime'))),
                    })
                if legs:
                    out.append(legs)
            return out

        def _norm_efa(data):
            """MVV-EFA (rapidJSON) Journeys → normalisierte Leg-Listen. Fußwege =
            product.class 99/100 (oder fehlende transportation). Liniennamen aus
            disassembledName/number (z.B. „S8", „U4", „Tram 19"). Zeiten sind UTC."""
            out = []
            for j in (data or {}).get('journeys', []) or []:
                legs = []
                for leg in j.get('legs', []) or []:
                    tr = leg.get('transportation') or {}
                    prod = tr.get('product') or {}
                    cls = prod.get('class')
                    is_walk = (cls in (98, 99, 100)) or (cls is None)
                    name = tr.get('disassembledName') or tr.get('number') or tr.get('name')
                    o = leg.get('origin') or {}
                    d = leg.get('destination') or {}
                    ocoord = o.get('coord') or []
                    # EFA (useRealtime=1): *Estimated = Echtzeit, *Planned = Fahrplan.
                    dep_plan = o.get('departureTimePlanned')
                    dep_rt = o.get('departureTimeEstimated')
                    arr_plan = d.get('arrivalTimePlanned')
                    arr_rt = d.get('arrivalTimeEstimated')
                    # EFA: Gleis am Abfahrts-Stop = `platform` (kurz, z.B. „3") bzw.
                    # `platformName` (Langtext). Kurzform bevorzugen, sonst Langtext.
                    _plat = o.get('platform') or o.get('platformName')
                    dep_platform = (str(_plat).strip() or None) if _plat not in (None, '') else None
                    _leg_out = {
                        'mode': 'walk' if is_walk else 'transit',
                        'line': None if is_walk else name, 'product': str(cls),
                        'fern': _leg_is_fern(name),
                        'from': o.get('name'), 'to': d.get('name'),
                        'from_lat': ocoord[0] if len(ocoord) >= 2 else None,
                        'from_lon': ocoord[1] if len(ocoord) >= 2 else None,
                        'dep': dep_rt or dep_plan,
                        'arr': arr_rt or arr_plan,
                        'dep_planned': dep_plan,
                        'arr_planned': arr_plan,
                        'delay_min': (None if is_walk or not dep_rt
                                      else _delay_min(dep_plan, dep_rt)),
                        'platform': None if is_walk else dep_platform,
                    }
                    # EFA liefert die Leg-Geometrie direkt als `coords`
                    # [[lat,lon],…] (S8: ~460 Punkte, verifiziert) → als
                    # kompaktes `path` durchreichen (additiv; fehlt bei
                    # Providern ohne Geometrie).
                    _pp = _thin_path(leg.get('coords'))
                    if _pp:
                        _leg_out['path'] = _pp
                    legs.append(_leg_out)
                if legs:
                    out.append(legs)
            return out

        def _hafas_iso(d, t):
            """HAFAS-REST liefert date='YYYY-MM-DD' + time='HH:MM:SS' LOKAL ohne TZ.
            → kombinieren und Europe/Berlin-Offset anhängen, damit iOS es parsen kann."""
            if not d or not t:
                return None
            try:
                from zoneinfo import ZoneInfo as _Z
                from datetime import datetime as _dt
                naive = _dt.fromisoformat(f'{d}T{t[:8]}')
                aware = naive.replace(tzinfo=_Z('Europe/Berlin'))
                return aware.isoformat()
            except Exception:
                return f'{d}T{t[:8]}'

        def _norm_rmv(data):
            """RMV-HAPI (HAFAS-REST `trip`) → normalisierte Leg-Listen. Leg.type WALK =
            Fußweg; Linie = Product.catOut/name (S8/U4/Bus). RMV-Host ist von Cloud
            Run erreichbar (kein DB/Akamai-Block) → deckt Frankfurt/Mainz/Wiesbaden/
            Hessen ab. Braucht einen GRATIS accessId-Key (opendata.rmv.de)."""
            out = []
            for trip in (data or {}).get('Trip', []) or []:
                legs = []
                ll = (trip.get('LegList') or {}).get('Leg') or []
                for leg in ll:
                    typ = (leg.get('type') or '').upper()
                    is_walk = typ in ('WALK', 'TRSF', 'DEVI')
                    prod = leg.get('Product')
                    if isinstance(prod, list):
                        prod = prod[0] if prod else {}
                    prod = prod or {}
                    name = (leg.get('name') or prod.get('name')
                            or prod.get('catOut') or prod.get('displayNumber'))
                    cat = (prod.get('catOut') or prod.get('catCode') or '').upper()
                    o = leg.get('Origin') or {}
                    d = leg.get('Destination') or {}
                    is_fern = cat in ('ICE', 'IC', 'EC', 'IR') or _leg_is_fern(name)
                    # HAFAS-Echtzeit (rtMode=REALTIME): Stop trägt Plan (date/time) UND
                    # Echtzeit (rtDate/rtTime). rtDate fehlt oft bei selbem Tag → auf
                    # die Plan-date zurückfallen. Fehlt rtTime ganz → keine Echtzeit.
                    dep_plan = _hafas_iso(o.get('date'), o.get('time'))
                    arr_plan = _hafas_iso(d.get('date'), d.get('time'))
                    dep_rt = (_hafas_iso(o.get('rtDate') or o.get('date'), o.get('rtTime'))
                              if o.get('rtTime') else None)
                    arr_rt = (_hafas_iso(d.get('rtDate') or d.get('date'), d.get('rtTime'))
                              if d.get('rtTime') else None)
                    # HAFAS-REST: Gleis am Abfahrts-Stop = `track` (Plan) / `rtTrack`
                    # (Echtzeit). Echtzeit bevorzugen, sonst Plan, sonst None.
                    _trk = o.get('rtTrack') or o.get('track')
                    dep_platform = (str(_trk).strip() or None) if _trk not in (None, '') else None
                    _leg_out = {
                        'mode': 'walk' if is_walk else 'transit',
                        'line': None if is_walk else (name or '').strip(), 'product': cat,
                        'fern': is_fern,
                        'from': o.get('name'), 'to': d.get('name'),
                        'from_lat': o.get('lat'), 'from_lon': o.get('lon'),
                        'dep': dep_rt or dep_plan,
                        'arr': arr_rt or arr_plan,
                        'dep_planned': dep_plan,
                        'arr_planned': arr_plan,
                        'delay_min': (None if is_walk or not dep_rt
                                      else _delay_min(dep_plan, dep_rt)),
                        'platform': None if is_walk else dep_platform,
                    }
                    # Leg-Geometrie via poly=1: RMV liefert sie als
                    # `PolylineGroup.polylineDesc[].crd` (flache lon,lat-Float-
                    # Liste, delta:false, dim:2 — live verifiziert 2026-07-04);
                    # klassisches HAFAS-REST kennt auch `Polyline.crd` (ggf.
                    # delta-kodiert = Differenzen zur vorigen Koordinate).
                    # Defensiv: Achsen-Reihenfolge wird gegen die Origin-
                    # Koordinate verprobt, µ°-Werte (>181) /1e6 skaliert. Bei
                    # Zweifel KEIN path → iOS zeichnet die ehrliche Stopp-Gerade.
                    try:
                        _descs = []
                        _pg = leg.get('PolylineGroup') or {}
                        for _pd in (_pg.get('polylineDesc') or []):
                            if isinstance(_pd, dict):
                                _descs.append(_pd)
                        _pl = leg.get('Polyline') or leg.get('polyline')
                        if isinstance(_pl, dict):
                            _descs.append(_pl)
                        _pts = []
                        for _pd in _descs:
                            _crd = _pd.get('crd') or []
                            _dim = int(_pd.get('dim') or 2)
                            if _dim < 2 or len(_crd) < 2 * _dim:
                                continue
                            _vals = [float(x) for x in _crd]
                            _pairs = list(zip(_vals[0::_dim], _vals[1::_dim]))
                            if _pd.get('delta'):
                                _acc, _x, _y = [], 0.0, 0.0
                                for _dx, _dy in _pairs:
                                    _x += _dx; _y += _dy
                                    _acc.append((_x, _y))
                                _pairs = _acc
                            if _pairs and any(abs(v) > 181 for v in _pairs[0]):
                                _pairs = [(px / 1e6, py / 1e6) for px, py in _pairs]
                            # HAFAS-Konvention: (x=lon, y=lat) → [lat, lon].
                            _pts.extend([py, px] for px, py in _pairs)
                        if _pts:
                            try:
                                _ola, _olo = float(o.get('lat')), float(o.get('lon'))
                                _p0 = _pts[0]
                                if (abs(_p0[0] - _ola) + abs(_p0[1] - _olo)
                                        > abs(_p0[1] - _ola) + abs(_p0[0] - _olo)):
                                    _pts = [[b, a] for a, b in _pts]
                            except (TypeError, ValueError):
                                pass
                            _pp = _thin_path(_pts)
                            if _pp:
                                _leg_out['path'] = _pp
                    except Exception:
                        pass
                    legs.append(_leg_out)
                if legs:
                    out.append(legs)
            return out

        def _mgate_iso(date_s, time_s):
            """HAFAS-mgate-Zeiten: `HHMMSS` bzw. `DDHHMMSS` (Tages-Offset-Präfix
            bei Über-Mitternacht), LOKAL Europe/Berlin; Basisdatum = con.date
            (`YYYYMMDD`). → ISO mit Offset, None wenn unparsebar (NIE raten)."""
            if not date_s or not time_s:
                return None
            try:
                from zoneinfo import ZoneInfo as _Z
                from datetime import datetime as _dt, timedelta as _td
                t = str(time_s)
                days = 0
                if len(t) > 6:
                    days, t = int(t[:-6]), t[-6:]
                naive = _dt.strptime(f'{date_s}{t}', '%Y%m%d%H%M%S') + _td(days=days)
                return naive.replace(tzinfo=_Z('Europe/Berlin')).isoformat()
            except Exception:
                return None

        def _norm_rmv_mgate(data):
            """RMV-EFA/HAFAS-mgate (www.rmv.de/auskunft/bin/jp/mgate.exe,
            TripSearch) → normalisierte Leg-Listen, GLEICHE Form wie _norm_efa
            (MVV). RECHERCHE 2026-07-05: einen öffentlichen EFA-Stil-Endpunkt
            (XML_TRIP_REQUEST2) hat RMV NICHT (alle Kandidaten-Pfade 404/503,
            /hapi braucht accessId-Key) — die eigene Web-Auskunft
            (/auskunft/rmv/app) spricht mgate; deren AID ist öffentlich im
            transport-apis-Repo dokumentiert. Live verifiziert (Frankfurt
            Innenstadt → FRA Regionalbf: S8, Gleis 21, arrive-by, Polyline).
            secL: type JNY = Fahrt, alles andere (WALK/TRSF/DEVI) = Fußweg/
            Umstieg. Referenzen: dep/arr.locX → common.locL (crd x=lon·1e6,
            y=lat·1e6), jny.prodX → common.prodL, jny.polyG.polyXL →
            common.polyL[].crdEncYX. Zeiten: *TimeS=Plan, *TimeR=Echtzeit;
            Gleis: dPlatfR vor dPlatfS (neuere Kerne: dPltf{R,S}.txt)."""
            svc = ((data or {}).get('svcResL') or [{}])[0] or {}
            err = svc.get('err')
            if err not in (None, 'OK'):
                # HAFAS-Kernel-Fehler (z.B. H9220 „keine Station nahe Ziel")
                # sichtbar machen → Provider-Chain loggt ihn und geht weiter.
                raise RuntimeError(f'mgate {err}: {str(svc.get("errTxt") or "")[:80]}')
            res = svc.get('res') or {}
            common = res.get('common') or {}
            locL = common.get('locL') or []
            prodL = common.get('prodL') or []
            polyL = common.get('polyL') or []

            def _loc(stop):
                lx = (stop or {}).get('locX')
                if isinstance(lx, int) and 0 <= lx < len(locL):
                    return locL[lx] or {}
                return {}

            out = []
            for con in res.get('outConL') or []:
                base_date = con.get('date')
                legs = []
                for sec in con.get('secL') or []:
                    typ = (sec.get('type') or '').upper()
                    is_walk = typ != 'JNY'
                    jny = sec.get('jny') or {}
                    prod = {}
                    px = jny.get('prodX')
                    if isinstance(px, int) and 0 <= px < len(prodL):
                        prod = prodL[px] or {}
                    name = (prod.get('name') or prod.get('nameS') or '').strip() or None
                    cls = prod.get('cls')
                    # RMV-Produkt-Bitmaske: 1=ICE, 2=EC/IC → Fernverkehr.
                    is_fern = (isinstance(cls, int) and bool(cls & 3)) or _leg_is_fern(name)
                    dep = sec.get('dep') or {}
                    arr = sec.get('arr') or {}
                    o = _loc(dep)
                    d = _loc(arr)
                    ocrd = o.get('crd') or {}
                    dep_plan = _mgate_iso(base_date, dep.get('dTimeS'))
                    arr_plan = _mgate_iso(base_date, arr.get('aTimeS'))
                    dep_rt = _mgate_iso(base_date, dep.get('dTimeR')) if dep.get('dTimeR') else None
                    arr_rt = _mgate_iso(base_date, arr.get('aTimeR')) if arr.get('aTimeR') else None
                    _plat = dep.get('dPlatfR') or dep.get('dPlatfS')
                    if not _plat:
                        _pl = dep.get('dPltfR') or dep.get('dPltfS')
                        if isinstance(_pl, dict):
                            _plat = _pl.get('txt')
                    dep_platform = (str(_plat).strip() or None) if _plat not in (None, '') else None
                    _leg_out = {
                        'mode': 'walk' if is_walk else 'transit',
                        'line': None if is_walk else name,
                        'product': str(cls) if cls is not None else typ.lower(),
                        'fern': is_fern,
                        'from': o.get('name'), 'to': d.get('name'),
                        'from_lat': (ocrd.get('y') / 1e6) if isinstance(ocrd.get('y'), (int, float)) else None,
                        'from_lon': (ocrd.get('x') / 1e6) if isinstance(ocrd.get('x'), (int, float)) else None,
                        'dep': dep_rt or dep_plan,
                        'arr': arr_rt or arr_plan,
                        'dep_planned': dep_plan,
                        'arr_planned': arr_plan,
                        'delay_min': (None if is_walk or not dep_rt
                                      else _delay_min(dep_plan, dep_rt)),
                        'platform': None if is_walk else dep_platform,
                    }
                    # Leg-Geometrie (getPolyline=1) → kompaktes `path` wie beim
                    # MVV-EFA; bei Zweifel KEIN path (ehrliche Stopp-Gerade).
                    try:
                        _pts = []
                        for _pix in ((jny.get('polyG') or {}).get('polyXL') or []):
                            if isinstance(_pix, int) and 0 <= _pix < len(polyL):
                                _enc = (polyL[_pix] or {}).get('crdEncYX')
                                if _enc:
                                    _pts.extend(_dec_hafas_poly(_enc))
                        _pp = _thin_path(_pts)
                        if _pp:
                            _leg_out['path'] = _pp
                    except Exception:
                        pass
                    legs.append(_leg_out)
                if legs:
                    out.append(legs)
            return out

        def _norm_dbrest(data):
            """db-rest-Journeys → normalisierte Leg-Listen."""
            out = []
            for j in (data or {}).get('journeys', []) or []:
                legs = []
                for leg in j.get('legs', []) or []:
                    is_walk = bool(leg.get('walking'))
                    line = leg.get('line') or {}
                    name = line.get('name')
                    product = (line.get('product') or '')
                    o = leg.get('origin') or {}
                    d = leg.get('destination') or {}
                    oloc = o.get('location') or {}
                    is_fern = product in ('nationalExpress', 'national') or _leg_is_fern(name)
                    # db-rest (HAFAS-Proxy): `departure`/`arrival` = Echtzeit, `planned*`
                    # = Fahrplan.
                    dep_plan = leg.get('plannedDeparture')
                    arr_plan = leg.get('plannedArrival')
                    dep_rt = leg.get('departure')
                    arr_rt = leg.get('arrival')
                    legs.append({
                        'mode': 'walk' if is_walk else 'transit',
                        'line': None if is_walk else name, 'product': product,
                        'fern': is_fern,
                        'from': o.get('name'), 'to': d.get('name'),
                        'from_lat': oloc.get('latitude'), 'from_lon': oloc.get('longitude'),
                        'dep': dep_rt or dep_plan,
                        'arr': arr_rt or arr_plan,
                        'dep_planned': dep_plan,
                        'arr_planned': arr_plan,
                        'delay_min': (None if is_walk or not (dep_rt and dep_plan)
                                      else _delay_min(dep_plan, dep_rt)),
                    })
                if legs:
                    out.append(legs)
            return out

        prod = 'true'
        fern = 'true' if want_fern else 'false'
        # db-rest: EINE Tür-zu-Tür-Abfrage direkt mit Koordinaten → Fußweg als Leg.
        dbrest_params = {
            'from.latitude': flat, 'from.longitude': flon, 'from.address': 'Zuhause',
            'to.latitude': tlat, 'to.longitude': tlon, 'to.address': 'Flughafen',
            'nationalExpress': fern, 'national': fern,
            'regionalExpress': prod, 'regional': prod,
            'suburban': prod, 'subway': prod, 'tram': prod,
            'bus': prod, 'ferry': prod, 'taxi': 'false',
            'results': 5, 'stopovers': 'false', 'remarks': 'false', 'walkingSpeed': 'normal',
        }
        if arrival_s:
            dbrest_params['arrival'] = arrival_s
        else:
            dbrest_params['departure'] = 'now'

        # Transitous (MOTIS): freier, kein-Key, DE-weiter ÖPNV-Router. Native
        # arrive-by-Suche (`arriveBy`+`time`). Wird ZUERST versucht (purpose-built,
        # zuverlässiger als die langsamen db-rest-Public-Proxies), db-rest als Fallback.
        motis_params = {'fromPlace': f'{flat},{flon}', 'toPlace': f'{tlat},{tlon}',
                        'numItineraries': 5}
        if arrival_s:
            # MOTIS will RFC3339; ein TZ-Offset („+02:00") lässt v6 500en → immer auf
            # UTC-„Z" normalisieren (db-rest/EFA bekommen weiter ihr eigenes Format).
            try:
                _au = datetime.fromisoformat(arrival_s.replace('Z', '+00:00'))
                from datetime import timezone as _tz
                motis_time = (_au.astimezone(_tz.utc) if _au.tzinfo else _au).strftime('%Y-%m-%dT%H:%M:%SZ')
            except Exception:
                motis_time = arrival_s
            motis_params['time'] = motis_time
            motis_params['arriveBy'] = 'true'

        # MVV-EFA (Großraum München): die eigene, authoritative ÖPNV-Auskunft des
        # Verkehrsverbunds — gratis, kein Key, liefert echte U-/S-/Tram-/Bus-Linien
        # mit „arrive-by". Deckt den Haupt-User (München, U4+S8 → MUC) zuverlässig ab,
        # wo Transitous (keine MVV-GTFS) leer bleibt und db-rest gerade down ist. EFA
        # erwartet Koordinaten als `lon:lat:WGS84[DD.ddddd]` und LOKALE Zeit (Europe/
        # Berlin) als itdDate/itdTime.
        in_mvv = (47.6 <= flat <= 48.7) and (10.7 <= flon <= 12.4)
        efa_params = None
        efa_dbg = {'in_mvv': in_mvv}
        if in_mvv:
            try:
                from zoneinfo import ZoneInfo
                tz = ZoneInfo('Europe/Berlin')
                if arrival_s:
                    a = datetime.fromisoformat(arrival_s.replace('Z', '+00:00'))
                    a = a.astimezone(tz) if a.tzinfo else a.replace(tzinfo=tz)
                else:
                    a = datetime.now(tz)
                # Ziel ggf. auf den Flughafen-Bahnhof snappen (MUC: München Flughafen
                # Terminal S1/S8) statt aufs Terminal-Zentrum — Route endet am Bahnhof.
                _elat, _elon = tlat, tlon
                _esnap = _snap_to_airport_rail(tlat, tlon)
                if _esnap:
                    _elat, _elon = _esnap[0], _esnap[1]
                    efa_dbg['airport_rail_snap'] = _esnap[2]
                efa_params = {
                    'outputFormat': 'rapidJSON',
                    'coordOutputFormat': 'WGS84[DD.ddddd]',
                    'type_origin': 'coord',
                    'name_origin': f'{flon}:{flat}:WGS84[DD.ddddd]',   # EFA = lon:lat!
                    'type_destination': 'coord',
                    'name_destination': f'{_elon}:{_elat}:WGS84[DD.ddddd]',
                    'itdDate': a.strftime('%Y%m%d'), 'itdTime': a.strftime('%H%M'),
                    'itdTripDateTimeDepArr': 'arr',
                    'calcNumberOfTrips': 5, 'useRealtime': 1,
                }
            except Exception as ee:
                efa_params = None
                efa_dbg['build_err'] = f'{type(ee).__name__}: {str(ee)[:140]}'

        # bahn.de-Vendo (dbweb): GANZ-Deutschland-Abdeckung (FRA/Köln/Berlin/Mainz/
        # Wiesbaden …), gratis, kein Key, von Cloud Run aus erreichbar (www.bahn.de
        # ist öffentlich, anders als DBs interne Vendo-Hosts). Koordinaten als
        # ADR-Location-Id `A=2@O=…@X=lon*1e6@Y=lat*1e6@`; arrive-by via ankunftSuche.
        bahn_body = None
        try:
            from zoneinfo import ZoneInfo as _ZI
            _tzb = _ZI('Europe/Berlin')
            if arrival_s:
                _ab = datetime.fromisoformat(arrival_s.replace('Z', '+00:00'))
                _ab = _ab.astimezone(_tzb) if _ab.tzinfo else _ab.replace(tzinfo=_tzb)
            else:
                _ab = datetime.now(_tzb)
            _nah = ['IR', 'REGIONAL', 'SBAHN', 'BUS', 'SCHIFF', 'UBAHN', 'TRAM', 'ANRUFPFLICHTIG']
            _prod = (['ICE', 'EC_IC'] + _nah) if want_fern else _nah
            bahn_body = {
                'abfahrtsHalt': f'A=2@O=Zuhause@X={int(round(flon * 1e6))}@Y={int(round(flat * 1e6))}@',
                'ankunftsHalt': f'A=2@O=Flughafen@X={int(round(tlon * 1e6))}@Y={int(round(tlat * 1e6))}@',
                'anfrageZeitpunkt': _ab.strftime('%Y-%m-%dT%H:%M:%S'),
                'ankunftSuche': 'ANKUNFT',          # arrive-by
                'klasse': 'KLASSE_2',
                'produktgattungen': _prod,
                'reisende': [{'typ': 'ERWACHSENER',
                              'ermaessigungen': [{'art': 'KEINE_ERMAESSIGUNG', 'klasse': 'KLASSENLOS'}],
                              'alter': [], 'anzahl': 1}],
                'schnelleVerbindungen': True, 'sitzplatzOnly': False,
                'bikeCarriage': False, 'reservierungsKontingenteVorhanden': False,
            }
        except Exception:
            bahn_body = None

        # Provider-Reihenfolge: (Name, callable→normalisierte Journeys). Erster mit
        # Treffer gewinnt. Jeder eigener try → ein langsamer/down Provider blockt nicht.
        # MVV-EFA zuerst (authoritativ für München), dann bahn.de (ganz DE), dann Rest.
        # HINWEIS: bahn.de-Vendo (_norm_bahnde/_post_json/_BAHN_HEADERS/bahn_body) ist
        # bewusst NICHT in der aktiven Kette: von Cloud Run aus liefert www.bahn.de
        # konstant 403 (Akamai blockt Google-Datacenter-IPs) — genau wie DBs interne
        # Vendo-Hosts per DNS NXDOMAIN sind. Die Helfer bleiben dormant, falls je ein
        # Proxy AUSSERHALB Googles (z.B. NAS/VPS) dazukommt, der DB erreichen darf.
        _ = bahn_body  # dormant

        # RMV-HAPI — HAFAS-REST `trip` mit GRATIS accessId-Key (env RMV_ACCESS_ID,
        # Registrierung opendata.rmv.de). RMVs HAFAS sitzt auf dem BUNDESWEITEN
        # DELFI-Fahrplan → routet ÖPNV in GANZ Deutschland (Frankfurt, Köln, Berlin,
        # Hamburg …), nicht nur Hessen. RMV-Host ist von Cloud Run erreichbar (kein
        # DB/Akamai-Block). Koordinaten-basiert (inkl. Fußweg) + arrive-by; Fern per
        # Post-Filter raus. Gate = grobe Deutschland-Bbox (kein Sinn außerhalb DE).
        rmv_key = os.environ.get('RMV_ACCESS_ID', '').strip()
        in_rmv = (47.2 <= flat <= 55.1) and (5.8 <= flon <= 15.1)   # ganz DE
        rmv_params = None
        if rmv_key and in_rmv:
            try:
                from zoneinfo import ZoneInfo as _ZR
                _tzr = _ZR('Europe/Berlin')
                if arrival_s:
                    _ar = datetime.fromisoformat(arrival_s.replace('Z', '+00:00'))
                    _ar = _ar.astimezone(_tzr) if _ar.tzinfo else _ar.replace(tzinfo=_tzr)
                else:
                    _ar = datetime.now(_tzr)
                # FLUGHAFEN-FIX (User 2026-06-29): das geometrische Flughafen-Zentrum
                # (z.B. FRA 50.0379,8.5622) liegt mitten im Vorfeld OHNE Haltestelle →
                # HAFAS antwortet SVC_LOC/H9220 „keine Station in der Nähe". Das ZIEL
                # daher auf die nächste BAHN-Station snappen (Regionalbahnhof), Bus
                # (Produkt-Bit 32) ausgeschlossen, damit nicht ein Vorfeld-Bus-Stop
                # gewählt wird. Der ORIGIN bleibt Koordinate → echter Fußweg-aus-dem-Haus.
                # Ziel ggf. vom Terminal-Zentrum auf den Flughafen-Bahnhof snappen
                # (s. _snap_to_airport_rail): so endet die Route am Regional-/S-Bahnhof
                # und HAFAS hängt KEINEN People-Mover (SkyLine/SkyTrain) an. Kein
                # Treffer → Ziel bleibt die Original-Koordinate (Verhalten wie zuvor).
                _dlat, _dlon = tlat, tlon
                _snap = _snap_to_airport_rail(tlat, tlon)
                if _snap:
                    _dlat, _dlon, _snap_label = _snap[0], _snap[1], _snap[2]
                    efa_dbg['airport_rail_snap'] = _snap_label
                rmv_dest_ext = None
                try:
                    _nb = _get_json('https://www.rmv.de/hapi/location.nearbystops', {
                        'accessId': rmv_key, 'format': 'json',
                        'originCoordLat': _dlat, 'originCoordLong': _dlon,
                        'maxNo': 1, 'r': 6000, 'products': 447,
                    }, 8)
                    _items = (_nb or {}).get('stopLocationOrCoordLocation') or []
                    if _items:
                        rmv_dest_ext = (_items[0].get('StopLocation') or {}).get('extId')
                except Exception:
                    rmv_dest_ext = None
                rmv_params = {
                    'accessId': rmv_key, 'format': 'json',
                    'originCoordLat': flat, 'originCoordLong': flon,
                    'date': _ar.strftime('%Y-%m-%d'), 'time': _ar.strftime('%H:%M'),
                    'searchForArrival': 1, 'numB': 0, 'numF': 4, 'rtMode': 'REALTIME',
                    # Leg-Geometrie (Polyline.crd) mitliefern → iOS zeichnet die
                    # Linie entlang der Gleise statt Luftlinie (s. _norm_rmv).
                    'poly': 1,
                }
                if rmv_dest_ext:
                    rmv_params['destExtId'] = rmv_dest_ext
                else:
                    rmv_params['destCoordLat'] = _dlat
                    rmv_params['destCoordLong'] = _dlon
            except Exception:
                rmv_params = None

        # RMV-mgate (Rhein-Main, KEIN Key): die eigene Web-Auskunft des RMV
        # (www.rmv.de/auskunft/rmv/app) spricht HAFAS-mgate auf www.rmv.de —
        # öffentlich erreichbar, AID im transport-apis-Repo dokumentiert
        # (public-transport/transport-apis, data/de/rmv-hafas-mgate.json).
        # Deckt Frankfurt/Mainz/Wiesbaden/Darmstadt authoritativ ab, wo ohne
        # RMV_ACCESS_ID-Key bisher GAR KEIN Provider ging (App fiel auf Apple-
        # ETA ohne Legs zurück). Region-Gate wie MVV: nur Rhein-Main-Bbox
        # (RMV-Verbundgebiet grob lat 49.3–50.95 / lon 7.6–9.8). Arrive-by =
        # outFrwd:false; Fern (ICE/IC, Bits 1+2) schon per jnyFltrL raus,
        # Post-Filter greift zusätzlich. Live verifiziert 2026-07-05.
        in_rhein_main = (49.3 <= flat <= 50.95) and (7.6 <= flon <= 9.8)
        rmv_mgate_body = None
        efa_dbg['in_rhein_main'] = in_rhein_main
        if in_rhein_main:
            try:
                from zoneinfo import ZoneInfo as _ZM
                _tzm = _ZM('Europe/Berlin')
                if arrival_s:
                    _am = datetime.fromisoformat(arrival_s.replace('Z', '+00:00'))
                    _am = _am.astimezone(_tzm) if _am.tzinfo else _am.replace(tzinfo=_tzm)
                else:
                    _am = datetime.now(_tzm)
                # Ziel auf den Flughafen-BAHNHOF snappen (FRA-Terminal-Zentrum =
                # Vorfeld ohne Haltestelle → HAFAS H9220, live reproduziert).
                _mlat, _mlon = tlat, tlon
                _msnap = _snap_to_airport_rail(tlat, tlon)
                if _msnap:
                    _mlat, _mlon = _msnap[0], _msnap[1]
                    efa_dbg['airport_rail_snap'] = _msnap[2]
                # Produkt-Bitmaske (RMV): 1 ICE + 2 EC/IC = Fern; Rest (4 RE/RB,
                # 8 S, 16 U, 32 Tram, 64/128 Bus, 256 Schiff, 512 AST,
                # 1024 Seilbahn) = 2044.
                rmv_mgate_body = {
                    'ver': '1.18', 'lang': 'deu', 'ext': 'RMV.1',
                    'auth': {'type': 'AID', 'aid': 'x0k4ZR33ICN9CWmj'},
                    'client': {'id': 'RMV', 'type': 'WEB', 'name': 'webapp'},
                    'svcReqL': [{'meth': 'TripSearch', 'req': {
                        'depLocL': [{'lid': f'A=2@O=Zuhause@X={int(round(flon * 1e6))}@Y={int(round(flat * 1e6))}@'}],
                        'arrLocL': [{'lid': f'A=2@O=Flughafen@X={int(round(_mlon * 1e6))}@Y={int(round(_mlat * 1e6))}@'}],
                        'outDate': _am.strftime('%Y%m%d'), 'outTime': _am.strftime('%H%M%S'),
                        'outFrwd': not bool(arrival_s),   # False = arrive-by
                        'numF': 5, 'getPolyline': True, 'getPasslist': False,
                        'jnyFltrL': [{'type': 'PROD', 'mode': 'INC',
                                      'value': 2047 if want_fern else 2044}],
                    }}],
                }
            except Exception as me:
                rmv_mgate_body = None
                efa_dbg['rmv_mgate_build_err'] = f'{type(me).__name__}: {str(me)[:140]}'

        # SCHLANKE Kette (User: „besser einfach RMV nutzen"): RMV deckt als
        # bundesweite DELFI-HAFAS GANZ DE ab → wird primäre Quelle. MVV-EFA bleibt
        # als verifiziertes München-Sicherheitsnetz davor (falls RMV mal lokale
        # MVV-Linien verpasst). Transitous + public-db-rest sind RAUS (limitiert/
        # dauer-down); für Städte ohne Treffer fällt die App ohnehin auf Apple-
        # Transit-ETA zurück. (motis_params/dbrest_params bleiben dormant ungenutzt.)
        _ = (motis_params, dbrest_params)  # dormant
        providers = []
        if efa_params is not None:
            providers.append(('mvv_efa', lambda: _norm_efa(
                _get_json('https://efa.mvv-muenchen.de/ng/XML_TRIP_REQUEST2', efa_params, 12))))
        if rmv_params is not None:
            providers.append(('rmv', lambda: _norm_rmv(
                _get_json('https://www.rmv.de/hapi/trip', rmv_params, 12))))
        # Keyless RMV-mgate NACH dem keyed HAPI: mit Key bleibt alles wie
        # bisher (HAPI zuerst), OHNE Key ist mgate der einzige Rhein-Main-
        # Provider (Frankfurt bekam bisher gar keine Legs → Apple-Fallback).
        if rmv_mgate_body is not None:
            providers.append(('rmv_mgate', lambda: _norm_rmv_mgate(
                _post_json('https://www.rmv.de/auskunft/bin/jp/mgate.exe', rmv_mgate_body, 12))))

        dbg = {'providers': [], 'efa': efa_dbg}
        journeys = None
        source = None
        for name, fn in providers:
            p = {'name': name}
            try:
                js = fn() or []
                p['n'] = len(js)
                dbg['providers'].append(p)
                if js:
                    journeys = js
                    source = name
                    break
            except Exception as pe:
                p['err'] = f'{type(pe).__name__}: {str(pe)[:120]}'
                dbg['providers'].append(p)
                continue
        if not journeys:
            out = {'ok': True, 'found': False, 'reason': 'no_journey'}
            if request.args.get('debug') == '1':
                out['debug'] = dbg
            return jsonify(out)

        def _mins(a, b):
            try:
                return max(0, int((datetime.fromisoformat(b) - datetime.fromisoformat(a)).total_seconds() // 60))
            except Exception:
                return 0

        # Zielzeit (für die Pünktlichkeits-Prüfung): PÜNKTLICH heißt am Flughafen
        # spätestens zur `arrival_s` sein. Wir dürfen NIE eine Verbindung empfehlen,
        # die zu spät ankommt.
        # TZ-FIX (User 2026-06-29 „im feed bin ich viel zu früh da, nicht 15 min vor
        # Briefing"): vorher wurde die tzinfo ABGESCHNITTEN und naiv verglichen. Aber
        # die Provider liefern UNTERSCHIEDLICHE Zonen — EFA (München) UTC („…Z"),
        # RMV/HAFAS (Frankfurt + ganz DE) Europe/Berlin („+02:00"). Die Zielzeit
        # `arrival_s` kommt als UTC vom Client. Naiv verglichen sah JEDE RMV-Ankunft
        # 2 h „zu spät" aus → KEINE galt als pünktlich → es fiel immer auf die
        # früheste Verbindung zurück = viel zu früh am Flughafen. Fix: ALLES auf
        # UTC-aware normalisieren, dann vergleichen (naive Werte als UTC annehmen).
        from datetime import timezone as _utctz
        def _parse(s):
            try:
                dt = datetime.fromisoformat((s or '').replace('Z', '+00:00'))
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=_utctz.utc)
                return dt.astimezone(_utctz.utc)
            except Exception:
                return None
        target_dt = _parse(arrival_s) if arrival_s else None

        # ECHTE "arrive-by"-Auswahl: die Verbindung, die SO SPÄT WIE MÖGLICH ankommt,
        # aber noch rechtzeitig (Ankunft ≤ `arrival_s`) — also Ankunft so NAH wie
        # möglich an der Zielzeit. NICHT nach Haus-Abfahrtszeit wählen: zwei Routen zu
        # verschiedenen ersten Stationen haben unterschiedlich lange Fußwege, sodass
        # "spätestes Losgehen" eine kurze Route zu einer NÄHEREN Station treffen kann,
        # die VIEL ZU FRÜH ankommt (User-Bug 2026-06-29: 14:32 statt ~15:15). Fern-
        # Treffer verwerfen. Kommt KEINE rechtzeitig an (Randfall), nimm die früheste
        # Ankunft (besser zu früh als verpasst).
        best = None              # späteste pünktliche Ankunft (≤ Zielzeit, max. Ankunft)
        best_arr = None          # deren Ankunfts-datetime (zum Vergleich)
        fallback = None          # früheste Ankunft, falls keine pünktlich ist
        fallback_arr = None
        for legs in journeys:
            transit_legs = [l for l in legs if l['mode'] == 'transit']
            if not transit_legs:
                continue
            if (not want_fern) and any(l['fern'] for l in transit_legs):
                continue
            leave_at = next((l['dep'] for l in legs if l['dep']), None)
            transit_dep = next((l['dep'] for l in transit_legs if l['dep']), None)
            last_arr = next((l['arr'] for l in reversed(legs) if l['arr']), None)
            ft = transit_legs[0]
            wleg = next((l for l in legs if l['mode'] == 'walk' and l['dep'] and l['arr']), None)
            walk_min = _mins(wleg['dep'], wleg['arr']) if wleg else 0
            cand = {'legs': legs, 'leave_at': leave_at, 'transit_dep': transit_dep,
                    'last_arr': last_arr, 'first_stop': ft['from'], 'walk_min': walk_min,
                    'first_dep_planned': ft.get('dep_planned'),
                    'first_dep_delay_min': ft.get('delay_min')}
            arr_dt = _parse(last_arr)
            # früheste-Ankunft-Fallback unabhängig von Pünktlichkeit
            if arr_dt is not None and (fallback is None or fallback_arr is None
                                       or arr_dt < fallback_arr):
                fallback, fallback_arr = cand, arr_dt
            # pünktlich? (2 Min Toleranz). Ohne Zielzeit gilt jede als ok.
            on_time = (target_dt is None) or (arr_dt is not None and
                                              arr_dt <= target_dt + timedelta(minutes=2))
            if not on_time:
                continue
            # LATESTE pünktliche Ankunft gewinnt (am nächsten an der Zielzeit). Bei
            # fehlender Ankunftszeit (arr_dt None) nur als allererster Treffer nehmen.
            if best is None or (arr_dt is not None and
                                (best_arr is None or arr_dt > best_arr)):
                best, best_arr = cand, arr_dt
        if best is None and fallback is not None:
            best = fallback

        if best is None:
            out = {'ok': True, 'found': False, 'reason': 'no_nahverkehr'}
            if request.args.get('debug') == '1':
                out['debug'] = dbg
            return jsonify(out)

        out = {
            'ok': True, 'found': True, 'source': source,
            'leave_at': best['leave_at'],          # wann aus dem Haus (Fußweg-Start)
            'walk_to_stop_min': best['walk_min'],
            'first_stop': best['first_stop'],
            'first_dep': best['transit_dep'],       # erste echte ÖPNV-Abfahrt (Echtzeit)
            'first_dep_planned': best.get('first_dep_planned'),  # planmäßige Abfahrt
            'first_dep_delay_min': best.get('first_dep_delay_min'),  # Verspätung Min (None=unbekannt)
            'last_arr': best['last_arr'],
            'arrival_target': arrival_s,
            'legs': best['legs'],
        }
        if request.args.get('debug') == '1':
            out['debug'] = dbg
        return jsonify(out)
    except Exception as e:
        app.logger.warning(f'[ax_transit] fail {type(e).__name__}: {str(e)[:400]}')
        return jsonify({'ok': False, 'error': 'internal_error'}), 200


@app.route('/api/airport/<token>/board', methods=['GET'])
def airport_board(token):
    """Per-Airport-Board (live). Query: ?airport=MUC&type=departure|arrival&airline=LH&limit=60.
    FRA → Fraport (gratis). MUC/DUS/HAJ/FMO/LEJ/DRS → native Scraper. Sonst →
    AeroDataBox (env-gated) → OpenSky (zuletzt geflogen) → ehrlich kein-Daten."""
    airport = (request.args.get('airport') or 'FRA').upper().strip()
    airline = (request.args.get('airline') or '').upper().strip()
    ftype = (request.args.get('type') or 'departure').lower()
    if ftype not in ('departure', 'arrival'):
        ftype = 'departure'
    try:
        limit = min(int(request.args.get('limit') or 60), 200)
    except Exception:
        limit = 60
    # ICAO → IATA normalisieren (FRA/EDDF gesondert).
    iata = _DE_ICAO_TO_IATA.get(airport, airport)
    # FRA/EDDF normalisiert auf das IATA-Label, das wir persistieren ('FRA') —
    # damit ein Historien-Read denselben airport-Key trifft wie der Live-Poller.
    board_ap = 'FRA' if (iata in ('FRA', 'EDDF') or airport in ('FRA', 'EDDF')) else iata
    # ── PAST-DATE-Tafel (iOS „zurück in der Zeit", #24) ─────────────────────
    # ?date=YYYY-MM-DD für einen VERGANGENEN Tag → die gespeicherten Abflüge
    # dieses Airport+Tags aus airport_delay_obs rekonstruieren. Der Live-Feed ist
    # now-relativ und kennt vergangene Tage nicht; die SB-Tabelle hält sie pro
    # Airport. Heute/Zukunft fallen NICHT in diesen Pfad (Live-Tafel unten).
    date_param = (request.args.get('date') or '').strip()
    if date_param:
        import re as _re
        if not _re.match(r'^\d{4}-\d{2}-\d{2}$', date_param):
            return jsonify({'ok': False, 'error': 'invalid_date',
                            'airport': board_ap, 'type': ftype,
                            'message': 'date muss YYYY-MM-DD sein.'}), 400
        try:
            today_str = _fra_local_now().strftime('%Y-%m-%d')
        except Exception:
            today_str = ''
        if date_param != today_str:
            # BUGFIX 2026-06-13: Ankünfte werden jetzt EBENFALLS persistiert
            # (Store-Key '<AP>#ARR') → auch die Ankunfts-Historie vergangener Tage
            # ist abrufbar. Departures: '<AP>', Arrivals: '<AP>#ARR'.
            hist = _board_rows_from_obs_for_date(
                date_param, _store_key_for(board_ap, ftype), airline or None)
            return jsonify({'ok': True, 'airport': board_ap, 'type': ftype,
                            'date': date_param, 'count': len(hist[:limit]),
                            'flights': hist[:limit], 'departed_today': [],
                            'source': 'airport_delay_obs'})
    # ── RECENT-Tafel: „Früher heute" über die LETZTEN ~3 TAGE ───────────────
    # ?days=N (N=1..3) → die gespeicherten/abgeflogenen Flüge der letzten N
    # Betriebstage (heute + N-1 vorige) aus airport_delay_obs, gruppiert pro Tag.
    # Heute kommt aus dem In-Memory-Store (`_departed_rows_from_store`, wächst
    # live), vorige Tage rein aus der SB-Persistenz (`_board_rows_from_obs_for_date`).
    # So sieht die iOS-Tafel nicht nur den heutigen Verlauf, sondern auch gestern/
    # vorgestern, ohne pro Tag einen eigenen `?date=`-Call zu brauchen.
    days_param = (request.args.get('days') or '').strip()
    if days_param:
        try:
            ndays = max(1, min(int(days_param), 3))
        except Exception:
            ndays = 3
        from datetime import timedelta as _td
        try:
            base = _airport_local_now(_store_key_for(board_ap, ftype))
        except Exception:
            base = None
        if base is None:
            return jsonify({'ok': False, 'error': 'date_unavailable',
                            'airport': board_ap, 'type': ftype,
                            'message': 'Lokaldatum für ' + board_ap
                                       + ' nicht bestimmbar.'}), 200
        store_key = _store_key_for(board_ap, ftype)
        recent = []
        for i in range(ndays):
            d = (base - _td(days=i)).strftime('%Y-%m-%d')
            if i == 0:
                # Heute: live-wachsender In-Memory-Store (inkl. SB-Reload).
                day_rows = _departed_rows_from_store(store_key)
                if airline:
                    day_rows = [r for r in day_rows
                                if (r.get('airline') or '').upper() == airline]
            else:
                # Vorige Tage: rein aus der Persistenz.
                day_rows = _board_rows_from_obs_for_date(d, store_key, airline or None)
            recent.append({'date': d, 'count': len(day_rows[:limit]),
                           'flights': day_rows[:limit]})
        return jsonify({'ok': True, 'airport': board_ap, 'type': ftype,
                        'days': ndays, 'recent_days': recent,
                        'source': 'airport_delay_obs'})
    src = None
    flights = None
    if iata in ('FRA', 'EDDF') or airport in ('FRA', 'EDDF'):
        flights = _fra_board_cached(ftype)
        src = 'fraport'
        out_airport = 'FRA'
        # BUGFIX (User: „Tafel zeigt Flüge, aber nicht die alten/vergangenen"):
        # Der FRA-Pfad merged die aktuellen Abflüge bisher NIE in den Beobachtungs-
        # Store — nur der Native-Scraper-Pfad unten tat das. Folge: `departed_today`
        # und die persistente Historie (airport_delay_obs / vergangene Tage) blieben
        # für FRA dauerhaft LEER. Jetzt akkumuliert auch FRA bei jeder Abfrage →
        # abgeflogene Flüge wachsen über den Tag und bleiben (SB) erhalten.
        # BUGFIX 2026-06-13: AUCH Ankünfte persistieren (eigener Store-Key '<AP>#ARR'),
        # damit die Ankunfts-Tafel genauso eine „Früher heute"-Historie aufbaut.
        if flights:
            try:
                _merge_into_delay_store(
                    flights, _fra_local_now().strftime('%Y-%m-%d'),
                    _store_key_for('FRA', ftype))
            except Exception:
                pass
    else:
        out_airport = iata
        # 1) Native-Scraper (für die großen Bases) bzw. AeroDataBox-Board.
        # FREE-FIRST (Increment 2, Owner 2026-07-06): der User-Board-Request fasst
        # KEIN bezahltes AeroDataBox-Board an (allow_paid=False) — nur der gratis
        # native Scraper/FRA-Feed. Airports ohne freie Quelle degradieren ehrlich
        # (source_unavailable) statt pro Aufruf zu zahlen; die Hintergrund-Poller
        # (die die Tabellen füllen) behalten ihren bezahlten Default unverändert.
        rows, board_src = _native_board_cached(iata, ftype, allow_paid=False)
        if rows is not None:
            flights = rows
            src = board_src
            # Proaktive TAGES-Akkumulation wie bei FRA: abgeflogene Flüge in den
            # Delay-/Beobachtungs-Store mergen, damit die „Früher heute"-Ansicht
            # über den Tag WÄCHST und nichts verloren geht. Vorher akkumulierte
            # NUR FRA (`_fra_day_board_cached`) — die anderen deutschen Flughäfen
            # zeigten nur das Live-Fenster (User: „die Ankunfts-/Abflugstabellen
            # der deutschen Flughäfen speichern nicht alle ab").
            # BUGFIX 2026-06-13: ftype-Restriktion entfernt — Ankünfte landen unter
            # dem eigenen Store-Key '<AP>#ARR' (siehe _store_key_for), Abflüge wie
            # bisher unter '<AP>'. So baut JEDE Tafel (dep UND arr) ihre Historie auf.
            try:
                _merge_into_delay_store(
                    rows, _fra_local_now().strftime('%Y-%m-%d'),
                    _store_key_for(out_airport, ftype))
            except Exception:
                pass
        elif len(airport) == 4 and airport.startswith('ED'):
            # 2) Letzter Fallback: OpenSky (nur ICAO, zuletzt geflogene Flüge).
            flights = _fetch_opensky_board(airport, ftype)
            src = 'opensky'
    if flights is None:
        # GRACEFUL DEGRADE (User „bei der Tafel fehlen wieder Flüge"): bevor wir
        # eine LEERE Tafel / source_unavailable melden, die zuletzt erfolgreich
        # zusammengestellte Liste für GENAU diese Abfrage servieren (als `stale`
        # markiert). So bleibt die Tafel auch bei einem transienten Quellen-Ausfall
        # gefüllt — die App liest weiter fertige, backend-zusammengestellte Infos.
        try:
            import time as _t_lg
            _lg = _BOARD_LAST_GOOD.get((out_airport, ftype, airline))
            if _lg and (_t_lg.time() - _lg[0]) < _BOARD_LAST_GOOD_MAX_AGE:
                _lg_flights = _lg[1] or []
                _lg_dep = _lg[2] or []
                return jsonify({'ok': True, 'airport': out_airport, 'type': ftype,
                                'count': len(_lg_flights[:limit]),
                                'flights': _lg_flights[:limit],
                                'departed_today': _lg_dep[:120],
                                'source': 'cache_stale', 'stale': True,
                                'stale_age_sec': int(_t_lg.time() - _lg[0])})
        except Exception:
            pass
        # Ehrlich: kein Native-Scraper getroffen, kein AeroDataBox-Key/leer.
        import os as _os
        if out_airport in ('FRA', 'EDDF'):
            msg = 'FRA-Board gerade nicht erreichbar.'
        elif not _os.environ.get('AERODATABOX_KEY') and iata not in _NATIVE_BOARD_SCRAPERS:
            msg = ('Keine Board-Daten für ' + out_airport
                   + ' (kein nativer Scraper, AeroDataBox-Key fehlt).')
        else:
            msg = 'Keine Board-Daten für ' + out_airport + ' (Quelle nicht erreichbar oder leer).'
        return jsonify({'ok': False, 'error': 'source_unavailable',
                        'airport': out_airport, 'type': ftype, 'message': msg}), 200
    if airline:
        flights = [f for f in flights if f.get('airline') == airline]
    # ── #29-FIX: STALE/abgeflogene Flüge aus der ANSTEHENDEN Tafel ziehen ────────
    # Der Fraport-/Scraper-Feed liefert ein Zeitfenster, das auch schon ABGEFLOGENE
    # Zeilen enthält (z.B. um 10:04 noch die 06:35-„geschlossen"). Nachts um 01:30
    # rutschten so die 18-19-Uhr-Flüge des Vortags als „anstehend" rein (User #29:
    # „was machen die Flüge hier wenn es schon 1:30 ist?"). Wir entfernen Flüge,
    # deren BESTE Zeit (esti sonst sched, beide tz-aware ISO mit Offset) deutlich in
    # der Vergangenheit liegt ODER deren Status klar „abgeflogen" sagt. Verspätete
    # Flüge bleiben sichtbar (zukünftige esti → behalten). Die herausgefilterten
    # landen automatisch in `departed_today` (sie sind im Beobachtungs-Store und
    # stehen dann nicht mehr in `live_keys`). Datums-bewusst → kein Tag-Übertrag.
    try:
        from datetime import datetime as _dtp, timezone as _tzp, timedelta as _tdp
        def _board_dt(s):
            if not s:
                return None
            t = str(s).strip().replace('Z', '+00:00')
            # „+0200" → „+02:00" für fromisoformat-Kompatibilität.
            if len(t) >= 5 and t[-5] in '+-' and t[-3] != ':':
                t = t[:-2] + ':' + t[-2:]
            try:
                dt = _dtp.fromisoformat(t)
            except Exception:
                return None
            # Nur tz-aware Zeiten (mit Offset, z.B. FRA „+02:00") sicher vergleichbar.
            # Naive Scraper-Zeiten OHNE Offset lassen wir ungefiltert (kein Tag-/TZ-
            # Ratespiel → keine Regression für Nicht-FRA-Boards).
            return dt if dt.tzinfo is not None else None
        _now_utc = _dtp.now(_tzp.utc)
        _stale_cut = _now_utc - _tdp(minutes=90)
        _gone = {'geschlossen', 'gestartet', 'abgeflogen', 'departed', 'gelandet',
                 'landed', 'closed', 'left', 'ges.', 'position verlassen'}
        def _is_past(f):
            st = (f.get('status') or '').strip().lower()
            bt = _board_dt(f.get('esti')) or _board_dt(f.get('sched'))
            if bt is not None and bt >= _now_utc:
                return False                      # Zukunft (inkl. verspätet) → behalten
            if st in _gone:
                return True                       # eindeutig weg
            if bt is not None and bt < _stale_cut:
                return True                       # > 90 min alt → weg/stale
            return False
        _just_removed = [f for f in flights if _is_past(f)]
        flights = [f for f in flights if not _is_past(f)]
    except Exception:
        _just_removed = []
    # „Früher heute" — bereits abgeflogene/angekommene Flüge aus der akkumulierten
    # Beobachtung, die NICHT mehr im Live-Feed stehen (dedup über flight+hh:mm).
    # BUGFIX 2026-06-13: jetzt für BEIDE Richtungen (Departures UND Arrivals) — die
    # Quelle ist der richtungs-spezifische Store-Key '<AP>' bzw. '<AP>#ARR'.
    departed = []
    try:
        live_keys = {((f.get('flight') or ''), (f.get('sched') or '')[11:16]) for f in flights}
        # GAP-FIX (User 2026-06-30: „Früher heute endet 7:30, jetzt 10:25 → Flüge
        # fehlen"): die gerade aus der ANSTEHENDEN Tafel herausgefilterten Stale-/
        # Abgeflogenen DIREKT in „Früher heute" übernehmen — nicht nur auf den
        # Store-Pfad verlassen (der erfasst frische Zeilen evtl. noch nicht). So
        # entsteht keine Lücke zwischen dem letzten „Früher heute" und dem ersten
        # anstehenden Flug.
        _seen = set()
        for dr in _just_removed:
            k = ((dr.get('flight') or ''), (dr.get('sched') or '')[11:16])
            if k not in live_keys and k not in _seen:
                _seen.add(k)
                departed.append(dr)
        for dr in _departed_rows_from_store(_store_key_for(out_airport, ftype)):
            k = ((dr['flight'], (dr['sched'] or '')[11:16]))
            if k not in live_keys and k not in _seen:
                _seen.add(k)
                departed.append(dr)
        if airline:
            departed = [d for d in departed if (d.get('airline') or '').upper() == airline]
        # Neueste zuerst (chronologisch absteigend) → „Früher heute" liest sauber
        # vom jüngsten zum ältesten, kein Loch in der Reihenfolge.
        departed.sort(key=lambda x: (x.get('sched') or ''), reverse=True)
    except Exception:
        departed = []
    # „Last-known-good" festhalten: die fertige, gemergte Liste für genau diese
    # Abfrage cachen, damit ein späterer Quellen-Ausfall (flights is None) diese
    # statt einer leeren Tafel servieren kann. Nur nicht-leere Boards merken.
    try:
        if flights:
            import time as _t_lgs
            _BOARD_LAST_GOOD[(out_airport, ftype, airline)] = (
                _t_lgs.time(), list(flights), list(departed))
            _cache_soft_cap(_BOARD_LAST_GOOD)
    except Exception:
        pass
    # Cross-Side-Enrich (Owner 2026-07-03): Abflug-Zeilen bekommen den Ankunfts-
    # Delay/-Status/-Gate ihres Ziels, Ankunfts-Zeilen den Abflug-Delay ihres
    # Origins — NUR aus bereits gecachten Boards (kein Fetch), rein additiv.
    try:
        flights_out = _board_cross_side_enrich(flights[:limit], ftype)
        departed_out = _board_cross_side_enrich(departed[:120], ftype)
    except Exception:
        flights_out = flights[:limit]
        departed_out = departed[:120]
    return jsonify({'ok': True, 'airport': out_airport, 'type': ftype,
                    'count': len(flights_out), 'flights': flights_out,
                    'departed_today': departed_out,
                    'source': src,
                    'cached_ttl': (_AIRPORT_BOARD_TTL if src == 'fraport'
                                   else _NATIVE_BOARD_TTL)})


# ── Einzelflug-Status (Flugnummer → Flugplan/Status) ──────────────────────
# Hintergrund (User-Brief): Im Radar zeigt ein Flug, der gerade KEIN ADS-B-Signal
# sendet (noch nicht gestartet / gelandet / keine ADS-B-Abdeckung), nur eine leere
# "nicht in der Luft"-Karte — obwohl der Flug auf der Abflugtafel und bei anderen
# Quellen auffindbar ist. Dieser Endpoint liefert den FLUGPLAN/STATUS eines
# einzelnen Fluges (Soll-Ab/-An, Route, Status, Gate/Terminal) aus derselben
# Quelle, die die Tafel nutzt: AeroDataBox (RapidAPI, env-gated AERODATABOX_KEY).
# KEINE Erfindung: ohne Key oder ohne Treffer → ehrlich ok=False + Klartext.

# AeroDataBox-Status-Strings → kompaktes Schema für die iOS-Karte. Wir geben den
# Roh-Status zusätzlich durch, die Kategorie ist nur eine Lesehilfe (kein Override).
def _flight_status_category(raw):
    s = (raw or '').strip().lower()
    if not s:
        return 'unknown'
    if 'cancel' in s or 'annull' in s:
        return 'cancelled'
    if 'arriv' in s or 'land' in s:
        return 'arrived'
    if 'enroute' in s or 'en route' in s or 'air' in s or 'departed' in s:
        return 'enroute'
    if 'board' in s:
        return 'boarding'
    if 'expected' in s or 'scheduled' in s or 'gate' in s or 'check' in s:
        return 'scheduled'
    if 'delay' in s:
        return 'delayed'
    if 'divert' in s:
        return 'diverted'
    return 'unknown'


def _aerodatabox_flight_by_number(number, date_iso=None):
    """Einzelflug via AeroDataBox /flights/number/{number}[/{date}] (RapidAPI,
    env-gated). number = IATA-Flugnummer ohne Leerzeichen, z.B. 'LH752'. Liefert
    ein kompaktes Dict (Soll-Ab/-An, Route, Status, Gate/Terminal) oder None
    (kein Key / Quelle down / kein Treffer → Caller degradiert ehrlich)."""
    import os as _os
    key = _os.environ.get('AERODATABOX_KEY')
    if not key:
        return None
    num = (number or '').upper().replace(' ', '').strip()
    if len(num) < 3:
        return None
    try:
        import requests
    except Exception:
        return None
    # /flights/number/{num} ohne Datum = heutiger/nächster Flug dieser Nummer.
    # Mit Datum (YYYY-MM-DD) gezielt der Flug an diesem Tag.
    base = 'https://aerodatabox.p.rapidapi.com/flights/number/' + num
    url = base + ('/' + date_iso if date_iso else '')
    try:
        r = requests.get(url,
                         params={'withAircraftImage': 'false',
                                 'withLocation': 'false'},
                         headers={'X-RapidAPI-Key': key,
                                  'X-RapidAPI-Host': 'aerodatabox.p.rapidapi.com'},
                         timeout=15)
        if r.status_code != 200:
            return None
        body = r.json()
    except Exception:
        return None
    # AeroDataBox liefert eine LISTE von Flügen (mehrere Tage/Legs). Wir nehmen
    # den ersten mit verwertbaren Zeiten.
    items = body if isinstance(body, list) else [body]
    if not items:
        return None
    for f in items:
        out = _aerodatabox_parse_flight(f, fallback_number=num)
        if out is not None:
            return out
    return None


def _aerodatabox_parse_flight(f, fallback_number=''):
    """Ein rohes AeroDataBox-Flight-Objekt → kompaktes Karten-Dict (gleiches
    Schema wie das Airport-Board / `/api/flight/<token>/status`). None, wenn das
    Objekt keine verwertbare Zeit ODER Route trägt. Gemeinsam genutzt von
    `_aerodatabox_flight_by_number` und `_aerodatabox_flight_by_reg`, damit beide
    Pfade exakt dasselbe Schema liefern (keine Doppel-Pflege)."""
    def _t(node):
        n = node or {}
        return ((n.get('local') or n.get('utc')) or None)
    try:
        if not isinstance(f, dict):
            return None
        dep = f.get('departure') or {}
        arr = f.get('arrival') or {}
        dep_ap = dep.get('airport') or {}
        arr_ap = arr.get('airport') or {}
        sched_dep = _t(dep.get('scheduledTime'))
        sched_arr = _t(arr.get('scheduledTime'))
        est_dep = (_t(dep.get('revisedTime')) or _t(dep.get('predictedTime'))
                   or _t(dep.get('actualTime')))
        est_arr = (_t(arr.get('revisedTime')) or _t(arr.get('predictedTime'))
                   or _t(arr.get('actualTime')))
        raw_status = (f.get('status') or '').strip()
        al = f.get('airline') or {}
        acft = f.get('aircraft') or {}
        out = {
            'flight': (f.get('number') or fallback_number or '').strip(),
            'airline': (al.get('iata') or al.get('icao') or '').strip().upper(),
            'airline_name': (al.get('name') or '').strip(),
            'dep_iata': (dep_ap.get('iata') or '').strip().upper(),
            'dep_name': _clean_city_name(dep_ap.get('name'),
                                         (dep_ap.get('iata') or '')),
            'arr_iata': (arr_ap.get('iata') or '').strip().upper(),
            'arr_name': _clean_city_name(arr_ap.get('name'),
                                         (arr_ap.get('iata') or '')),
            'sched_dep': (sched_dep or '').replace(' ', 'T') or None,
            'sched_arr': (sched_arr or '').replace(' ', 'T') or None,
            'est_dep': ((est_dep or '').replace(' ', 'T') or None),
            'est_arr': ((est_arr or '').replace(' ', 'T') or None),
            'dep_gate': (dep.get('gate') or '').strip(),
            'dep_terminal': (dep.get('terminal') or '').strip(),
            'arr_gate': (arr.get('gate') or '').strip(),
            'arr_terminal': (arr.get('terminal') or '').strip(),
            'arr_baggage': (arr.get('baggageBelt') or '').strip(),
            'status': raw_status,
            'status_category': _flight_status_category(raw_status),
            'aircraft': (acft.get('model') or '').strip(),
            'reg': (acft.get('reg') or '').strip(),
        }
        # Verspätung (Abflug) aus Soll vs. erwartet, wie im Board.
        out['dep_delay_min'] = _board_delay_min(out['sched_dep'], out['est_dep'])
        # Mindestens eine verwertbare Zeit ODER Route nötig, sonst skip.
        if out['sched_dep'] or out['sched_arr'] or out['dep_iata'] or out['arr_iata']:
            return out
    except Exception:
        return None
    return None


def _aerodatabox_flight_by_reg(registration, date_iso=None):
    """DEPRECATED (2026-06-07): NICHT mehr im by-reg-Pfad verdrahtet. Der
    /api/aircraft/<token>/by-reg-Endpoint nutzt jetzt ausschließlich OpenSky
    (permanent gratis, kein RapidAPI-Key). Diese Funktion bleibt nur stehen, weil
    sie sich `_aerodatabox_parse_flight` mit dem flight-by-NUMBER-Pfad teilt; sie
    wird nirgends mehr aufgerufen.

    Aktueller/nächster Flug einer Tail-Registration via AeroDataBox
    /flights/reg/{registration}[/{date}] (RapidAPI, env-gated). registration =
    Tail wie 'D-AIXG'. Liefert dasselbe kompakte Dict wie
    `_aerodatabox_flight_by_number` (Route, Soll-/erwartete Zeiten, Status,
    Gate/Terminal, dep_delay_min) oder None (kein Key / Quelle down / kein
    Treffer → Caller degradiert ehrlich, KEINE Erfindung).

    Das ist die Tier-1-Quelle des iOS-Live-Fliegers: Tail bekannt → woher kommt
    sie, wann landet sie, welcher Status — VOR jedem Flugnummer-/ADS-B-Fallback."""
    import os as _os
    key = _os.environ.get('AERODATABOX_KEY')
    if not key:
        return None
    reg = (registration or '').upper().replace(' ', '').strip()
    if len(reg) < 3:
        return None
    try:
        import requests
    except Exception:
        return None
    base = 'https://aerodatabox.p.rapidapi.com/flights/reg/' + reg
    url = base + ('/' + date_iso if date_iso else '')
    try:
        r = requests.get(url,
                         params={'withAircraftImage': 'false',
                                 'withLocation': 'false'},
                         headers={'X-RapidAPI-Key': key,
                                  'X-RapidAPI-Host': 'aerodatabox.p.rapidapi.com'},
                         timeout=15)
        if r.status_code != 200:
            return None
        body = r.json()
    except Exception:
        return None
    items = body if isinstance(body, list) else [body]
    if not items:
        return None
    for f in items:
        out = _aerodatabox_parse_flight(f, fallback_number='')
        if out is not None:
            return out
    return None


@app.route('/api/flight/<token>/status', methods=['GET'])
def flight_status(token):
    """Einzelflug-Status/-Flugplan nach Flugnummer. Query: ?number=LH752&date=YYYY-MM-DD
    (date optional). Quelle: AeroDataBox (dieselbe wie die Airport-Tafel). Ehrlich:
    ohne AERODATABOX_KEY oder ohne Treffer → ok=False + Klartext, KEINE Erfindung.

    Genutzt vom Radar/Flug-Detail, wenn der Flug gerade KEIN ADS-B-Signal sendet:
    dann zeigt die App statt einer leeren Karte den echten Flugplan/Status."""
    import os as _os
    number = (request.args.get('number') or '').upper().replace(' ', '').strip()
    date_iso = (request.args.get('date') or '').strip() or None
    if date_iso:
        import re as _re
        if not _re.match(r'^\d{4}-\d{2}-\d{2}$', date_iso):
            date_iso = None
    if len(number) < 3:
        return jsonify({'ok': False, 'error': 'bad_number',
                        'message': 'Keine gültige Flugnummer.'}), 200

    def _merged_status_fallback():
        """GRATIS-Fallback über den zentralen Dual-Side-Resolver (Owner-Direktive
        2026-07-03): Strecke aus der eigenen Beobachtungs-DB (airport_delay_obs)
        lernen, dann Boards/Warehouse BEIDER Seiten mergen. Liefert ein Flight-
        Dict im selben Schema wie der AeroDataBox-Pfad (nur ehrlich befüllte
        Felder; Zeiten sind Flughafen-ORTSZEIT wie auf den Tafeln) oder None."""
        dep = arr = None
        if SB_AVAILABLE and sb is not None:
            try:
                q = sb.table('airport_delay_obs').select(
                    'airport,dest_iata,date').eq('flight', number)
                if date_iso:
                    q = q.eq('date', date_iso)
                r = q.order('date', desc=True).limit(20).execute()
                rows = r.data or []
                dep_rec = next((x for x in rows
                                if '#' not in (x.get('airport') or '')), None)
                arr_rec = next((x for x in rows
                                if '#' in (x.get('airport') or '')), None)
                if dep_rec:
                    dep = (dep_rec.get('airport') or '').split('#')[0] or None
                    arr = (dep_rec.get('dest_iata') or '').upper() or None
                elif arr_rec:
                    arr = (arr_rec.get('airport') or '').split('#')[0] or None
                    dep = (arr_rec.get('dest_iata') or '').upper() or None
            except Exception:
                pass
        try:
            # free_only=True (Increment 2): KEIN AeroDataBox-Spend im Merge —
            # dieser Fallback ist jetzt der PRIMÄRE (freie) Status-Pfad.
            m = _flight_obs_merged(number, date=date_iso,
                                   dep_iata=dep, arr_iata=arr, free_only=True)
        except Exception:
            m = None
        if not m:
            return None
        raw_status = m.get('status') or ''
        return {
            'flight': number,
            'airline': m.get('airline') or '', 'airline_name': '',
            'dep_iata': m.get('dep_iata') or '', 'dep_name': m.get('origin_name') or '',
            'arr_iata': m.get('arr_iata') or '', 'arr_name': m.get('dest_name') or '',
            'sched_dep': m.get('sched_dep'), 'sched_arr': m.get('sched_arr'),
            'est_dep': m.get('esti_dep'), 'est_arr': m.get('esti_arr'),
            # Planmäßige Flugdauer (Minuten) — GRATIS aus Soll-Ab/-An abgeleitet,
            # sobald beide Seiten beobachtet sind (arr-Board am Ziel). TZ-korrekt.
            'duration_min': _sched_block_min(m.get('sched_dep'), m.get('dep_iata'),
                                             m.get('sched_arr'), m.get('arr_iata')),
            'dep_gate': m.get('gate_dep') or '', 'dep_terminal': m.get('terminal_dep') or '',
            'arr_gate': m.get('gate_arr') or '', 'arr_terminal': m.get('terminal_arr') or '',
            'arr_baggage': '',
            'status': ('cancelled' if m.get('cancelled') else raw_status),
            'status_category': ('cancelled' if m.get('cancelled')
                                else _flight_status_category(raw_status)),
            # Museums-Tail-Wächter (Owner 2026-07-12, LH781→D-ABTL): reg nur,
            # wenn die Reg kürzlich wirklich fliegend gesehen wurde — sonst
            # leer (iOS lässt die MASCHINE-Zeile dann ehrlich weg).
            'aircraft': m.get('aircraft') or '',
            'reg': ((m.get('reg') or '')
                    if _tail_recently_active(m.get('reg')) else ''),
            'dep_delay_min': m.get('dep_delay_min'),
            'arr_delay_min': m.get('arr_delay_min'),
            'delay_min': m.get('delay_min'), 'delay_side': m.get('delay_side'),
            'obs_sides': m.get('sides'),
        }

    # ── FREE-FIRST (Increment 2, Owner 2026-07-06): der zentrale Dual-Side-Merge
    #    (eigene Beobachtungs-DB airport_delay_obs + freie Live-Boards, free_only)
    #    ist jetzt PRIMÄR — kein AeroDataBox-Spend pro User-Request. ──
    merged = _merged_status_fallback()
    if merged:
        return jsonify({'ok': True, 'number': number, 'flight': merged,
                        'source': 'aerox_obs_merged'})
    # ── BEZAHLT (letzter Notnagel): FR24 flight-summary NUR mit Token UND Budget.
    #    AeroDataBox gestrichen (Owner 2026-07-09 „forget aerodatabox" — der Key
    #    war eh 403 tot). Den aufgelösten Flug (Route+Tail+Typ+Ist-Zeiten) spiegeln
    #    wir ins Warehouse → derselbe Flug kommt beim nächsten Lookup GRATIS.
    #    FR24 flight-summary ≈ 2 Credits, hart gecacht (Zero-Double-Spend). Gate/
    #    Soll-Zeiten kennt flight-summary nicht — dafür bleiben Board/Warehouse. ──
    from blueprints.aerox_data_blueprint import (_fr24_available,
                                                 _fr24_flight_by_number)
    if _fr24_available():
        flight = _fr24_flight_by_number(number, date_iso)
        if flight:
            try:
                _crowdsource_flight_obs(flight, date_iso, source='fr24')
            except Exception:
                pass
            return jsonify({'ok': True, 'number': number, 'flight': flight,
                            'source': 'fr24'})
    return jsonify({'ok': False, 'error': 'not_found', 'number': number,
                    'message': ('Für ' + number + ' liegt aktuell kein '
                                'Flugplan vor.')}), 200


def _icao_to_iata_best(code):
    """ICAO-Airport-Code → IATA, best-effort über die DE-Map; sonst der Code
    unverändert (iOS hat eine eigene umfangreichere AirportDB für die Anzeige)."""
    if not code:
        return None
    c = code.strip().upper()
    return _DE_ICAO_TO_IATA.get(c, c)


@app.route('/api/aircraft/<token>/by-reg', methods=['GET'])
def aircraft_by_reg(token):
    """Live-Position/Inbound-Status nach Tail-REGISTRATION — OpenSky-only
    (permanent gratis, funktioniert ANONYM; KEINE bezahlte Flug-API).

    Query: ?reg=D-AIXG  (date wird ignoriert — OpenSky liefert ist-Daten, keine
    Termin-Pläne; der Parameter bleibt für Client-Abwärtskompatibilität erlaubt).

    Wasserfall (ehrlich, nichts erfunden):
      Reg → Hex (resolve_reg_to_hex: Supabase tail_hex → hartkodierte Map).
        kein Hex → state='unknown', source='unknown' (kein Fehler, leise).
      Tier 1 (live):   OpenSky /states/all?icao24=hex → Position (lat/lng/alt/…).
      Tier 2 (flights):OpenSky /flights/aircraft (letzte ~36h) → jüngster Flug →
                       Inbound-Herkunft (estDepartureAirport) + Ziel + last-seen.
                       OpenSky gibt HISTORISCHE Flüge, KEINE geplante ETA — wir
                       erfinden keine eta_minutes.
      Tier 3 (cache):  aircraft_positions letzte bekannte Position (mit Alter).
      Tier 4:          unknown.

    Response: {ok, registration, hex, state, position?, inbound_from_icao?,
               eta_minutes?, source:'live'|'flights'|'cache'|'unknown', fetched_at}.
    Niemals ein bezahlter Provider als source. Stale wird NIE als aktuell verkauft."""
    import time
    reg = (request.args.get('reg') or '').upper().replace(' ', '').strip()
    if len(reg) < 3:
        return jsonify({'ok': False, 'error': 'bad_reg', 'registration': reg,
                        'message': 'Keine gültige Registrierung.'}), 200

    # Blueprint-Helfer (Reg→Hex, OpenSky-Fetch, Cache). Soft-Import: wenn das
    # Blueprint nicht geladen ist, degradieren wir ehrlich auf 'unknown'.
    try:
        from blueprints.adsb_blueprint import (
            resolve_reg_to_hex, fetch_live_state, fetch_recent_flight,
            _touch_watch,
        )
    except Exception:
        resolve_reg_to_hex = fetch_live_state = fetch_recent_flight = None
        _touch_watch = None

    now_unix = time.time()
    base = {'ok': True, 'registration': reg, 'hex': None, 'state': 'unknown',
            'source': 'unknown', 'fetched_at': now_unix}
    # WAREHOUSE-FIRST (Owner 2026-07-07): der aktuelle Flug DIESES Tails (Richtung
    # egal, Hin ODER Rück) aus den gescrapten Board-Obs — trägt das ECHTE Ziel
    # („auf dem Weg nach GRU"), das OpenSky fast nie kennt. Immer mitliefern, auch
    # ohne Hex/Live-Position; die iOS-Karte baut daraus „Dein Flieger ist auf dem
    # Weg nach <Stadt>". fr24 bleibt nur Backup (route_for_flight-Kaskade).
    base['current_flight'] = _warehouse_latest_flight_for_reg(reg)

    if resolve_reg_to_hex is None:
        return jsonify(base), 200

    hex_id = resolve_reg_to_hex(reg)
    if not hex_id:
        # Tail unbekannt → leise unknown, KEINE Fehlermeldung (Spec).
        return jsonify(base), 200
    base['hex'] = hex_id

    # Nutzer-getriebenes Watch-Set füttern: dieser User trackt gerade diese
    # Maschine → in adsb_watch upserten (priority=1 = explizit nachgefragt),
    # damit der Shared-Poller sie aufnimmt. Best-effort, bricht by-reg nie.
    if _touch_watch is not None:
        try:
            _touch_watch(hex_id, registration=reg, priority=1)
        except Exception:
            pass

    # ── Tier 1: Live-Position (OpenSky → adsb.lol) ──
    row = None
    try:
        row = fetch_live_state(hex_id)
    except Exception:
        row = None
    if row and isinstance(row, (list, tuple)) and len(row) > 6:
        lat = row[6]
        lon = row[5]
        if lat is not None and lon is not None:
            on_ground = bool(row[8]) if len(row) > 8 and row[8] is not None else False
            vel_ms = row[9] if len(row) > 9 else None
            try:
                gs_kts = round(float(vel_ms) / 0.514444, 1) if vel_ms is not None else None
            except (TypeError, ValueError):
                gs_kts = None
            alt_m = row[7] if len(row) > 7 else None
            try:
                alt_ft = round(float(alt_m) / 0.3048) if alt_m is not None else None
            except (TypeError, ValueError):
                alt_ft = None
            heading = row[10] if len(row) > 10 else None
            out = dict(base)
            out['state'] = 'at_gate' if on_ground else 'in_flight'
            out['source'] = 'live'
            out['position'] = {
                'lat': lat, 'lng': lon,
                'altitude_ft': alt_ft,
                'ground_speed_kts': gs_kts,
                'heading': heading,
                'on_ground': on_ground,
            }
            # Inbound-Herkunft best-effort aus dem jüngsten Flug anreichern
            # (keine ETA — OpenSky liefert keine geplante Ankunft).
            try:
                fl = fetch_recent_flight(hex_id)
            except Exception:
                fl = None
            if fl and fl.get('est_departure_icao'):
                out['inbound_from_icao'] = fl['est_departure_icao']
            out['flight'] = _by_reg_legacy_flight(out, fl)
            _by_reg_board_enrich(out, fl)   # Dual-Side-Board additiv (out['board'])
            # fr24-BACKUP für das ECHTE Ziel: kennt das Warehouse den aktuellen Flug
            # nicht (Out-of-Network / Reg nicht gescrapt), holt fr24 ihn über die
            # gerade aufgelöste Live-Position — „Dein Flieger ist auf dem Weg nach X".
            if not out.get('current_flight') and not on_ground:
                cs_live = (str(row[1]).strip() if len(row) > 1 and row[1] else None)
                out['current_flight'] = _fr24_current_flight_for_reg(
                    reg, hex_id, cs_live, lat, lon)
            return jsonify(out), 200

    # ── Tier 2: Letzter/aktueller Flug (historisch, keine ETA) ──
    fl = None
    try:
        fl = fetch_recent_flight(hex_id)
    except Exception:
        fl = None
    if fl and (fl.get('est_departure_icao') or fl.get('est_arrival_icao')):
        out = dict(base)
        out['source'] = 'flights'
        # Airborne vs. abgeschlossen: wenn der Track noch "frisch" endet (<10min),
        # behandeln wir ihn als in_flight, sonst als gelandet. KEINE eta_minutes.
        last_seen = fl.get('last_seen_unix')
        try:
            age = now_unix - float(last_seen) if last_seen is not None else None
        except (TypeError, ValueError):
            age = None
        if age is not None and age < 600:
            out['state'] = 'in_flight'
        else:
            out['state'] = 'landed'
        if fl.get('est_departure_icao'):
            out['inbound_from_icao'] = fl['est_departure_icao']
        if last_seen is not None:
            out['last_seen_unix'] = last_seen
        out['flight'] = _by_reg_legacy_flight(out, fl)
        _by_reg_board_enrich(out, fl)       # Dual-Side-Board additiv (out['board'])
        return jsonify(out), 200

    # ── Tier 3: Letzte bekannte Position aus aircraft_positions (mit Alter) ──
    if SB_AVAILABLE:
        try:
            r = (sb.table('aircraft_positions').select('*')
                 .eq('registration', reg).limit(1).execute())
            rows = r.data or []
        except Exception:
            rows = []
        if rows:
            rec = rows[0]
            lat = rec.get('latitude')
            lon = rec.get('longitude')
            fetched_at_iso = rec.get('fetched_at')
            cache_age = None
            if fetched_at_iso:
                try:
                    dt = datetime.fromisoformat(str(fetched_at_iso).replace('Z', '+00:00'))
                    if dt.tzinfo is None:
                        dt = dt.replace(tzinfo=timezone.utc)
                    cache_age = (datetime.now(timezone.utc) - dt).total_seconds()
                except (ValueError, TypeError):
                    cache_age = None
            # Nur < 24h als "letzte bekannte Position" zeigen — älter ist wertlos.
            if lat is not None and lon is not None and (cache_age is None or cache_age < 24 * 3600):
                alt_m = rec.get('altitude_m')
                try:
                    alt_ft = round(float(alt_m) / 0.3048) if alt_m is not None else None
                except (TypeError, ValueError):
                    alt_ft = None
                out = dict(base)
                out['state'] = 'landed' if rec.get('on_ground') else 'in_flight'
                out['source'] = 'cache'
                out['position'] = {
                    'lat': lat, 'lng': lon,
                    'altitude_ft': alt_ft,
                    'ground_speed_kts': rec.get('ground_speed_kts'),
                    'heading': rec.get('heading_deg'),
                    'on_ground': rec.get('on_ground'),
                }
                if rec.get('last_seen_unix') is not None:
                    out['last_seen_unix'] = rec.get('last_seen_unix')
                if cache_age is not None:
                    out['cache_age_seconds'] = int(cache_age)
                out['flight'] = _by_reg_legacy_flight(out, None)
                return jsonify(out), 200

    # ── Tier 4: unknown ──
    return jsonify(base), 200


def _by_reg_legacy_flight(out, fl):
    """Baut ein `flight`-Dict im alten /status-Schema aus dem neuen OpenSky-
    Waterfall-Ergebnis — damit ältere iOS-Builds (die `resp.flight.dep_iata`
    lesen) NICHT brechen, während neue Builds die expliziten Top-Level-Felder
    (inbound_from_icao/state/source) nutzen. EHRLICH: keine erfundenen Zeiten —
    nur was wir aus OpenSky kennen (Inbound-Origin, Status-Kategorie)."""
    inbound_icao = out.get('inbound_from_icao')
    dep_iata = _icao_to_iata_best(inbound_icao) if inbound_icao else ''
    arr_iata = ''
    if fl and fl.get('est_arrival_icao'):
        arr_iata = _icao_to_iata_best(fl['est_arrival_icao']) or ''
    state = out.get('state')
    status_category = {
        'in_flight': 'enroute', 'at_gate': 'scheduled',
        'landed': 'arrived', 'scheduled': 'scheduled',
    }.get(state, '')
    return {
        'flight': (fl.get('callsign').strip() if fl and fl.get('callsign') else ''),
        'dep_iata': dep_iata or '',
        'dep_name': '',
        'arr_iata': arr_iata,
        'arr_name': '',
        'sched_dep': None, 'sched_arr': None,
        'est_dep': None, 'est_arr': None,
        'status': state or '',
        'status_category': status_category,
        'reg': out.get('registration', ''),
    }


def _by_reg_board_enrich(out, fl):
    """Dual-Side-Board/Warehouse-Anreicherung des by-reg-Live-Fliegers (Owner-
    Direktive 2026-07-03: „Live-Flieger, Inbound-Flieger — alle anbinden"):
    OpenSky liefert nur Callsign + Herkunft/Ziel-ICAO, KEINE Zeiten/Delays. Der
    zentrale Resolver holt dazu die Board-/Warehouse-Sicht BEIDER Seiten (Soll/
    Erwartet, dep-/arr-Delay, Gates, Status, Cancelled) — rein gratis
    (free_only=True, kein AeroDataBox-Spend auf dem heißen Radar-Pfad). Additives
    Feld out['board'] (None-frei nur bei Treffer); die bestehenden Felder
    (state/position/flight) bleiben unangetastet. Wirft nie."""
    try:
        cs = ((fl or {}).get('callsign') or '').strip().upper()
        if len(cs) < 3:
            return
        fn = _wh_callsign_to_iata_flightno(cs) or cs
        def _ap3(icao):
            x = _icao_to_iata_best(icao) if icao else None
            return x if (x and len(x) == 3 and x.isalpha()) else None
        dep = _ap3((fl or {}).get('est_departure_icao'))
        arr = _ap3((fl or {}).get('est_arrival_icao'))
        merged = _flight_obs_merged(fn, dep_iata=dep, arr_iata=arr,
                                    free_only=True)
        if merged:
            out['board'] = merged
    except Exception:
        pass


def _warehouse_latest_flight_for_reg(reg):
    """Owner 2026-07-07 („der Scraping-Backend zeigt Hin- UND Rückflug, nutz das,
    fr24 nur Backup"): findet aus den GESCRAPTEN Board-Beobachtungen
    (airport_delay_obs) den aktuellen/jüngsten Flug DIESES Tails — Richtung egal.
    Eine ABFLUG-Beobachtung trägt airport=Start + dest_iata=Ziel + reg → daraus
    baut die App „Dein Flieger ist auf dem Weg nach <Stadt>". Funktioniert auch
    dann, wenn OpenSky den Tail gar nicht kennt (kein Hex nötig). Rein Warehouse,
    kein bezahlter Provider. Returns dict | None.
    """
    reg_u = (reg or '').strip().upper()
    if len(reg_u) < 3 or not (SB_AVAILABLE and sb is not None):
        return None
    try:
        import datetime as _dt2
        today = _dt2.date.today()
        dates = [today.isoformat(), (today - _dt2.timedelta(days=1)).isoformat()]
        # Reg steht je nach Board mit/ohne Bindestrich (D-AIMA vs DAIMA) — beide.
        reg_variants = list({reg_u, reg_u.replace('-', '')})
        r = (sb.table('airport_delay_obs')
             .select('date,airport,flight,sched,esti,dest_iata,dest_name,'
                     'status,max_delay_min,cancelled,updated_at')
             .in_('reg', reg_variants)
             .in_('date', dates)
             .order('updated_at', desc=True)
             .limit(30).execute())
        rows = r.data or []
        # NUR echte Abflug-Rows belegen die Richtung: gespiegelte '<AP>#ARR'-Rows
        # tragen dest_iata=HERKUNFT (Board-Konvention) → sonst Richtung invertiert.
        deps = [x for x in rows
                if (x.get('dest_iata') or '').strip()
                and '#' not in (x.get('airport') or '')]
        if not deps:
            return None
        x = deps[0]   # frischeste (updated_at desc)
        dest = (x.get('dest_iata') or '').strip().upper()
        dep = (x.get('airport') or '').strip().upper()
        _city = None
        if dest and not (x.get('dest_name') or '').strip():
            try:
                from blueprints.aerox_data_blueprint import _iata_city_name
                _city = _iata_city_name(dest)
            except Exception:
                _city = None
        return {
            'dep_iata': dep or None,
            'dest_iata': dest or None,
            'dest_name': (x.get('dest_name') or '').strip() or _city,
            'flight': (x.get('flight') or '').strip().upper() or None,
            'sched': x.get('sched'),
            'esti': x.get('esti'),
            'status': (x.get('status') or '').strip() or None,
            'delay_min': x.get('max_delay_min'),
            'cancelled': bool(x.get('cancelled')),
            'date': x.get('date'),
            'source': 'warehouse',
        }
    except Exception:
        return None


def _fr24_current_flight_for_reg(reg, hex_id, callsign, lat, lon):
    """fr24-BACKUP (Owner 2026-07-07 „fr24 nur als Backup"): kennt das Warehouse den
    aktuellen Flug DIESES Tails NICHT (Out-of-Network-Leg wie HND→GRU, Reg nicht
    gescrapt), holt fr24 über die bereits aufgelöste LIVE-POSITION (lat/lon aus
    OpenSky) die ECHTE Route (dep→dest) — auch über Russland/Ozean/Asien. Nur mit
    Position (fr24-Live-Feed ist area-basiert). Returns dict | None.
    """
    if lat is None or lon is None:
        return None
    # resolve_route_live (schnell, EIN fr24-Call) statt detail_card (2× Calls, bis
    # 35s → Worker-Starvation-Risiko). Nur die Route (dep→dest). Die Ankunftszeit
    # („landet HH:MM") liefert ohnehin die axInboundChain-Kette der Karte, nicht
    # dieser by-reg-Pfad.
    try:
        from blueprints import fr24_grpc
        g = fr24_grpc.resolve_route_live(callsign=callsign, hex=hex_id, reg=reg,
                                         lat=lat, lon=lon)
    except Exception:
        g = None
    if not g:
        return None
    dep = (g.get('src') or '').strip().upper() or None
    dest = (g.get('dst') or '').strip().upper() or None
    if not dest:
        return None
    dest_name = None
    try:
        from blueprints.aerox_data_blueprint import _iata_city_name
        dest_name = _iata_city_name(dest)
    except Exception:
        dest_name = None
    return {
        'dep_iata': dep,
        'dest_iata': dest,
        'dest_name': dest_name,
        'flight': (g.get('flight_number') or callsign or '').strip().upper() or None,
        'sched': None, 'esti': None, 'status': None,
        'delay_min': None, 'cancelled': False, 'date': None,
        'source': 'fr24',
    }


# Fraport-Status-Strings, die "annulliert/gestrichen" bedeuten.
_FRA_CANCEL_MARKERS = ('annull', 'cancel', 'gestrich')

# Mindest-Stichprobe (abgeflogene Flüge), ab der eine Pünktlichkeits-Quote als
# aussagekräftig gilt. Darunter → data_incomplete (UI: "Daten unvollständig"),
# statt eine irreführende 100%-über-7-Flüge-Zahl zu behaupten.
_PUNCTUALITY_MIN_SAMPLE = 15

# Verspätungs-Schwelle (Minuten) für „delayed". MUSS identisch zur Live-Board-
# Flag (`delayed = _fra_delay_min(...) >= _DELAY_THRESHOLD_MIN`) sein, sonst
# wechselt das Urteil eines Fluges, sobald er aus dem Live-Feed in den Store-Replay
# wandert (live „verspätet" → replay „pünktlich") → springende Quote + falsche
# Tabellen-Klassifikation. Eine Quelle der Wahrheit für alle Pünktlichkeits-Pfade:
# _DELAY_THRESHOLD_MIN (15 Min = übliche D15-OTP-Definition, siehe oben).
_PUNCTUALITY_DELAY_THRESHOLD_MIN = _DELAY_THRESHOLD_MIN

def _is_cancelled(f):
    return any(m in (f.get('status') or '').lower() for m in _FRA_CANCEL_MARKERS)


def _flight_sched_passed(f, now_local):
    """True wenn der geplante Abflug (`sched`) bereits in der Vergangenheit liegt
    (bzw. unparsbar → wir zählen ihn konservativ als bekannt). Annullierte gelten
    immer als 'bekannt'. now_local = naive Europe/Berlin-Zeit."""
    if _is_cancelled(f):
        return True
    if now_local is None:
        return True
    sdt = _parse_local_iso(f.get('sched'))
    if sdt is None:
        return True
    return sdt <= now_local


# ── Daten-Ehrlichkeit: „Unbekannt ≠ Pünktlich" (2026-07-03, LH400-Bug) ───────
# airport_delay_obs hält max_delay_min als int — 0 heißt dort aber ZWEIERLEI:
# „nachweislich pünktlich" ODER „nie ein Delay-Signal gesehen". Flüge stehen im
# +27h-Feed schon VOR Abflug (delay 0 mangels esti); geht das finale Update
# (esti/departed) in einer Poll-Lücke/SB-Flake verloren, blieb fälschlich 0 =
# App sagte „Pünktlich" ohne jedes Wissen (LH400 FRA→JFK 2026-07-02: real +86,
# dep-Row sagte 0). Diese Helfer entscheiden, ob eine Beobachtung ihren Delay
# WIRKLICH kennt:
#   (a) es gab ein Delay-Signal (esti gesetzt ODER max_delay > 0),
#   (b) die Row wurde mit IST-Status beobachtet (departed/landed/„Pünktlich"),
#   (c) der Flug war bis sched+_DELAY_KNOWN_CONFIRM_MIN noch im LIVE-Feed
#       sichtbar ohne esti → echtes „pünktlich" (nur zur Beobachtungszeit
#       feststellbar — siehe _merge_into_delay_store bzw. src=='live' in
#       _row_delay_known; aus alten SB-Rows NICHT rekonstruierbar).
# Cancelled zählt immer als bekannt. Alles andere = UNBEKANNT → die Read-Seite
# liefert delay_min: null statt 0 (iOS zeigt „keine Daten" statt „Pünktlich").
_DELAY_KNOWN_CONFIRM_MIN = 20   # Min. nach sched: „noch sichtbar ohne esti" = bestätigt pünktlich

# IST-Status-Marker (substring, lowercase) — Abflug- vs. Ankunfts-Kontext ist
# KRITISCH: bei einer ANKUNFTS-Row heißt „departed/unterwegs" nur, dass der
# Flieger seinen HERKUNFTS-Airport verlassen hat — der ANKUNFTS-Delay (die
# Metrik dieser Row) ist damit noch unbekannt. Deutsch UND Englisch, weil die
# Quellen gemischt normalisieren (Fraport→DE, native/EU-Scraper teils EN).
_DELAY_KNOWN_STATUS_DEP = ('abgeflogen', 'gestartet', 'departed', 'airborne',
                           'lifted', 'pünktlich', 'punktlich', 'on time',
                           'ontime')
_DELAY_KNOWN_STATUS_ARR = ('gelandet', 'landed', 'arrived', 'on position',
                           'on blocks', 'at gate', 'pünktlich', 'punktlich',
                           'on time', 'ontime')


def _obs_status_actual(status, is_arr):
    """True wenn der Status ein IST-/Abschluss-Status der jeweiligen Seite ist
    (Kriterium (b)). 'Verspätet' OHNE esti zählt bewusst NICHT — dann wissen wir
    zwar „spät", aber nicht WIE spät (Wert bleibt unbekannt, ehrlich)."""
    s = (status or '').strip().lower()
    if not s:
        return False
    markers = _DELAY_KNOWN_STATUS_ARR if is_arr else _DELAY_KNOWN_STATUS_DEP
    return any(m in s for m in markers)


def _obs_delay_known(max_delay, cancelled, esti, status, is_arr, flag=None):
    """True = der Delay dieser Beobachtung ist WIRKLICH bekannt (Regeln oben).
    `flag` = explizites delay_known aus dem Meta-Store; nur True zählt — ein
    fehlendes/False-Flag fällt auf die Signal-Rekonstruktion zurück, damit
    SB-geladene Alt-Rows (ohne Flag, das Flag ist nicht persistierbar — die
    Tabelle hat keine jsonb-Spalte, kein DDL) mit esti/IST-Status weiterhin
    als bekannt gelten."""
    if flag:
        return True
    if cancelled:
        return True
    try:
        if int(max_delay or 0) > 0:
            return True
    except Exception:
        pass
    if isinstance(esti, str) and esti.strip():
        return True
    return _obs_status_actual(status, is_arr)


def _row_delay_known(row, is_arr, src=None, ap=None):
    """delay_known einer ZEILE im Row-Builder-/Board-Format. Obs-Zeilen tragen
    das Flag bereits ('delay_known' aus _departed_rows_from_store /
    _board_rows_from_obs_for_date); Live-Zeilen werden aus ihren Signalen
    beurteilt + Kriterium (c): noch im Live-Feed sichtbar nach sched+Puffer
    ohne esti = bestätigt pünktlich (NUR src=='live' — für Warehouse-Rows wäre
    „jetzt > sched" trivialerweise immer wahr und damit gelogen)."""
    if row is None:
        return False
    flag = row.get('delay_known')
    if flag is not None:
        return bool(flag)
    if _obs_delay_known(row.get('delay_min'), row.get('cancelled'),
                        row.get('esti'), row.get('status'), is_arr):
        return True
    if src == 'live':
        try:
            from datetime import timedelta as _tdk
            sdt = _parse_local_iso(row.get('sched'))
            nl = _airport_local_now(ap) if ap else None
            if sdt is not None and nl is not None:
                return nl >= sdt + _tdk(minutes=_DELAY_KNOWN_CONFIRM_MIN)
        except Exception:
            pass
    return False


# Tages-keyed Verspätungs-Store: (date_str, flight_no, sched_hhmm) → max beobachtete Verspätung (min).
# Wird bei jedem Board-Rebuild gemergt (nur max, nie zurückgesetzt bis 05:00 Rollover).
_delay_store: dict = {}
_delay_store_date: str = ''  # YYYY-MM-DD des aktuellen Betriebstages
# Cancelled-Flüge separat (key (date_str, fn, hhmm) → True), damit der SB-Write-
# Through pro Flug genau eine Row (max_delay_min + cancelled-Flag) schreiben kann.
_delay_store_cancelled: dict = {}
# Marker: welche (Betriebstag|Airport)-Kombis bereits aus airport_delay_obs (SB)
# geladen wurden. Verhindert, dass jeder Punctuality-/Resolver-Call die SB-Tabelle
# erneut voll liest. WAR ein einzelner String (nur die LETZTE Kombi gemerkt) —
# sobald zwei Store-Keys alternierend lasen (Route-History dep+arr, Dual-Side-
# Resolver), las JEDER Call die volle Tages-Tabelle neu (SB-Roundtrip-Thrash).
# Jetzt ein Set, exakt wie der Docstring es immer meinte („einmal pro Betriebstag
# UND Airport"). Tagesrollover leert das Set (siehe _merge_into_delay_store).
_delay_store_sb_loaded_date: set = set()

# Persistenz-Diagnose (vom /api/health/full exponiert). Ein still
# fehlschlagender Write-Through war die Wurzel des "Pünktlichkeit verschwindet"-
# Bugs — die Fail-Counter + last-error machen das jetzt sichtbar, ohne dass man
# in Cloud-Run-Logs graben muss.
_delay_obs_write_fail_count: int = 0
_delay_obs_write_ok_count: int = 0
_delay_obs_load_fail_count: int = 0
_delay_obs_last_error: str = ''

# ── Requeue-Puffer für endgültig gescheiterte Warehouse-Writes (2026-07-03) ──
# Root-Cause-Nachwehe des RemoteProtocolError-Vorfalls: scheitert ein Row-Upsert
# TROTZ der Transport-Retries (längerer SB-Ausfall), war die Beobachtung bisher
# STILL weg — der In-Memory-Store stirbt mit der Instanz (Deploys!), FRA hatte
# dadurch 08:00–10:00 lokal keine Flüge im Warehouse. Jetzt landet jede endgültig
# gescheiterte Row in dieser begrenzten FIFO-Deque und wird beim nächsten
# Persist-Durchlauf (Scheduler-Poll /api/internal/scrape-boards, jeder
# _merge_into_delay_store, EU-Fill) ZUERST erneut geschrieben. Der Upsert ist
# idempotent (UPDATE-dann-INSERT auf den Key date/airport/flight/sched), ein
# Doppel-Write konvergiert also.
#
# EHRLICHE GRENZE: der Puffer ist in-process/in-memory — ein Instanz-Neustart
# oder Deploy während eines SB-Ausfalls verliert ihn. Das ist bewusst so (kein
# Disk-Spool auf Cloud-Run-ephemeral); der Puffer überbrückt den häufigen Fall
# "SB minutenlang down, Instanz lebt weiter".
import collections as _dobs_collections
_DELAY_OBS_PENDING_CAP = 2000          # FIFO-Cap: Ältestes fliegt (mit Log)
_DELAY_OBS_PENDING_MAX_AGE_S = 24 * 3600  # älter als 24h → Drop (mit Log)
_delay_obs_pending: _dobs_collections.deque = _dobs_collections.deque()
# Deque-Ops sind GIL-atomar, aber Drain+Re-Add im Flush braucht einen Lock
# (Poller-Thread vs. Request-Threads schreiben beide). Zweiter Lock als
# Flush-Guard, damit zwei parallele Poll-Durchläufe nicht denselben Batch
# doppelt abarbeiten (non-blocking acquire → einer flusht, der andere skippt).
_delay_obs_pending_lock = _req_threading.Lock()
_delay_obs_flush_guard = _req_threading.Lock()
_delay_obs_requeue_count: int = 0      # Diagnose (kumulativ eingereiht)
_delay_obs_flush_ok_count: int = 0     # Diagnose (kumulativ nachgeholt)
_delay_obs_pending_dropped: int = 0    # Diagnose (Cap-/Alters-Drops)

# ── Finalizer: die delay_known=False-Liste aktiv leerräumen (2026-07-03) ──────
# OWNER-DIREKTIVE „Es muss einfach funktionieren, dann ist es immer richtig":
# delay_known ist ab jetzt die ARBEITSLISTE eines Finalizers, KEIN User-Label.
# Jeder Flug, der real längst ab/gelandet ist, aber ohne bestätigten Delay-Wert
# im Store hängt, wird VOR dem User aktiv aufgelöst — zuerst gratis (Gegenseite/
# gecachte Boards/OpenSky-ADS-B), und wenn nach sched+GIVEUP_H trotzdem keine
# Quelle etwas meldet, konservativ als pünktlich (delay_min=0) GESCHLOSSEN statt
# ewig unbekannt zu bleiben. Läuft am Ende jedes /scrape-boards-Ticks (~15 min).
_DELAY_FINALIZE_AFTER_MIN = 30         # sched + 30min lokal → Flug ist real durch
# 2026-07-03: 45 → 30. Verkürzt die „unbekannt"-Lücke frisch abgeflogener Flüge um
# 15 Min OHNE Risiko einer Fehl-Schließung: AFTER_MIN steuert NUR, ab wann der
# Finalizer eine Row ÜBERHAUPT aufzulösen VERSUCHT (Gegenseite/gecachte Boards/
# ADS-B). Der einzige Pfad, der eine Row als pünktlich SCHLIESST ohne Signal, ist
# der Give-up-Zweig (d) — und der bleibt hart an _DELAY_STALE_GIVEUP_H (6h) gekoppelt.
# Ein noch nicht abgeflogener (verspäteter) Flug matcht in ADS-B/Boards nicht →
# resolved bleibt None → er wird NICHT geschlossen, sondern im nächsten Zyklus erneut
# probiert. Die delay_known-Invariante (nur echte Signale setzen delay_known früh)
# bleibt damit unberührt. Crossside/gecachte-Boards sind sofort frisch; der OpenSky-
# Zweig greift erst, wenn OpenSky den Flug verarbeitet hat (Latenz) — ein früherer
# Versuch schadet nie, er trifft nur früher, sobald das Signal da ist.
_DELAY_STALE_GIVEUP_H = 6              # sched + 6h ohne Quelle → als pünktlich (0) schließen
# Obergrenze fürs Scannen: Rows, die älter als _DELAY_FINALIZE_MAX_AGE_H nach sched
# sind, werden GAR NICHT mehr als Kandidat aufgenommen. Grund: sie sind längst durch,
# ein Delay-Wert kommt garantiert nicht mehr, und ein gaveup=0-Abschluss ist nach
# Instanz-Restart NICHT als „bekannt" rekonstruierbar (airport_delay_obs hat keine
# delay_known-jsonb-Spalte; _obs_delay_known liest delay_min=0 wieder als „unbekannt").
# Ohne diese Grenze re-gaveupt jeder Restart alle heutigen offenen Rows erneut
# (1 WARNING + 1 SB-Write pro Row pro Restart). Es gehen KEINE echten Delays verloren:
# Rows mit echtem Delay>0 / cancelled / esti / actual-status sind bereits delay_known
# und werden VOR dem Alters-Gate aussortiert — nur signal-lose Rows erreichen es, und
# die werden ohnehin als pünktlich (0) geschlossen.
_DELAY_FINALIZE_MAX_AGE_H = 12         # sched + 12h → nicht mehr scannen (durch, kein Re-Gaveup)
_DELAY_FINALIZE_OPENSKY_CAP = 40       # max OpenSky-Airport/Richtungs-Fetches pro Durchlauf
# Hartes Tages-Sub-Cap: der Finalizer zieht aus DEMSELBEN OPENSKY_FILL_DAILY_CAP-Topf
# (1500/Tag) wie die EU-Warehouse-Fill (_opensky_fill_airport). Über ~96 Läufe/Tag
# könnte er den Topf sonst leerfressen und die EU-Fill aushungern. Darum darf der
# Finalizer HÖCHSTENS _DELAY_FINALIZE_OPENSKY_DAILY OpenSky-Fetches/Tag machen —
# geprüft VOR dem Fetch. Bei 400 bleiben garantiert ≥ 1100 des Topfes für die
# EU-Fill übrig, egal in welcher Reihenfolge die beiden laufen. Die gratis
# Crossside-/Boards-Auflösung ist davon NICHT betroffen (kein Spend).
_DELAY_FINALIZE_OPENSKY_DAILY = 400    # max OpenSky-Fetches/Tag (Reserve für EU-Fill)
_DELAY_FINALIZE_OS_BUDGET = {'day': '', 'calls': 0}  # prozess-lokaler Tageszähler
_DELAY_FINALIZE_MAX_ROWS = 300         # Soft-Cap verarbeiteter Unknowns pro Durchlauf (FIFO)
_delay_finalize_ok_count: int = 0      # Diagnose (kumulativ aufgelöst)
_delay_finalize_gaveup_count: int = 0  # Diagnose (kumulativ als pünktlich geschlossen)
# Non-blocking Guard wie beim Flush: zwei parallele Poll-Durchläufe sollen den
# Finalizer nicht doppelt fahren; Netz-Calls laufen außerhalb jedes Store-Locks.
_delay_finalize_guard = _req_threading.Lock()


def _delay_finalize_opensky_budget_ok(inc=0):
    """Tages-Sub-Budget-Guard für die OpenSky-Fetches des Finalizers. Zählt die
    Fetches des Finalizers separat (prozess-lokal, UTC-Tag) und deckelt sie hart
    auf _DELAY_FINALIZE_OPENSKY_DAILY — VOR dem Fetch geprüft. So kann der
    Finalizer höchstens diesen Anteil des gemeinsamen OPENSKY_FILL_DAILY_CAP-Topfes
    verbrauchen; der Rest bleibt garantiert der EU-Warehouse-Fill. Mit inc>0 wird
    gezählt. True solange noch Finalizer-Sub-Budget frei ist."""
    import time as _t
    day = _t.strftime('%Y%m%d', _t.gmtime())
    if _DELAY_FINALIZE_OS_BUDGET['day'] != day:
        _DELAY_FINALIZE_OS_BUDGET['day'] = day
        _DELAY_FINALIZE_OS_BUDGET['calls'] = 0
    if inc:
        _DELAY_FINALIZE_OS_BUDGET['calls'] += inc
    return _DELAY_FINALIZE_OS_BUDGET['calls'] < _DELAY_FINALIZE_OPENSKY_DAILY


def _delay_obs_requeue(date_str, fn, hhmm, max_delay, cancelled, airport,
                       status, meta):
    """Reiht eine endgültig gescheiterte Delay-Beobachtung in den Pending-Puffer
    ein (FIFO, Cap → ältester Eintrag fliegt LAUT raus). Läuft nur aus dem
    except-Pfad von _delay_obs_write_through — nie aus dem Flush selbst."""
    global _delay_obs_requeue_count, _delay_obs_pending_dropped
    dropped = 0
    with _delay_obs_pending_lock:
        while len(_delay_obs_pending) >= _DELAY_OBS_PENDING_CAP:
            _delay_obs_pending.popleft()
            dropped += 1
        _delay_obs_pending.append({
            'ts': time.time(),
            'date_str': date_str, 'fn': fn, 'hhmm': hhmm,
            'max_delay': max_delay, 'cancelled': cancelled,
            'airport': airport, 'status': status,
            'meta': dict(meta or {}),
        })
        pending_n = len(_delay_obs_pending)
    _delay_obs_requeue_count += 1
    if dropped:
        _delay_obs_pending_dropped += dropped
        app.logger.warning(
            f'[delay-obs] pending buffer FULL (cap={_DELAY_OBS_PENDING_CAP}) — '
            f'dropped {dropped} oldest rows')
    app.logger.warning(
        f'[delay-obs] requeued 1 rows (pending={pending_n}) '
        f'date={date_str} airport={airport} flight={fn} sched={hhmm}')


def _delay_obs_flush_pending():
    """Flusht den Pending-Puffer nach airport_delay_obs — wird zu Beginn JEDES
    Persist-Durchlaufs gerufen (_merge_into_delay_store, _scrape_boards_once,
    _opensky_fill_airport), also spätestens beim nächsten Scheduler-Poll.
    Erfolgreich geschriebene Einträge verlassen den Puffer; erneut gescheiterte
    bleiben (FIFO-Reihenfolge erhalten); älter als 24h → Drop mit Log.
    Idempotent (Upsert per Key) → ein doppelter Flush konvergiert. No-op wenn
    der Puffer leer ist (der Normalfall — nur ein len-Check)."""
    global _delay_obs_flush_ok_count, _delay_obs_pending_dropped
    if not _delay_obs_pending:
        return
    if not SB_AVAILABLE or sb is None:
        return  # kein SB → Einträge bleiben liegen, nächster Durchlauf probiert
    if not _delay_obs_flush_guard.acquire(blocking=False):
        return  # ein anderer Thread flusht gerade — nicht doppelt abarbeiten
    try:
        with _delay_obs_pending_lock:
            batch = list(_delay_obs_pending)
            _delay_obs_pending.clear()
        if not batch:
            return
        now = time.time()
        ok = 0
        aged = 0
        kept = []
        for e in batch:
            try:
                if now - float(e.get('ts') or 0) > _DELAY_OBS_PENDING_MAX_AGE_S:
                    aged += 1
                    continue
                if _delay_obs_write_through(
                        e['date_str'], e['fn'], e['hhmm'], e['max_delay'],
                        e['cancelled'], e['airport'], e['status'],
                        e.get('meta'), requeue_on_fail=False):
                    ok += 1
                else:
                    kept.append(e)  # bleibt im Puffer, nächster Durchlauf
            except Exception:
                kept.append(e)  # defensiv: unerwarteter Fehler → behalten
        if kept:
            # Vorne wieder einreihen (FIFO bleibt: kept ist ältest-zuerst,
            # extendleft dreht die Reihenfolge → vorher umkehren). Neue Fails,
            # die WÄHREND des Flushs eingereiht wurden, hängen dahinter.
            with _delay_obs_pending_lock:
                _delay_obs_pending.extendleft(reversed(kept))
        _delay_obs_flush_ok_count += ok
        if aged:
            _delay_obs_pending_dropped += aged
            app.logger.warning(
                f'[delay-obs] dropped {aged} pending rows older than 24h')
        app.logger.warning(
            f'[delay-obs] flushed {ok}/{len(batch)} pending '
            f'(kept={len(kept)}, dropped_age={aged})')
    finally:
        _delay_obs_flush_guard.release()

# VOLLE Flug-Felder pro Beobachtung (dest/gate/terminal/airline/esti). Der
# _delay_store hält nur das max_delay (int) pro Key — die reichen Felder kommen
# vom Live-Board und werden hier parallel gehalten, damit die Historie (vergangene
# Tage / „Früher heute") von→nach + Gate/Terminal zurückgeben kann. Key = derselbe
# (date, airport, flight, sched)-Tupel wie _delay_store. Best-effort: SB-Load
# füllt das auch aus persistierten Rows zurück, falls vorhanden.
_delay_store_meta: dict = {}


def _delay_obs_write_through(date_str, fn, hhmm, max_delay, cancelled, airport,
                             status, meta=None, requeue_on_fail=True):
    """Best-effort Write-Through einer Delay-Beobachtung nach airport_delay_obs.
    Mirror des wall-posts/disk-Patterns: SB-down/Tabelle-fehlt → still degrade,
    der In-Memory-Store bleibt die Wahrheit. Nur max-Wert (upsert überschreibt,
    aber wir schreiben hier bereits das laufende Maximum aus dem Store).

    Fehler werden LAUT (logger.warning) geloggt + in einem Fail-Counter gehalten,
    damit ein dauerhaft scheiternder Write (Schema-Mismatch, RLS, SB down) im
    /api/health/full sichtbar wird statt still die Tages-Stichprobe zu verlieren.

    Scheitert der Write endgültig (nach den Transport-Retries), wandert die Row
    zusätzlich in den Pending-Puffer (_delay_obs_requeue) und wird beim nächsten
    Persist-Durchlauf nachgeholt — außer requeue_on_fail=False (der Flush-Pfad
    selbst, der gescheiterte Einträge ohnehin behält). Rückgabe: True = in SB
    persistiert, False = nicht (SB fehlt / Fehler)."""
    global _delay_obs_write_fail_count, _delay_obs_write_ok_count, _delay_obs_last_error
    if not SB_AVAILABLE or sb is None:
        return False
    payload = {
        'date': date_str,
        'airport': airport or 'FRA',
        'flight': fn,
        'sched': hhmm,
        'max_delay_min': int(max_delay or 0),
        'cancelled': bool(cancelled),
        'status': (status or None),
        'updated_at': datetime.now(timezone.utc).isoformat(),
    }
    # VOLLE Felder (dest/gate/terminal/airline/esti) best-effort mitschreiben, damit
    # die Historie von→nach + Gate/Terminal zeigen kann (nicht nur die Flugnummer).
    # Nur nicht-leere Werte ins Payload — so überschreibt ein späterer, ärmerer
    # Snapshot (Live-Feed ohne Gate kurz vor Abflug) einen früheren reichen NICHT
    # mit Leerstrings. Spalten sind nullable (Migration 20260614) → fehlt eine
    # Spalte in einer alten Tabelle, degradiert der Write still (Exception unten).
    meta = meta or {}
    for col in ('dest_iata', 'dest_name', 'gate', 'terminal', 'airline', 'esti',
                'reg', 'type_code', 'source'):
        v = (meta.get(col) or '')
        if isinstance(v, str):
            v = v.strip()
        if v:
            payload[col] = v
    # WRITE-ON-CHANGE (adaptiver Poll-Takt 2026-07-09): der bis-zu-3-min-Board-
    # Takt darf die SB-Writes nicht linear multiplizieren. Content-Hash der
    # OPERATIVEN Felder pro Row-Key im In-Process-Memo (poll_scheduler) —
    # unverändert seit dem letzten ERFOLGREICHEN Write → skippen; True ist
    # ehrlich („steht exakt so in SB"). Leeres Memo (Restart) → normal
    # schreiben; der Hash wird erst NACH Erfolg gemerkt (Fehler → Retry/Requeue
    # bleiben unangetastet). Import defensiv: fehlt das Modul, wird immer
    # geschrieben (Verhalten von vorher).
    try:
        from blueprints import poll_scheduler as _psched_woc
    except Exception:
        _psched_woc = None
    if _psched_woc is not None and not _psched_woc.obs_write_needed(payload):
        return True
    try:
        # BUGFIX 2026-06-13 (ROOT CAUSE „Tafel/Pünktlichkeit speichert nicht"):
        # `upsert(on_conflict='date,airport,flight,sched')` schlug in PROD bei JEDEM
        # Write mit Postgres 42P10 fehl („there is no unique or exclusion constraint
        # matching the ON CONFLICT specification") — die Live-Tabelle hatte den
        # zusammengesetzten Primary Key NICHT (Migration nie/early ohne PK angewandt,
        # `create table if not exists` no-opte danach). Folge: write_ok=0,
        # write_fail=132 → NICHTS wurde je persistiert, die Historie lebte nur im
        # flüchtigen In-Memory-Store einer Instanz und verschwand bei jedem Restart.
        #
        # Fix: manueller Upsert OHNE DB-seitige ON-CONFLICT-Abhängigkeit. Erst
        # UPDATE auf den Schlüssel; matchte keine Row → INSERT. Funktioniert auch
        # ohne den Unique-Key, also sofort nach Deploy — unabhängig davon, ob die
        # korrigierende Migration (20260613_*) schon im SQL-Editor lief.
        upd_fields = {'max_delay_min': payload['max_delay_min'],
                      'cancelled': payload['cancelled'],
                      'status': payload['status'],
                      'updated_at': payload['updated_at']}
        # reg/type_code/dest nur dann mit-aktualisieren, wenn dieser Snapshot sie
        # trägt — so reichert ein späterer reicher Board-Poll eine frühere Row an,
        # ohne sie bei einem ärmeren Poll wieder zu leeren.
        for col in ('reg', 'type_code', 'dest_iata', 'dest_name', 'airline',
                    'gate', 'terminal', 'esti', 'source'):
            if payload.get(col):
                upd_fields[col] = payload[col]
        try:
            upd = (sb.table('airport_delay_obs')
                   .update(upd_fields)
                   .eq('date', date_str).eq('airport', payload['airport'])
                   .eq('flight', fn).eq('sched', hhmm).execute())
            if not (upd.data or []):
                sb.table('airport_delay_obs').insert(payload).execute()
        except Exception as inner:
            # SCHEMA-SAFE FALLBACK: läuft die reg/type_code-Migration (20260623)
            # noch nicht, kennt PostgREST diese Spalten nicht (Fehler enthält
            # 'reg'/'type_code'/PGRST204/42703). Dann den Write OHNE die neuen
            # Spalten wiederholen — die Pünktlichkeits-/Delay-Daten dürfen NICHT
            # verloren gehen, nur weil die Aircraft-Spalten noch fehlen. Sobald die
            # Migration läuft, greift der reiche Pfad automatisch.
            msg = str(inner).lower()
            if ("type_code" in msg or "'reg'" in msg or '"reg"' in msg
                    or 'source' in msg
                    or 'pgrst204' in msg or '42703' in msg
                    or 'column' in msg):
                # Optionale (evtl. noch nicht migrierte) Spalten wegwerfen und den
                # Write wiederholen — die Route/Tail-/Delay-Daten dürfen nicht wegen
                # einer fehlenden Provenance-Spalte verloren gehen.
                _slim_drop = ('reg', 'type_code', 'source')
                slim_payload = {k: v for k, v in payload.items()
                                if k not in _slim_drop}
                slim_upd = {k: v for k, v in upd_fields.items()
                            if k not in _slim_drop}
                upd = (sb.table('airport_delay_obs')
                       .update(slim_upd)
                       .eq('date', date_str).eq('airport', payload['airport'])
                       .eq('flight', fn).eq('sched', hhmm).execute())
                if not (upd.data or []):
                    sb.table('airport_delay_obs').insert(slim_payload).execute()
            else:
                raise
        _delay_obs_write_ok_count += 1
        if _psched_woc is not None:
            _psched_woc.obs_mark_written(payload)
        return True
    except Exception as e:
        # Tabelle fehlt / SB down / Schema-Mismatch → ehrlich nur in-memory
        # weiter, kein Crash. ABER laut loggen + zählen, damit es nicht still
        # die Persistenz killt (Root-Cause "Pünktlichkeit verschwindet").
        _delay_obs_write_fail_count += 1
        _delay_obs_last_error = f'write {type(e).__name__}: {str(e)[:140]}'
        app.logger.warning(
            f'[delay-obs] sb_write_FAIL date={date_str} airport={airport} '
            f'flight={fn} sched={hhmm} {type(e).__name__}: {str(e)[:160]}')
        # Endgültig gescheitert (Transport-Retries sind bereits durch) → Row in
        # den Pending-Puffer, der nächste Persist-Durchlauf holt sie nach. Die
        # RemoteProtocolError-Stunden heute Morgen wären damit NICHT verloren
        # gegangen (solange die Instanz weiterlebte).
        if requeue_on_fail:
            try:
                _delay_obs_requeue(date_str, fn, hhmm, max_delay, cancelled,
                                   airport, status, meta)
            except Exception:
                pass  # Puffer darf den Write-Pfad nie crashen
        return False


def _crowdsource_flight_obs(flight, date_iso=None, source='aerodatabox'):
    """Eine KOMPLETTE, echte Flug-Beobachtung (Route + Tail) zurück ins Warehouse
    (`airport_delay_obs`) schreiben, damit derselbe Flug beim NÄCHSTEN Mal GRATIS
    aus unseren eigenen Daten kommt — statt den bezahlten Dienst (AeroDataBox) noch
    einmal zu treffen (Owner 2026-07-04: „damit man sich APIs spart … bevor wir
    falsche oder keine info rausgeben"). Das ist das Crowdsource-/Self-Growing-
    Prinzip: eine bezahlte ODER live beobachtete Auflösung füttert die geteilte DB,
    von der alle Crew/Freunde profitieren.

    DOMÄNENREGEL (hart, wie überall): NUR echte Beobachtungen. `reg` MUSS vorhanden
    sein (kein Tail → nichts zu crowdsourcen); nie geraten, nie ein per Turnaround
    ABGELEITETER (`tail_inferred`) Tail — der bleibt lokal. Best-effort, wirft nie.
    `flight` ist ein Karten-Dict im `_aerodatabox_parse_flight`-Schema (reg, dep_iata,
    arr_iata, sched_dep, aircraft, status, dep_delay_min). Rückgabe: True bei SB-Write.
    """
    try:
        if not isinstance(flight, dict):
            return False
        reg = (flight.get('reg') or '').strip()
        if not reg:
            return False                       # ohne echten Tail nichts zu speichern
        try:
            fn = _fn_norm(flight.get('flight') or '')
        except Exception:
            fn = None
        dep = (flight.get('dep_iata') or '').strip().upper()
        arr = (flight.get('arr_iata') or '').strip().upper()
        if not fn or len(fn) < 3 or len(dep) != 3 or not dep.isalpha():
            return False                       # ohne Flugnr+Abflug-Airport kein Key
        sched_dep = (flight.get('sched_dep') or '').strip()
        # date + hhmm aus sched_dep ableiten (ISO, evtl. lokal mit TZ), sonst date_iso.
        d = (str(date_iso or '')[:10]
             or (sched_dep[:10] if len(sched_dep) >= 10 else ''))
        hhmm = ''
        if 'T' in sched_dep:
            tp = sched_dep.split('T', 1)[1]
            if len(tp) >= 5 and tp[2] == ':':
                hhmm = tp[:5].replace(':', '')
        if not d:
            return False                       # ohne Datum kein sicherer Warehouse-Key
        cancelled = ((flight.get('status_category') or '') == 'cancelled'
                     or (flight.get('status') or '').strip().lower() == 'cancelled')
        meta = {
            'reg': reg,
            'type_code': (flight.get('aircraft') or '').strip() or None,
            'dest_iata': arr or None,
            'dest_name': (flight.get('arr_name') or '').strip() or None,
            'airline': (flight.get('airline') or '').strip() or None,
            'esti': (flight.get('est_dep') or '').strip() or None,
            'source': source,
        }
        return _delay_obs_write_through(
            d, fn, hhmm, int(flight.get('dep_delay_min') or 0), cancelled,
            dep, (flight.get('status') or None), meta=meta, requeue_on_fail=False)
    except Exception:
        return False


def _delay_store_load_from_sb(date_str, airport='FRA'):
    """Lädt die heutigen Delay-Beobachtungen aus airport_delay_obs zurück in den
    In-Memory-Store (einmal pro Betriebstag UND Airport). Damit überlebt die
    Tages-Stichprobe einen Cloud-Run-Restart und wächst cross-instance. Degradiert
    still wenn SB down ist oder die Tabelle fehlt — dann bleibt nur die
    in-memory-Sicht. Store-Keys sind airport-gekeyt, damit MUC/BER/FRA sich nicht
    gegenseitig kontaminieren.

    Ein SB-Read-Fehler wird LAUT (logger.warning) geloggt + gezählt — wenn der
    Load-on-Read bricht, überlebt die Tages-Stichprobe keinen Restart, also darf
    das nicht still passieren."""
    global _delay_store_sb_loaded_date, _delay_obs_load_fail_count, _delay_obs_last_error
    global _delay_store_meta
    if not SB_AVAILABLE or sb is None:
        return
    airport = (airport or 'FRA').upper()
    load_marker = date_str + '|' + airport
    if load_marker in _delay_store_sb_loaded_date:
        return  # heute+airport schon geladen
    try:
        offset = 0
        page = 1000
        while True:
            r = _sb_retry('delay_load',
                          lambda: (sb.table('airport_delay_obs').select('*')
                                   .eq('date', date_str).eq('airport', airport)
                                   .range(offset, offset + page - 1).execute()))
            rows = r.data or []
            for row in rows:
                fn = row.get('flight') or ''
                hhmm = row.get('sched') or ''
                if not fn or not hhmm:
                    continue
                key = (date_str, airport, fn, hhmm)
                md = int(row.get('max_delay_min') or 0)
                cxl = bool(row.get('cancelled'))
                # VOLLE Felder (dest/gate/terminal/airline/esti) aus der Row in den
                # Meta-Store laden, damit die Historie von→nach + Gate zeigen kann.
                # Alte Rows ohne diese Spalten liefern None → leere Strings.
                meta = {
                    'dest_iata': (row.get('dest_iata') or ''),
                    'dest_name': (row.get('dest_name') or ''),
                    'gate':      (row.get('gate') or ''),
                    'terminal':  (row.get('terminal') or ''),
                    'airline':   (row.get('airline') or ''),
                    'esti':      (row.get('esti') or ''),
                    'reg':       (row.get('reg') or ''),
                    'type_code': (row.get('type_code') or ''),
                    'status':    (row.get('status') or ''),
                }
                if any(v for v in meta.values()):
                    _delay_store_meta[key] = meta
                if md > 0:
                    _delay_store[key] = max(_delay_store.get(key, 0), md)
                elif not cxl:
                    # On-Time-Beobachtung (delay 0) ebenfalls in den Store laden, damit
                    # ein leeres Live-Board die volle Tages-Stichprobe behält und nicht
                    # nur die verspäteten Flüge zurückbekommt (sonst Quote zu pessimistisch).
                    _delay_store.setdefault(key, 0)
                if cxl:
                    _delay_store[(date_str, airport, fn, hhmm + '_cancelled')] = 1
            if len(rows) < page:
                break
            offset += page
        _delay_store_sb_loaded_date.add(load_marker)
        if len(_delay_store_sb_loaded_date) > 400:   # Soft-Cap (viele Airports/Tage)
            _delay_store_sb_loaded_date.clear()
            _delay_store_sb_loaded_date.add(load_marker)
    except Exception as e:
        # Load-on-Read gebrochen → Tages-Stichprobe übersteht keinen Restart.
        # Laut loggen + zählen statt still schlucken.
        _delay_obs_load_fail_count += 1
        _delay_obs_last_error = f'load {type(e).__name__}: {str(e)[:140]}'
        app.logger.warning(
            f'[delay-obs] sb_load_FAIL date={date_str} airport={airport} '
            f'{type(e).__name__}: {str(e)[:160]}')


def _board_type_code(f):
    """Best-effort ICAO/IATA-Typ-Code aus einer Board-Row. `type`/`type_code`
    sind schon kurz; `aircraft` ist je nach Quelle „A320" ODER „Airbus A320 neo".
    Nur kurze, code-artige Werte (≤8, keine Leerzeichen, alnum) durchlassen."""
    for k in ('type', 'type_code', 'aircraft'):
        v = (f.get(k) or '')
        if not isinstance(v, str):
            continue
        v = v.strip().upper()
        if v and len(v) <= 8 and ' ' not in v and v.replace('-', '').isalnum():
            return v
    return ''


# Plan-artige Board-Status (kein Ist/Actual) — Basis der Folgetags-Heuristik.
# Deckungsgleich mit _PRE_DEP_STATUS (case-insensitiv), plus die englischen
# Rohwerte, die manche EU-Quellen unnormalisiert liefern.
_PLAN_LIKE_STATUS = (_PRE_DEP_STATUS | {
    'estimated', 'delayed', 'verspätet', 'verspaetet', 'expected', 'new time',
    'new gate', 'departs', 'now'})


def _obs_service_day(sched, fallback_date, now_local=None,
                     status=None, esti=None, cancelled=False):
    """VERKEHRSTAG (nicht Poll-Tag) einer Board-Beobachtung als 'YYYY-MM-DD'.

    WHY (ROOT-CAUSE „Folgetags-Kontamination an der Quelle", 2026-07-15):
    airport_delay_obs.date wurde bisher mit dem POLL-Tag (`fallback_date`, meist
    „heute") gestempelt — der `_merge_into_delay_store`-Key ignorierte das Datum,
    das in `sched` bereits steckt. Der Fraport-/EU-Feed ankert das Board ab 05:00
    Ortszeit und listet auch die frühen Flüge des FOLGETAGS. Live-Beweis:
    am 2026-07-14 abends (upd 21:24) bekam „FRA#ARR date=2026-07-14" eine Row
    LH867 sched='08:45' status='Geplant' — das ist der LH867 vom 15. (Soll 08:45),
    fälschlich unter dem 14. abgelegt (ebenso LH1126). Die Lese-Seite musste das
    mit Kompensationen abfangen; hier wird die QUELLE sauber:

      1) Trägt `sched` ein volles, parsbares Datum (Fraport liefert
         '2026-07-16T05:10:00+0200', inkl. Datum im Flug-`id`), ist DAS der
         Verkehrstag — Poll-Tag egal. Fixt LH867 direkt.
      2) Liefert `sched` nur HH:MM (Quellen ohne Datum): konservative Heuristik.
         Liegt die Soll-Zeit >6 h in der VERGANGENHEIT (Airport-Lokalzeit) UND ist
         der Status plan-artig (Geplant/Scheduled/leer, KEIN esti/Ist) → die Row
         gehört zum FOLGETAG (date+1). Ein 08:45-„Geplant", das abends noch als
         geplant im Board steht, ist niemals der heutige Morgen-Flug.

    Flüge mit echtem Ist (departed/landed/esti/cancelled) bleiben IMMER beim
    heutigen `fallback_date` — nur unbestätigte Plan-Rows werden verschoben.
    """
    from datetime import datetime as _dt, timedelta as _td
    fb = str(fallback_date or '')[:10]
    s = str(sched or '')
    # 1) Volles Datum im sched → maßgeblicher Verkehrstag.
    if len(s) >= 10 and s[4] == '-' and s[7] == '-':
        d = s[:10]
        try:
            _dt.strptime(d, '%Y-%m-%d')
            return d
        except Exception:
            pass
    # 2) Nur HH:MM (kein Datum im sched) → Folgetags-Heuristik gegen fallback_date.
    if not fb:
        return fb
    if cancelled or (isinstance(esti, str) and esti.strip()):
        return fb  # echtes Ist/Prognose → heutiger Tag
    st = (status or '').strip().lower()
    if st and st not in _PLAN_LIKE_STATUS:
        return fb  # departed/landed/… → heutiger Tag
    hhmm = s[11:16] if len(s) >= 16 else s[:5]
    import re as _re
    if not _re.match(r'^\d{1,2}:\d{2}$', hhmm):
        return fb
    try:
        sched_dt = _dt.strptime(f'{fb}T{hhmm.zfill(5)}', '%Y-%m-%dT%H:%M')
    except Exception:
        return fb
    nl = now_local
    if nl is None:
        return fb
    if isinstance(nl, _dt) and nl.tzinfo is not None:
        nl = nl.replace(tzinfo=None)
    # Soll >6 h in der Vergangenheit + plan-artig → Row ist der FOLGETAG.
    if sched_dt <= nl - _td(hours=6):
        return (sched_dt + _td(days=1)).strftime('%Y-%m-%d')
    return fb


def _merge_into_delay_store(flights, date_str, airport='FRA'):
    """Mergt beobachtete Delays aus flights in den globalen _delay_store.
    Nur max-Wert pro Flug — nie zurücksetzen, nie aus dem Store löschen.
    Schreibt jede geänderte Beobachtung best-effort nach airport_delay_obs (SB)
    durch, sodass die Tages-Stichprobe cross-instance/cross-restart akkumuliert.
    SB-down/Tabelle-fehlt → still degrade auf rein-in-memory."""
    global _delay_store, _delay_store_date, _delay_store_cancelled
    global _delay_store_sb_loaded_date, _delay_store_meta
    airport = (airport or 'FRA').upper()
    # ZUERST liegen gebliebene Beobachtungen nachholen (Requeue-Puffer aus
    # endgültig gescheiterten Writes) — no-op wenn leer (der Normalfall).
    _delay_obs_flush_pending()
    if _delay_store_date != date_str:
        _delay_store.clear()
        _delay_store_cancelled.clear()
        _delay_store_meta.clear()
        _delay_store_date = date_str
        # Tagesrollover → SB-Load-Marker zurücksetzen, damit der neue Tag seine
        # (ggf. von anderen Instanzen bereits geschriebenen) Beobachtungen lädt.
        _delay_store_sb_loaded_date = set()
    # Beim ersten Merge eines neuen Tages+Airports: vorhandene SB-Beobachtungen
    # zurückladen (cross-instance Akkumulation), bevor wir die neuen mergen.
    _delay_store_load_from_sb(date_str, airport)
    try:
        # Flughafen-LOKALE Jetzt-Zeit (nicht Berlin) — sonst ist der `passed`-Check
        # für Nicht-Europa-Flughäfen um Stunden verschoben (siehe _airport_local_now).
        now_local = _airport_local_now(airport)
    except Exception:
        now_local = None
    for f in (flights or []):
        # Flugnummer kanonisch leerzeichen-frei + groß persistieren — manche
        # Scraper liefern sie mit Leerzeichen ('4Y 450'), aber /api/ax/flight-info
        # fragt no-space/upper ab ('4Y450'). Ohne Normalisierung blieb die MUC-/
        # Native-Scraper-Historie unauffindbar und der PK (date,airport,flight,sched)
        # spaltete denselben Flug in zwei Zeilen. Quelle bleibt unverändert — nur
        # der gespeicherte Key wird vereinheitlicht.
        fn = (f.get('flight') or f.get('flightNumber') or '').replace(' ', '').upper()
        sched = f.get('sched') or ''
        if not fn or not sched:
            continue
        # sched ist ISO: '2026-06-06T14:30:00' → [11:16] = 'HH:MM' als Diskriminator.
        # NICHT [:5] — das würde '2026-' liefern und alle Flüge desselben Tages kollidierten.
        hhmm = sched[11:16] if len(sched) >= 16 else sched
        # VERKEHRSTAG statt Poll-Tag (Folgetags-Kontaminations-Fix, s. _obs_service_day):
        # der Board-Feed listet ab 05:00 auch die frühen Flüge des Folgetags —
        # deren Row muss unter IHREM Datum landen, nicht unter „heute".
        row_date = _obs_service_day(
            sched, date_str, now_local,
            status=(f.get('status') or ''),
            esti=(f.get('esti') if isinstance(f.get('esti'), str) else ''),
            cancelled=bool(f.get('cancelled')))
        key = (row_date, airport, fn, hhmm)
        delay = f.get('delay_min') or 0
        cancelled = bool(f.get('cancelled'))
        # VOLLE Felder aus dem Live-Board festhalten (von→nach, Gate, Terminal,
        # Airline, esti) → die Historie kann später mehr als die Flugnummer zeigen.
        # Nur nicht-leere Werte mergen, damit ein späterer ärmerer Snapshot einen
        # früheren reichen nicht überschreibt (z.B. Gate fällt kurz vor Abflug weg).
        flight_meta = {
            'dest_iata': (f.get('dest_iata') or '').strip(),
            'dest_name': (f.get('dest_name') or '').strip(),
            'gate':      (f.get('gate') or '').strip(),
            'terminal':  (f.get('terminal') or '').strip(),
            'airline':   (f.get('airline') or '').strip(),
            'esti':      (f.get('esti') or '').strip() if isinstance(f.get('esti'), str) else '',
            'status':    (f.get('status') or '').strip(),
            # Aircraft-Identität aus dem Board festhalten (Tail-Reg + Typ-Code), damit
            # airport_delay_obs auch „welche Maschine flog Flug X" / „wo war Tail Y"
            # beantworten kann — bisher fielen reg/type still weg.
            'reg':       (f.get('reg') or f.get('aircraft_reg') or '').strip().upper()[:12],
            # `aircraft` ist je nach Quelle ein Typ-Code (A320) ODER ein langer
            # Modellname (Airbus A320) — nur kurze Codes als type_code übernehmen.
            'type_code': _board_type_code(f),
        }
        prev_meta = _delay_store_meta.get(key) or {}
        merged_meta = dict(prev_meta)
        meta_changed = False
        for mk, mv in flight_meta.items():
            if mv and mv != prev_meta.get(mk):
                merged_meta[mk] = mv
                meta_changed = True
        if merged_meta:
            _delay_store_meta[key] = merged_meta
        # DATEN-EHRLICHKEIT (LH400-Bug): wissen wir den Delay WIRKLICH? (a) Delay-
        # Signal (esti/delay>0), (b) IST-Status (departed/landed/Pünktlich), (c)
        # noch im Live-Feed sichtbar nach sched+Puffer ohne esti → bestätigt
        # pünktlich. Nur-vor-Abflug-gesehen ohne Signal = UNBEKANNT. Das Flag lebt
        # im Meta-Store (kein DDL — airport_delay_obs hat keine jsonb-Spalte) und
        # fließt über das meta-Dict auch durch den Requeue-Puffer; SB-persistierte
        # Rows werden read-seitig aus esti/status/delay/cancelled rekonstruiert.
        # Kriterium (c) ist dort ehrlich NICHT rekonstruierbar → nach einem
        # Restart degradiert so eine Row konservativ auf „unbekannt" (nie
        # fälschlich „bekannt"). Sticky: einmal True, nie wieder False.
        if not merged_meta.get('delay_known'):
            dk = _obs_delay_known(delay, cancelled, merged_meta.get('esti'),
                                  merged_meta.get('status'),
                                  airport.endswith('#ARR'))
            if not dk and now_local is not None:
                sdt_k = _parse_local_iso(sched)
                if sdt_k is not None:
                    from datetime import timedelta as _tdk
                    dk = now_local >= sdt_k + _tdk(
                        minutes=_DELAY_KNOWN_CONFIRM_MIN)
            merged_meta['delay_known'] = bool(dk)
            _delay_store_meta[key] = merged_meta
        # Nur bereits abgeflogene Flüge sind echte Tages-Beobachtungen. Zukunft NICHT
        # persistieren — sonst zählte ein leeres Live-Board sie später fälschlich als
        # on-time. (now_local None → defensiv alles aufnehmen, wie zuvor.)
        passed = (now_local is None) or _flight_sched_passed(f, now_local)
        changed = False
        # Persistenz-Regel (BUGFIX 2026-06-10 „abgeflogene Flüge verschwinden"):
        # Eine Beobachtung wird NUR festgehalten, wenn der Flug bereits ABGEFLOGEN
        # ist (passed) bzw. annulliert. Vorher schrieb der delay>0-Zweig auch noch
        # NICHT abgeflogene Flüge mit einer prognostizierten `esti`-Verspätung in
        # den Store/airport_delay_obs — ein Phantom-„departed". Schlimmer: war so
        # ein Key einmal mit einem flüchtigen Vorab-Delay gesetzt, konnte der
        # On-Time-Zweig ihn nach echtem (pünktlichem) Abflug NICHT mehr auf 0
        # korrigieren (`key not in _delay_store` war False) → der Flug blieb falsch
        # als „verspätet" markiert, während echte On-Time-Flüge, die der Poller im
        # engen Post-Sched-Fenster nicht erwischte, ganz fehlten → Stichprobe fiel
        # unter MIN_SAMPLE → „Daten unvollständig". Jetzt symmetrisch: erst ab
        # Abflug erfassen, dann Delay wachsen lassen ODER on-time (0) setzen.
        if passed and not cancelled:
            if delay and delay > 0:
                prev = _delay_store.get(key, 0)
                if delay > prev:
                    _delay_store[key] = delay
                    changed = True
            elif key not in _delay_store:
                # On-Time-Beobachtung eines abgeflogenen Fluges festhalten (delay 0).
                # Damit ein temporär leeres Live-Board die volle Tages-Stichprobe
                # behält, nicht nur die verspäteten/annullierten Flüge. Reale,
                # abgeschlossene Flüge — keine Erfindung.
                _delay_store[key] = 0
                changed = True
        if cancelled:
            _delay_store[(row_date, airport, fn, hhmm + '_cancelled')] = 1
            if not _delay_store_cancelled.get(key):
                _delay_store_cancelled[key] = True
                changed = True
        # Write-Through bei tatsächlicher Änderung (max gewachsen, neu on-time, neu
        # cancelled ODER neue/aktualisierte Voll-Felder) → wir hämmern die SB-Tabelle
        # nicht pro Board-Rebuild voll, halten aber dest/gate/terminal aktuell. Der
        # Meta-Write läuft nur für bereits erfasste (passed/cancelled) Flüge mit, also
        # nicht für reine Zukunfts-Snapshots (key noch nicht im Store).
        if changed or (meta_changed and (key in _delay_store
                                         or _delay_store_cancelled.get(key))):
            _delay_obs_write_through(
                row_date, fn, hhmm, _delay_store.get(key, 0),
                cancelled or bool(_delay_store_cancelled.get(key)),
                airport, f.get('status'), merged_meta)


def _punctuality_stats(flights, airport='FRA', airline=None):
    """Aggregiert on-time/delayed/cancelled über eine TAGES-Flugliste.

    STABILITÄTS-FIX: Die Quote basiert NUR auf Flügen, deren geplante Zeit bereits
    PASSIERT ist (sched <= jetzt) — also abgeschlossene/bekannte Flüge. Noch nicht
    abgeflogene Flüge (Zukunft im selben Tag) werden NICHT als 'on time' gezählt.
    Dadurch springt die Zahl beim Neu-Laden (09:00 vs 09:05) nicht mehr, sie wächst
    nur, wenn weitere Flüge tatsächlich abfliegen. Das Tages-Fenster selbst ist in
    `_fra_day_board_cached` ab 05:00 Ortszeit fixiert.

    `airport` keyt den Delay-Store und die SB-Persistenz, damit MUC/BER/HAJ ihre
    eigene Tages-Stichprobe akkumulieren (keine FRA-Kontamination) und genauso wie
    FRA cross-restart/cross-instance über airport_delay_obs wachsen.

    `airline` (IATA-Code wie LH/4Y/EW) — wenn gesetzt, zählt die Quote NUR Flüge
    dieser Airline. Der Caller filtert `flights` bereits airline-rein; dieser
    Parameter filtert ZUSÄTZLICH die Store-Replay-Nachzählung (departed Flüge aus
    _delay_store), die sonst über ALLE Airlines dieses Airports liefe — sonst
    sickern fremde Carrier (z.B. LH) in eine 4Y/EW-Quote ein."""
    airport = (airport or 'FRA').upper()
    airline = (airline or '').upper().strip()
    # Tages-Datum ermitteln und Delay-Store mergen. Load-on-Read: vorhandene
    # SB-Beobachtungen (airport_delay_obs) für heute zurückholen, damit die
    # Tages-Stichprobe einen Restart/Instanz-Wechsel überlebt — auch wenn die
    # aktuelle Flugliste leer ist (Quelle down). Beides degradiert still auf
    # rein-in-memory, wenn SB nicht erreichbar ist.
    try:
        today = _fra_local_now().strftime('%Y-%m-%d')
        # merge handhabt Rollover (clear) UND lädt vorhandene SB-Beobachtungen
        # zurück bevor es die neue Flugliste mergt.
        _merge_into_delay_store(flights, today, airport)
        # Defensiv: falls flights leer war (Quelle down) und der Store für heute
        # noch nie initialisiert wurde, trotzdem aus SB nachladen.
        _delay_store_load_from_sb(today, airport)
    except Exception:
        today = ''
    # Flughafen-lokale Jetzt-Zeit für den passed-Check (siehe _airport_local_now).
    now_local = _airport_local_now(airport)
    # Bahn/Bus (LH Express Rail / AIRail) raus — defensiv, falls ein Altbestand
    # aus dem Cache (vor dem Source-Filter gebaut) noch Zug-Zeilen enthält.
    flights = [f for f in (flights or []) if not _is_rail_or_bus(f)]
    # Nur bereits abgeflogene/bekannte Flüge in die Quote — Zukunft ignorieren.
    completed = [f for f in flights if _flight_sched_passed(f, now_local)]
    total = len(completed)
    cancelled = sum(1 for f in completed if _is_cancelled(f))
    delayed = sum(1 for f in completed if f.get('delayed') and not _is_cancelled(f))
    on_time = max(0, total - cancelled - delayed)
    avg_delay = 0
    delay_vals = [int(f.get('delay_min') or 0) for f in completed
                  if not _is_cancelled(f) and int(f.get('delay_min') or 0) > 0]
    if delay_vals:
        avg_delay = round(sum(delay_vals) / len(delay_vals))
    # Store-basierte Nachhol-Zählung: Flüge die aus der Tafel verschwunden sind
    # (departed) behalten ihr Urteil. Nur addieren was NICHT schon in completed ist.
    # Store-Keys sind airport-gekeyt — wir zählen NUR die heutigen Beobachtungen
    # DIESES Airports, sonst würden MUC-Flüge in eine FRA-Quote einsickern.
    if today:
        def _hhmm(s): return s[11:16] if s and len(s) >= 16 else s
        known_keys = {(today, airport, (f.get('flight') or ''), _hhmm(f.get('sched') or '')) for f in completed}
        for (d, ap, fn, sc), max_delay in list(_delay_store.items()):
            if sc.endswith('_cancelled'):
                continue  # cancelled separat
            if d != today or ap != airport:
                continue
            if (today, airport, fn, sc) in known_keys:
                continue  # schon oben gezählt
            # Airline-Filter (LH/4Y/EW): nur Flüge dieser Airline nachzählen, sonst
            # sickern fremde Carrier aus dem (airport-, nicht airline-gekeyten) Store
            # in eine airline-spezifische Quote ein.
            if airline:
                try:
                    al, _num = _split_flightno(fn)
                except Exception:
                    al = (fn[:2] if fn else '')
                if (al or '').upper() != airline:
                    continue
            # Dieser Flug hat geheilt — sein gespeichertes Max zurückholen.
            total += 1
            if max_delay >= _PUNCTUALITY_DELAY_THRESHOLD_MIN:
                delayed += 1
            else:
                on_time += 1
    active = max(0, total - cancelled)
    pct = round(100.0 * on_time / active, 0) if active > 0 else None
    # EHRLICHKEIT (User-Pain "7 Flüge, 0 verspätet → 100%"): bei zu kleiner
    # Stichprobe ist eine Pünktlichkeits-Quote nicht aussagekräftig. Statt eine
    # irreführende 100%-Zahl zu zeigen, flaggen wir data_incomplete → UI zeigt
    # "Daten unvollständig". Die volle Tages-Stichprobe wächst über Supabase-
    # Snapshots (airport_delay_obs) — bis genug Flüge abgeflogen sind bleibt's
    # ehrlich als unvollständig markiert.
    incomplete = active < _PUNCTUALITY_MIN_SAMPLE
    # VOLLER TAGES-FLUGPLAN als ehrlicher Kontext (User: „denkst du wirklich FRA
    # hat so wenig Abflüge?"). `total` zählt nur die BEREITS BEWERTETEN (abgeflogenen)
    # Flüge — früh am Tag/bei lückenhaftem Poller ist das wenig. `scheduled_total`
    # ist die GESAMTZAHL der heutigen Flüge in der Tages-Tafel (abgeflogen + noch
    # offen), damit die UI „18 von ~210 ausgewertet" statt nur „18 Flüge" zeigt und
    # die niedrige Zahl nicht als FRA-Tagesvolumen missverstanden wird.
    scheduled_total = len(flights)
    return {'total': total, 'on_time': on_time, 'delayed': delayed,
            'cancelled': cancelled, 'on_time_pct': pct, 'avg_delay_min': avg_delay,
            'sample_size': active, 'data_incomplete': incomplete,
            'min_sample': _PUNCTUALITY_MIN_SAMPLE,
            # EHRLICH: ab wann ein Flug als „verspätet" zählt (D15-Standard, 15 Min).
            'delay_threshold_min': _PUNCTUALITY_DELAY_THRESHOLD_MIN,
            'scheduled_total': scheduled_total}


def _delay_obs_rows_for_date(date_str, airport='FRA', dest_iata=None):
    """Liest ALLE persistierten Delay-Beobachtungen eines BELIEBIGEN (auch
    vergangenen) Betriebstags direkt aus airport_delay_obs — OHNE den
    In-Memory-Store (_delay_store) zu beruehren. Der Store haelt nur den heutigen
    Tag; fuer „zurueck in der Zeit" (iOS-Tabelle) muessen wir die SB-Tabelle
    selbst abfragen. Gibt eine flache Liste roher Rows zurueck (leere Liste bei
    SB-down/leer — der Caller degradiert dann ehrlich)."""
    if not SB_AVAILABLE or sb is None or not date_str:
        return []
    airport = (airport or 'FRA').upper()
    dest_iata = (dest_iata or '').upper().strip() or None
    out = []
    try:
        offset = 0
        page = 1000
        while True:
            q = (sb.table('airport_delay_obs').select('*')
                 .eq('date', date_str).eq('airport', airport))
            # Route-History kennt die Gegenseite bereits. Serverseitig filtern,
            # BEVOR paginiert wird, statt fuer grosse Hub-Tage alle 1000er-Seiten
            # zu laden und danach fast alles lokal wegzuwerfen.
            if dest_iata:
                q = q.eq('dest_iata', dest_iata)
            r = q.range(offset, offset + page - 1).execute()
            rows = r.data or []
            out.extend(rows)
            if len(rows) < page:
                break
            offset += page
    except Exception as e:
        app.logger.warning(
            f'[delay-obs] sb_date_read_FAIL date={date_str} airport={airport} '
            f'{type(e).__name__}: {str(e)[:160]}')
        return []
    return out


def _board_rows_from_obs_for_date(date_str, airport='FRA', airline=None,
                                  dest_iata=None):
    """Tafel-Zeilen eines BELIEBIGEN (auch vergangenen) Betriebstags aus den
    persistierten Beobachtungen (airport_delay_obs) rekonstruieren — für die
    iOS-Tafel „zurück in der Zeit" (#24: Tafeln pro Airport speichern → Historie).

    Gleiche sparse-Zeilenform wie `_departed_rows_from_store` (Flugnummer,
    Soll-Zeit, Verspätung/Status — KEIN Gate/Ziel, das hält die Tabelle nicht).
    Quelle ist airport-gekeyt ('<AP>' für Abflüge, '<AP>#ARR' für Ankünfte), also
    liefert auch ein Nicht-FRA-Flughafen seine eigenen gespeicherten Flüge — und
    seit 2026-06-13 AUCH die Ankunfts-Historie. Leere Liste bei SB-down/leer →
    Caller degradiert ehrlich."""
    is_arr = (airport or '').upper().endswith('#ARR')
    rows = _delay_obs_rows_for_date(date_str, airport, dest_iata=dest_iata)
    airline = (airline or '').upper().strip()
    out = []
    for row in rows:
        fn = row.get('flight') or ''
        sc = row.get('sched') or ''
        # sched ist als 'HH:MM' persistiert; nur valide Slots übernehmen.
        if not fn or not isinstance(sc, str) or len(sc) != 5:
            continue
        try:
            al, _num = _split_flightno(fn)
        except Exception:
            al = (fn[:2] if fn else '')
        if airline and (al or '').upper() != airline:
            continue
        cancelled = bool(row.get('cancelled'))
        md = int(row.get('max_delay_min') or 0)
        # „Unbekannt ≠ Pünktlich" (LH400-Bug): max_delay_min == 0 heißt in Alt-
        # Rows auch „nie ein Delay-Signal gesehen" (nur vor Abflug beobachtet,
        # finales Update verloren). Nur wenn die Row ein echtes Signal trägt
        # (esti / IST-Status / delay>0 / cancelled) geben wir delay_min aus —
        # sonst null (Status-Rekonstruktion; das delay_known-Flag selbst ist
        # nicht persistierbar, die Tabelle hat keine jsonb-Spalte).
        known = _obs_delay_known(md, cancelled, row.get('esti'),
                                 row.get('status'), is_arr)
        # VOLLE Felder direkt aus der persistierten Row (von→nach + Gate/Terminal).
        # Alte Rows (vor 2026-06-14) haben diese Spalten nicht → fallen auf '' zurück.
        out.append({
            'airline': ((row.get('airline') or '') or al), 'airline_name': '', 'flight': fn,
            'dest_iata': (row.get('dest_iata') or ''),
            'dest_name': (row.get('dest_name') or ''),
            'sched': date_str + 'T' + sc + ':00', 'esti': (row.get('esti') or None),
            'delay_min': (md if known else None),
            'delay_known': known,
            'delayed': bool(known and md >= _PUNCTUALITY_DELAY_THRESHOLD_MIN),
            'cancelled': cancelled,
            'gate': (row.get('gate') or ''),
            'terminal': (row.get('terminal') or ''), 'hall': '',
            'status': _departed_status(row.get('status'), cancelled, is_arr),
            # reg/type_code aus der persistierten Row mit ausgeben (Tail + Muster
            # auch auf vergangenen Tagen — select('*') liest sie bereits).
            'reg': (row.get('reg') or ''), 'aircraft': (row.get('type_code') or ''),
            'departed': True,
        })
    out.sort(key=lambda f: f.get('sched') or '')
    return out


def _punctuality_stats_from_obs(date_str, airport='FRA', airline=None):
    """Pünktlichkeits-Quote eines VERGANGENEN (oder beliebigen) Betriebstags rein
    aus den persistierten Beobachtungen (airport_delay_obs) — kein Live-Board,
    kein In-Memory-Store. Damit kann die iOS-Tabelle in der Zeit zurueckgehen.

    Jede Row ist ein abgeschlossener Flug des Tages (der Poller hat ihn in seinem
    Abflug-Fenster erfasst). delayed = max_delay_min >= _PUNCTUALITY_DELAY_THRESHOLD_MIN
    (15 Min D15, gleiche Schwelle wie die Live-Aggregation — eine Quelle der
    Wahrheit). `airline` (z.B. 'LH') filtert per Flugnummer-Prefix.
    Liefert denselben Contract wie _punctuality_stats."""
    rows = _delay_obs_rows_for_date(date_str, airport)
    airline = (airline or '').upper().strip()
    total = 0
    cancelled = 0
    delayed = 0
    on_time = 0
    delay_vals = []
    for row in rows:
        fn = row.get('flight') or ''
        if not fn:
            continue
        if airline:
            try:
                al, _num = _split_flightno(fn)
            except Exception:
                al = (fn[:2] if fn else '')
            if (al or '').upper() != airline:
                continue
        total += 1
        if bool(row.get('cancelled')):
            cancelled += 1
            continue
        md = int(row.get('max_delay_min') or 0)
        if md >= _PUNCTUALITY_DELAY_THRESHOLD_MIN:
            delayed += 1
            delay_vals.append(md)
        else:
            on_time += 1
    active = max(0, total - cancelled)
    pct = round(100.0 * on_time / active, 0) if active > 0 else None
    avg_delay = round(sum(delay_vals) / len(delay_vals)) if delay_vals else 0
    incomplete = active < _PUNCTUALITY_MIN_SAMPLE
    return {'total': total, 'on_time': on_time, 'delayed': delayed,
            'cancelled': cancelled, 'on_time_pct': pct, 'avg_delay_min': avg_delay,
            'sample_size': active, 'data_incomplete': incomplete,
            'min_sample': _PUNCTUALITY_MIN_SAMPLE,
            # EHRLICH: ab wann ein Flug als „verspätet" zählt (D15-Standard, 15 Min).
            'delay_threshold_min': _PUNCTUALITY_DELAY_THRESHOLD_MIN,
            'scheduled_total': total}


def _aerodatabox_punctuality(iata, airline):
    """Heutige Abflug-Pünktlichkeit eines beliebigen IATA-Airports via AeroDataBox
    (RapidAPI, env-gated über AERODATABOX_KEY). Aggressiv gecacht (15 Min/Schlüssel),
    weil der Free-Tier nur 600 Units/Monat hat. Liefert ein Dict im selben Contract
    wie die FRA-Aggregation (on_time_pct/on_time/delayed/cancelled/avg_delay_min) oder
    None bei Quelle-down/leer (Caller degradiert dann ehrlich). KEINE Erfindung —
    1:1 was AeroDataBox liefert."""
    import os as _os
    key = _os.environ.get('AERODATABOX_KEY')
    if not key:
        return None
    iata = (iata or '').upper().strip()
    airline = (airline or '').upper().strip()
    if len(iata) != 3:
        return None
    import time as _t
    ckey = (iata, airline)
    cached = _AERODATABOX_CACHE.get(ckey)
    if cached and (_t.time() - cached[0]) < _AERODATABOX_TTL:
        return cached[1]
    try:
        import requests
        from datetime import datetime, timezone
    except Exception:
        return None
    # TAGES-ANKER: Betriebstag ab 05:00 LOKAL bis Tagesende. AeroDataBox akzeptiert
    # lokal-ISO ohne Offset und liefert lokale Zeiten — wir ankern das Fenster also
    # am Flughafen-Tag, nicht now-relativ. Das `from` ist FIX auf heute 05:00 →
    # gleiches Fenster beim Neu-Laden (Stabilität). Die Quote zählt unten nur Flüge
    # mit bereits passierter Plan-Zeit.
    # BUG-023-Fix: Betriebstag aus der FLUGHAFEN-Ortszeit ableiten, nicht UTC —
    # sonst rollt der Tag für westliche Flughäfen (z.B. JFK) zu früh/spät um und
    # das 05:00–23:59-Fenster trifft den falschen Kalendertag.
    try:
        from zoneinfo import ZoneInfo
        tz = ZoneInfo(airport_tz(iata) or 'UTC')
    except Exception:
        tz = timezone.utc
    day = datetime.now(tz).strftime('%Y-%m-%d')
    from_iso = day + 'T05:00'
    to_iso = day + 'T23:59'
    url = ('https://aerodatabox.p.rapidapi.com/flights/airports/iata/'
           + iata + '/' + from_iso + '/' + to_iso)
    try:
        r = requests.get(url,
                         params={'direction': 'Departure', 'withLocation': 'false',
                                 'withCancelled': 'true', 'withCodeshared': 'false'},
                         headers={'X-RapidAPI-Key': key,
                                  'X-RapidAPI-Host': 'aerodatabox.p.rapidapi.com'},
                         timeout=15)
    except Exception:
        return None
    if r.status_code != 200:
        # Non-200 (Quote/Auth/Server) → ehrlich None, niemals 500.
        return None
    try:
        body = r.json() or {}
    except Exception:
        return None
    deps = body.get('departures') or []
    if not deps:
        # Leerer Tag (oder gefilterte Antwort) → ehrlich kein-Daten.
        result = {'total': 0, 'on_time': 0, 'delayed': 0, 'cancelled': 0,
                  'on_time_pct': None, 'avg_delay_min': 0}
        _AERODATABOX_CACHE[ckey] = (_t.time(), result)
        _cache_soft_cap(_AERODATABOX_CACHE)
        return result

    def _airline_iata(f):
        return ((f.get('airline') or {}).get('iata') or '').upper().strip()

    def _callsign_prefix(f):
        # ICAO-Callsign-Prefix als Fallback-Filter (z.B. DLH für LH).
        cs = ((f.get('aircraft') or {}).get('reg') or '')  # nicht zuverlässig
        num = (f.get('number') or '').replace(' ', '').upper()
        return num[:2]

    def _matches_airline(f):
        if not airline:
            return True
        if _airline_iata(f) == airline:
            return True
        # Flight-Number-Prefix (z.B. "LH 441" → LH) als Fallback.
        return _callsign_prefix(f) == airline

    def _parse_t(v):
        if not v:
            return None
        try:
            return datetime.fromisoformat(str(v).replace('Z', '+00:00'))
        except Exception:
            return None

    # now als tz-aware UTC — Vergleichsbasis für "Plan-Zeit bereits passiert?".
    now_aware = datetime.now(timezone.utc)
    total = 0
    cancelled = 0
    delayed = 0
    on_time = 0
    delay_vals = []
    def _adb_is_rail(f):
        # AeroDataBox-Roh-Dict in den _is_rail_or_bus-Contract bringen
        # (aircraft/reg sind hier NESTED unter f['aircraft']).
        acft = f.get('aircraft') or {}
        mv = f.get('departure') or f.get('movement') or {}
        ap = mv.get('airport') or {}
        return _is_rail_or_bus({
            'aircraft': (acft.get('model') or '').strip(),
            'reg': (acft.get('reg') or '').strip(),
            'dest_iata': (ap.get('iata') or '').strip(),
            'dest_name': (ap.get('name') or '').strip(),
        })

    for f in deps:
        if not _matches_airline(f):
            continue
        # Bahn/Bus (LH Express Rail) niemals in die Pünktlichkeits-Quote.
        if _adb_is_rail(f):
            continue
        status = (f.get('status') or '').lower()
        if 'cancel' in status:
            # Annulliert = bekannt → zählt mit.
            total += 1
            cancelled += 1
            continue
        mv = f.get('departure') or {}
        sched = _parse_t(((mv.get('scheduledTime') or {}).get('local'))
                         or ((mv.get('scheduledTime') or {}).get('utc')))
        revised = _parse_t(((mv.get('revisedTime') or {}).get('local'))
                           or ((mv.get('revisedTime') or {}).get('utc'))
                           or ((mv.get('actualTime') or {}).get('local'))
                           or ((mv.get('actualTime') or {}).get('utc')))
        # STABILITÄTS-FIX: Nur Flüge in die Quote, deren PLAN-Zeit bereits passiert
        # ist (oder die schon eine revidierte/tatsächliche Zeit haben = bekannt).
        # Künftige Flüge ohne Bewegungsdaten würden sonst als 'on time' gezählt und
        # die Zahl beim Neu-Laden springen lassen.
        if revised is None and sched is not None:
            try:
                if sched > now_aware:
                    continue
            except Exception:
                pass
        total += 1
        dmin = 0
        if sched and revised:
            try:
                dmin = int((revised - sched).total_seconds() / 60)
            except Exception:
                dmin = 0
        if dmin >= _AERODATABOX_DELAY_THRESHOLD:
            delayed += 1
            delay_vals.append(dmin)
        else:
            on_time += 1
    active = max(0, total - cancelled)
    pct = round(100.0 * on_time / active, 0) if active > 0 else None
    avg_delay = round(sum(delay_vals) / len(delay_vals)) if delay_vals else 0
    result = {'total': total, 'on_time': on_time, 'delayed': delayed,
              'cancelled': cancelled, 'on_time_pct': pct, 'avg_delay_min': avg_delay}
    _AERODATABOX_CACHE[ckey] = (_t.time(), result)
    _cache_soft_cap(_AERODATABOX_CACHE)
    return result


@app.route('/api/airport/poll-punctuality', methods=['POST', 'GET'])
def poll_punctuality_accumulate():
    """Cloud-Scheduler-getriggert (~10 min): triggert die TAGES-Akkumulation der
    Pünktlichkeits-Beobachtungen für die großen DE-Airports.

    WARUM: Die Fraport-/Flughafen-Feeds sind now-relativ — ein bereits abgeflogener
    Flug verschwindet kurz nach Abflug aus dem Feed. Die Quote akkumuliert ihn nur,
    wenn _punctuality_stats GENAU in diesem kurzen Fenster läuft. Ohne Poller
    passierte das nur bei zufälligen User-Requests → winzige Stichprobe (User:
    „weiß nicht wie pünktlich LH ist"). Mit diesem 10-Minuten-Tick wird jeder Flug
    in seinem Abflug-Fenster erfasst und nach airport_delay_obs persistiert → die
    Tages-Stichprobe wächst von 05:00 bis Mitternacht, Rollover löscht sie täglich.

    Security: X-Poll-Secret == ADSB_POLL_SECRET (reuse). Ohne Secret nur localhost."""
    import os as _os, hmac as _hmac
    secret = _os.environ.get('ADSB_POLL_SECRET', '').strip()
    if secret:
        provided = (request.headers.get('X-Poll-Secret') or '').strip()
        if not provided or not _hmac.compare_digest(provided, secret):
            return jsonify({'ok': False, 'error': 'forbidden'}), 403
    elif (request.remote_addr or '') not in ('127.0.0.1', '::1'):
        return jsonify({'ok': False, 'error': 'forbidden_no_secret'}), 403
    results = {}
    # BUGFIX 2026-06-13: BEIDE Richtungen pollen (Abflug UND Ankunft). Vorher lief
    # der Poller nur über 'departure' → die Ankunfts-Tafel akkumulierte NIE eine
    # Historie. Arrivals landen unter dem Store-Key '<AP>#ARR' (siehe _store_key_for).
    for ap in ('FRA', 'MUC', 'BER', 'DUS', 'HAM', 'HAJ'):
        for ftype in ('departure', 'arrival'):
            tag = ap if ftype == 'departure' else (ap + '#ARR')
            try:
                if ap in ('FRA', 'EDDF'):
                    flights = (_fra_day_board_cached(ftype) if ftype == 'departure'
                               else _fra_board_cached(ftype))
                elif ap in _NATIVE_BOARD_SCRAPERS:
                    rows, _src = (_native_board_cached(ap, ftype) or (None, None))
                    flights = rows
                else:
                    flights = None
                if not flights:
                    results[tag] = 'no_flights'
                    continue
                # _punctuality_stats ruft intern _merge_into_delay_store → persistiert
                # die neuen Beobachtungen nach airport_delay_obs (cross-instance).
                # Store-Key trägt die Richtung ('<AP>' bzw. '<AP>#ARR').
                stats = _punctuality_stats(flights, _store_key_for(ap, ftype))
                results[tag] = stats.get('sample_size')
            except Exception as e:
                results[tag] = 'err:' + type(e).__name__
    return jsonify({'ok': True, 'accumulated': results})


# ══════════════════════════════════════════════════════════════════════════
#  EUROPÄISCHE WAREHOUSE-EXPANSION  —  OpenSky-Bulk-Fill (gratis, weltweit)
# ══════════════════════════════════════════════════════════════════════════
#  Owner-Vision: „wir scrapen alle großen deutschen Flughäfen (Tail, Zeiten,
#  Gates) → Feed/Kalender/Radar. Das will ich für JEDEN großen EU-Flughafen."
#
#  Die deutschen Hubs haben freie NATIVE Board-Scraper (Fraport/munich-airport/…)
#  mit Gate+Terminal+Ist-Zeiten → bleiben die reiche Quelle (siehe
#  _NATIVE_BOARD_SCRAPERS). Für den REST Europas gibt es keine sauber-freie
#  Board-JSON (LHR=JS-SPA, ZRH=302/Sitecore, VIE=301, AMS=403 key-required,
#  Stand 2026-07) → wir nutzen die AUTHENTIFIZIERTE OpenSky-Flights-API als
#  skalierbare, kostenlose Engine: /flights/departure + /flights/arrival je
#  ICAO liefern JEDEN Flug rein/raus (icao24=Tail-Hex, callsign, dep/arr-Airport,
#  first/lastSeen-Zeiten) — für die GANZE Welt, ohne Per-Airport-Scraper.
#
#  Wir schreiben diese Beobachtungen im GLEICHEN Contract wie die deutschen
#  Scraper nach airport_delay_obs (+ ax_route_cache) → route-history,
#  aircraft-history, flight-info und der Radar-Route-Resolver leuchten damit für
#  europäische Flüge auf. EHRLICH: KEINE Gates (nicht in ADS-B) und KEINE
#  Verspätung (OpenSky kennt keine SOLL-Zeit) → Gate/Delay bleiben leer, die
#  Zeile trägt Tail + echte Strecke + Ist-Zeit. Provenance-Spalte source=
#  'opensky' hält das getrennt von den Scheduled-Quellen (kein Fake-„pünktlich").
#
#  (IATA, ICAO) — die großen EU-Hubs (grob nach Verkehr). Die deutschen sind
#  bewusst dabei (Vollständigkeit), werden aber im Fill übersprungen, weil sie
#  ihren reichen nativen Scraper haben (_EU_FILL_ICAOS filtert sie raus).
