    import json as _j
    crew = _ai_resolver_airline_crew_context_block()  # Phase 5d Vokabular

    # PII-Strip + Hard-Cap auf 200 Zeichen
    _PII_PATTERNS = (
        # vereinfacht: Namen/PNRs/...
        # Reader-V2 erwartet anonymisierten Excerpt vom Caller
    )
