        f'  "start_time": "HH:MM or empty",\n'
        f'  "end_time": "HH:MM or empty",\n'
        f'  "duty_duration_minutes": null,\n'
        f'  "has_fl": false,\n'
        f'  "starts_at_homebase": false,\n'
        f'  "ends_at_homebase": false,\n'
        f'  "overnight_after_day": false,\n'
